--==================================================
-- [2] BASIC HELPERS
--==================================================

function HolyCleanText(value)

    local text =
        tostring(value or "")

    text =
        text:gsub(
            "^%s+",
            ""
        )

    text =
        text:gsub(
            "%s+$",
            ""
        )

    return text
end

function HolyGetRequestFunction()

    if type(syn) == "table"
    and type(syn.request) == "function" then

        return syn.request
    end

    if type(http_request) == "function" then
        return http_request
    end

    if type(request) == "function" then
        return request
    end

    if type(fluxus) == "table"
    and type(fluxus.request) == "function" then

        return fluxus.request
    end

    local env =
        type(getgenv) == "function"
        and getgenv()
        or _G

    if type(env) == "table" then

        if type(env.request) == "function" then
            return env.request
        end

        if type(env.http_request) == "function" then
            return env.http_request
        end
    end

    return nil
end

function HolyValidateSource(body)

    if type(body) ~= "string"
    or body == "" then

        return nil,
            "empty response"
    end

    if body:sub(1, 3) == "\239\187\191" then
        body = body:sub(4)
    end

    local preview =
        body:sub(1, 220):lower()

    if preview:find("<!doctype html", 1, true)
    or preview:find("<html", 1, true)
    or preview:find("rate limit", 1, true) then

        return nil,
            "response was HTML/rate-limit page"
    end

    if body:find("\0", 1, true) then

        return nil,
            "response contains binary null bytes"
    end

    return body,
        nil
end

function HolyHttpGet(url)

    url =
        HolyCleanText(url)

    if url == "" then
        return nil, "empty URL"
    end

    local failures =
        {}

    local ok,
        result =
        pcall(function()

            return game:HttpGet(
                url,
                true
            )
        end)

    if ok == true then

        local source,
            sourceError =
            HolyValidateSource(result)

        if source then
            return source, nil
        end

        failures[#failures + 1] =
            "game:HttpGet: "
            .. tostring(sourceError)

    else

        failures[#failures + 1] =
            "game:HttpGet failed: "
            .. tostring(result)
    end

    local requestFunction =
        HolyGetRequestFunction()

    if type(requestFunction) == "function" then

        local requestOk,
            response =
            pcall(function()

                return requestFunction({
                    Url = url,
                    Method = "GET",
                    Headers = {
                        ["Accept"] = "text/plain",
                        ["Accept-Encoding"] = "identity",
                        ["Cache-Control"] = "no-cache",
                    },
                })
            end)

        if requestOk == true then

            local body =
                nil

            if type(response) == "string" then

                body =
                    response

            elseif type(response) == "table" then

                body =
                    response.Body
                    or response.body
                    or response.ResponseBody
                    or response.responseBody
            end

            local source,
                sourceError =
                HolyValidateSource(body)

            if source then
                return source, nil
            end

            failures[#failures + 1] =
                "request: "
                .. tostring(sourceError)

        else

            failures[#failures + 1] =
                "request failed: "
                .. tostring(response)
        end
    end

    return nil,
        table.concat(
            failures,
            " | "
        )
end

function HolyGetCompiler()

    if type(loadstring) == "function" then
        return loadstring
    end

    if type(load) == "function" then
        return load
    end

    local env =
        type(getgenv) == "function"
        and getgenv()
        or _G

    if type(env) == "table" then

        if type(env.loadstring) == "function" then
            return env.loadstring
        end

        if type(env.load) == "function" then
            return env.load
        end
    end

    return nil
end

function HolyLoadUrl(url, name)

    name =
        tostring(name or "remote script")

    local source,
        downloadError =
        HolyHttpGet(url)

    if type(source) ~= "string"
    or source == "" then

        error(
            "[HOLY] Failed to download "
            .. name
            .. ": "
            .. tostring(downloadError),
            0
        )
    end

    local compiler =
        HolyGetCompiler()

    if type(compiler) ~= "function" then

        error(
            "[HOLY] loadstring/load is missing.",
            0
        )
    end

    local compileOk,
        chunk,
        compileError =
        pcall(
            compiler,
            source
        )

    if compileOk ~= true
    or type(chunk) ~= "function" then

        error(
            "[HOLY] Failed to compile "
            .. name
            .. ": "
            .. tostring(compileError or chunk),
            0
        )
    end

    local runOk,
        result =
        pcall(chunk)

    if runOk ~= true then

        error(
            "[HOLY] Failed to run "
            .. name
            .. ": "
            .. tostring(result),
            0
        )
    end

    return result
end

function HolyCanUseFiles()

    return type(writefile) == "function"
        and type(readfile) == "function"
        and type(isfile) == "function"
end

function HolyEnsureFolder()

    if type(makefolder) ~= "function"
    or type(isfolder) ~= "function" then

        return false
    end

    local ok =
        pcall(function()

            if not isfolder(UI_SETTINGS_FOLDER) then

                makefolder(
                    UI_SETTINGS_FOLDER
                )
            end
        end)

    return ok == true
end

function HolyAccountTokenValid(value)

    local token =
        HolyCleanText(
            value
        )

    if #token < 32
    or #token > 128 then

        return false
    end

    return token:match(
        "^[%w_-]+$"
    ) ~= nil
end

function HolyAccountReadFile(path)

    if type(readfile) ~= "function"
    or type(isfile) ~= "function" then

        return nil
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                path
            )
    end)

    if exists ~= true then
        return nil
    end

    local ok,
        contents =
        pcall(function()

            return readfile(
                path
            )
        end)

    if ok ~= true
    or type(contents) ~= "string" then

        return nil
    end

    contents =
        HolyCleanText(
            contents
        )

    if contents == "" then
        return nil
    end

    return contents
end

function HolyAccountDecodeStoredToken(contents)

    contents =
        HolyCleanText(
            contents
        )

    if HolyAccountTokenValid(
        contents
    ) == true then

        return contents
    end

    local ok,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                contents
            )
        end)

    if ok ~= true
    or type(data) ~= "table" then

        return nil
    end

    local token =
        HolyCleanText(
            data.AccountToken
            or data.account_token
            or data.Token
            or data.token
        )

    if HolyAccountTokenValid(
        token
    ) ~= true then

        return nil
    end

    return token
end

function HolyAccountLoadSavedToken()

    local token =
        HolyAccountDecodeStoredToken(
            HolyAccountReadFile(
                HOLY_ACCOUNT_SETTINGS_FILE
            )
            or ""
        )

    local source =
        token
        and "official"
        or nil

    if not token then

        local environmentToken =
            HOLY_ACCOUNT_ENVIRONMENT
            and HOLY_ACCOUNT_ENVIRONMENT
                .HOLY_ACCOUNT_TOKEN
            or nil

        if HolyAccountTokenValid(
            environmentToken
        ) == true then

            token =
                HolyCleanText(
                    environmentToken
                )

            source =
                "environment"
        end
    end

    if not token then

        token =
            HolyAccountDecodeStoredToken(
                HolyAccountReadFile(
                    HOLY_ACCOUNT_LEGACY_TOKEN_FILE
                )
                or ""
            )

        if token then

            source =
                "legacy"
        end
    end

    HOLY_ACCOUNT_RUNTIME.Token =
        token

    HOLY_ACCOUNT_RUNTIME.Source =
        source

    HOLY_ACCOUNT_RUNTIME.NeedsMigration =
        token ~= nil
        and source ~= "official"

    HOLY_ACCOUNT_RUNTIME.Account =
        nil

    if token then

        HOLY_ACCOUNT_ENVIRONMENT.HOLY_ACCOUNT_TOKEN =
            token

        HOLY_ACCOUNT_RUNTIME.Status =
            "Checking"

        HOLY_ACCOUNT_RUNTIME.Message =
            "Authenticating the saved account..."

        return true
    end

    HOLY_ACCOUNT_RUNTIME.Status =
        type(
            HolyGetRequestFunction()
        ) == "function"
        and "Not connected"
        or "Unsupported executor"

    HOLY_ACCOUNT_RUNTIME.Message =
        type(
            HolyGetRequestFunction()
        ) == "function"
        and "Generate a pairing code on HOLY HUB to connect this Roblox account."
        or "This executor does not support HTTP requests."

    return false
end

function HolyAccountSaveToken(token)

    token =
        HolyCleanText(
            token
        )

    if HolyAccountTokenValid(
        token
    ) ~= true
    or HolyCanUseFiles() ~= true then

        return false
    end

    HolyEnsureFolder()

    local ok,
        encoded =
        pcall(function()

            return HttpService:JSONEncode({
                Version =
                    1,

                AccountToken =
                    token,

                RobloxUserId =
                    tostring(
                        LocalPlayer.UserId
                    ),

                RobloxUsername =
                    LocalPlayer.Name,
            })
        end)

    if ok ~= true
    or type(encoded) ~= "string" then

        return false
    end

    local writeOk =
        pcall(function()

            writefile(
                HOLY_ACCOUNT_SETTINGS_FILE,
                encoded
            )
        end)

    if writeOk == true then

        HOLY_ACCOUNT_RUNTIME.Source =
            "official"

        HOLY_ACCOUNT_RUNTIME.NeedsMigration =
            false
    end

    return writeOk == true
end

function HolyAccountDeleteStoredFile(path)

    if type(isfile) ~= "function" then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                path
            )
    end)

    if exists ~= true then
        return true
    end

    if type(delfile) == "function" then

        return pcall(
            delfile,
            path
        )
    end

    if type(writefile) == "function" then

        return pcall(
            writefile,
            path,
            ""
        )
    end

    return false
end

function HolyAccountClearInvalidToken()

    HOLY_ACCOUNT_RUNTIME.Active =
        false

    HOLY_ACCOUNT_RUNTIME.Generation =
        HOLY_ACCOUNT_RUNTIME.Generation
        + 1

    HOLY_ACCOUNT_RUNTIME.Token =
        nil

    HOLY_ACCOUNT_RUNTIME.Account =
        nil

    HOLY_ACCOUNT_RUNTIME.Source =
        nil

    HOLY_ACCOUNT_RUNTIME.NeedsMigration =
        false

    HOLY_ACCOUNT_RUNTIME.InventoryBusy =
        false

    HOLY_ACCOUNT_RUNTIME.InventoryStatus =
        "Waiting for account connection"

    HOLY_ACCOUNT_RUNTIME.InventoryFingerprint =
        ""

    HOLY_ACCOUNT_RUNTIME.InventoryLastScanClock =
        0

    HOLY_ACCOUNT_RUNTIME.InventoryLastUpload =
        0

    HOLY_ACCOUNT_RUNTIME.InventoryFruitCount =
        0

    HOLY_ACCOUNT_RUNTIME.InventoryEggCount =
        0

    HOLY_ACCOUNT_RUNTIME.InventoryItemRows =
        0

    HOLY_ACCOUNT_ENVIRONMENT.HOLY_ACCOUNT_TOKEN =
        nil

    HolyAccountDeleteStoredFile(
        HOLY_ACCOUNT_SETTINGS_FILE
    )

    HolyAccountDeleteStoredFile(
        HOLY_ACCOUNT_LEGACY_TOKEN_FILE
    )
end

function HolyAccountFriendlyError(value)

    local code =
        HolyCleanText(
            value
            or "request_failed"
        )

    local messages = {
        invalid_pairing_code =
            "That pairing code is invalid.",

        pairing_code_used =
            "That pairing code has already been used.",

        pairing_code_revoked =
            "That pairing code was replaced. Generate a new one.",

        pairing_code_expired =
            "That pairing code expired. Generate a new one.",

        account_already_linked =
            "This Roblox account is already linked. Use the device where its saved login was created.",

        account_limit_reached =
            "Your HOLY workspace has no available account slots.",

        pairing_conflict =
            "The pairing code changed while connecting. Generate a new one.",

        account_token_required =
            "The saved account login is missing.",

        invalid_account_token =
            "The saved account login is invalid. Pair this account again.",

        account_token_revoked =
            "The saved account login was revoked.",

        account_unlinked =
            "This Roblox account is no longer linked.",

        account_identity_mismatch =
            "The saved login belongs to a different Roblox account.",

        invalid_roblox_user_id =
            "The current Roblox account ID was rejected.",

        invalid_roblox_username =
            "The current Roblox username was rejected.",

        internal_server_error =
            "The HOLY account service had a server error.",
    }

    if messages[code] then
        return messages[code]
    end

    local friendly =
        code:gsub(
            "_",
            " "
        )

    return friendly:sub(1, 1):upper()
        .. friendly:sub(2)
end

function HolyAccountRequest(
    path,
    method,
    payload,
    accountToken
)

    local requestFunction =
        HolyGetRequestFunction()

    if type(requestFunction) ~= "function" then

        return 0,
            nil,
            "HTTP requests are not supported by this executor."
    end

    local headers = {
        ["Accept"] =
            "application/json",

        ["Content-Type"] =
            "application/json",

        ["Cache-Control"] =
            "no-cache",
    }

    if HolyAccountTokenValid(
        accountToken
    ) == true then

        headers["Authorization"] =
            "Bearer "
            .. HolyCleanText(
                accountToken
            )
    end

    local body =
        nil

    if type(payload) == "table" then

        local encodeOk,
            encoded =
            pcall(function()

                return HttpService:JSONEncode(
                    payload
                )
            end)

        if encodeOk ~= true then

            return 0,
                nil,
                "Could not encode the account request."
        end

        body =
            encoded
    end

    local requestOk,
        response =
        pcall(function()

            return requestFunction({
                Url =
                    HOLY_ACCOUNT_API_BASE
                    .. tostring(
                        path
                        or ""
                    ),

                Method =
                    tostring(
                        method
                        or "POST"
                    ),

                Headers =
                    headers,

                Body =
                    body,
            })
        end)

    if requestOk ~= true then

        return 0,
            nil,
            "Could not reach the HOLY account service."
    end

    local statusCode =
        0

    local responseBody =
        nil

    if type(response) == "table" then

        statusCode =
            tonumber(
                response.StatusCode
                or response.Status
                or response.status_code
                or 0
            )
            or 0

        responseBody =
            response.Body
            or response.body
            or response.ResponseBody
            or response.responseBody

    elseif type(response) == "string" then

        responseBody =
            response
    end

    if type(responseBody) ~= "string"
    or responseBody == "" then

        return statusCode,
            nil,
            "The HOLY account service returned an empty response."
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                responseBody
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return statusCode,
            nil,
            "The HOLY account service returned an invalid response."
    end

    return statusCode,
        data,
        nil
end

function HolyAccountInventoryCleanName(value)

    local result =
        tostring(
            value
            or ""
        )

    result =
        result:gsub(
            "%s*%[%s*[xX]%d+%s*%]%s*$",
            ""
        )

    result =
        result:gsub(
            "%s+[xX]%d+%s*$",
            ""
        )

    result =
        result:gsub(
            "^%s+",
            ""
        )

    result =
        result:gsub(
            "%s+$",
            ""
        )

    return result
end

function HolyAccountInventoryKey(value)

    return HolyAccountInventoryCleanName(
        value
    )
        :lower()
        :gsub(
            "[%s%p_]",
            ""
        )
end

function HolyAccountInventorySafeId(value)

    local result =
        tostring(
            value
            or ""
        )
            :gsub(
                "^%s+",
                ""
            )
            :gsub(
                "%s+$",
                ""
            )
            :gsub(
                "[^%w%._:%-]",
                "_"
            )
            :gsub(
                "_+",
                "_"
            )

    result =
        result:sub(
            1,
            150
        )

    if result == "" then
        return nil
    end

    return result
end

function HolyAccountInventoryFirstText(...)

    for index = 1, select("#", ...) do

        local value =
            select(
                index,
                ...
            )

        if type(value) == "string" then

            local cleaned =
                HolyAccountInventoryCleanName(
                    value
                )

            if cleaned ~= "" then

                return cleaned
            end
        end
    end

    return ""
end

function HolyAccountInventoryReadFavorite(item)

    if typeof(item) ~= "Instance" then
        return false
    end

    return item:GetAttribute(
        "IsFavorite"
    ) == true
        or item:GetAttribute(
            "Favorite"
        ) == true
        or item:GetAttribute(
            "Favorited"
        ) == true
end

function HolyAccountInventoryReadCount(item)

    if typeof(item) ~= "Instance" then
        return 1
    end

    local count =
        tonumber(
            item:GetAttribute(
                "Count"
            )
            or item:GetAttribute(
                "Amount"
            )
            or item:GetAttribute(
                "Quantity"
            )
            or item:GetAttribute(
                "Stack"
            )
            or item:GetAttribute(
                "Uses"
            )
        )
        or 1

    return math.clamp(
        math.floor(
            count
        ),
        1,
        1000000000
    )
end

function HolyAccountInventoryReadWeight(
    item,
    attributes
)

    attributes =
        type(attributes) == "table"
        and attributes
        or {}

    local weight =
        tonumber(
            attributes.WeightKg
            or attributes.WeightKG
            or attributes.Weight
            or attributes.Mass
        )

    if not weight
    and typeof(item) == "Instance" then

        weight =
            tonumber(
                tostring(
                    item.Name
                ):match(
                    "([%d%.]+)%s*[Kk][Gg]"
                )
            )
    end

    if not weight
    or weight <= 0
    or weight > 1000000000 then

        return nil
    end

    return weight
end

function HolyAccountInventoryLoadEggCatalog()

    if type(
        HOLY_ACCOUNT_RUNTIME.InventoryEggCatalog
    ) == "table" then

        return HOLY_ACCOUNT_RUNTIME
            .InventoryEggCatalog
    end

    local catalog = {}

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local eggModule =
        sharedModules
        and sharedModules:FindFirstChild(
            "EggData"
        )

    if eggModule
    and eggModule:IsA(
        "ModuleScript"
    ) then

        local requireOk,
            eggData =
            pcall(
                require,
                eggModule
            )

        if requireOk == true
        and type(eggData) == "table" then

            local function walk(
                value,
                depth,
                seen
            )

                if type(value) ~= "table"
                or depth > 6
                or seen[value] then

                    return
                end

                seen[value] =
                    true

                local name =
                    HolyAccountInventoryFirstText(
                        value.EggName,
                        value.ItemName,
                        value.DisplayName,
                        value.Name
                    )

                if name ~= "" then

                    catalog[
                        HolyAccountInventoryKey(
                            name
                        )
                    ] =
                        true
                end

                for _, child in pairs(
                    value
                ) do

                    if type(child) == "table" then

                        walk(
                            child,
                            depth + 1,
                            seen
                        )
                    end
                end
            end

            walk(
                eggData,
                0,
                {}
            )
        end
    end

    HOLY_ACCOUNT_RUNTIME.InventoryEggCatalog =
        catalog

    return catalog
end

function HolyAccountBuildMailInventory()

    local items = {}

    local groupedEggs = {}
    local usedInstances = {}
    local usedFruitIds = {}

    local fruitCount = 0
    local eggCount = 0

    local eggCatalog =
        HolyAccountInventoryLoadEggCatalog()

    local roots = {
        {
            Instance =
                LocalPlayer.Character,

            Name =
                "character",
        },

        {
            Instance =
                LocalPlayer:FindFirstChildOfClass(
                    "Backpack"
                ),

            Name =
                "backpack",
        },
    }

    for _, rootData in ipairs(
        roots
    ) do

        local root =
            rootData.Instance

        if typeof(root) == "Instance" then

            for _, item in ipairs(
                root:GetChildren()
            ) do

                if not usedInstances[item]
                and (
                    item:IsA(
                        "Tool"
                    )
                    or item:IsA(
                        "Configuration"
                    )
                ) then

                    usedInstances[item] =
                        true

                    local attributes =
                        item:GetAttributes()

                    local favorite =
                        HolyAccountInventoryReadFavorite(
                            item
                        )

                    if attributes.HarvestedFruit == true then

                        local rawItemId =
                            HolyAccountInventoryFirstText(
                                attributes.Id,
                                attributes.FruitId,
                                attributes.FruitID,
                                attributes.UUID,
                                attributes.Guid
                            )

                        local clientItemId =
                            HolyAccountInventorySafeId(
                                rawItemId
                            )

                        if clientItemId
                        and not usedFruitIds[
                            clientItemId
                        ] then

                            usedFruitIds[
                                clientItemId
                            ] =
                                true

                            local name =
                                HolyAccountInventoryFirstText(
                                    attributes.FruitName,
                                    attributes.Fruit,
                                    attributes.ItemName,
                                    item.Name
                                )

                            name =
                                name:sub(
                                    1,
                                    100
                                )

                            if name == "" then

                                name =
                                    "Unknown Fruit"
                            end

                            local mutation =
                                HolyAccountInventoryFirstText(
                                    attributes.Mutation,
                                    attributes.Mutations
                                )

                            local variant =
                                HolyAccountInventoryFirstText(
                                    attributes.FruitVariant,
                                    attributes.Variant
                                )

                            if mutation == ""
                            and variant ~= "" then

                                mutation =
                                    variant

                                variant =
                                    ""
                            end

                            if mutation == "" then

                                mutation =
                                    "Normal"
                            end

                            mutation =
                                mutation:sub(
                                    1,
                                    240
                                )

                            variant =
                                variant:sub(
                                    1,
                                    80
                                )

                            local icon = ""

                            if item:IsA(
                                "Tool"
                            ) then

                                icon =
                                    tostring(
                                        item.TextureId
                                        or ""
                                    )
                            end

                            table.insert(
                                items,
                                {
                                    client_item_id =
                                        clientItemId,

                                    category =
                                        "fruit",

                                    name =
                                        name,

                                    variant =
                                        variant,

                                    mutation =
                                        mutation,

                                    weight =
                                        HolyAccountInventoryReadWeight(
                                            item,
                                            attributes
                                        ),

                                    quantity =
                                        1,

                                    is_favorited =
                                        favorite,

                                    is_mailable =
                                        true,

                                    metadata = {
                                        mail_category =
                                            "HarvestedFruits",

                                        mail_item_key =
                                            rawItemId,

                                        source =
                                            rootData.Name,

                                        source_name =
                                            tostring(
                                                item.Name
                                            ),

                                        icon =
                                            icon,

                                        unique =
                                            true,
                                    },
                                }
                            )

                            fruitCount +=
                                1
                        end
                    else

                        local mainCategory =
                            HolyAccountInventoryFirstText(
                                attributes.MainCategory,
                                attributes.Category
                            )

                        local mainKey =
                            HolyAccountInventoryKey(
                                mainCategory
                            )

                        local eggName =
                            HolyAccountInventoryFirstText(
                                attributes.Egg,
                                attributes.EggName,
                                attributes.ItemName,
                                item.Name
                            )

                        local eggKey =
                            HolyAccountInventoryKey(
                                eggName
                            )

                        local isEgg =
                            mainKey == "egg"
                            or mainKey == "eggs"
                            or attributes.Egg ~= nil
                            or attributes.EggName ~= nil
                            or eggCatalog[
                                eggKey
                            ] == true

                        if isEgg
                        and eggName ~= ""
                        and eggKey ~= "" then

                            local group =
                                groupedEggs[
                                    eggKey
                                ]

                            if not group then

                                local icon = ""

                                if item:IsA(
                                    "Tool"
                                ) then

                                    icon =
                                        tostring(
                                            item.TextureId
                                            or ""
                                        )
                                end

                                group = {
                                    Name =
                                        eggName:sub(
                                            1,
                                            100
                                        ),

                                    Quantity =
                                        0,

                                    Favorite =
                                        false,

                                    Icon =
                                        icon,

                                    SourceName =
                                        tostring(
                                            item.Name
                                        ),
                                }

                                groupedEggs[
                                    eggKey
                                ] =
                                    group
                            end

                            local quantity =
                                HolyAccountInventoryReadCount(
                                    item
                                )

                            group.Quantity =
                                math.clamp(
                                    group.Quantity
                                    + quantity,
                                    1,
                                    1000000000
                                )

                            group.Favorite =
                                group.Favorite
                                or favorite

                            eggCount +=
                                quantity
                        end
                    end
                end
            end
        end
    end

    for eggKey, egg in pairs(
        groupedEggs
    ) do

        local clientItemId =
            HolyAccountInventorySafeId(
                "egg:"
                .. eggKey
            )

        if clientItemId then

            table.insert(
                items,
                {
                    client_item_id =
                        clientItemId,

                    category =
                        "egg",

                    name =
                        egg.Name,

                    variant =
                        "",

                    mutation =
                        "",

                    quantity =
                        egg.Quantity,

                    is_favorited =
                        egg.Favorite == true,

                    is_mailable =
                        true,

                    metadata = {
                        mail_category =
                            "Eggs",

                        mail_item_key =
                            egg.Name,

                        source =
                            "backpack",

                        source_name =
                            egg.SourceName,

                        icon =
                            egg.Icon,

                        unique =
                            false,
                    },
                }
            )
        end
    end

    table.sort(
        items,
        function(left, right)

            return tostring(
                left.client_item_id
            ) < tostring(
                right.client_item_id
            )
        end
    )

    local fingerprintParts = {}

    for _, item in ipairs(
        items
    ) do

        table.insert(
            fingerprintParts,
            table.concat(
                {
                    tostring(
                        item.client_item_id
                    ),

                    tostring(
                        item.category
                    ),

                    tostring(
                        item.name
                    ),

                    tostring(
                        item.variant
                        or ""
                    ),

                    tostring(
                        item.mutation
                        or ""
                    ),

                    tostring(
                        item.weight
                        or ""
                    ),

                    tostring(
                        item.quantity
                        or 1
                    ),

                    item.is_favorited == true
                        and "1"
                        or "0",
                },
                "\30"
            )
        )
    end

    return items,
        table.concat(
            fingerprintParts,
            "\31"
        ),
        {
            FruitCount =
                fruitCount,

            EggCount =
                eggCount,

            ItemRows =
                #items,
        }
end

function HolyAccountInventoryDescription(
    summary
)

    summary =
        type(summary) == "table"
        and summary
        or {}

    return tostring(
        math.max(
            0,
            math.floor(
                tonumber(
                    summary.FruitCount
                )
                or 0
            )
        )
    )
        .. " fruits · "
        .. tostring(
            math.max(
                0,
                math.floor(
                    tonumber(
                        summary.EggCount
                    )
                    or 0
                )
            )
        )
        .. " eggs"
end

function HolyAccountInventoryFriendlyError(
    value
)

    local code =
        HolyCleanText(
            value
            or "inventory_sync_failed"
        )

    local messages = {
        inventory_item_limit_exceeded =
            "This account has more inventory rows than the service currently supports.",

        body_too_large =
            "This inventory snapshot is too large to upload.",

        invalid_inventory_item_id =
            "One inventory item had an invalid ID.",

        duplicate_inventory_item_id =
            "Two inventory items returned the same ID.",

        invalid_inventory_category =
            "An inventory category was rejected.",

        invalid_inventory_item_name =
            "An inventory item had an invalid name.",

        invalid_inventory_item_quantity =
            "An inventory stack returned an invalid amount.",

        inventory_snapshot_failed =
            "The HOLY account service could not save this inventory snapshot.",

        account_identity_mismatch =
            "This saved login belongs to another Roblox account.",

        account_token_required =
            "The saved account login is missing.",

        invalid_account_token =
            "The saved account login is invalid.",

        account_token_revoked =
            "The saved account login was revoked.",

        account_unlinked =
            "This Roblox account is no longer linked.",
    }

    return messages[
        code
    ]
        or HolyAccountFriendlyError(
            code
        )
end

function HolyAccountSendMailInventory(
    force,
    notifyUser
)

    if HOLY_ACCOUNT_RUNTIME.InventoryBusy == true then

        return false
    end

    local token =
        HOLY_ACCOUNT_RUNTIME.Token

    if HolyAccountTokenValid(
        token
    ) ~= true then

        HOLY_ACCOUNT_RUNTIME.InventoryStatus =
            "Waiting for account connection"

        HolyAccountRefreshUI()

        return false
    end

    HOLY_ACCOUNT_RUNTIME.InventoryBusy =
        true

    HOLY_ACCOUNT_RUNTIME.InventoryStatus =
        "Scanning fruits and eggs..."

    HolyAccountRefreshUI()

    local scanOk,
        items,
        fingerprint,
        summary =
        pcall(
            HolyAccountBuildMailInventory
        )

    if scanOk ~= true
    or type(items) ~= "table"
    or type(fingerprint) ~= "string"
    or type(summary) ~= "table" then

        HOLY_ACCOUNT_RUNTIME.InventoryBusy =
            false

        HOLY_ACCOUNT_RUNTIME.InventoryStatus =
            "Inventory scan failed"

        HolyAccountRefreshUI()

        if notifyUser == true then

            HolyNotify(
                "HOLY Inventory",
                "Could not scan this account's fruits and eggs.",
                6
            )
        end

        return false
    end

    if #items > 5000 then

        HOLY_ACCOUNT_RUNTIME.InventoryBusy =
            false

        HOLY_ACCOUNT_RUNTIME.InventoryStatus =
            "Too many inventory rows to upload"

        HolyAccountRefreshUI()

        if notifyUser == true then

            HolyNotify(
                "HOLY Inventory",
                "This account has more than 5,000 fruit and egg inventory rows.",
                7
            )
        end

        return false
    end

    local now =
        os.time()

    local unchanged =
        fingerprint
        == HOLY_ACCOUNT_RUNTIME
            .InventoryFingerprint

    local recentlyUploaded =
        HOLY_ACCOUNT_RUNTIME
            .InventoryLastUpload > 0
        and now
            - HOLY_ACCOUNT_RUNTIME
                .InventoryLastUpload
            < 300

    if force ~= true
    and unchanged
    and recentlyUploaded then

        HOLY_ACCOUNT_RUNTIME.InventoryBusy =
            false

        HOLY_ACCOUNT_RUNTIME.InventoryFruitCount =
            summary.FruitCount

        HOLY_ACCOUNT_RUNTIME.InventoryEggCount =
            summary.EggCount

        HOLY_ACCOUNT_RUNTIME.InventoryItemRows =
            summary.ItemRows

        HOLY_ACCOUNT_RUNTIME.InventoryStatus =
            HolyAccountInventoryDescription(
                summary
            )
            .. " synced"

        HolyAccountRefreshUI()

        return true
    end

    HOLY_ACCOUNT_RUNTIME.InventoryStatus =
        "Uploading "
        .. HolyAccountInventoryDescription(
            summary
        )
        .. "..."

    HolyAccountRefreshUI()

    local statusCode,
        data,
        requestError =
        HolyAccountRequest(
            "/api/account/mail/inventory",
            "POST",
            {
                roblox_user_id =
                    tostring(
                        LocalPlayer.UserId
                    ),

                revision =
                    tostring(
                        LocalPlayer.UserId
                    )
                    .. "-"
                    .. tostring(
                        now
                    )
                    .. "-"
                    .. tostring(
                        #items
                    ),

                captured_at =
                    now,

                items =
                    items,
            },
            token
        )

    HOLY_ACCOUNT_RUNTIME.InventoryBusy =
        false

    if statusCode == 200
    and type(data) == "table"
    and data.ok == true then

        HOLY_ACCOUNT_RUNTIME.InventoryFingerprint =
            fingerprint

        HOLY_ACCOUNT_RUNTIME.InventoryLastUpload =
            now

        HOLY_ACCOUNT_RUNTIME.InventoryFruitCount =
            summary.FruitCount

        HOLY_ACCOUNT_RUNTIME.InventoryEggCount =
            summary.EggCount

        HOLY_ACCOUNT_RUNTIME.InventoryItemRows =
            summary.ItemRows

        HOLY_ACCOUNT_RUNTIME.InventoryStatus =
            HolyAccountInventoryDescription(
                summary
            )
            .. " synced"

        HolyAccountRefreshUI()

        if notifyUser == true then

            HolyNotify(
                "HOLY Inventory",
                "Uploaded "
                .. HolyAccountInventoryDescription(
                    summary
                )
                .. " to HOLY HUB.",
                5
            )
        end

        return true
    end

    local message =
        requestError
        or HolyAccountInventoryFriendlyError(
            type(data) == "table"
            and data.error
            or "inventory_sync_failed"
        )

    HOLY_ACCOUNT_RUNTIME.InventoryStatus =
        "Sync failed: "
        .. tostring(
            message
        )

    HolyAccountRefreshUI()

    if notifyUser == true then

        HolyNotify(
            "HOLY Inventory",
            message,
            7
        )
    end

    return false
end

function HolyAccountQueueMailInventorySync(
    force,
    notifyUser
)

    if HOLY_ACCOUNT_RUNTIME.InventoryBusy == true then

        return false
    end

    local now =
        os.clock()

    if force ~= true
    and now
        - (
            tonumber(
                HOLY_ACCOUNT_RUNTIME
                    .InventoryLastScanClock
            )
            or 0
        )
        < 10 then

        return false
    end

    HOLY_ACCOUNT_RUNTIME.InventoryLastScanClock =
        now

    task.spawn(function()

        HolyAccountSendMailInventory(
            force,
            notifyUser
        )
    end)

    return true
end

function HolyAccountMailJobSetStatus(value)

    HOLY_ACCOUNT_RUNTIME.MailJobStatus =
        tostring(value or "Watching for queued orders")

    HolyAccountRefreshUI()
end

function HolyAccountMailJobGetPacket()

    local sharedModules =
        ReplicatedStorage:FindFirstChild("SharedModules")

    local networkingModule =
        sharedModules
        and sharedModules:FindFirstChild("Networking")

    if not networkingModule
    or not networkingModule:IsA("ModuleScript") then

        return nil,
            "SharedModules.Networking was not found"
    end

    local ok, networking =
        pcall(require, networkingModule)

    local packet =
        ok
        and type(networking) == "table"
        and type(networking.Mailbox) == "table"
        and networking.Mailbox.SendBatch
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return nil,
            "Networking.Mailbox.SendBatch is unavailable"
    end

    return packet
end

function HolyAccountMailJobLocalInventory()

    local ok, items =
        pcall(HolyAccountBuildMailInventory)

    if not ok
    or type(items) ~= "table" then

        return nil,
            "Could not scan the current inventory"
    end

    local itemMap = {}

    for _, item in ipairs(items) do

        if type(item) == "table" then

            local id =
                HolyCleanText(item.client_item_id)

            if id ~= "" then
                itemMap[id] = item
            end
        end
    end

    return itemMap
end

function HolyAccountMailJobBuildBatch(job)

    if type(job) ~= "table"
    or type(job.recipient) ~= "table"
    or type(job.items) ~= "table" then

        return nil,
            "The claimed mail job was malformed",
            "failed"
    end

    local recipientUserId =
        math.floor(
            tonumber(job.recipient.roblox_user_id)
            or 0
        )

    if recipientUserId <= 0
    or recipientUserId == LocalPlayer.UserId then

        return nil,
            "The mail recipient is invalid",
            "failed"
    end

    if #job.items < 1
    or #job.items > 20 then

        return nil,
            "The claimed mail job has an invalid row count",
            "failed"
    end

    local localItems, scanError =
        HolyAccountMailJobLocalInventory()

    if type(localItems) ~= "table" then

        return nil,
            scanError or "Inventory scan failed",
            "retry"
    end

    local batch = {
        RecipientUserId = recipientUserId,

        RecipientName =
            HolyCleanText(
                job.recipient.roblox_username
                or job.recipient.alias
            ),

        Payload = {},
        Before = {},
        Required = {},
        Total = 0,
    }

    for _, jobItem in ipairs(job.items) do

        if type(jobItem) ~= "table" then
            return nil,
                "One claimed mail row was malformed",
                "failed"
        end

        local id =
            HolyCleanText(jobItem.client_item_id)

        local quantity =
            math.floor(
                tonumber(jobItem.quantity)
                or 0
            )

        local localItem =
            localItems[id]

        local available =
            type(localItem) == "table"
            and math.max(
                0,
                math.floor(
                    tonumber(localItem.quantity)
                    or 0
                )
            )
            or 0

        if id == ""
        or quantity <= 0 then

            return nil,
                "One claimed mail row was invalid",
                "failed"
        end

        if available < quantity then

            return nil,
                tostring(jobItem.item_name or "A selected item")
                .. " is no longer available in the requested quantity",
                "failed"
        end

        if localItem.is_favorited == true
        and jobItem.allow_favorited ~= true then

            return nil,
                tostring(jobItem.item_name or "A selected item")
                .. " is now favorited and protected",
                "failed"
        end

        local metadata =
            type(localItem.metadata) == "table"
            and localItem.metadata
            or {}

        local category =
            HolyCleanText(
                metadata.mail_category
                or jobItem.mail_category
            )

        local itemKey =
            HolyCleanText(
                metadata.mail_item_key
                or jobItem.mail_item_key
            )

        if category ~= "HarvestedFruits"
        and category ~= "Eggs" then

            return nil,
                "One selected item has an unsupported mail category",
                "failed"
        end

        if itemKey == "" then
            return nil,
                "One selected item is missing its in-game mail key",
                "failed"
        end

        table.insert(
            batch.Payload,
            {
                ItemKey = itemKey,
                Count = quantity,
                Category = category,
            }
        )

        batch.Before[id] = available

        batch.Required[id] =
            (batch.Required[id] or 0)
            + quantity

        batch.Total =
            batch.Total
            + quantity
    end

    return batch
end

function HolyAccountMailJobWaitForRemoval(batch)

    local deadline =
        os.clock()
        + HOLY_ACCOUNT_MAIL_CONFIRM_TIMEOUT

    repeat

        local currentItems =
            HolyAccountMailJobLocalInventory()

        if type(currentItems) == "table" then

            local complete = true

            for id, required in pairs(batch.Required) do

                local currentItem =
                    currentItems[id]

                local current =
                    type(currentItem) == "table"
                    and math.max(
                        0,
                        math.floor(
                            tonumber(currentItem.quantity)
                            or 0
                        )
                    )
                    or 0

                if current
                    > math.max(
                        0,
                        (batch.Before[id] or 0)
                            - required
                    )
                then
                    complete = false
                    break
                end
            end

            if complete then
                return true
            end
        end

        task.wait(0.2)

    until os.clock() >= deadline

    return false
end

function HolyAccountMailJobReport(
    claimId,
    result,
    errorText
)

    local statusCode, data, requestError =
        HolyAccountRequest(
            "/api/account/mail/jobs/report",
            "POST",
            {
                roblox_user_id =
                    tostring(LocalPlayer.UserId),

                claim_id = claimId,
                result = result,

                error =
                    tostring(errorText or ""):sub(1, 500),
            },
            HOLY_ACCOUNT_RUNTIME.Token
        )

    if statusCode == 200
    and type(data) == "table"
    and data.ok == true then
        return true
    end

    if statusCode == 409
    and type(data) == "table"
    and data.error == "mail_claim_not_found" then
        return true
    end

    return false,
        requestError
        or HolyAccountFriendlyError(
            type(data) == "table"
            and data.error
            or "mail_job_result_failed"
        )
end

function HolyAccountMailJobSubmitResult(
    claimId,
    result,
    errorText
)

    HOLY_ACCOUNT_RUNTIME.MailJobPendingReport = {
        ClaimId = claimId,
        Result = result,
        Error = tostring(errorText or ""),
    }

    local reported, reportError =
        HolyAccountMailJobReport(
            claimId,
            result,
            errorText
        )

    if reported then
        HOLY_ACCOUNT_RUNTIME.MailJobPendingReport = nil
        return true
    end

    HolyAccountMailJobSetStatus(
        "Result saved; API report retry pending: "
        .. tostring(reportError or "service unavailable")
    )

    return false
end

function HolyAccountMailJobRetryPendingReport()

    local pending =
        HOLY_ACCOUNT_RUNTIME.MailJobPendingReport

    if type(pending) ~= "table" then
        return true
    end

    local reported, reportError =
        HolyAccountMailJobReport(
            pending.ClaimId,
            pending.Result,
            pending.Error
        )

    if not reported then

        HolyAccountMailJobSetStatus(
            "Waiting to report the previous result: "
            .. tostring(reportError or "service unavailable")
        )

        return false
    end

    local wasSent =
        pending.Result == "sent"

    HOLY_ACCOUNT_RUNTIME.MailJobPendingReport = nil

    if wasSent then
        HolyAccountQueueMailInventorySync(true, false)
    end

    HolyAccountMailJobSetStatus(
        wasSent
        and "Previous delivery reported successfully"
        or "Previous order result reported successfully"
    )

    return true
end

function HolyAccountMailJobRecordAccepted()

    HOLY_ACCOUNT_RUNTIME.MailJobNextSendClock =
        os.clock()
        + HOLY_ACCOUNT_MAIL_SEND_COOLDOWN

    if type(HolyMailCheckDay) == "function" then
        pcall(HolyMailCheckDay)
    end

    if type(HOLY_MAIL_STATE) == "table" then

        HOLY_MAIL_STATE.TrackerUsed =
            math.clamp(
                math.floor(
                    tonumber(HOLY_MAIL_STATE.TrackerUsed)
                    or 0
                )
                + 1,
                0,
                50
            )

        if type(HolyMailSaveSettings) == "function" then
            pcall(HolyMailSaveSettings)
        end
    end

    if type(HOLY_MAIL_RUNTIME) == "table"
    and type(HOLY_MAIL_RUNTIME.UpdateQuota) == "function" then
        pcall(HOLY_MAIL_RUNTIME.UpdateQuota)
    end
end

function HolyAccountProcessMailJob()

    if HOLY_ACCOUNT_RUNTIME.MailJobBusy == true
    or HOLY_ACCOUNT_RUNTIME.Status ~= "Online"
    or HOLY_ACCOUNT_RUNTIME.InventoryBusy == true
    or HOLY_ACCOUNT_RUNTIME.HeartbeatBusy == true
    or HOLY_ACCOUNT_RUNTIME.PairingBusy == true then
        return false
    end

    local deliveryState =
        type(HOLY_MAIL_RUNTIME) == "table"
        and HOLY_MAIL_RUNTIME.DeliveryState
        or nil

    if type(deliveryState) == "table"
    and deliveryState.Running == true then

        HolyAccountMailJobSetStatus(
            "Waiting for the current manual delivery"
        )

        return false
    end

    if os.clock()
        < (HOLY_ACCOUNT_RUNTIME.MailJobNextSendClock or 0)
    then
        return false
    end

    HOLY_ACCOUNT_RUNTIME.MailJobBusy = true

    local activeClaimId = ""

    local processOk, processError =
        xpcall(
            function()

                if not HolyAccountMailJobRetryPendingReport() then
                    return
                end

                local packet, packetError =
                    HolyAccountMailJobGetPacket()

                if not packet then
                    HolyAccountMailJobSetStatus(packetError)
                    return
                end

                HolyAccountMailJobSetStatus(
                    "Checking for queued orders..."
                )

                local statusCode, data, requestError =
                    HolyAccountRequest(
                        "/api/account/mail/jobs/claim",
                        "POST",
                        {
                            roblox_user_id =
                                tostring(LocalPlayer.UserId),
                        },
                        HOLY_ACCOUNT_RUNTIME.Token
                    )

                if statusCode ~= 200
                or type(data) ~= "table"
                or data.ok ~= true then

                    HolyAccountMailJobSetStatus(
                        "Order check failed: "
                        .. tostring(
                            requestError
                            or HolyAccountFriendlyError(
                                type(data) == "table"
                                and data.error
                                or "mail_job_claim_failed"
                            )
                        )
                    )

                    return
                end

                if type(data.job) ~= "table" then
                    HolyAccountMailJobSetStatus(
                        "Watching for queued orders"
                    )

                    return
                end

                activeClaimId =
                    HolyCleanText(data.job.claim_id)

                if activeClaimId == "" then
                    error("Claimed order has no claim ID")
                end

                local batch, batchError, invalidResult =
                    HolyAccountMailJobBuildBatch(data.job)

                if type(batch) ~= "table" then

                    HolyAccountMailJobSubmitResult(
                        activeClaimId,
                        invalidResult == "retry"
                            and "retry"
                            or "failed",
                        batchError or "Inventory validation failed"
                    )

                    activeClaimId = ""

                    HolyAccountMailJobSetStatus(
                        "Order not sent: "
                        .. tostring(batchError)
                    )

                    return
                end

                deliveryState =
                    type(HOLY_MAIL_RUNTIME) == "table"
                    and HOLY_MAIL_RUNTIME.DeliveryState
                    or nil

                if type(deliveryState) == "table"
                and deliveryState.Running == true then

                    HolyAccountMailJobSubmitResult(
                        activeClaimId,
                        "retry",
                        "A manual delivery started"
                    )

                    activeClaimId = ""
                    return
                end

                local recipientName =
                    batch.RecipientName ~= ""
                    and batch.RecipientName
                    or tostring(batch.RecipientUserId)

                HolyAccountMailJobSetStatus(
                    "Sending "
                    .. tostring(batch.Total)
                    .. (batch.Total == 1 and " item" or " items")
                    .. " to "
                    .. recipientName
                    .. "..."
                )

                local fireOk, accepted, serverMessage =
                    pcall(function()

                        return packet:Fire(
                            batch.RecipientUserId,
                            batch.Payload,
                            "Created from HOLY HUB"
                        )
                    end)

                if not fireOk then

                    HolyAccountMailJobSubmitResult(
                        activeClaimId,
                        "uncertain",
                        "Mailbox call ended without a confirmed result: "
                        .. tostring(accepted)
                    )

                    activeClaimId = ""

                    HolyAccountMailJobSetStatus(
                        "Delivery paused because its result is uncertain"
                    )

                    return
                end

                local responseText =
                    tostring(serverMessage or "")

                if accepted == true then

                    HolyAccountMailJobRecordAccepted()

                    if not HolyAccountMailJobWaitForRemoval(batch) then

                        HolyAccountMailJobSubmitResult(
                            activeClaimId,
                            "uncertain",
                            "Server accepted the mail, but inventory removal was not confirmed"
                        )

                        activeClaimId = ""

                        HolyAccountMailJobSetStatus(
                            "Mail accepted; confirmation paused for safety"
                        )

                        return
                    end

                    local reported =
                        HolyAccountMailJobSubmitResult(
                            activeClaimId,
                            "sent",
                            ""
                        )

                    activeClaimId = ""

                    if reported then
                        HolyAccountQueueMailInventorySync(
                            true,
                            false
                        )
                    end

                    HolyAccountMailJobSetStatus(
                        reported
                        and (
                            "Delivered "
                            .. tostring(batch.Total)
                            .. (
                                batch.Total == 1
                                and " item"
                                or " items"
                            )
                            .. " to "
                            .. recipientName
                        )
                        or "Delivery confirmed; API report retry pending"
                    )

                    return
                end

                local waitSeconds =
                    tonumber(
                        responseText:lower():match(
                            "wait%s+(%d+)%s*s"
                        )
                    )

                if waitSeconds then

                    HOLY_ACCOUNT_RUNTIME.MailJobNextSendClock =
                        os.clock()
                        + waitSeconds
                        + 0.25

                    HolyAccountMailJobSubmitResult(
                        activeClaimId,
                        "retry",
                        responseText ~= ""
                            and responseText
                            or "Mailbox cooldown"
                    )

                    activeClaimId = ""

                    HolyAccountMailJobSetStatus(
                        "Mailbox cooldown; retrying safely"
                    )

                    return
                end

                HolyAccountMailJobSubmitResult(
                    activeClaimId,
                    "failed",
                    responseText ~= ""
                        and responseText
                        or "The server rejected this mail"
                )

                activeClaimId = ""

                HolyAccountMailJobSetStatus(
                    "Order failed: "
                    .. (
                        responseText ~= ""
                        and responseText
                        or "server rejected the mail"
                    )
                )
            end,
            function(value)

                return tostring(value)
            end
        )

    if not processOk then

        if activeClaimId ~= "" then

            HolyAccountMailJobSubmitResult(
                activeClaimId,
                "uncertain",
                "Processor error after claim: "
                .. tostring(processError)
            )
        end

        HolyAccountMailJobSetStatus(
            "Order processor paused: "
            .. tostring(processError)
        )
    end

    HOLY_ACCOUNT_RUNTIME.MailJobBusy = false

    HolyAccountRefreshUI()

    return processOk == true
end

function HolyAccountStartMailJobWorker(generation)

    task.spawn(function()

        task.wait(2)

        while HOLY_ACCOUNT_RUNTIME.Active == true
        and HOLY_ACCOUNT_RUNTIME.Generation == generation do

            if HOLY_ACCOUNT_RUNTIME.Status == "Online" then

                HolyAccountProcessMailJob()
            end

            local elapsed = 0

            while elapsed < HOLY_ACCOUNT_MAIL_JOB_INTERVAL
            and HOLY_ACCOUNT_RUNTIME.Active == true
            and HOLY_ACCOUNT_RUNTIME.Generation == generation do

                task.wait(0.5)

                elapsed =
                    elapsed
                    + 0.5
            end
        end
    end)
end

function HolyAccountRefreshUI()

    local ui =
        HOLY_ACCOUNT_RUNTIME.UI
        or {}

    local status =
        tostring(
            HOLY_ACCOUNT_RUNTIME.Status
            or "Not connected"
        )

    if ui.StatusLabel
    and type(ui.StatusLabel.SetText) == "function" then

        ui.StatusLabel:SetText(
            "Status: "
            .. status
        )
    end

    local account =
        HOLY_ACCOUNT_RUNTIME.Account

    local username =
        type(account) == "table"
        and HolyCleanText(
            account.roblox_username
            or account.RobloxUsername
        )
        or ""

    local alias =
        type(account) == "table"
        and HolyCleanText(
            account.alias
            or account.Alias
        )
        or ""

    local displayName =
        alias ~= ""
        and alias
        or username

    if alias ~= ""
    and username ~= "" then

        displayName =
            alias
            .. " (@"
            .. username
            .. ")"
    end

    if displayName == "" then

        displayName =
            "Not linked"
    end

    if ui.AccountLabel
    and type(ui.AccountLabel.SetText) == "function" then

        ui.AccountLabel:SetText(
            "Account: "
            .. displayName
        )
    end

    if ui.DetailLabel
    and type(ui.DetailLabel.SetText) == "function" then

        ui.DetailLabel:SetText(
            tostring(
                HOLY_ACCOUNT_RUNTIME.Message
                or ""
            )
        )
    end

    if ui.InventoryLabel
    and type(ui.InventoryLabel.SetText) == "function" then

        ui.InventoryLabel:SetText(
            "Inventory: "
            .. tostring(
                HOLY_ACCOUNT_RUNTIME.InventoryStatus
                or "Waiting for account connection"
            )
        )
    end

    if ui.MailJobLabel
    and type(ui.MailJobLabel.SetText) == "function" then

        ui.MailJobLabel:SetText(
            "Mail Orders: "
            .. tostring(
                HOLY_ACCOUNT_RUNTIME.MailJobStatus
                or "Waiting for account connection"
            )
        )
    end

    local inventoryDisabled =
        HolyAccountTokenValid(
            HOLY_ACCOUNT_RUNTIME.Token
        ) ~= true
        or HOLY_ACCOUNT_RUNTIME.InventoryBusy == true
        or HOLY_ACCOUNT_RUNTIME.PairingBusy == true

    if ui.SyncInventoryButton
    and type(ui.SyncInventoryButton.SetDisabled) == "function" then

        ui.SyncInventoryButton:SetDisabled(
            inventoryDisabled
        )
    end

    local heartbeatDisabled =
        HolyAccountTokenValid(
            HOLY_ACCOUNT_RUNTIME.Token
        ) ~= true
        or HOLY_ACCOUNT_RUNTIME.HeartbeatBusy == true
        or HOLY_ACCOUNT_RUNTIME.PairingBusy == true

    if ui.RefreshButton
    and type(ui.RefreshButton.SetDisabled) == "function" then

        ui.RefreshButton:SetDisabled(
            heartbeatDisabled
        )
    end

    local pairingDisabled =
        HOLY_ACCOUNT_RUNTIME.PairingBusy == true
        or HOLY_ACCOUNT_RUNTIME.HeartbeatBusy == true
        or status == "Online"

    if ui.ConnectButton
    and type(ui.ConnectButton.SetDisabled) == "function" then

        ui.ConnectButton:SetDisabled(
            pairingDisabled
        )
    end

    if ui.PairingInput
    and type(ui.PairingInput.SetDisabled) == "function" then

        ui.PairingInput:SetDisabled(
            pairingDisabled
        )
    end
end

function HolyAccountStopHeartbeat(reason)

    HOLY_ACCOUNT_RUNTIME.Active =
        false

    HOLY_ACCOUNT_RUNTIME.Generation =
        HOLY_ACCOUNT_RUNTIME.Generation
        + 1

    if reason ~= "unload"
    and reason ~= "replace" then

        HolyAccountRefreshUI()
    end
end

function HolyAccountSendHeartbeat(notifyUser)

    if HOLY_ACCOUNT_RUNTIME.HeartbeatBusy == true
    or HOLY_ACCOUNT_RUNTIME.PairingBusy == true then

        return false
    end

    local token =
        HOLY_ACCOUNT_RUNTIME.Token

    if HolyAccountTokenValid(
        token
    ) ~= true then

        HOLY_ACCOUNT_RUNTIME.Status =
            "Not connected"

        HOLY_ACCOUNT_RUNTIME.Message =
            "Generate a pairing code on HOLY HUB to connect this Roblox account."

        HolyAccountRefreshUI()

        return false
    end

    HOLY_ACCOUNT_RUNTIME.HeartbeatBusy =
        true

    if HOLY_ACCOUNT_RUNTIME.Status ~= "Online" then

        HOLY_ACCOUNT_RUNTIME.Status =
            "Checking"

        HOLY_ACCOUNT_RUNTIME.Message =
            "Authenticating the saved account..."
    end

    HolyAccountRefreshUI()

    local statusCode,
        data,
        requestError =
        HolyAccountRequest(
            "/api/account/heartbeat",
            "POST",
            {
                roblox_user_id =
                    tostring(
                        LocalPlayer.UserId
                    ),

                roblox_username =
                    LocalPlayer.Name,
            },
            token
        )

    HOLY_ACCOUNT_RUNTIME.HeartbeatBusy =
        false

    if statusCode == 200
    and type(data) == "table"
    and data.ok == true
    and type(data.account) == "table" then

        HOLY_ACCOUNT_RUNTIME.Account =
            data.account

        HOLY_ACCOUNT_RUNTIME.Status =
            "Online"

        local nextIn =
            type(data.heartbeat) == "table"
            and tonumber(
                data.heartbeat.next_in
            )
            or HOLY_ACCOUNT_HEARTBEAT_INTERVAL

        HOLY_ACCOUNT_RUNTIME.Interval =
            math.clamp(
                nextIn
                or HOLY_ACCOUNT_HEARTBEAT_INTERVAL,
                10,
                60
            )

        HOLY_ACCOUNT_RUNTIME.Message =
            "Automatic heartbeat every "
            .. tostring(
                math.floor(
                    HOLY_ACCOUNT_RUNTIME.Interval
                    + 0.5
                )
            )
            .. " seconds."

        HOLY_ACCOUNT_RUNTIME.LastHeartbeat =
            os.time()

        if HOLY_ACCOUNT_RUNTIME.NeedsMigration == true then

            HolyAccountSaveToken(
                token
            )
        end

        HolyAccountRefreshUI()

        HolyAccountQueueMailInventorySync(
            false,
            false
        )

        if notifyUser == true then

            HolyNotify(
                "HOLY Account",
                "Connection verified for "
                .. tostring(
                    data.account.roblox_username
                    or LocalPlayer.Name
                )
                .. ".",
                4
            )
        end

        return true
    end

    local errorCode =
        type(data) == "table"
        and data.error
        or nil

    local message =
        requestError
        or HolyAccountFriendlyError(
            errorCode
            or (
                statusCode > 0
                and "request_failed"
                or "service_unreachable"
            )
        )

    if statusCode == 401
    and (
        errorCode == "account_token_required"
        or errorCode == "invalid_account_token"
        or errorCode == "account_token_revoked"
        or errorCode == "account_unlinked"
    ) then

        HolyAccountClearInvalidToken()

        HOLY_ACCOUNT_RUNTIME.Status =
            "Not connected"

        HOLY_ACCOUNT_RUNTIME.Message =
            message

    elseif statusCode == 403
    and errorCode == "account_identity_mismatch" then

        HolyAccountStopHeartbeat(
            "identity mismatch"
        )

        HOLY_ACCOUNT_RUNTIME.Status =
            "Wrong Roblox account"

        HOLY_ACCOUNT_RUNTIME.Message =
            "This saved login belongs to another Roblox account. Generate a fresh pairing code for "
            .. LocalPlayer.Name
            .. "."

        message =
            HOLY_ACCOUNT_RUNTIME.Message

    else

        HOLY_ACCOUNT_RUNTIME.Status =
            "Connection issue"

        HOLY_ACCOUNT_RUNTIME.Message =
            message
            .. " Retrying automatically."
    end

    HolyAccountRefreshUI()

    if notifyUser == true then

        HolyNotify(
            "HOLY Account",
            message,
            6
        )
    end

    return false
end

function HolyAccountStartHeartbeat()

    if HolyAccountTokenValid(
        HOLY_ACCOUNT_RUNTIME.Token
    ) ~= true then

        return false
    end

    if type(
        HolyGetRequestFunction()
    ) ~= "function" then

        HOLY_ACCOUNT_RUNTIME.Status =
            "Unsupported executor"

        HOLY_ACCOUNT_RUNTIME.Message =
            "This executor does not support HTTP requests."

        HolyAccountRefreshUI()

        return false
    end

    HolyAccountStopHeartbeat(
        "replace"
    )

    HOLY_ACCOUNT_RUNTIME.Active =
        true

    local generation =
        HOLY_ACCOUNT_RUNTIME.Generation

    task.spawn(function()

        while HOLY_ACCOUNT_RUNTIME.Active == true
        and HOLY_ACCOUNT_RUNTIME.Generation == generation do

            HolyAccountSendHeartbeat(
                false
            )

            local elapsed =
                0

            local interval =
                math.clamp(
                    tonumber(
                        HOLY_ACCOUNT_RUNTIME.Interval
                    )
                    or HOLY_ACCOUNT_HEARTBEAT_INTERVAL,
                    10,
                    60
                )

            while elapsed < interval
            and HOLY_ACCOUNT_RUNTIME.Active == true
            and HOLY_ACCOUNT_RUNTIME.Generation == generation do

                task.wait(
                    0.5
                )

                elapsed =
                    elapsed
                    + 0.5
            end
        end
    end)

    HolyAccountStartMailJobWorker(
        generation
    )

    return true
end

function HolyAccountNormalizePairingCode(value)

    local compact =
        tostring(
            value
            or ""
        ):upper():gsub(
            "[^A-Z0-9]",
            ""
        )

    if #compact ~= 8
    or compact:match(
        "^[ABCDEFGHJKLMNPQRSTUVWXYZ23456789]+$"
    ) == nil then

        return nil
    end

    return compact:sub(1, 4)
        .. "-"
        .. compact:sub(5, 8)
end

function HolyAccountRedeemPairingCode(value)

    if HOLY_ACCOUNT_RUNTIME.PairingBusy == true
    or HOLY_ACCOUNT_RUNTIME.HeartbeatBusy == true then

        return false
    end

    if value == nil
    and HOLY_ACCOUNT_RUNTIME.UI.PairingInput then

        value =
            HOLY_ACCOUNT_RUNTIME.UI
                .PairingInput.Value
    end

    local code =
        HolyAccountNormalizePairingCode(
            value
        )

    if not code then

        HolyNotify(
            "HOLY Account",
            "Enter the 8-character code shown on HOLY HUB.",
            5
        )

        return false
    end

    HOLY_ACCOUNT_RUNTIME.PairingBusy =
        true

    HOLY_ACCOUNT_RUNTIME.Status =
        "Connecting"

    HOLY_ACCOUNT_RUNTIME.Message =
        "Redeeming the one-use pairing code..."

    HolyAccountRefreshUI()

    local statusCode,
        data,
        requestError =
        HolyAccountRequest(
            "/api/pairing/redeem",
            "POST",
            {
                code =
                    code,

                roblox_user_id =
                    tostring(
                        LocalPlayer.UserId
                    ),

                roblox_username =
                    LocalPlayer.Name,
            }
        )

    HOLY_ACCOUNT_RUNTIME.PairingBusy =
        false

    if statusCode == 201
    and type(data) == "table"
    and data.ok == true
    and HolyAccountTokenValid(
        data.account_token
    ) == true then

        local token =
            HolyCleanText(
                data.account_token
            )

        HOLY_ACCOUNT_RUNTIME.Token =
            token

        HOLY_ACCOUNT_RUNTIME.Account =
            type(data.account) == "table"
            and data.account
            or nil

        HOLY_ACCOUNT_RUNTIME.Status =
            "Checking"

        HOLY_ACCOUNT_ENVIRONMENT.HOLY_ACCOUNT_TOKEN =
            token

        local saved =
            HolyAccountSaveToken(
                token
            )

        HOLY_ACCOUNT_RUNTIME.Message =
            saved == true
            and "Account linked. Starting automatic heartbeats..."
            or "Account linked for this session, but this executor could not save the login."

        local pairingInput =
            HOLY_ACCOUNT_RUNTIME.UI.PairingInput

        if pairingInput
        and type(pairingInput.SetValue) == "function" then

            pairingInput:SetValue(
                "",
                true
            )
        end

        HolyAccountRefreshUI()

        HolyNotify(
            "HOLY Account",
            saved == true
            and "Roblox account connected and saved."
            or "Roblox account connected for this session.",
            5
        )

        HolyAccountStartHeartbeat()

        return true
    end

    local message =
        requestError
        or HolyAccountFriendlyError(
            type(data) == "table"
            and data.error
            or "pairing_request_failed"
        )

    HOLY_ACCOUNT_RUNTIME.Status =
        HolyAccountTokenValid(
            HOLY_ACCOUNT_RUNTIME.Token
        ) == true
        and "Connection paused"
        or "Not connected"

    HOLY_ACCOUNT_RUNTIME.Message =
        message

    HolyAccountRefreshUI()

    HolyNotify(
        "HOLY Account",
        message,
        6
    )

    return false
end

function HolySaveUISettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local payload = {
        ShowUIOnLoad =
            HOLY_DEV_UI_STATE.ShowUIOnLoad == true,

        AutoCloseUI =
            HOLY_DEV_UI_STATE.ShowUIOnLoad ~= true,

        DPIScale =
            tonumber(
                HOLY_DEV_UI_STATE.DPIScale
            )
            or 100,

        PerformanceMonitor =
            HOLY_DEV_UI_STATE.PerformanceMonitor
            == true,

        PerformanceMonitorX =
            math.floor(
                (
                    tonumber(
                        HOLY_DEV_UI_STATE.PerformanceMonitorX
                    )
                    or 12
                )
                + 0.5
            ),

        PerformanceMonitorY =
            math.floor(
                (
                    tonumber(
                        HOLY_DEV_UI_STATE.PerformanceMonitorY
                    )
                    or 12
                )
                + 0.5
            ),

        ThemeName =
            tostring(
                HOLY_DEV_UI_STATE.ThemeName
                or "HOLY Red"
            ),

        InterfaceTransparency =
            math.clamp(
                tonumber(
                    HOLY_DEV_UI_STATE.InterfaceTransparency
                )
                or 0,
                0,
                70
            ),

        InterfaceAnimations =
            HOLY_DEV_UI_STATE.InterfaceAnimations
            ~= false,

        ShowHolyLoadingScreen =
            HOLY_DEV_UI_STATE.ShowHolyLoadingScreen
            ~= false,

        SettingsDashboard =
            tostring(
                HOLY_DEV_UI_STATE.SettingsDashboard
                or "Interface"
            ),

        TopLayerColorEnabled =
            HOLY_DEV_UI_STATE.TopLayerColorEnabled
            == true,

        TopLayerColor = {
            R =
                math.clamp(
                    math.floor(
                        tonumber(
                            HOLY_DEV_UI_STATE.TopLayerColor
                            and HOLY_DEV_UI_STATE.TopLayerColor.R
                        )
                        or 211
                    ),
                    0,
                    255
                ),

            G =
                math.clamp(
                    math.floor(
                        tonumber(
                            HOLY_DEV_UI_STATE.TopLayerColor
                            and HOLY_DEV_UI_STATE.TopLayerColor.G
                        )
                        or 190
                    ),
                    0,
                    255
                ),

            B =
                math.clamp(
                    math.floor(
                        tonumber(
                            HOLY_DEV_UI_STATE.TopLayerColor
                            and HOLY_DEV_UI_STATE.TopLayerColor.B
                        )
                        or 150
                    ),
                    0,
                    255
                ),
        },

        AutoSkipLoading =
            HOLY_DEV_UI_STATE.AutoSkipLoading == true,

        AntiAfk =
            HOLY_DEV_UI_STATE.AntiAfk == true,

        AntiKnockback =
            HOLY_DEV_UI_STATE.AntiKnockback == true,

        AntiWheelbarrow =
            HOLY_DEV_UI_STATE.AntiWheelbarrow == true,

        HideHarvestPrompts =
            HOLY_DEV_UI_STATE.HideHarvestPrompts == true,

        AutoFarmMiddle =
            HOLY_DEV_UI_STATE.AutoFarmMiddle == true,

        LowEndMode =
            HOLY_DEV_UI_STATE.LowEndMode == true,

        PerformanceMode =
            HOLY_DEV_UI_STATE.PerformanceMode == true,

        UnloadOtherGardens =
            HOLY_DEV_UI_STATE.UnloadOtherGardens == true,

        UnloadOwnGarden =
            HOLY_DEV_UI_STATE.UnloadOwnGarden == true,

        HideMiddle =
            HOLY_DEV_UI_STATE.HideMiddle == true,

        DeleteBackpack =
            HOLY_DEV_UI_STATE.DeleteBackpack == true,
    }

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        return false
    end

    local writeOk =
        pcall(function()

            writefile(
                UI_SETTINGS_FILE,
                encoded
            )
        end)

    return writeOk == true
end

function HolyLoadUISettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                UI_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                UI_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then

        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return false
    end

    if type(data.AutoCloseUI) == "boolean" then

        HOLY_DEV_UI_STATE.ShowUIOnLoad =
            data.AutoCloseUI ~= true

    elseif type(data.ShowUIOnLoad) == "boolean" then

        HOLY_DEV_UI_STATE.ShowUIOnLoad =
            data.ShowUIOnLoad
    end

    local scale =
        tonumber(
            data.DPIScale
        )

    if scale then

        HOLY_DEV_UI_STATE.DPIScale =
            math.clamp(
                math.floor(
                    scale + 0.5
                ),
                30,
                110
            )
    end

    if type(data.PerformanceMonitor) == "boolean" then

        HOLY_DEV_UI_STATE.PerformanceMonitor =
            data.PerformanceMonitor
    end

    local monitorX =
        tonumber(
            data.PerformanceMonitorX
        )

    if monitorX then

        HOLY_DEV_UI_STATE.PerformanceMonitorX =
            math.clamp(
                math.floor(
                    monitorX + 0.5
                ),
                -10000,
                10000
            )
    end

    local monitorY =
        tonumber(
            data.PerformanceMonitorY
        )

    if monitorY then

        HOLY_DEV_UI_STATE.PerformanceMonitorY =
            math.clamp(
                math.floor(
                    monitorY + 0.5
                ),
                -10000,
                10000
            )
    end

    local themeName =
        tostring(
            data.ThemeName
            or "HOLY Red"
        )

    if themeName == "Obsidian Red" then

        themeName =
            "HOLY Red"
    end

    HOLY_DEV_UI_STATE.ThemeName =
        themeName

    HOLY_DEV_UI_STATE.InterfaceTransparency =
        math.clamp(
            tonumber(
                data.InterfaceTransparency
            )
            or 0,
            0,
            70
        )

    if type(data.InterfaceAnimations) == "boolean" then

        HOLY_DEV_UI_STATE.InterfaceAnimations =
            data.InterfaceAnimations
    end

    if type(data.ShowHolyLoadingScreen) == "boolean" then

        HOLY_DEV_UI_STATE.ShowHolyLoadingScreen =
            data.ShowHolyLoadingScreen
    end

    local settingsDashboard =
        tostring(
            data.SettingsDashboard
            or "Interface"
        )

    if settingsDashboard ~= "Themes"
    and settingsDashboard ~= "Session"
    and settingsDashboard ~= "Performance"
    and settingsDashboard ~= "Account" then

        settingsDashboard =
            "Interface"
    end

    HOLY_DEV_UI_STATE.SettingsDashboard =
        settingsDashboard

    if type(data.TopLayerColorEnabled) == "boolean" then

        HOLY_DEV_UI_STATE.TopLayerColorEnabled =
            data.TopLayerColorEnabled
    end

    if type(data.TopLayerColor) == "table" then

        HOLY_DEV_UI_STATE.TopLayerColor = {
            R =
                math.clamp(
                    math.floor(
                        tonumber(
                            data.TopLayerColor.R
                            or data.TopLayerColor.r
                        )
                        or 211
                    ),
                    0,
                    255
                ),

            G =
                math.clamp(
                    math.floor(
                        tonumber(
                            data.TopLayerColor.G
                            or data.TopLayerColor.g
                        )
                        or 190
                    ),
                    0,
                    255
                ),

            B =
                math.clamp(
                    math.floor(
                        tonumber(
                            data.TopLayerColor.B
                            or data.TopLayerColor.b
                        )
                        or 150
                    ),
                    0,
                    255
                ),
        }
    end

    if type(data.AutoSkipLoading) == "boolean" then

        HOLY_DEV_UI_STATE.AutoSkipLoading =
            data.AutoSkipLoading
    end

    if type(data.AntiAfk) == "boolean" then

        HOLY_DEV_UI_STATE.AntiAfk =
            data.AntiAfk
    end

    if type(data.AntiKnockback) == "boolean" then

        HOLY_DEV_UI_STATE.AntiKnockback =
            data.AntiKnockback
    end

    if type(data.AntiWheelbarrow) == "boolean" then

        HOLY_DEV_UI_STATE.AntiWheelbarrow =
            data.AntiWheelbarrow
    end

    if type(data.HideHarvestPrompts) == "boolean" then

        HOLY_DEV_UI_STATE.HideHarvestPrompts =
            data.HideHarvestPrompts
    end

    if type(data.AutoFarmMiddle) == "boolean" then

        HOLY_DEV_UI_STATE.AutoFarmMiddle =
            data.AutoFarmMiddle
    end

    if type(data.LowEndMode) == "boolean" then

        HOLY_DEV_UI_STATE.LowEndMode =
            data.LowEndMode
    end

    if type(data.PerformanceMode) == "boolean" then

        HOLY_DEV_UI_STATE.PerformanceMode =
            data.PerformanceMode
    end

    if type(data.UnloadOtherGardens) == "boolean" then

        HOLY_DEV_UI_STATE.UnloadOtherGardens =
            data.UnloadOtherGardens

    elseif type(data.DeleteOtherGardens) == "boolean" then

        HOLY_DEV_UI_STATE.UnloadOtherGardens =
            data.DeleteOtherGardens
    end

    if type(data.UnloadOwnGarden) == "boolean" then

        HOLY_DEV_UI_STATE.UnloadOwnGarden =
            data.UnloadOwnGarden

    elseif type(data.DeleteOwnGarden) == "boolean" then

        HOLY_DEV_UI_STATE.UnloadOwnGarden =
            data.DeleteOwnGarden
    end

    if type(data.HideMiddle) == "boolean" then

        HOLY_DEV_UI_STATE.HideMiddle =
            data.HideMiddle

    elseif type(data.DeleteMiddle) == "boolean" then

        HOLY_DEV_UI_STATE.HideMiddle =
            data.DeleteMiddle

    elseif type(data.UnloadMiddle) == "boolean" then

        HOLY_DEV_UI_STATE.HideMiddle =
            data.UnloadMiddle
    end

    if type(data.DeleteBackpack) == "boolean" then

        HOLY_DEV_UI_STATE.DeleteBackpack =
            data.DeleteBackpack
    end

    return true
end


--==================================================
-- [2.005] TOP LAYER COLOR
--==================================================

local previousTopLayerRuntime =
    type(HOLY_TOP_LAYER_RUNTIME) == "table"
    and HOLY_TOP_LAYER_RUNTIME
    or nil

if previousTopLayerRuntime
and previousTopLayerRuntime.WatchConnection then

    pcall(function()

        previousTopLayerRuntime.WatchConnection:Disconnect()
    end)
end

HOLY_TOP_LAYER_RUNTIME = {
    OriginalColors =
        previousTopLayerRuntime
        and previousTopLayerRuntime.OriginalColors
        or setmetatable(
            {},
            {
                __mode = "k",
            }
        ),

    PrimaryOriginal =
        previousTopLayerRuntime
        and previousTopLayerRuntime.PrimaryOriginal
        or nil,

    WatchConnection = nil,
    ApplyGeneration = 0,
    SaveGeneration = 0,
}

function HolyTopLayerGetParts()

    local baseplate =
        workspace:FindFirstChild(
            "Baseplate"
        )

    local topLayer =
        baseplate
        and baseplate:FindFirstChild(
            "TopLayer"
        )
        or nil

    local parts = {}

    if not topLayer then

        return parts,
            nil
    end

    if topLayer:IsA("BasePart") then

        table.insert(
            parts,
            topLayer
        )

    else

        for _, descendant in ipairs(
            topLayer:GetDescendants()
        ) do

            if descendant:IsA("BasePart") then

                table.insert(
                    parts,
                    descendant
                )
            end
        end
    end

    return parts,
        topLayer
end

function HolyTopLayerGetSavedColor()

    local saved =
        type(HOLY_DEV_UI_STATE.TopLayerColor) == "table"
        and HOLY_DEV_UI_STATE.TopLayerColor
        or {}

    return Color3.fromRGB(
        math.clamp(
            math.floor(
                tonumber(saved.R)
                or 211
            ),
            0,
            255
        ),

        math.clamp(
            math.floor(
                tonumber(saved.G)
                or 190
            ),
            0,
            255
        ),

        math.clamp(
            math.floor(
                tonumber(saved.B)
                or 150
            ),
            0,
            255
        )
    )
end

function HolyTopLayerCaptureOriginal()

    local parts =
        HolyTopLayerGetParts()

    for _, part in ipairs(parts) do

        if HOLY_TOP_LAYER_RUNTIME.OriginalColors[
            part
        ] == nil then

            HOLY_TOP_LAYER_RUNTIME.OriginalColors[
                part
            ] =
                part.Color
        end

        if HOLY_TOP_LAYER_RUNTIME.PrimaryOriginal == nil then

            HOLY_TOP_LAYER_RUNTIME.PrimaryOriginal =
                HOLY_TOP_LAYER_RUNTIME.OriginalColors[
                    part
                ]
        end
    end

    return #parts > 0
end

function HolyTopLayerRestore()

    local parts =
        HolyTopLayerGetParts()

    for _, part in ipairs(parts) do

        local original =
            HOLY_TOP_LAYER_RUNTIME.OriginalColors[
                part
            ]

        if typeof(original) == "Color3" then

            pcall(function()

                part.Color =
                    original
            end)
        end
    end

    return #parts > 0
end

function HolyTopLayerApply()

    HolyTopLayerCaptureOriginal()

    if HOLY_DEV_UI_STATE.TopLayerColorEnabled ~= true then

        return HolyTopLayerRestore()
    end

    local selectedColor =
        HolyTopLayerGetSavedColor()

    local parts =
        HolyTopLayerGetParts()

    for _, part in ipairs(parts) do

        pcall(function()

            part.Color =
                selectedColor
        end)
    end

    return #parts > 0
end

function HolyTopLayerQueueSave()

    HOLY_TOP_LAYER_RUNTIME.SaveGeneration +=
        1

    local generation =
        HOLY_TOP_LAYER_RUNTIME.SaveGeneration

    task.delay(
        0.3,
        function()

            if HOLY_TOP_LAYER_RUNTIME.SaveGeneration
                ~= generation
            then

                return
            end

            HolySaveUISettings()
        end
    )
end

function HolyTopLayerSetColor(value)

    if typeof(value) ~= "Color3" then

        return false
    end

    HOLY_DEV_UI_STATE.TopLayerColor = {
        R =
            math.clamp(
                math.floor(
                    value.R * 255
                    + 0.5
                ),
                0,
                255
            ),

        G =
            math.clamp(
                math.floor(
                    value.G * 255
                    + 0.5
                ),
                0,
                255
            ),

        B =
            math.clamp(
                math.floor(
                    value.B * 255
                    + 0.5
                ),
                0,
                255
            ),
    }

    if HOLY_DEV_UI_STATE.TopLayerColorEnabled == true then

        HolyTopLayerApply()
    end

    HolyTopLayerQueueSave()

    return true
end

function HolyTopLayerSetEnabled(value)

    HOLY_DEV_UI_STATE.TopLayerColorEnabled =
        value == true

    HolyTopLayerApply()
    HolySaveUISettings()

    return HOLY_DEV_UI_STATE.TopLayerColorEnabled
end

function HolyTopLayerReset()

    HolyTopLayerCaptureOriginal()

    local original =
        HOLY_TOP_LAYER_RUNTIME.PrimaryOriginal

    HOLY_DEV_UI_STATE.TopLayerColorEnabled =
        false

    if typeof(original) == "Color3" then

        HOLY_DEV_UI_STATE.TopLayerColor = {
            R =
                math.floor(
                    original.R * 255
                    + 0.5
                ),

            G =
                math.floor(
                    original.G * 255
                    + 0.5
                ),

            B =
                math.floor(
                    original.B * 255
                    + 0.5
                ),
        }
    end

    HolyTopLayerRestore()
    HolySaveUISettings()

    return original
end

function HolyTopLayerScheduleApply()

    HOLY_TOP_LAYER_RUNTIME.ApplyGeneration +=
        1

    local generation =
        HOLY_TOP_LAYER_RUNTIME.ApplyGeneration

    task.delay(
        0.1,
        function()

            if HOLY_TOP_LAYER_RUNTIME.ApplyGeneration
                ~= generation
            then

                return
            end

            HolyTopLayerApply()
        end
    )
end

function HolyTopLayerStart()

    HolyTopLayerApply()

    if HOLY_TOP_LAYER_RUNTIME.WatchConnection then

        HOLY_TOP_LAYER_RUNTIME.WatchConnection:Disconnect()
    end

    HOLY_TOP_LAYER_RUNTIME.WatchConnection =
        workspace.DescendantAdded:Connect(function(instance)

            local current =
                instance

            while current
            and current ~= workspace
            do

                if current.Name == "TopLayer" then

                    local parent =
                        current.Parent

                    if parent
                    and parent.Name == "Baseplate"
                    and parent.Parent == workspace
                    then

                        HolyTopLayerScheduleApply()

                        return
                    end
                end

                current =
                    current.Parent
            end
        end)

    return true
end

function HolyTopLayerStop(restoreOriginal)

    if HOLY_TOP_LAYER_RUNTIME.WatchConnection then

        pcall(function()

            HOLY_TOP_LAYER_RUNTIME.WatchConnection:Disconnect()
        end)

        HOLY_TOP_LAYER_RUNTIME.WatchConnection =
            nil
    end

    if restoreOriginal == true then

        HolyTopLayerRestore()
    end

    return true
end


--==================================================
-- [2.01] PERFORMANCE MONITOR
--==================================================

local HOLY_PERFORMANCE_MONITOR_SCALE =
    0.8

function HolyPerformanceMonitorDisconnect()

    local runtime =
        HOLY_PERFORMANCE_MONITOR_RUNTIME

    local connections =
        runtime.Connections

    if type(connections) == "table" then

        for _, connection in pairs(connections) do

            if connection then

                pcall(function()

                    connection:Disconnect()
                end)
            end
        end
    end

    runtime.Connections =
        {}

    runtime.Dragging =
        false

    runtime.DragTouch =
        nil
end

function HolyPerformanceMonitorAddConnection(connection)

    if connection == nil then
        return nil
    end

    table.insert(
        HOLY_PERFORMANCE_MONITOR_RUNTIME.Connections,
        connection
    )

    return connection
end

function HolyPerformanceMonitorReadMemory()

    local success,
        value =
        pcall(function()

            return Stats:GetTotalMemoryUsageMb()
        end)

    value =
        tonumber(value)

    if success == true
    and value
    and value >= 0 then

        return value
    end

    return nil
end

function HolyPerformanceMonitorReadPing()

    local success,
        value =
        pcall(function()

            return Stats.Network.ServerStatsItem["Data Ping"]:GetValue()
        end)

    value =
        tonumber(value)

    if success == true
    and value
    and value >= 0 then

        return value
    end

    local fallbackSuccess,
        fallbackValue =
        pcall(function()

            return LocalPlayer:GetNetworkPing()
                * 1000
        end)

    fallbackValue =
        tonumber(fallbackValue)

    if fallbackSuccess == true
    and fallbackValue
    and fallbackValue >= 0 then

        return fallbackValue
    end

    return nil
end

function HolyPerformanceMonitorGetViewport()

    local camera =
        workspace.CurrentCamera

    if camera then

        local viewport =
            camera.ViewportSize

        if viewport.X > 0
        and viewport.Y > 0 then

            return viewport
        end
    end

    return Vector2.new(
        1920,
        1080
    )
end

function HolyPerformanceMonitorSetPosition(
    x,
    y,
    savePosition
)

    local runtime =
        HOLY_PERFORMANCE_MONITOR_RUNTIME

    local frame =
        runtime.Frame

    if typeof(frame) ~= "Instance"
    or frame.Parent == nil then

        return false
    end

    x =
        tonumber(x)
        or 12

    y =
        tonumber(y)
        or 12

    local viewport =
        HolyPerformanceMonitorGetViewport()

    local frameSize =
        frame.AbsoluteSize

    local renderedWidth =
        tonumber(frameSize.X)
        or 0

    local renderedHeight =
        tonumber(frameSize.Y)
        or 0

    if renderedWidth <= 0 then

        renderedWidth =
            frame.Size.X.Offset
            * HOLY_PERFORMANCE_MONITOR_SCALE
    end

    if renderedHeight <= 0 then

        renderedHeight =
            frame.Size.Y.Offset
            * HOLY_PERFORMANCE_MONITOR_SCALE
    end

    local maximumX =
        math.max(
            4,
            viewport.X
            - renderedWidth
            - 4
        )

    local maximumY =
        math.max(
            4,
            viewport.Y
            - renderedHeight
            - 4
        )

    x =
        math.floor(
            math.clamp(
                x,
                4,
                maximumX
            )
            + 0.5
        )

    y =
        math.floor(
            math.clamp(
                y,
                4,
                maximumY
            )
            + 0.5
        )

    frame.Position =
        UDim2.fromOffset(
            x,
            y
        )

    HOLY_DEV_UI_STATE.PerformanceMonitorX =
        x

    HOLY_DEV_UI_STATE.PerformanceMonitorY =
        y

    if savePosition == true then

        HolySaveUISettings()
    end

    return true
end

function HolyPerformanceMonitorRefresh()

    local runtime =
        HOLY_PERFORMANCE_MONITOR_RUNTIME

    local frame =
        runtime.Frame

    if runtime.Active ~= true
    or typeof(frame) ~= "Instance"
    or frame.Parent == nil then

        return false
    end

    local memory =
        HolyPerformanceMonitorReadMemory()

    local ping =
        HolyPerformanceMonitorReadPing()

    local memoryText =
        memory
        and tostring(
            math.floor(
                memory + 0.5
            )
        )
        or "--"

    local fpsText =
        runtime.FPS
        and tostring(
            math.floor(
                runtime.FPS + 0.5
            )
        )
        or "--"

    local pingText =
        ping
        and tostring(
            math.floor(
                ping + 0.5
            )
        )
        or "--"

    local text =
        memoryText
        .. " MB  |  "
        .. fpsText
        .. " fps  |  "
        .. pingText
        .. " ms"

    frame.Text =
        text

    local textSize =
        TextService:GetTextSize(
            text,
            frame.TextSize,
            frame.Font,
            Vector2.new(
                1000,
                42
            )
        )

    frame.Size =
        UDim2.fromOffset(
            textSize.X + 38,
            42
        )

    HolyPerformanceMonitorSetPosition(
        HOLY_DEV_UI_STATE.PerformanceMonitorX,
        HOLY_DEV_UI_STATE.PerformanceMonitorY,
        false
    )

    return true
end

function HolyPerformanceMonitorStop(destroyGui)

    local runtime =
        HOLY_PERFORMANCE_MONITOR_RUNTIME

    runtime.Active =
        false

    HolyPerformanceMonitorDisconnect()

    if destroyGui == true then

        local screenGui =
            runtime.ScreenGui

        runtime.ScreenGui =
            nil

        runtime.Frame =
            nil

        runtime.Scale =
            nil

        if typeof(screenGui) == "Instance" then

            pcall(function()

                screenGui:Destroy()
            end)
        end

    elseif typeof(runtime.ScreenGui) == "Instance" then

        runtime.ScreenGui.Enabled =
            false
    end

    runtime.Frames =
        0

    runtime.FPS =
        nil

    return true
end

function HolyPerformanceMonitorGetParent()

    local parent =
        nil

    if type(gethui) == "function" then

        pcall(function()

            parent =
                gethui()
        end)
    end

    if typeof(parent) ~= "Instance" then

        parent =
            CoreGui
    end

    return parent
end

function HolyPerformanceMonitorStart()

    if HOLY_DEV_UI_STATE.PerformanceMonitor
    ~= true then

        return false
    end

    local runtime =
        HOLY_PERFORMANCE_MONITOR_RUNTIME

    if runtime.Active == true
    and typeof(runtime.ScreenGui) == "Instance"
    and runtime.ScreenGui.Parent ~= nil then

        runtime.ScreenGui.Enabled =
            true

        return true
    end

    HolyPerformanceMonitorStop(
        true
    )

    local screenGui =
        Instance.new("ScreenGui")

    screenGui.Name =
        "HOLYPerformanceMonitor"

    screenGui.IgnoreGuiInset =
        true

    screenGui.ResetOnSpawn =
        false

    screenGui.DisplayOrder =
        999999

    screenGui.ZIndexBehavior =
        Enum.ZIndexBehavior.Sibling

    local parentSuccess =
        pcall(function()

            screenGui.Parent =
                HolyPerformanceMonitorGetParent()
        end)

    if parentSuccess ~= true
    or screenGui.Parent == nil then

        local playerGui =
            LocalPlayer:FindFirstChildOfClass(
                "PlayerGui"
            )
            or LocalPlayer:WaitForChild(
                "PlayerGui",
                5
            )

        if playerGui == nil then

            screenGui:Destroy()

            return false
        end

        screenGui.Parent =
            playerGui
    end

    local frame =
        Instance.new("TextLabel")

    frame.Name =
        "PerformanceMonitor"

    frame.Position =
        UDim2.fromOffset(
            tonumber(
                HOLY_DEV_UI_STATE.PerformanceMonitorX
            )
            or 12,
            tonumber(
                HOLY_DEV_UI_STATE.PerformanceMonitorY
            )
            or 12
        )

    frame.Size =
        UDim2.fromOffset(
            300,
            42
        )

    frame.BackgroundColor3 =
        Color3.fromRGB(
            13,
            13,
            15
        )

    frame.BackgroundTransparency =
        0

    frame.BorderSizePixel =
        0

    frame.Text =
        "-- MB  |  -- fps  |  -- ms"

    frame.TextColor3 =
        Color3.fromRGB(
            220,
            220,
            225
        )

    frame.TextTransparency =
        0

    frame.TextSize =
        16

    frame.Font =
        Enum.Font.GothamMedium

    frame.TextXAlignment =
        Enum.TextXAlignment.Center

    frame.Active =
        true

    frame.Selectable =
        false

    frame.ZIndex =
        100

    frame.Parent =
        screenGui

    local scale =
        Instance.new("UIScale")

    scale.Scale =
        HOLY_PERFORMANCE_MONITOR_SCALE

    scale.Parent =
        frame

    local corner =
        Instance.new("UICorner")

    corner.CornerRadius =
        UDim.new(
            0,
            8
        )

    corner.Parent =
        frame

    local stroke =
        Instance.new("UIStroke")

    stroke.Color =
        Color3.fromRGB(
            0,
            0,
            0
        )

    stroke.Thickness =
        3

    stroke.Transparency =
        0

    stroke.ApplyStrokeMode =
        Enum.ApplyStrokeMode.Border

    stroke.Parent =
        frame

    local padding =
        Instance.new("UIPadding")

    padding.PaddingLeft =
        UDim.new(
            0,
            16
        )

    padding.PaddingRight =
        UDim.new(
            0,
            16
        )

    padding.Parent =
        frame

    runtime.ScreenGui =
        screenGui

    runtime.Frame =
        frame

    runtime.Scale =
        scale

    runtime.Active =
        true

    runtime.Frames =
        0

    runtime.FPS =
        nil

    runtime.LastSampleAt =
        os.clock()

    HolyPerformanceMonitorAddConnection(
        frame.InputBegan:Connect(function(input)

            if runtime.Active ~= true then
                return
            end

            local inputType =
                input.UserInputType

            if inputType
                ~= Enum.UserInputType.MouseButton1
            and inputType
                ~= Enum.UserInputType.Touch then

                return
            end

            runtime.Dragging =
                true

            runtime.DragTouch =
                inputType
                == Enum.UserInputType.Touch
                and input
                or nil

            runtime.DragStart =
                input.Position

            runtime.DragStartPosition =
                frame.Position
        end)
    )

    HolyPerformanceMonitorAddConnection(
        UserInputService.InputChanged:Connect(function(input)

            if runtime.Active ~= true
            or runtime.Dragging ~= true then

                return
            end

            local inputType =
                input.UserInputType

            if inputType
                ~= Enum.UserInputType.MouseMovement
            and inputType
                ~= Enum.UserInputType.Touch then

                return
            end

            if inputType == Enum.UserInputType.Touch
            and runtime.DragTouch
            and input ~= runtime.DragTouch then

                return
            end

            local dragStart =
                runtime.DragStart

            local startingPosition =
                runtime.DragStartPosition

            if dragStart == nil
            or startingPosition == nil then

                return
            end

            local delta =
                input.Position
                - dragStart

            HolyPerformanceMonitorSetPosition(
                startingPosition.X.Offset
                + delta.X,
                startingPosition.Y.Offset
                + delta.Y,
                false
            )
        end)
    )

    HolyPerformanceMonitorAddConnection(
        UserInputService.InputEnded:Connect(function(input)

            if runtime.Dragging ~= true then
                return
            end

            local inputType =
                input.UserInputType

            if inputType
                ~= Enum.UserInputType.MouseButton1
            and inputType
                ~= Enum.UserInputType.Touch then

                return
            end

            if inputType == Enum.UserInputType.Touch
            and runtime.DragTouch
            and input ~= runtime.DragTouch then

                return
            end

            runtime.Dragging =
                false

            runtime.DragTouch =
                nil

            HolyPerformanceMonitorSetPosition(
                frame.Position.X.Offset,
                frame.Position.Y.Offset,
                true
            )
        end)
    )

    HolyPerformanceMonitorAddConnection(
        RunService.RenderStepped:Connect(function()

            if runtime.Active ~= true then
                return
            end

            runtime.Frames += 1

            local now =
                os.clock()

            local elapsed =
                now
                - runtime.LastSampleAt

            if elapsed < 1 then
                return
            end

            runtime.FPS =
                runtime.Frames
                / elapsed

            runtime.Frames =
                0

            runtime.LastSampleAt =
                now

            HolyPerformanceMonitorRefresh()
        end)
    )

    HolyPerformanceMonitorRefresh()

    task.defer(function()

        if runtime.Active == true then

            HolyPerformanceMonitorSetPosition(
                HOLY_DEV_UI_STATE.PerformanceMonitorX,
                HOLY_DEV_UI_STATE.PerformanceMonitorY,
                false
            )
        end
    end)

    return true
end

function HolyPerformanceMonitorSetEnabled(value)

    value =
        value == true

    HOLY_DEV_UI_STATE.PerformanceMonitor =
        value

    if value == true then

        HolyPerformanceMonitorStart()

    else

        HolyPerformanceMonitorStop(
            true
        )
    end

    HolySaveUISettings()

    return value
end

function HolyVisualReadNumberText(value, fallback, maxValue)

    local number =
        tonumber(
            tostring(value or "")
                :match("%d+%.?%d*")
        )

    if number == nil then

        number =
            tonumber(fallback)
            or 0
    end

    number =
        math.max(
            0,
            number
        )

    if maxValue ~= nil then

        number =
            math.min(
                number,
                tonumber(maxValue)
                or number
            )
    end

    if math.abs(number - math.floor(number)) < 0.001 then

        return tostring(
            math.floor(number)
        )
    end

    return tostring(
        math.floor(number * 100 + 0.5) / 100
    )
end

function HolyVisualNormalizeGardenFruitMode(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "only selected"
    or lower == "selected"
    or (
        lower:find("only", 1, true)
        and lower:find("selected", 1, true)
    ) then

        return "Only Selected"
    end

    if lower == "skip selected"
    or lower == "exclude selected"
    or lower:find("skip", 1, true)
    or lower:find("exclude", 1, true)
    or lower:find("ignore selected", 1, true) then

        return "Skip Selected"
    end

    return "All"
end

function HolyVisualNormalizeGardenFruitSelection(value)

    local raw =
        HolyShopSelectionArray(
            value
        )

    if #raw <= 0 then
        return {}
    end

    local validMap =
        {}

    if type(HolyFarmGetPlantValueMap) == "function" then

        validMap =
            HolyFarmGetPlantValueMap()
    end

    local output =
        {}

    local seen =
        {}

    for _, fruitName in ipairs(raw) do

        local normalized =
            ""

        if type(HolyFarmNormalizePlantName) == "function" then

            normalized =
                HolyFarmNormalizePlantName(
                    fruitName
                )

        else

            normalized =
                HolyCleanText(
                    fruitName
                )
        end

        if normalized ~= ""
        and normalized ~= "All"
        and seen[normalized] ~= true
        and (
            next(validMap) == nil
            or validMap[normalized] == true
        ) then

            seen[normalized] =
                true

            table.insert(
                output,
                normalized
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyVisualNormalizeGardenMutationMode(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "only mutated"
    or (
        lower:find("only", 1, true)
        and lower:find("mutat", 1, true)
    ) then

        return "Only Mutated"
    end

    if lower == "only selected"
    or (
        lower:find("only", 1, true)
        and lower:find("selected", 1, true)
    ) then

        return "Only Selected"
    end

    if lower == "skip selected"
    or lower:find("skip", 1, true)
    or lower:find("exclude", 1, true)
    or lower:find("ignore selected", 1, true) then

        return "Skip Selected"
    end

    return "All"
end

