function HolyVisualReadSprinklerESPScale(value)

    local text =
        tostring(value or "")
            :gsub("%%", "")

    local scale =
        tonumber(text)

    if type(scale) ~= "number"
    or scale ~= scale
    or scale == math.huge
    or scale == -math.huge then

        scale =
            80
    end

    return math.max(
        10,
        scale
    )
end

function HolyVisualEnsureState()

    HOLY_VISUAL_STATE =
        type(HOLY_VISUAL_STATE) == "table"
        and HOLY_VISUAL_STATE
        or {}

    HOLY_VISUAL_STATE.FruitValueOverlay =
        HOLY_VISUAL_STATE.FruitValueOverlay == true

    HOLY_VISUAL_STATE.FruitTotalValue =
        HOLY_VISUAL_STATE.FruitTotalValue == true

    HOLY_VISUAL_STATE.GardenFruitESP =
        HOLY_VISUAL_STATE.GardenFruitESP == true

    HOLY_VISUAL_STATE.SprinklerTimerESP =
        HOLY_VISUAL_STATE.SprinklerTimerESP == true

    HOLY_VISUAL_STATE.SprinklerTimerESPScale =
        tostring(
            HolyVisualReadSprinklerESPScale(
                HOLY_VISUAL_STATE.SprinklerTimerESPScale
                or "80"
            )
        )

    if HOLY_VISUAL_STATE.GardenFruitShowValue == nil then

        HOLY_VISUAL_STATE.GardenFruitShowValue =
            true

    else

        HOLY_VISUAL_STATE.GardenFruitShowValue =
            HOLY_VISUAL_STATE.GardenFruitShowValue == true
