function HolyFarmNormalizePlantName(value)

    local text =
        HolyFarmCleanPlantName(
            value
        )

    if text == "" then
        return ""
    end

    local cache =
        HolyFarmBuildPlantNameCache(
            false
        )

    local map =
        type(cache) == "table"
        and type(cache.Map) == "table"
        and cache.Map
        or {}

    local canonical =
        map[
            HolyFarmPlantKey(
                text
            )
        ]

    if canonical ~= nil then
        return canonical
    end

    return text
end

function HolyFarmNormalizePlantSelection(value)

    local raw =
        HolyShopSelectionArray(
            value
        )

    if #raw <= 0 then
        return {}
    end

    local validMap =
        HolyFarmGetPlantValueMap()

    local output =
        {}

    local seen =
        {}

    for _, plantName in ipairs(raw) do

        plantName =
            HolyFarmNormalizePlantName(
                plantName
            )

        if plantName ~= ""
        and plantName ~= "All"
        and validMap[plantName] == true
        and seen[plantName] ~= true then

            seen[plantName] =
                true

            table.insert(
                output,
                plantName
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyFarmMutationKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.'\"_/{}]", "")
end

function HolyFarmCleanMutationName(value)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return ""
    end

    local lower =
        text:lower()

    if lower == "all"
    or lower == "none"
    or lower == "normal"
    or lower == "---"
    or lower == "nil"
    or lower == "false"
    or lower == "true"
    or lower == "0"
    or lower == "{}"
    or lower == "[]"
    or lower == "default" then

        return ""
    end

    if lower:find("kg", 1, true) then
        return ""
    end

    if lower:find("table:", 1, true) then
        return ""
    end

    if text:match("^%d+%.?%d*$") then
        return ""
    end

    if #text > 48 then
        return ""
    end

    return text
end

function HolyFarmMutationCacheAddName(cache, value)

