        )

    if mutationName == "" then
        return false
    end

    local key =
        HolyFarmMutationKey(
            mutationName
        )

    if key == "" then
        return false
    end

    if cache.Map[key] ~= nil then
        return false
    end

    cache.Map[key] =
        mutationName

    table.insert(
        cache.Values,
        mutationName
    )

    return true
end

