function HolySniperReadHopDelay(value)

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub(
            "[sS]",
            ""
        )

    local number =
        tonumber(
            text
        )

    if not number then

        number =
            5
    end

    return math.max(
        0,
        number
    )
end

function HolySniperFormatDelay(value)

    local number =
        HolySniperReadHopDelay(
            value
        )

    if math.abs(number - math.floor(number)) < 0.001 then

        return tostring(
            math.floor(number)
        )
    end

    return tostring(
        math.floor(number * 100 + 0.5) / 100
    )
end

function HolySniperReadAmount(value)

    local amount =
        math.floor(
            tonumber(value)
            or 999
        )

    return math.clamp(
        amount,
        1,
        999
    )
end

function HolySniperReadMaxPrice(value)

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub("¢", "")
            :gsub("%$", "")
            :gsub(",", "")
            :gsub("%s+", "")

    local lower =
        text:lower()

    if lower == ""
    or lower == "0"
    or lower == "none"
    or lower == "off"
    or lower == "no" then

        return 0
    end

    local multiplier =
        1

    if lower:find("b", 1, true) then

        multiplier =
            1000000000

    elseif lower:find("m", 1, true) then

        multiplier =
            1000000

    elseif lower:find("k", 1, true) then

        multiplier =
            1000
    end

    local rawNumber =
        lower:match("%d+%.?%d*")

    local number =
        tonumber(rawNumber)

    if number == nil then
        return 0
    end

    return math.max(
        0,
        math.floor(number * multiplier + 0.5)
    )
end

function HolySniperFormatMaxPrice(value)

    local number =
        HolySniperReadMaxPrice(
            value
        )

    if number <= 0 then
        return "No Cap"
    end

    return "Max "
        .. HolySniperFormatMoney(
            number
        )
end

function HolySniperArrayText(values, fallback)

    values =
        HolyShopSelectionArray(
            values
        )

    fallback =
        tostring(fallback or "Any")

    if #values <= 0 then
        return fallback
    end

    if #values == 1
    and values[1] == "Any" then
        return fallback
    end

    return table.concat(
        values,
        "/"
    )
end

function HolySniperGetPetData()

    local petData =
        HolyDataGetModule(
            "PetData"
        )

    if type(petData) ~= "table" then
        return {}
    end

    return petData
end

function HolySniperIsPetDataRow(key, row)

    if type(key) ~= "string" then
        return false
    end

    if type(row) ~= "table" then
        return false
    end

    if type(row.DisplayName) == "string"
    or type(row.BasePrice) == "number"
    or type(row.Rarity) == "string"
    or type(row.SpawnChance) == "number" then

        return true
    end

    return false
end

function HolySniperPetAliasKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.]", "")
end

function HolySniperBuildPetMaps()

    local values = {
        "Any Pet",
    }

    local seen = {
        ["Any Pet"] = true,
    }

    local displayToKey = {
        ["Any Pet"] = "*",
    }

    local keyToDisplay = {
        ["*"] = "Any Pet",
    }

    local petData =
        HolySniperGetPetData()

    for key, row in pairs(petData) do

        if HolySniperIsPetDataRow(key, row) == true then

            local internalKey =
                HolyCleanText(
                    key
                )

            local displayName =
                HolyCleanText(
                    row.DisplayName
                    or row.PetName
                    or row.Name
                    or key
                )

            if internalKey ~= ""
            and displayName ~= "" then

                if seen[displayName] ~= true then

                    seen[displayName] =
                        true

                    table.insert(
                        values,
                        displayName
                    )
                end

                displayToKey[displayName] =
                    internalKey

                keyToDisplay[internalKey] =
                    displayName
            end
        end
    end

    table.sort(values, function(a, b)

        if a == "Any Pet" then
            return true
        end

        if b == "Any Pet" then
            return false
        end

        return tostring(a) < tostring(b)
    end)

    if #values <= 1 then

        values = {
            "Any Pet",
            "Raccoon",
        }

        displayToKey["Any Pet"] =
            "*"

        displayToKey.Raccoon =
            "Raccoon"

        keyToDisplay["*"] =
            "Any Pet"

        keyToDisplay.Raccoon =
            "Raccoon"
    end

    HOLY_SNIPER_STATE.PetDisplayToKey =
        displayToKey

    HOLY_SNIPER_STATE.PetKeyToDisplay =
        keyToDisplay

    return values,
        displayToKey,
        keyToDisplay
end

function HolySniperGetPetValues()

    local values =
        HolySniperBuildPetMaps()

    return values
end

function HolySniperGetDefaultPetName()

    local values =
        HolySniperGetPetValues()

    for _, petName in ipairs(values) do

        if petName == "Raccoon" then
            return "Raccoon"
        end
    end

    return values[1]
        or "Raccoon"
end

function HolySniperResolvePetKey(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "any"
    or lower == "all"
    or lower == "any pet"
    or lower == "all pets"
    or lower == "*" then

        return "*"
    end

    if text == "" then
        return "Raccoon"
    end

    HolySniperGetPetValues()

    local displayToKey =
        type(HOLY_SNIPER_STATE.PetDisplayToKey) == "table"
        and HOLY_SNIPER_STATE.PetDisplayToKey
        or {}

    local keyToDisplay =
        type(HOLY_SNIPER_STATE.PetKeyToDisplay) == "table"
        and HOLY_SNIPER_STATE.PetKeyToDisplay
        or {}

    if displayToKey[text] then
        return displayToKey[text]
    end

    if keyToDisplay[text] then
        return text
    end

    local wantedAlias =
        HolySniperPetAliasKey(
            text
        )

    for internalKey, displayName in pairs(keyToDisplay) do

        if HolySniperPetAliasKey(internalKey) == wantedAlias
        or HolySniperPetAliasKey(displayName) == wantedAlias then

            return internalKey
        end
    end

    return text
end

function HolySniperResolvePetDisplay(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "any"
    or lower == "all"
    or lower == "any pet"
    or lower == "all pets"
    or lower == "*" then

        return "Any Pet"
    end

    if text == "" then
        return HolySniperGetDefaultPetName()
    end

    HolySniperGetPetValues()

    local displayToKey =
        type(HOLY_SNIPER_STATE.PetDisplayToKey) == "table"
        and HOLY_SNIPER_STATE.PetDisplayToKey
        or {}

    local keyToDisplay =
        type(HOLY_SNIPER_STATE.PetKeyToDisplay) == "table"
        and HOLY_SNIPER_STATE.PetKeyToDisplay
        or {}

    if displayToKey[text] then
        return text
    end

    if keyToDisplay[text] then
        return keyToDisplay[text]
    end

    local wantedAlias =
        HolySniperPetAliasKey(
            text
        )

    for internalKey, displayName in pairs(keyToDisplay) do

        if HolySniperPetAliasKey(internalKey) == wantedAlias
        or HolySniperPetAliasKey(displayName) == wantedAlias then

            return displayName
        end
    end

    return text
end

function HolySniperNormalizeFilter(row)

    row =
        type(row) == "table"
        and row
        or {}

    local rawPet =
        row.Pet
        or row.PetName
        or row.Name
        or HolySniperGetDefaultPetName()

    local petName =
        HolySniperResolvePetDisplay(
            rawPet
        )

    if petName == "" then

        petName =
            HolySniperGetDefaultPetName()
    end

    local maxPrice =
        HolySniperReadMaxPrice(
            row.MaxPrice
            or row.Max
            or row.PriceLimit
            or row.BuilderMaxPrice
            or 0
        )

    return {
        Pet =
            petName,

        PetKey =
            HolySniperResolvePetKey(
                petName
            ),

        Sizes =
            HolySniperNormalizeSizeSelection(
                row.Sizes
                or row.Size
                or {
                    "Any",
                }
            ),

        Variants =
            HolySniperNormalizeVariantSelection(
                row.Variants
                or row.Variant
                or {
                    "Any",
                }
            ),

        MaxPrice =
            maxPrice,

        Amount =
            999,

        Priority =
            HolySniperNormalizePriority(
                row.Priority
                or "Medium"
            ),

        Enabled =
            row.Enabled ~= false,
    }
end

function HolySniperNormalizeWatchlist(value)

    local output =
        {}

    if type(value) ~= "table" then
        return output
    end

    for _, row in ipairs(value) do

        table.insert(
            output,
            HolySniperNormalizeFilter(
                row
            )
        )
    end

    return output
end

function HolySniperFilterKey(row)

    row =
        HolySniperNormalizeFilter(
            row
        )

    return table.concat({
        HolyCleanText(
            row.PetKey
            or HolySniperResolvePetKey(
                row.Pet
            )
        ):lower(),

        HolySniperArrayText(row.Sizes, "Any"):lower(),

        HolySniperArrayText(row.Variants, "Any"):lower(),

        tostring(
            tonumber(row.MaxPrice)
            or 0
        ),
    }, "|")
end

function HolySniperGetBasePrice(row)

    local petKey =
        ""

    if type(row) == "table" then

        petKey =
            HolyCleanText(
                row.PetKey
                or HolySniperResolvePetKey(
                    row.Pet
                )
            )

    else

        petKey =
            HolyCleanText(
                HolySniperResolvePetKey(
                    row
                )
            )
    end

    if petKey == "" then
        return 0
    end

    local petData =
        HolySniperGetPetData()

    local data =
        type(petData) == "table"
        and petData[petKey]
        or nil

    if type(data) ~= "table" then
        return 0
    end

    return tonumber(data.BasePrice)
        or 0
end

function HolySniperFormatMoney(value)

    value =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    if value >= 1000000 then

        return "$"
            .. string.format(
                "%.1fM",
                value / 1000000
            )
    end

    if value >= 1000 then

        return "$"
            .. string.format(
                "%.0fK",
                value / 1000
            )
    end

    return "$"
        .. tostring(
            math.floor(value)
        )
end

function HolySniperShortValue(value)

    value =
        HolyCleanText(
            value
        )

    if value == "Mega" then
        return "Huge"
    end

    if value == "Rainbow" then
        return "Rb"
    end

    if value == "Normal" then
        return "Norm"
    end

    return value
end

function HolySniperShortArrayText(values, fallback)

    values =
        HolyShopSelectionArray(
            values
        )

    fallback =
        tostring(fallback or "Any")

    if #values <= 0 then
        return fallback
    end

    if #values == 1
    and values[1] == "Any" then
        return fallback
    end

    local output =
        {}

    for _, value in ipairs(values) do

        if value ~= "Any" then

            table.insert(
                output,
                HolySniperShortValue(
                    value
                )
            )
        end
    end

    if #output <= 0 then
        return fallback
    end

    return table.concat(
        output,
        "+"
    )
end

function HolySniperPriorityRank(value)

    value =
        HolySniperNormalizePriority(
            value
        )

    if value == "High" then
        return 1
    end

    if value == "Medium" then
        return 2
    end

    return 3
end

function HolySniperPriorityShort(value)

    value =
        HolySniperNormalizePriority(
            value
        )

    return value:sub(
        1,
        1
    )
end

function HolySniperSortWatchlist(watchlist)

    table.sort(watchlist, function(a, b)

        local priceA =
            tonumber(a.ValueNumber)
            or HolySniperGetBasePrice(a)

        local priceB =
            tonumber(b.ValueNumber)
            or HolySniperGetBasePrice(b)

        if priceA ~= priceB then
            return priceA > priceB
        end

        local rankA =
            HolySniperPriorityRank(
                a.Priority
            )

        local rankB =
            HolySniperPriorityRank(
                b.Priority
            )

        if rankA ~= rankB then
            return rankA < rankB
        end

        return tostring(a.Pet) < tostring(b.Pet)
    end)

    return watchlist
end

function HolySniperMatchesSearch(row, searchText)

    searchText =
        HolyCleanText(
            searchText
        )
        :lower()

    if searchText == "" then
        return true
    end

    local haystack =
        table.concat({
            tostring(row.Pet or ""),
            tostring(row.PetKey or ""),
            tostring(row.Value or ""),
            tostring(row.Size or ""),
            tostring(row.Variant or ""),
            tostring(row.MaxPrice or ""),
            tostring(row.Amount or ""),
            tostring(row.Priority or ""),
            tostring(row.PriorityFull or ""),
        }, " "):lower()

    return haystack:find(
        searchText,
        1,
        true
    ) ~= nil
end

function HolySniperBuildAllWatchlistRows()

    local rows =
        {}

    local searchText =
        HolyCleanText(
            HOLY_SNIPER_STATE.WatchlistSearch
            or ""
        )

    for sourceIndex, row in ipairs(HOLY_SNIPER_STATE.Watchlist or {}) do

        local filter =
            HolySniperNormalizeFilter(
                row
            )

        local price =
            HolySniperGetBasePrice(
                filter
            )

        local maxPriceText =
            HolySniperFormatMaxPrice(
                filter.MaxPrice
            )

        local tableRow = {
            SourceIndex =
                sourceIndex,

            Pet =
                tostring(filter.Pet),

            PetKey =
                tostring(filter.PetKey),

            Value =
                HolySniperFormatMoney(
                    price
                ),

            ValueNumber =
                price,

            MaxPrice =
                maxPriceText,

            MaxPriceNumber =
                tonumber(filter.MaxPrice)
                or 0,

            Size =
                HolySniperShortArrayText(
                    filter.Sizes,
                    "Any"
                ),

            Variant =
                HolySniperShortArrayText(
                    filter.Variants,
                    "Any"
                ),

            Amount =
                maxPriceText,

            AmountNumber =
                tonumber(filter.MaxPrice)
                or 0,

            Priority =
                HolySniperPriorityShort(
                    filter.Priority
                ),

            PriorityFull =
                HolySniperNormalizePriority(
                    filter.Priority
                ),
        }

        if HolySniperMatchesSearch(
            tableRow,
            searchText
        ) == true then

            table.insert(
                rows,
                tableRow
            )
        end
    end

    HolySniperSortWatchlist(
        rows
    )

    return rows
end

function HolySniperGetWatchlistPageSize()

    local pageSize =
        math.floor(
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPageSize
            )
            or 7
        )

    return math.clamp(
        pageSize,
        1,
        20
    )
end

function HolySniperGetWatchlistPageCount(totalRows)

    totalRows =
        math.max(
            0,
            math.floor(
                tonumber(totalRows)
                or 0
            )
        )

    local pageSize =
        HolySniperGetWatchlistPageSize()

    return math.max(
        1,
        math.ceil(
            totalRows / pageSize
        )
    )
end

function HolySniperClampWatchlistPage(totalRows)

    local pageCount =
        HolySniperGetWatchlistPageCount(
            totalRows
        )

    local page =
        math.floor(
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPage
            )
            or 1
        )

    page =
        math.clamp(
            page,
            1,
            pageCount
        )

    HOLY_SNIPER_STATE.WatchlistPage =
        page

    return page,
        pageCount
end

function HolySniperBuildWatchlistRows()

    local allRows =
        HolySniperBuildAllWatchlistRows()

    local page,
        pageCount =
        HolySniperClampWatchlistPage(
            #allRows
        )

    local pageSize =
        HolySniperGetWatchlistPageSize()

    local firstIndex =
        ((page - 1) * pageSize) + 1

    local lastIndex =
        math.min(
            #allRows,
            firstIndex + pageSize - 1
        )

    local pageRows =
        {}

    for index = firstIndex, lastIndex do

        if type(allRows[index]) == "table" then

            table.insert(
                pageRows,
                allRows[index]
            )
        end
    end

    return pageRows,
        {
            Page =
                page,

            PageCount =
                pageCount,

            TotalRows =
                #allRows,

            FirstIndex =
                firstIndex,

            LastIndex =
                lastIndex,
        }
end

function HolySniperBuildWatchlistPageText()

    local allRows =
        HolySniperBuildAllWatchlistRows()

    local page,
        pageCount =
        HolySniperClampWatchlistPage(
            #allRows
        )

    return "Page "
        .. tostring(page)
        .. "/"
        .. tostring(pageCount)
end

function HolySniperSetWatchlistPage(page)

    local allRows =
        HolySniperBuildAllWatchlistRows()

    local pageCount =
        HolySniperGetWatchlistPageCount(
            #allRows
        )

    HOLY_SNIPER_STATE.WatchlistPage =
        math.clamp(
            math.floor(
                tonumber(page)
                or 1
            ),
            1,
            pageCount
        )

    HOLY_SNIPER_STATE.SelectedWatchlistSourceIndex =
        nil

    if HOLY_SNIPER_UI
    and type(HOLY_SNIPER_UI.WatchlistTable) == "table"
    and type(HOLY_SNIPER_UI.WatchlistTable.SetSelected) == "function" then

        HOLY_SNIPER_UI.WatchlistTable:SetSelected(
            nil
        )
    end

    HolySniperRefreshUI()

    return true
end

function HolySniperWatchlistPrevPage()

    return HolySniperSetWatchlistPage(
        (
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPage
            )
            or 1
        )
        - 1
    )
end

function HolySniperWatchlistNextPage()

    return HolySniperSetWatchlistPage(
        (
            tonumber(
                HOLY_SNIPER_STATE.WatchlistPage
            )
            or 1
        )
        + 1
    )
end


function HolySniperBuildWatchlistText()

    local rows =
        HolySniperBuildWatchlistRows()

    if #rows <= 0 then

        return "No active watchlist filters."
    end

    local lines =
        {}

    for index, row in ipairs(rows) do

        lines[#lines + 1] =
            tostring(index)
            .. ". "
            .. tostring(row.Value)
            .. " "
            .. tostring(row.Priority)
            .. " "
            .. tostring(row.Pet)
            .. " "
            .. tostring(row.Size)
            .. " "
            .. tostring(row.Variant)
            .. " "
            .. tostring(row.MaxPrice or row.Amount or "No Cap")
    end

    return table.concat(
        lines,
        "\n"
    )
end

function HolySniperBuildStatusText()

    return "Status: "
        .. tostring(
            HOLY_SNIPER_STATE.Status
            or "Ready"
        )
end

function HolySniperAddLabel(groupbox, text)

    if type(groupbox) ~= "table"
    or type(groupbox.AddLabel) ~= "function" then

        return nil
    end

    local ok,
        label =
        pcall(function()

            return groupbox:AddLabel({
                Text =
                    tostring(text or ""),
            })
        end)

    if ok == true then
        return label
    end

    ok,
        label =
        pcall(function()

            return groupbox:AddLabel(
                tostring(text or "")
            )
        end)

    if ok == true then
        return label
    end

    return nil
end

function HolySniperSetLabel(label, text)

    text =
        tostring(text or "")

    if type(label) == "table" then

        if type(label.SetText) == "function" then

            pcall(function()

                label:SetText(
                    text
                )
            end)

            return true
        end

        if label.TextLabel
        and typeof(label.TextLabel) == "Instance" then

            pcall(function()

                label.TextLabel.Text =
                    text
            end)

            return true
        end
    end

    if typeof(label) == "Instance" then

        pcall(function()

            label.Text =
                text
        end)

        return true
    end

    return false
end

function HolySniperRefreshUI()

    HOLY_SNIPER_UI =
        type(HOLY_SNIPER_UI) == "table"
        and HOLY_SNIPER_UI
        or {}

    HolySniperSetLabel(
        HOLY_SNIPER_UI.StatusLabel,
        HolySniperBuildStatusText()
    )

    local pageRows,
        pageInfo =
        HolySniperBuildWatchlistRows()

    if type(HOLY_SNIPER_UI.WatchlistTable) == "table"
    and type(HOLY_SNIPER_UI.WatchlistTable.SetRows) == "function" then

        HOLY_SNIPER_UI.WatchlistTable:SetRows(
            pageRows
        )

    else

        HolySniperSetLabel(
            HOLY_SNIPER_UI.WatchlistLabel,
            HolySniperBuildWatchlistText()
        )
    end

    local pager =
        HOLY_SNIPER_UI.WatchlistPager

    if type(pager) == "table" then

        local page =
            tonumber(
                pageInfo
                and pageInfo.Page
            )
            or 1

        local pageCount =
            tonumber(
                pageInfo
                and pageInfo.PageCount
            )
            or 1

        if type(pager.SetText) == "function" then

            pager:SetText(
                "Page",
                "Page "
                .. tostring(page)
                .. "/"
                .. tostring(pageCount)
            )
        end

        if type(pager.SetDisabled) == "function" then

            pager:SetDisabled(
                "Prev",
                page <= 1
            )

            pager:SetDisabled(
                "Next",
                page >= pageCount
            )
        end
    end
end

function HolySniperSetStatus(status)

    HOLY_SNIPER_STATE.Status =
        tostring(status or "Ready")

    HolySniperRefreshUI()
end

function HolySniperGetCharacter()

    return LocalPlayer
        and LocalPlayer.Character
        or nil
end

function HolySniperGetCharacterHumanoid()

    local character =
        HolySniperGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChildOfClass(
        "Humanoid"
    )
end

function HolySniperGetCharacterRoot()

    local character =
        HolySniperGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChild(
        "HumanoidRootPart"
    )
    or character:FindFirstChild(
        "RootPart"
    )
    or character.PrimaryPart
end

function HolySniperGetEquippedToolForMovement()

    local character =
        HolySniperGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChildOfClass(
        "Tool"
    )
end

function HolySniperMovementToolClearBlocked()

    return type(HOLY_DEFENSE_RUNTIME) == "table"
        and HOLY_DEFENSE_RUNTIME.Active == true
end

function HolySniperClearHeldToolForMovement(reason)

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if HolySniperMovementToolClearBlocked() == true then
        return false
    end

    local equippedTool =
        HolySniperGetEquippedToolForMovement()

    if typeof(equippedTool) ~= "Instance"
    or equippedTool:IsA("Tool") ~= true then

        return false
    end

    local humanoid =
        HolySniperGetCharacterHumanoid()

    if typeof(humanoid) ~= "Instance"
    or humanoid:IsA("Humanoid") ~= true then

        return false
    end

    local now =
        os.clock()

    if now - (
        tonumber(HOLY_SNIPER_RUNTIME.LastMovementUnequipAt)
        or 0
    ) < 0.28 then

        return true
    end

    HOLY_SNIPER_RUNTIME.LastMovementUnequipAt =
        now

    HOLY_SNIPER_RUNTIME.LastMovementUnequipTool =
        tostring(
            equippedTool.Name
            or "Tool"
        )

    HOLY_SNIPER_RUNTIME.LastMovementUnequipReason =
        tostring(
            reason
            or "movement"
        )

    pcall(function()

        humanoid:UnequipTools()
    end)

    task.wait(
        0.10
    )

    return true
end

function HolySniperGetEquippedToolForBuy()

    return HolySniperGetEquippedToolForMovement()
end

function HolySniperClearHeldToolForBuy(reason)

    return HolySniperClearHeldToolForMovement(
        reason
        or "buy"
    )
end

function HolySniperStillActive(token)

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if HOLY_SNIPER_RUNTIME.ManualBuying == true then

        if token ~= nil
        and HOLY_SNIPER_RUNTIME.ManualToken ~= token then

            return false
        end

        return true
    end

    if HOLY_SNIPER_STATE.ActivateSniper ~= true then
        return false
    end

    if token ~= nil
    and HOLY_SNIPER_RUNTIME.Token ~= token then

        return false
    end

    return true
end

function HolySniperLoadingGateReady()

    if HolySniperGetCharacterRoot() == nil then
        return false
    end

    local loadingGui =
        HolyLoadingGetWorkspaceLoadingGui()

    if loadingGui == nil then
        return true
    end

    if type(HOLY_LOADING_SKIP_STATE) == "table"
    and HOLY_LOADING_SKIP_STATE.PressedFinal == true then

        return true
    end

    if type(HOLY_LOADING_SKIP_STATE) == "table"
    and HOLY_LOADING_SKIP_STATE.ClickedSkip == true
    and loadingGui == nil then

        return true
    end

    return false
end

function HolySniperGetWildPetRoot()

    local map =
        workspace:FindFirstChild(
            "Map"
        )

    local root =
        map
        and map:FindFirstChild(
            "WildPetSpawns"
        )
        or nil

    if typeof(root) == "Instance" then
        return root
    end

    root =
        workspace:FindFirstChild(
            "WildPetSpawns",
            true
        )

    if typeof(root) == "Instance" then
        return root
    end

    return nil
end

function HolySniperGetWildPetRefRoot()

    local map =
        workspace:FindFirstChild(
            "Map"
        )

    local root =
        map
        and map:FindFirstChild(
            "WildPetRef"
        )
        or nil

    if typeof(root) == "Instance" then
        return root
    end

    root =
        workspace:FindFirstChild(
            "WildPetRef",
            true
        )

    if typeof(root) == "Instance" then
        return root
    end

    return nil
end

function HolySniperUuidFromName(value)

    value =
        tostring(value or "")

    return value:match(
        "WildPet_([%w%-]+)$"
    )
    or value:match(
        "_WildPet_([%w%-]+)$"
    )
    or value:match(
        "([%w]+%-%w+%-%w+%-%w+%-%w+)"
    )
    or ""
end

function HolySniperReadModelAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return ""
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        value =
            HolyCleanText(
                ok == true
                and value
                or ""
            )

        if value ~= "" then
            return value
        end
    end

    return ""
end

function HolySniperFindRefForModel(model)

    if typeof(model) ~= "Instance" then
        return nil,
            ""
    end

    local refs =
        HolySniperGetWildPetRefRoot()

    if typeof(refs) ~= "Instance" then
        return nil,
            ""
    end

    local uuid =
        HolySniperUuidFromName(
            model.Name
        )

    if uuid ~= "" then

        local direct =
            refs:FindFirstChild(
                "WildPet_"
                .. uuid
            )

        if typeof(direct) == "Instance" then

            return direct,
                uuid
        end

        for _, ref in ipairs(refs:GetChildren()) do

            if tostring(ref.Name):find(
                uuid,
                1,
                true
            ) then

                return ref,
                    uuid
            end
        end
    end

    local modelPetName =
        HolySniperReadModelAttribute(
            model,
            {
                "PetName",
                "Pet",
                "DisplayName",
                "Name",
            }
        )

    if modelPetName ~= "" then

        for _, ref in ipairs(refs:GetChildren()) do

            local refPetName =
                HolySniperReadModelAttribute(
                    ref,
                    {
                        "PetName",
                        "Pet",
                        "DisplayName",
                        "Name",
                    }
                )

            if refPetName == modelPetName then

                return ref,
                    uuid
            end
        end
    end

    return nil,
        uuid
end

function HolySniperFindBuyPrompt(model)

    if typeof(model) ~= "Instance" then
        return nil
    end

    local directRoot =
        model:FindFirstChild(
            "RootPart"
        )
        or model:FindFirstChild(
            "RigPart"
        )
        or model.PrimaryPart

    local directPrompt =
        directRoot
        and directRoot:FindFirstChild(
            "BuyPrompt"
        )
        or nil

    if typeof(directPrompt) == "Instance"
    and directPrompt:IsA("ProximityPrompt") then

        return directPrompt
    end

    for _, descendant in ipairs(model:GetDescendants()) do

        if descendant:IsA("ProximityPrompt") then

            local action =
                HolyCleanText(
                    descendant.ActionText
                )
                :lower()

            local name =
                tostring(
                    descendant.Name
                    or ""
                )
                :lower()

            if action == "buy"
            or action:find("buy", 1, true)
            or name:find("buy", 1, true) then

                return descendant
            end
        end
    end

    return nil
end

function HolySniperGetPromptPosition(prompt, model)

    if typeof(prompt) == "Instance" then

        local parent =
            prompt.Parent

        if typeof(parent) == "Instance" then

            if parent:IsA("BasePart") then
                return parent.Position
            end

            if parent:IsA("Attachment") then
                return parent.WorldPosition
            end
        end
    end

    return HolySniperGetModelPosition(
        model
    )
end

function HolySniperReadLivePetName(model, ref)

    local attrName =
        HolySniperReadModelAttribute(
            ref,
            {
                "PetName",
                "Pet",
                "PetTypeName",
                "DisplayName",
                "Name",
            }
        )

    if attrName == "" then

        attrName =
            HolySniperReadModelAttribute(
                model,
                {
                    "PetName",
                    "Pet",
                    "PetTypeName",
                    "DisplayName",
                    "Name",
                }
            )
    end

    if attrName ~= "" then

        return HolySniperResolvePetDisplay(
            attrName
        )
    end

    local rawName =
        tostring(
            model
            and model.Name
            or ""
        )

    local fromWildName =
        rawName:match(
            "^WildPet_([^_]+)_"
        )
        or rawName:match(
            "^WildPet_([^_]+)"
        )
        or ""

    fromWildName =
        HolyCleanText(
            fromWildName
        )

    if fromWildName ~= "" then

        return HolySniperResolvePetDisplay(
            fromWildName
        )
    end

    return ""
end

function HolySniperReadModelBooleanAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return false
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        if ok == true then

            if value == true then
                return true
            end

            local text =
                tostring(value or "")
                    :lower()

            if text == "true"
            or text == "1"
            or text == "yes" then

                return true
            end

            local number =
                tonumber(value)

            if number ~= nil
            and number == 1 then

                return true
            end
        end
    end

    return false
end

function HolySniperReadModelNumberAttribute(instance, names)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        if ok == true then

            local number =
                tonumber(value)

            if number ~= nil then
                return number
            end
        end
    end

    return nil
end

function HolySniperReadLiveSize(model, ref)

    local rawSize =
        HolySniperReadModelAttribute(
            ref,
            {
                "PetSize",
                "Size",
                "DisplaySize",
                "ScaleType",
                "WildPetSize",
                "PetScaleType",
                "VariantSize",
            }
        )

    if rawSize == "" then

        rawSize =
            HolySniperReadModelAttribute(
                model,
                {
                    "PetSize",
                    "Size",
                    "DisplaySize",
                    "ScaleType",
                    "WildPetSize",
                    "PetScaleType",
                    "VariantSize",
                }
            )
    end

    if rawSize ~= "" then

        return HolySniperNormalizeSizeName(
            rawSize
        )
    end

    local scale =
        HolySniperReadModelNumberAttribute(
            ref,
            {
                "Scale",
                "PetScale",
                "SizeScale",
                "SizeMulti",
                "ScaleMultiplier",
            }
        )

    if scale == nil then

        scale =
            HolySniperReadModelNumberAttribute(
                model,
                {
                    "Scale",
                    "PetScale",
                    "SizeScale",
                    "SizeMulti",
                    "ScaleMultiplier",
                }
            )
    end

    if scale == nil then

        scale =
            1

        if typeof(model) == "Instance" then

            pcall(function()

                scale =
                    model:GetScale()
            end)
        end
    end

    scale =
        tonumber(scale)
        or 1

    if scale >= 3.25 then
        return "Huge"
    end

    if scale >= 1.50 then
        return "Big"
    end

    return "Normal"
end

function HolySniperReadLiveVariant(model, ref)

    if HolySniperReadModelBooleanAttribute(
        ref,
        {
            "Rainbow",
            "IsRainbow",
            "PetRainbow",
            "RainbowPet",
        }
    ) == true then

        return "Rainbow"
    end

    if HolySniperReadModelBooleanAttribute(
        model,
        {
            "Rainbow",
            "IsRainbow",
            "PetRainbow",
            "RainbowPet",
        }
    ) == true then

        return "Rainbow"
    end

    local rawVariant =
        HolySniperReadModelAttribute(
            ref,
            {
                "PetType",
                "Type",
                "Variant",
                "PetVariant",
                "DisplayType",
                "DisplayVariant",
                "Mutation",
                "WildPetType",
                "PetTypeName",
            }
        )

    if rawVariant == "" then

        rawVariant =
            HolySniperReadModelAttribute(
                model,
                {
                    "PetType",
                    "Type",
                    "Variant",
                    "PetVariant",
                    "DisplayType",
                    "DisplayVariant",
                    "Mutation",
                    "WildPetType",
                    "PetTypeName",
                }
            )
    end

    if rawVariant ~= "" then

        rawVariant =
            HolySniperNormalizeVariantName(
                rawVariant
            )

        if rawVariant == "Rainbow" then
            return "Rainbow"
        end

        if rawVariant ~= "Normal"
        and HolySniperPetTypeIsValid(rawVariant) == true then

            return rawVariant
        end

        return "Normal"
    end

    local refName =
        tostring(
            ref
            and ref.Name
            or ""
        )
        :lower()

    local modelName =
        tostring(
            model
            and model.Name
            or ""
        )
        :lower()

    if refName:find("rainbow", 1, true)
    or modelName:find("rainbow", 1, true) then

        return "Rainbow"
    end

    return "Normal"
end

function HolySniperGetModelPosition(model)

    if typeof(model) ~= "Instance" then
        return nil
    end

    local rootPart =
        model:FindFirstChild(
            "RootPart"
        )
        or model:FindFirstChild(
            "RigPart"
        )
        or model.PrimaryPart

    if typeof(rootPart) == "Instance"
    and rootPart:IsA("BasePart") then

        return rootPart.Position
    end

    local ok,
        pivot =
        pcall(function()

            return model:GetPivot()
        end)

    if ok == true
    and typeof(pivot) == "CFrame" then

        return pivot.Position
    end

    return nil
end

function HolySniperReadShecklesObject()

    local roots = {
        LocalPlayer,
        LocalPlayer and LocalPlayer:FindFirstChild("leaderstats"),
        LocalPlayer and LocalPlayer:FindFirstChild("PlayerData"),
    }

    for _, root in ipairs(roots) do

        if typeof(root) == "Instance" then

            for _, name in ipairs({
                "Sheckles",
                "Sheckle",
                "Money",
                "Cash",
                "Coins",
            }) do

                local object =
                    root:FindFirstChild(
                        name,
                        true
                    )

                if object
                and object:IsA("ValueBase")
                and tonumber(object.Value) then

                    return object
                end
            end
        end
    end

    return nil
end

function HolySniperReadSheckles()

    local object =
        HolySniperReadShecklesObject()

    if object then

        return tonumber(object.Value)
            or 0
    end

    return nil
end

function HolySniperReadEntryPrice(ref, prompt, petName, petKey)

    local refPrice =
        tonumber(
            HolySniperReadModelAttribute(
                ref,
                {
                    "Price",
                    "Cost",
                }
            )
        )

    if refPrice
    and refPrice > 0 then

        return refPrice
    end

    if typeof(prompt) == "Instance" then

        local text =
            HolyCleanText(
                prompt.ObjectText
            )

        local raw =
            text:match(
                "([%d,]+)"
            )

        if raw then

            local price =
                tonumber(
                    raw:gsub(",", "")
                )

            if price
            and price > 0 then

                return price
            end
        end
    end

    return HolySniperGetBasePrice({
        Pet =
            petName,

        PetKey =
            petKey,
    })
end

function HolySniperRawBuyable(model, ref, prompt)

    if typeof(model) ~= "Instance"
    or model.Parent == nil then

        return false,
            "spawn missing"
    end

    if typeof(ref) ~= "Instance"
    or ref.Parent == nil then

        return false,
            "ref missing"
    end

    if typeof(prompt) ~= "Instance"
    or prompt:IsA("ProximityPrompt") ~= true
    or prompt.Parent == nil then

        return false,
            "prompt missing"
    end

    if prompt.Enabled ~= true then

        return false,
            "prompt disabled"
    end

    local ownerUserId =
        tonumber(
            HolySniperReadModelAttribute(
                ref,
                {
                    "OwnerUserId",
                }
            )
        )
        or 0

    local ownerName =
        HolyCleanText(
            HolySniperReadModelAttribute(
                ref,
                {
                    "OwnerName",
                }
            )
        )

    local state =
        HolyCleanText(
            HolySniperReadModelAttribute(
                ref,
                {
                    "State",
                }
            )
        )

    if ownerUserId ~= 0 then

        return false,
            "already owned"
    end

    if ownerName ~= "" then

        return false,
            "already owned"
    end

    if state ~= ""
    and state ~= "wandering"
    and state ~= "wandering_walking" then

        return false,
            "state "
            .. state
    end

    return true,
        "buyable"
end

function HolySniperBuildLiveEntry(model)

    if typeof(model) ~= "Instance"
    or model:IsA("Model") ~= true then

        return nil
    end

    local ref,
        uuid =
        HolySniperFindRefForModel(
            model
        )

    local prompt =
        HolySniperFindBuyPrompt(
            model
        )

    local petName =
        HolySniperReadLivePetName(
            model,
            ref
        )

    if petName == "" then
        return nil
    end

    local petKey =
        HolySniperResolvePetKey(
            petName
        )

    local position =
        HolySniperGetPromptPosition(
            prompt,
            model
        )

    local root =
        HolySniperGetCharacterRoot()

    local distance =
        999999

    if typeof(position) == "Vector3"
    and typeof(root) == "Instance"
    and root:IsA("BasePart") then

        distance =
            (
                root.Position
                - position
            ).Magnitude
    end

    local size =
    HolySniperReadLiveSize(
        model,
        ref
    )

    local variant =
        HolySniperReadLiveVariant(
            model,
            ref
        )

    local debugId =
        ""

    pcall(function()

        debugId =
            model:GetDebugId()
    end)

    local buyable,
        buyableReason =
        HolySniperRawBuyable(
            model,
            ref,
            prompt
        )

    local promptRange =
        12

    if typeof(prompt) == "Instance"
    and prompt:IsA("ProximityPrompt") then

        promptRange =
            tonumber(prompt.MaxActivationDistance)
            or 12
    end

    local key =
        uuid ~= ""
        and uuid
        or (
            debugId ~= ""
            and debugId
            or tostring(model.Name)
        )

    local entry = {
        Key =
            key,

        UUID =
            uuid,

        Model =
            model,

        Ref =
            ref,

        Prompt =
            prompt,

        Pet =
            petName,

        PetKey =
            petKey,

        Size =
            size,

        Variant =
            variant,

        Position =
            position,

        Distance =
            distance,

        PromptRange =
            promptRange,

        Buyable =
            buyable == true,

        BuyableReason =
            tostring(buyableReason or ""),

        Price =
            HolySniperReadEntryPrice(
                ref,
                prompt,
                petName,
                petKey
            ),

        BasePrice =
            HolySniperGetBasePrice({
                Pet =
                    petName,

                PetKey =
                    petKey,
            }),
    }

    return entry
end

function HolySniperRefreshEntry(entry)

    if type(entry) ~= "table" then
        return nil
    end

    if typeof(entry.Model) ~= "Instance"
    or entry.Model.Parent == nil then

        return nil
    end

    return HolySniperBuildLiveEntry(
        entry.Model
    )
end

function HolySniperEntryKey(entry)

    if type(entry) ~= "table" then
        return ""
    end

    return HolyCleanText(
        entry.UUID
        or entry.Key
        or ""
    )
end

function HolySniperPetBuyProtectionEnsure()

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    HOLY_SNIPER_RUNTIME.BuyProtection =
        type(HOLY_SNIPER_RUNTIME.BuyProtection) == "table"
        and HOLY_SNIPER_RUNTIME.BuyProtection
        or {
            Active = false,
        }

    return HOLY_SNIPER_RUNTIME.BuyProtection
end

function HolySniperPetBuyStateLooksPending(value)

    local state =
        HolyCleanText(
            value
        )
        :lower()

    state =
        state:gsub(
            "%s+",
            "_"
        )

    if state == "" then
        return false
    end

    if state == "walking_to_garden"
    or state == "waiting_for_garden"
    or state == "going_to_garden"
    or state == "moving_to_garden"
    or state == "traveling_to_garden"
    or state == "travelling_to_garden"
    or state == "pathing_to_garden"
    or state == "returning_to_garden" then

        return true
    end

    if state:find("_to_garden", 1, true) then
        return true
    end

    if state:find("garden", 1, true)
    and (
        state:find("walk", 1, true)
        or state:find("wait", 1, true)
        or state:find("go", 1, true)
        or state:find("move", 1, true)
        or state:find("travel", 1, true)
        or state:find("path", 1, true)
        or state:find("return", 1, true)
    ) then

        return true
    end

    return false
end

function HolySniperFindPetBuyProtectionRef(lock)

    lock =
        type(lock) == "table"
        and lock
        or {}

    local key =
        HolyCleanText(
            lock.UUID
            or lock.Key
            or lock.EntryKey
        )

    if key == "" then
        return nil
    end

    local root =
        HolySniperGetWildPetRefRoot()

    if typeof(root) ~= "Instance" then
        return nil
    end

    local direct =
        root:FindFirstChild(
            "WildPet_"
            .. key
        )

    if typeof(direct) == "Instance" then
        return direct
    end

    for _, child in ipairs(root:GetChildren()) do

        if tostring(child.Name):find(
            key,
            1,
            true
        ) then

            return child
        end
    end

    return nil
end

function HolySniperArmPetBuyProtection(entry, reason)

    local lock =
        HolySniperPetBuyProtectionEnsure()

    entry =
        type(entry) == "table"
        and entry
        or {}

    local now =
        os.clock()

    local key =
        HolySniperEntryKey(
            entry
        )

    lock.Active =
        true

    lock.EntryKey =
        key

    lock.Key =
        key

    lock.UUID =
        HolyCleanText(
            entry.UUID
            or entry.Key
            or key
        )

    lock.Pet =
        HolyCleanText(
            entry.Pet
            or entry.PetName
            or entry.DisplayName
            or "pet"
        )

    lock.Ref =
        entry.Ref

    lock.StartedAt =
        now

    lock.ConfirmedAt =
        tonumber(lock.ConfirmedAt)
        or 0

    lock.MinUntil =
        now
        + (
            tonumber(HOLY_SNIPER_PET_BUY_SETTLE_SECONDS)
            or 18
        )

    lock.HardUntil =
        now
        + (
            tonumber(HOLY_SNIPER_PET_BUY_HARD_TIMEOUT)
            or 120
        )

    lock.Reason =
        tostring(reason or "buy pending")

    lock.LastStatusAt =
        0

    lock.LastNotifyAt =
        0

    HOLY_SNIPER_RUNTIME.BuyProtectionActive =
        true

    return true
end

function HolySniperTouchPetBuyProtection(entry, reason)

    local lock =
        HolySniperPetBuyProtectionEnsure()

    if lock.Active ~= true then

        return HolySniperArmPetBuyProtection(
            entry,
            reason
        )
    end

    local now =
        os.clock()

    entry =
        type(entry) == "table"
        and entry
        or {}

    if entry.Ref ~= nil then
        lock.Ref =
            entry.Ref
    end

    local key =
        HolySniperEntryKey(
            entry
        )

    if key ~= "" then

        lock.EntryKey =
            key

        lock.Key =
            key

        lock.UUID =
            HolyCleanText(
                entry.UUID
                or entry.Key
                or key
            )
    end

    if reason ~= nil then

        lock.Reason =
            tostring(reason)
    end

    lock.ConfirmedAt =
        now

    lock.MinUntil =
        math.max(
            tonumber(lock.MinUntil)
            or 0,
            now
            + (
                tonumber(HOLY_SNIPER_PET_BUY_SETTLE_SECONDS)
                or 18
            )
        )

    HOLY_SNIPER_RUNTIME.BuyProtectionActive =
        true

    return true
end

function HolySniperClearPetBuyProtection(reason)

    local lock =
        HolySniperPetBuyProtectionEnsure()

    if lock.Active ~= true then
        return false
    end

    lock.Active =
        false

    lock.Reason =
        tostring(reason or "clear")

    lock.Ref =
        nil

    lock.EntryKey =
        ""

    lock.Key =
        ""

    lock.UUID =
        ""

    lock.Pet =
        ""

    lock.StartedAt =
        0

    lock.ConfirmedAt =
        0

    lock.MinUntil =
        0

    lock.HardUntil =
        0

    HOLY_SNIPER_RUNTIME.BuyProtectionActive =
        false

    return true
end

function HolySniperPetBuyProtectionActive()

    local lock =
        HolySniperPetBuyProtectionEnsure()

    if lock.Active ~= true then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            false

        return false,
            "clear"
    end

    local now =
        os.clock()

    local hardUntil =
        tonumber(lock.HardUntil)
        or 0

    if hardUntil > 0
    and now >= hardUntil then

        HolySniperClearPetBuyProtection(
            "hard timeout"
        )

        return false,
            "hard timeout"
    end

    if HOLY_SNIPER_RUNTIME.Buying == true then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            true

        return true,
            "buying"
    end

    local ref =
        lock.Ref

    if typeof(ref) ~= "Instance"
    or ref.Parent == nil then

        ref =
            HolySniperFindPetBuyProtectionRef(
                lock
            )

        lock.Ref =
            ref
    end

    local state =
        ""

    local ownerUserId =
        0

    local ownerName =
        ""

    if typeof(ref) == "Instance"
    and ref.Parent ~= nil then

        state =
            HolySniperReadModelAttribute(
                ref,
                {
                    "State",
                    "PetState",
                }
            )

        ownerUserId =
            tonumber(
                HolySniperReadModelAttribute(
                    ref,
                    {
                        "OwnerUserId",
                        "OwnerUserID",
                        "Owner",
                        "UserId",
                        "UserID",
                    }
                )
            )
            or 0

        ownerName =
            HolyCleanText(
                HolySniperReadModelAttribute(
                    ref,
                    {
                        "OwnerName",
                        "OwnerDisplayName",
                    }
                )
            )
    end

    local ownedByLocal =
        ownerUserId == tonumber(LocalPlayer.UserId)
        or (
            ownerName ~= ""
            and ownerName == HolyCleanText(LocalPlayer.Name)
        )

    if HolySniperPetBuyStateLooksPending(state) == true then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            true

        lock.Reason =
            state ~= ""
            and state
            or "going to garden"

        return true,
            lock.Reason
    end

    if ownedByLocal == true then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            true

        lock.Reason =
            "owned by you, settling"

        return true,
            lock.Reason
    end

    local minUntil =
        tonumber(lock.MinUntil)
        or 0

    if now < minUntil then

        HOLY_SNIPER_RUNTIME.BuyProtectionActive =
            true

        return true,
            tostring(lock.Reason or "settling")
    end

    HolySniperClearPetBuyProtection(
        "settled"
    )

    return false,
        "settled"
end

function HolySniperPetBuyProtectionBlocks(actionName, notify)

    local active,
        reason =
        HolySniperPetBuyProtectionActive()

    if active ~= true then
        return false
    end

    local lock =
        HolySniperPetBuyProtectionEnsure()

    local now =
        os.clock()

    if now - (
        tonumber(lock.LastStatusAt)
        or 0
    ) >= 1.25 then

        lock.LastStatusAt =
            now

        if type(HolySniperSetStatus) == "function" then

            HolySniperSetStatus(
                tostring(actionName or "Action")
                .. " blocked: pet buy pending"
            )
        end

        if type(HolyServerSetStatus) == "function" then

            HolyServerSetStatus(
                tostring(actionName or "Action")
                .. " blocked: pet buy pending"
            )
        end
    end

    if notify == true
    and now - (
        tonumber(lock.LastNotifyAt)
        or 0
    ) >= 3 then

        lock.LastNotifyAt =
            now

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Protection",
                tostring(actionName or "Action")
                .. " blocked while pet is settling: "
                .. tostring(reason or "pending"),
                4
            )
        end
    end

    return true
end

function HolySniperTargetLockEnsure()

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    HOLY_SNIPER_RUNTIME.TargetLock =
        type(HOLY_SNIPER_RUNTIME.TargetLock) == "table"
        and HOLY_SNIPER_RUNTIME.TargetLock
        or {
            Active = false,
        }

    return HOLY_SNIPER_RUNTIME.TargetLock
end

function HolySniperArmTargetLock(entry, reason)

    local lock =
        HolySniperTargetLockEnsure()

    entry =
        type(entry) == "table"
        and entry
        or {}

    local key =
        HolySniperEntryKey(
            entry
        )

    if key == "" then
        return false
    end

    local now =
        os.clock()

    lock.Active =
        true

    lock.EntryKey =
        key

    lock.Key =
        key

    lock.UUID =
        HolyCleanText(
            entry.UUID
            or entry.Key
            or key
        )

    lock.Pet =
        HolyCleanText(
            entry.Pet
            or entry.PetName
            or entry.DisplayName
            or "target pet"
        )

    lock.StartedAt =
        now

    lock.LastTouchAt =
        now

    lock.HardUntil =
        now
        + (
            tonumber(HOLY_SNIPER_TARGET_LOCK_TIMEOUT)
            or 45
        )

    lock.Reason =
        tostring(reason or "target locked")

    lock.LastStatusAt =
        0

    lock.LastNotifyAt =
        0

    HOLY_SNIPER_RUNTIME.TargetLockActive =
        true

    return true
end

function HolySniperTouchTargetLock(entry, reason)

    local lock =
        HolySniperTargetLockEnsure()

    entry =
        type(entry) == "table"
        and entry
        or {}

    if lock.Active ~= true then

        return HolySniperArmTargetLock(
            entry,
            reason
        )
    end

    local key =
        HolySniperEntryKey(
            entry
        )

    if key ~= "" then

        lock.EntryKey =
            key

        lock.Key =
            key

        lock.UUID =
            HolyCleanText(
                entry.UUID
                or entry.Key
                or key
            )
    end

    if entry.Pet
    or entry.PetName
    or entry.DisplayName then

        lock.Pet =
            HolyCleanText(
                entry.Pet
                or entry.PetName
                or entry.DisplayName
                or lock.Pet
            )
    end

    lock.LastTouchAt =
        os.clock()

    lock.HardUntil =
        math.max(
            tonumber(lock.HardUntil)
            or 0,
            os.clock()
            + (
                tonumber(HOLY_SNIPER_TARGET_LOCK_TIMEOUT)
                or 45
            )
        )

    if reason ~= nil then
        lock.Reason =
            tostring(reason)
    end

    HOLY_SNIPER_RUNTIME.TargetLockActive =
        true

    return true
end

function HolySniperClearTargetLock(reason)

    local lock =
        HolySniperTargetLockEnsure()

    if lock.Active ~= true then
        return false
    end

    lock.Active =
        false

    lock.EntryKey =
        ""

    lock.Key =
        ""

    lock.UUID =
        ""

    lock.Pet =
        ""

    lock.StartedAt =
        0

    lock.LastTouchAt =
        0

    lock.HardUntil =
        0

    lock.Reason =
        tostring(reason or "clear")

    lock.LastStatusAt =
        0

    lock.LastNotifyAt =
        0

    HOLY_SNIPER_RUNTIME.TargetLockActive =
        false

    return true
end

function HolySniperTargetLockActive()

    local lock =
        HolySniperTargetLockEnsure()

    if lock.Active ~= true then

        HOLY_SNIPER_RUNTIME.TargetLockActive =
            false

        return false,
            "clear"
    end

    local now =
        os.clock()

    local hardUntil =
        tonumber(lock.HardUntil)
        or 0

    if hardUntil > 0
    and now >= hardUntil then

        HolySniperClearTargetLock(
            "target lock timeout"
        )

        return false,
            "target lock timeout"
    end

    if HOLY_SNIPER_RUNTIME.Buying == true then

        HOLY_SNIPER_RUNTIME.TargetLockActive =
            true

        return true,
            tostring(lock.Reason or "buying target")
    end

    local currentKey =
        HolyCleanText(
            HOLY_SNIPER_RUNTIME.CurrentTargetKey
            or ""
        )

    local lockKey =
        HolyCleanText(
            lock.EntryKey
            or lock.Key
            or lock.UUID
        )

    if currentKey ~= ""
    and lockKey ~= ""
    and currentKey == lockKey then

        HOLY_SNIPER_RUNTIME.TargetLockActive =
            true

        return true,
            tostring(lock.Reason or "target locked")
    end

    if now - (
        tonumber(lock.LastTouchAt)
        or 0
    ) <= 2.5 then

        HOLY_SNIPER_RUNTIME.TargetLockActive =
            true

        return true,
            tostring(lock.Reason or "target locked")
    end

    HolySniperClearTargetLock(
        "target no longer active"
    )

    return false,
        "target no longer active"
end

function HolySniperTargetLockBlocks(actionName, notify)

    local active,
        reason =
        HolySniperTargetLockActive()

    if active ~= true then
        return false
    end

    local lock =
        HolySniperTargetLockEnsure()

    local now =
        os.clock()

    if now - (
        tonumber(lock.LastStatusAt)
        or 0
    ) >= 1.25 then

        lock.LastStatusAt =
            now

        if type(HolySniperSetStatus) == "function" then

            HolySniperSetStatus(
                tostring(actionName or "Action")
                .. " blocked: sniper target locked"
            )
        end

        if type(HolyServerSetStatus) == "function" then

            HolyServerSetStatus(
                tostring(actionName or "Action")
                .. " blocked: sniper target locked"
            )
        end
    end

    if notify == true
    and now - (
        tonumber(lock.LastNotifyAt)
        or 0
    ) >= 3 then

        lock.LastNotifyAt =
            now

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Protection",
                tostring(actionName or "Action")
                .. " blocked while sniper is handling "
                .. tostring(lock.Pet or "a target")
                .. ".",
                4
            )
        end
    end

    return true
end

function HolySniperServerSwitchBlocked(actionName, notify)

    if type(HOLY_DEFENSE_RUNTIME) == "table"
    and HOLY_DEFENSE_RUNTIME.Active == true then

        if notify == true
        and type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Protection",
                tostring(actionName or "Server switch")
                .. " blocked while a bought pet is being defended.",
                4
            )
        end

        return true
    end

    if HolySniperPetBuyProtectionBlocks(
        actionName,
        notify
    ) == true then

        return true
    end

    if HolySniperTargetLockBlocks(
        actionName,
        notify
    ) == true then

        return true
    end

    return false
end

function HolySniperIsHandled(entry)

    local key =
        HolySniperEntryKey(
            entry
        )

    if key == "" then
        return false
    end

    HOLY_SNIPER_RUNTIME.Handled =
        type(HOLY_SNIPER_RUNTIME.Handled) == "table"
        and HOLY_SNIPER_RUNTIME.Handled
        or {}

    return HOLY_SNIPER_RUNTIME.Handled[key] == true
end

function HolySniperIsFailedCooling(entry)

    local key =
        HolySniperEntryKey(
            entry
        )

    if key == "" then
        return false
    end

    HOLY_SNIPER_RUNTIME.FailedUntil =
        type(HOLY_SNIPER_RUNTIME.FailedUntil) == "table"
        and HOLY_SNIPER_RUNTIME.FailedUntil
        or {}

    local untilTime =
        tonumber(
            HOLY_SNIPER_RUNTIME.FailedUntil[key]
        )
        or 0

    if untilTime <= 0 then
        return false
    end

    if os.clock() >= untilTime then

        HOLY_SNIPER_RUNTIME.FailedUntil[key] =
            nil

        return false
    end

    return true
end

function HolySniperFilterComplete(filter)

    return false
end

function HolySniperScanLivePets()

    local root =
        HolySniperGetWildPetRoot()

    local entries =
        {}

    if typeof(root) ~= "Instance" then
        return entries
    end

    for _, child in ipairs(root:GetChildren()) do

        if child:IsA("Model") then

            local entry =
                HolySniperBuildLiveEntry(
                    child
                )

            if entry then

                table.insert(
                    entries,
                    entry
                )
            end
        end
    end

    return entries
end

function HolySniperSelectionHasAny(values)

    values =
        HolyShopSelectionArray(
            values
        )

    if #values <= 0 then
        return true
    end

    for _, value in ipairs(values) do

        if value == "Any" then
            return true
        end
    end

    return false
end

function HolySniperSelectionContains(values, wanted)

    wanted =
        HolyCleanText(
            wanted
        )

    if wanted == "" then
        return false
    end

    values =
        HolyShopSelectionArray(
            values
        )

    for _, value in ipairs(values) do

        if value == wanted then
            return true
        end
    end

    return false
end

function HolySniperEntryMatchesFilter(entry, filter)

    if type(entry) ~= "table"
    or type(filter) ~= "table"
    or filter.Enabled == false then

        return false
    end

    if entry.Buyable ~= true then
        return false
    end

    if HolySniperIsHandled(entry) == true then
        return false
    end

    if HolySniperIsFailedCooling(entry) == true then
        return false
    end

    local entryPet =
        HolySniperPetAliasKey(
            entry.PetKey
            or entry.Pet
        )

    local filterPetKey =
        HolyCleanText(
            filter.PetKey
            or HolySniperResolvePetKey(
                filter.Pet
            )
        )

    local filterPet =
        HolySniperPetAliasKey(
            filterPetKey ~= ""
            and filterPetKey
            or filter.Pet
        )

    if filterPetKey ~= "*"
    and filterPet ~= "*"
    and entryPet ~= filterPet then

        return false
    end

    local maxPrice =
        tonumber(filter.MaxPrice)
        or 0

    local entryPrice =
        tonumber(entry.Price)
        or 0

    if maxPrice > 0
    and entryPrice > maxPrice then

        return false
    end

    if HolySniperSelectionHasAny(filter.Sizes) ~= true
    and HolySniperSelectionContains(filter.Sizes, entry.Size) ~= true then

        return false
    end

    if HolySniperSelectionHasAny(filter.Variants) ~= true
    and HolySniperSelectionContains(filter.Variants, entry.Variant) ~= true then

        return false
    end

    return true
end

function HolySniperSizeRank(sizeName)

    sizeName =
        HolySniperNormalizeSizeName(
            sizeName
        )

    if sizeName == "Huge" then
        return 3
    end

    if sizeName == "Big" then
        return 2
    end

    return 1
end

function HolySniperVariantRank(variantName)

    variantName =
        HolySniperNormalizeVariantName(
            variantName
        )

    if variantName == "Rainbow" then
        return 2
    end

    return 1
end

function HolySniperFindMatches(entries)

    local matches =
        {}

    local watchlist =
        type(HOLY_SNIPER_STATE.Watchlist) == "table"
        and HOLY_SNIPER_STATE.Watchlist
        or {}

    for _, entry in ipairs(entries or {}) do

        for filterIndex, rawFilter in ipairs(watchlist) do

            local filter =
                HolySniperNormalizeFilter(
                    rawFilter
                )

            if HolySniperEntryMatchesFilter(
                entry,
                filter
            ) == true then

                table.insert(
                    matches,
                    {
                        Entry =
                            entry,

                        Filter =
                            filter,

                        FilterIndex =
                            filterIndex,

                        PriorityRank =
                            HolySniperPriorityRank(
                                filter.Priority
                            ),

                        ValueRank =
                            tonumber(entry.BasePrice)
                            or tonumber(entry.Price)
                            or 0,

                        SizeRank =
                            HolySniperSizeRank(
                                entry.Size
                            ),

                        VariantRank =
                            HolySniperVariantRank(
                                entry.Variant
                            ),

                        Distance =
                            tonumber(entry.Distance)
                            or 999999,
                    }
                )
            end
        end
    end

    table.sort(matches, function(a, b)

        if a.PriorityRank ~= b.PriorityRank then
            return a.PriorityRank < b.PriorityRank
        end

        if a.ValueRank ~= b.ValueRank then
            return a.ValueRank > b.ValueRank
        end

        if a.VariantRank ~= b.VariantRank then
            return a.VariantRank > b.VariantRank
        end

        if a.SizeRank ~= b.SizeRank then
            return a.SizeRank > b.SizeRank
        end

        return a.Distance < b.Distance
    end)

    return matches
end

function HolySniperDescribeEntry(entry)

    if type(entry) ~= "table" then
        return "None"
    end

    return tostring(entry.Size)
        .. " "
        .. tostring(entry.Variant)
        .. " "
        .. tostring(entry.Pet)
end

function HolySniperGetSafeRange(prompt)

    local maxRange =
        12

    if typeof(prompt) == "Instance"
    and prompt:IsA("ProximityPrompt") then

        maxRange =
            tonumber(prompt.MaxActivationDistance)
            or 12
    end

    local padding =
        tonumber(
            HOLY_SNIPER_RUNTIME.SafeRangePadding
        )
        or 2.15

    return math.clamp(
        maxRange - padding,
        5,
        math.max(5, maxRange - 0.35)
    )
end

function HolySniperDistanceToEntry(entry)

    if type(entry) ~= "table" then
        return math.huge
    end

    local root =
        HolySniperGetCharacterRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return math.huge
    end

    local position =
        HolySniperGetPromptPosition(
            entry.Prompt,
            entry.Model
        )

    if typeof(position) ~= "Vector3" then
        return math.huge
    end

    return (
        root.Position
        - position
    ).Magnitude
end

function HolySniperValidateTargetForBuy(entry, filter)

    local refreshed =
        HolySniperRefreshEntry(
            entry
        )

    if type(refreshed) ~= "table" then

        return false,
            nil,
            "target gone"
    end

    if refreshed.Buyable ~= true then

        return false,
            refreshed,
            refreshed.BuyableReason
            or "not buyable"
    end

    if HolySniperEntryMatchesFilter(
        refreshed,
        filter
    ) ~= true then

        return false,
            refreshed,
            "no longer matches"
    end

    return true,
        refreshed,
        "ok"
end

function HolySniperZeroRootVelocity(root)

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false
    end

    pcall(function()

        root.AssemblyLinearVelocity =
            Vector3.zero

        root.AssemblyAngularVelocity =
            Vector3.zero
    end)

    return true
end

function HolySniperMovementInputIsDown()

    if typeof(UserInputService) ~= "Instance" then
        return false
    end

    local movementKeys = {
        Enum.KeyCode.W,
        Enum.KeyCode.A,
        Enum.KeyCode.S,
        Enum.KeyCode.D,
        Enum.KeyCode.Up,
        Enum.KeyCode.Down,
        Enum.KeyCode.Left,
        Enum.KeyCode.Right,
        Enum.KeyCode.Space,
    }

    for _, keyCode in ipairs(movementKeys) do

        local ok,
            isDown =
            pcall(function()

                return UserInputService:IsKeyDown(
                    keyCode
                )
            end)

        if ok == true
        and isDown == true then

            return true
        end
    end

    return false
end

function HolySniperIsManualMovementInput(input)

    if typeof(input) ~= "InputObject" then
        return false
    end

    local keyCode =
        input.KeyCode

    if keyCode == Enum.KeyCode.W
    or keyCode == Enum.KeyCode.A
    or keyCode == Enum.KeyCode.S
    or keyCode == Enum.KeyCode.D
    or keyCode == Enum.KeyCode.Up
    or keyCode == Enum.KeyCode.Down
    or keyCode == Enum.KeyCode.Left
    or keyCode == Enum.KeyCode.Right
    or keyCode == Enum.KeyCode.Space then

        return true
    end

    if input.UserInputType == Enum.UserInputType.Touch then
        return true
    end

    if input.UserInputType == Enum.UserInputType.Gamepad1
    and (
        keyCode == Enum.KeyCode.Thumbstick1
        or keyCode == Enum.KeyCode.DPadUp
        or keyCode == Enum.KeyCode.DPadDown
        or keyCode == Enum.KeyCode.DPadLeft
        or keyCode == Enum.KeyCode.DPadRight
        or keyCode == Enum.KeyCode.ButtonA
    ) then

        return true
    end

    return false
end

function HolySniperMarkManualMovementInput(input)

    if HOLY_SNIPER_RUNTIME.Returning ~= true then
        return
    end

    if HolySniperIsManualMovementInput(input) ~= true then
        return
    end

    HOLY_SNIPER_RUNTIME.LastManualMoveInputAt =
        os.clock()
end

function HolySniperStartManualInputWatcher()

    HOLY_SNIPER_RUNTIME =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if HOLY_SNIPER_RUNTIME.ManualInputWatcherStarted == true then
        return true
    end

    HOLY_SNIPER_RUNTIME.ManualInputWatcherStarted =
        true

    pcall(function()

        UserInputService.InputBegan:Connect(function(input)

            HolySniperMarkManualMovementInput(
                input
            )
        end)

        UserInputService.InputChanged:Connect(function(input)

            if input.UserInputType == Enum.UserInputType.Gamepad1
            and input.KeyCode == Enum.KeyCode.Thumbstick1 then

                HolySniperMarkManualMovementInput(
                    input
                )
            end
        end)
    end)

    return true
end

function HolySniperManualReturnCancelled(returnStartedAt)

    returnStartedAt =
        tonumber(returnStartedAt)
        or 0

    if HolySniperMovementInputIsDown() == true then
        return true
    end

    local lastInputAt =
        tonumber(
            HOLY_SNIPER_RUNTIME.LastManualMoveInputAt
        )
        or 0

    local grace =
        tonumber(
            HOLY_SNIPER_RUNTIME.ManualReturnCancelGrace
        )
        or 0.20

    return lastInputAt > returnStartedAt + grace
end

function HolySniperStopHumanoidMovement(humanoid, root)

    if typeof(humanoid) == "Instance"
    and humanoid:IsA("Humanoid") then

        pcall(function()

            humanoid:Move(
                Vector3.zero,
                false
            )
        end)

        if typeof(root) == "Instance"
        and root:IsA("BasePart") then

            pcall(function()

                humanoid:MoveTo(
                    root.Position
                )
            end)
        end
    end
end

function HolySniperCFrameToData(cframe)

    if typeof(cframe) ~= "CFrame" then
        return nil
    end

    return {
        cframe:GetComponents()
    }
end

function HolySniperDataToCFrame(data)

    if type(data) ~= "table" then
        return nil
    end

    local components =
        {}

    for index = 1, 12 do

        local value =
            tonumber(
                data[index]
                or data[tostring(index)]
            )

        if value == nil then
            return nil
        end

        components[index] =
            value
    end

    local unpackFunction =
        table.unpack
        or unpack

    return CFrame.new(
        unpackFunction(
            components
        )
    )
end

function HolySniperFormatVectorShort(position)

    if typeof(position) ~= "Vector3" then
        return "Not set"
    end

    return tostring(
        math.floor(position.X + 0.5)
    )
    .. ", "
    .. tostring(
        math.floor(position.Y + 0.5)
    )
    .. ", "
    .. tostring(
        math.floor(position.Z + 0.5)
    )
end

function HolySniperSetSavedReturnPosition()

    local root =
        HolySniperGetCharacterRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Sniper",
                "Could not save return position. Character root missing.",
                4
            )
        end

        return false
    end

    HOLY_SNIPER_STATE.SavedReturnCFrameData =
        HolySniperCFrameToData(
            root.CFrame
        )

    HOLY_SNIPER_STATE.ReturnDestination =
        "Saved Position"

    HolySaveSniperSettings()

    local options =
        HOLY_DEV_LIBRARY
        and HOLY_DEV_LIBRARY.Options
        or nil

    if type(options) == "table"
    and options.HolySniperReturnDestination
    and type(options.HolySniperReturnDestination.SetValue) == "function" then

        pcall(function()

            options.HolySniperReturnDestination:SetValue(
                "Saved Position"
            )
        end)
    end

    if type(HolyNotify) == "function" then

        HolyNotify(
            "HOLY Sniper",
            "Saved return position: "
            .. HolySniperFormatVectorShort(root.Position),
            4
        )
    end

    return true
end

function HolySniperGetSavedReturnCFrame()

    return HolySniperDataToCFrame(
        HOLY_SNIPER_STATE.SavedReturnCFrameData
    )
end

function HolySniperScoreOwnedGarden(garden)

    if typeof(garden) ~= "Instance" then
        return 0
    end

    local localUserId =
        tostring(
            LocalPlayer
            and LocalPlayer.UserId
            or ""
        )

    local localName =
        HolyCleanText(
            LocalPlayer
            and LocalPlayer.Name
            or ""
        )

    local ownerUserId =
        nil

    pcall(function()

        ownerUserId =
            garden:GetAttribute(
                "OwnerUserId"
            )
    end)

    if ownerUserId ~= nil
    and tostring(ownerUserId) == localUserId then

        return 1000
    end

    local ownerName =
        nil

    pcall(function()

        ownerName =
            garden:GetAttribute(
                "Owner"
            )
    end)

    ownerName =
        HolyCleanText(
            ownerName
        )

    if ownerName ~= ""
    and localName ~= ""
    and ownerName == localName then

        return 900
    end

    return 0
end

function HolySniperFindOwnedGarden()

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if typeof(gardens) ~= "Instance" then

        gardens =
            workspace:FindFirstChild(
                "Gardens",
                true
            )
    end

    if typeof(gardens) ~= "Instance" then
        return nil
    end

    local bestGarden =
        nil

    local bestScore =
        0

    for _, child in ipairs(gardens:GetChildren()) do

        if child:IsA("Model")
        or child:IsA("Folder") then

            local score =
                HolySniperScoreOwnedGarden(
                    child
                )

            if score > bestScore then

                bestScore =
                    score

                bestGarden =
                    child
            end
        end
    end

    if bestGarden
    and bestScore > 0 then

        return bestGarden
    end

    return nil
end

function HolySniperPickGardenCenterPosition(garden)

    if typeof(garden) ~= "Instance" then
        return nil
    end

    local bestPart =
        nil

    local bestScore =
        0

    for _, descendant in ipairs(garden:GetDescendants()) do

        if descendant:IsA("BasePart") then

            local lowerName =
                tostring(descendant.Name)
                :lower()

            local area =
                math.max(
                    1,
                    descendant.Size.X
                    * descendant.Size.Z
                )

            local score =
                area

            if lowerName:find("farm", 1, true)
            or lowerName:find("soil", 1, true)
            or lowerName:find("dirt", 1, true)
            or lowerName:find("plot", 1, true)
            or lowerName:find("ground", 1, true)
            or lowerName:find("base", 1, true)
            or lowerName:find("garden", 1, true) then

                score =
                    score * 4
            end

            if score > bestScore then

                bestScore =
                    score

                bestPart =
                    descendant
            end
        end
    end

    if bestPart then

        return bestPart.Position
            + Vector3.new(
                0,
                math.clamp(
                    bestPart.Size.Y / 2 + 3,
                    3,
                    8
                ),
                0
            )
    end

    local ok,
        pivot =
        pcall(function()

            return garden:GetPivot()
        end)

    if ok == true
    and typeof(pivot) == "CFrame" then

        return pivot.Position
            + Vector3.new(
                0,
                4,
                0
            )
    end

    return nil
end

function HolySniperBuildReturnCFrame(position)

    if typeof(position) ~= "Vector3" then
        return nil
    end

    local root =
        HolySniperGetCharacterRoot()

    local lookVector =
        root
        and root:IsA("BasePart")
        and root.CFrame.LookVector
        or Vector3.new(
            0,
            0,
            -1
        )

    lookVector =
        Vector3.new(
            lookVector.X,
            0,
            lookVector.Z
        )

    if lookVector.Magnitude < 0.1 then

        lookVector =
            Vector3.new(
                0,
                0,
                -1
            )

    else

        lookVector =
            lookVector.Unit
    end

    return CFrame.new(
        position,
        position + lookVector
    )
end

function HolySniperGetFarmCenterCFrame(forceRefresh)

    HOLY_SNIPER_RUNTIME.FarmCenterLastScanAt =
        tonumber(
            HOLY_SNIPER_RUNTIME.FarmCenterLastScanAt
        )
        or 0

    if forceRefresh ~= true
    and typeof(HOLY_SNIPER_RUNTIME.FarmCenterCFrame) == "CFrame"
    and os.clock() - HOLY_SNIPER_RUNTIME.FarmCenterLastScanAt < 8 then

        return HOLY_SNIPER_RUNTIME.FarmCenterCFrame
    end

    local garden =
        HolySniperFindOwnedGarden()

    if not garden then
        return nil
    end

    local position =
        HolySniperPickGardenCenterPosition(
            garden
        )

    if typeof(position) ~= "Vector3" then
        return nil
    end

    local cframe =
        HolySniperBuildReturnCFrame(
            position
        )

    HOLY_SNIPER_RUNTIME.FarmCenterCFrame =
        cframe

    HOLY_SNIPER_RUNTIME.FarmCenterLastScanAt =
        os.clock()

    return cframe
end

function HolyFarmMiddleWateringRejoinActive()

    local state =
        type(HOLY_WATERING_REJOIN_STATE) == "table"
        and HOLY_WATERING_REJOIN_STATE
        or {}

    local runtime =
        type(HOLY_WATERING_REJOIN_RUNTIME) == "table"
        and HOLY_WATERING_REJOIN_RUNTIME
        or {}

    return state.Enabled == true
        or runtime.Running == true
        or runtime.Teleporting == true
end

function HolyFarmMiddlePauseForWatering(reason)

    local state =
        HolyFarmMiddleGetState()

    state.Token =
        nil

    state.Running =
        false

    state.Moving =
        false

    state.CancelArmed =
        false

    state.ManualCancelled =
        false

    state.SniperCancelled =
        false

    HolyFarmMiddleStopMovement()

    HolyFarmMiddleSetStatus(
        "Paused",
        reason or "watering rejoin"
    )

    return true
end

function HolyFarmMiddleResumeAfterWatering()

    if HOLY_DEV_UI_STATE.AutoFarmMiddle ~= true then
        return false
    end

    if HolyFarmMiddleWateringRejoinActive() == true then
        return false
    end

    local state =
        HolyFarmMiddleGetState()

    if state.Running == true then
        return true
    end

    state.ManualCancelled =
        false

    state.SniperCancelled =
        false

    state.Done =
        false

    state.Moving =
        false

    state.CancelArmed =
        false

    HolyFarmMiddleConnectCharacterWatcher()

    return HolyFarmMiddleStart(
        "watering rejoin ended"
    )
end

function HolyFarmMiddleGetState()

    HOLY_FARM_MIDDLE_STATE =
        type(HOLY_FARM_MIDDLE_STATE) == "table"
        and HOLY_FARM_MIDDLE_STATE
        or {}

    local state =
        HOLY_FARM_MIDDLE_STATE

    state.InputConnections =
        type(state.InputConnections) == "table"
        and state.InputConnections
        or {}

    state.StopDistance =
        math.clamp(
            tonumber(state.StopDistance)
            or 10,
            6,
            18
        )

    state.MaxRunSeconds =
        math.clamp(
            tonumber(state.MaxRunSeconds)
            or 75,
            15,
            180
        )

    state.MoveRetryDelay =
        math.clamp(
            tonumber(state.MoveRetryDelay)
            or 0.35,
            0.12,
            1
        )

    state.TargetRefreshSeconds =
        math.clamp(
            tonumber(state.TargetRefreshSeconds)
            or 2,
            0.5,
            10
        )

    state.StartAfterLoadingDelay =
        math.clamp(
            tonumber(state.StartAfterLoadingDelay)
            or 1.00,
            0,
            3
        )

    state.SniperPauseDelay =
        math.clamp(
            tonumber(state.SniperPauseDelay)
            or 0.18,
            0.08,
            1
        )

    state.MissingTargetDelay =
        math.clamp(
            tonumber(state.MissingTargetDelay)
            or 0.25,
            0.10,
            2
        )

    state.ManualCancelGrace =
        math.clamp(
            tonumber(state.ManualCancelGrace)
            or 0.20,
            0,
            1
        )

    state.Enabled =
        HOLY_DEV_UI_STATE.AutoFarmMiddle == true

    return state
end

function HolyFarmMiddleSetStatus(status, reason)

    local state =
        HolyFarmMiddleGetState()

    state.LastStatus =
        tostring(status or "Ready")

    state.LastReason =
        tostring(reason or "")

    state.LastStatusAt =
        os.clock()
end

function HolyFarmMiddleStopMovement()

    local humanoid =
        HolySniperGetCharacterHumanoid()

    local root =
        HolySniperGetCharacterRoot()

    if type(HolySniperStopHumanoidMovement) == "function" then

        HolySniperStopHumanoidMovement(
            humanoid,
            root
        )
    end

    if type(HolySniperZeroRootVelocity) == "function" then

        HolySniperZeroRootVelocity(
            root
        )
    end

    return true
end

function HolyFarmMiddleDisconnectInputWatcher()

    local state =
        HolyFarmMiddleGetState()

    for _, connection in ipairs(state.InputConnections or {}) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    state.InputConnections =
        {}

    state.InputWatcherStarted =
        false
end

function HolyFarmMiddleCancel(reason)

    local state =
        HolyFarmMiddleGetState()

    state.ManualCancelled =
        true

    state.Running =
        false

    state.Moving =
        false

    state.Token =
        nil

    state.CancelArmed =
        false

    HolyFarmMiddleStopMovement()

    HolyFarmMiddleSetStatus(
        "Cancelled",
        reason or "manual movement"
    )

    return true
end

function HolyFarmMiddleCancelForSniper(reason)

    local state =
        HolyFarmMiddleGetState()

    if state.Done == true then
        return false
    end

    if state.Running ~= true
    and state.Moving ~= true
    and state.Token == nil then

        return false
    end

    state.SniperCancelled =
        true

    state.ManualCancelled =
        true

    state.Running =
        false

    state.Moving =
        false

    state.Token =
        nil

    state.CancelArmed =
        false

    state.TargetCFrame =
        nil

    state.TargetResolvedAt =
        0

    HolyFarmMiddleSetStatus(
        "Cancelled",
        reason or "sniper priority"
    )

    return true
end

function HolyFarmMiddleInputIsCancel(input)

    if typeof(input) ~= "InputObject" then
        return false
    end

    if input.UserInputType == Enum.UserInputType.Gamepad1
    and input.KeyCode == Enum.KeyCode.Thumbstick1 then

        local position =
            input.Position

        if typeof(position) == "Vector3" then

            if math.abs(position.X) < 0.18
            and math.abs(position.Y) < 0.18 then

                return false
            end
        end
    end

    if type(HolySniperIsManualMovementInput) == "function" then

        return HolySniperIsManualMovementInput(
            input
        ) == true
    end

    local keyCode =
        input.KeyCode

    return keyCode == Enum.KeyCode.W
        or keyCode == Enum.KeyCode.A
        or keyCode == Enum.KeyCode.S
        or keyCode == Enum.KeyCode.D
        or keyCode == Enum.KeyCode.Up
        or keyCode == Enum.KeyCode.Down
        or keyCode == Enum.KeyCode.Left
        or keyCode == Enum.KeyCode.Right
        or keyCode == Enum.KeyCode.Space
end

function HolyFarmMiddleMarkManualInput(input)

    local state =
        HolyFarmMiddleGetState()

    if state.Running ~= true then
        return false
    end

    if state.CancelArmed ~= true then
        return false
    end

    if state.Done == true
    or state.ManualCancelled == true then

        return false
    end

    if os.clock() < (
        tonumber(state.AcceptManualInputAfter)
        or 0
    ) then

        return false
    end

    local focusedTextBox =
        nil

    pcall(function()

        focusedTextBox =
            UserInputService:GetFocusedTextBox()
    end)

    if focusedTextBox ~= nil then
        return false
    end

    if HolyFarmMiddleInputIsCancel(input) ~= true then
        return false
    end

    return HolyFarmMiddleCancel(
        "manual movement"
    )
end

function HolyFarmMiddleConnectInputWatcher()

    local state =
        HolyFarmMiddleGetState()

    if state.InputWatcherStarted == true then
        return true
    end

    state.InputWatcherStarted =
        true

    state.InputConnections =
        type(state.InputConnections) == "table"
        and state.InputConnections
        or {}

    table.insert(
        state.InputConnections,
        UserInputService.InputBegan:Connect(function(input)

            HolyFarmMiddleMarkManualInput(
                input
            )
        end)
    )

    table.insert(
        state.InputConnections,
        UserInputService.InputChanged:Connect(function(input)

            if input.UserInputType == Enum.UserInputType.Gamepad1
            and input.KeyCode == Enum.KeyCode.Thumbstick1 then

                HolyFarmMiddleMarkManualInput(
                    input
                )
            end
        end)
    )

    return true
end

function HolyFarmMiddleManualInputDown()

    local state =
        HolyFarmMiddleGetState()

    if state.CancelArmed ~= true then
        return false
    end

    if os.clock() < (
        tonumber(state.AcceptManualInputAfter)
        or 0
    ) then

        return false
    end

    local focusedTextBox =
        nil

    pcall(function()

        focusedTextBox =
            UserInputService:GetFocusedTextBox()
    end)

    if focusedTextBox ~= nil then
        return false
    end

    if type(HolySniperMovementInputIsDown) == "function" then

        return HolySniperMovementInputIsDown() == true
    end

    return false
end

function HolyFarmMiddleLoadingReady()

    if HolySniperGetCharacterRoot() == nil then

        return false,
            "character"
    end

    local loadingGui =
        nil

    if type(HolyLoadingGetWorkspaceLoadingGui) == "function" then

        local ok,
            result =
            pcall(function()

                return HolyLoadingGetWorkspaceLoadingGui()
            end)

        if ok == true then

            loadingGui =
                result
        end
    end

    if loadingGui ~= nil then

        if type(HOLY_LOADING_SKIP_STATE) == "table"
        and HOLY_LOADING_SKIP_STATE.PressedFinal == true then

            return true,
                "final pressed"
        end

        return false,
            "loading"
    end

    if type(HOLY_LOADING_SKIP_STATE) == "table"
    and HOLY_DEV_UI_STATE.AutoSkipLoading == true
    and HOLY_LOADING_SKIP_STATE.Running == true
    and HOLY_LOADING_SKIP_STATE.ClickedSkip ~= true
    and HOLY_LOADING_SKIP_STATE.PressedFinal ~= true then

        return false,
            "skip loading"
    end

    return true,
        "ready"
end

function HolyFarmMiddleSeedCollectorBusy()

    local states = {
        rawget(_G, "HOLY_SEED_COLLECTOR_STATE"),
        rawget(_G, "HOLY_AUTO_COLLECT_SEEDS_STATE"),
        rawget(_G, "GAG2_AUTO_COLLECT_SEEDS_STATE"),
    }

    for _, seedState in ipairs(states) do

        if type(seedState) == "table" then

            if seedState.Busy == true
            or seedState.Moving == true
            or seedState.Collecting == true
            or seedState.Claiming == true
            or seedState.Walking == true then

                return true,
                    "seed collector"
            end

            if seedState.Enabled == true
            and seedState.Running == true
            and (
                seedState.CurrentTarget ~= nil
                or seedState.Target ~= nil
            ) then

                return true,
                    "seed collector"
            end
        end
    end

    return false,
        "clear"
end

function HolyFarmMiddleSniperBusy()

    if type(HOLY_DEFENSE_RUNTIME) == "table"
    and HOLY_DEFENSE_RUNTIME.Active == true then

        return true,
            "pet defense"
    end

    local runtime =
        type(HOLY_SNIPER_RUNTIME) == "table"
        and HOLY_SNIPER_RUNTIME
        or {}

    if runtime.Buying == true then
        return true, "sniper buying"
    end

    if runtime.Returning == true then
        return true, "sniper returning"
    end

    if runtime.AutoHopInProgress == true then
        return true, "auto hop"
    end

    if runtime.CurrentTarget ~= nil then
        return true, "sniper target"
    end

    if HolyCleanText(runtime.CurrentTargetKey) ~= "" then
        return true, "sniper target"
    end

    if runtime.BatchActive == true then
        return true, "sniper batch"
    end

    if type(HolySniperTargetLockActive) == "function" then

        local ok,
            active,
            reason =
            pcall(function()

                return HolySniperTargetLockActive()
            end)

        if ok == true
        and active == true then

            return true,
                tostring(reason or "target locked")
        end
    end

    if type(HolySniperPetBuyProtectionActive) == "function" then

        local ok,
            active,
            reason =
            pcall(function()

                return HolySniperPetBuyProtectionActive()
            end)

        if ok == true
        and active == true then

            return true,
                tostring(reason or "pet buy protection")
        end
    end

    local lastMatchAt =
        tonumber(runtime.LastMatchAt)
        or 0

    local matchCount =
        tonumber(runtime.MatchCount)
        or 0

    if matchCount > 0
    and os.clock() - lastMatchAt <= 3 then

        return true,
            "match found"
    end

    local seedBusy,
        seedReason =
        HolyFarmMiddleSeedCollectorBusy()

    if seedBusy == true then
        return true, seedReason
    end

    return false,
        "clear"
end

function HolyFarmMiddleResolveTarget(forceRefresh)

    local state =
        HolyFarmMiddleGetState()

    if forceRefresh ~= true
    and typeof(state.TargetCFrame) == "CFrame"
    and os.clock() - (
        tonumber(state.TargetResolvedAt)
        or 0
    ) < state.TargetRefreshSeconds then

        return state.TargetCFrame
    end

    local cframe =
        nil

    if type(HolySniperGetFarmCenterCFrame) == "function" then

        cframe =
            HolySniperGetFarmCenterCFrame(
                true
            )
    end

    if typeof(cframe) == "CFrame" then

        state.TargetCFrame =
            cframe

        state.TargetResolvedAt =
            os.clock()

        return cframe
    end

    return nil
end

function HolyFarmMiddleFlatDistance(root, targetPosition)

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or typeof(targetPosition) ~= "Vector3" then

        return math.huge
    end

    return (
        Vector3.new(
            root.Position.X,
            0,
            root.Position.Z
        )
        -
        Vector3.new(
            targetPosition.X,
            0,
            targetPosition.Z
        )
    ).Magnitude
end

function HolyFarmMiddleRunWorker(token, reason)

    local state =
        HolyFarmMiddleGetState()

    state.StartedAt =
        os.clock()

    state.Running =
        true

    state.Done =
        false

    state.Moving =
        false

    state.ManualCancelled =
        false

    state.SniperCancelled =
        false

    state.CancelArmed =
        false

    state.AcceptManualInputAfter =
        0

    state.TargetCFrame =
        nil

    state.TargetResolvedAt =
        0

    local loadingReadyAt =
        0

    HolyFarmMiddleSetStatus(
        "Waiting loading",
        tostring(reason or "startup")
    )

    while state.Token == token
    and state.Enabled == true
    and HOLY_DEV_UI_STATE.AutoFarmMiddle == true
    and os.clock() - state.StartedAt <= state.MaxRunSeconds do

        if state.ManualCancelled == true then

            HolyFarmMiddleStopMovement()

            state.Running =
                false

            state.Moving =
                false

            return false
        end

        local loadingReady,
            loadingReason =
            HolyFarmMiddleLoadingReady()

        if loadingReady ~= true then

            state.CancelArmed =
                false

            state.Moving =
                false

            HolyFarmMiddleSetStatus(
                "Waiting loading",
                loadingReason
            )

            task.wait(
                0.15
            )

            continue
        end

        if loadingReadyAt <= 0 then

            loadingReadyAt =
                os.clock()

            state.CancelArmed =
                true

            state.AcceptManualInputAfter =
                os.clock()
                + state.ManualCancelGrace
                + state.StartAfterLoadingDelay

            HolyFarmMiddleSetStatus(
                "Settling",
                "loading ready"
            )
        end

        if os.clock() - loadingReadyAt < state.StartAfterLoadingDelay then

            task.wait(
                0.05
            )

            continue
        end

        if HolyFarmMiddleManualInputDown() == true then

            HolyFarmMiddleCancel(
                "manual movement"
            )

            return false
        end

        local sniperBusy,
            busyReason =
            HolyFarmMiddleSniperBusy()

        if sniperBusy == true then

            HolyFarmMiddleCancelForSniper(
                busyReason
            )

            return false
        end

        local targetCFrame =
            HolyFarmMiddleResolveTarget(
                os.clock() - (
                    tonumber(state.TargetResolvedAt)
                    or 0
                ) >= state.TargetRefreshSeconds
            )

        if typeof(targetCFrame) ~= "CFrame" then

            state.Moving =
                false

            HolyFarmMiddleSetStatus(
                "Waiting farm",
                "farm middle not found"
            )

            task.wait(
                state.MissingTargetDelay
            )

            continue
        end

        local humanoid =
            HolySniperGetCharacterHumanoid()

        local root =
            HolySniperGetCharacterRoot()

        if typeof(humanoid) ~= "Instance"
        or humanoid:IsA("Humanoid") ~= true
        or typeof(root) ~= "Instance"
        or root:IsA("BasePart") ~= true then

            state.Moving =
                false

            HolyFarmMiddleSetStatus(
                "Waiting character",
                "humanoid/root missing"
            )

            task.wait(
                0.15
            )

            continue
        end

        local targetPosition =
            targetCFrame.Position

        local distance =
            HolyFarmMiddleFlatDistance(
                root,
                targetPosition
            )

        state.LastDistance =
            distance

        if distance <= state.StopDistance then

            state.Done =
                true

            state.Running =
                false

            state.Moving =
                false

            state.CancelArmed =
                false

            HolyFarmMiddleStopMovement()

            HolyFarmMiddleSetStatus(
                "Done",
                tostring(
                    math.floor(distance + 0.5)
                )
                .. " studs"
            )

            return true
        end

        state.Moving =
            true

        state.CancelArmed =
            true

        if (
            tonumber(state.AcceptManualInputAfter)
            or 0
        ) <= 0 then

            state.AcceptManualInputAfter =
                os.clock()
                + state.ManualCancelGrace
        end

        HolyFarmMiddleSetStatus(
            "Walking",
            tostring(
                math.floor(distance + 0.5)
            )
            .. " studs"
        )

        local movePosition =
            Vector3.new(
                targetPosition.X,
                root.Position.Y,
                targetPosition.Z
            )

        if type(HolySniperClearHeldToolForMovement) == "function" then

            HolySniperClearHeldToolForMovement(
                "farm middle walk"
            )
        end

        pcall(function()

            humanoid:MoveTo(
                movePosition
            )
        end)

        state.LastMoveAt =
            os.clock()

        task.wait(
            state.MoveRetryDelay
        )
    end

    if state.Token == token then

        state.Running =
            false

        state.Moving =
            false

        state.CancelArmed =
            false

        HolyFarmMiddleStopMovement()

        HolyFarmMiddleSetStatus(
            "Stopped",
            "timeout"
        )
    end

    return false
end

function HolyFarmMiddleStop(reason)

    local state =
        HolyFarmMiddleGetState()

    state.Token =
        nil

    state.Running =
        false

    state.Moving =
        false

    state.CancelArmed =
        false

    HolyFarmMiddleStopMovement()

    HolyFarmMiddleSetStatus(
        "Stopped",
        reason or "manual"
    )

    return true
end

function HolyFarmMiddleStart(reason)

    local state =
        HolyFarmMiddleGetState()

    if HOLY_DEV_UI_STATE.AutoFarmMiddle ~= true then

        return false
    end

    state.Enabled =
        true

    if type(HolyFruitAutomationPickupOwnsMovement)
        == "function"
    and HolyFruitAutomationPickupOwnsMovement() == true then

        state.Token =
            nil

        state.Running =
            false

        state.Moving =
            false

        state.CancelArmed =
            false

        HolyFarmMiddleStopMovement()

        HolyFarmMiddleSetStatus(
            "Paused",
            "dropped fruit walking"
        )

        return false
    end

    if HolyFarmMiddleWateringRejoinActive() == true then

        HolyFarmMiddlePauseForWatering(
            "watering rejoin active"
        )

        return false
    end

    if state.Running == true then

        return false
    end

    HolyFarmMiddleConnectInputWatcher()

    local token =
        {}

    state.Token =
        token

    state.Running =
        true

    state.Done =
        false

    state.ManualCancelled =
        false

    state.SniperCancelled =
        false

    state.Moving =
        false

    state.CancelArmed =
        false

    task.spawn(function()

        HolyFarmMiddleRunWorker(
            token,
            reason or "startup"
        )
    end)

    return true
end

function HolyFarmMiddleConnectCharacterWatcher()

    local state =
        HolyFarmMiddleGetState()

    if state.CharacterConnection then
        return true
    end

    if not LocalPlayer then
        return false
    end

    state.CharacterConnection =
        LocalPlayer.CharacterAdded:Connect(function()

            local liveState =
                HolyFarmMiddleGetState()

            liveState.Token =
                nil

            liveState.Running =
                false

            liveState.Moving =
                false

            liveState.Done =
                false

            liveState.ManualCancelled =
                false

            liveState.SniperCancelled =
                false

            liveState.CancelArmed =
                false

            liveState.TargetCFrame =
                nil

            liveState.TargetResolvedAt =
                0

            if HOLY_DEV_UI_STATE.AutoFarmMiddle == true then

                task.delay(0.65, function()

                    if HOLY_DEV_UI_STATE.AutoFarmMiddle == true then

                        HolyFarmMiddleStart(
                            "respawn"
                        )
                    end
                end)
            end
        end)

    return true
end

function HolyFarmMiddleDisconnectCharacterWatcher()

    local state =
        HolyFarmMiddleGetState()

    if state.CharacterConnection then

        pcall(function()

            state.CharacterConnection:Disconnect()
        end)
    end

    state.CharacterConnection =
        nil
end

function HolyFarmMiddleSetEnabled(value, reason)

    local enabled =
        value == true

    HOLY_DEV_UI_STATE.AutoFarmMiddle =
        enabled

    local state =
        HolyFarmMiddleGetState()

    state.Enabled =
        enabled

    HolySaveUISettings()

    if enabled == true then

        HolyFarmMiddleConnectCharacterWatcher()

        state.ManualCancelled =
            false

        state.SniperCancelled =
            false

        state.Done =
            false

        return HolyFarmMiddleStart(
            reason or "enabled"
        )
    end

    HolyFarmMiddleStop(
        reason or "disabled"
    )

    HolyFarmMiddleDisconnectCharacterWatcher()
    HolyFarmMiddleDisconnectInputWatcher()

    return true
end

function HolyFarmMiddleRestoreState()

    local state =
        HolyFarmMiddleGetState()

    state.Enabled =
        HOLY_DEV_UI_STATE.AutoFarmMiddle == true

    if state.Enabled == true then

        HolyFarmMiddleConnectCharacterWatcher()

        task.defer(function()

            HolyFarmMiddleStart(
                "startup"
            )
        end)

    else

        HolyFarmMiddleStop(
            "disabled"
        )
    end

    return true
end

function HolySniperResolveReturnCFrame()

    local destination =
        HolySniperNormalizeReturnDestination(
            HOLY_SNIPER_STATE.ReturnDestination
        )

    local savedCFrame =
        HolySniperGetSavedReturnCFrame()

    local activationCFrame =
        typeof(HOLY_SNIPER_RUNTIME.ReturnActivationCFrame) == "CFrame"
        and HOLY_SNIPER_RUNTIME.ReturnActivationCFrame
        or nil

    local root =
        HolySniperGetCharacterRoot()

    local currentCFrame =
        root
        and root:IsA("BasePart")
        and root.CFrame
        or nil

    if destination == "Saved Position" then

        if savedCFrame then
            return savedCFrame, "Saved Position"
        end

        if activationCFrame then
            return activationCFrame, "Sniper Start"
        end

        local farmCFrame =
            HolySniperGetFarmCenterCFrame()

        if farmCFrame then
            return farmCFrame, "Farm Center"
        end

        return currentCFrame,
            "Current Position"
    end

    local farmCFrame =
        HolySniperGetFarmCenterCFrame()

    if farmCFrame then
        return farmCFrame, "Farm Center"
    end

    if savedCFrame then
        return savedCFrame, "Saved Position"
    end

    if activationCFrame then
        return activationCFrame, "Sniper Start"
    end

    return currentCFrame,
        "Current Position"
end

function HolySniperReturnTeleport(cframe, token)

    HolySniperClearHeldToolForMovement(
        "return teleport"
    )

    if typeof(cframe) ~= "CFrame" then
        return false, "missing return cframe"
    end

    if HolySniperStillActive(token) ~= true then
        return false, "stopped"
    end

    local root =
        HolySniperGetCharacterRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false,
            "missing root"
    end

    HolySniperZeroRootVelocity(
        root
    )

    local ok,
        err =
        pcall(function()

            root.CFrame =
                cframe
        end)

    if ok ~= true then

        return false,
            "teleport return failed "
            .. tostring(err)
    end

    task.wait(
        0.08
    )

    HolySniperZeroRootVelocity(
        root
    )

    return true,
        "teleported"
end

function HolySniperReturnWalk(cframe, token)

    HolySniperClearHeldToolForMovement(
        "return walk start"
    )

    if typeof(cframe) ~= "CFrame" then
        return false, "missing return cframe"
    end

    local targetPosition =
        cframe.Position

    local timeout =
        tonumber(
            HOLY_SNIPER_RUNTIME.ReturnWalkTimeout
        )
        or 22

    local arriveDistance =
        tonumber(
            HOLY_SNIPER_RUNTIME.ReturnArriveDistance
        )
        or 12

    local startedAt =
        os.clock()

    local lastStatusAt =
        0

    while HolySniperStillActive(token) == true
    and os.clock() - startedAt <= timeout do

        HolySniperClearHeldToolForMovement(
            "return walk loop"
        )

        local humanoid =
            HolySniperGetCharacterHumanoid()

        local root =
            HolySniperGetCharacterRoot()

        if typeof(humanoid) ~= "Instance"
        or typeof(root) ~= "Instance"
        or root:IsA("BasePart") ~= true then

            return false,
                "missing humanoid/root"
        end

        if HolySniperManualReturnCancelled(
            startedAt
        ) == true then

            HolySniperStopHumanoidMovement(
                humanoid,
                root
            )

            return false,
                "manual movement"
        end

        local flatDelta =
            Vector3.new(
                root.Position.X - targetPosition.X,
                0,
                root.Position.Z - targetPosition.Z
            )

        local flatDistance =
            flatDelta.Magnitude

        if os.clock() - lastStatusAt >= 0.55 then

            lastStatusAt =
                os.clock()

            HolySniperSetStatus(
                "Returning / "
                .. tostring(
                    math.floor(flatDistance + 0.5)
                )
                .. " studs"
            )
        end

        if flatDistance <= arriveDistance then

            HolySniperStopHumanoidMovement(
                humanoid,
                root
            )

            HolySniperZeroRootVelocity(
                root
            )

            return true,
                "walked"
        end

        local movePosition =
            Vector3.new(
                targetPosition.X,
                root.Position.Y,
                targetPosition.Z
            )

        pcall(function()

            humanoid:MoveTo(
                movePosition
            )
        end)

        task.wait(
            0.14
        )
    end

    local humanoid =
        HolySniperGetCharacterHumanoid()

    local root =
        HolySniperGetCharacterRoot()

    HolySniperStopHumanoidMovement(
        humanoid,
        root
    )

    return false,
        "return walk timeout"
end

function HolySniperReturnToDestination(reason, token)

    if HOLY_SNIPER_STATE.ReturnEnabled ~= true then
        return false
    end

    if type(HOLY_DEFENSE_RUNTIME) == "table"
    and HOLY_DEFENSE_RUNTIME.Active == true then

        return false
    end

    if HOLY_SNIPER_RUNTIME.Returning == true then
        return false
    end

    local cframe,
        destinationName =
        HolySniperResolveReturnCFrame()

    if typeof(cframe) ~= "CFrame" then

        HolySniperSetStatus(
            "Return skipped: no destination"
        )

        return false
    end

    HOLY_SNIPER_RUNTIME.Returning =
        true

    HolySniperSetStatus(
        "Returning to "
        .. tostring(destinationName)
    )

    local mode =
        HolySniperNormalizeReturnMode(
            HOLY_SNIPER_STATE.ReturnMode
        )

    local ok,
        returnReason =
        false,
        ""

    if mode == "Teleport" then

        ok,
            returnReason =
            HolySniperReturnTeleport(
                cframe,
                token
            )

    else

        ok,
            returnReason =
            HolySniperReturnWalk(
                cframe,
                token
            )
    end

    HOLY_SNIPER_RUNTIME.Returning =
        false

    if ok == true then

        HolySniperSetStatus(
            "Returned to "
            .. tostring(destinationName)
        )

    elseif tostring(returnReason) == "manual movement" then

        HolySniperSetStatus(
            "Return cancelled by movement"
        )

    else

        HolySniperSetStatus(
            "Return failed: "
            .. tostring(returnReason)
        )
    end

    return ok
end

function HolySniperRegisterConfirmedBuy(match, entry)

    if HOLY_SNIPER_STATE.ReturnEnabled ~= true then
        return
    end

    if HolySniperNormalizeReturnTiming(
        HOLY_SNIPER_STATE.ReturnTiming
    ) ~= "After Batch" then

        return
    end

    HOLY_SNIPER_RUNTIME.BatchActive =
        true

    HOLY_SNIPER_RUNTIME.BatchBoughtCount =
        (
            tonumber(
                HOLY_SNIPER_RUNTIME.BatchBoughtCount
            )
            or 0
        )
        + 1

    HOLY_SNIPER_RUNTIME.BatchEmptySince =
        0
end

function HolySniperMaybeReturnAfterBuy(token)

    if HOLY_SNIPER_STATE.ReturnEnabled ~= true then
        return false
    end

    if HolySniperNormalizeReturnTiming(
        HOLY_SNIPER_STATE.ReturnTiming
    ) ~= "After Buy" then

        return false
    end

    return HolySniperReturnToDestination(
        "after buy",
        token
    )
end

function HolySniperMaybeReturnAfterBatchNoMatches(token)

    if HOLY_SNIPER_STATE.ReturnEnabled ~= true then
        return false
    end

    if HolySniperNormalizeReturnTiming(
        HOLY_SNIPER_STATE.ReturnTiming
    ) ~= "After Batch" then

        HOLY_SNIPER_RUNTIME.BatchActive =
            false

        HOLY_SNIPER_RUNTIME.BatchBoughtCount =
            0

        HOLY_SNIPER_RUNTIME.BatchEmptySince =
            0

        return false
    end

    if HOLY_SNIPER_RUNTIME.BatchActive ~= true then
        return false
    end

    if (
        tonumber(
            HOLY_SNIPER_RUNTIME.BatchBoughtCount
        )
        or 0
    ) <= 0 then

        return false
    end

    if HOLY_SNIPER_RUNTIME.Buying == true
    or HOLY_SNIPER_RUNTIME.Returning == true then

        return false
    end

    local now =
        os.clock()

    if (
        tonumber(
            HOLY_SNIPER_RUNTIME.BatchEmptySince
        )
        or 0
    ) <= 0 then

        HOLY_SNIPER_RUNTIME.BatchEmptySince =
            now

        HolySniperSetStatus(
            "Batch clear, waiting..."
        )

        return false
    end

    local stableSeconds =
        tonumber(
            HOLY_SNIPER_RUNTIME.BatchStableSeconds
        )
        or 1.5

    if now - HOLY_SNIPER_RUNTIME.BatchEmptySince < stableSeconds then
        return false
    end

    local returned =
        HolySniperReturnToDestination(
            "after batch",
            token
        )

    HOLY_SNIPER_RUNTIME.BatchActive =
        false

    HOLY_SNIPER_RUNTIME.BatchBoughtCount =
        0

    HOLY_SNIPER_RUNTIME.BatchEmptySince =
        0

    return returned
end

function HolySniperMoveWalkToEntry(entry, filter, token)

    HolySniperClearHeldToolForMovement(
        "walk to pet start"
    )

    local startedAt =
        os.clock()

    local timeout =
        tonumber(
            HOLY_SNIPER_RUNTIME.WalkTimeout
        )
        or 26

    local lastStatusAt =
        0

    while HolySniperStillActive(token) == true
    and os.clock() - startedAt <= timeout do

        HolySniperClearHeldToolForMovement(
            "walk to pet loop"
        )

        local valid,
            refreshed,
            reason =
            HolySniperValidateTargetForBuy(
                entry,
                filter
            )

        if valid ~= true then

            return false,
                refreshed,
                reason
        end

        entry =
            refreshed

        local humanoid =
            HolySniperGetCharacterHumanoid()

        local root =
            HolySniperGetCharacterRoot()

        if typeof(humanoid) ~= "Instance"
        or typeof(root) ~= "Instance"
        or root:IsA("BasePart") ~= true then

            return false,
                entry,
                "missing humanoid/root"
        end

        local position =
            HolySniperGetPromptPosition(
                entry.Prompt,
                entry.Model
            )

        if typeof(position) ~= "Vector3" then

            return false,
                entry,
                "missing prompt position"
        end

        local distance =
            (
                root.Position
                - position
            ).Magnitude

        local safeRange =
            HolySniperGetSafeRange(
                entry.Prompt
            )

        if os.clock() - lastStatusAt >= 0.55 then

            lastStatusAt =
                os.clock()

            HolySniperSetStatus(
                "Walking: "
                .. HolySniperDescribeEntry(entry)
                .. " / "
                .. tostring(
                    math.floor(distance + 0.5)
                )
                .. " studs"
            )
        end

        if distance <= safeRange then

            pcall(function()

                humanoid:MoveTo(
                    root.Position
                )
            end)

            return true,
                entry,
                "in range"
        end

        pcall(function()

            humanoid:MoveTo(
                position
            )
        end)

        task.wait(
            0.12
        )
    end

    return false,
        entry,
        "walk timeout"
end

function HolySniperMoveTeleportToEntry(entry, filter, token)

    HolySniperClearHeldToolForMovement(
        "teleport to pet start"
    )

    local valid,
        refreshed,
        reason =
        HolySniperValidateTargetForBuy(
            entry,
            filter
        )

    if valid ~= true then

        return false,
            refreshed,
            reason
    end

    entry =
        refreshed

    local root =
        HolySniperGetCharacterRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false,
            entry,
            "missing root"
    end

    local position =
        HolySniperGetPromptPosition(
            entry.Prompt,
            entry.Model
        )

    if typeof(position) ~= "Vector3" then

        return false,
            entry,
            "missing prompt position"
    end

    HolySniperSetStatus(
        "Teleporting: "
        .. HolySniperDescribeEntry(entry)
    )

    local away =
        root.Position
        - position

    away =
        Vector3.new(
            away.X,
            0,
            away.Z
        )

    if away.Magnitude < 1 then

        away =
            Vector3.new(
                0,
                0,
                1
            )

    else

        away =
            away.Unit
    end

    local destination =
        position
        + away * 6
        + Vector3.new(
            0,
            2.4,
            0
        )

    local cframe =
        CFrame.new(
            destination,
            position
        )

    HolySniperZeroRootVelocity(
        root
    )

    local ok,
        err =
        pcall(function()

            root.CFrame =
                cframe
        end)

    if ok ~= true then

        return false,
            entry,
            "teleport failed "
            .. tostring(err)
    end

    task.wait(
        0.055
    )

    HolySniperZeroRootVelocity(
        root
    )

    task.wait(
        0.035
    )

    HolySniperClearHeldToolForMovement(
        "teleport to pet verify"
    )

    valid,
        refreshed,
        reason =
        HolySniperValidateTargetForBuy(
            entry,
            filter
        )

    if valid ~= true then

        return false,
            refreshed,
            reason
    end

    entry =
        refreshed

    local distance =
        HolySniperDistanceToEntry(
            entry
        )

    local safeRange =
        HolySniperGetSafeRange(
            entry.Prompt
        )

    if distance > safeRange then

        return false,
            entry,
            "teleport out of range "
            .. tostring(
                math.floor(distance + 0.5)
            )
    end

    return true,
        entry,
        "teleported"
end

function HolySniperTriggerPrompt(prompt)

    if typeof(prompt) ~= "Instance"
    or prompt:IsA("ProximityPrompt") ~= true
    or prompt.Parent == nil then

        return false,
            "bad prompt"
    end

    local hold =
        math.max(
            tonumber(prompt.HoldDuration)
            or 1,
            0.05
        )

    local buyMode =
        HolySniperNormalizeBuyMode(
            HOLY_SNIPER_STATE.BuyMode
        )

    if buyMode == "Instant"
    and type(fireproximityprompt) == "function" then

        local ok,
            err =
            pcall(function()

                fireproximityprompt(
                    prompt,
                    hold + 0.25
                )
            end)

        if ok == true then

            task.wait(
                0.08
            )

            return true,
                "fireproximityprompt"
        end
    end

    local beginOk =
        pcall(function()

            prompt:InputHoldBegin()
        end)

    task.wait(
        hold + 0.20
    )

    local endOk =
        pcall(function()

            prompt:InputHoldEnd()
        end)

    if beginOk == true
    and endOk == true then

        return true,
            "hold prompt"
    end

    return false,
        "prompt trigger failed"
end

function HolySniperAddUniqueReason(reasons, reason)

    reason =
        HolyCleanText(
            reason
        )

    if reason == "" then
        return
    end

    for _, existing in ipairs(reasons) do

        if existing == reason then
            return
        end
    end

    table.insert(
        reasons,
        reason
    )
end

function HolySniperConfirmBuy(entry, beforeSheckles, token)

    local deadline =
        os.clock()
        + (
            tonumber(
                HOLY_SNIPER_RUNTIME.ConfirmTimeout
            )
            or 9
        )

    local reasons =
        {}

    while os.clock() <= deadline do

        if token ~= nil
        and HolySniperStillActive(token) ~= true then

            return false,
                "cancelled"
        end

        local ref =
            type(entry) == "table"
            and entry.Ref
            or nil

        if typeof(ref) == "Instance"
        and ref.Parent ~= nil then

            local ownerUserId =
                tonumber(
                    HolySniperReadModelAttribute(
                        ref,
                        {
                            "OwnerUserId",
                            "OwnerUserID",
                            "Owner",
                            "UserId",
                            "UserID",
                        }
                    )
                )
                or 0

            local ownerName =
                HolyCleanText(
                    HolySniperReadModelAttribute(
                        ref,
                        {
                            "OwnerName",
                            "OwnerDisplayName",
                        }
                    )
                )

            local state =
                HolyCleanText(
                    HolySniperReadModelAttribute(
                        ref,
                        {
                            "State",
                            "PetState",
                        }
                    )
                )

            if ownerUserId == tonumber(LocalPlayer.UserId) then

                HolySniperAddUniqueReason(
                    reasons,
                    "owner user id"
                )

                HolySniperTouchPetBuyProtection(
                    entry,
                    "owner user id"
                )
            end

            if ownerName == HolyCleanText(LocalPlayer.Name) then

                HolySniperAddUniqueReason(
                    reasons,
                    "owner name"
                )

                HolySniperTouchPetBuyProtection(
                    entry,
                    "owner name"
                )
            end

            if HolySniperPetBuyStateLooksPending(state) == true then

                HolySniperAddUniqueReason(
                    reasons,
                    state ~= ""
                    and state
                    or "walking to garden"
                )

                HolySniperTouchPetBuyProtection(
                    entry,
                    state ~= ""
                    and state
                    or "walking to garden"
                )
            end
        end

        local currentSheckles =
            HolySniperReadSheckles()

        if beforeSheckles
        and currentSheckles
        and currentSheckles < beforeSheckles then

            HolySniperAddUniqueReason(
                reasons,
                "sheckles decreased"
            )

            HolySniperTouchPetBuyProtection(
                entry,
                "sheckles decreased"
            )
        end

        if #reasons > 0 then

            return true,
                table.concat(
                    reasons,
                    ", "
                )
        end

        task.wait(
            0.10
        )
    end

    return false,
        "confirm timeout"
end

function HolySniperMarkBought(match, entry)

    HOLY_SNIPER_RUNTIME.Handled =
        type(HOLY_SNIPER_RUNTIME.Handled) == "table"
        and HOLY_SNIPER_RUNTIME.Handled
        or {}

    HOLY_SNIPER_RUNTIME.BoughtCounts =
        type(HOLY_SNIPER_RUNTIME.BoughtCounts) == "table"
        and HOLY_SNIPER_RUNTIME.BoughtCounts
        or {}

    local entryKey =
        HolySniperEntryKey(
            entry
        )

    if entryKey ~= "" then

        HOLY_SNIPER_RUNTIME.Handled[entryKey] =
            true
    end

    local filter =
        match
        and match.Filter
        or nil

    if type(filter) == "table" then

        local filterKey =
            HolySniperFilterKey(
                filter
            )

        HOLY_SNIPER_RUNTIME.BoughtCounts[filterKey] =
            (
                tonumber(
                    HOLY_SNIPER_RUNTIME.BoughtCounts[filterKey]
                )
                or 0
            )
            + 1
    end

    HOLY_SNIPER_RUNTIME.LastBuyAt =
        os.clock()
end

function HolySniperMarkFailed(entry)

    HOLY_SNIPER_RUNTIME.FailedUntil =
        type(HOLY_SNIPER_RUNTIME.FailedUntil) == "table"
        and HOLY_SNIPER_RUNTIME.FailedUntil
        or {}

    local key =
        HolySniperEntryKey(
            entry
        )

    if key ~= "" then

        HOLY_SNIPER_RUNTIME.FailedUntil[key] =
            os.clock() + 3.5
    end
end

function HolySniperExecuteMatch(match, token)

    if type(match) ~= "table"
    or type(match.Entry) ~= "table"
    or type(match.Filter) ~= "table" then

        return false,
            "bad match"
    end

        if type(HOLY_DEFENSE_RUNTIME) == "table"
    and HOLY_DEFENSE_RUNTIME.Active == true then

        HolySniperSetStatus(
            "Paused: pet defense active"
        )

        return false,
            "defense active"
    end

    if type(HolyFarmMiddleCancelForSniper) == "function" then

        HolyFarmMiddleCancelForSniper(
            "sniper buy"
        )
    end

    if HOLY_SNIPER_RUNTIME.Buying == true
    or HOLY_SNIPER_RUNTIME.Returning == true then

        return false,
            "busy"
    end

    if HolySniperPetBuyProtectionBlocks(
        "Buy",
        false
    ) == true then

        return false,
            "pet buy pending"
    end

    HOLY_SNIPER_RUNTIME.Buying =
        true

    HolySniperClearHeldToolForMovement(
        "buy flow"
    )

    local entry =
        match.Entry

    local filter =
        match.Filter

    HolySniperArmTargetLock(
        entry,
        "buy flow"
    )

    local protectionArmed =
        false

    local promptTriggered =
        false

    HOLY_SNIPER_RUNTIME.CurrentTarget =
        entry

    HOLY_SNIPER_RUNTIME.CurrentTargetKey =
        HolySniperEntryKey(
            entry
        )

    local root =
        HolySniperGetCharacterRoot()

    if typeof(root) == "Instance"
    and root:IsA("BasePart")
    and typeof(HOLY_SNIPER_RUNTIME.ReturnActivationCFrame) ~= "CFrame" then

        HOLY_SNIPER_RUNTIME.ReturnActivationCFrame =
            root.CFrame
    end

    local success =
        false

    local finalReason =
        "unknown"

    local ok,
        err =
        pcall(function()

            local valid,
                refreshed,
                reason =
                HolySniperValidateTargetForBuy(
                    entry,
                    filter
                )

            if valid ~= true then

                entry =
                    refreshed
                    or entry

                finalReason =
                    reason
                    or "target invalid"

                return
            end

            entry =
                refreshed

            local beforeSheckles =
                HolySniperReadSheckles()

            HolySniperSetStatus(
                "Target locked: "
                .. HolySniperDescribeEntry(entry)
            )

            local moveOk,
                movedEntry,
                moveReason =
                false,
                nil,
                ""

            if HolySniperNormalizeMovementMode(
                HOLY_SNIPER_STATE.MovementMode
            ) == "Teleport" then

                moveOk,
                    movedEntry,
                    moveReason =
                    HolySniperMoveTeleportToEntry(
                        entry,
                        filter,
                        token
                    )

            else

                moveOk,
                    movedEntry,
                    moveReason =
                    HolySniperMoveWalkToEntry(
                        entry,
                        filter,
                        token
                    )
            end

            entry =
                movedEntry
                or entry

            if moveOk ~= true then

                finalReason =
                    moveReason
                    or "move failed"

                return
            end

            valid,
                refreshed,
                reason =
                HolySniperValidateTargetForBuy(
                    entry,
                    filter
                )

            if valid ~= true then

                entry =
                    refreshed
                    or entry

                finalReason =
                    reason
                    or "target invalid after move"

                return
            end

            entry =
                refreshed

            local distance =
                HolySniperDistanceToEntry(
                    entry
                )

            local safeRange =
                HolySniperGetSafeRange(
                    entry.Prompt
                )

            if distance > safeRange then

                finalReason =
                    "not in range"

                return
            end

            HolySniperArmPetBuyProtection(
                entry,
                "buy prompt"
            )

            protectionArmed =
                true

            HolySniperSetStatus(
                "Buying: "
                .. HolySniperDescribeEntry(entry)
            )

            local triggerOk,
                triggerReason =
                HolySniperTriggerPrompt(
                    entry.Prompt
                )

            if triggerOk ~= true then

                finalReason =
                    triggerReason
                    or "prompt trigger failed"

                HolySniperClearPetBuyProtection(
                    "prompt trigger failed"
                )

                protectionArmed =
                    false

                return
            end

            promptTriggered =
                true

            HolySniperTouchPetBuyProtection(
                entry,
                "prompt fired"
            )

            local confirmed,
                confirmReason =
                HolySniperConfirmBuy(
                    entry,
                    beforeSheckles,
                    token
                )

            if confirmed == true then

                HolySniperTouchPetBuyProtection(
                    entry,
                    confirmReason
                    or "confirmed"
                )

                HolySniperMarkBought(
                    match,
                    entry
                )

                HolySniperRegisterConfirmedBuy(
                    match,
                    entry
                )

                if type(HolyDefenseArm) == "function" then

                    HolyDefenseArm(
                        entry,
                        filter,
                        "confirmed buy"
                    )
                end

                success =
                    true

                finalReason =
                    confirmReason
                    or "confirmed"

                HolySniperSetStatus(
                    "Bought: "
                    .. HolySniperDescribeEntry(entry)
                    .. " / protected"
                )

                HolySniperMaybeReturnAfterBuy(
                    token
                )

            else

                finalReason =
                    confirmReason
                    or "confirm failed"
            end
        end)

    if ok ~= true then

        finalReason =
            tostring(err)
    end

    if protectionArmed == true
    and promptTriggered ~= true
    and success ~= true then

        HolySniperClearPetBuyProtection(
            "buy failed before prompt"
        )
    end

    if success == true then

        HolySniperClearTargetLock(
            "buy protection active"
        )

    else

        HolySniperMarkFailed(
            entry
        )

        HolySniperClearTargetLock(
            "buy failed: "
            .. tostring(finalReason or "unknown")
        )

        HolySniperSetStatus(
            "Buy failed: "
            .. tostring(finalReason or "unknown")
        )
    end

    HOLY_SNIPER_RUNTIME.Buying =
        false

    HOLY_SNIPER_RUNTIME.CurrentTarget =
        nil

    HOLY_SNIPER_RUNTIME.CurrentTargetKey =
        ""

    task.wait(
        success == true
        and 0.30
        or 0.55
    )

    return success,
        finalReason
end

function HolySniperRunScan()

    local entries =
        HolySniperScanLivePets()

    local matches =
        HolySniperFindMatches(
            entries
        )

    HOLY_SNIPER_RUNTIME.ScanCount =
        (
            tonumber(
                HOLY_SNIPER_RUNTIME.ScanCount
            )
            or 0
        )
        + 1

    HOLY_SNIPER_RUNTIME.PetCount =
        #entries

    HOLY_SNIPER_RUNTIME.MatchCount =
        #matches

    HOLY_SNIPER_RUNTIME.LastScanAt =
        os.clock()

    if #matches > 0 then

        if type(HolyFarmMiddleCancelForSniper) == "function" then

            HolyFarmMiddleCancelForSniper(
                "match found"
            )
        end

        local best =
            matches[1].Entry

        HOLY_SNIPER_RUNTIME.CurrentTarget =
            best

        HOLY_SNIPER_RUNTIME.CurrentTargetKey =
            HolySniperEntryKey(
                best
            )

        HOLY_SNIPER_RUNTIME.LastMatchAt =
            os.clock()

        HolySniperArmTargetLock(
            best,
            "match found"
        )

        HolySniperSetStatus(
            tostring(#entries)
            .. " pets / "
            .. tostring(#matches)
            .. " matches / Best: "
            .. HolySniperDescribeEntry(best)
        )

        return matches
    end

    HOLY_SNIPER_RUNTIME.CurrentTarget =
        nil

    HOLY_SNIPER_RUNTIME.CurrentTargetKey =
        ""

    HolySniperClearTargetLock(
        "no matches"
    )

    if type(HOLY_SNIPER_STATE.Watchlist) ~= "table"
    or #HOLY_SNIPER_STATE.Watchlist <= 0 then

        HolySniperSetStatus(
            tostring(#entries)
            .. " pets / No watchlist"
        )

    else

        HolySniperSetStatus(
            tostring(#entries)
            .. " pets / 0 matches"
        )
    end

    return matches
end

