if type(HOLY_DEFENSE_RUNTIME) == "table" then

    HOLY_DEFENSE_RUNTIME.Token =
        nil

    HOLY_DEFENSE_RUNTIME.MonitorToken =
        nil

    HOLY_DEFENSE_RUNTIME.Active =
        false

    HOLY_DEFENSE_RUNTIME.MonitorRunning =
        false

    HOLY_DEFENSE_RUNTIME.GearLockActive =
        false

    for _, listName in ipairs({
        "Connections",
        "GearConnections",
    }) do

        local connections =
            HOLY_DEFENSE_RUNTIME[listName]

        if type(connections) == "table" then

            for _, connection in ipairs(connections) do

                pcall(function()

                    connection:Disconnect()
                end)
            end
        end
    end
end

HOLY_DEFENSE_RUNTIME = {
    Active = false,
    Token = nil,

    MonitorRunning = false,
    MonitorToken = nil,
    MonitorScanDelay = 0.15,

    Target = nil,
    Entry = nil,
    Filter = nil,

    TargetPetId = "",
    TargetPetName = "",
    TargetMissingAt = 0,
    CompletionStartedAt = 0,

    InventoryConfirmed = false,
    InventoryConfirmationItem = nil,
    InventoryBaselineInstances = {},
    InventoryBaselineIds = {},
    CompletedTargets = {},
    LastInventoryCheckAt = 0,

    Connections = {},
    GearConnections = {},

    GearLockActive = false,
    DefenseTool = nil,
    EquipPending = false,
    ReequipToken = 0,
    ReequipCooldown = 0.18,

    RebuyCount = 0,
    MaxRebuys = 3,

    LastEquipAt = 0,
    LastMoveAt = 0,
    LastMoveToAt = 0,
    LastShotAt = 0,
    LastShovelAt = 0,
    LastPreAimAt = 0,

    LastPetSamplePos = nil,
    LastPetSampleAt = 0,
    StablePetDirection = nil,
    SmoothedFollowGoal = nil,

    OriginalWalkSpeed = nil,
    PlayerControls = nil,
    ControlsDisabled = false,

    Networking = nil,
    WildTamePacket = nil,
    StrawberryPacket = nil,
    ShovelSwingPacket = nil,
    ShovelHitPacket = nil,
    PetScarePacket = nil,
}

function HolyDefenseEnsureRuntime()

    HOLY_DEFENSE_RUNTIME =
        type(HOLY_DEFENSE_RUNTIME) == "table"
        and HOLY_DEFENSE_RUNTIME
        or {}

    local runtime =
        HOLY_DEFENSE_RUNTIME

    runtime.Connections =
        type(runtime.Connections) == "table"
        and runtime.Connections
        or {}

    runtime.GearConnections =
        type(runtime.GearConnections) == "table"
        and runtime.GearConnections
        or {}

    runtime.InventoryBaselineInstances =
        type(runtime.InventoryBaselineInstances) == "table"
        and runtime.InventoryBaselineInstances
        or {}

    runtime.InventoryBaselineIds =
        type(runtime.InventoryBaselineIds) == "table"
        and runtime.InventoryBaselineIds
        or {}

    runtime.CompletedTargets =
        type(runtime.CompletedTargets) == "table"
        and runtime.CompletedTargets
        or {}

    runtime.ReequipToken =
        tonumber(runtime.ReequipToken)
        or 0

    runtime.ReequipCooldown =
        math.clamp(
            tonumber(runtime.ReequipCooldown)
            or 0.18,
            0.08,
            1
        )

    runtime.MonitorScanDelay =
        math.clamp(
            tonumber(runtime.MonitorScanDelay)
            or 0.15,
            0.08,
            1
        )

    runtime.MaxRebuys =
        tonumber(runtime.MaxRebuys)
        or 3

    return runtime
end

function HolyDefenseDisconnect()

    local runtime =
        HolyDefenseEnsureRuntime()

    for _, connection in ipairs(runtime.Connections or {}) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.Connections =
        {}
end

function HolyDefenseAddConnection(connection)

    local runtime =
        HolyDefenseEnsureRuntime()

    if connection ~= nil then

        table.insert(
            runtime.Connections,
            connection
        )
    end

    return connection
end

function HolyDefenseReadAttr(instance, name)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    local ok,
        value =
        pcall(function()

            return instance:GetAttribute(
                name
            )
        end)

    if ok == true then
        return value
    end

    return nil
end

function HolyDefenseGetPosition(object)

    if typeof(object) ~= "Instance" then
        return nil
    end

    if object:IsA("BasePart") then
        return object.Position
    end

    if object:IsA("Model") then

        local ok,
            pivot =
            pcall(function()

                return object:GetPivot()
            end)

        if ok == true
        and typeof(pivot) == "CFrame" then

            return pivot.Position
        end
    end

    local part =
        object:FindFirstChild(
            "HumanoidRootPart",
            true
        )
        or object:FindFirstChild(
            "RootPart",
            true
        )
        or object:FindFirstChildWhichIsA(
            "BasePart",
            true
        )

    if typeof(part) == "Instance"
    and part:IsA("BasePart") then

        return part.Position
    end

    return nil
end

function HolyDefenseDeepGet(root, path)

    local current =
        root

    for part in tostring(path or ""):gmatch("[^%.]+") do

        if type(current) ~= "table" then
            return nil
        end

        current =
            current[part]
    end

    return current
end

function HolyDefenseGetNetworking()

    local runtime =
        HolyDefenseEnsureRuntime()

    if type(runtime.Networking) == "table" then
        return runtime.Networking
    end

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local module =
            ReplicatedStorage:FindFirstChild("SharedModules")
            and ReplicatedStorage.SharedModules:FindFirstChild("Networking")

        if typeof(module) == "Instance"
        and module:IsA("ModuleScript") then

            local ok,
                result =
                pcall(function()

                    return require(
                        module
                    )
                end)

            if ok == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    runtime.Networking =
        type(networking) == "table"
        and networking
        or nil

    return runtime.Networking
end

function HolyDefenseResolvePackets()

    local runtime =
        HolyDefenseEnsureRuntime()

    local networking =
        HolyDefenseGetNetworking()

    if type(networking) ~= "table" then
        return false
    end

    runtime.WildTamePacket =
        runtime.WildTamePacket
        or HolyDefenseDeepGet(
            networking,
            "Pets.WildPetTame"
        )

    runtime.StrawberryPacket =
        runtime.StrawberryPacket
        or HolyDefenseDeepGet(
            networking,
            "StrawberrySniper.Fire"
        )

    runtime.ShovelSwingPacket =
        runtime.ShovelSwingPacket
        or HolyDefenseDeepGet(
            networking,
            "Shovel.SwingShovel"
        )

    runtime.ShovelHitPacket =
        runtime.ShovelHitPacket
        or HolyDefenseDeepGet(
            networking,
            "Shovel.HitPlayer"
        )

    runtime.PetScarePacket =
        runtime.PetScarePacket
        or HolyDefenseDeepGet(
            networking,
            "Pets.ScarePet"
        )

    return true
end

function HolyDefenseFirePacket(packet, ...)

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false
    end

    local ok =
        pcall(function(...)

            packet:Fire(
                ...
            )
        end, ...)

    return ok == true
end

function HolyDefenseGetCharacter()

    return LocalPlayer
        and LocalPlayer.Character
        or nil
end

function HolyDefenseGetHumanoid()

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChildOfClass(
        "Humanoid"
    )
end

function HolyDefenseGetRoot()

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChild(
        "HumanoidRootPart"
    )
    or character:FindFirstChild(
        "RootPart"
    )
    or character.PrimaryPart
end

function HolyDefenseToolMatches(tool, gearName)

    if typeof(tool) ~= "Instance"
    or tool:IsA("Tool") ~= true then

        return false
    end

    gearName =
        HolyDefenseNormalizeGear(
            gearName
        )

    local lowerName =
        tostring(tool.Name or "")
            :lower()

    local attrs =
        ""

    pcall(function()

        for key, value in pairs(tool:GetAttributes()) do

            attrs =
                attrs
                .. " "
                .. tostring(key)
                .. "="
                .. tostring(value)
        end
    end)

    attrs =
        attrs:lower()

    if gearName == "Shovel" then

        return lowerName == "shovel"
            or attrs:find("shovel", 1, true) ~= nil
    end

    return lowerName == "strawberry sniper"
        or (
            lowerName:find("strawberry", 1, true)
            and lowerName:find("sniper", 1, true)
        )
        or attrs:find("strawberrysniper", 1, true) ~= nil
        or attrs:find("strawberry sniper", 1, true) ~= nil
end

function HolyDefenseGetEquippedTool()

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChildOfClass(
        "Tool"
    )
end

function HolyDefenseFindTool(gearName)

    gearName =
        HolyDefenseNormalizeGear(
            gearName
        )

    local containers =
        {}

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) == "Instance" then

        table.insert(
            containers,
            character
        )
    end

    local backpack =
        LocalPlayer
        and LocalPlayer:FindFirstChildOfClass("Backpack")
        or nil

    if typeof(backpack) == "Instance" then

        table.insert(
            containers,
            backpack
        )
    end

    for _, container in ipairs(containers) do

        for _, child in ipairs(container:GetChildren()) do

            if HolyDefenseToolMatches(
                child,
                gearName
            ) == true then

                return child
            end
        end
    end

    return nil
end

function HolyDefenseDisconnectGearLock()

    local runtime =
        HolyDefenseEnsureRuntime()

    runtime.GearLockActive =
        false

    runtime.EquipPending =
        false

    runtime.ReequipToken =
        (
            tonumber(runtime.ReequipToken)
            or 0
        )
        + 1

    for _, connection in ipairs(
        runtime.GearConnections
        or {}
    ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.GearConnections =
        {}

    runtime.DefenseTool =
        nil
end

function HolyDefenseAddGearConnection(connection)

    local runtime =
        HolyDefenseEnsureRuntime()

    if connection ~= nil then

        table.insert(
            runtime.GearConnections,
            connection
        )
    end

    return connection
end

function HolyDefenseNormalizeId(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub(
            "[^%w]",
            ""
        )
end

function HolyDefenseReadAnyAttr(instance, names)

    if typeof(instance) ~= "Instance" then
        return nil
    end

    for _, name in ipairs(names or {}) do

        local value =
            HolyDefenseReadAttr(
                instance,
                name
            )

        if value ~= nil
        and HolyCleanText(value) ~= "" then

            return value
        end
    end

    return nil
end

function HolyDefenseReadPetId(instance)

    return HolyCleanText(
        HolyDefenseReadAnyAttr(
            instance,
            {
                "PetId",
                "PetID",
                "WildPetId",
                "WildPetID",
                "WildPetUUID",
                "UUID",
                "Uuid",
                "Id",
                "ID",
            }
        )
        or ""
    )
end

function HolyDefenseReadPetName(instance)

    return HolyCleanText(
        HolyDefenseReadAnyAttr(
            instance,
            {
                "PetName",
                "Pet",
                "DisplayName",
            }
        )
        or ""
    )
end

function HolyDefenseRefKey(ref)

    local key =
        HolyDefenseReadPetId(
            ref
        )

    if key == ""
    and typeof(ref) == "Instance" then

        key =
            HolySniperUuidFromName(
                ref.Name
            )
    end

    return HolyDefenseNormalizeId(
        key
    )
end

function HolyDefenseGetInventoryPetRows()

    local rows =
        {}

    local seen =
        {}

    local roots = {
        HolyDefenseGetCharacter(),

        LocalPlayer
        and LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )
        or nil,
    }

    local function inspect(instance)

        if typeof(instance) ~= "Instance"
        or seen[instance] == true then

            return
        end

        seen[instance] =
            true

        local petId =
            HolyDefenseReadPetId(
                instance
            )

        local petName =
            HolyDefenseReadPetName(
                instance
            )

        if petId == ""
        and petName == "" then

            return
        end

        if petName == ""
        and instance:IsA("Tool") then

            petName =
                HolyCleanText(
                    instance.Name
                )
        end

        table.insert(
            rows,
            {
                Instance =
                    instance,

                PetIdKey =
                    HolyDefenseNormalizeId(
                        petId
                    ),

                PetNameKey =
                    HolySniperPetAliasKey(
                        petName
                    ),
            }
        )
    end

    for _, root in ipairs(roots) do

        if typeof(root) == "Instance" then

            for _, descendant in ipairs(
                root:GetDescendants()
            ) do

                inspect(
                    descendant
                )
            end
        end
    end

    return rows
end

function HolyDefenseCaptureInventoryBaseline()

    local runtime =
        HolyDefenseEnsureRuntime()

    runtime.InventoryBaselineInstances =
        {}

    runtime.InventoryBaselineIds =
        {}

    for _, row in ipairs(
        HolyDefenseGetInventoryPetRows()
    ) do

        runtime.InventoryBaselineInstances[
            row.Instance
        ] =
            true

        if row.PetIdKey ~= "" then

            runtime.InventoryBaselineIds[
                row.PetIdKey
            ] =
                true
        end
    end
end

function HolyDefenseInventoryConfirmed(forceCheck)

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.InventoryConfirmed == true then

        return true,
            runtime.InventoryConfirmationItem
    end

    local now =
        os.clock()

    if forceCheck ~= true
    and now - (
        tonumber(runtime.LastInventoryCheckAt)
        or 0
    ) < 0.10 then

        return false,
            nil
    end

    runtime.LastInventoryCheckAt =
        now

    local targetIdKey =
        HolyDefenseNormalizeId(
            runtime.TargetPetId
        )

    local targetNameKey =
        HolySniperPetAliasKey(
            runtime.TargetPetName
        )

    for _, row in ipairs(
        HolyDefenseGetInventoryPetRows()
    ) do

        local exactId =
            targetIdKey ~= ""
            and row.PetIdKey ~= ""
            and row.PetIdKey == targetIdKey

        local newMatchingPet =
            targetNameKey ~= ""
            and row.PetNameKey == targetNameKey
            and (
                runtime.InventoryBaselineInstances[
                    row.Instance
                ] ~= true
                or (
                    row.PetIdKey ~= ""
                    and runtime.InventoryBaselineIds[
                        row.PetIdKey
                    ] ~= true
                )
            )

        if exactId == true
        or newMatchingPet == true then

            runtime.InventoryConfirmed =
                true

            runtime.InventoryConfirmationItem =
                row.Instance

            return true,
                row.Instance
        end
    end

    return false,
        nil
end

function HolyDefenseSelectedGearEquipped()

    return HolyDefenseToolMatches(
        HolyDefenseGetEquippedTool(),
        HOLY_SNIPER_STATE.DefendGear
    ) == true
end

function HolyDefenseEquipSelectedGear(reason)

    local runtime =
        HolyDefenseEnsureRuntime()

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true
    or runtime.Active ~= true
    or runtime.GearLockActive ~= true
    or runtime.InventoryConfirmed == true then

        return false
    end

    if HolyDefenseSelectedGearEquipped() == true then

        runtime.DefenseTool =
            HolyDefenseGetEquippedTool()

        return true
    end

    if runtime.EquipPending == true then
        return false
    end

    local now =
        os.clock()

    if now - (
        tonumber(runtime.LastEquipAt)
        or 0
    ) < runtime.ReequipCooldown then

        return false
    end

    local tool =
        HolyDefenseFindTool(
            HOLY_SNIPER_STATE.DefendGear
        )

    local humanoid =
        HolyDefenseGetHumanoid()

    if typeof(tool) ~= "Instance"
    or typeof(humanoid) ~= "Instance" then

        return false
    end

    runtime.EquipPending =
        true

    local ok =
        pcall(function()

            humanoid:EquipTool(
                tool
            )
        end)

    runtime.EquipPending =
        false

    if ok == true then

        runtime.DefenseTool =
            tool

        runtime.LastEquipAt =
            os.clock()

        runtime.LastEquipReason =
            tostring(
                reason
                or "defense"
            )
    end

    return ok == true
end

function HolyDefenseQueueReequip(reason)

    local runtime =
        HolyDefenseEnsureRuntime()

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true
    or runtime.Active ~= true
    or runtime.GearLockActive ~= true
    or runtime.InventoryConfirmed == true then

        return false
    end

    runtime.ReequipToken =
        (
            tonumber(runtime.ReequipToken)
            or 0
        )
        + 1

    local token =
        runtime.ReequipToken

    task.delay(0.12, function()

        local liveRuntime =
            HolyDefenseEnsureRuntime()

        if liveRuntime.ReequipToken ~= token
        or HOLY_SNIPER_STATE.DefendBoughtPets ~= true
        or liveRuntime.Active ~= true
        or liveRuntime.GearLockActive ~= true
        or liveRuntime.InventoryConfirmed == true
        or HolyDefenseSelectedGearEquipped() == true then

            return
        end

        HolyDefenseEquipSelectedGear(
            reason
            or "defense tool unequipped"
        )
    end)

    return true
end

function HolyDefenseStartGearLock()

    local runtime =
        HolyDefenseEnsureRuntime()

    HolyDefenseDisconnectGearLock()

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true
    or runtime.Active ~= true then

        return false
    end

    runtime.GearLockActive =
        true

    runtime.InventoryConfirmed =
        false

    runtime.InventoryConfirmationItem =
        nil

    runtime.LastEquipAt =
        0

    HolyDefenseCaptureInventoryBaseline()

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) == "Instance" then

        HolyDefenseAddGearConnection(
            character.ChildRemoved:Connect(function(child)

                if child == runtime.DefenseTool
                or HolyDefenseToolMatches(
                    child,
                    HOLY_SNIPER_STATE.DefendGear
                ) == true then

                    HolyDefenseQueueReequip(
                        "defense tool unequipped"
                    )
                end
            end)
        )

        HolyDefenseAddGearConnection(
            character.ChildAdded:Connect(function(child)

                if child:IsA("Tool")
                and HolyDefenseToolMatches(
                    child,
                    HOLY_SNIPER_STATE.DefendGear
                ) ~= true then

                    HolyDefenseQueueReequip(
                        "another tool equipped"
                    )
                end
            end)
        )
    end

    local backpack =
        LocalPlayer
        and LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )
        or nil

    if typeof(backpack) == "Instance" then

        HolyDefenseAddGearConnection(
            backpack.ChildAdded:Connect(function(child)

                if HolyDefenseToolMatches(
                    child,
                    HOLY_SNIPER_STATE.DefendGear
                ) == true then

                    HolyDefenseQueueReequip(
                        "defense tool returned to backpack"
                    )
                end
            end)
        )
    end

    HolyDefenseEquipSelectedGear(
        "defense start"
    )

    return true
end

function HolyDefenseBuildEntryFromRef(ref)

    if typeof(ref) ~= "Instance"
    or ref.Parent == nil then

        return nil
    end

    local model =
        nil

    if type(HolyLivePetsFindModelForRef) == "function" then

        model =
            HolyLivePetsFindModelForRef(
                ref
            )
    end

    local petName =
        HolySniperReadLivePetName(
            model,
            ref
        )

    petName =
        HolySniperResolvePetDisplay(
            petName
        )

    if petName == "" then
        return nil
    end

    local uuid =
        HolySniperUuidFromName(
            ref.Name
        )

    if uuid == "" then

        uuid =
            HolyDefenseReadPetId(
                ref
            )
    end

    return {
        Key =
            uuid,

        UUID =
            uuid,

        Ref =
            ref,

        Model =
            model,

        Pet =
            petName,

        PetKey =
            HolySniperResolvePetKey(
                petName
            ),

        Size =
            HolySniperReadLiveSize(
                model,
                ref
            ),

        Variant =
            HolySniperReadLiveVariant(
                model,
                ref
            ),

        Price =
            tonumber(
                HolyDefenseReadAnyAttr(
                    ref,
                    {
                        "Price",
                        "Cost",
                        "TameCost",
                    }
                )
            )
            or 0,
    }
end

function HolyDefenseFindFilterForEntry(entry)

    local best =
        nil

    local bestRank =
        math.huge

    for _, rawFilter in ipairs(
        type(HOLY_SNIPER_STATE.Watchlist) == "table"
        and HOLY_SNIPER_STATE.Watchlist
        or {}
    ) do

        local filter =
            HolySniperNormalizeFilter(
                rawFilter
            )

        local filterPetKey =
            HolyCleanText(
                filter.PetKey
            )

        local petMatches =
            filterPetKey == "*"
            or HolySniperPetAliasKey(
                filterPetKey
            ) == HolySniperPetAliasKey(
                entry.PetKey
                or entry.Pet
            )

        local sizeMatches =
            HolySniperSelectionHasAny(
                filter.Sizes
            )
            or HolySniperSelectionContains(
                filter.Sizes,
                entry.Size
            )

        local variantMatches =
            HolySniperSelectionHasAny(
                filter.Variants
            )
            or HolySniperSelectionContains(
                filter.Variants,
                entry.Variant
            )

        local rank =
            HolySniperPriorityRank(
                filter.Priority
            )

        if filter.Enabled ~= false
        and petMatches == true
        and sizeMatches == true
        and variantMatches == true
        and rank < bestRank then

            best =
                filter

            bestRank =
                rank
        end
    end

    if type(best) == "table" then
        return best
    end

    return HolySniperNormalizeFilter({
        Pet =
            entry.Pet,

        Sizes = {
            entry.Size
            or "Any",
        },

        Variants = {
            entry.Variant
            or "Any",
        },

        MaxPrice =
            0,

        Priority =
            "Medium",

        Enabled =
            true,
    })
end

function HolyDefenseRefReady(ref)

    if typeof(ref) ~= "Instance"
    or ref.Parent == nil then

        return false
    end

    local owner =
        tonumber(
            HolyDefenseReadAnyAttr(
                ref,
                {
                    "OwnerUserId",
                    "OwnerUserID",
                    "Owner",
                    "UserId",
                    "UserID",
                }
            )
        )
        or 0

    local state =
        HolyCleanText(
            HolyDefenseReadAnyAttr(
                ref,
                {
                    "State",
                    "PetState",
                }
            )
            or ""
        )

    return owner == tonumber(LocalPlayer.UserId)
        and HolySniperPetBuyStateLooksPending(
            state
        ) == true
end

function HolyDefenseMonitorScan()

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true then
        return false
    end

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.Active == true then
        return true
    end

    local root =
        HolySniperGetWildPetRefRoot()

    if typeof(root) ~= "Instance" then
        return false
    end

    local now =
        os.clock()

    for key, expiresAt in pairs(
        runtime.CompletedTargets
        or {}
    ) do

        if tonumber(expiresAt) == nil
        or tonumber(expiresAt) <= now then

            runtime.CompletedTargets[key] =
                nil
        end
    end

    for _, ref in ipairs(root:GetChildren()) do

        local refKey =
            HolyDefenseRefKey(
                ref
            )

        local recentlyCompleted =
            refKey ~= ""
            and (
                tonumber(
                    runtime.CompletedTargets[
                        refKey
                    ]
                )
                or 0
            ) > now

        if recentlyCompleted ~= true
        and HolyDefenseRefReady(
            ref
        ) == true then

            local entry =
                HolyDefenseBuildEntryFromRef(
                    ref
                )

            if type(entry) == "table"
            and type(HolyDefenseStartTarget) == "function" then

                return HolyDefenseStartTarget(
                    ref,
                    entry,
                    HolyDefenseFindFilterForEntry(
                        entry
                    ),
                    "defense monitor"
                )
            end
        end
    end

    return false
end

function HolyDefenseStartMonitor(reason)

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true then
        return false
    end

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.MonitorRunning == true then
        return true
    end

    runtime.MonitorToken =
        {}

    local token =
        runtime.MonitorToken

    runtime.MonitorRunning =
        true

    task.spawn(function()

        while runtime.MonitorToken == token
        and HOLY_SNIPER_STATE.DefendBoughtPets == true do

            HolyDefenseMonitorScan()

            task.wait(
                runtime.MonitorScanDelay
            )
        end

        if runtime.MonitorToken == token then

            runtime.MonitorRunning =
                false
        end
    end)

    return true
end

function HolyDefenseStopMonitor(reason)

    local runtime =
        HolyDefenseEnsureRuntime()

    runtime.MonitorToken =
        nil

    runtime.MonitorRunning =
        false

    return true
end

function HolyDefenseGetPlayerRoot(player)

    local character =
        player
        and player.Character
        or nil

    if typeof(character) ~= "Instance" then
        return nil
    end

    return character:FindFirstChild(
        "HumanoidRootPart"
    )
    or character:FindFirstChild(
        "RootPart"
    )
    or character.PrimaryPart
end

function HolyDefenseFindThreat(targetPos)

    if typeof(targetPos) ~= "Vector3" then
        return nil
    end

    local best =
        nil

    for _, player in ipairs(Players:GetPlayers()) do

        if player ~= LocalPlayer then

            local root =
                HolyDefenseGetPlayerRoot(
                    player
                )

            if typeof(root) == "Instance"
            and root:IsA("BasePart") then

                local distance =
                    (
                        root.Position
                        - targetPos
                    ).Magnitude

                if distance <= 45
                and (
                    best == nil
                    or distance < best.Distance
                ) then

                    best = {
                        Player =
                            player,

                        Root =
                            root,

                        Distance =
                            distance,
                    }
                end
            end
        end
    end

    return best
end

function HolyDefenseGetPlayerControls()

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.PlayerControls ~= nil then
        return runtime.PlayerControls
    end

    local playerScripts =
        LocalPlayer
        and LocalPlayer:FindFirstChild("PlayerScripts")
        or nil

    local playerModule =
        playerScripts
        and playerScripts:FindFirstChild("PlayerModule")
        or nil

    if typeof(playerModule) ~= "Instance"
    or playerModule:IsA("ModuleScript") ~= true then

        return nil
    end

    local okModule,
        module =
        pcall(require, playerModule)

    if okModule ~= true
    or type(module) ~= "table"
    or type(module.GetControls) ~= "function" then

        return nil
    end

    local okControls,
        controls =
        pcall(function()

            return module:GetControls()
        end)

    if okControls == true then

        runtime.PlayerControls =
            controls

        return controls
    end

    return nil
end

function HolyDefenseDisableControls()

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.ControlsDisabled == true then
        return true
    end

    local controls =
        HolyDefenseGetPlayerControls()

    if controls == nil then
        return false
    end

    local ok =
        pcall(function()

            controls:Disable()
        end)

    if ok == true then

        runtime.ControlsDisabled =
            true
    end

    return ok == true
end

function HolyDefenseRestoreControls()

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.ControlsDisabled ~= true then
        return
    end

    local controls =
        runtime.PlayerControls

    if controls ~= nil then

        pcall(function()

            controls:Enable()
        end)
    end

    runtime.ControlsDisabled =
        false
end

function HolyDefenseUpdatePetDirection(targetPos)

    local runtime =
        HolyDefenseEnsureRuntime()

    local root =
        HolyDefenseGetRoot()

    local now =
        os.clock()

    if runtime.StablePetDirection == nil then

        if typeof(root) == "Instance"
        and root:IsA("BasePart") then

            local fromPetToSelf =
                root.Position
                - targetPos

            local flat =
                Vector3.new(
                    fromPetToSelf.X,
                    0,
                    fromPetToSelf.Z
                )

            if flat.Magnitude > 0.2 then

                runtime.StablePetDirection =
                    -flat.Unit

            else

                runtime.StablePetDirection =
                    Vector3.new(0, 0, 1)
            end

        else

            runtime.StablePetDirection =
                Vector3.new(0, 0, 1)
        end
    end

    if runtime.LastPetSamplePos == nil then

        runtime.LastPetSamplePos =
            targetPos

        runtime.LastPetSampleAt =
            now

        return runtime.StablePetDirection
    end

    if now - (
        tonumber(runtime.LastPetSampleAt)
        or 0
    ) < 0.10 then

        return runtime.StablePetDirection
    end

    local delta =
        targetPos
        - runtime.LastPetSamplePos

    local flatDelta =
        Vector3.new(
            delta.X,
            0,
            delta.Z
        )

    runtime.LastPetSamplePos =
        targetPos

    runtime.LastPetSampleAt =
        now

    if flatDelta.Magnitude >= 0.22 then

        local fresh =
            flatDelta.Unit

        local mixed =
            runtime.StablePetDirection:Lerp(
                fresh,
                0.22
            )

        if mixed.Magnitude > 0.05 then

            runtime.StablePetDirection =
                mixed.Unit

        else

            runtime.StablePetDirection =
                fresh
        end
    end

    return runtime.StablePetDirection
end

function HolyDefenseSmoothGoal(rawGoal)

    local runtime =
        HolyDefenseEnsureRuntime()

    if typeof(rawGoal) ~= "Vector3" then
        return rawGoal
    end

    if runtime.SmoothedFollowGoal == nil
    or (
        runtime.SmoothedFollowGoal
        - rawGoal
    ).Magnitude >= 18 then

        runtime.SmoothedFollowGoal =
            rawGoal

    else

        runtime.SmoothedFollowGoal =
            runtime.SmoothedFollowGoal:Lerp(
                rawGoal,
                0.30
            )
    end

    return runtime.SmoothedFollowGoal
end

function HolyDefenseChooseGoal(targetPos, threat)

    local root =
        HolyDefenseGetRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return nil
    end

    if threat
    and threat.Root
    and threat.Distance <= 18 then

        local diff =
            threat.Root.Position
            - targetPos

        local flat =
            Vector3.new(
                diff.X,
                0,
                diff.Z
            )

        if flat.Magnitude > 0.1 then

            local threatDir =
                flat.Unit

            local guardDistance =
                threat.Distance <= 8
                and 3.85
                or 4.75

            return Vector3.new(
                targetPos.X,
                root.Position.Y,
                targetPos.Z
            )
            + threatDir * guardDistance
        end
    end

    local stableDir =
        HolyDefenseUpdatePetDirection(
            targetPos
        )

    local rawGoal =
        targetPos
        - stableDir * 5.75

    rawGoal =
        Vector3.new(
            rawGoal.X,
            root.Position.Y,
            rawGoal.Z
        )

    return HolyDefenseSmoothGoal(
        rawGoal
    )
end

function HolyDefenseSetWalkSpeed(distance, threat)

    local runtime =
        HolyDefenseEnsureRuntime()

    local humanoid =
        HolyDefenseGetHumanoid()

    if typeof(humanoid) ~= "Instance" then
        return
    end

    if runtime.OriginalWalkSpeed == nil then

        runtime.OriginalWalkSpeed =
            humanoid.WalkSpeed
    end

    local base =
        tonumber(runtime.OriginalWalkSpeed)
        or humanoid.WalkSpeed

    local wanted =
        math.max(
            base,
            22
        )

    if threat
    and threat.Distance <= 8 then

        wanted =
            math.max(
                base,
                31
            )

    elseif threat
    and threat.Distance <= 24 then

        wanted =
            math.max(
                base,
                27
            )

    elseif distance >= 14 then

        wanted =
            math.max(
                base,
                27
            )
    end

    pcall(function()

        humanoid.WalkSpeed =
            wanted

        humanoid.AutoRotate =
            true
    end)
end

function HolyDefenseWalkTo(goal, threat)

    local runtime =
        HolyDefenseEnsureRuntime()

    local humanoid =
        HolyDefenseGetHumanoid()

    local root =
        HolyDefenseGetRoot()

    if typeof(goal) ~= "Vector3"
    or typeof(humanoid) ~= "Instance"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false
    end

    HolyDefenseDisableControls()

    local delta =
        goal
        - root.Position

    local flat =
        Vector3.new(
            delta.X,
            0,
            delta.Z
        )

    local distance =
        flat.Magnitude

    HolyDefenseSetWalkSpeed(
        distance,
        threat
    )

    if distance <= 2.30 then

        pcall(function()

            humanoid:Move(
                Vector3.zero,
                false
            )
        end)

        return true
    end

    local now =
        os.clock()

    if now - (
        tonumber(runtime.LastMoveAt)
        or 0
    ) >= 0.04 then

        runtime.LastMoveAt =
            now

        pcall(function()

            humanoid:Move(
                flat.Unit,
                false
            )
        end)
    end

    if now - (
        tonumber(runtime.LastMoveToAt)
        or 0
    ) >= 0.16 then

        runtime.LastMoveToAt =
            now

        pcall(function()

            humanoid:MoveTo(
                goal
            )
        end)
    end

    return true
end

function HolyDefenseTweenTo(goal)

    local root =
        HolyDefenseGetRoot()

    if typeof(goal) ~= "Vector3"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false
    end

    local distance =
        (
            root.Position
            - goal
        ).Magnitude

    if distance <= 2.30 then
        return true
    end

    local speed =
        30

    local duration =
        math.clamp(
            distance / speed,
            0.10,
            0.35
        )

    local TweenService =
        game:GetService("TweenService")

    local tween =
        TweenService:Create(
            root,
            TweenInfo.new(
                duration,
                Enum.EasingStyle.Linear,
                Enum.EasingDirection.Out
            ),
            {
                CFrame =
                    CFrame.new(
                        goal,
                        goal + root.CFrame.LookVector
                    ),
            }
        )

    pcall(function()

        tween:Play()
    end)

    return true
end

function HolyDefenseMoveTo(goal, threat)

    local movement =
        HolyDefenseNormalizeMovement(
            HOLY_SNIPER_STATE.DefendMovement
        )

    local root =
        HolyDefenseGetRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false
    end

    local distance =
        typeof(goal) == "Vector3"
        and (
            root.Position
            - goal
        ).Magnitude
        or 0

    if movement == "Tween" then

        return HolyDefenseTweenTo(
            goal
        )
    end

    if movement == "Hybrid" then

        if distance >= 15
        or (
            threat
            and threat.Distance <= 8
        ) then

            return HolyDefenseTweenTo(
                goal
            )
        end
    end

    return HolyDefenseWalkTo(
        goal,
        threat
    )
end

function HolyDefenseRayClear(fromPos, toPos, targetCharacter)

    if typeof(fromPos) ~= "Vector3"
    or typeof(toPos) ~= "Vector3" then

        return false
    end

    local params =
        RaycastParams.new()

    params.FilterType =
        Enum.RaycastFilterType.Exclude

    local ignore =
        {}

    local character =
        HolyDefenseGetCharacter()

    if typeof(character) == "Instance" then

        table.insert(
            ignore,
            character
        )
    end

    local runtime =
        HolyDefenseEnsureRuntime()

    if typeof(runtime.Target) == "Instance" then

        table.insert(
            ignore,
            runtime.Target
        )
    end

    params.FilterDescendantsInstances =
        ignore

    local result =
        workspace:Raycast(
            fromPos,
            toPos - fromPos,
            params
        )

    if result == nil then
        return true
    end

    if typeof(targetCharacter) == "Instance"
    and result.Instance
    and result.Instance:IsDescendantOf(
        targetCharacter
    ) then

        return true
    end

    return false
end

function HolyDefenseGetThreatParts(threat)

    local character =
        threat
        and threat.Player
        and threat.Player.Character
        or nil

    if typeof(character) ~= "Instance" then
        return nil
    end

    local root =
        character:FindFirstChild(
            "HumanoidRootPart"
        )
        or character:FindFirstChild(
            "RootPart"
        )
        or character.PrimaryPart

    local head =
        character:FindFirstChild(
            "Head"
        )

    return {
        Character =
            character,

        Root =
            root,

        Head =
            head,
    }
end

function HolyDefenseGetVelocity(part)

    if typeof(part) ~= "Instance"
    or part:IsA("BasePart") ~= true then

        return Vector3.zero
    end

    local ok,
        velocity =
        pcall(function()

            return part.AssemblyLinearVelocity
        end)

    if ok == true
    and typeof(velocity) == "Vector3" then

        return velocity
    end

    return Vector3.zero
end

function HolyDefenseChooseAim(threat)

    local parts =
        HolyDefenseGetThreatParts(
            threat
        )

    if parts == nil
    or typeof(parts.Root) ~= "Instance"
    or parts.Root:IsA("BasePart") ~= true then

        return nil
    end

    local root =
        HolyDefenseGetRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return nil
    end

    local velocity =
        HolyDefenseGetVelocity(
            parts.Root
        )

    local distance =
        tonumber(threat.Distance)
        or 0

    local tinyLead =
        math.clamp(
            distance / 470,
            0.010,
            0.050
        )

    local softLead =
        math.clamp(
            distance / 330,
            0.020,
            0.090
        )

    local headPos =
        typeof(parts.Head) == "Instance"
        and parts.Head:IsA("BasePart")
        and (
            parts.Head.Position
            + Vector3.new(0, -0.05, 0)
        )
        or (
            parts.Root.Position
            + Vector3.new(0, 2.3, 0)
        )

    local rootHigh =
        parts.Root.Position
        + Vector3.new(0, 1.45, 0)

    local candidates = {
        headPos + velocity * tinyLead,
        headPos + velocity * softLead,
        rootHigh,
        rootHigh + velocity * tinyLead,
    }

    local camera =
        workspace.CurrentCamera

    local rootFrom =
        root.Position
        + Vector3.new(0, 1.5, 0)

    local cameraFrom =
        camera
        and camera.CFrame.Position
        or rootFrom

    for _, aim in ipairs(candidates) do

        if HolyDefenseRayClear(
            rootFrom,
            aim,
            parts.Character
        ) == true
        and HolyDefenseRayClear(
            cameraFrom,
            aim,
            parts.Character
        ) == true then

            return aim
        end
    end

    return nil
end

function HolyDefensePreAim(aim)

    local camera =
        workspace.CurrentCamera

    if typeof(camera) == "Instance"
    and typeof(aim) == "Vector3" then

        pcall(function()

            camera.CFrame =
                CFrame.new(
                    camera.CFrame.Position,
                    aim
                )
        end)
    end
end

function HolyDefenseFaceShot(aim)

    local root =
        HolyDefenseGetRoot()

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or typeof(aim) ~= "Vector3" then

        return
    end

    local lookAt =
        Vector3.new(
            aim.X,
            root.Position.Y,
            aim.Z
        )

    if (
        lookAt
        - root.Position
    ).Magnitude < 0.35 then

        return
    end

    pcall(function()

        root.CFrame =
            CFrame.lookAt(
                root.Position,
                lookAt
            )
    end)
end

function HolyDefenseUseStrawberry(threat)

    local runtime =
        HolyDefenseEnsureRuntime()

    if threat == nil
    or threat.Player == nil
    or threat.Root == nil then

        return false
    end

    if threat.Distance > 30 then
        return false
    end

    local velocity =
        HolyDefenseGetVelocity(
            threat.Root
        )

    local flatSpeed =
        Vector3.new(
            velocity.X,
            0,
            velocity.Z
        ).Magnitude

    if threat.Distance > 22
    and flatSpeed > 7 then

        return false
    end

    local cooldown =
        threat.Distance <= 8
        and 2.78
        or 3.00

    if os.clock() - (
        tonumber(runtime.LastShotAt)
        or 0
    ) < cooldown then

        return false
    end

    HolyDefenseResolvePackets()

    local packet =
        runtime.StrawberryPacket

    if type(packet) ~= "table" then
        return false
    end

    local aim =
        HolyDefenseChooseAim(
            threat
        )

    if typeof(aim) ~= "Vector3" then
        return false
    end

    if HolyDefenseSelectedGearEquipped() ~= true then
        return false
    end

    local tool =
        HolyDefenseGetEquippedTool()

    if HolyDefenseToolMatches(
        tool,
        "Strawberry Sniper"
    ) ~= true then

        return false
    end

    HolyDefensePreAim(
        aim
    )

    HolyDefenseFaceShot(
        aim
    )

    task.wait()

    local ok =
        HolyDefenseFirePacket(
            packet,
            aim,
            tool,
            threat.Player
        )

    if ok == true then

        runtime.LastShotAt =
            os.clock()
    end

    return ok
end

function HolyDefenseReadTargetPetId()

    local runtime =
        HolyDefenseEnsureRuntime()

    local target =
        runtime.Target

    if typeof(target) ~= "Instance" then
        return ""
    end

    local petId =
        HolyCleanText(
            HolyDefenseReadAttr(
                target,
                "PetId"
            )
            or HolyDefenseReadAttr(
                target,
                "PetID"
            )
            or HolyDefenseReadAttr(
                target,
                "UUID"
            )
            or ""
        )

    if petId ~= "" then
        return petId
    end

    return HolySniperUuidFromName(
        target.Name
    )
end

function HolyDefenseUseShovel(threat)

    local runtime =
        HolyDefenseEnsureRuntime()

    if threat == nil
    or threat.Player == nil
    or threat.Distance > 7 then

        return false
    end

    if os.clock() - (
        tonumber(runtime.LastShovelAt)
        or 0
    ) < 0.85 then

        return false
    end

    HolyDefenseResolvePackets()

    if HolyDefenseSelectedGearEquipped() ~= true then
        return false
    end

    local ok =
        false

    if type(runtime.ShovelSwingPacket) == "table" then

        ok =
            HolyDefenseFirePacket(
                runtime.ShovelSwingPacket
            )
            or ok
    end

    if type(runtime.ShovelHitPacket) == "table" then

        ok =
            HolyDefenseFirePacket(
                runtime.ShovelHitPacket,
                threat.Player.UserId
            )
            or ok
    end

    local petId =
        HolyDefenseReadTargetPetId()

    if petId ~= ""
    and type(runtime.PetScarePacket) == "table" then

        ok =
            HolyDefenseFirePacket(
                runtime.PetScarePacket,
                threat.Player.UserId,
                petId
            )
            or ok
    end

    runtime.LastShovelAt =
        os.clock()

    return ok
end

function HolyDefenseUseGear(threat)

    local gear =
        HolyDefenseNormalizeGear(
            HOLY_SNIPER_STATE.DefendGear
        )

    if gear == "Shovel" then

        return HolyDefenseUseShovel(
            threat
        )
    end

    return HolyDefenseUseStrawberry(
        threat
    )
end

function HolyDefenseStop(reason)

    local runtime =
        HolyDefenseEnsureRuntime()

    local wasActive =
        runtime.Active == true
        or runtime.ControlsDisabled == true

    local wasConfirmed =
        runtime.InventoryConfirmed == true

    local completedKey =
        HolyDefenseNormalizeId(
            runtime.TargetPetId
        )

    if completedKey == ""
    and typeof(runtime.Target) == "Instance" then

        completedKey =
            HolyDefenseRefKey(
                runtime.Target
            )
    end

    runtime.GearLockActive =
        false

    HolyDefenseDisconnectGearLock()

    runtime.Token =
        nil

    runtime.Active =
        false

    HolyDefenseDisconnect()

    if wasActive == true then

        HolyDefenseRestoreControls()

        local humanoid =
            HolyDefenseGetHumanoid()

        if typeof(humanoid) == "Instance" then

            pcall(function()

                humanoid:Move(
                    Vector3.zero,
                    false
                )

                if runtime.OriginalWalkSpeed ~= nil then

                    humanoid.WalkSpeed =
                        runtime.OriginalWalkSpeed
                end

                humanoid.AutoRotate =
                    true
            end)
        end
    end

    if wasConfirmed == true
    and completedKey ~= "" then

        runtime.CompletedTargets[
            completedKey
        ] =
            os.clock() + 30
    end

    runtime.Target =
        nil

    runtime.Entry =
        nil

    runtime.Filter =
        nil

    runtime.TargetPetId =
        ""

    runtime.TargetPetName =
        ""

    runtime.TargetMissingAt =
        0

    runtime.CompletionStartedAt =
        0

    runtime.InventoryConfirmed =
        false

    runtime.InventoryConfirmationItem =
        nil

    runtime.InventoryBaselineInstances =
        {}

    runtime.InventoryBaselineIds =
        {}

    runtime.SmoothedFollowGoal =
        nil

    runtime.StablePetDirection =
        nil

    runtime.LastPetSamplePos =
        nil

    runtime.LastPetSampleAt =
        0

    runtime.OriginalWalkSpeed =
        nil

    runtime.LastStopReason =
        tostring(
            reason
            or "stopped"
        )

    if HOLY_SNIPER_STATE.DefendBoughtPets == true
    and runtime.MonitorRunning == true then

        task.defer(function()

            HolyDefenseMonitorScan()
        end)
    end

    return true
end

function HolyDefenseCanRebuy(target)

    local runtime =
        HolyDefenseEnsureRuntime()

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true
    or HOLY_SNIPER_STATE.DefendRebuyIfStolen ~= true then

        return false
    end

    local filter =
        type(runtime.Filter) == "table"
        and HolySniperNormalizeFilter(
            runtime.Filter
        )
        or {}

    local maxPrice =
        tonumber(filter.MaxPrice)
        or 0

    if maxPrice <= 0 then
        return false
    end

    if runtime.RebuyCount >= runtime.MaxRebuys then
        return false
    end

    local price =
        tonumber(
            HolyDefenseReadAttr(
                target,
                "Price"
            )
        )
        or 0

    if price <= 0
    or price > maxPrice then

        return false
    end

    local state =
        HolyCleanText(
            HolyDefenseReadAttr(
                target,
                "State"
            )
            or ""
        )

    return HolySniperPetBuyStateLooksPending(
        state
    ) == true
end

function HolyDefenseTryRebuy(target)

    local runtime =
        HolyDefenseEnsureRuntime()

    if typeof(target) ~= "Instance"
    or HolyDefenseCanRebuy(
        target
    ) ~= true then

        return false
    end

    HolyDefenseResolvePackets()

    if type(runtime.WildTamePacket) ~= "table" then
        return false
    end

    local ok =
        HolyDefenseFirePacket(
            runtime.WildTamePacket,
            target
        )

    if ok == true then

        runtime.RebuyCount =
            (
                tonumber(runtime.RebuyCount)
                or 0
            )
            + 1

        runtime.Target =
            target
    end

    return ok
end

function HolyDefenseHandleOwnerChanged(target)

    local runtime =
        HolyDefenseEnsureRuntime()

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true
    or runtime.Active ~= true
    or target ~= runtime.Target then

        return
    end

    task.delay(0.05, function()

        local liveRuntime =
            HolyDefenseEnsureRuntime()

        if HOLY_SNIPER_STATE.DefendBoughtPets ~= true
        or liveRuntime.Active ~= true
        or target ~= liveRuntime.Target
        or typeof(target) ~= "Instance"
        or target.Parent == nil then

            return
        end

        local owner =
            tonumber(
                HolyDefenseReadAttr(
                    target,
                    "OwnerUserId"
                )
            )
            or 0

        if owner == 0
        or owner == tonumber(LocalPlayer.UserId) then

            return
        end

        if HolyDefenseTryRebuy(
            target
        ) == true then

            return
        end

        HolyDefenseStop(
            "stolen"
        )
    end)
end

function HolyDefenseWatchTarget(target)

    local runtime =
        HolyDefenseEnsureRuntime()

    HolyDefenseDisconnect()

    for _, attrName in ipairs({
        "OwnerUserId",
        "OwnerName",
        "State",
        "Price",
    }) do

        pcall(function()

            HolyDefenseAddConnection(
                target:GetAttributeChangedSignal(
                    attrName
                ):Connect(function()

                    if attrName == "OwnerUserId" then

                        HolyDefenseHandleOwnerChanged(
                            target
                        )
                    end
                end)
            )
        end)
    end

    HolyDefenseAddConnection(
        target.AncestryChanged:Connect(function(_, parent)

            if parent == nil
            and runtime.Active == true
            and runtime.Target == target
            and (
                tonumber(runtime.TargetMissingAt)
                or 0
            ) <= 0 then

                runtime.TargetMissingAt =
                    os.clock()
            end
        end)
    )
end

function HolyDefenseStopMovementOnly()

    local humanoid =
        HolyDefenseGetHumanoid()

    local root =
        HolyDefenseGetRoot()

    if typeof(humanoid) == "Instance" then

        pcall(function()

            humanoid:Move(
                Vector3.zero,
                false
            )

            if typeof(root) == "Instance"
            and root:IsA("BasePart") then

                humanoid:MoveTo(
                    root.Position
                )
            end
        end)
    end
end

function HolyDefenseRunWorker(token)

    local runtime =
        HolyDefenseEnsureRuntime()

    while runtime.Token == token
    and runtime.Active == true do

        local wateringState =
            type(HOLY_WATERING_REJOIN_STATE) == "table"
            and HOLY_WATERING_REJOIN_STATE
            or {}

        local wateringRuntime =
            type(HOLY_WATERING_REJOIN_RUNTIME) == "table"
            and HOLY_WATERING_REJOIN_RUNTIME
            or {}

        local wateringOwnsMovement =
            wateringState.Enabled == true
            and (
                wateringRuntime.Running == true
                or wateringRuntime.Busy == true
                or wateringRuntime.RespawnPending == true
                or wateringRuntime.RecoveryScheduled == true
            )

        if wateringOwnsMovement == true then

            task.wait(
                0.08
            )

            continue
        end

        if HOLY_SNIPER_STATE.DefendBoughtPets ~= true then

            HolyDefenseStop(
                "toggle off"
            )

            return
        end

        if HolyDefenseInventoryConfirmed(
            false
        ) == true then

            HolyDefenseStop(
                "inventory confirmed"
            )

            return
        end

        local target =
            runtime.Target

        if typeof(target) ~= "Instance"
        or target.Parent == nil then

            if (
                tonumber(runtime.TargetMissingAt)
                or 0
            ) <= 0 then

                runtime.TargetMissingAt =
                    os.clock()
            end

            HolyDefenseStopMovementOnly()

            task.wait(
                0.08
            )

            continue
        end

        runtime.TargetMissingAt =
            0

        local owner =
            tonumber(
                HolyDefenseReadAttr(
                    target,
                    "OwnerUserId"
                )
            )
            or 0

        if owner ~= tonumber(LocalPlayer.UserId) then

            HolyDefenseHandleOwnerChanged(
                target
            )

            task.wait(
                0.12
            )

            continue
        end

        local state =
            HolyCleanText(
                HolyDefenseReadAttr(
                    target,
                    "State"
                )
                or ""
            )

        local walking =
            HolySniperPetBuyStateLooksPending(
                state
            ) == true

        if walking ~= true then

            if (
                tonumber(runtime.CompletionStartedAt)
                or 0
            ) <= 0 then

                runtime.CompletionStartedAt =
                    os.clock()
            end

            HolyDefenseStopMovementOnly()

            task.wait(
                0.08
            )

            continue
        end

        runtime.CompletionStartedAt =
            0

        local targetPos =
            HolyDefenseGetPosition(
                target
            )

        if typeof(targetPos) == "Vector3" then

            local threat =
                HolyDefenseFindThreat(
                    targetPos
                )

            local goal =
                HolyDefenseChooseGoal(
                    targetPos,
                    threat
                )

            if typeof(goal) == "Vector3" then

                HolyDefenseMoveTo(
                    goal,
                    threat
                )
            end

            if threat ~= nil then

                HolyDefenseUseGear(
                    threat
                )
            end
        end

        task.wait(
            0.04
        )
    end
end

function HolyDefenseWaitForOwnedTarget(entry)

    entry =
        type(entry) == "table"
        and entry
        or {}

    local ref =
        entry.Ref

    if typeof(ref) ~= "Instance"
    or ref.Parent == nil then

        ref =
            HolySniperFindPetBuyProtectionRef({
                UUID =
                    entry.UUID
                    or entry.Key,

                Key =
                    entry.Key,
            })
    end

    if typeof(ref) ~= "Instance" then
        return nil
    end

    local deadline =
        os.clock() + 2.5

    while os.clock() <= deadline do

        if HOLY_SNIPER_STATE.DefendBoughtPets ~= true
        or typeof(ref) ~= "Instance"
        or ref.Parent == nil then

            return nil
        end

        if HolyDefenseRefReady(
            ref
        ) == true then

            return ref
        end

        task.wait(
            0.05
        )
    end

    return nil
end

function HolyDefenseStartTarget(target, entry, filter, reason)

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true
    or typeof(target) ~= "Instance"
    or target.Parent == nil
    or HolyDefenseRefReady(
        target
    ) ~= true then

        return false
    end

    if type(HolyFarmMiddleCancelForSniper) == "function" then

        HolyFarmMiddleCancelForSniper(
            "pet defense"
        )
    end

    local runtime =
        HolyDefenseEnsureRuntime()

    if runtime.Active == true then

        return runtime.Target == target
    end

    runtime.Active =
        true

    runtime.Token =
        {}

    runtime.Target =
        target

    runtime.Entry =
        type(entry) == "table"
        and entry
        or HolyDefenseBuildEntryFromRef(
            target
        )

    runtime.Filter =
        type(filter) == "table"
        and filter
        or HolyDefenseFindFilterForEntry(
            runtime.Entry
            or {}
        )

    runtime.TargetPetId =
        HolyCleanText(
            HolyDefenseReadPetId(
                target
            )
        )

    if runtime.TargetPetId == "" then

        runtime.TargetPetId =
            HolyCleanText(
                runtime.Entry
                and (
                    runtime.Entry.UUID
                    or runtime.Entry.Key
                )
                or ""
            )
    end

    runtime.TargetPetName =
        HolyCleanText(
            runtime.Entry
            and runtime.Entry.Pet
            or HolyDefenseReadPetName(
                target
            )
        )

    runtime.TargetMissingAt =
        0

    runtime.CompletionStartedAt =
        0

    runtime.InventoryConfirmed =
        false

    runtime.InventoryConfirmationItem =
        nil

    runtime.LastInventoryCheckAt =
        0

    runtime.RebuyCount =
        0

    runtime.SmoothedFollowGoal =
        nil

    runtime.StablePetDirection =
        nil

    runtime.LastPetSamplePos =
        nil

    runtime.LastPetSampleAt =
        0

    local humanoid =
        HolyDefenseGetHumanoid()

    runtime.OriginalWalkSpeed =
        typeof(humanoid) == "Instance"
        and humanoid.WalkSpeed
        or nil

    HolyDefenseResolvePackets()

    HolyDefenseWatchTarget(
        target
    )

    HolyDefenseStartGearLock()

    local workerToken =
        runtime.Token

    task.spawn(function()

        HolyDefenseRunWorker(
            workerToken
        )
    end)

    return true
end

function HolyDefenseArm(entry, filter, reason)

    if HOLY_SNIPER_STATE.DefendBoughtPets ~= true then
        return false
    end

    local target =
        HolyDefenseWaitForOwnedTarget(
            entry
        )

    if typeof(target) ~= "Instance" then
        return false
    end

    return HolyDefenseStartTarget(
        target,
        entry,
        filter,
        reason
        or "confirmed buy"
    )
end

function HolyDefenseSetDefendBoughtPets(value)

    HOLY_SNIPER_STATE.DefendBoughtPets =
        value == true

    HolySaveSniperSettings()

    if HOLY_SNIPER_STATE.DefendBoughtPets == true then

        HolyDefenseStartMonitor(
            "toggle on"
        )

        HolyDefenseMonitorScan()

        return
    end

    HolyDefenseStopMonitor(
        "toggle off"
    )

    HolyDefenseStop(
        "toggle off"
    )
end

function HolyDefenseSetGear(value)

    HOLY_SNIPER_STATE.DefendGear =
        HolyDefenseNormalizeGear(
            value
        )

    HolySaveSniperSettings()

    local runtime =
        HolyDefenseEnsureRuntime()

    if HOLY_SNIPER_STATE.DefendBoughtPets == true
    and runtime.Active == true then

        HolyDefenseStartGearLock()
    end
end

function HolyDefenseSetMovement(value)

    HOLY_SNIPER_STATE.DefendMovement =
        HolyDefenseNormalizeMovement(
            value
        )

    HolySaveSniperSettings()
end

function HolyDefenseSetRebuyIfStolen(value)

    HOLY_SNIPER_STATE.DefendRebuyIfStolen =
        value == true

    HolySaveSniperSettings()
end

function HolyDefenseRestoreState()

    if HOLY_SNIPER_STATE.DefendBoughtPets == true then

        HolyDefenseStartMonitor(
            "startup"
        )

        HolyDefenseMonitorScan()

        return true
    end

    HolyDefenseStopMonitor(
        "disabled"
    )

    HolyDefenseStop(
        "disabled"
    )

    return false
end

--==================================================
-- [2.45] LIVE WILD PETS MAIN PANEL
--==================================================

if type(HOLY_LIVE_PETS_RUNTIME) == "table" then

    HOLY_LIVE_PETS_RUNTIME.Running =
        false

    HOLY_LIVE_PETS_RUNTIME.Token =
        nil

    local oldConnections =
        HOLY_LIVE_PETS_RUNTIME.Connections

    if type(oldConnections) == "table" then

        for _, connection in ipairs(oldConnections) do

            pcall(function()

                connection:Disconnect()
            end)
        end
    end
end

HOLY_LIVE_PETS_RUNTIME = {
    Running = false,
    Token = nil,
    Connections = {},
    LastRows = {},
    LastSummary = "Next Spawn: --:-- | Active: 0",

    LastSpawnedAt = 0,
    LastSpawnKey = "",
    LastPet = "None",
    SpawnSequence = {},
}

function HolyLivePetsReadAttr(instance, names)

    if typeof(instance) ~= "Instance" then
        return ""
    end

    for _, name in ipairs(names or {}) do

        local ok,
            value =
            pcall(function()

                return instance:GetAttribute(
                    name
                )
            end)

        value =
            HolyCleanText(
                ok == true
                and value
                or ""
            )

        if value ~= "" then
            return value
        end
    end

    return ""
end

function HolyLivePetsReadNumber(instance, names)

    local value =
        HolyLivePetsReadAttr(
            instance,
            names
        )

    return tonumber(value)
        or 0
end

function HolyLivePetsFormatTime(seconds)

    seconds =
        math.max(
            0,
            math.floor(
                tonumber(seconds)
                or 0
            )
        )

    local minutes =
        math.floor(seconds / 60)

    local remaining =
        seconds % 60

    return tostring(minutes)
        .. "m "
        .. tostring(remaining)
        .. "s"
end

function HolyLivePetsFormatCountdown(seconds)

    seconds =
        math.max(
            0,
            math.floor(
                tonumber(seconds)
                or 0
            )
        )

    local minutes =
        math.floor(seconds / 60)

    local remaining =
        seconds % 60

    return string.format(
        "%02d:%02d",
        minutes,
        remaining
    )
end

function HolyLivePetsFormatMoney(value)

    value =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    local text =
        tostring(
            math.floor(value)
        )

    local left,
        number,
        right =
        string.match(
            text,
            "^([^%d]*%d)(%d*)(.-)$"
        )

    if number then

        text =
            left
            .. number:reverse():gsub("(%d%d%d)", "%1,"):reverse()
            .. right
    end

    return "¢"
        .. text
end

function HolyLivePetsGetUuidFromRef(ref)

    if typeof(ref) ~= "Instance" then
        return ""
    end

    local uuid =
        tostring(ref.Name):match(
            "^WildPet_([%w%-]+)$"
        )
        or ""

    return uuid
end

function HolyLivePetsFindRefByKey(key)

    key =
        HolyCleanText(
            key
        )

    if key == "" then
        return nil
    end

    local root =
        HolySniperGetWildPetRefRoot()

    if typeof(root) ~= "Instance" then
        return nil
    end

    local direct =
        root:FindFirstChild(
            "WildPet_"
            .. key
        )

    if typeof(direct) == "Instance" then
        return direct
    end

    for _, child in ipairs(root:GetChildren()) do

        if tostring(child.Name):find(
            key,
            1,
            true
        ) then

            return child
        end
    end

    return nil
end

function HolyLivePetsFindModelForRef(ref)

    local uuid =
        HolyLivePetsGetUuidFromRef(
            ref
        )

    if uuid == "" then
        return nil
    end

    local root =
        HolySniperGetWildPetRoot()

    if typeof(root) ~= "Instance" then
        return nil
    end

    for _, child in ipairs(root:GetChildren()) do

        if child:IsA("Model")
        and tostring(child.Name):find(
            uuid,
            1,
            true
        ) then

            return child
        end
    end

    return nil
end

function HolyLivePetsGetPosition(ref, model)

    if typeof(ref) == "Instance"
    and ref:IsA("BasePart") then

        return ref.Position
    end

    if typeof(model) == "Instance" then

        return HolySniperGetModelPosition(
            model
        )
    end

    return nil
end

function HolyLivePetsGetDistance(position)

    local root =
        HolySniperGetCharacterRoot()

    if typeof(position) ~= "Vector3"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return nil
    end

    return (
        root.Position
        - position
    ).Magnitude
end

function HolyLivePetsReadSize(ref, model)

    local raw =
        HolyLivePetsReadAttr(
            ref,
            {
                "PetSize",
                "Size",
                "DisplaySize",
                "ScaleType",
                "WildPetSize",
            }
        )

    if raw ~= "" then
        return HolySniperNormalizeSizeName(
            raw
        )
    end

    raw =
        HolySniperReadModelAttribute(
            model,
            {
                "PetSize",
                "Size",
                "DisplaySize",
                "ScaleType",
                "WildPetSize",
            }
        )

    if raw ~= "" then
        return HolySniperNormalizeSizeName(
            raw
        )
    end

    if typeof(model) == "Instance" then

        return HolySniperReadLiveSize(
            model
        )
    end

    return "Normal"
end

function HolyLivePetsReadVariant(ref, model)

    local raw =
        HolyLivePetsReadAttr(
            ref,
            {
                "PetType",
                "Type",
                "Variant",
                "PetVariant",
                "Mutation",
                "WildPetType",
            }
        )

    if raw == "" then

        raw =
            HolySniperReadModelAttribute(
                model,
                {
                    "PetType",
                    "Type",
                    "Variant",
                    "PetVariant",
                    "Mutation",
                    "WildPetType",
                }
            )
    end

    raw =
        HolySniperNormalizeVariantName(
            raw
        )

    if raw ~= ""
    and raw ~= "Normal" then
        return raw
    end

    local modelName =
        tostring(
            model
            and model.Name
            or ""
        )
        :lower()

    if modelName:find("rainbow", 1, true) then
        return "Rainbow"
    end

    return "Normal"
end

function HolyLivePetsBuildDisplayName(petName, sizeName, variantName)

    local parts =
        {}

    sizeName =
        HolySniperNormalizeSizeName(
            sizeName
        )

    variantName =
        HolySniperNormalizeVariantName(
            variantName
        )

    if sizeName ~= ""
    and sizeName ~= "Normal"
    and sizeName ~= "Any" then

        table.insert(
            parts,
            sizeName
        )
    end

    if variantName ~= ""
    and variantName ~= "Normal"
    and variantName ~= "Any" then

        table.insert(
            parts,
            variantName
        )
    end

    table.insert(
        parts,
        tostring(petName or "?")
    )

    return table.concat(
        parts,
        " "
    )
end

function HolyLivePetsRarityRank(rarity)

    rarity =
        HolyCleanText(
            rarity
        )

    local ranks = {
        Super = 7,
        Mythic = 6,
        Legendary = 5,
        Epic = 4,
        Rare = 3,
        Uncommon = 2,
        Common = 1,
    }

    return ranks[rarity]
        or 0
end

function HolyLivePetsFilterMatches(entry)

    local watchlist =
        type(HOLY_SNIPER_STATE.Watchlist) == "table"
        and HOLY_SNIPER_STATE.Watchlist
        or {}

    if #watchlist <= 0 then
        return false
    end

    for _, rawFilter in ipairs(watchlist) do

        local filter =
            HolySniperNormalizeFilter(
                rawFilter
            )

        if filter.Enabled ~= false then

            local entryPet =
                HolySniperPetAliasKey(
                    entry.PetKey
                    or entry.Pet
                )

            local filterPet =
                HolySniperPetAliasKey(
                    filter.PetKey
                    or filter.Pet
                )

            if entryPet == filterPet then

                local sizeOk =
                    HolySniperSelectionHasAny(
                        filter.Sizes
                    )
                    or HolySniperSelectionContains(
                        filter.Sizes,
                        entry.Size
                    )

                local variantOk =
                    HolySniperSelectionHasAny(
                        filter.Variants
                    )
                    or HolySniperSelectionContains(
                        filter.Variants,
                        entry.Variant
                    )

                if sizeOk == true
                and variantOk == true then
                    return true
                end
            end
        end
    end

    return false
end

function HolyLivePetsBuildEntryFromRef(ref)

    if typeof(ref) ~= "Instance" then
        return nil
    end

    local petName =
        HolyLivePetsReadAttr(
            ref,
            {
                "PetName",
                "Pet",
                "DisplayName",
                "Name",
            }
        )

    if petName == "" then
        return nil
    end

    petName =
        HolySniperResolvePetDisplay(
            petName
        )

    local petKey =
        HolySniperResolvePetKey(
            petName
        )

    local uuid =
        HolyLivePetsGetUuidFromRef(
            ref
        )

    if uuid == "" then
        uuid =
            tostring(ref.Name)
    end

    local spawnedAt =
        HolyLivePetsReadNumber(
            ref,
            {
                "SpawnedAt",
                "SpawnTime",
                "CreatedAt",
            }
        )

    local lifetime =
        HolyLivePetsReadNumber(
            ref,
            {
                "Lifetime",
                "LifeTime",
                "Duration",
            }
        )

    local timeLeft =
        lifetime > 0
        and spawnedAt > 0
        and (
            spawnedAt
            + lifetime
            - os.time()
        )
        or 0

    if lifetime > 0
    and timeLeft <= -4 then

        return nil
    end

    local ownerUserId =
        HolyLivePetsReadNumber(
            ref,
            {
                "OwnerUserId",
                "OwnerUserID",
                "Owner",
                "UserId",
                "UserID",
            }
        )

    local ownerName =
        HolyLivePetsReadAttr(
            ref,
            {
                "OwnerName",
                "OwnerDisplayName",
            }
        )

    local rawState =
        HolyLivePetsReadAttr(
            ref,
            {
                "State",
                "PetState",
            }
        )

    local lowerState =
        rawState:lower()

    local model =
        HolyLivePetsFindModelForRef(
            ref
        )

    local prompt =
        model
        and HolySniperFindBuyPrompt(
            model
        )
        or nil

    local size =
        HolyLivePetsReadSize(
            ref,
            model
        )

    local variant =
        HolyLivePetsReadVariant(
            ref,
            model
        )

    local rarity =
        HolyLivePetsReadAttr(
            ref,
            {
                "Rarity",
                "PetRarity",
            }
        )

    local price =
        HolyLivePetsReadNumber(
            ref,
            {
                "Price",
                "Cost",
                "TameCost",
            }
        )

    if price <= 0 then
        price =
            HolySniperGetBasePrice({
                Pet =
                    petName,

                PetKey =
                    petKey,
            })
    end

    local position =
        HolyLivePetsGetPosition(
            ref,
            model
        )

    local distance =
        HolyLivePetsGetDistance(
            position
        )

    local handledEntry = {
        UUID = uuid,
        Key = uuid,
    }

    local handled =
        HolySniperIsHandled(
            handledEntry
        )

    local cooling =
        HolySniperIsFailedCooling(
            handledEntry
        )

    local owned =
        ownerUserId ~= 0
        or ownerName ~= ""

    if owned == true
    and handled ~= true then

        return nil
    end

    if lowerState:find("owned", 1, true)
    or lowerState:find("collected", 1, true)
    or lowerState:find("tamed", 1, true) then

        if handled ~= true then
            return nil
        end
    end

    local entry = {
        Key =
            uuid,

        UUID =
            uuid,

        Ref =
            ref,

        Model =
            model,

        Prompt =
            prompt,

        Pet =
            petName,

        PetKey =
            petKey,

        Size =
            size,

        Variant =
            variant,

        Rarity =
            rarity,

        Price =
            price,

        SpawnedAt =
            spawnedAt,

        Lifetime =
            lifetime,

        TimeLeft =
            timeLeft,

        Distance =
            distance,

        Position =
            position,

        RawState =
            rawState,
    }

    local match =
        HolyLivePetsFilterMatches(
            entry
        )

    local displayName =
        HolyLivePetsBuildDisplayName(
            petName,
            size,
            variant
        )

    local priceText =
        HolyLivePetsFormatMoney(
            price
        )

    local distanceText =
        distance
        and (
            tostring(math.floor(distance + 0.5))
            .. " studs"
        )
        or "? studs"

    local timeText =
        lifetime > 0
        and HolyLivePetsFormatTime(timeLeft)
        or "? left"

    local metaParts =
        {}

    if rarity ~= "" then
        table.insert(
            metaParts,
            rarity
        )
    end

    table.insert(
        metaParts,
        priceText
    )

    table.insert(
        metaParts,
        distanceText
    )

    local rowState =
        "ready"

    local badge =
        "BUY"

    local clickable =
        true

    if handled == true then

        rowState =
            "sent"

        badge =
            "SENT"

        clickable =
            false

    elseif cooling == true then

        rowState =
            "blocked"

        badge =
            "WAIT"

        clickable =
            false

    elseif model == nil
    or prompt == nil then

        badge =
            "WAIT"

        clickable =
            true
    end

    return {
        Key =
            uuid,

        UUID =
            uuid,

        DisplayName =
            displayName,

        Pet =
            petName,

        PetKey =
            petKey,

        Size =
            size,

        Variant =
            variant,

        Rarity =
            rarity,

        RarityRank =
            HolyLivePetsRarityRank(
                rarity
            ),

        PriceNumber =
            tonumber(price)
            or 0,

        Price =
            priceText,

        SpawnedAt =
            tonumber(spawnedAt)
            or 0,

        Lifetime =
            tonumber(lifetime)
            or 0,

        DistanceNumber =
            tonumber(distance)
            or 999999,

        Distance =
            distanceText,

        TimeLeftNumber =
            tonumber(timeLeft)
            or 0,

        Timer =
            timeText,

        Meta =
            table.concat(
                metaParts,
                " · "
            ),

        Match =
            match == true,

        Badge =
            badge,

        State =
            rowState,

        Clickable =
            clickable,

        RawState =
            rawState,

        Ref =
            ref,
    }
end

function HolyLivePetsScanRows()

    local rows =
        {}

    local refRoot =
        HolySniperGetWildPetRefRoot()

    if typeof(refRoot) ~= "Instance" then
        return rows
    end

    for _, ref in ipairs(refRoot:GetChildren()) do

        local row =
            HolyLivePetsBuildEntryFromRef(
                ref
            )

        if row then

            table.insert(
                rows,
                row
            )
        end
    end

    table.sort(rows, function(a, b)

        if a.Match ~= b.Match then
            return a.Match == true
        end

        if a.RarityRank ~= b.RarityRank then
            return a.RarityRank > b.RarityRank
        end

        if a.PriceNumber ~= b.PriceNumber then
            return a.PriceNumber > b.PriceNumber
        end

        if a.TimeLeftNumber ~= b.TimeLeftNumber then
            return a.TimeLeftNumber < b.TimeLeftNumber
        end

        return a.DistanceNumber < b.DistanceNumber
    end)

    return rows
end

function HolyLivePetsBuildTimer(rows)

    rows =
        rows
        or HolyLivePetsScanRows()

    HOLY_LIVE_PETS_RUNTIME =
        type(HOLY_LIVE_PETS_RUNTIME) == "table"
        and HOLY_LIVE_PETS_RUNTIME
        or {}

    HOLY_LIVE_PETS_RUNTIME.SpawnSequence =
        type(HOLY_LIVE_PETS_RUNTIME.SpawnSequence) == "table"
        and HOLY_LIVE_PETS_RUNTIME.SpawnSequence
        or {}

    local clean =
        {}

    for _, row in ipairs(rows) do

        local spawnedAt =
            tonumber(row.SpawnedAt)
            or 0

        if spawnedAt > 0 then

            table.insert(
                clean,
                row
            )
        end
    end

    table.sort(clean, function(a, b)

        return tonumber(a.SpawnedAt or 0)
            < tonumber(b.SpawnedAt or 0)
    end)

    if #clean > 0 then

        local latest =
            clean[#clean]

        local latestSpawnedAt =
            tonumber(latest.SpawnedAt)
            or 0

        local latestPet =
            tostring(latest.Pet or "None")

        local latestKey =
            tostring(latestSpawnedAt)
            .. "|"
            .. latestPet

        if latestSpawnedAt > 0
        and latestKey ~= tostring(HOLY_LIVE_PETS_RUNTIME.LastSpawnKey or "") then

            HOLY_LIVE_PETS_RUNTIME.LastSpawnedAt =
                latestSpawnedAt

            HOLY_LIVE_PETS_RUNTIME.LastSpawnKey =
                latestKey

            HOLY_LIVE_PETS_RUNTIME.LastPet =
                latestPet

            table.insert(
                HOLY_LIVE_PETS_RUNTIME.SpawnSequence,
                latestPet
            )

            while #HOLY_LIVE_PETS_RUNTIME.SpawnSequence > 4 do

                table.remove(
                    HOLY_LIVE_PETS_RUNTIME.SpawnSequence,
                    1
                )
            end
        end
    end

    local lastSpawnedAt =
        tonumber(
            HOLY_LIVE_PETS_RUNTIME.LastSpawnedAt
        )
        or 0

    local lastPet =
        HolyCleanText(
            HOLY_LIVE_PETS_RUNTIME.LastPet
            or "None"
        )

    if lastSpawnedAt <= 0 then

        return {
            NextText = "--:--",
            Active = #rows,
            Last = "None",
            Sequence = "None",
        }
    end

    local nextSpawn =
        lastSpawnedAt + 100

    while nextSpawn <= os.time() - 3 do

        nextSpawn =
            nextSpawn + 100
    end

    local sequence =
        "None"

    if #HOLY_LIVE_PETS_RUNTIME.SpawnSequence > 0 then

        sequence =
            table.concat(
                HOLY_LIVE_PETS_RUNTIME.SpawnSequence,
                " > "
            )
    end

    return {
        NextText =
            HolyLivePetsFormatCountdown(
                nextSpawn - os.time()
            ),

        Active =
            #rows,

        Last =
            lastPet ~= ""
            and lastPet
            or "None",

        Sequence =
            sequence,
    }
end

function HolyLivePetsBuildSummary(rows)

    local timer =
        HolyLivePetsBuildTimer(
            rows
        )

    return "Next Spawn: "
        .. tostring(timer.NextText)
        .. " | Active: "
        .. tostring(timer.Active)
        .. " | Last: "
        .. tostring(timer.Last)
end

function HolyLivePetsBuildModeText()

    local movement =
        HolySniperNormalizeMovementMode(
            HOLY_SNIPER_STATE.MovementMode
            or "Walk"
        )

    local buy =
        HolySniperNormalizeBuyMode(
            HOLY_SNIPER_STATE.BuyMode
            or "Instant"
        )

    return "Mode: "
        .. movement
        .. " · "
        .. buy
        .. " | Click a pet to buy"
end

function HolyLivePetsRefreshUI()

    local list =
        HOLY_SNIPER_UI
        and HOLY_SNIPER_UI.LivePetsList
        or nil

    if type(list) ~= "table" then
        return false
    end

    local rows =
        HolyLivePetsScanRows()

    HOLY_LIVE_PETS_RUNTIME.LastRows =
        rows

    if type(list.SetSummary) == "function" then

        list:SetSummary(
            HolyLivePetsBuildSummary(
                rows
            )
        )
    end

    if type(list.SetModeText) == "function" then

        list:SetModeText(
            HolyLivePetsBuildModeText()
        )
    end

    if type(list.SetRows) == "function" then

        list:SetRows(
            rows
        )
    end

    return true
end

function HolyLivePetsResolveEntryForBuy(rowData)

    rowData =
        type(rowData) == "table"
        and rowData
        or {}

    local key =
        HolyCleanText(
            rowData.Key
            or rowData.UUID
            or ""
        )

    if key == "" then
        return nil, "missing key"
    end

    local deadline =
        os.clock() + 3

    while os.clock() <= deadline do

        local ref =
            HolyLivePetsFindRefByKey(
                key
            )

        if typeof(ref) ~= "Instance" then

            return nil,
                "pet gone"
        end

        local model =
            HolyLivePetsFindModelForRef(
                ref
            )

        if typeof(model) == "Instance"
        and model:IsA("Model") then

            local entry =
                HolySniperBuildLiveEntry(
                    model
                )

            if type(entry) == "table" then

                return entry,
                    "ok"
            end
        end

        task.wait(
            0.05
        )
    end

    return nil,
        "prompt missing"
end

function HolyLivePetsMakeManualFilter(entry)

    entry =
        type(entry) == "table"
        and entry
        or {}

    return HolySniperNormalizeFilter({
        Pet =
            entry.Pet
            or "Raccoon",

        Sizes = {
            entry.Size
            or "Any",
        },

        Variants = {
            entry.Variant
            or "Any",
        },

        Amount =
            999,

        Priority =
            "High",

        Enabled =
            true,
    })
end

function HolyLivePetsManualBuy(rowData)

    if type(rowData) ~= "table" then
        return false
    end

    if HOLY_SNIPER_RUNTIME.Buying == true
    or HOLY_SNIPER_RUNTIME.Returning == true then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Live Pets",
                "Already buying or returning.",
                3
            )
        end

        return false
    end

    local key =
        HolyCleanText(
            rowData.Key
            or rowData.UUID
            or ""
        )

    local list =
        HOLY_SNIPER_UI
        and HOLY_SNIPER_UI.LivePetsList
        or nil

    if type(list) == "table"
    and type(list.SetStateByKey) == "function"
    and key ~= "" then

        list:SetStateByKey(
            key,
            "buying"
        )
    end

    local token =
        {}

    HOLY_SNIPER_RUNTIME.ManualBuying =
        true

    HOLY_SNIPER_RUNTIME.ManualToken =
        token

    local success =
        false

    local reason =
        "unknown"

    local ok,
        err =
        pcall(function()

            local entry,
                resolveReason =
                HolyLivePetsResolveEntryForBuy(
                    rowData
                )

            if type(entry) ~= "table" then

                reason =
                    resolveReason
                    or "target missing"

                return
            end

            local filter =
                HolyLivePetsMakeManualFilter(
                    entry
                )

            local match = {
                Entry =
                    entry,

                Filter =
                    filter,

                FilterIndex =
                    0,

                Manual =
                    true,
            }

            HolySniperSetStatus(
                "Manual buy: "
                .. HolySniperDescribeEntry(entry)
            )

            local executeReason =
                nil

            success,
                executeReason =
                HolySniperExecuteMatch(
                    match,
                    token
                )

            reason =
                executeReason
                or (
                    success == true
                    and "bought"
                    or "buy failed"
                )
        end)

    if ok ~= true then

        reason =
            tostring(err)
    end

    HOLY_SNIPER_RUNTIME.ManualBuying =
        false

    HOLY_SNIPER_RUNTIME.ManualToken =
        nil

    if type(list) == "table"
    and type(list.SetStateByKey) == "function"
    and key ~= "" then

        list:SetStateByKey(
            key,
            success == true
            and "sent"
            or "ready"
        )
    end

    HolyLivePetsRefreshUI()

    if success == true then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Live Pets",
                "Bought "
                .. tostring(rowData.DisplayName or rowData.Pet or "pet")
                .. ".",
                3
            )
        end

    else

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Live Pets",
                "Buy failed: "
                .. tostring(reason),
                4
            )
        end
    end

    return success
end

function HolyLivePetsCopySnapshot()

    local rows =
        HolyLivePetsScanRows()

    local lines =
        {}

    local function add(line)

        table.insert(
            lines,
            tostring(line or "")
        )
    end

    add("========== HOLY LIVE WILD PETS ==========")
    add("PlaceId: " .. tostring(game.PlaceId))
    add("JobId: " .. tostring(game.JobId))
    add(HolyLivePetsBuildSummary(rows))
    add("Mode: " .. HolySniperNormalizeMovementMode(HOLY_SNIPER_STATE.MovementMode) .. " / " .. HolySniperNormalizeBuyMode(HOLY_SNIPER_STATE.BuyMode))
    add("")

    if #rows <= 0 then

        add("No active wild pets.")

    else

        for index, row in ipairs(rows) do

            add(
                tostring(index)
                .. ". "
                .. tostring(row.DisplayName)
                .. " | "
                .. tostring(row.Meta)
                .. " | "
                .. tostring(row.Timer)
                .. " | "
                .. tostring(row.Badge)
            )
        end
    end

    local text =
        table.concat(
            lines,
            "\n"
        )

    if HolyCopyText(text) == true then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Live Pets",
                "Copied live pets.",
                3
            )
        end

        return true
    end

    if type(HolyNotify) == "function" then

        HolyNotify(
            "HOLY Live Pets",
            "Clipboard unsupported.",
            4
        )
    end

    return false
end

function HolyLivePetsDisconnect()

    local connections =
        HOLY_LIVE_PETS_RUNTIME
        and HOLY_LIVE_PETS_RUNTIME.Connections
        or nil

    if type(connections) == "table" then

        for _, connection in ipairs(connections) do

            pcall(function()

                connection:Disconnect()
            end)
        end
    end

    HOLY_LIVE_PETS_RUNTIME.Connections =
        {}
end

function HolyLivePetsStart()

    HOLY_LIVE_PETS_RUNTIME =
        type(HOLY_LIVE_PETS_RUNTIME) == "table"
        and HOLY_LIVE_PETS_RUNTIME
        or {}

    if HOLY_LIVE_PETS_RUNTIME.Running == true then
        return false
    end

    HolyLivePetsDisconnect()

    HOLY_LIVE_PETS_RUNTIME.Running =
        true

    HOLY_LIVE_PETS_RUNTIME.RefreshQueued =
        true

    HOLY_LIVE_PETS_RUNTIME.LastRefreshAt =
        0

    local token =
        {}

    HOLY_LIVE_PETS_RUNTIME.Token =
        token

    local function queueRefresh()

        HOLY_LIVE_PETS_RUNTIME.RefreshQueued =
            true
    end

    local function connectRoot(root)

        if typeof(root) ~= "Instance" then
            return
        end

        table.insert(
            HOLY_LIVE_PETS_RUNTIME.Connections,
            root.ChildAdded:Connect(
                queueRefresh
            )
        )

        table.insert(
            HOLY_LIVE_PETS_RUNTIME.Connections,
            root.ChildRemoved:Connect(
                queueRefresh
            )
        )
    end

    connectRoot(
        HolySniperGetWildPetRefRoot()
    )

    connectRoot(
        HolySniperGetWildPetRoot()
    )

    task.spawn(function()

        while HOLY_LIVE_PETS_RUNTIME.Token == token do

            local lowEnd =
                HolyLowEndModeEnabled()

            local periodicInterval =
                lowEnd == true
                and 1
                or 0.35

            local eventInterval =
                lowEnd == true
                and 0.75
                or 0.25

            local now =
                os.clock()

            local elapsed =
                now
                - (
                    tonumber(
                        HOLY_LIVE_PETS_RUNTIME.LastRefreshAt
                    )
                    or 0
                )

            local eventReady =
                HOLY_LIVE_PETS_RUNTIME.RefreshQueued == true
                and elapsed >= eventInterval

            local periodicReady =
                elapsed >= periodicInterval

            if eventReady
            or periodicReady then

                HOLY_LIVE_PETS_RUNTIME.RefreshQueued =
                    false

                HOLY_LIVE_PETS_RUNTIME.LastRefreshAt =
                    now

                HolyLivePetsRefreshUI()
            end

            task.wait(
                lowEnd == true
                and 0.25
                or 0.10
            )
        end

        if HOLY_LIVE_PETS_RUNTIME.Token == token then

            HOLY_LIVE_PETS_RUNTIME.Running =
                false
        end
    end)

    return true
end

function HolyLivePetsStop(reason)

    HOLY_LIVE_PETS_RUNTIME =
        type(HOLY_LIVE_PETS_RUNTIME) == "table"
        and HOLY_LIVE_PETS_RUNTIME
        or {}

    HOLY_LIVE_PETS_RUNTIME.Token =
        nil

    HOLY_LIVE_PETS_RUNTIME.Running =
        false

    HolyLivePetsDisconnect()

    return true
end

--==================================================
-- PET INVENTORY
--==================================================

HOLY_PET_INVENTORY_RUNTIME =
    type(HOLY_PET_INVENTORY_RUNTIME) == "table"
    and HOLY_PET_INVENTORY_RUNTIME
    or {
        Running =
            false,

        Token =
            nil,

        Connections =
            {},

        ConnectedRoots =
            {},

        RefreshQueued =
            false,

        LastSignature =
            "",
    }

HOLY_PET_INVENTORY_UI =
    type(HOLY_PET_INVENTORY_UI) == "table"
    and HOLY_PET_INVENTORY_UI
    or {}

function HolyPetInventoryEscapeRichText(value)

    return tostring(value or "")
        :gsub("&", "&amp;")
        :gsub("<", "&lt;")
        :gsub(">", "&gt;")
        :gsub('"', "&quot;")
        :gsub("'", "&apos;")
end

function HolyPetInventoryScanRows()

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local petModulesObject =
        sharedModules
        and sharedModules:FindFirstChild(
            "PetModules"
        )
        or nil

    if typeof(petModulesObject) ~= "Instance"
    or petModulesObject:IsA("ModuleScript") ~= true then

        return {}
    end

    local requireOk,
        petModules =
        pcall(
            require,
            petModulesObject
        )

    if requireOk ~= true
    or type(petModules) ~= "table" then

        return {}
    end

    local petCatalog =
        {}

    local function prettyPetName(value)

        local text =
            HolyCleanText(
                value
            )
            :gsub("_", " ")
            :gsub("(%l)(%u)", "%1 %2")
            :gsub("(%u)(%u%l)", "%1 %2")

        return HolyCleanText(
            text
        )
    end

    local function addCatalogAlias(
        alias,
        catalogEntry
    )

        alias =
            HolySniperPetAliasKey(
                alias
            )

        if alias == "" then
            return
        end

        petCatalog[alias] =
            catalogEntry
    end

    for moduleKey, moduleData in pairs(
        petModules
    ) do

        if type(moduleKey) == "string"
        and type(moduleData) == "table" then

            local displayName =
                HolyCleanText(
                    moduleData.DisplayName
                    or moduleData.Name
                    or ""
                )

            if displayName == "" then

                displayName =
                    prettyPetName(
                        moduleKey
                    )
            end

            local catalogEntry = {
                Key =
                    moduleKey,

                Name =
                    displayName,
            }

            addCatalogAlias(
                moduleKey,
                catalogEntry
            )

            addCatalogAlias(
                moduleData.AssetName,
                catalogEntry
            )

            addCatalogAlias(
                displayName,
                catalogEntry
            )
        end
    end

    local grouped =
        {}

    local seenTools =
        {}

    local roots = {
        LocalPlayer
        and LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )
        or nil,

        LocalPlayer
        and LocalPlayer.Character
        or nil,
    }

    for _, root in ipairs(roots) do

        if typeof(root) == "Instance" then

            for _, tool in ipairs(
                root:GetChildren()
            ) do

                if tool:IsA("Tool")
                and seenTools[tool] ~= true then

                    seenTools[tool] =
                        true

                    local rawPetName =
                        HolyCleanText(
                            tool:GetAttribute(
                                "Pet"
                            )
                            or ""
                        )

                    local petId =
                        HolyCleanText(
                            tool:GetAttribute(
                                "PetId"
                            )
                            or ""
                        )

                    if rawPetName ~= ""
                    and petId ~= "" then

                        local catalogEntry =
                            petCatalog[
                                HolySniperPetAliasKey(
                                    rawPetName
                                )
                            ]

                        if type(catalogEntry) == "table" then

                            local petName =
                                catalogEntry.Name

                            local sizeName =
                                HolySniperNormalizeSizeName(
                                    HolySniperReadLiveSize(
                                        tool,
                                        nil
                                    )
                                )

                            if sizeName == "Normal" then

                                local lowerToolName =
                                    tostring(tool.Name or "")
                                        :lower()

                                if lowerToolName:match(
                                    "^huge%s+"
                                )
                                or lowerToolName:match(
                                    "^mega%s+"
                                ) then

                                    sizeName =
                                        "Huge"

                                elseif lowerToolName:match(
                                    "^big%s+"
                                ) then

                                    sizeName =
                                        "Big"
                                end
                            end

                            local variantName =
                                HolySniperNormalizeVariantName(
                                    HolySniperReadLiveVariant(
                                        tool,
                                        nil
                                    )
                                )

                            local groupKey =
                                HolySniperPetAliasKey(
                                    petName
                                )
                                .. "|"
                                .. HolySniperPetAliasKey(
                                    sizeName
                                )
                                .. "|"
                                .. HolySniperPetAliasKey(
                                    variantName
                                )

                            local group =
                                grouped[groupKey]

                            if type(group) ~= "table" then

                                group = {
                                    Key =
                                        groupKey,

                                    Name =
                                        petName,

                                    Size =
                                        sizeName,

                                    Variant =
                                        variantName,

                                    Amount =
                                        0,
                                }

                                grouped[groupKey] =
                                    group
                            end

                            group.Amount +=
                                1
                        end
                    end
                end
            end
        end
    end

    local rows =
        {}

    for _, group in pairs(grouped) do

        local details =
            {}

        if group.Size ~= ""
        and group.Size ~= "Normal"
        and group.Size ~= "Any" then

            table.insert(
                details,
                group.Size
            )
        end

        if group.Variant ~= ""
        and group.Variant ~= "Normal"
        and group.Variant ~= "Any" then

            table.insert(
                details,
                group.Variant
            )
        end

        table.insert(
            rows,
            {
                Key =
                    group.Key,

                Name =
                    group.Name,

                Details =
                    table.concat(
                        details,
                        " · "
                    ),

                Size =
                    group.Size,

                Variant =
                    group.Variant,

                Amount =
                    group.Amount,
            }
        )
    end

    local sizeOrder = {
        Normal =
            1,

        Big =
            2,

        Huge =
            3,
    }

    table.sort(rows, function(a, b)

        local nameA =
            tostring(a.Name or "")
                :lower()

        local nameB =
            tostring(b.Name or "")
                :lower()

        if nameA ~= nameB then
            return nameA < nameB
        end

        local sizeA =
            sizeOrder[a.Size]
            or 50

        local sizeB =
            sizeOrder[b.Size]
            or 50

        if sizeA ~= sizeB then
            return sizeA < sizeB
        end

        return tostring(a.Variant or "")
            < tostring(b.Variant or "")
    end)

    return rows
end

function HolyPetInventoryBuildSignature(rows)

    local parts =
        {}

    for _, row in ipairs(rows or {}) do

        table.insert(
            parts,
            tostring(row.Key or "")
            .. ":"
            .. tostring(row.Amount or 0)
        )
    end

    return table.concat(
        parts,
        "|"
    )
end

function HolyPetInventoryApplyListStyle(list)

    if type(list) ~= "table" then
        return
    end

    for _, row in ipairs(
        list.Rows
        or {}
    ) do

        if row.KeyLabel then

            row.KeyLabel.Font =
                Enum.Font.GothamBold

            row.KeyLabel.TextSize =
                14

            row.KeyLabel.TextTransparency =
                0

            row.KeyLabel.TextXAlignment =
                Enum.TextXAlignment.Left
        end

        if row.ValueLabel then

            row.ValueLabel.Font =
                Enum.Font.GothamBold

            row.ValueLabel.TextSize =
                14

            row.ValueLabel.TextTransparency =
                0

            row.ValueLabel.TextXAlignment =
                Enum.TextXAlignment.Right
        end
    end
end

function HolyPetInventoryRefreshUI(force)

    local rows =
        HolyPetInventoryScanRows()

    HOLY_PET_INVENTORY_RUNTIME.LastRows =
        rows

    HOLY_PET_INVENTORY_RUNTIME.LastRefreshAt =
        os.clock()

    HOLY_PET_INVENTORY_RUNTIME.RefreshQueued =
        false

    local list =
        HOLY_PET_INVENTORY_UI.List

    if type(list) ~= "table"
    or type(list.SetRows) ~= "function" then

        return rows
    end

    local signature =
        HolyPetInventoryBuildSignature(
            rows
        )

    if force ~= true
    and signature
        == HOLY_PET_INVENTORY_RUNTIME.LastSignature then

        return rows
    end

    HOLY_PET_INVENTORY_RUNTIME.LastSignature =
        signature

    local renderedRows =
        {}

    if #rows <= 0 then

        table.insert(
            renderedRows,
            {
                Key =
                    '<font color="#8E95A5">'
                    .. "No pets in inventory."
                    .. "</font>",

                Value =
                    "",
            }
        )

    else

        for _, row in ipairs(rows) do

            local leftText =
                '<font color="#F2F4F8">'
                .. HolyPetInventoryEscapeRichText(
                    row.Name
                )
                .. "</font>"

            if row.Details ~= "" then

                leftText =
                    leftText
                    .. '<font color="#8E95A5">'
                    .. " · "
                    .. HolyPetInventoryEscapeRichText(
                        row.Details
                    )
                    .. "</font>"
            end

            table.insert(
                renderedRows,
                {
                    Key =
                        leftText,

                    Value =
                        '<font color="#FF2F68">'
                        .. "×"
                        .. tostring(row.Amount)
                        .. "</font>",
                }
            )
        end
    end

    list:SetRows(
        renderedRows
    )

    HolyPetInventoryApplyListStyle(
        list
    )

    return rows
end

function HolyPetInventoryIsPetTool(instance)

    if typeof(instance) ~= "Instance"
    or instance:IsA("Tool") ~= true then

        return false
    end

    local petName =
        HolyCleanText(
            instance:GetAttribute(
                "Pet"
            )
            or ""
        )

    local petId =
        HolyCleanText(
            instance:GetAttribute(
                "PetId"
            )
            or ""
        )

    return petName ~= ""
        and petId ~= ""
end

function HolyPetInventoryScheduleRefresh()

    HOLY_PET_INVENTORY_RUNTIME.RefreshQueued =
        true
end

function HolyPetInventoryDisconnect()

    for _, connection in ipairs(
        HOLY_PET_INVENTORY_RUNTIME.Connections
        or {}
    ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    HOLY_PET_INVENTORY_RUNTIME.Connections =
        {}

    HOLY_PET_INVENTORY_RUNTIME.ConnectedRoots =
        {}
end

function HolyPetInventoryStop(reason)

    HOLY_PET_INVENTORY_RUNTIME.Token =
        nil

    HOLY_PET_INVENTORY_RUNTIME.Running =
        false

    HolyPetInventoryDisconnect()

    return true
end

function HolyPetInventoryStart()

    if HOLY_PET_INVENTORY_RUNTIME.Running == true then

        HolyPetInventoryStop(
            "restart"
        )
    end

    HOLY_PET_INVENTORY_RUNTIME.Running =
        true

    HOLY_PET_INVENTORY_RUNTIME.LastSignature =
        ""

    local token =
        {}

    HOLY_PET_INVENTORY_RUNTIME.Token =
        token

    local function addConnection(connection)

        if connection ~= nil then

            table.insert(
                HOLY_PET_INVENTORY_RUNTIME.Connections,
                connection
            )
        end
    end

    local function connectRoot(root)

        if typeof(root) ~= "Instance"
        or HOLY_PET_INVENTORY_RUNTIME.ConnectedRoots[root] == true then

            return
        end

        HOLY_PET_INVENTORY_RUNTIME.ConnectedRoots[root] =
            true

        addConnection(
            root.ChildAdded:Connect(function(child)

                if HolyPetInventoryIsPetTool(
                    child
                ) == true then

                    HolyPetInventoryScheduleRefresh()
                end
            end)
        )

        addConnection(
            root.ChildRemoved:Connect(function(child)

                if HolyPetInventoryIsPetTool(
                    child
                ) == true then

                    HolyPetInventoryScheduleRefresh()
                end
            end)
        )
    end

    local function connectCurrentRoots()

        if not LocalPlayer then
            return
        end

        connectRoot(
            LocalPlayer.Character
        )

        connectRoot(
            LocalPlayer:FindFirstChildOfClass(
                "Backpack"
            )
        )
    end

    connectCurrentRoots()

    if LocalPlayer then

        addConnection(
            LocalPlayer.CharacterAdded:Connect(function(character)

                connectRoot(
                    character
                )

                HolyPetInventoryScheduleRefresh()
            end)
        )

        addConnection(
            LocalPlayer.ChildAdded:Connect(function(child)

                if child:IsA("Backpack") then

                    connectRoot(
                        child
                    )

                    HolyPetInventoryScheduleRefresh()
                end
            end)
        )
    end

    HOLY_PET_INVENTORY_RUNTIME.LastRefreshAt =
        0

    HOLY_PET_INVENTORY_RUNTIME.RefreshQueued =
        true

    HolyPetInventoryRefreshUI(
        true
    )

    task.spawn(function()

        while HOLY_PET_INVENTORY_RUNTIME.Token == token do

            connectCurrentRoots()

            local lowEnd =
                HolyLowEndModeEnabled()

            local dirtyInterval =
                lowEnd == true
                and 0.75
                or 0.15

            local safetyInterval =
                lowEnd == true
                and 15
                or 5

            local elapsed =
                os.clock()
                - (
                    tonumber(
                        HOLY_PET_INVENTORY_RUNTIME.LastRefreshAt
                    )
                    or 0
                )

            local dirtyReady =
                HOLY_PET_INVENTORY_RUNTIME.RefreshQueued == true
                and elapsed >= dirtyInterval

            local safetyReady =
                elapsed >= safetyInterval

            if dirtyReady
            or safetyReady then

                HolyPetInventoryRefreshUI()
            end

            task.wait(
                lowEnd == true
                and 0.25
                or 0.10
            )
        end
    end)

    return true
end


