        end)
    end
end

HOLY_FARM_DETAILS_STATE =
    type(HOLY_FARM_DETAILS_STATE) == "table"
    and HOLY_FARM_DETAILS_STATE
    or {}

HOLY_FARM_DETAILS_STATE.SelectedPlants =
    type(HOLY_FARM_DETAILS_STATE.SelectedPlants) == "table"
    and HOLY_FARM_DETAILS_STATE.SelectedPlants
    or {}

HOLY_FARM_DETAILS_STATE.SelectedMutations =
    type(HOLY_FARM_DETAILS_STATE.SelectedMutations) == "table"
    and HOLY_FARM_DETAILS_STATE.SelectedMutations
    or {}

HOLY_FARM_DETAILS_STATE.OverviewPage =
    tonumber(
        HOLY_FARM_DETAILS_STATE.OverviewPage
    )
    or 1

HOLY_FARM_DETAILS_STATE.FruitPage =
    tonumber(
        HOLY_FARM_DETAILS_STATE.FruitPage
    )
    or 1

HOLY_FARM_DETAILS_STATE.RowsPerPage =
    6

HOLY_FARM_DETAILS_RUNTIME = {
    Running =
        false,

    Token =
        nil,

    Connections =
        {},

    Networking =
        nil,

    GardenNetworking =
        nil,

    Cache = {
        Plants =
            {},
    },

    SnapshotReady =
        false,

    EventsConnected =
        false,

    LastRequestAt =
        0,

    RefreshQueued =
        false,

    LastRenderAt =
        0,

    FilterMode =
        "Plants",

    CurrentMode =
        "Overview",

    CurrentPageCount =
        1,

    Status =
        "Loading",
}

HOLY_FARM_DETAILS_UI = {}

function HolyFarmDetailsEscape(value)

    return tostring(value or "")
        :gsub("&", "&amp;")
        :gsub("<", "&lt;")
        :gsub(">", "&gt;")
        :gsub('"', "&quot;")
        :gsub("'", "&apos;")
end

function HolyFarmDetailsCountSet(set)

    local count =
        0

    for _ in pairs(
        type(set) == "table"
        and set
        or {}
    ) do

        count +=
            1
    end

    return count
end

function HolyFarmDetailsCleanName(value)

    if type(value) == "table" then

        value =
            value.Name
            or value.DisplayName
            or value.PlantName
            or value.Seed
            or ""
    end

    local text =
        HolyCleanText(
            value
        )

    text =
        text:gsub("_", " ")
            :gsub("(%l)(%u)", "%1 %2")
            :gsub("(%u)(%u%l)", "%1 %2")

    return HolyCleanText(
        text
    )
end

function HolyFarmDetailsPlantName(plantData)

    if type(plantData) ~= "table" then
        return "Unknown"
    end

    local name =
        HolyFarmDetailsCleanName(
            plantData.PlantName
            or plantData.SeedName
            or plantData.Seed
            or plantData.Name
            or ""
        )

    if name == "" then

        name =
            "Unknown"
    end

    return name
end

function HolyFarmDetailsMutationHex(value)

    local key =
        tostring(value or "")
            :lower()
            :gsub("[^%w]", "")

    local colors = {
        normal =
            "#DCDDE6",

        glow =
            "#35D4FF",

        gold =
            "#FFD84A",

        rainbow =
            "#FF4DFF",

        electric =
            "#FFE23D",

        frozen =
            "#70C9FF",

        bloodlit =
            "#FF4545",

        starstruck =
            "#FFF06A",

        aurora =
            "#B56CFF",

        solarflare =
            "#FF8A25",

        ignited =
            "#FF5A2E",

        chained =
            "#B8B8C2",

        pizza =
            "#FFB347",
    }

    return colors[key]
        or "#F2F4F8"
end

function HolyFarmDetailsCollectMutations(
    fruitData,
    plantData
)

    local output =
        {}

    local seen =
        {}

    local function addMutation(
        value,
        depth
    )

        depth =
            tonumber(depth)
            or 0

        if depth > 3
        or value == nil then

            return
        end

        if type(value) == "string"
        or type(value) == "number" then

            local text =
                HolyCleanText(
                    value
                )

            text =
                text:gsub("^%[", "")
                    :gsub("%]$", "")
                    :gsub("^%{", "")
                    :gsub("%}$", "")

            for part in text:gmatch(
                "[^,%|/;]+"
            ) do

                part =
                    HolyCleanText(
                        part
                    )

                if part ~= ""
                and part:lower() ~= "none"
                and seen[part:lower()] ~= true then

                    seen[part:lower()] =
                        true

                    table.insert(
                        output,
                        part
                    )
                end
            end

            return
        end

        if type(value) == "table" then

            if value.Name ~= nil then

                addMutation(
                    value.Name,
                    depth + 1
                )
            end

            if value.Mutation ~= nil then

                addMutation(
                    value.Mutation,
                    depth + 1
                )
            end

            if value.Mutations ~= nil then

                addMutation(
                    value.Mutations,
                    depth + 1
                )
            end

            for key,
                entry in pairs(value) do

                if type(key) == "string"
                and entry == true then

                    addMutation(
                        key,
                        depth + 1
                    )

                elseif type(entry) == "string"
                or type(entry) == "number" then

                    addMutation(
                        entry,
                        depth + 1
                    )
                end
            end
        end
    end

    local fruitMutation =
        type(fruitData) == "table"
        and (
            fruitData.Mutation
            or fruitData.Mutations
            or fruitData.Variant
        )
        or nil

    if fruitMutation ~= nil then

        addMutation(
            fruitMutation,
            0
        )

    elseif type(plantData) == "table" then

        addMutation(
            plantData.Mutation
            or plantData.Mutations
            or plantData.Variant,
            0
        )
    end

    if #output <= 0 then

        output[1] =
            "Normal"
    end

    table.sort(output, function(a, b)

        if a == "Normal" then
            return true
        end

        if b == "Normal" then
            return false
        end

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyFarmDetailsMutationText(mutations)

    return table.concat(
        mutations or {
            "Normal",
        },
        " + "
    )
end

function HolyFarmDetailsPrepareFruit(fruitData)

    if type(fruitData) ~= "table" then
        return
    end

    fruitData._HolyFarmDetailsClock =
        os.clock()
end

function HolyFarmDetailsPreparePlant(plantData)

    if type(plantData) ~= "table" then
        return
    end

    plantData._HolyFarmDetailsClock =
        os.clock()

    plantData.Fruits =
        type(plantData.Fruits) == "table"
        and plantData.Fruits
        or {}

    for _,
        fruitData in pairs(
            plantData.Fruits
        ) do

        HolyFarmDetailsPrepareFruit(
            fruitData
        )
    end
end

function HolyFarmDetailsCurrentAge(data)

    if type(data) ~= "table" then
        return 0
    end

    local age =
        tonumber(
            data.Age
            or data.CurrentAge
        )
        or 0

    local growthRate =
        tonumber(
            data.GrowRate
            or data.GrowthRate
            or data.StableGrowthAmount
        )
        or 0

    local lastClock =
        tonumber(
            data._HolyFarmDetailsClock
        )

    if lastClock ~= nil
    and growthRate > 0 then

        age +=
            math.max(
                0,
                os.clock() - lastClock
            )
            * growthRate
    end

    local maxAge =
        tonumber(
            data.MaxAge
        )

    if maxAge ~= nil
    and maxAge > 0 then

        age =
            math.min(
                age,
                maxAge
            )
    end

    return age
end

function HolyFarmDetailsFruitReady(fruitData)

    if type(fruitData) ~= "table" then
        return false
    end

    local finishedAt =
        tonumber(
            fruitData.FinishedGrowingAt
        )

    if finishedAt ~= nil
    and finishedAt > 100000000 then

        local now =
            os.time()

        pcall(function()

            now =
                workspace:GetServerTimeNow()
        end)

        return now >= finishedAt
    end

    local maxAge =
        tonumber(
            fruitData.MaxAge
        )
        or 0

    if maxAge <= 0 then
        return false
    end

    return HolyFarmDetailsCurrentAge(
        fruitData
    ) >= maxAge - 0.01
end

function HolyFarmDetailsWeightKg(
    plantName,
    fruitData
)

    if type(fruitData) ~= "table" then
        return nil
    end

    local directWeight =
        tonumber(
            fruitData.WeightKg
            or fruitData.Weight
            or fruitData.Kg
            or fruitData.Mass
        )

    if directWeight ~= nil
    and directWeight > 0 then

        return directWeight
    end

    local baseWeight =
        nil

    if type(HolyFarmGetBaseKg) == "function" then

        baseWeight =
            tonumber(
                HolyFarmGetBaseKg(
                    plantName,
                    "Fruit"
                )
            )
    end

    if baseWeight == nil
    or baseWeight <= 0 then

        return nil
    end

    local sizeMultiplier =
        tonumber(
            fruitData.SizeMultiplier
            or fruitData.SizeMulti
            or fruitData.ScaleMultiplier
            or fruitData.ScaleMulti
            or fruitData.Scale
        )
        or 1

    if sizeMultiplier <= 0 then

        sizeMultiplier =
            1
    end

    local overtimeGrowth =
        tonumber(
            fruitData.OvertimeGrowth
            or fruitData.OvertimeMultiplier
        )
        or 1

    if overtimeGrowth <= 0 then

        overtimeGrowth =
            1
    end

    return baseWeight
        * sizeMultiplier
        * overtimeGrowth
end

function HolyFarmDetailsFormatKg(value)

    value =
        tonumber(value)

    if value == nil then
        return "?kg"
    end

    return string.format(
        "%.2fkg",
        value
    )
end

function HolyFarmDetailsBuildGroups()

    local runtime =
        HOLY_FARM_DETAILS_RUNTIME

    local grouped =
        {}

    for plantId,
        plantData in pairs(
            runtime.Cache.Plants
            or {}
        ) do

        if type(plantData) == "table" then

            local plantName =
                HolyFarmDetailsPlantName(
                    plantData
                )

            local key =
                plantName:lower()

            local group =
                grouped[key]

            if type(group) ~= "table" then

                group = {
                    Key =
                        key,

                    Name =
                        plantName,

                    Plants =
                        0,

                    Fruits =
                        {},
                }

                grouped[key] =
                    group
            end

            group.Plants +=
                1

            for fruitId,
                fruitData in pairs(
                    type(plantData.Fruits) == "table"
                    and plantData.Fruits
                    or {}
                ) do

                if type(fruitData) == "table" then

                    local mutations =
                        HolyFarmDetailsCollectMutations(
                            fruitData,
                            plantData
                        )

                    table.insert(
                        group.Fruits,
                        {
                            PlantId =
                                tostring(plantId),

                            FruitId =
                                tostring(fruitId),

                            PlantName =
                                plantName,

                            Mutations =
                                mutations,

                            MutationText =
                                HolyFarmDetailsMutationText(
                                    mutations
                                ),

                            Weight =
                                HolyFarmDetailsWeightKg(
                                    plantName,
                                    fruitData
                                ),

                            Ready =
                                HolyFarmDetailsFruitReady(
                                    fruitData
                                ),

                            FruitData =
                                fruitData,
                        }
                    )
                end
            end
        end
    end

    local groups =
        {}

    for _,
        group in pairs(grouped) do

        table.sort(
            group.Fruits,
            function(a, b)

                local weightA =
                    tonumber(a.Weight)
                    or -math.huge

                local weightB =
                    tonumber(b.Weight)
                    or -math.huge

                if weightA ~= weightB then

                    return weightA > weightB
                end

                if a.MutationText
                    ~= b.MutationText then

                    return tostring(
                        a.MutationText
                    ):lower()
                        < tostring(
                            b.MutationText
                        ):lower()
                end

                return tostring(a.FruitId)
                    < tostring(b.FruitId)
            end
        )

        table.insert(
            groups,
            group
        )
    end

    table.sort(groups, function(a, b)

        return tostring(a.Name):lower()
            < tostring(b.Name):lower()
    end)

    return groups
end

function HolyFarmDetailsMutationAllowed(fruit)

    local selected =
        HOLY_FARM_DETAILS_STATE.SelectedMutations

    if HolyFarmDetailsCountSet(
        selected
    ) <= 0 then

        return true
    end

    for _,
        mutation in ipairs(
            fruit.Mutations
            or {}
        ) do

        if selected[mutation] == true then
            return true
        end
    end

    return false
end

function HolyFarmDetailsGetVisibleGroups(groups)

    local selected =
        HOLY_FARM_DETAILS_STATE.SelectedPlants

    local hasSelection =
        HolyFarmDetailsCountSet(
            selected
        ) > 0

    local output =
        {}

    for _,
        group in ipairs(groups or {}) do

        if hasSelection ~= true
        or selected[group.Name] == true then

            local filteredFruits =
                {}

            local ready =
                0

            for _,
                fruit in ipairs(
                    group.Fruits
                    or {}
                ) do

                if HolyFarmDetailsMutationAllowed(
                    fruit
                ) then

                    table.insert(
                        filteredFruits,
                        fruit
                    )

                    if fruit.Ready == true then

                        ready +=
                            1
                    end
                end
            end

            table.insert(
                output,
                {
                    Key =
                        group.Key,

                    Name =
                        group.Name,

                    Plants =
                        group.Plants,

                    Fruits =
                        filteredFruits,

                    AllFruits =
                        group.Fruits,

                    Ready =
                        ready,
                }
            )
        end
    end

    return output
end

function HolyFarmDetailsBuildMutationSummary(fruits)

    local counts =
        {}

    for _,
        fruit in ipairs(fruits or {}) do

        for _,
            mutation in ipairs(
                fruit.Mutations
                or {
                    "Normal",
                }
            ) do

            counts[mutation] =
                (
                    counts[mutation]
                    or 0
                )
                + 1
        end
    end

    local entries =
        {}

    for mutation,
        amount in pairs(counts) do

        table.insert(
            entries,
            {
                Mutation =
                    mutation,

                Amount =
                    amount,
            }
        )
    end

    table.sort(entries, function(a, b)

        if a.Amount ~= b.Amount then

            return a.Amount >
                b.Amount
        end

        return tostring(a.Mutation):lower()
            < tostring(b.Mutation):lower()
    end)

    local parts =
        {}

    local shown =
        math.min(
            2,
            #entries
        )

    for index = 1,
        shown do

        local entry =
            entries[index]

        table.insert(
            parts,
            '<font color="'
            .. HolyFarmDetailsMutationHex(
                entry.Mutation
            )
            .. '">'
            .. HolyFarmDetailsEscape(
                entry.Mutation
            )
            .. " "
            .. tostring(
                entry.Amount
            )
            .. "</font>"
        )
    end

    if #entries > shown then

        table.insert(
            parts,
            '<font color="#8E95A5">+'
            .. tostring(
                #entries - shown
            )
            .. "</font>"
        )
    end

    if #parts <= 0 then

        return '<font color="#8E95A5">No matching fruits</font>'
    end

    return table.concat(
        parts,
        " · "
    )
end

function HolyFarmDetailsBuildFruitRichText(fruit)

    local mutationParts =
        {}

    for _,
        mutation in ipairs(
            fruit.Mutations
            or {
                "Normal",
            }
        ) do

        table.insert(
            mutationParts,
            '<font color="'
            .. HolyFarmDetailsMutationHex(
                mutation
            )
            .. '">'
            .. HolyFarmDetailsEscape(
                mutation
            )
            .. "</font>"
        )
    end

    return table.concat(
        mutationParts,
        '<font color="#8E95A5"> + </font>'
    )
        .. ' <font color="#F2F4F8">'
        .. HolyFarmDetailsEscape(
            fruit.PlantName
        )
        .. "</font>"
end

function HolyFarmDetailsScheduleRender()

    HOLY_FARM_DETAILS_RUNTIME.RefreshQueued =
        true
end

function HolyFarmDetailsGetGardenNetworking()

    local runtime =
        HOLY_FARM_DETAILS_RUNTIME

    if type(runtime.GardenNetworking) == "table" then

        return runtime.GardenNetworking
    end

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        local networkingModule =
            sharedModules
            and sharedModules:FindFirstChild(
                "Networking"
            )

        if typeof(networkingModule) == "Instance"
        and networkingModule:IsA("ModuleScript") then

            local ok,
                result =
                pcall(
                    require,
                    networkingModule
                )

            if ok == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    local garden =
        type(networking) == "table"
        and type(networking.Garden) == "table"
        and networking.Garden
        or nil

    runtime.Networking =
        networking

    runtime.GardenNetworking =
        garden

    return garden
end

function HolyFarmDetailsOwnerMatches(owner)

    return tostring(owner or "")
        == tostring(
            LocalPlayer.UserId
        )
end

function HolyFarmDetailsDisconnect()

    local runtime =
        HOLY_FARM_DETAILS_RUNTIME

    for _,
        connection in ipairs(
            runtime.Connections
            or {}
        ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.Connections =
        {}

    runtime.EventsConnected =
        false
end

function HolyFarmDetailsConnectPacket(
    packet,
    callback
)

    if type(packet) ~= "table"
    or packet.OnClientEvent == nil then

        return false
    end

    local ok,
        connection =
        pcall(function()

            return packet.OnClientEvent:Connect(
                callback
            )
        end)

    if ok == true
    and connection ~= nil then

        table.insert(
            HOLY_FARM_DETAILS_RUNTIME.Connections,
            connection
        )

        return true
    end

    return false
end

function HolyFarmDetailsApplySnapshot(snapshot)

    if type(snapshot) ~= "table" then
        return false
    end

    local userId =
        LocalPlayer.UserId

    local gardenData =
        snapshot[userId]
        or snapshot[tostring(userId)]

    if type(gardenData) ~= "table"
    or type(gardenData.Plants) ~= "table" then

        -- Some SyncAllGardens packets only contain another
        -- player's garden. Never clear our cache from those.
        return false
    end

    local runtime =
        HOLY_FARM_DETAILS_RUNTIME

    runtime.Cache.Plants =
        gardenData.Plants

    for _,
        plantData in pairs(
            runtime.Cache.Plants
        ) do

        HolyFarmDetailsPreparePlant(
            plantData
        )
    end

    runtime.SnapshotReady =
        true

    runtime.Status =
        "Ready"

    HolyFarmDetailsScheduleRender()

    return true
end

function HolyFarmDetailsConnectEvents()

    local runtime =
        HOLY_FARM_DETAILS_RUNTIME

    HolyFarmDetailsDisconnect()

    local garden =
        HolyFarmDetailsGetGardenNetworking()

    if type(garden) ~= "table" then
        return false
    end

    local snapshotConnected =
        HolyFarmDetailsConnectPacket(
            garden.SyncAllGardens,
            function(snapshot)

                HolyFarmDetailsApplySnapshot(
                    snapshot
                )
            end
        )

    HolyFarmDetailsConnectPacket(
        garden.PlantAdded,
        function(owner, plantId, plantData)

            if HolyFarmDetailsOwnerMatches(
                owner
            ) ~= true
            or type(plantData) ~= "table" then

                return
            end

            plantId =
                tostring(plantId)

            HolyFarmDetailsPreparePlant(
                plantData
            )

            runtime.Cache.Plants[plantId] =
                plantData

            HolyFarmDetailsScheduleRender()
        end
    )

    HolyFarmDetailsConnectPacket(
        garden.PlantRemoved,
        function(owner, plantId)

            if HolyFarmDetailsOwnerMatches(
                owner
            ) ~= true then

                return
            end

            runtime.Cache.Plants[
                tostring(plantId)
            ] =
                nil

            HolyFarmDetailsScheduleRender()
        end
    )

    HolyFarmDetailsConnectPacket(
        garden.FruitAdded,
        function(
            owner,
            plantId,
            fruitId,
            fruitData
        )

            if HolyFarmDetailsOwnerMatches(
                owner
            ) ~= true
            or type(fruitData) ~= "table" then

                return
            end

            plantId =
                tostring(plantId)

            fruitId =
                tostring(fruitId)

            local plantData =
                runtime.Cache.Plants[
                    plantId
                ]

            if type(plantData) ~= "table" then

                plantData = {
                    PlantName =
                        fruitData.PlantName
                        or fruitData.Seed
                        or "Unknown",

                    Fruits =
                        {},
                }

                runtime.Cache.Plants[
                    plantId
                ] =
                    plantData
            end

            plantData.Fruits =
                type(plantData.Fruits) == "table"
                and plantData.Fruits
                or {}

            HolyFarmDetailsPrepareFruit(
                fruitData
            )

            plantData.Fruits[fruitId] =
                fruitData

            HolyFarmDetailsScheduleRender()
        end
    )

    HolyFarmDetailsConnectPacket(
        garden.FruitRemoved,
        function(
            owner,
            plantId,
            fruitId
        )

            if HolyFarmDetailsOwnerMatches(
                owner
            ) ~= true then

                return
            end

            local plantData =
                runtime.Cache.Plants[
                    tostring(plantId)
                ]

            if type(plantData) == "table"
            and type(plantData.Fruits) == "table" then

                plantData.Fruits[
                    tostring(fruitId)
                ] =
                    nil
            end

            HolyFarmDetailsScheduleRender()
        end
    )

    HolyFarmDetailsConnectPacket(
        garden.PlantGrowthUpdated,
        function(
            owner,
            plantId,
            currentAge,
            growthRate
        )

            if HolyFarmDetailsOwnerMatches(
                owner
            ) ~= true then

                return
            end

            local plantData =
                runtime.Cache.Plants[
                    tostring(plantId)
                ]

            if type(plantData) == "table" then

                plantData.Age =
                    tonumber(currentAge)
                    or plantData.Age
                    or 0

                plantData.GrowRate =
                    tonumber(growthRate)
                    or plantData.GrowRate
                    or 0

                plantData._HolyFarmDetailsClock =
                    os.clock()
            end
        end
    )

    HolyFarmDetailsConnectPacket(
        garden.FruitGrowthUpdated,
        function(
            owner,
            plantId,
            fruitId,
            currentAge,
            growthRate
        )

            if HolyFarmDetailsOwnerMatches(
                owner
            ) ~= true then

                return
            end

            local plantData =
                runtime.Cache.Plants[
                    tostring(plantId)
                ]

            local fruitData =
                type(plantData) == "table"
                and type(plantData.Fruits) == "table"
                and plantData.Fruits[
                    tostring(fruitId)
                ]
                or nil

            if type(fruitData) == "table" then

                fruitData.Age =
                    tonumber(currentAge)
                    or fruitData.Age
                    or 0

                fruitData.GrowRate =
                    tonumber(growthRate)
                    or fruitData.GrowRate
                    or 0

                fruitData._HolyFarmDetailsClock =
                    os.clock()
            end
        end
    )

    HolyFarmDetailsConnectPacket(
        garden.PlantMutationUpdated,
        function(
            owner,
            plantId,
            mutationData
        )

            if HolyFarmDetailsOwnerMatches(
                owner
            ) ~= true then

                return
            end

            local plantData =
                runtime.Cache.Plants[
                    tostring(plantId)
                ]

            if type(plantData) == "table" then

                plantData.Mutation =
                    mutationData
            end

            HolyFarmDetailsScheduleRender()
        end
    )

    HolyFarmDetailsConnectPacket(
        garden.FruitMutationUpdated,
        function(
            owner,
            plantId,
            fruitId,
            mutationData
        )

            if HolyFarmDetailsOwnerMatches(
                owner
            ) ~= true then

                return
            end

            local plantData =
                runtime.Cache.Plants[
                    tostring(plantId)
                ]

            local fruitData =
                type(plantData) == "table"
                and type(plantData.Fruits) == "table"
                and plantData.Fruits[
                    tostring(fruitId)
                ]
                or nil

            if type(fruitData) == "table" then

                fruitData.Mutation =
                    mutationData
            end

            HolyFarmDetailsScheduleRender()
        end
    )

    HolyFarmDetailsConnectPacket(
        garden.FruitOvertimeGrowthUpdated,
        function(
            owner,
            plantId,
            fruitId,
            overtimeGrowth
        )

            if HolyFarmDetailsOwnerMatches(
                owner
            ) ~= true then

                return
            end

            local plantData =
                runtime.Cache.Plants[
                    tostring(plantId)
                ]

            local fruitData =
                type(plantData) == "table"
                and type(plantData.Fruits) == "table"
                and plantData.Fruits[
                    tostring(fruitId)
                ]
                or nil

            if type(fruitData) == "table" then

                fruitData.OvertimeGrowth =
                    tonumber(overtimeGrowth)
                    or fruitData.OvertimeGrowth
            end

            HolyFarmDetailsScheduleRender()
        end
    )

    runtime.EventsConnected =
        snapshotConnected == true

    return runtime.EventsConnected
end

function HolyFarmDetailsRequestSnapshot()

    local runtime =
        HOLY_FARM_DETAILS_RUNTIME

    local garden =
        HolyFarmDetailsGetGardenNetworking()

    local packet =
        type(garden) == "table"
        and garden.RequestGardens
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        runtime.Status =
            "Unavailable"

        HolyFarmDetailsScheduleRender()

        return false
    end

    runtime.LastRequestAt =
        os.clock()

    runtime.Status =
        runtime.SnapshotReady == true
        and "Ready"
        or "Refreshing"

    local ok =
        pcall(function()

            packet:Fire()
        end)

    if ok ~= true then

        runtime.Status =
            "Refresh failed"
    end

    HolyFarmDetailsScheduleRender()

    return ok
end

function HolyFarmDetailsCreateLabel(
    parent,
    name,
    position,
    size,
    textSize,
    alignment
)

    local label =
        Instance.new(
            "TextLabel"
        )

    label.Name =
        name

    label.BackgroundTransparency =
        1

    label.BorderSizePixel =
        0

    label.Position =
        position

    label.Size =
        size

    label.Font =
        Enum.Font.GothamBold

    label.Text =
        ""

    label.TextColor3 =
        Color3.fromRGB(
            245,
            246,
            249
        )

    label.TextSize =
        textSize
        or 12

    label.TextScaled =
        false

    label.TextTransparency =
        0

    label.TextStrokeTransparency =
        1

    label.TextWrapped =
        false

    label.TextXAlignment =
        alignment
        or Enum.TextXAlignment.Left

    label.TextYAlignment =
        Enum.TextYAlignment.Center

    label.TextTruncate =
        Enum.TextTruncate.AtEnd

    label.Parent =
        parent

    return label
end

