function HolyFarmDetailsApplyCleanStyle(
    surface
)

    local ui =
        HOLY_FARM_DETAILS_UI

    if typeof(surface) ~= "Instance" then
        return false
    end

    surface.BackgroundColor3 =
        Color3.fromRGB(
            8,
            9,
            13
        )

    surface.BackgroundTransparency =
        0

    surface.BorderSizePixel =
        0

    surface.ClipsDescendants =
        true

    local metricCards = {
        ui.PlantsMetric
        and ui.PlantsMetric.Parent,

        ui.FruitsMetric
        and ui.FruitsMetric.Parent,

        ui.ReadyMetric
        and ui.ReadyMetric.Parent,
    }

    local flatObjects = {
        ui.FilterDescription
        and ui.FilterDescription.Parent,

        ui.Header1
        and ui.Header1.Parent,

        ui.BestLabel
        and ui.BestLabel.Parent,

        ui.FilterPanel,

        ui.FilterList,
    }

    for _,
        card in ipairs(metricCards) do

        if typeof(card) == "Instance" then

            card.BackgroundColor3 =
                Color3.fromRGB(
                    8,
                    9,
                    13
                )

            card.BackgroundTransparency =
                0

            card.BorderSizePixel =
                0

            card.Position =
                UDim2.new(
                    (
                        _ - 1
                    )
                    / 3,
                    0,
                    0,
                    0
                )

            card.Size =
                UDim2.new(
                    1 / 3,
                    0,
                    0,
                    52
                )

            table.insert(
                flatObjects,
                card
            )
        end
    end

    for _,
        row in ipairs(
            ui.Rows
            or {}
        ) do

        if type(row) == "table"
        and typeof(row.Frame) == "Instance" then

            table.insert(
                flatObjects,
                row.Frame
            )
        end
    end

    for _,
        object in ipairs(flatObjects) do

        if typeof(object) == "Instance" then

            for _,
                child in ipairs(
                    object:GetChildren()
                ) do

                if child:IsA("UIStroke")
                or child:IsA("UICorner") then

                    child:Destroy()
                end
            end
        end
    end

    for _,
        child in ipairs(
            surface:GetChildren()
        ) do

        if child.Name
            == "HolyFarmDetailsFlatDivider" then

            child:Destroy()
        end
    end

    local function createDivider(
        parent,
        position,
        size,
        color,
        zIndex
    )

        local divider =
            Instance.new(
                "Frame"
            )

        divider.Name =
            "HolyFarmDetailsFlatDivider"

        divider.BackgroundColor3 =
            color
            or Color3.fromRGB(
                36,
                39,
                48
            )

        divider.BackgroundTransparency =
            0

        divider.BorderSizePixel =
            0

        divider.Position =
            position

        divider.Size =
            size

        divider.ZIndex =
            zIndex
            or 1

        divider.Parent =
            parent

        return divider
    end

    createDivider(
        surface,
        UDim2.new(
            1 / 3,
            0,
            0,
            8
        ),
        UDim2.fromOffset(
            1,
            36
        )
    )

    createDivider(
        surface,
        UDim2.new(
            2 / 3,
            0,
            0,
            8
        ),
        UDim2.fromOffset(
            1,
            36
        )
    )

    createDivider(
        surface,
        UDim2.fromOffset(
            0,
            89
        ),
        UDim2.new(
            1,
            0,
            0,
            1
        )
    )

    createDivider(
        surface,
        UDim2.fromOffset(
            0,
            114
        ),
        UDim2.new(
            1,
            0,
            0,
            1
        )
    )

    createDivider(
        surface,
        UDim2.fromOffset(
            0,
            325
        ),
        UDim2.new(
            1,
            0,
            0,
            1
        )
    )

    for index,
        row in ipairs(
            ui.Rows
            or {}
        ) do

        if type(row) == "table"
        and typeof(row.Frame) == "Instance" then

            row.Frame.BackgroundColor3 =
                index % 2 == 0
                and Color3.fromRGB(
                    10,
                    11,
                    16
                )
                or Color3.fromRGB(
                    8,
                    9,
                    13
                )

            row.Frame.BackgroundTransparency =
                0

            row.Frame.BorderSizePixel =
                0

            createDivider(
                row.Frame,
                UDim2.new(
                    0,
                    5,
                    1,
                    -1
                ),
                UDim2.new(
                    1,
                    -10,
                    0,
                    1
                ),
                Color3.fromRGB(
                    26,
                    28,
                    35
                )
            )

            row.Name.Font =
                Enum.Font.GothamBold

            row.Name.TextSize =
                12

            row.Name.TextScaled =
                false

            row.Sub.Font =
                Enum.Font.GothamMedium

            row.Sub.TextSize =
                10

            row.Sub.TextScaled =
                false

            row.Value2.Font =
                Enum.Font.GothamBold

            row.Value2.TextSize =
                11

            row.Value2.TextScaled =
                false

            row.Value3.Font =
                Enum.Font.GothamBold

            row.Value3.TextSize =
                11

            row.Value3.TextScaled =
                false

            row.Value4.Font =
                Enum.Font.GothamBold

            row.Value4.TextSize =
                11

            row.Value4.TextScaled =
                false
        end
    end

    for _,
        metric in ipairs({
            ui.PlantsMetric,
            ui.FruitsMetric,
            ui.ReadyMetric,
        }) do

        if typeof(metric) == "Instance" then

            metric.Font =
                Enum.Font.GothamBold

            metric.TextSize =
                18

