function HolyFarmDetailsSetFilterDescription(
    groups
)

    local ui =
        HOLY_FARM_DETAILS_UI

    if typeof(ui.FilterDescription) ~= "Instance" then
        return
    end

    if HOLY_FARM_DETAILS_RUNTIME.SnapshotReady ~= true
    and #groups <= 0 then

        ui.FilterDescription.Text =
            "Waiting for garden data..."

        return
    end

    local plantCount =
        HolyFarmDetailsCountSet(
            HOLY_FARM_DETAILS_STATE.SelectedPlants
        )

    local mutationCount =
        HolyFarmDetailsCountSet(
            HOLY_FARM_DETAILS_STATE.SelectedMutations
        )

    local plantText =
        "All plants"

    if plantCount == 1 then

        for plantName in pairs(
            HOLY_FARM_DETAILS_STATE.SelectedPlants
        ) do

            plantText =
                plantName
        end

    elseif plantCount > 1 then

        plantText =
            tostring(plantCount)
            .. " plants"
    end

    local mutationText =
        "All mutations"

    if mutationCount == 1 then

        for mutation in pairs(
            HOLY_FARM_DETAILS_STATE.SelectedMutations
        ) do

            mutationText =
                mutation
        end

    elseif mutationCount > 1 then

        mutationText =
            tostring(mutationCount)
            .. " mutations"
    end

    ui.FilterDescription.Text =
        plantText
        .. " · "
        .. mutationText
end

function HolyFarmDetailsResetRows()

    for _,
        row in ipairs(
            HOLY_FARM_DETAILS_UI.Rows
            or {}
        ) do

        row.Frame.Visible =
            false

        row.Name.Visible =
            true

        row.Sub.Visible =
            false

        row.Value2.Visible =
            false

        row.Value3.Visible =
            false

        row.Value4.Visible =
            false
    end
end

function HolyFarmDetailsShowEmpty(text)

    local row =
        HOLY_FARM_DETAILS_UI.Rows
        and HOLY_FARM_DETAILS_UI.Rows[1]

    if type(row) ~= "table" then
        return
    end

    row.Frame.Visible =
        true

    row.Name.Position =
        UDim2.fromOffset(
            8,
            0
        )

    row.Name.Size =
        UDim2.new(
            1,
            -16,
            1,
            0
        )

    row.Name.Text =
        '<font color="#8E95A5">'
        .. HolyFarmDetailsEscape(
            text
        )
        .. "</font>"

    row.Name.TextXAlignment =
        Enum.TextXAlignment.Center
end

function HolyFarmDetailsSetPager(
    page,
    pageCount
)

    local ui =
        HOLY_FARM_DETAILS_UI

    HOLY_FARM_DETAILS_RUNTIME.CurrentPageCount =
        pageCount

    if typeof(ui.PageLabel) == "Instance" then

        ui.PageLabel.Text =
            tostring(page)
            .. " / "
            .. tostring(pageCount)
    end

    if typeof(ui.PreviousButton) == "Instance" then

        ui.PreviousButton.TextTransparency =
            page > 1
            and 0
            or 0.62
    end

    if typeof(ui.NextButton) == "Instance" then

        ui.NextButton.TextTransparency =
            page < pageCount
            and 0
            or 0.62
    end
end

function HolyFarmDetailsSetBest(fruit)

    local label =
        HOLY_FARM_DETAILS_UI.BestLabel

    if typeof(label) ~= "Instance" then
        return
    end

    if type(fruit) ~= "table"
    or tonumber(fruit.Weight) == nil then

        label.Text =
            '<font color="#969CAB">Best: —</font>'

        return
    end

    local plantName =
        HolyFarmDetailsCleanName(
            fruit.PlantName
            or "Unknown"
        )

    if plantName == "" then

        plantName =
            "Unknown"
    end

    local mutationParts =
        {}

    for _,
        mutation in ipairs(
            fruit.Mutations
            or {
                "Normal",
            }
        ) do

        table.insert(
            mutationParts,
            '<font color="'
            .. HolyFarmDetailsMutationHex(
                mutation
            )
            .. '">'
            .. HolyFarmDetailsEscape(
                mutation
            )
            .. "</font>"
        )
    end

    if #mutationParts <= 0 then

        mutationParts[1] =
            '<font color="#DCDDE6">Normal</font>'
    end

    label.Text =
        '<font color="#969CAB">Best: </font>'
        .. '<font color="#F5F6F9"><b>'
        .. HolyFarmDetailsEscape(
            plantName
        )
        .. "</b></font>"
        .. '<font color="#707684"> · </font>'
        .. table.concat(
            mutationParts,
            '<font color="#707684"> + </font>'
        )
        .. '<font color="#707684"> · </font>'
        .. '<font color="#42EB8B"><b>'
        .. HolyFarmDetailsEscape(
            HolyFarmDetailsFormatKg(
                fruit.Weight
            )
        )
        .. "</b></font>"
end

function HolyFarmDetailsRenderOverview(
    groups
)

    local state =
        HOLY_FARM_DETAILS_STATE

    local runtime =
        HOLY_FARM_DETAILS_RUNTIME

    local ui =
        HOLY_FARM_DETAILS_UI

    runtime.CurrentMode =
        "Overview"

    HolyFarmDetailsConfigureOverview()

    local totalPlants =
        0

    local totalFruits =
        0

    local totalReady =
        0

    local best =
        nil

    for _,
        group in ipairs(groups) do

        totalPlants +=
            tonumber(group.Plants)
            or 0

        totalFruits +=
            #group.Fruits

        totalReady +=
            tonumber(group.Ready)
            or 0

        for _,
            fruit in ipairs(
                group.Fruits
            ) do

            if tonumber(fruit.Weight) ~= nil
            and (
                best == nil
                or tonumber(fruit.Weight)
                    > tonumber(best.Weight)
            ) then

                best =
                    fruit
            end
        end
    end

    ui.PlantsMetric.Text =
        tostring(totalPlants)

    ui.FruitsMetric.Text =
        tostring(totalFruits)

    ui.ReadyMetric.Text =
        tostring(totalReady)

    local rowsPerPage =
        state.RowsPerPage

    local pageCount =
        math.max(
            1,
            math.ceil(
                #groups
                / rowsPerPage
            )
        )

    state.OverviewPage =
        math.clamp(
            math.floor(
                tonumber(state.OverviewPage)
                or 1
            ),
            1,
            pageCount
        )

    local firstIndex =
        (
            state.OverviewPage - 1
        )
        * rowsPerPage
        + 1

    for rowIndex = 1,
        rowsPerPage do

        local group =
            groups[
                firstIndex
                + rowIndex
                - 1
            ]

        local row =
            ui.Rows[rowIndex]

        if type(group) == "table"
        and type(row) == "table" then

            row.Frame.Visible =
                true

            row.Name.Visible =
                true

            row.Name.Position =
                UDim2.fromOffset(
                    7,
                    1
                )

            row.Name.Size =
                UDim2.new(
                    0.50,
                    -9,
                    0,
                    15
                )

            row.Name.TextXAlignment =
                Enum.TextXAlignment.Left

            row.Name.Text =
                '<font color="#F2F4F8"><b>'
                .. HolyFarmDetailsEscape(
                    group.Name
                )
                .. "</b></font>"

            row.Sub.Visible =
                true

            row.Sub.Position =
                UDim2.fromOffset(
                    7,
                    15
                )

            row.Sub.Size =
                UDim2.new(
                    0.50,
                    -9,
                    0,
                    14
                )

            row.Sub.Text =
                HolyFarmDetailsBuildMutationSummary(
                    group.Fruits
                )

            row.Value2.Visible =
                true

            row.Value2.Position =
                UDim2.fromScale(
                    0.50,
                    0
                )

            row.Value2.Size =
                UDim2.fromScale(
                    0.17,
                    1
                )

            row.Value2.TextXAlignment =
                Enum.TextXAlignment.Center

            row.Value2.Text =
                '<font color="#FF2F68"><b>'
                .. tostring(
                    group.Plants
                )
                .. "</b></font>"

            row.Value3.Visible =
                true

            row.Value3.Position =
                UDim2.fromScale(
                    0.67,
                    0
                )

            row.Value3.Size =
                UDim2.fromScale(
                    0.16,
                    1
                )

            row.Value3.TextXAlignment =
                Enum.TextXAlignment.Center

            row.Value3.Text =
                '<font color="#F2F4F8"><b>'
                .. tostring(
                    #group.Fruits
                )
                .. "</b></font>"

            row.Value4.Visible =
                true

            row.Value4.Position =
                UDim2.fromScale(
                    0.83,
                    0
                )

            row.Value4.Size =
                UDim2.new(
                    0.17,
                    -5,
                    1,
                    0
                )

            row.Value4.TextXAlignment =
                Enum.TextXAlignment.Right

            row.Value4.Text =
                '<font color="#42EB8B"><b>'
                .. tostring(
                    group.Ready
                )
                .. "</b></font>"
        end
    end

    if #groups <= 0 then

        HolyFarmDetailsShowEmpty(
            runtime.SnapshotReady == true
            and "No plants match these filters."
            or "Waiting for garden data..."
        )
    end

    HolyFarmDetailsSetBest(
        best
    )

    HolyFarmDetailsSetPager(
        state.OverviewPage,
        pageCount
    )
end

function HolyFarmDetailsRenderFruits(group)

    local state =
        HOLY_FARM_DETAILS_STATE

    local runtime =
        HOLY_FARM_DETAILS_RUNTIME

    local ui =
        HOLY_FARM_DETAILS_UI

    runtime.CurrentMode =
        "Fruits"

    HolyFarmDetailsConfigureFruits()

    local fruits =
        group.Fruits
        or {}

    ui.PlantsMetric.Text =
        tostring(
            group.Plants
            or 0
        )

    ui.FruitsMetric.Text =
        tostring(
            #fruits
        )

    ui.ReadyMetric.Text =
        tostring(
            group.Ready
            or 0
        )

    local rowsPerPage =
        state.RowsPerPage

    local pageCount =
        math.max(
            1,
            math.ceil(
                #fruits
                / rowsPerPage
            )
        )

    state.FruitPage =
        math.clamp(
            math.floor(
                tonumber(state.FruitPage)
                or 1
            ),
            1,
            pageCount
        )

    local firstIndex =
        (
            state.FruitPage - 1
        )
        * rowsPerPage
        + 1

    for rowIndex = 1,
        rowsPerPage do

        local fruit =
            fruits[
                firstIndex
                + rowIndex
                - 1
            ]

        local row =
            ui.Rows[rowIndex]

        if type(fruit) == "table"
        and type(row) == "table" then

            row.Frame.Visible =
                true

            row.Name.Visible =
                true

            row.Name.Position =
                UDim2.fromOffset(
                    7,
                    0
                )

            row.Name.Size =
                UDim2.new(
                    0.58,
                    -9,
                    1,
                    0
                )

            row.Name.TextXAlignment =
                Enum.TextXAlignment.Left

            row.Name.Text =
                HolyFarmDetailsBuildFruitRichText(
                    fruit
                )

            row.Sub.Visible =
                false

            row.Value2.Visible =
                true

            row.Value2.Position =
                UDim2.fromScale(
                    0.58,
                    0
                )

            row.Value2.Size =
                UDim2.new(
                    0.22,
                    -4,
                    1,
                    0
                )

            row.Value2.TextXAlignment =
                Enum.TextXAlignment.Right

            row.Value2.Text =
                '<font color="#F2F4F8"><b>'
                .. HolyFarmDetailsEscape(
                    HolyFarmDetailsFormatKg(
                        fruit.Weight
                    )
                )
                .. "</b></font>"

            row.Value3.Visible =
                true

            row.Value3.Position =
                UDim2.fromScale(
                    0.80,
                    0
                )

            row.Value3.Size =
                UDim2.new(
                    0.20,
                    -5,
                    1,
                    0
                )

            row.Value3.TextXAlignment =
                Enum.TextXAlignment.Right

            row.Value3.Text =
                fruit.Ready == true
                and '<font color="#42EB8B"><b>Ready</b></font>'
                or '<font color="#8E95A5">Growing</font>'

            row.Value4.Visible =
                false
        end
    end

    if #fruits <= 0 then

        HolyFarmDetailsShowEmpty(
            #group.AllFruits <= 0
            and "Harvest crop — no individual fruits."
            or "No fruits match these filters."
        )
    end

    HolyFarmDetailsSetBest(
        fruits[1]
    )

    HolyFarmDetailsSetPager(
        state.FruitPage,
        pageCount
    )
end

function HolyFarmDetailsGetFilterValues(
    groups
)

    local plants =
        {}

    local mutations =
        {}

    local mutationSeen =
        {}

    for _,
        group in ipairs(groups or {}) do

        table.insert(
            plants,
            group.Name
        )

        for _,
            fruit in ipairs(
                group.Fruits
                or {}
            ) do

            for _,
                mutation in ipairs(
                    fruit.Mutations
                    or {}
                ) do

                if mutationSeen[mutation] ~= true then

                    mutationSeen[mutation] =
                        true

                    table.insert(
                        mutations,
                        mutation
                    )
                end
            end
        end
    end

    table.sort(plants, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    table.sort(mutations, function(a, b)

        if a == "Normal" then
            return true
        end

        if b == "Normal" then
            return false
        end

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return plants,
        mutations
end

function HolyFarmDetailsBuildFilterList()

    local ui =
        HOLY_FARM_DETAILS_UI

    local list =
        ui.FilterList

    if typeof(list) ~= "Instance" then
        return false
    end

    for _,
        child in ipairs(
            list:GetChildren()
        ) do

        if child:IsA("TextButton") then

            child:Destroy()
        end
    end

    local groups =
        HolyFarmDetailsBuildGroups()

    local plants,
        mutations =
        HolyFarmDetailsGetFilterValues(
            groups
        )

    local mode =
        HOLY_FARM_DETAILS_RUNTIME.FilterMode

    local values =
        mode == "Mutations"
        and mutations
        or plants

    ui.PlantsTab.BackgroundColor3 =
        Color3.fromRGB(
            21,
            15,
            24
        )

    ui.PlantsTab.BackgroundTransparency =
        mode == "Plants"
        and 0
        or 1

    ui.PlantsTab.TextColor3 =
        mode == "Plants"
        and Color3.fromRGB(
            255,
            47,
            104
        )
        or Color3.fromRGB(
            145,
            151,
            164
        )

    ui.MutationsTab.BackgroundColor3 =
        Color3.fromRGB(
            21,
            15,
            24
        )

    ui.MutationsTab.BackgroundTransparency =
        mode == "Mutations"
        and 0
        or 1

    ui.MutationsTab.TextColor3 =
        mode == "Mutations"
        and Color3.fromRGB(
            255,
            47,
            104
        )
        or Color3.fromRGB(
            145,
            151,
            164
        )

    ui.FilterEmpty.Visible =
        #values <= 0

    ui.FilterEmpty.Text =
        HOLY_FARM_DETAILS_RUNTIME.SnapshotReady == true
        and "No filters available."
        or "Waiting for garden data..."

    local selectedSet =
        mode == "Mutations"
        and HOLY_FARM_DETAILS_STATE.SelectedMutations
        or HOLY_FARM_DETAILS_STATE.SelectedPlants

    for index,
        value in ipairs(values) do

        local selected =
            selectedSet[value] == true

        local button =
            HolyFarmDetailsCreateButton(
                list,
                (
                    selected
                    and "✓  "
                    or ""
                )
                .. value,
                UDim2.new(),
                UDim2.new(
                    1,
                    -6,
                    0,
                    27
                )
            )

        button.LayoutOrder =
            index

        button.ZIndex =
            13

        button.TextXAlignment =
            Enum.TextXAlignment.Left

        button.TextSize =
            10

        button.BackgroundColor3 =
            Color3.fromRGB(
                28,
                15,
                25
            )

        button.BackgroundTransparency =
            selected
            and 0
            or 1

        if mode == "Mutations" then

            local hex =
                HolyFarmDetailsMutationHex(
                    value
                )

            local red,
                green,
                blue =
                hex:match(
                    "#(%x%x)(%x%x)(%x%x)"
                )

            if red then

                button.TextColor3 =
                    Color3.fromRGB(
                        tonumber(red, 16),
                        tonumber(green, 16),
                        tonumber(blue, 16)
                    )
            end

        else

            button.TextColor3 =
                selected
                and Color3.fromRGB(
                    255,
                    47,
                    104
                )
                or Color3.fromRGB(
                    242,
                    244,
                    248
                )
        end

        button.MouseButton1Click:Connect(
            function()

                if selectedSet[value] == true then

                    selectedSet[value] =
                        nil

                else

                    selectedSet[value] =
                        true
                end

                HOLY_FARM_DETAILS_STATE.OverviewPage =
                    1

                HOLY_FARM_DETAILS_STATE.FruitPage =
                    1

                HolyFarmDetailsRender()

                HolyFarmDetailsBuildFilterList()
            end
        )
    end

    list.CanvasSize =
        UDim2.fromOffset(
            0,
            math.max(
                0,
                #values * 31
            )
        )

    return true
end

function HolyFarmDetailsRender()

    local ui =
        HOLY_FARM_DETAILS_UI

    if typeof(ui.Surface) ~= "Instance" then
        return false
    end

    HOLY_FARM_DETAILS_RUNTIME.LastRenderAt =
        os.clock()

    HOLY_FARM_DETAILS_RUNTIME.RefreshQueued =
        false

    HolyFarmDetailsResetRows()

    local allGroups =
        HolyFarmDetailsBuildGroups()

    local groups =
        HolyFarmDetailsGetVisibleGroups(
            allGroups
        )

    HolyFarmDetailsSetFilterDescription(
        groups
    )

    local selectedPlantCount =
        HolyFarmDetailsCountSet(
            HOLY_FARM_DETAILS_STATE.SelectedPlants
        )

    if selectedPlantCount == 1
    and #groups == 1 then

        HolyFarmDetailsRenderFruits(
            groups[1]
        )

    else

        HolyFarmDetailsRenderOverview(
            groups
        )
    end

    if typeof(ui.FilterPanel) == "Instance"
    and ui.FilterPanel.Visible == true then

        local signatureParts =
            {}

        for _,
            group in ipairs(allGroups) do

            table.insert(
                signatureParts,
                group.Name
                .. ":"
                .. tostring(
                    #group.Fruits
                )
            )
        end

        local signature =
            table.concat(
                signatureParts,
                "|"
            )

        if signature
            ~= HOLY_FARM_DETAILS_RUNTIME.LastFilterSignature then

            HOLY_FARM_DETAILS_RUNTIME.LastFilterSignature =
                signature

            HolyFarmDetailsBuildFilterList()
        end
    end

    return true
end

