    local ok,
        service =
        pcall(function()

            return game:GetService(
                "VirtualInputManager"
            )
        end)

    if ok == true then
        return service
    end

    return nil
end

function HolyAntiAfkCaptureOldOverride()

    HOLY_ANTI_AFK_STATE =
        type(HOLY_ANTI_AFK_STATE) == "table"
        and HOLY_ANTI_AFK_STATE
        or {}

    if HOLY_ANTI_AFK_STATE.OldOverrideCaptured == true then
        return
    end

    local oldValue =
        nil

    pcall(function()

        oldValue =
            LocalPlayer:GetAttribute(
                "AntiAfkIdleOverride"
            )
    end)

    HOLY_ANTI_AFK_STATE.OldOverride =
        oldValue

    HOLY_ANTI_AFK_STATE.OldOverrideCaptured =
        true
end

function HolyAntiAfkSetOverride()

    if not LocalPlayer then
        return false
    end

    local ok =
        pcall(function()

            LocalPlayer:SetAttribute(
                "AntiAfkIdleOverride",
                999999999
            )
        end)

    return ok == true
end

function HolyAntiAfkRestoreOverride()

    if not LocalPlayer then
        return false
    end

    if type(HOLY_ANTI_AFK_STATE) ~= "table"
    or HOLY_ANTI_AFK_STATE.OldOverrideCaptured ~= true then

        return false
    end

    local oldValue =
        HOLY_ANTI_AFK_STATE.OldOverride

    local ok =
        pcall(function()

            LocalPlayer:SetAttribute(
                "AntiAfkIdleOverride",
                oldValue
            )
        end)

    HOLY_ANTI_AFK_STATE.OldOverrideCaptured =
        false

    HOLY_ANTI_AFK_STATE.OldOverride =
        nil

    return ok == true
end

function HolyAntiAfkPulse()

    HolyAntiAfkSetOverride()

    local inputManager =
        HolyAntiAfkGetInputManager()

    if not inputManager then
        return false
    end

    pcall(function()

        inputManager:SendKeyEvent(
            true,
            Enum.KeyCode.RightControl,
            false,
            game
        )
    end)

    task.wait(
        0.055
    )

    pcall(function()

        inputManager:SendKeyEvent(
            false,
            Enum.KeyCode.RightControl,
            false,
            game
        )
    end)

    return true
end

function HolyAntiAfkStop(reason)

    HOLY_ANTI_AFK_STATE =
        type(HOLY_ANTI_AFK_STATE) == "table"
        and HOLY_ANTI_AFK_STATE
        or {}

    HOLY_ANTI_AFK_STATE.Token =
        nil

    HOLY_ANTI_AFK_STATE.Running =
        false

    HolyAntiAfkRestoreOverride()

    HolyAntiAfkLog(
        "stopped",
        tostring(reason or "manual")
    )
end

function HolyAntiAfkStart(reason)

    HOLY_ANTI_AFK_STATE =
        type(HOLY_ANTI_AFK_STATE) == "table"
        and HOLY_ANTI_AFK_STATE
        or {}

    if HOLY_ANTI_AFK_STATE.Running == true then
        return false
    end

    HOLY_ANTI_AFK_STATE.Running =
        true

    HOLY_ANTI_AFK_STATE.LogsPrinted =
        0

    local token =
        {}

    HOLY_ANTI_AFK_STATE.Token =
        token

    HolyAntiAfkCaptureOldOverride()

    HolyAntiAfkSetOverride()

    HolyAntiAfkLog(
        "started",
        tostring(reason or "startup")
    )

    task.spawn(function()

        local nextPulseAt =
            os.clock() + 15

        while HOLY_ANTI_AFK_STATE.Token == token do

            HolyAntiAfkSetOverride()

            if os.clock() >= nextPulseAt then

                HolyAntiAfkPulse()

                nextPulseAt =
                    os.clock() + 75
            end

            task.wait(
                1
            )
        end

        if HOLY_ANTI_AFK_STATE.Token == token then

            HOLY_ANTI_AFK_STATE.Running =
                false
        end
    end)

    return true
end

HOLY_ANTI_AFK_STATE.Stop =
    HolyAntiAfkStop

--==================================================
-- ANTI KNOCKBACK
--==================================================

function HolyAntiKnockbackDisconnectList(list)

    for _, connection in ipairs(
        list
        or {}
    ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    if type(list) == "table" then

        table.clear(
            list
        )
    end
end

function HolyAntiKnockbackLoadModule()

    local runtime =
        HOLY_ANTI_KNOCKBACK_STATE

    if type(runtime.RagdollModule) == "table"
    and type(runtime.RagdollModule.Unragdoll) == "function" then

        return runtime.RagdollModule
    end

    local clientModules =
        ReplicatedStorage:FindFirstChild(
            "ClientModules"
        )

    local moduleObject =
        clientModules
        and clientModules:FindFirstChild(
            "RagdollModule"
        )
        or nil

    if typeof(moduleObject) ~= "Instance"
    or moduleObject:IsA("ModuleScript") ~= true then

        return nil
    end

    local ok,
        module =
        pcall(
            require,
            moduleObject
        )

    if ok ~= true
    or type(module) ~= "table"
    or type(module.Unragdoll) ~= "function" then

        return nil
    end

    runtime.RagdollModule =
        module

    return module
end

function HolyAntiKnockbackGetCharacter()

    local runtime =
        HOLY_ANTI_KNOCKBACK_STATE

    local character =
        runtime.Character

    local humanoid =
        runtime.Humanoid

    local root =
        runtime.Root

    if typeof(character) ~= "Instance"
    or character.Parent == nil
    or LocalPlayer.Character ~= character then

        return nil,
            nil,
            nil
    end

    if typeof(humanoid) ~= "Instance"
    or humanoid.Parent == nil then

        return character,
            nil,
            nil
    end

    if typeof(root) ~= "Instance"
    or root.Parent == nil
    or root:IsA("BasePart") ~= true then

        return character,
            humanoid,
            nil
    end

    return character,
        humanoid,
        root
end

function HolyAntiKnockbackIsForce(instance)

    if typeof(instance) ~= "Instance" then
        return false
    end

    return instance:IsA("BodyVelocity")
        or instance:IsA("BodyAngularVelocity")
end

function HolyAntiKnockbackIsSpringForce(
    instance,
    character
)

    if typeof(instance) ~= "Instance"
    or instance:IsA("BodyVelocity") ~= true then

        return false
    end

    if typeof(character) ~= "Instance"
    or instance:IsDescendantOf(
        character
    ) ~= true then

        return false
    end

    local velocity =
        Vector3.zero

    local maximumForce =
        Vector3.zero

    pcall(function()

        velocity =
            instance.Velocity
    end)

    pcall(function()

        maximumForce =
            instance.MaxForce
    end)

    return math.abs(
        velocity.Y
    ) >= 1000
        or math.abs(
            maximumForce.Y
        ) >= 1000
end

function HolyAntiKnockbackRemoveForces(root)

    if typeof(root) ~= "Instance" then
        return 0
    end

    local searchRoot =
        root

    local character =
        HOLY_ANTI_KNOCKBACK_STATE.Character

    if typeof(character) == "Instance"
    and (
        root == character
        or root:IsDescendantOf(
            character
        )
    ) then

        searchRoot =
            character
    end

    local removed =
        0

    for _, descendant in ipairs(
        searchRoot:GetDescendants()
    ) do

        if HolyAntiKnockbackIsForce(
            descendant
        ) == true then

            local destroyed =
                pcall(function()

                    descendant:Destroy()
                end)

            if destroyed == true then

                removed +=
                    1
            end
        end
    end

    return removed
end

function HolyAntiKnockbackNeckConnected(character)

    if typeof(character) ~= "Instance" then
        return false
    end

    for _, descendant in ipairs(
        character:GetDescendants()
    ) do

        if descendant:IsA("Motor6D")
        and descendant.Name == "Neck"
        and descendant.Enabled == true
        and descendant.Part0 ~= nil
        and descendant.Part1 ~= nil then

            return true
        end
    end

    return false
end

function HolyAntiKnockbackRestoreRequiresNeck()

    local runtime =
        HOLY_ANTI_KNOCKBACK_STATE

    local character =
        runtime.Character

    local humanoid =
        runtime.Humanoid

    local originalValue =
        runtime.OriginalRequiresNeck

    if typeof(character) ~= "Instance"
    or typeof(humanoid) ~= "Instance"
    or type(originalValue) ~= "boolean" then

        return false
    end

    if originalValue == false then

        pcall(function()

            humanoid.RequiresNeck =
                false
        end)

        return true
    end

    local currentlyRagdolled =
        character:GetAttribute(
            "Ragdolled"
        ) == true
        or humanoid.PlatformStand == true

    if currentlyRagdolled == true
    or HolyAntiKnockbackNeckConnected(
        character
    ) ~= true then

        return false
    end

    local ok =
        pcall(function()

            humanoid.RequiresNeck =
                originalValue
        end)

    return ok == true
end

function HolyAntiKnockbackStabilize(
    humanoid,
    root,
    clearVelocity
)

    if typeof(humanoid) ~= "Instance"
    or typeof(root) ~= "Instance" then

        return false
    end

    pcall(function()

        humanoid.PlatformStand =
            false

        humanoid.Sit =
            false

        humanoid.AutoRotate =
            true

        root.CanCollide =
            false
    end)

    if clearVelocity == true then

        pcall(function()

            root.AssemblyLinearVelocity =
                Vector3.zero

            root.AssemblyAngularVelocity =
                Vector3.zero
        end)
    end

    if humanoid.Health > 0 then

        pcall(function()

            humanoid:ChangeState(
                Enum.HumanoidStateType.GettingUp
            )
        end)
    end

    return true
end

function HolyAntiKnockbackLateCleanup(
    expectedCharacter,
    clearVelocity
)

    local runtime =
        HOLY_ANTI_KNOCKBACK_STATE

    if runtime.Running ~= true
    or runtime.Character ~= expectedCharacter then

        return false
    end

    local character,
        humanoid,
        root =
        HolyAntiKnockbackGetCharacter()

    if character ~= expectedCharacter
    or not humanoid
    or not root then

        return false
    end

    HolyAntiKnockbackRemoveForces(
        character
    )

    if clearVelocity == true then

        HolyAntiKnockbackStabilize(
            humanoid,
            root,
            true
        )

    else

        pcall(function()

            if humanoid.Health > 0
            and humanoid.PlatformStand == true then

                humanoid.PlatformStand =
                    false
            end

            if humanoid.Health > 0
            and humanoid.AutoRotate ~= true then

                humanoid.AutoRotate =
                    true
            end
        end)
    end

    return true
end

function HolyAntiKnockbackRecover(reason)

    local runtime =
        HOLY_ANTI_KNOCKBACK_STATE

    local springRecovery =
        runtime.SpringRecoveryQueued == true

    runtime.RecoveryQueued =
        false

    runtime.SpringRecoveryQueued =
        false

    if runtime.Running ~= true then
        return false
    end

    local character,
        humanoid,
        root =
        HolyAntiKnockbackGetCharacter()

    if not character
    or not humanoid
    or not root
    or humanoid.Health <= 0 then

        return false
    end

    local currentlyRagdolled =
        character:GetAttribute(
            "Ragdolled"
        ) == true

    if springRecovery ~= true
    or currentlyRagdolled == true then

        local ragdollModule =
            HolyAntiKnockbackLoadModule()

        if type(ragdollModule) == "table"
        and type(ragdollModule.Unragdoll) == "function" then

            pcall(function()

                ragdollModule:Unragdoll(
                    character
                )
            end)
        end
    end

    HolyAntiKnockbackRemoveForces(
        character
    )

    HolyAntiKnockbackStabilize(
        humanoid,
        root,
        true
    )

    local cleanupDelays =
        springRecovery == true
        and {
            0.03,
            0.08,
            0.16,
        }
        or {
            0.05,
            0.15,
            0.30,
        }

    for _, delayTime in ipairs(
        cleanupDelays
    ) do

        task.delay(
            delayTime,
            function()

                HolyAntiKnockbackLateCleanup(
                    character,
                    springRecovery
                )
            end
        )
    end

    return true
end

function HolyAntiKnockbackQueueRecovery(
    reason,
    springRecovery
)

    local runtime =
        HOLY_ANTI_KNOCKBACK_STATE

    if runtime.Running ~= true then
        return
    end

    if springRecovery == true then

        runtime.SpringRecoveryQueued =
            true

    else

        runtime.LastRagdollAt =
            os.clock()
    end

    if runtime.RecoveryQueued == true then
        return
    end

    runtime.RecoveryQueued =
        true

    task.defer(function()

        HolyAntiKnockbackRecover(
            reason
        )
    end)
end

function HolyAntiKnockbackBindCharacter(character)

    local runtime =
        HOLY_ANTI_KNOCKBACK_STATE

    HolyAntiKnockbackDisconnectList(
        runtime.CharacterConnections
    )

    runtime.Character =
        character

    runtime.Humanoid =
        nil

    runtime.Root =
        nil

    runtime.OriginalRequiresNeck =
        nil

    runtime.RecoveryQueued =
        false

    runtime.SpringRecoveryQueued =
        false

    runtime.LastRagdollAt =
        0

    if typeof(character) ~= "Instance" then
        return false
    end

    local humanoid =
        character:FindFirstChildOfClass(
            "Humanoid"
        )
        or character:WaitForChild(
            "Humanoid",
            8
        )

    local root =
        character:FindFirstChild(
            "HumanoidRootPart"
        )
        or character:WaitForChild(
            "HumanoidRootPart",
            8
        )

    if typeof(humanoid) ~= "Instance"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false
    end

    runtime.Humanoid =
        humanoid

    runtime.Root =
        root

    runtime.OriginalRequiresNeck =
        humanoid.RequiresNeck

    pcall(function()

        humanoid.RequiresNeck =
            false
    end)

    table.insert(
        runtime.CharacterConnections,
        character:GetAttributeChangedSignal(
            "Ragdolled"
        ):Connect(function()

            if character:GetAttribute(
                "Ragdolled"
            ) == true then

                HolyAntiKnockbackQueueRecovery(
                    "ragdoll"
                )
            end
        end)
    )

    table.insert(
        runtime.CharacterConnections,
        character.DescendantAdded:Connect(
            function(descendant)

                if runtime.Running ~= true
                or HolyAntiKnockbackIsForce(
                    descendant
                ) ~= true then

                    return
                end

                if HolyAntiKnockbackIsSpringForce(
                    descendant,
                    character
                ) == true then

                    pcall(function()

                        descendant:Destroy()
                    end)

                    HolyAntiKnockbackQueueRecovery(
                        "spring force",
                        true
                    )

                    return
                end

                local currentlyRagdolled =
                    character:GetAttribute(
                        "Ragdolled"
                    ) == true

                local recentlyRagdolled =
                    os.clock()
                    - (
                        tonumber(
                            runtime.LastRagdollAt
                        )
                        or 0
                    )
                    <= 0.75

                if currentlyRagdolled ~= true
                and recentlyRagdolled ~= true then

                    return
                end

                task.defer(function()

                    if runtime.Running ~= true
                    or descendant.Parent == nil then

                        return
                    end

                    pcall(function()

                        descendant:Destroy()
                    end)
                end)
            end
        )
    )

    if character:GetAttribute(
        "Ragdolled"
    ) == true then

        HolyAntiKnockbackQueueRecovery(
            "character bind"
        )
    end

    return true
end

function HolyAntiKnockbackStop(reason)

    local runtime =
        HOLY_ANTI_KNOCKBACK_STATE

    if type(runtime) ~= "table" then
        return false
    end

    runtime.Running =
        false

    runtime.RecoveryQueued =
        false

    runtime.SpringRecoveryQueued =
        false

    local character,
        humanoid,
        root =
        HolyAntiKnockbackGetCharacter()

    local ragdollModule =
        runtime.RagdollModule

    if character
    and humanoid
    and root
    and humanoid.Health > 0 then

        if type(ragdollModule) == "table"
        and type(ragdollModule.Unragdoll) == "function" then

            pcall(function()

                ragdollModule:Unragdoll(
                    character
                )
            end)
        end

        HolyAntiKnockbackRemoveForces(
            root
        )

        HolyAntiKnockbackStabilize(
            humanoid,
            root,
            false
        )
    end

    HolyAntiKnockbackRestoreRequiresNeck()

    HolyAntiKnockbackDisconnectList(
        runtime.CharacterConnections
    )

    HolyAntiKnockbackDisconnectList(
        runtime.Connections
    )

    runtime.Character =
        nil

    runtime.Humanoid =
        nil

    runtime.Root =
        nil

    runtime.OriginalRequiresNeck =
        nil

    return true
end

function HolyAntiKnockbackStart(reason)

    local runtime =
        HOLY_ANTI_KNOCKBACK_STATE

    if runtime.Running == true then
        return false
    end

    if HolyAntiKnockbackLoadModule() == nil then
        return false
    end

    runtime.Running =
        true

    runtime.Connections =
        {}

    runtime.CharacterConnections =
        {}

    table.insert(
        runtime.Connections,
        LocalPlayer.CharacterAdded:Connect(
            function(character)

                task.defer(function()

                    if runtime.Running == true then

                        HolyAntiKnockbackBindCharacter(
                            character
                        )
                    end
                end)
            end
        )
    )

    HolyAntiKnockbackBindCharacter(
        LocalPlayer.Character
        or LocalPlayer.CharacterAdded:Wait()
    )

    return true
end

HOLY_ANTI_KNOCKBACK_STATE.Stop =
    HolyAntiKnockbackStop

--==================================================
-- ANTI WHEELBARROW
--==================================================

function HolyAntiWheelbarrowDisconnectList(list)

    for _, connection in ipairs(
        list
        or {}
    ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    if type(list) == "table" then

        table.clear(
            list
        )
    end
end

function HolyAntiWheelbarrowGetCharacter()

    local runtime =
        HOLY_ANTI_WHEELBARROW_STATE

    local character =
        runtime.Character

    local humanoid =
        runtime.Humanoid

    local root =
        runtime.Root

    if typeof(character) ~= "Instance"
    or character.Parent == nil
    or LocalPlayer.Character ~= character then

        return nil,
            nil,
            nil
    end

    if typeof(humanoid) ~= "Instance"
    or humanoid.Parent ~= character then

        return character,
            nil,
            nil
    end

    if typeof(root) ~= "Instance"
    or root.Parent ~= character
    or root:IsA("BasePart") ~= true then

        return character,
            humanoid,
            nil
    end

    return character,
        humanoid,
        root
end

function HolyAntiWheelbarrowIsCharacterPart(instance)

    local character =
        HOLY_ANTI_WHEELBARROW_STATE.Character

    return typeof(character) == "Instance"
        and typeof(instance) == "Instance"
        and instance:IsDescendantOf(
            character
        )
end

function HolyAntiWheelbarrowFindAncestor(instance)

    local current =
        instance

    for _ =
        1,
        12
    do

        if typeof(current) ~= "Instance" then
            break
        end

        local name =
            string.lower(
                tostring(current.Name)
            )

        local wheelbarrowAttribute =
            nil

        pcall(function()

            wheelbarrowAttribute =
                current:GetAttribute(
                    "Wheelbarrow"
                )
        end)

        if wheelbarrowAttribute ~= nil then

            return current
        end

        if name:find(
            "wheelbarrow",
            1,
            true
        ) then

            return current
        end

        current =
            current.Parent
    end

    return nil
end

function HolyAntiWheelbarrowIsSeat(instance)

    if typeof(instance) ~= "Instance"
    or instance:IsA("BasePart") ~= true then

        return false,
            nil
    end

    local wheelbarrow =
        HolyAntiWheelbarrowFindAncestor(
            instance
        )

    return wheelbarrow ~= nil,
        wheelbarrow
end

function HolyAntiWheelbarrowWeldConnectsCharacter(
    weld,
    expectedSeat
)

    if typeof(weld) ~= "Instance"
    or weld:IsA("Weld") ~= true then

        return false
    end

    local part0 =
        weld.Part0

    local part1 =
        weld.Part1

    if typeof(part0) ~= "Instance"
    or typeof(part1) ~= "Instance" then

        return false
    end

    local part0IsCharacter =
        HolyAntiWheelbarrowIsCharacterPart(
            part0
        )

    local part1IsCharacter =
        HolyAntiWheelbarrowIsCharacterPart(
            part1
        )

    if part0IsCharacter == part1IsCharacter then

        return false
    end

    local outsidePart =
        part0IsCharacter
        and part1
        or part0

    if expectedSeat ~= nil
    and outsidePart ~= expectedSeat then

        return false
    end

    return HolyAntiWheelbarrowIsSeat(
        outsidePart
    ) == true
end

function HolyAntiWheelbarrowHasSeatWeld(seat)

    if typeof(seat) ~= "Instance"
    or seat.Parent == nil then

        return false
    end

    for _, descendant in ipairs(
        seat:GetDescendants()
    ) do

        if descendant:IsA("Weld")
        and string.lower(
            descendant.Name
        ) == "seatweld"
        and HolyAntiWheelbarrowWeldConnectsCharacter(
            descendant,
            seat
        ) == true then

            return true
        end
    end

    return false
end

function HolyAntiWheelbarrowRemoveSeatWelds(seat)

    if typeof(seat) ~= "Instance"
    or seat.Parent == nil then

        return 0
    end

    local removed =
        0

    for _, descendant in ipairs(
        seat:GetDescendants()
    ) do

        if descendant:IsA("Weld")
        and string.lower(
            descendant.Name
        ) == "seatweld"
        and HolyAntiWheelbarrowWeldConnectsCharacter(
            descendant,
            seat
        ) == true then

            local destroyed =
                pcall(function()

                    descendant:Destroy()
                end)

            if destroyed == true then

                removed +=
                    1
            end
        end
    end

    return removed
end

function HolyAntiWheelbarrowDisableSeat(seat)

    local runtime =
        HOLY_ANTI_WHEELBARROW_STATE

    if typeof(seat) ~= "Instance"
    or seat:IsA("Seat") ~= true
    or runtime.DisabledSeats[seat] ~= nil then

        return false
    end

    local originalDisabled =
        seat.Disabled

    runtime.DisabledSeats[seat] =
        originalDisabled

    local disabled =
        pcall(function()

            seat.Disabled =
                true
        end)

    if disabled ~= true then

        runtime.DisabledSeats[seat] =
            nil

        return false
    end

    return true
end

function HolyAntiWheelbarrowRestoreSeats()

    local runtime =
        HOLY_ANTI_WHEELBARROW_STATE

    for seat,
        originalDisabled in pairs(
        runtime.DisabledSeats
        or {}
    ) do

        if typeof(seat) == "Instance"
        and seat.Parent ~= nil then

            pcall(function()

                seat.Disabled =
                    originalDisabled
            end)
        end
    end

    runtime.DisabledSeats =
        {}

    return true
end

function HolyAntiWheelbarrowForceUnseat()

    local character,
        humanoid,
        root =
        HolyAntiWheelbarrowGetCharacter()

    if not character
    or not humanoid
    or not root
    or humanoid.Health <= 0 then

        return false
    end

    pcall(function()

        humanoid.Sit =
            false
    end)

    pcall(function()

        humanoid:ChangeState(
            Enum.HumanoidStateType.GettingUp
        )
    end)

    pcall(function()

        root.AssemblyLinearVelocity =
            Vector3.zero

        root.AssemblyAngularVelocity =
            Vector3.zero
    end)

    return true
end

function HolyAntiWheelbarrowCaptureSafePosition(
    ignoreRecovery
)

    local runtime =
        HOLY_ANTI_WHEELBARROW_STATE

    if runtime.Running ~= true then
        return false
    end

    if ignoreRecovery ~= true
    and os.clock() <= (
        tonumber(runtime.RecoveringUntil)
        or 0
    ) then

        return false
    end

    local character,
        humanoid,
        root =
        HolyAntiWheelbarrowGetCharacter()

    if not character
    or not humanoid
    or not root
    or humanoid.Health <= 0
    or humanoid.Sit == true
    or humanoid.FloorMaterial
        == Enum.Material.Air then

        return false
    end

    local state =
        humanoid:GetState()

    if state == Enum.HumanoidStateType.Seated
    or state == Enum.HumanoidStateType.Dead
    or state == Enum.HumanoidStateType.Ragdoll
    or state == Enum.HumanoidStateType.FallingDown
    or state == Enum.HumanoidStateType.PlatformStanding then

        return false
    end

    local activeSeat =
        runtime.ActiveSeat

    if typeof(activeSeat) == "Instance"
    and HolyAntiWheelbarrowHasSeatWeld(
        activeSeat
    ) == true then

        return false
    end

    if root.AssemblyLinearVelocity.Magnitude > 24
    or root.AssemblyAngularVelocity.Magnitude > 12 then

        return false
    end

    runtime.SafeCFrame =
        root.CFrame

    runtime.SafeCapturedAt =
        os.clock()

    return true
end

function HolyAntiWheelbarrowResumeSampling(
    expectedEpisode
)

    task.spawn(function()

        local runtime =
            HOLY_ANTI_WHEELBARROW_STATE

        for _ =
            1,
            12
        do

            if runtime.Running ~= true
            or runtime.CurrentEpisode
                ~= expectedEpisode then

                return
            end

            local _,
                humanoid =
                HolyAntiWheelbarrowGetCharacter()

            if humanoid then

                pcall(function()

                    humanoid.Sit =
                        false
                end)
            end

            if HolyAntiWheelbarrowCaptureSafePosition(
                true
            ) == true then

                runtime.RecoveringUntil =
                    0

                return
            end

            task.wait(
                0.1
            )
        end
    end)
end

function HolyAntiWheelbarrowRecoveryPass(
    expectedEpisode,
    passIndex,
    seat,
    recoveryCFrame
)

    local runtime =
        HOLY_ANTI_WHEELBARROW_STATE

    if runtime.Running ~= true
    or runtime.CurrentEpisode
        ~= expectedEpisode then

        return false
    end

    local character,
        humanoid,
        root =
        HolyAntiWheelbarrowGetCharacter()

    if not character
    or not humanoid
    or not root
    or humanoid.Health <= 0 then

        return false
    end

    local stillAttached =
        humanoid.Sit == true
        or humanoid.SeatPart == seat
        or HolyAntiWheelbarrowHasSeatWeld(
            seat
        ) == true

    HolyAntiWheelbarrowRemoveSeatWelds(
        seat
    )

    HolyAntiWheelbarrowForceUnseat()

    local shouldRestore =
        typeof(recoveryCFrame) == "CFrame"
        and (
            passIndex == 1
            or (
                passIndex == 3
                and stillAttached == true
            )
        )

    if shouldRestore == true then

        pcall(function()

            root.CFrame =
                recoveryCFrame
        end)
    end

    if passIndex == 3 then

        task.delay(
            0.2,
            function()

                HolyAntiWheelbarrowResumeSampling(
                    expectedEpisode
                )
            end
        )
    end

    return true
end

function HolyAntiWheelbarrowTrigger(
    reason,
    seat
)

    local runtime =
        HOLY_ANTI_WHEELBARROW_STATE

    if runtime.Running ~= true then
        return false
    end

    local character,
        humanoid,
        root =
        HolyAntiWheelbarrowGetCharacter()

    if not character
    or not humanoid
    or not root
    or humanoid.Health <= 0 then

        return false
    end

    seat =
        seat
        or humanoid.SeatPart

    local verified =
        HolyAntiWheelbarrowIsSeat(
            seat
        )

    if verified ~= true then
        return false
    end

    local now =
        os.clock()

    local duplicate =
        seat == runtime.ActiveSeat
        and now <= (
            tonumber(
                runtime.CurrentEpisodeUntil
            )
            or 0
        )

    if duplicate == true then

        HolyAntiWheelbarrowRemoveSeatWelds(
            seat
        )

        pcall(function()

            humanoid.Sit =
                false
        end)

        return true
    end

    runtime.CurrentEpisode +=
        1

    local expectedEpisode =
        runtime.CurrentEpisode

    runtime.ActiveSeat =
        seat

    runtime.CurrentEpisodeUntil =
        now + 1

    runtime.RecoveringUntil =
        now + 1.25

    local recoveryCFrame =
        runtime.SafeCFrame

    if typeof(recoveryCFrame) ~= "CFrame" then

        recoveryCFrame =
            root.CFrame
    end

    HolyAntiWheelbarrowDisableSeat(
        seat
    )

    local recoveryDelays = {
        0,
        0.05,
        0.14,
    }

    for passIndex,
        delayTime in ipairs(
            recoveryDelays
        )
    do

        local capturedPassIndex =
            passIndex

        task.delay(
            delayTime,
            function()

                HolyAntiWheelbarrowRecoveryPass(
                    expectedEpisode,
                    capturedPassIndex,
                    seat,
                    recoveryCFrame
                )
            end
        )
    end

    return true
end

function HolyAntiWheelbarrowInspectSeatWeld(weld)

    if typeof(weld) ~= "Instance"
    or weld:IsA("Weld") ~= true
    or string.lower(
        weld.Name
    ) ~= "seatweld"
    or HolyAntiWheelbarrowWeldConnectsCharacter(
        weld,
        nil
    ) ~= true then

        return false
    end

    local part0 =
        weld.Part0

    local part1 =
        weld.Part1

    local seat =
        HolyAntiWheelbarrowIsCharacterPart(
            part0
        )
        and part1
        or part0

    return HolyAntiWheelbarrowTrigger(
        "seat weld",
        seat
    )
end

function HolyAntiWheelbarrowBindCharacter(character)

    local runtime =
        HOLY_ANTI_WHEELBARROW_STATE

    HolyAntiWheelbarrowDisconnectList(
        runtime.CharacterConnections
    )

    runtime.Character =
        character

    runtime.Humanoid =
        nil

    runtime.Root =
        nil

    runtime.SafeCFrame =
        nil

    runtime.SafeCapturedAt =
        0

    runtime.RecoveringUntil =
        0

    runtime.CurrentEpisodeUntil =
        0

    runtime.ActiveSeat =
        nil

    if typeof(character) ~= "Instance" then
        return false
    end

    local humanoid =
        character:FindFirstChildOfClass(
            "Humanoid"
        )
        or character:WaitForChild(
            "Humanoid",
            8
        )

    local root =
        character:FindFirstChild(
            "HumanoidRootPart"
        )
        or character:WaitForChild(
            "HumanoidRootPart",
            8
        )

    if typeof(humanoid) ~= "Instance"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true then

        return false
    end

    runtime.Humanoid =
        humanoid

    runtime.Root =
        root

    runtime.SafeCFrame =
        root.CFrame

    runtime.SafeCapturedAt =
        os.clock()

    table.insert(
        runtime.CharacterConnections,
        humanoid:GetPropertyChangedSignal(
            "SeatPart"
        ):Connect(function()

            local seat =
                humanoid.SeatPart

            if seat ~= nil then

                HolyAntiWheelbarrowTrigger(
                    "seat part",
                    seat
                )
            end
        end)
    )

    table.insert(
        runtime.CharacterConnections,
        humanoid:GetPropertyChangedSignal(
            "Sit"
        ):Connect(function()

            if humanoid.Sit == true
            and humanoid.SeatPart ~= nil then

                HolyAntiWheelbarrowTrigger(
                    "sit",
                    humanoid.SeatPart
                )
            end
        end)
    )

    table.insert(
        runtime.CharacterConnections,
        humanoid.Seated:Connect(function(
            active,
            seat
        )

            if active == true
            and seat ~= nil then

                HolyAntiWheelbarrowTrigger(
                    "seated",
                    seat
                )
            end
        end)
    )

    table.insert(
        runtime.CharacterConnections,
        humanoid.StateChanged:Connect(function(
            _,
            newState
        )

            if newState
                == Enum.HumanoidStateType.Seated
            and humanoid.SeatPart ~= nil then

                HolyAntiWheelbarrowTrigger(
                    "seated state",
                    humanoid.SeatPart
                )
            end
        end)
    )

    if humanoid.SeatPart ~= nil then

        HolyAntiWheelbarrowTrigger(
            "character bind",
            humanoid.SeatPart
        )
    end

    return true
end

function HolyAntiWheelbarrowStop(reason)

    local runtime =
        HOLY_ANTI_WHEELBARROW_STATE

    if type(runtime) ~= "table" then
        return false
    end

    runtime.Running =
        false

    runtime.Token =
        nil

    HolyAntiWheelbarrowDisconnectList(
        runtime.CharacterConnections
    )

    HolyAntiWheelbarrowDisconnectList(
        runtime.Connections
    )

    HolyAntiWheelbarrowRestoreSeats()

    runtime.Character =
        nil

    runtime.Humanoid =
        nil

    runtime.Root =
        nil

    runtime.SafeCFrame =
        nil

    runtime.SafeCapturedAt =
        0

    runtime.RecoveringUntil =
        0

    runtime.CurrentEpisode =
        0

    runtime.CurrentEpisodeUntil =
        0

    runtime.ActiveSeat =
        nil

    return true
end

function HolyAntiWheelbarrowStart(reason)

    local runtime =
        HOLY_ANTI_WHEELBARROW_STATE

    if runtime.Running == true then
        return false
    end

    runtime.Running =
        true

    runtime.Token =
        {}

    local token =
        runtime.Token

    runtime.Connections =
        {}

    runtime.CharacterConnections =
        {}

    runtime.DisabledSeats =
        {}

    table.insert(
        runtime.Connections,
        LocalPlayer.CharacterAdded:Connect(function(
            character
        )

            task.defer(function()

                if runtime.Running == true
                and runtime.Token == token then

                    HolyAntiWheelbarrowBindCharacter(
                        character
                    )
                end
            end)
        end)
    )

    table.insert(
        runtime.Connections,
        workspace.DescendantAdded:Connect(function(
            descendant
        )

            if runtime.Running ~= true
            or runtime.Token ~= token
            or descendant:IsA("Weld") ~= true
            or string.lower(
                descendant.Name
            ) ~= "seatweld" then

                return
            end

            task.defer(function()

                HolyAntiWheelbarrowInspectSeatWeld(
                    descendant
                )
            end)

            task.delay(
                0.03,
                function()

                    if runtime.Running == true
                    and runtime.Token == token
                    and descendant.Parent ~= nil then

                        HolyAntiWheelbarrowInspectSeatWeld(
                            descendant
                        )
                    end
                end
            )
        end)
    )

    HolyAntiWheelbarrowBindCharacter(
        LocalPlayer.Character
        or LocalPlayer.CharacterAdded:Wait()
    )

    task.spawn(function()

        while runtime.Running == true
        and runtime.Token == token do

            HolyAntiWheelbarrowCaptureSafePosition(
                false
            )

            task.wait(
                0.15
            )
        end
    end)

    return true
end

HOLY_ANTI_WHEELBARROW_STATE.Stop =
    HolyAntiWheelbarrowStop

function HolySetGroupboxVisible(groupbox, visible)

    if type(groupbox) ~= "table" then
        return false
    end

    visible =
        visible == true

    if groupbox.BoxHolder then

        groupbox.BoxHolder.Visible =
            visible

        groupbox.BoxHolder.Size =
            visible
            and UDim2.fromScale(
                1,
                0
            )
            or UDim2.new(
                1,
                0,
                0,
                0
            )
    end

    if groupbox.Holder then

        groupbox.Holder.Visible =
            visible
    end

    if visible == true
    and type(groupbox.Resize) == "function" then

        pcall(function()

            groupbox:Resize()
        end)
    end

    if groupbox.Tab
    and type(groupbox.Tab.RefreshSides) == "function" then

        task.defer(function()

            groupbox.Tab:RefreshSides()
        end)
    end

    return true
end

HOLY_SHOP_CATEGORIES = {
    Seeds = {
        ShopName = "SeedShop",
        PacketShop = "SeedShop",
        PacketName = "PurchaseSeed",
    },

    Gear = {
        ShopName = "GearShop",
        PacketShop = "GearShop",
        PacketName = "PurchaseGear",
    },

    Props = {
        ShopName = "CrateShop",
        PacketShop = "CrateShop",
        PacketName = "PurchaseCrate",
    },
}

function HolyShopRequireModule(path)

    local current =
        ReplicatedStorage

    for part in tostring(path or ""):gmatch("[^%.]+") do

        current =
            current
            and current:FindFirstChild(part)
            or nil
    end

    if typeof(current) ~= "Instance"
    or current:IsA("ModuleScript") ~= true then

        return nil
    end

    local ok,
        result =
        pcall(function()

            return require(
                current
            )
        end)

    if ok ~= true then
        return nil
    end

    return result
end

function HolyDataLogOnce(key, ...)

    HOLY_DATA_STATE =
        type(HOLY_DATA_STATE) == "table"
        and HOLY_DATA_STATE
        or {}

    HOLY_DATA_STATE.Logged =
        type(HOLY_DATA_STATE.Logged) == "table"
        and HOLY_DATA_STATE.Logged
        or {}

    key =
        tostring(key or "")

    if key ~= ""
    and HOLY_DATA_STATE.Logged[key] == true then
        return false
    end

    if key ~= "" then

        HOLY_DATA_STATE.Logged[key] =
            true
    end

    print(
        "[HOLY DATA]",
        ...
    )

    return true
end

function HolyDataFindSharedModule(moduleName)

    moduleName =
        HolyCleanText(
            moduleName
        )

    if moduleName == "" then
        return nil,
            "empty module"
    end

    local sharedData =
        ReplicatedStorage:FindFirstChild(
            "SharedData"
        )

    if typeof(sharedData) ~= "Instance" then

        return nil,
            "SharedData missing"
    end

    local module =
        sharedData:FindFirstChild(
            moduleName
        )

    if typeof(module) ~= "Instance"
    or module:IsA("ModuleScript") ~= true then

        return nil,
            moduleName .. " missing"
    end

    return module,
        "found"
end

function HolyDataTryRequireModule(moduleName)

    HOLY_DATA_STATE =
        type(HOLY_DATA_STATE) == "table"
        and HOLY_DATA_STATE
        or {}

    HOLY_DATA_STATE.Modules =
        type(HOLY_DATA_STATE.Modules) == "table"
        and HOLY_DATA_STATE.Modules
        or {}

    moduleName =
        HolyCleanText(
            moduleName
        )

    if moduleName == "" then
        return nil,
            "empty module"
    end

    local cached =
        HOLY_DATA_STATE.Modules[moduleName]

    if type(cached) == "table" then
        return cached,
            "cached"
    end

    local module,
        findReason =
        HolyDataFindSharedModule(
            moduleName
        )

    if typeof(module) ~= "Instance" then
        return nil,
            findReason
    end

    local ok,
        result =
        pcall(function()

            return require(
                module
            )
        end)

    if ok ~= true
    or type(result) ~= "table" then

        return nil,
            "require failed"
    end

    HOLY_DATA_STATE.Modules[moduleName] =
        result

    HolyDataLogOnce(
        "loaded:" .. moduleName,
        moduleName .. " loaded."
    )

    return result,
        "loaded"
end

function HolyDataGetModule(moduleName)

    local result =
        HolyDataTryRequireModule(
            moduleName
        )

    if type(result) ~= "table" then
        return nil
    end

    return result
end

function HolyDataCountPetDataRows(petData)

    if type(petData) ~= "table" then
        return 0
    end

    local count =
        0

    for key, row in pairs(petData) do

        if type(HolySniperIsPetDataRow) == "function"
        and HolySniperIsPetDataRow(key, row) == true then

            count =
                count + 1
        end
    end

    return count
end

function HolyDataListHasValue(values, value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return false
    end

    for _, item in ipairs(values or {}) do

        if item == value then
            return true
        end
    end

    return false
end

function HolyDataSetDropdownValues(dropdown, values, selected)

    if type(dropdown) ~= "table" then
        return false
    end

    values =
        type(values) == "table"
        and values
        or {
            "Raccoon",
        }

    selected =
        HolyCleanText(
            selected
        )

    if selected == "" then
        selected =
            "Raccoon"
    end

    pcall(function()

        if type(dropdown.SetValues) == "function" then

            dropdown:SetValues(
                values
            )

        elseif type(dropdown.SetItems) == "function" then

            dropdown:SetItems(
                values
            )
        end
    end)

    if type(dropdown.SetValue) == "function" then

        pcall(function()

            dropdown:SetValue(
                selected
            )
        end)
    end

    return true
end

function HolyDataRefreshPetDropdowns()

    local values =
        HolySniperGetPetValues()

    if type(values) ~= "table"
    or #values <= 0 then

        values = {
            "Any Pet",
            "Raccoon",
        }
    end

    local selected =
        HolySniperResolvePetDisplay(
            HOLY_SNIPER_STATE.BuilderPet
            or "Raccoon"
        )

    if HolyDataListHasValue(values, selected) ~= true then

        selected =
            HolyDataListHasValue(values, "Raccoon") == true
            and "Raccoon"
            or values[1]
            or "Raccoon"
    end

    HOLY_SNIPER_STATE.BuilderPet =
        selected

    local options =
        HOLY_DEV_LIBRARY
        and HOLY_DEV_LIBRARY.Options
        or Options

    if type(options) == "table" then

        HolyDataSetDropdownValues(
            options.HolySniperPetFilter,
            values,
            selected
        )
    end

    if type(HolyServerFinderApplyFilterOptions) == "function"
    and type(HOLY_SERVER_FINDER_HUD) == "table" then

        HolyServerFinderApplyFilterOptions(
            HOLY_SERVER_FINDER_HUD
        )
    end

    if type(HolySniperRefreshUI) == "function" then

        HolySniperRefreshUI()
    end

    HolyDataLogOnce(
        "pet-dropdown-refreshed",
        "Pet dropdown refreshed."
    )

    return true
end

function HolyDataStartPetLoader(reason)

    HOLY_DATA_STATE =
        type(HOLY_DATA_STATE) == "table"
        and HOLY_DATA_STATE
        or {}

    if HOLY_DATA_STATE.LoaderStarted == true then
        return false
    end

    HOLY_DATA_STATE.LoaderStarted =
        true

    HolyDataLogOnce(
        "petdata-waiting",
        "PetData waiting..."
    )

    task.spawn(function()

        local retryDelays = {
            0,
            0.15,
            0.35,
            0.75,
            1.20,
            1.80,
            2.50,
        }

        local lastReason =
            "not started"

        for _, delay in ipairs(retryDelays) do

            if delay > 0 then

                task.wait(
                    delay
                )
            end

            HolyDataTryRequireModule(
                "PetSizes"
            )

            HolyDataTryRequireModule(
                "PetTypes"
            )

            local petData,
                petReason =
                HolyDataTryRequireModule(
                    "PetData"
                )

            lastReason =
                tostring(petReason or "unknown")

            local count =
                HolyDataCountPetDataRows(
                    petData
                )

            if count > 0 then

                HOLY_DATA_STATE.PetDataReady =
                    true

                HOLY_DATA_STATE.PetDataCount =
                    count

                HolyDataLogOnce(
                    "petdata-loaded",
                    "PetData loaded: "
                        .. tostring(count)
                        .. " pets."
                )

                HolyDataRefreshPetDropdowns()

                return
            end
        end

        HOLY_DATA_STATE.PetDataReady =
            false

        HOLY_DATA_STATE.PetDataCount =
            0

        HolyDataLogOnce(
            "petdata-failed",
            "PetData unavailable after startup retries. Using Raccoon fallback. Last: "
                .. tostring(lastReason)
        )
    end)

    return true
end

function HolyShopAddItemRow(rows, name, price)

    name =
        HolyCleanText(name)

    if name == "" then
        return
    end

    rows[name] =
        rows[name]
        or {
            Name = name,
            Price = 0,
        }

    rows[name].Price =
        math.max(
            tonumber(rows[name].Price)
            or 0,
            tonumber(price)
            or 0
        )
end

function HolyShopModuleEnabled(modulePath, functionName, itemName, fallback)

    local module =
        HolyShopRequireModule(
            modulePath
        )

    local callback =
        type(module) == "table"
        and module[functionName]
        or nil

    if type(callback) ~= "function" then
        return fallback ~= false
    end

    local ok,
        result =
        pcall(
            callback,
            itemName
        )

    if ok ~= true then

        ok,
            result =
            pcall(
                callback,
                module,
                itemName
            )
    end

    if ok == true
    and type(result) == "boolean" then

        return result
    end

    return fallback ~= false
end

function HolyShopFlagEnabled(modulePath, itemName, fallback)

    local module =
        HolyShopRequireModule(
            modulePath
        )

    local enabledOverrides =
        type(module) == "table"
        and module.EnabledOverrides
        or nil

    local valueTable =
        type(enabledOverrides) == "table"
        and enabledOverrides.Value
        or nil

    if type(valueTable) == "table"
    and valueTable[itemName] ~= nil then

        return valueTable[itemName] == true
    end

    return fallback ~= false
end

function HolyShopGetFlagOverride(modulePath, itemName)

    local module =
        HolyShopRequireModule(
            modulePath
        )

    local enabledOverrides =
        type(module) == "table"
        and module.EnabledOverrides
        or nil

    local valueTable =
        type(enabledOverrides) == "table"
        and enabledOverrides.Value
        or nil

    if type(valueTable) == "table"
    and valueTable[itemName] ~= nil then

        return valueTable[itemName] == true,
            true
    end

    return nil,
        false
end

function HolyShopSeedEnabled(seedName)

    local overrideValue,
        hasOverride =
        HolyShopGetFlagOverride(
            "SharedModules.Flags.SeedShopFlags",
            seedName
        )

    if hasOverride == true then

        return overrideValue == true
    end

    return HolyShopModuleEnabled(
        "SharedModules.SeedShopEnabled",
        "IsSeedEnabled",
        seedName,
        true
    ) == true
end

function HolyShopAddStockRows(category, rows)

    -- Dropdown names must come from real shop data only.
    -- StockValues can contain hidden, future, or internal items.
    return false
end

function HolyShopBuildSeedRows()

    local rows =
        {}

    local data =
        HolyShopRequireModule(
            "SharedModules.SeedData"
        )

    if type(data) == "table" then

        for _, row in pairs(data) do

            if type(row) == "table" then

                local seedName =
                    HolyCleanText(
                        row.SeedName
                    )

                if seedName ~= ""
                and row.RestockShop == true
                and HolyShopSeedEnabled(
                    seedName
                ) == true then

                    HolyShopAddItemRow(
                        rows,
                        seedName,
                        row.PurchasePrice
                    )
                end
            end
        end
    end

    return rows
end

function HolyShopBuildGearRows()

    local rows =
        {}

    local data =
        HolyShopRequireModule(
            "SharedModules.GearShopData"
        )

    data =
        type(data) == "table"
        and data.Data
        or nil

    if type(data) == "table" then

        for _, row in pairs(data) do

            if type(row) == "table" then

                local itemName =
                    HolyCleanText(
                        row.ItemName
                    )

                if itemName ~= ""
                and row.HideFromShop ~= true
                and HolyShopModuleEnabled(
                    "SharedModules.GearShopABTest",
                    "IsGearEnabled",
                    itemName,
                    true
                ) == true
                and HolyShopFlagEnabled(
                    "SharedModules.Flags.GearShopFlags",
                    itemName,
                    true
                ) == true then

                    HolyShopAddItemRow(
                        rows,
                        itemName,
                        row.Cost
                    )
                end
            end
        end
    end

    return rows
end

function HolyShopBuildPropRows()

    local rows =
        {}

    local data =
        HolyShopRequireModule(
            "SharedModules.CrateData"
        )

    if type(data) == "table"
    and type(data.GetAllCrates) == "function" then

        local ok,
            crates =
            pcall(function()

                return data.GetAllCrates()
            end)

        if ok ~= true
        or type(crates) ~= "table" then

            ok,
                crates =
                pcall(
                    data.GetAllCrates,
                    data
                )
        end

        if ok == true
        and type(crates) == "table" then

            for key, row in pairs(crates) do

                if type(row) == "table" then

                    local crateName =
                        HolyCleanText(
                            row.Name
                            or key
                        )

                    if crateName ~= ""
                    and HolyShopModuleEnabled(
                        "SharedModules.CrateShopEnabled",
                        "IsCrateEnabled",
                        crateName,
                        true
                    ) == true
                    and HolyShopFlagEnabled(
                        "SharedModules.Flags.CrateShopFlags",
                        crateName,
                        true
                    ) == true then

                        HolyShopAddItemRow(
                            rows,
                            crateName,
                            row.Cost
                        )
                    end
                end
            end
        end
    end

    return rows
end

function HolyShopGetItemRows(category)

    HOLY_SHOP_STATE.ItemCache =
        type(HOLY_SHOP_STATE.ItemCache) == "table"
        and HOLY_SHOP_STATE.ItemCache
        or {}

    if type(HOLY_SHOP_STATE.ItemCache[category]) == "table" then

        return HOLY_SHOP_STATE.ItemCache[category]
    end

    local map =
        {}

    if category == "Seeds" then

        map =
            HolyShopBuildSeedRows()

    elseif category == "Gear" then

        map =
            HolyShopBuildGearRows()

    elseif category == "Props" then

        map =
            HolyShopBuildPropRows()
    end

    local rows =
        {}

    for _, row in pairs(map) do

        table.insert(
            rows,
            row
        )
    end

    table.sort(rows, function(a, b)

        local priceA =
            tonumber(a.Price)
            or 0

        local priceB =
            tonumber(b.Price)
            or 0

        if priceA ~= priceB then
            return priceA > priceB
        end

        return tostring(a.Name) < tostring(b.Name)
    end)

    HOLY_SHOP_STATE.ItemCache[category] =
        rows

    return rows
end

function HolyShopGetDropdownValues(category)

    local values = {
        "All",
    }

    for _, row in ipairs(HolyShopGetItemRows(category)) do

        table.insert(
            values,
            row.Name
        )
    end

    return values
end

function HolyShopNormalizeSelection(value)

    local output =
        {}

    if type(value) == "table" then

        for key, enabled in pairs(value) do

            if type(key) == "number" then

                local text =
                    HolyCleanText(enabled)

                if text ~= "" then

                    output[text] =
                        true
                end

            elseif enabled == true then

                local text =
                    HolyCleanText(key)

                if text ~= "" then

                    output[text] =
                        true
                end
            end
        end

    elseif type(value) == "string" then

        local text =
            HolyCleanText(value)

        if text ~= "" then

            output[text] =
                true
        end
    end

    return output
end

function HolyShopGetSelection(category)

    if category == "Seeds" then

        return HolyShopNormalizeSelection(
            HOLY_SHOP_STATE.SelectedSeeds
        )

    elseif category == "Gear" then

        return HolyShopNormalizeSelection(
            HOLY_SHOP_STATE.SelectedGear
        )

    elseif category == "Props" then

        return HolyShopNormalizeSelection(
            HOLY_SHOP_STATE.SelectedProps
        )
    end

    return {}
end

function HolyShopCategoryEnabled(category)

    if category == "Seeds" then
        return HOLY_SHOP_STATE.AutoBuySeeds == true
    end

    if category == "Gear" then
        return HOLY_SHOP_STATE.AutoBuyGear == true
    end

    if category == "Props" then
        return HOLY_SHOP_STATE.AutoBuyProps == true
    end

    return false
end

function HolyShopGetSelectedRows(category)

    local selection =
        HolyShopGetSelection(category)

    local hasSelection =
        false

    for _ in pairs(selection) do

        hasSelection =
            true

        break
    end

    if hasSelection ~= true then
        return {}
    end

    local useAll =
        selection.All == true

    local rows =
        {}

    for _, row in ipairs(HolyShopGetItemRows(category)) do

        if useAll == true
        or selection[row.Name] == true then

            table.insert(
                rows,
                row
            )
        end
    end

    return rows
end

function HolyShopGetStockValue(category, itemName)

    local config =
        HOLY_SHOP_CATEGORIES[category]

    local valueObject =
        config
        and ReplicatedStorage:FindFirstChild("StockValues")
        and ReplicatedStorage.StockValues:FindFirstChild(config.ShopName)
        and ReplicatedStorage.StockValues[config.ShopName]:FindFirstChild("Items")
        and ReplicatedStorage.StockValues[config.ShopName].Items:FindFirstChild(itemName)
        or nil

    if typeof(valueObject) ~= "Instance"
    or valueObject:IsA("ValueBase") ~= true then

        return 0
    end

    local value =
        0

    pcall(function()

        value =
            valueObject.Value
    end)

    return math.max(
        0,
        math.floor(
            tonumber(value)
            or 0
        )
    )
end

function HolyShopGetRestockKey(category)

    local config =
        HOLY_SHOP_CATEGORIES[category]

    local shop =
        config
        and ReplicatedStorage:FindFirstChild("StockValues")
        and ReplicatedStorage.StockValues:FindFirstChild(config.ShopName)
        or nil

    local value =
        0

    if typeof(shop) == "Instance" then

        local last =
            shop:FindFirstChild("UnixLastRestock")

        if last
        and last:IsA("ValueBase") then

            pcall(function()

                value =
                    last.Value
            end)
        end
    end

    return tostring(value)
end

function HolyShopResolvePacket(category)

    local config =
        HOLY_SHOP_CATEGORIES[category]

    if type(config) ~= "table" then
        return nil
    end

    HOLY_SHOP_STATE.PacketCache =
        type(HOLY_SHOP_STATE.PacketCache) == "table"
        and HOLY_SHOP_STATE.PacketCache
        or {}

    if HOLY_SHOP_STATE.PacketCache[category] ~= nil then

        return HOLY_SHOP_STATE.PacketCache[category]
    end

    local networking =
        HolyShopRequireModule(
            "SharedModules.Networking"
        )

    local packet =
        type(networking) == "table"
        and networking[config.PacketShop]
        and networking[config.PacketShop][config.PacketName]
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        HOLY_SHOP_STATE.PacketCache[category] =
            false

        return nil
    end

    HOLY_SHOP_STATE.PacketCache[category] =
        packet

    return packet
end

function HolyShopFireBurst(category, itemName, amount)

    local packet =
        HolyShopResolvePacket(category)

    if type(packet) ~= "table" then
        return 0
    end

    amount =
        math.clamp(
            math.floor(
                tonumber(amount)
                or 0
            ),
            0,
            tonumber(HOLY_SHOP_STATE.MaxBurstFires)
            or 120
        )

    local fired =
        0

    local yieldEvery =
        math.max(
            1,
            math.floor(
                tonumber(HOLY_SHOP_STATE.YieldEvery)
                or 24
            )
        )

    for index = 1, amount do

        local ok =
            pcall(function()

                packet:Fire(
                    itemName
                )
            end)

        if ok == true then

            fired =
                fired + 1
        end

        if index % yieldEvery == 0 then

            task.wait()
        end
    end

    return fired
end

function HolyShopIsItemSelected(category, itemName)

    local selection =
        HolyShopGetSelection(
            category
        )

    return selection.All == true
        or selection[itemName] == true
end

function HolyShopGetBurstItemState(category, itemName)

    HOLY_SHOP_STATE.BurstItems =
        type(HOLY_SHOP_STATE.BurstItems) == "table"
        and HOLY_SHOP_STATE.BurstItems
        or {}

    local key =
        tostring(category)
        .. "|"
        .. tostring(itemName)

    HOLY_SHOP_STATE.BurstItems[key] =
        type(HOLY_SHOP_STATE.BurstItems[key]) == "table"
        and HOLY_SHOP_STATE.BurstItems[key]
        or {
            Running = false,
            BlockedSignature = "",
            RetryAfter = 0,
        }

    return HOLY_SHOP_STATE.BurstItems[key]
end

function HolyShopRunVerifiedBurst(category, itemName)

    if HolyShopCategoryEnabled(category) ~= true
    or HolyShopIsItemSelected(category, itemName) ~= true then

        return false
    end

    local firstStock =
        HolyShopGetStockValue(
            category,
            itemName
        )

    if firstStock <= 0 then

        return false
    end

    local state =
        HolyShopGetBurstItemState(
            category,
            itemName
        )

    if state.Running == true then

        return false
    end

    local restockKey =
        HolyShopGetRestockKey(
            category
        )

    local signature =
        tostring(restockKey)
        .. "|"
        .. tostring(firstStock)

    if state.BlockedSignature == signature
    and os.clock() < (
        tonumber(state.RetryAfter)
        or 0
    ) then

        return false
    end

    state.Running =
        true

    state.BlockedSignature =
        ""

    state.RetryAfter =
        0

    local retryDelays =
        type(HOLY_SHOP_STATE.BurstRetryDelays) == "table"
        and HOLY_SHOP_STATE.BurstRetryDelays
        or {
            0,
            0.75,
            1.50,
        }

    local progressed =
        false

    local completed =
        false

    local cancelled =
        false

    local restockChanged =
        false

    for passIndex, retryDelay in ipairs(retryDelays) do

        if passIndex > 1 then

            task.wait(
                math.max(
                    0,
                    tonumber(retryDelay)
                    or 0
                )
            )
        end

        if HolyShopCategoryEnabled(category) ~= true
        or HolyShopIsItemSelected(category, itemName) ~= true then

            cancelled =
                true

            break
        end

        if HolyShopGetRestockKey(category) ~= restockKey then

            restockChanged =
                true

            break
        end

        local beforeStock =
            HolyShopGetStockValue(
                category,
                itemName
            )

        if beforeStock <= 0 then

            completed =
                true

            break
        end

        local fired =
            HolyShopFireBurst(
                category,
                itemName,
                beforeStock
            )

        if fired <= 0 then

            break
        end

        task.wait(
            math.max(
                0.05,
                tonumber(
                    HOLY_SHOP_STATE.BurstConfirmDelay
                )
                or 0.75
            )
        )

        local afterStock =
            HolyShopGetStockValue(
                category,
                itemName
            )

        if afterStock < beforeStock then

            progressed =
                true
        end

        if afterStock <= 0 then

            completed =
                true

            break
        end
    end

    local remainingStock =
        HolyShopGetStockValue(
            category,
            itemName
        )

    state.Running =
        false

    if cancelled == true
    or completed == true
    or restockChanged == true
    or remainingStock <= 0 then

        state.BlockedSignature =
            ""

        state.RetryAfter =
            0

    else

        state.BlockedSignature =
            tostring(
                HolyShopGetRestockKey(
                    category
                )
            )
            .. "|"
            .. tostring(remainingStock)

        state.RetryAfter =
            os.clock()
            + math.max(
                0,
                tonumber(
                    HOLY_SHOP_STATE.BurstFailureCooldown
                )
                or 5
            )
    end

    if restockChanged == true
    and HolyShopCategoryEnabled(category) == true then

        HolyShopQueueCategory(
            category
        )
    end

    return completed == true
        or progressed == true
end

function HolyShopRunCategory(category)

    if HolyShopCategoryEnabled(category) ~= true then

        return false
    end

    if category == "Seeds" then

        HOLY_SHOP_STATE.ItemCache =
            type(HOLY_SHOP_STATE.ItemCache) == "table"
            and HOLY_SHOP_STATE.ItemCache
            or {}

        HOLY_SHOP_STATE.ItemCache.Seeds =
            nil
    end

    local rows =
        HolyShopGetSelectedRows(
            category
        )

    if #rows <= 0 then

        return false
    end

    for _, row in ipairs(rows) do

        if HolyShopCategoryEnabled(category) ~= true then

            return true
        end

        local stock =
            HolyShopGetStockValue(
                category,
                row.Name
            )

        if stock > 0 then

            HolyShopRunVerifiedBurst(
                category,
                row.Name
            )
        end
    end

    return true
end

function HolyShopQueueCategory(category)

    HOLY_SHOP_STATE.PendingCategories =
        type(HOLY_SHOP_STATE.PendingCategories) == "table"
        and HOLY_SHOP_STATE.PendingCategories
        or {}

    HOLY_SHOP_STATE.PendingCategories[category] =
        true

    if HOLY_SHOP_STATE.WorkerRunning == true then
        return
    end

    HOLY_SHOP_STATE.WorkerRunning =
        true

    task.spawn(function()

        while true do

            local pending =
                HOLY_SHOP_STATE.PendingCategories

            HOLY_SHOP_STATE.PendingCategories =
                {}

            local hasPending =
                false

            for _ in pairs(pending) do

                hasPending =
                    true

                break
            end

            if hasPending ~= true then
                break
            end

            if pending.Seeds == true then

                HolyShopRunCategory(
                    "Seeds"
                )
            end

            if pending.Gear == true then

                HolyShopRunCategory(
                    "Gear"
                )
            end

            if pending.Props == true then

                HolyShopRunCategory(
                    "Props"
                )
            end

            task.wait()
        end

        HOLY_SHOP_STATE.WorkerRunning =
            false
    end)
end

function HolyShopQueueAll()

    if HOLY_SHOP_STATE.AutoBuySeeds == true then

        HolyShopQueueCategory(
            "Seeds"
        )
    end

    if HOLY_SHOP_STATE.AutoBuyGear == true then

        HolyShopQueueCategory(
            "Gear"
        )
    end

    if HOLY_SHOP_STATE.AutoBuyProps == true then

        HolyShopQueueCategory(
            "Props"
        )
    end
end

function HolyShopConnectStockValue(category, child)

    if typeof(child) ~= "Instance"
    or child:IsA("ValueBase") ~= true then

        return false
    end

    table.insert(
        HOLY_SHOP_STATE.StockConnections,
        child.Changed:Connect(function()

            HolyShopQueueCategory(
                category
            )
        end)
    )

    return true
end

function HolyShopConnectStockSignals()

    if HOLY_SHOP_STATE.StockConnected == true then

        return
    end

    HOLY_SHOP_STATE.StockConnected =
        true

    HOLY_SHOP_STATE.StockConnections =
        type(HOLY_SHOP_STATE.StockConnections) == "table"
        and HOLY_SHOP_STATE.StockConnections
        or {}

    for category, config in pairs(HOLY_SHOP_CATEGORIES) do

        local items =
            ReplicatedStorage:FindFirstChild(
                "StockValues"
            )
            and ReplicatedStorage.StockValues:FindFirstChild(
                config.ShopName
            )
            and ReplicatedStorage.StockValues[
                config.ShopName
            ]:FindFirstChild(
                "Items"
            )
            or nil

        if typeof(items) == "Instance" then

            for _, child in ipairs(items:GetChildren()) do

                HolyShopConnectStockValue(
                    category,
                    child
                )
            end

            table.insert(
                HOLY_SHOP_STATE.StockConnections,
                items.ChildAdded:Connect(function(child)

                    if child:IsA("ValueBase") then

                        HolyShopConnectStockValue(
                            category,
                            child
                        )

                        HOLY_SHOP_STATE.ItemCache =
                            type(HOLY_SHOP_STATE.ItemCache) == "table"
                            and HOLY_SHOP_STATE.ItemCache
                            or {}

                        HOLY_SHOP_STATE.ItemCache[category] =
                            nil

                        task.defer(function()

                            HolyShopQueueCategory(
                                category
                            )
                        end)
                    end
                end)
            )
        end
    end
end

--==================================================
-- [2.55] AUCTION CORE
--==================================================

function HolyAuctionEnsureBaseState()

    HOLY_SHOP_STATE =
        type(HOLY_SHOP_STATE) == "table"
        and HOLY_SHOP_STATE
        or {}

    HOLY_SHOP_STATE.AutoBuyAuctions =
        HOLY_SHOP_STATE.AutoBuyAuctions == true

    HOLY_SHOP_STATE.AuctionWatchlist =
        HolyAuctionNormalizeWatchlist(
            HOLY_SHOP_STATE.AuctionWatchlist
        )

    HOLY_SHOP_STATE.AuctionWatchlistSelectedKey =
        tostring(
            HOLY_SHOP_STATE.AuctionWatchlistSelectedKey
            or ""
        )

    HOLY_SHOP_STATE.AuctionRoundRobinIndex =
        math.max(
            0,
            math.floor(
                tonumber(
                    HOLY_SHOP_STATE.AuctionRoundRobinIndex
                )
                or 0
            )
        )

    HOLY_SHOP_STATE.AuctionKnownItems =
        HolyShopSelectionArray(
            HOLY_SHOP_STATE.AuctionKnownItems
            or {}
        )

    HOLY_SHOP_STATE.AuctionBuyUntilSoldOut =
        HOLY_SHOP_STATE.AuctionBuyUntilSoldOut ~= false

    HOLY_SHOP_STATE.AuctionStatus =
        tostring(
            HOLY_SHOP_STATE.AuctionStatus
            or "Ready"
        )

    HOLY_SHOP_STATE.AuctionWorkerRunning =
        HOLY_SHOP_STATE.AuctionWorkerRunning == true

    HOLY_SHOP_STATE.AuctionWatcherStarted =
        HOLY_SHOP_STATE.AuctionWatcherStarted == true

    HOLY_SHOP_STATE.AuctionNextBuyAt =
        tonumber(HOLY_SHOP_STATE.AuctionNextBuyAt)
        or 0

    HOLY_SHOP_STATE.AuctionLastLots =
        type(HOLY_SHOP_STATE.AuctionLastLots) == "table"
        and HOLY_SHOP_STATE.AuctionLastLots
        or {}

    HOLY_SHOP_STATE.AuctionAttemptedLots =
        type(HOLY_SHOP_STATE.AuctionAttemptedLots) == "table"
        and HOLY_SHOP_STATE.AuctionAttemptedLots
        or {}

    HOLY_SHOP_STATE.AuctionConnections =
        type(HOLY_SHOP_STATE.AuctionConnections) == "table"
        and HOLY_SHOP_STATE.AuctionConnections
        or {}

    HOLY_SHOP_STATE.AuctionStockMap =
        type(HOLY_SHOP_STATE.AuctionStockMap) == "table"
        and HOLY_SHOP_STATE.AuctionStockMap
        or {}

    HOLY_SHOP_STATE.AuctionServerNow =
        tonumber(HOLY_SHOP_STATE.AuctionServerNow)
        or 0

    HOLY_SHOP_STATE.AuctionLastStockUpdateAt =
        tonumber(HOLY_SHOP_STATE.AuctionLastStockUpdateAt)
        or 0

    HOLY_SHOP_STATE.AuctionItemCache =
        type(HOLY_SHOP_STATE.AuctionItemCache) == "table"
        and HOLY_SHOP_STATE.AuctionItemCache
        or nil

    return HOLY_SHOP_STATE
end

function HolyAuctionItemKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.'\"_/{}:]", "")
end

function HolyAuctionSafeTonumber(value)

    local ok,
        result =
        pcall(function()

            return tonumber(
                value
            )
        end)

    if ok == true
    and result ~= nil then

        return result
    end

    return nil
end

function HolyAuctionReadMoney(value)

    if type(value) == "number" then

        return math.max(
            0,
            math.floor(value + 0.5)
        )
    end

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return 0
    end

    text =
        text:gsub("¢", "")
            :gsub("%$", "")
            :gsub(",", "")
            :gsub("%s+", "")

    local lower =
        text:lower()

    local multiplier =
        1

    if lower:find("b", 1, true) then

        multiplier =
            1000000000

    elseif lower:find("m", 1, true) then

        multiplier =
            1000000

    elseif lower:find("k", 1, true) then

        multiplier =
            1000
    end

    local rawNumber =
        lower:match("%d+%.?%d*")

    local number =
        HolyAuctionSafeTonumber(
            rawNumber
        )

    if number == nil then
        return 0
    end

    return math.max(
        0,
        math.floor(
            number * multiplier + 0.5
        )
    )
end

function HolyAuctionFormatMoney(value)

    value =
        math.max(
            0,
            tonumber(value)
            or 0
        )

    if value >= 1000000000 then

        return string.format(
            "%.2fB¢",
            value / 1000000000
        )
    end

    if value >= 1000000 then

        return string.format(
            "%.2fM¢",
            value / 1000000
        )
    end

    if value >= 1000 then

        return string.format(
            "%.2fK¢",
            value / 1000
        )
    end

    return tostring(
        math.floor(value)
    )
        .. "¢"
end

function HolyAuctionNormalizeWatchlist(value)

    local output = {}
    local seen = {}

    for _, rawEntry in ipairs(
        type(value) == "table"
        and value
        or {}
    ) do

        local name = ""
        local maxPrice = 0

        if type(rawEntry) == "table" then

            name =
                HolyCleanText(
                    rawEntry.Name
                    or rawEntry.Item
                    or rawEntry.DisplayName
                )

            maxPrice =
                HolyAuctionReadMoney(
                    rawEntry.MaxPrice
                    or rawEntry.Price
                    or rawEntry.Limit
                )

        elseif type(rawEntry) == "string" then

            name =
                HolyCleanText(
                    rawEntry
                )
        end

        local key =
            HolyAuctionItemKey(
                name
            )

        if key ~= ""
        and key ~= "all"
        and maxPrice > 0
        and seen[key] ~= true then

            seen[key] = true

            output[#output + 1] = {
                Name = name,
                MaxPrice = maxPrice,
            }
        end
    end

    return output
end

function HolyAuctionGetWatchEntry(itemName)

    local wantedKey =
        HolyAuctionItemKey(
            itemName
        )

    for index, entry in ipairs(
        HOLY_SHOP_STATE.AuctionWatchlist
        or {}
    ) do

        if HolyAuctionItemKey(entry.Name) == wantedKey then

            return entry,
                index
        end
    end

    return nil,
        nil
end

function HolyAuctionGetWatchMax(itemName)

    local entry =
        HolyAuctionGetWatchEntry(
            itemName
        )

    return type(entry) == "table"
        and HolyAuctionReadMoney(
            entry.MaxPrice
        )
        or 0
end

function HolyAuctionGetWatchNames()

    local names = {}

    for _, entry in ipairs(
        HOLY_SHOP_STATE.AuctionWatchlist
        or {}
    ) do

        names[#names + 1] =
            tostring(
                entry.Name
            )
    end

    return names
end

function HolyAuctionGetSelectedWatchEntry()

    local selectedKey =
        tostring(
            HOLY_SHOP_STATE.AuctionWatchlistSelectedKey
            or ""
        )

    for index, entry in ipairs(
        HOLY_SHOP_STATE.AuctionWatchlist
        or {}
    ) do

        if HolyAuctionItemKey(entry.Name) == selectedKey then

            return entry,
                index
        end
    end

    return nil,
        nil
end

function HolyAuctionUpsertWatchItem(itemName, maxPrice)

    HolyAuctionEnsureState()

    itemName =
        HolyCleanText(
            itemName
        )

    maxPrice =
        HolyAuctionReadMoney(
            maxPrice
        )

    if itemName == ""
    or HolyAuctionItemKey(itemName) == "all" then

        return false,
            "Select an auction item."
    end

    if maxPrice <= 0 then

        return false,
            "Enter a valid maximum price."
    end

    local entry =
        HolyAuctionGetWatchEntry(
            itemName
        )

    if type(entry) == "table" then

        entry.Name =
            itemName

        entry.MaxPrice =
            maxPrice

    else

        table.insert(
            HOLY_SHOP_STATE.AuctionWatchlist,
            {
                Name = itemName,
                MaxPrice = maxPrice,
            }
        )
    end

    HOLY_SHOP_STATE.AuctionWatchlistSelectedKey =
        HolyAuctionItemKey(
            itemName
        )

    HOLY_SHOP_STATE.AuctionNextRetryAt =
        0

    HolyAuctionRememberKnownItem(
        itemName
    )

    HolySaveShopSettings()

    if type(HolyAuctionRefreshWatchlistUI) == "function" then

        HolyAuctionRefreshWatchlistUI(
            true
        )
    end

    HolyAuctionRefreshUI()

    if HOLY_SHOP_STATE.AutoBuyAuctions == true then

        HolyAuctionQueueWorker(
            "watchlist changed"
        )
    end

    return true
end

function HolyAuctionRemoveWatchItem(itemName)

    HolyAuctionEnsureState()

    local entry,
        index =
        HolyAuctionGetWatchEntry(
            itemName
        )

    if type(entry) ~= "table"
    or index == nil then

        return false
    end

    local removedKey =
        HolyAuctionItemKey(
            entry.Name
        )

    table.remove(
        HOLY_SHOP_STATE.AuctionWatchlist,
        index
    )

    if HOLY_SHOP_STATE.AuctionWatchlistSelectedKey == removedKey then

        HOLY_SHOP_STATE.AuctionWatchlistSelectedKey =
            ""
    end

    HOLY_SHOP_STATE.AuctionRoundRobinIndex =
        math.min(
            HOLY_SHOP_STATE.AuctionRoundRobinIndex,
            #HOLY_SHOP_STATE.AuctionWatchlist
        )

    HOLY_SHOP_STATE.AuctionNextRetryAt =
        0

    HolySaveShopSettings()

    if type(HolyAuctionRefreshWatchlistUI) == "function" then

        HolyAuctionRefreshWatchlistUI(
            true
        )
    end

    HolyAuctionRefreshUI()

    return true
end

function HolyAuctionReadStock(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == ""
    or lower:find("sold", 1, true)
    or lower:find("out", 1, true)
    or lower:find("expired", 1, true) then

        return 0
    end

    -- Strict UI stock safety:
    -- only trust text like "x19,631 in Stock".
    if lower:find("stock", 1, true) == nil then
        return 0
    end

    local raw =
        text:match("x%s*([%d,]+)")
        or text:match("([%d,]+)")

    if raw == nil then
        return 0
    end

    local digits =
        tostring(raw or "")

    digits =
        digits:gsub(
            ",",
            ""
        )

    local number =
        HolyAuctionSafeTonumber(
            digits
        )

    return math.max(
        0,
        math.floor(
            number
            or 0
        )
    )
end

function HolyAuctionGetFlags()

    HolyAuctionEnsureState()

    if type(
        HOLY_SHOP_STATE.AuctionFlagsModule
    ) == "table" then

        return HOLY_SHOP_STATE.AuctionFlagsModule
    end

    local flags =
        HolyShopRequireModule(
            "SharedModules.Flags.AuctioneerFlags"
        )

    if type(flags) == "table" then

        HOLY_SHOP_STATE.AuctionFlagsModule =
            flags

        return flags
    end

    return nil
end

function HolyAuctionReadFlagNumber(
    flagName,
    fallback
)

    local flags =
        HolyAuctionGetFlags()

    local flag =
        type(flags) == "table"
        and flags[flagName]
        or nil

    local value =
        nil

    if type(flag) == "table" then

        value =
            flag.Value

        if type(value) == "function" then

            local ok,
                result =
                pcall(
                    value,
                    flag
                )

            if ok == true then

                value =
                    result
            end
        end

        if tonumber(value) == nil then

            value =
                flag.DefaultValue
        end

    elseif tonumber(flag) ~= nil then

        value =
            flag
    end

    return tonumber(value)
        or tonumber(fallback)
        or 0
end

function HolyAuctionReadDebounce()

    return math.clamp(
        HolyAuctionReadFlagNumber(
            "PurchaseDebounceSeconds",
            0.2
        ),
        0.05,
        5
    )
end

function HolyAuctionReadServerCooldown()

    return math.clamp(
        HolyAuctionReadFlagNumber(
            "PurchaseCooldownSeconds",
            10
        ),
        0.2,
        120
    )
end

function HolyAuctionReadCooldownGuard()

    local storedGuard =
        type(HOLY_SHOP_STATE) == "table"
        and tonumber(
            HOLY_SHOP_STATE.AuctionCooldownGuard
        )
        or nil

    return math.clamp(
        math.max(
            0.35,
            HolyAuctionReadDebounce(),
            storedGuard
                or 0.35
        ),
        0.35,
        1.85
    )
end

function HolyAuctionReadCooldown()

    return HolyAuctionReadServerCooldown()
        + HolyAuctionReadCooldownGuard()
end

function HolyAuctionIncreaseCooldownGuard()

    HolyAuctionEnsureState()

    local previousGuard =
        HolyAuctionReadCooldownGuard()

    local nextGuard =
        math.clamp(
            previousGuard + 0.25,
            0.35,
            1.85
        )

    HOLY_SHOP_STATE.AuctionCooldownGuard =
        nextGuard

    if type(HolyDevTrace) == "function" then

        HolyDevTrace(
            "Auction",
            "CooldownGuardIncreased",
            {
                PreviousGuard =
                    previousGuard,

                NextGuard =
                    nextGuard,
            },
            "Warning"
        )
    end

    return nextGuard
end

function HolyAuctionScheduleCooldown(
    anchorAt,
    source,
    synchronized,
    unknownOutcome
)

    HolyAuctionEnsureState()

    anchorAt =
        tonumber(anchorAt)
        or os.clock()

    source =
        tostring(
            source
            or "unknown"
        )

    local serverCooldown =
        HolyAuctionReadServerCooldown()

    local normalGuard =
        HolyAuctionReadCooldownGuard()

    local appliedGuard =
        unknownOutcome == true
        and math.max(
            1,
            normalGuard
        )
        or normalGuard

    local cooldownUntil =
        anchorAt
        + serverCooldown
        + appliedGuard

    HOLY_SHOP_STATE.AuctionCooldownAnchorAt =
        anchorAt

    HOLY_SHOP_STATE.AuctionCooldownAnchorReason =
        source

    HOLY_SHOP_STATE.AuctionCooldownBase =
        serverCooldown

    HOLY_SHOP_STATE.AuctionCooldownGuard =
        normalGuard

    HOLY_SHOP_STATE.AuctionCooldownAppliedGuard =
        appliedGuard

    HOLY_SHOP_STATE.AuctionCooldownSynchronized =
        synchronized == true

    HOLY_SHOP_STATE.AuctionUnknownOutcome =
        unknownOutcome == true

    HOLY_SHOP_STATE.AuctionNextBuyAt =
        cooldownUntil

    HOLY_SHOP_STATE.AuctionNextRetryAt =
        0

    HOLY_SHOP_STATE.AuctionSchedulerState =
        "Cooldown"

    if type(HolyDevTrace) == "function" then

        HolyDevTrace(
            "Auction",
            "CooldownScheduled",
            {
                Source =
                    source,

                AnchorAt =
                    anchorAt,

                ServerCooldown =
                    serverCooldown,

                Guard =
                    appliedGuard,

                CooldownUntil =
                    cooldownUntil,

                Remaining =
                    math.max(
                        0,
                        cooldownUntil
                            - os.clock()
                    ),

                Synchronized =
                    synchronized == true,

                UnknownOutcome =
                    unknownOutcome == true,
            },
            unknownOutcome == true
            and "Warning"
            or "Info"
        )
    end

    return cooldownUntil
end

function HolyAuctionAddCandidate(rows, name, source, data)

    name =
        HolyCleanText(
            name
        )

    if name == ""
    or name == "All"
    or name == "None"
    or name == "Normal"
    or name == "Big"
    or name == "Huge"
    or name == "Mega"
    or #name > 80
    or name:find("table:", 1, true) then

        return false
    end

    source =
        HolyCleanText(
            source
        )

    local blockedUnlessLive = {
        Gold = true,
        Rainbow = true,
        Mega = true,
        Default = true,
        Wood = true,
        Stone = true,
        White = true,
        Light = true,
        Star = true,
        Flower = true,
        Pole = true,
        Stick = true,
        Spike = true,
        Cupid = true,
        Lantern = true,
        Futuristic = true,
    }

    if blockedUnlessLive[name] == true
    and source ~= "LiveAuctionGui"
    and source ~= "KnownAuctionItems" then

        return false
    end

    if name == "Test Egg"
    and source ~= "LiveAuctionGui"
    and source ~= "KnownAuctionItems" then

        return false
    end

    local key =
        HolyAuctionItemKey(
            name
        )

    if key == "" then
        return false
    end

    rows[key] =
        rows[key]
        or {
            Name = name,
            Sources = {},
            Price = 0,
        }

    rows[key].Sources[source ~= "" and source or "Unknown"] =
        true

    data =
        type(data) == "table"
        and data
        or {}

    rows[key].Category =
        rows[key].Category
        or data.Category

    rows[key].Rarity =
        rows[key].Rarity
        or data.Rarity

    rows[key].Price =
        math.max(
            tonumber(rows[key].Price)
            or 0,
            tonumber(data.Price)
            or tonumber(data.Cost)
            or 0
        )

    return true
end

function HolyAuctionScanCrateCandidates(rows)

    local data =
        HolyShopRequireModule(
            "SharedModules.CrateData"
        )

    if type(data) == "table"
    and type(data.GetAllCrates) == "function" then

        local ok,
            crates =
            pcall(function()

                return data.GetAllCrates()
            end)

        if ok ~= true
        or type(crates) ~= "table" then

            ok,
                crates =
                pcall(
                    data.GetAllCrates,
                    data
                )
        end

        if ok == true
        and type(crates) == "table" then

            for key, row in pairs(crates) do

                if type(row) == "table" then

                    HolyAuctionAddCandidate(
                        rows,
                        row.Name
                            or key,
                        "CrateData",
                        {
                            Category =
                                "Crate",

                            Rarity =
                                row.Rarity,

                            Cost =
                                row.Cost,
                        }
                    )
                end
            end
        end
    end

    local root =
        ReplicatedStorage:FindFirstChild("SharedModules")
        and ReplicatedStorage.SharedModules:FindFirstChild("CrateData")
        or nil

    if typeof(root) == "Instance" then

        for _, child in ipairs(root:GetChildren()) do

            if child:IsA("ModuleScript") then

                local ok,
                    row =
                    pcall(function()

                        return require(child)
                    end)

                if ok == true
                and type(row) == "table" then

                    HolyAuctionAddCandidate(
                        rows,
                        row.Name
                            or child.Name,
                        "CrateData",
                        {
                            Category =
                                "Crate",

                            Rarity =
                                row.Rarity,

                            Cost =
                                row.Cost,
                        }
                    )

                else

                    HolyAuctionAddCandidate(
                        rows,
                        child.Name,
                        "CrateData",
                        {
                            Category =
                                "Crate",
                        }
                    )
                end
            end
        end
    end
end

function HolyAuctionScanGuildCrateCandidates(rows)

    local root =
        ReplicatedStorage:FindFirstChild("SharedModules")
        and ReplicatedStorage.SharedModules:FindFirstChild("GuildCrateData")
        or nil

    if typeof(root) ~= "Instance" then
        return false
    end

    for _, child in ipairs(root:GetChildren()) do

        if child:IsA("ModuleScript") then

            local ok,
                row =
                pcall(function()

                    return require(child)
                end)

            row =
                ok == true
                and type(row) == "table"
                and row
                or {}

            HolyAuctionAddCandidate(
                rows,
                row.Name
                    or row.CrateName
                    or child.Name,
                "GuildCrateData",
                {
                    Category =
                        "Guild Crate",

                    Rarity =
                        row.Rarity,

                    Cost =
                        row.Cost,
                }
            )
        end
    end

    return true
end

function HolyAuctionScanGearCandidates(rows)

    local data =
        HolyShopRequireModule(
            "SharedModules.GearShopData"
        )

    data =
        type(data) == "table"
        and (
            data.Data
            or data
        )
        or {}

    for _, row in pairs(data) do

        if type(row) == "table" then

            HolyAuctionAddCandidate(
                rows,
                row.ItemName
                    or row.Name,
                "GearShopData",
                {
                    Category =
                        "Gear",

                    Rarity =
                        row.Rarity,

                    Cost =
                        row.Cost,
                }
            )
        end
    end
end

function HolyAuctionScanEggCandidates(rows)

    local data =
        HolyShopRequireModule(
            "SharedModules.EggData"
        )

    data =
        type(data) == "table"
        and (
