                    Color3.fromRGB(
                        173,
                        179,
                        191
                    ),

                BorderSizePixel =
                    0,

                Position =
                    UDim2.fromOffset(
                        7.6,
                        5.8
                    ),

                Rotation =
                    42,

                Size =
                    UDim2.fromOffset(
                        7,
                        2
                    ),

                ZIndex =
                    22,

                Parent =
                    miniChevron,
            }
        )

    for _,
        chevronPart in ipairs({
            miniChevronLeft,
            miniChevronRight,
        }) do

        HolyAuctionHudCorner(
            chevronPart,
            UDim.new(
                1,
                0
            )
        )
    end

    HolyAuctionHudAddConnection(
        miniButton.MouseEnter:Connect(function()

            miniButton.BackgroundColor3 =
                Color3.fromRGB(
                    11,
                    13,
                    18
                )

            miniStroke.Color =
                Color3.fromRGB(
                    65,
                    69,
                    81
                )
        end)
    )

    HolyAuctionHudAddConnection(
        miniButton.MouseLeave:Connect(function()

            miniButton.BackgroundColor3 =
                Color3.fromRGB(
                    8,
                    10,
                    14
                )

            miniStroke.Color =
                Color3.fromRGB(
                    48,
                    52,
                    63
                )
        end)
    )

    local dragController =
        nil


    local function applyMinimizedState(isMinimized)

        HOLY_SHOP_STATE.AuctionHudMinimized =
            isMinimized == true

        local currentMinimized =
            HOLY_SHOP_STATE.AuctionHudMinimized
            == true

        top.Visible =
            not currentMinimized

        body.Visible =
            not currentMinimized

        miniButton.Visible =
            currentMinimized

        miniShadow.Visible =
            currentMinimized

        holder.ClipsDescendants =
            not currentMinimized

        holder.BackgroundTransparency =
            currentMinimized
            and 1
            or 0.12

        holderStroke.Enabled =
            not currentMinimized

        holder.Size =
            currentMinimized
            and UDim2.fromOffset(
                150,
                38
            )
            or UDim2.fromOffset(
                480,
                tonumber(
                    HOLY_AUCTION_HUD.ExpandedHeight
                )
                or expandedHeight
            )

        -- Fixed 100% size while minimized.
        -- Restore the saved user scale while expanded.
        HolyAuctionHudApplyScale()

        HolySaveShopSettings()

        HolyAuctionHudRefresh()

        task.defer(function()

            if typeof(holder) == "Instance"
            and holder.Parent ~= nil then

                HolyAuctionHudClampToViewport(
                    holder
                )

                HolyAuctionHudSavePosition(
                    holder
                )
            end
        end)
    end

    HolyAuctionHudAddConnection(
        minimizeButton.MouseButton1Click:Connect(function()

            applyMinimizedState(
                true
            )
        end)
    )

    HolyAuctionHudAddConnection(
        miniButton.MouseButton1Click:Connect(function()

            if dragController
            and dragController:ConsumeClick(
                miniButton
            ) == true then

                return
            end

            applyMinimizedState(
                false
            )
        end)
    )

    HolyAuctionHudAddConnection(
        closeButton.MouseButton1Click:Connect(function()

            HolyAuctionSetHudVisible(
                false,
                "closed"
            )
        end)
    )

    dragController =
        HolyAuctionHudMakeDraggable(
            holder,
            {
                top,
                miniButton,
            }
        )

    HolyAuctionHudApplyScale()

    task.defer(function()

        if typeof(holder) == "Instance"
        and holder.Parent ~= nil then

            HolyAuctionHudClampToViewport(
                holder
            )

            HolyAuctionHudSavePosition(
                holder
            )
        end
    end)

    return true
end

function HolyAuctionHudRefresh(rows)

    HolyAuctionEnsureState()

    if HOLY_SHOP_STATE.AuctionHudEnabled ~= true then
        return false
    end

    HolyAuctionHudStart()

    local hud =
        HOLY_AUCTION_HUD

    if type(hud) ~= "table"
    or typeof(hud.Holder) ~= "Instance" then

        return false
    end

    rows =
        type(rows) == "table"
        and rows
        or HOLY_SHOP_STATE.AuctionLastLots
        or {}

    local networkHealthy =
        HOLY_SHOP_STATE.AuctionNetworkReady == true

    local selected =
        HolyAuctionGetWatchNames()

    local function readDecision(row)

        local selectedRow =
            HolyAuctionSelectionAllows(
                row.Name
            )

        local maxPrice =
            HolyAuctionGetWatchMax(
                row.Name
            )

        if row.Expired == true then

            return {
                Text = "ENDED",
                TextColor = Color3.fromRGB(126, 133, 148),
                PillColor = Color3.fromRGB(28, 31, 39),
                PillTransparency = 0.52,
                Selected = selectedRow,
                Inactive = true,
            }
        end

        if row.StockKnown == true
        and (
            tonumber(row.Stock)
            or 0
        ) <= 0 then

            return {
                Text = "SOLD",
                TextColor = Color3.fromRGB(126, 133, 148),
                PillColor = Color3.fromRGB(28, 31, 39),
                PillTransparency = 0.52,
                Selected = selectedRow,
                Inactive = true,
            }
        end

        if selectedRow == true
        and maxPrice <= 0 then

            return {
                Text = "NO LIMIT",
                TextColor = Color3.fromRGB(245, 199, 100),
                PillColor = Color3.fromRGB(55, 40, 15),
                PillTransparency = 0.28,
                Selected = true,
                Inactive = false,
            }
        end

        if selectedRow == true
        and (
            tonumber(row.Price)
            or math.huge
        ) > maxPrice then

            return {
                Text = "OVER CAP",
                TextColor = Color3.fromRGB(245, 199, 100),
                PillColor = Color3.fromRGB(55, 40, 15),
                PillTransparency = 0.28,
                Selected = true,
                Inactive = false,
            }
        end

        if selectedRow == true
        and networkHealthy == true
        and row.NetworkReady == true then

            return {
                Text = "READY",
                TextColor = Color3.fromRGB(105, 229, 160),
                PillColor = Color3.fromRGB(22, 69, 44),
                PillTransparency = 0.20,
                Selected = true,
                Inactive = false,
            }
        end

        if selectedRow == true then

            return {
                Text = "WAIT",
                TextColor = Color3.fromRGB(245, 199, 100),
                PillColor = Color3.fromRGB(55, 40, 15),
                PillTransparency = 0.34,
                Selected = true,
                Inactive = false,
            }
        end

        return {
            Text = "LIVE",
            TextColor = Color3.fromRGB(155, 162, 175),
            PillColor = Color3.fromRGB(25, 29, 38),
            PillTransparency = 0.52,
            Selected = false,
            Inactive = false,
        }
    end

    local readyCount =
        0

    for _, row in ipairs(rows) do

        if type(row) == "table" then

            local decision =
                readDecision(
                    row
                )

            if decision.Text == "READY" then

                readyCount =
                    readyCount + 1
            end
        end
    end

    local visibleRows =
        math.min(
            6,
            #rows
        )

    local layoutRows =
        math.max(
            1,
            visibleRows
        )

    local listHeight =
        31
        + (layoutRows * 31)

    local bodyHeight =
        52
        + listHeight

    local expandedHeight =
        46
        + bodyHeight

    hud.ExpandedHeight =
        expandedHeight

    if HOLY_SHOP_STATE.AuctionHudMinimized ~= true then

        hud.Holder.Size =
            UDim2.fromOffset(
                480,
                expandedHeight
            )

        if typeof(hud.Body) == "Instance" then

            hud.Body.Size =
                UDim2.fromOffset(
                    480,
                    bodyHeight
                )
        end

        if typeof(hud.ListSurface) == "Instance" then

            hud.ListSurface.Size =
                UDim2.fromOffset(
                    480,
                    listHeight
                )
        end
    end

    if typeof(hud.HealthDot) == "Instance" then

        hud.HealthDot.BackgroundColor3 =
            networkHealthy == true
            and Color3.fromRGB(
                105,
                229,
                160
            )
            or Color3.fromRGB(
                245,
                199,
                100
            )
    end

    if typeof(hud.AutoBadge) == "Instance"
    and typeof(hud.AutoPill) == "Instance" then

        if HOLY_SHOP_STATE.AutoBuyAuctions == true then

            if HOLY_SHOP_STATE.AuctionDryRun == true then

                hud.AutoBadge.Text =
                    "AUTO TEST"

                hud.AutoBadge.TextColor3 =
                    Color3.fromRGB(
                        245,
                        199,
                        100
                    )

                hud.AutoPill.BackgroundColor3 =
                    Color3.fromRGB(
                        157,
                        103,
                        255
                    )

                hud.AutoPill.BackgroundTransparency =
                    0.76

            else

                hud.AutoBadge.Text =
                    "AUTO ON"

                hud.AutoBadge.TextColor3 =
                    Color3.fromRGB(
                        255,
                        111,
                        176
                    )

                hud.AutoPill.BackgroundColor3 =
                    Color3.fromRGB(
                        255,
                        61,
                        145
                    )

                hud.AutoPill.BackgroundTransparency =
                    0.78
            end

        else

            hud.AutoBadge.Text =
                "AUTO OFF"

            hud.AutoBadge.TextColor3 =
                Color3.fromRGB(
                    155,
                    162,
                    175
                )

            hud.AutoPill.BackgroundColor3 =
                Color3.fromRGB(
                    55,
                    61,
                    74
                )

            hud.AutoPill.BackgroundTransparency =
                0.65
        end
    end

    if typeof(hud.TargetsValue) == "Instance" then

        hud.TargetsValue.Text =
            tostring(#selected)
            .. (
                #selected == 1
                and " watched"
                or " watched"
            )
    end

    if typeof(hud.LimitValue) == "Instance" then

        hud.LimitValue.Text =
            #selected > 0
            and "Per item"
            or "Not set"
    end

    if typeof(hud.ReadyValue) == "Instance" then

        hud.ReadyValue.Text =
            tostring(readyCount)
            .. (
                readyCount == 1
                and " auction"
                or " auctions"
            )

        hud.ReadyValue.TextColor3 =
            readyCount > 0
            and Color3.fromRGB(
                105,
                229,
                160
            )
            or Color3.fromRGB(
                145,
                151,
                164
            )
    end

    if typeof(hud.EmptyLabel) == "Instance" then

        hud.EmptyLabel.Visible =
            #rows <= 0

        hud.EmptyLabel.Text =
            networkHealthy == true
            and "No active auction lots"
            or "Waiting for auction data"
    end

    for index = 1, 6 do

        local rowUi =
            hud.RowFrames
            and hud.RowFrames[index]
            or nil

        local row =
            rows[index]

        if type(rowUi) == "table" then

            if type(row) ~= "table" then

                rowUi.Holder.Visible =
                    false

            else

                rowUi.Holder.Visible =
                    true

                local decision =
                    readDecision(
                        row
                    )

                local displayName =
                    tostring(
                        row.Name
                        or "--"
                    )

                if HolyCleanText(
                    row.AmountText
                ) ~= "" then

                    displayName =
                        displayName
                        .. " "
                        .. tostring(
                            row.AmountText
                        )
                end

                rowUi.Name.Text =
                    displayName

                rowUi.Price.Text =
                    tostring(
                        row.PriceText
                        or HolyAuctionFormatMoney(
                            row.Price
                        )
                        or "--"
                    )

                rowUi.Stock.Text =
                    row.StockKnown == true
                    and (
                        tostring(
                            math.max(
                                0,
                                math.floor(
                                    tonumber(row.Stock)
                                    or 0
                                )
                            )
                        )
                    )
                    or "--"

                rowUi.Decision.Text =
                    decision.Text

                rowUi.Decision.TextColor3 =
                    decision.TextColor

                rowUi.DecisionPill.BackgroundColor3 =
                    decision.PillColor

                rowUi.DecisionPill.BackgroundTransparency =
                    decision.PillTransparency

                if decision.Selected == true then

                    rowUi.Holder.BackgroundColor3 =
                        Color3.fromRGB(
                            50,
                            21,
                            39
                        )

                    rowUi.Holder.BackgroundTransparency =
                        0.18

                    rowUi.Accent.Visible =
                        true

                    if typeof(rowUi.Stroke) == "Instance" then

                        rowUi.Stroke.Color =
                            Color3.fromRGB(
                                255,
                                79,
                                157
                            )

                        rowUi.Stroke.Transparency =
                            0.05

                        rowUi.Stroke.Thickness =
                            1.25
                    end

                    rowUi.Name.TextColor3 =
                        Color3.fromRGB(
                            255,
                            229,
                            242
                        )

                else

                    rowUi.Holder.BackgroundColor3 =
                        Color3.fromRGB(
                            15,
                            18,
                            24
                        )

                    rowUi.Holder.BackgroundTransparency =
                        decision.Inactive == true
                        and 0.48
                        or 0.32

                    rowUi.Accent.Visible =
                        false

                    if typeof(rowUi.Stroke) == "Instance" then

                        rowUi.Stroke.Color =
                            Color3.fromRGB(
                                54,
                                59,
                                72
                            )

                        rowUi.Stroke.Transparency =
                            decision.Inactive == true
                            and 0.55
                            or 0.32

                        rowUi.Stroke.Thickness =
                            1
                    end

                    rowUi.Name.TextColor3 =
                        decision.Inactive == true
                        and Color3.fromRGB(
                            143,
                            150,
                            163
                        )
                        or Color3.fromRGB(
                            236,
                            239,
                            245
                        )
                end

                rowUi.Price.TextColor3 =
                    decision.Inactive == true
                    and Color3.fromRGB(
                        143,
                        150,
                        163
                    )
                    or Color3.fromRGB(
                        225,
                        228,
                        235
                    )

                rowUi.Stock.TextColor3 =
                    decision.Inactive == true
                    and Color3.fromRGB(
                        118,
                        125,
                        139
                    )
                    or Color3.fromRGB(
                        155,
                        162,
                        175
                    )
            end
        end
    end

    if typeof(hud.MiniDot) == "Instance" then

        local schedulerState =
            tostring(
                HOLY_SHOP_STATE.AuctionSchedulerState
                or "Idle"
            )

        local pendingLotId =
            HolyCleanText(
                HOLY_SHOP_STATE.AuctionPendingLotId
            )

        local cooldownRemaining =
            math.max(
                0,
                (
                    tonumber(
                        HOLY_SHOP_STATE.AuctionNextBuyAt
                    )
                    or 0
                ) - os.clock()
            )

        local statusText =
            tostring(
                HOLY_SHOP_STATE.AuctionStatus
                or ""
            ):lower()

        local hasError =
            statusText:find(
                "error",
                1,
                true
            ) ~= nil
            or statusText:find(
                "failed",
                1,
                true
            ) ~= nil
            or statusText:find(
                "missing",
                1,
                true
            ) ~= nil
            or statusText:find(
                "could not",
                1,
                true
            ) ~= nil

        local dotColor =
            Color3.fromRGB(
                105,
                229,
                160
            )

        if hasError == true then

            -- Auctioneer error.
            dotColor =
                Color3.fromRGB(
                    241,
                    79,
                    90
                )

        elseif pendingLotId ~= ""
        or schedulerState == "Pending" then

            -- Purchase currently processing.
            dotColor =
                Color3.fromRGB(
                    244,
                    91,
                    151
                )

        elseif HOLY_SHOP_STATE.AuctionUnknownOutcome == true then

            -- A request was sent but its result was not received.
            dotColor =
                Color3.fromRGB(
                    239,
                    194,
                    102
                )

        elseif networkHealthy ~= true then

            -- Waiting for synchronized manifest and stock data.
            dotColor =
                Color3.fromRGB(
                    239,
                    194,
                    102
                )

        elseif HOLY_SHOP_STATE.AutoBuyAuctions ~= true then

            -- HUD is live, but automatic purchasing is disabled.
            dotColor =
                Color3.fromRGB(
                    112,
                    119,
                    133
                )

        elseif HOLY_SHOP_STATE.AuctionDryRun == true then

            -- Test Mode is enabled.
            dotColor =
                Color3.fromRGB(
                    173,
                    124,
                    244
                )

        elseif schedulerState == "Cooldown"
        and cooldownRemaining > 0 then

            -- Waiting for the account-wide Auctioneer cooldown.
            dotColor =
                Color3.fromRGB(
                    239,
                    194,
                    102
                )

        elseif readyCount > 0 then

            -- At least one selected auction is ready.
            dotColor =
                Color3.fromRGB(
                    105,
                    229,
                    160
                )

        else

            -- Auction monitoring is healthy and active.
            dotColor =
                Color3.fromRGB(
                    105,
                    229,
                    160
                )
        end

        hud.MiniDot.Visible =
            true

        hud.MiniDot.BackgroundColor3 =
            dotColor
    end

    return true
end

--==================================================
-- [2.6] SELL CORE
--==================================================

function HolySellResolvePacket(packetName)

    packetName =
        HolyCleanText(
            packetName
        )

    if packetName == "" then
        return nil
    end

    HOLY_SHOP_STATE.SellPacketCache =
        type(HOLY_SHOP_STATE.SellPacketCache) == "table"
        and HOLY_SHOP_STATE.SellPacketCache
        or {}

    if HOLY_SHOP_STATE.SellPacketCache[packetName] ~= nil then

        return HOLY_SHOP_STATE.SellPacketCache[packetName]
    end

    local networking =
        HolyShopRequireModule(
            "SharedModules.Networking"
        )

    local packet =
        type(networking) == "table"
        and type(networking.NPCS) == "table"
        and networking.NPCS[packetName]
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        HOLY_SHOP_STATE.SellPacketCache[packetName] =
            false

        return nil
    end

    HOLY_SHOP_STATE.SellPacketCache[packetName] =
        packet

    return packet
end

function HolySellFirePacket(packetName, ...)

    local packet =
        HolySellResolvePacket(
            packetName
        )

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false
    end

    local ok =
        pcall(function(...)

            packet:Fire(...)

        end, ...)

    return ok == true
end

--==================================================
-- [2.605] AUTO DAILY DEAL CORE
--==================================================

HOLY_DAILY_DEAL_RUNTIME =
    type(HOLY_DAILY_DEAL_RUNTIME) == "table"
    and HOLY_DAILY_DEAL_RUNTIME
    or {}

function HolyDailyDealEnsureState()

    HOLY_SHOP_STATE =
        type(HOLY_SHOP_STATE) == "table"
        and HOLY_SHOP_STATE
        or {}

    HOLY_SHOP_UI =
        type(HOLY_SHOP_UI) == "table"
        and HOLY_SHOP_UI
        or {}

    HOLY_DAILY_DEAL_RUNTIME =
        type(HOLY_DAILY_DEAL_RUNTIME) == "table"
        and HOLY_DAILY_DEAL_RUNTIME
        or {}

    HOLY_DAILY_DEAL_RUNTIME.InputErrors =
        type(HOLY_DAILY_DEAL_RUNTIME.InputErrors) == "table"
        and HOLY_DAILY_DEAL_RUNTIME.InputErrors
        or {}

    HOLY_SHOP_STATE.AutoDailyDealAll =
        HOLY_SHOP_STATE.AutoDailyDealAll == true

    HOLY_SHOP_STATE.DailyDealTriggerFruits =
        HolyShopSelectionArray(
            HOLY_SHOP_STATE.DailyDealTriggerFruits
            or {
                "All",
            }
        )

    if #HOLY_SHOP_STATE.DailyDealTriggerFruits <= 0 then

        HOLY_SHOP_STATE.DailyDealTriggerFruits = {
            "All",
        }
    end

    HOLY_SHOP_STATE.DailyDealMinStockMultiplier =
        tostring(
            HOLY_SHOP_STATE.DailyDealMinStockMultiplier
            or "2"
        )

    HOLY_SHOP_STATE.DailyDealMinFriendBoost =
        tostring(
            HOLY_SHOP_STATE.DailyDealMinFriendBoost
            or "0"
        )

    HOLY_SHOP_STATE.DailyDealMinInventoryValue =
        tostring(
            HOLY_SHOP_STATE.DailyDealMinInventoryValue
            or "0"
        )

    HOLY_SHOP_STATE.DailyDealMinValue =
        tostring(
            HOLY_SHOP_STATE.DailyDealMinValue
            or "0"
        )

    HOLY_SHOP_STATE.DailyDealAutoDisable =
        HOLY_SHOP_STATE.DailyDealAutoDisable ~= false

    HOLY_SHOP_STATE.DailyDealRequirePreview =
        HOLY_SHOP_STATE.DailyDealRequirePreview ~= false

    HOLY_SHOP_STATE.DailyDealStatus =
        tostring(
            HOLY_SHOP_STATE.DailyDealStatus
            or "Ready"
        )

    HOLY_SHOP_STATE.DailyDealLastStock =
        tostring(
            HOLY_SHOP_STATE.DailyDealLastStock
            or "Stock: --"
        )

    HOLY_SHOP_STATE.DailyDealLastPreview =
        tostring(
            HOLY_SHOP_STATE.DailyDealLastPreview
            or "Preview: --"
        )

    HOLY_SHOP_STATE.DailyDealLastResult =
        tostring(
            HOLY_SHOP_STATE.DailyDealLastResult
            or "Last: --"
        )

    return HOLY_SHOP_STATE
end

function HolyDailyDealFormatDecimal(value)

    local number =
        tonumber(value)

    if number == nil then
        return "0"
    end

    local text =
        string.format(
            "%.4f",
            number
        )

    text =
        text:gsub(
            "0+$",
            ""
        )

    text =
        text:gsub(
            "%.$",
            ""
        )

    if text == "" then
        text = "0"
    end

    return text
end

function HolyDailyDealFormatMoney(value)

    value =
        math.max(
            0,
            math.floor(
                tonumber(value)
                or 0
            )
        )

    if value >= 1000000000000 then

        return string.format(
            "%.2fT¢",
            value / 1000000000000
        )
    end

    if value >= 1000000000 then

        return string.format(
            "%.2fB¢",
            value / 1000000000
        )
    end

    if value >= 1000000 then

        return string.format(
            "%.2fM¢",
            value / 1000000
        )
    end

    if value >= 1000 then

        return string.format(
            "%.2fK¢",
            value / 1000
        )
    end

    return tostring(value)
        .. "¢"
end

function HolyDailyDealFormatDuration(seconds)

    seconds =
        math.max(
            0,
            math.floor(
                tonumber(seconds)
                or 0
            )
        )

    local hours =
        math.floor(seconds / 3600)

    local minutes =
        math.floor((seconds % 3600) / 60)

    local remaining =
        seconds % 60

    if hours > 0 then

        return tostring(hours)
            .. "h "
            .. tostring(minutes)
            .. "m"
    end

    if minutes > 0 then

        return tostring(minutes)
            .. "m "
            .. tostring(remaining)
            .. "s"
    end

    return tostring(remaining)
        .. "s"
end

function HolyDailyDealRefreshUI()

    HolyDailyDealEnsureState()

    if type(HolySniperSetLabel) ~= "function" then
        return false
    end

    HolySniperSetLabel(
        HOLY_SHOP_UI.DailyDealStatusLabel,
        "Daily: "
            .. tostring(HOLY_SHOP_STATE.DailyDealStatus or "Ready")
    )

    HolySniperSetLabel(
        HOLY_SHOP_UI.DailyDealStockLabel,
        tostring(HOLY_SHOP_STATE.DailyDealLastStock or "Stock: --")
    )

    HolySniperSetLabel(
        HOLY_SHOP_UI.DailyDealPreviewLabel,
        tostring(HOLY_SHOP_STATE.DailyDealLastPreview or "Preview: --")
    )

    HolySniperSetLabel(
        HOLY_SHOP_UI.DailyDealLastLabel,
        tostring(HOLY_SHOP_STATE.DailyDealLastResult or "Last: --")
    )

    return true
end

function HolyDailyDealSetStatus(status)

    HolyDailyDealEnsureState()

    HOLY_SHOP_STATE.DailyDealStatus =
