if type(HOLY_DAILY_DEAL_LIVE_RUNTIME) == "table" then

    HOLY_DAILY_DEAL_LIVE_RUNTIME.Token =
        nil

    HOLY_DAILY_DEAL_LIVE_RUNTIME.Running =
        false

    local oldSnapshotConnection =
        HOLY_DAILY_DEAL_LIVE_RUNTIME
            .SnapshotConnection

    if oldSnapshotConnection ~= nil then

        pcall(function()

            oldSnapshotConnection:Disconnect()
        end)
    end
end

HOLY_DAILY_DEAL_LIVE_RUNTIME = {
    Running = false,
    Token = nil,

    SnapshotConnection = nil,
    SnapshotConnected = false,
    LastSnapshotAt = 0,

    LastCycleKey = "",
    LastProcessedCycleKey = "",
    LastStockResult = nil,

    LastHash = "",
    LastSentAt = 0,
    LastResult = "Live: --",
    LastErrorAt = 0,
}

function HolyDailyDealLiveReadNumber(value)

    if type(value) == "number" then

        if value == value
        and value ~= math.huge
        and value ~= -math.huge then

            return value
        end

        return 0
    end

    local text =
        tostring(value or "")

    text =
        text:gsub(",", "")

    local raw =
        text:match(
            "%-?%d+%.?%d*"
        )

    local number =
        tonumber(raw)

    if number == nil then
        return 0
    end

    return number
end

function HolyDailyDealLiveNormalizeEntry(entry, fallbackName)

    local fallback =
        HolyCleanText(
            fallbackName
            or ""
        )

    if type(entry) ~= "table" then

        local multiplier =
            HolyDailyDealLiveReadNumber(
                entry
            )

        if fallback ~= ""
        and multiplier > 0 then

            return {
                Name =
                    fallback,

                Multiplier =
                    multiplier,

                Tier =
                    "",
            }
        end

        return nil
    end

    local name =
        HolyCleanText(
            entry.StockName
            or entry.stockName
            or entry.Name
            or entry.name
            or entry.FruitName
            or entry.fruitName
            or entry.Fruit
            or entry.fruit
            or entry.ItemName
            or entry.itemName
            or entry.DisplayName
            or entry.displayName
            or fallback
            or ""
        )

    if name == "" then
        return nil
    end

    local multiplier =
        HolyDailyDealLiveReadNumber(
            entry.Multiplier
            or entry.multiplier
            or entry.StockMultiplier
            or entry.stockMultiplier
            or entry.ValueMultiplier
            or entry.valueMultiplier
            or entry.DailyMultiplier
            or entry.dailyMultiplier
            or entry.Value
            or entry.value
            or entry.X
            or entry.x
            or 0
        )

    if multiplier <= 0 then
        return nil
    end

    return {
        Name =
            name,

        Multiplier =
            multiplier,

        Tier =
            HolyCleanText(
                entry.Tier
                or entry.tier
                or entry.Rarity
                or entry.rarity
                or ""
            ),
    }
end

function HolyDailyDealLiveBuildEntries(entries)

    local output =
        {}

    local seen =
        {}

    if type(entries) ~= "table" then
        return output
    end

    local function addEntry(entry, fallbackName)

        local normalized =
            HolyDailyDealLiveNormalizeEntry(
                entry,
                fallbackName
            )

        if type(normalized) ~= "table" then
            return false
        end

        local key =
            HolyCleanText(
                normalized.Name
            )
                :lower()
                :gsub("%s+", "")
                :gsub("[_%-%[%]%(%)%.'\"]", "")

        if key == "" then
            return false
        end

        if seen[key] == true then
            return false
        end

        seen[key] =
            true

        table.insert(
            output,
            normalized
        )

        return true
    end

    for stockFruitName, row in pairs(entries) do

        local fallbackName =
            type(stockFruitName) == "string"
            and stockFruitName
            or ""

        addEntry(
            row,
            fallbackName
        )
    end

    table.sort(output, function(a, b)

        local multiplierA =
            tonumber(a.Multiplier)
            or 0

        local multiplierB =
            tonumber(b.Multiplier)
            or 0

        if multiplierA ~= multiplierB then
            return multiplierA > multiplierB
        end

        return tostring(a.Name)
            < tostring(b.Name)
    end)

    return output
end

function HolyDailyDealLiveReadUnix(value)

    local number =
        HolyDailyDealLiveReadNumber(
            value
        )

    if number > 1000000000 then
        return math.floor(number)
    end

    return 0
end

function HolyDailyDealLiveReadSeconds(value)

    local number =
        HolyDailyDealLiveReadNumber(
            value
        )

    if number <= 0 then
        return 0
    end

    return math.floor(
        number
    )
end

function HolyDailyDealLiveServerNow()

    local success,
        result =
        pcall(function()

            return workspace:GetServerTimeNow()
        end)

    local serverNow =
        success == true
        and tonumber(result)
        or nil

    if serverNow ~= nil
    and serverNow > 1000000000
    and serverNow == serverNow
    and serverNow ~= math.huge
    and serverNow ~= -math.huge then

        return serverNow
    end

    return os.time()
end

function HolyDailyDealLiveResolveLastRefreshAt(stockResult)

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local directValues = {
        stockResult.LastRefreshAt,
        stockResult.lastRefreshAt,
        stockResult.LastRefreshUnix,
        stockResult.lastRefreshUnix,
        stockResult.last_refresh_unix,
        stockResult.LastRestockAt,
        stockResult.lastRestockAt,
        stockResult.LastRestockUnix,
        stockResult.lastRestockUnix,
    }

    for _, value in ipairs(directValues) do

        local unix =
            HolyDailyDealLiveReadUnix(
                value
            )

        if unix > 0 then
            return unix
        end
    end

    return 0
end

function HolyDailyDealLiveResolveNextRestockAt(stockResult)

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local directValues = {
        stockResult.NextRestockAt,
        stockResult.nextRestockAt,
        stockResult.NextRefreshAt,
        stockResult.nextRefreshAt,
        stockResult.NextRefreshUnix,
        stockResult.nextRefreshUnix,
        stockResult.next_refresh_unix,
        stockResult.UnixNextRestock,
        stockResult.unixNextRestock,
    }

    for _, value in ipairs(directValues) do

        local unix =
            HolyDailyDealLiveReadUnix(
                value
            )

        if unix > 0 then
            return unix
        end
    end

    local lastRefreshAt =
        HolyDailyDealLiveResolveLastRefreshAt(
            stockResult
        )

    local cycleSeconds =
        HolyDailyDealLiveReadSeconds(
            stockResult.CycleSeconds
            or stockResult.cycleSeconds
            or stockResult.cycle_seconds
        )

    if lastRefreshAt > 0
    and cycleSeconds > 0 then

        return lastRefreshAt
            + cycleSeconds
    end

    local secondsUntil =
        HolyDailyDealLiveReadSeconds(
            stockResult.NextRestockIn
            or stockResult.nextRestockIn
            or stockResult.RefreshIn
            or stockResult.refreshIn
            or stockResult.NextRefreshSeconds
            or stockResult.nextRefreshSeconds
            or stockResult.RefreshSeconds
            or stockResult.refreshSeconds
            or stockResult.SecondsUntilRefresh
            or stockResult.secondsUntilRefresh
            or stockResult.seconds_until_refresh
        )

    if secondsUntil > 0 then

        return math.floor(
            HolyDailyDealLiveServerNow()
            + secondsUntil
        )
    end

    return 0
end

function HolyDailyDealLiveBuildStockFingerprint(stockResult)

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local entries =
        HolyDailyDealLiveBuildEntries(
            stockResult.entries
            or stockResult.Entries
            or stockResult.Stock
            or stockResult.stock
            or {}
        )

    if #entries <= 0 then
        return ""
    end

    local parts =
        {}

    for _, entry in ipairs(entries) do

        parts[
            #parts + 1
        ] =
            HolyCleanText(
                entry.Name
            ):lower()
            .. ":"
            .. string.format(
                "%.9f",
                tonumber(entry.Multiplier)
                or 0
            )
            .. ":"
            .. HolyCleanText(
                entry.Tier
            ):lower()
    end

    return table.concat(
        parts,
        "|"
    )
end

function HolyDailyDealLiveBuildRestockKey(stockResult)

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local explicitKey =
        HolyCleanText(
            stockResult.RestockKey
            or stockResult.restockKey
            or stockResult.StockKey
            or stockResult.stockKey
            or stockResult.CycleKey
            or stockResult.cycleKey
            or ""
        )

    if explicitKey ~= "" then
        return explicitKey
    end

    local lastRefreshAt =
        HolyDailyDealLiveResolveLastRefreshAt(
            stockResult
        )

    if lastRefreshAt > 0 then

        return tostring(
            lastRefreshAt
        )
    end

    local nextRefreshAt =
        HolyDailyDealLiveResolveNextRestockAt(
            stockResult
        )

    if nextRefreshAt > 0 then

        return tostring(
            nextRefreshAt
        )
    end

    local fingerprint =
        HolyDailyDealLiveBuildStockFingerprint(
            stockResult
        )

    if fingerprint ~= "" then

        return "stock:"
            .. fingerprint
    end

    return ""
end

function HolyDailyDealLiveBuildHash(stockResult, entries)

    local parts =
        {}

    for _, entry in ipairs(entries or {}) do

        table.insert(
            parts,
            HolyCleanText(entry.Name)
            .. ":"
            .. string.format(
                "%.4f",
                tonumber(entry.Multiplier)
                or 0
            )
        )
    end

    return HolyDailyDealLiveBuildRestockKey(
        stockResult
    )
        .. "|"
        .. table.concat(
            parts,
            "|"
        )
end

function HolyDailyDealLivePostNow(stockResult, source)

    local runtime =
        HOLY_DAILY_DEAL_LIVE_RUNTIME

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local entries =
        HolyDailyDealLiveBuildEntries(
            stockResult.entries
            or stockResult.Entries
            or stockResult.Stock
            or stockResult.stock
            or {}
        )

    if #entries <= 0 then

        runtime.LastResult =
            "Live: no entries"

        return false,
            "no entries"
    end

    local reportHash =
        HolyDailyDealLiveBuildHash(
            stockResult,
            entries
        )

    local nowClock =
        os.clock()

    if runtime.LastHash == reportHash
    and nowClock - (
        tonumber(runtime.LastSentAt)
        or 0
    ) < 20 then

        return false,
            "duplicate"
    end

    runtime.LastHash =
        reportHash

    runtime.LastSentAt =
        nowClock

    local nextRestockAt =
        HolyDailyDealLiveResolveNextRestockAt(
            stockResult
        )

    local payload = {
        Key =
            SERVER_FINDER_API_KEY,

        PlaceId =
            game.PlaceId,

        JobId =
            game.JobId,

        Reporter =
            LocalPlayer
            and LocalPlayer.Name
            or "",

        Source =
            tostring(source or "client"),

        RestockKey =
            HolyDailyDealLiveBuildRestockKey(
                stockResult
            ),

        NextRestockAt =
            nextRestockAt,

        NextRefreshAt =
            nextRestockAt,

        Entries =
            entries,
    }

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        runtime.LastResult =
            "Live: encode failed"

        return false,
            "encode failed"
    end

    local requestFunction =
        HolyGetRequestFunction()

    if type(requestFunction) ~= "function" then

        runtime.LastResult =
            "Live: no request"

        return false,
            "no request"
    end

    local requestOk,
        response =
        pcall(function()

            return requestFunction({
                Url =
                    DAILY_DEAL_REPORT_API_URL,

                Method =
                    "POST",

                Headers = {
                    ["Content-Type"] =
                        "application/json",

                    ["Accept"] =
                        "application/json",

                    ["x-api-key"] =
                        SERVER_FINDER_API_KEY,
                },

                Body =
                    encoded,
            })
        end)

    if requestOk ~= true then

        runtime.LastResult =
            "Live: request failed"

        local now =
            os.clock()

        if now - (
            tonumber(runtime.LastErrorAt)
            or 0
        ) > 15 then

            runtime.LastErrorAt =
                now

            warn(
                "[HOLY DAILY DEAL LIVE]",
                "request failed:",
                tostring(response)
            )
        end

        return false,
            tostring(response)
    end

    local statusCode =
        nil

    local body =
        ""

    if type(response) == "table" then

        statusCode =
            tonumber(
                response.StatusCode
                or response.status_code
                or response.Status
                or response.status
            )

        body =
            tostring(
                response.Body
                or response.body
                or response.ResponseBody
                or response.responseBody
                or ""
            )

    elseif type(response) == "string" then

        body =
            response
    end

    if statusCode ~= nil
    and statusCode ~= 200
    and statusCode ~= 204 then

        runtime.LastResult =
            "Live: HTTP "
            .. tostring(statusCode)

        warn(
            "[HOLY DAILY DEAL LIVE]",
            runtime.LastResult,
            body
        )

        return false,
            runtime.LastResult
    end

    local decoded =
        nil

    if body ~= "" then

        pcall(function()

            decoded =
                HttpService:JSONDecode(
                    body
                )
        end)
    end

    if type(decoded) == "table"
    and decoded.ok == false then

        runtime.LastResult =
            "Live: "
            .. tostring(decoded.error or "failed")

        warn(
            "[HOLY DAILY DEAL LIVE]",
            runtime.LastResult
        )

        return false,
            runtime.LastResult
    end

    local top =
        entries[1]

    runtime.LastResult =
        "Live: sent "
        .. tostring(#entries)
        .. " fruit(s)"

    if type(top) == "table" then

        runtime.LastResult =
            runtime.LastResult
            .. " | Top: "
            .. tostring(top.Name)
            .. " x"
            .. tostring(
                math.floor(
                    (
                        tonumber(top.Multiplier)
                        or 0
                    ) * 100
                    + 0.5
                ) / 100
            )
    end

    print(
        "[HOLY DAILY DEAL LIVE]",
        runtime.LastResult
    )

    return true,
        runtime.LastResult
end

function HolyDailyDealSendLiveReportAsync(stockResult, source)

    task.spawn(function()

        local ok,
            success,
            reason =
            pcall(function()

                return HolyDailyDealLivePostNow(
                    stockResult,
                    source
                )
            end)

        if ok ~= true then

            HOLY_DAILY_DEAL_LIVE_RUNTIME.LastResult =
                "Live: error"

            warn(
                "[HOLY DAILY DEAL LIVE]",
                tostring(success)
            )

            return
        end

        return success,
            reason
    end)

    return true
end

function HolyDailyDealLiveResolveWait(stockResult)

    stockResult =
        type(stockResult) == "table"
        and stockResult
        or {}

    local nextRestockAt =
        HolyDailyDealLiveResolveNextRestockAt(
            stockResult
        )

    if nextRestockAt <= 0 then

        return 30
    end

    local seconds =
        nextRestockAt
        - HolyDailyDealLiveServerNow()
        + 1

    if seconds <= 0 then

        return 1
    end

    return math.max(
        1,
        seconds
    )
end

function HolyDailyDealSetNextWait(seconds)

    HOLY_DAILY_DEAL_RUNTIME.NextWait =
        math.clamp(
            tonumber(seconds)
            or 10,
            3,
            60
        )

    return HOLY_DAILY_DEAL_RUNTIME.NextWait
end

function HolyDailyDealGetNextWait()

    return math.clamp(
        tonumber(HOLY_DAILY_DEAL_RUNTIME.NextWait)
        or 10,
        3,
        60
    )
end

function HolyDailyDealEvaluate(mode)

    HolyDailyDealEnsureState()

    mode =
        tostring(mode or "check")

    HolyDailyDealSetNextWait(
        10
    )

    if mode == "auto"
    and HolyDailyDealTextBoxFocused() == true then

        HolyDailyDealSetStatus(
            "Paused while typing"
        )

        HolyDailyDealSetNextWait(
            3
        )

        return false,
            "typing"
    end

    local settingsOk,
        settings =
        HolyDailyDealValidateSettings()

    if settingsOk ~= true then

        HolyDailyDealSetStatus(
            "⚠️ "
            .. tostring(settings)
        )

        HolyDailyDealSetNextWait(
            3
        )

        return false,
            tostring(settings)
    end

    if mode ~= "check" then

        local blocked =
            HolyDailyDealOtherSystemBlocked()

        if blocked ~= "" then

            HolyDailyDealSetStatus(
                "Blocked: "
                .. blocked
            )

            HolyDailyDealSetNextWait(
                8
            )

            return false,
                blocked
        end
    end

    HolyDailyDealSetStatus(
        "Checking stock..."
    )

    local stockResult,
        stockOk,
        stockReason =
        HolyDailyDealFireFruitStockRequest()

    if stockOk ~= true
    or type(stockResult) ~= "table"
    or type(stockResult.entries) ~= "table" then

        HolyDailyDealSetStatus(
            "Stock check failed"
        )

        HolyDailyDealSetStockText(
            "Stock: "
            .. tostring(stockReason or "missing")
        )

        return false,
            "stock failed"
    end

    if type(HolyDailyDealLiveHandleStockResult)
    == "function" then

        HolyDailyDealLiveHandleStockResult(
            stockResult,
            mode
        )

    else

        HolyDailyDealSendLiveReportAsync(
            stockResult,
            mode
        )
    end

    local best,
        triggerReason =
        HolyDailyDealFindBestTrigger(
            stockResult.entries
        )

    if best == nil then

        HolyDailyDealSetStatus(
            tostring(triggerReason)
        )

        HolyDailyDealSetStockText(
            "Stock: no trigger fruit"
        )

        return false,
            tostring(triggerReason)
    end

    HolyDailyDealSetStockText(
        "Stock: "
        .. tostring(best.StockName)
        .. " X"
        .. HolyDailyDealFormatDecimal(best.Multiplier)
        .. " / Need X"
        .. HolyDailyDealFormatDecimal(settings.MinStockMultiplier)
    )

    if tonumber(best.Multiplier) < tonumber(settings.MinStockMultiplier) then

        HolyDailyDealSetStatus(
            "Waiting stock X"
            .. HolyDailyDealFormatDecimal(settings.MinStockMultiplier)
        )

        local waitSeconds =
            30

        if tonumber(stockResult.nextRefreshUnix)
        and tonumber(stockResult.server_now_unix) then

            waitSeconds =
                tonumber(stockResult.nextRefreshUnix)
                - tonumber(stockResult.server_now_unix)
        end

        HolyDailyDealSetNextWait(
            waitSeconds
        )

        return false,
            "stock too low"
    end

    local boost,
        boostText =
        HolyDailyDealReadFriendBoost()

    if boost < settings.MinFriendBoost then

        HolyDailyDealSetStatus(
            "Waiting boost "
            .. HolyDailyDealFormatDecimal(settings.MinFriendBoost)
            .. "%"
        )

        HolyDailyDealSetNextWait(
            20
        )

        return false,
            "boost too low"
    end

    HolyDailyDealSetStatus(
        "Checking availability..."
    )

    local checkResult,
        checkOk,
        checkReason =
        HolyDailyDealFireNpcPacket(
            "CheckDailyDeal"
        )

    if checkOk ~= true
    or type(checkResult) ~= "table" then

        HolyDailyDealSetStatus(
            "Daily check failed"
        )

        return false,
            tostring(checkReason or "check failed")
    end

    if checkResult.Available ~= true then

        local remaining =
            tonumber(checkResult.TimeRemaining)
            or 0

        HolyDailyDealSetStatus(
            "Cooldown "
            .. HolyDailyDealFormatDuration(
                remaining
            )
        )

        HolyDailyDealSetPreviewText(
            "Preview: skipped, cooldown"
        )

        HolyDailyDealSetNextWait(
            remaining
        )

        return false,
            "cooldown"
    end

    HolyDailyDealSetStatus(
        "Checking preview..."
    )

    local preview,
        previewOk,
        previewReason =
        HolyDailyDealFireNpcPacket(
            "PreviewSellAll"
        )

    if previewOk ~= true
    or type(preview) ~= "table" then

        HolyDailyDealSetStatus(
            "Preview failed"
        )

        HolyDailyDealSetPreviewText(
            "Preview: "
            .. tostring(previewReason or "failed")
        )

        return false,
            "preview failed"
    end

    local fruitCount =
        tonumber(preview.FruitCount)
        or 0

    local expectedDaily,
        baseValue,
        dailyMultiplier =
        HolyDailyDealExpectedValue(
            preview
        )

    HolyDailyDealSetPreviewText(
        "Preview: "
        .. tostring(fruitCount)
        .. " fruits | Inv "
        .. HolyDailyDealFormatMoney(
            baseValue
        )
        .. " → Daily "
        .. HolyDailyDealFormatMoney(
            expectedDaily
        )
    )

    if fruitCount <= 0 then

        HolyDailyDealSetStatus(
            "Preview has no fruit"
        )

        return false,
            "no preview fruit"
    end

    if settings.MinInventoryValue > 0
    and baseValue < settings.MinInventoryValue then

        HolyDailyDealSetStatus(
            "Inventory too low"
        )

        HolyDailyDealSetNextWait(
            20
        )

        return false,
            "inventory too low"
    end

    if settings.MinValue > 0
    and expectedDaily < settings.MinValue then

        HolyDailyDealSetStatus(
            "Daily payout too low"
        )

        HolyDailyDealSetNextWait(
            20
        )

        return false,
            "daily payout too low"
    end

    HolyDailyDealSetStatus(
        "Ready"
    )

    return true,
        "ready",
        {
            Settings =
                settings,

            Stock =
                stockResult,

            Best =
                best,

            FriendBoost =
                boost,

            FriendBoostText =
                boostText,

            Check =
                checkResult,

            Preview =
                preview,

            ExpectedDaily =
                expectedDaily,

            BaseValue =
                baseValue,

            DailyMultiplier =
                dailyMultiplier,
        }
end

function HolyDailyDealSyncAutoToggle()

    local options =
        HOLY_DEV_LIBRARY
        and HOLY_DEV_LIBRARY.Options
        or Options

    local toggle =
        type(options) == "table"
        and options.HolyShopAutoDailyDealAll
        or nil

    if type(toggle) == "table"
    and type(toggle.SetValue) == "function" then

        pcall(function()

            toggle:SetValue(
                HOLY_SHOP_STATE.AutoDailyDealAll == true,
                true
            )
        end)
    end

    return true
end

function HolyDailyDealRunUseAll(source)

    HolyDailyDealEnsureState()

    source =
        tostring(source or "manual")

    if HOLY_SHOP_STATE.DailyDealManualBusy == true then

        HolyDailyDealSetStatus(
            "Busy"
        )

        return false,
            "busy"
    end

    HOLY_SHOP_STATE.DailyDealManualBusy =
        true

    local success =
        false

    local reason =
        "unknown"

    local ok,
        err =
        pcall(function()

            local ready,
                readyReason,
                context =
                HolyDailyDealEvaluate(
                    source == "auto"
                    and "auto"
                    or "manual"
                )

            if ready ~= true then

                reason =
                    tostring(readyReason or "not ready")

                return
            end

            HolyDailyDealSetStatus(
                "Ready → selling"
            )

            local beforeMoney =
                type(HolySniperReadSheckles) == "function"
                and HolySniperReadSheckles()
                or nil

            local result,
                fireOk,
                fireReason =
                HolyDailyDealFireNpcPacket(
                    "UseDailyDealAll"
                )

            task.wait(
                0.25
            )

            local afterMoney =
                type(HolySniperReadSheckles) == "function"
                and HolySniperReadSheckles()
                or nil

            local moneyDelta =
                beforeMoney ~= nil
                and afterMoney ~= nil
                and afterMoney - beforeMoney
                or 0

            result =
                type(result) == "table"
                and result
                or {}

            local soldCount =
                tonumber(result.SoldCount)
                or 0

            local sellPrice =
                tonumber(result.SellPrice)
                or moneyDelta
                or 0

            if fireOk == true
            and (
                result.Success == true
                or soldCount > 0
                or moneyDelta > 0
            ) then

                success =
                    true

                reason =
                    "sold"

                HolyDailyDealSetLastText(
                    "Last: Sold "
                    .. tostring(soldCount)
                    .. " for "
                    .. HolyDailyDealFormatMoney(
                        sellPrice
                    )
                )

                if HOLY_SHOP_STATE.DailyDealAutoDisable == true then

                    HOLY_SHOP_STATE.AutoDailyDealAll =
                        false

                    HOLY_SHOP_STATE.DailyDealToken =
                        nil

                    HOLY_SHOP_STATE.DailyDealWorkerRunning =
                        false

                    HolySaveShopSettings()

                    HolyDailyDealSyncAutoToggle()
                end

                HolyDailyDealSetStatus(
                    "Sold "
                    .. tostring(soldCount)
                    .. " for "
                    .. HolyDailyDealFormatMoney(
                        sellPrice
                    )
                )

                if type(HolyNotify) == "function" then

                    HolyNotify(
                        "HOLY Daily Deal",
                        "Sold "
                        .. tostring(soldCount)
                        .. " fruit(s) for "
                        .. HolyDailyDealFormatMoney(sellPrice)
                        .. ".",
                        4
                    )
                end

            else

                reason =
                    tostring(fireReason or "sale failed")

                HolyDailyDealSetStatus(
                    "Failed: "
                    .. reason
                )

                HolyDailyDealSetLastText(
                    "Last: failed"
                )
            end
        end)

    if ok ~= true then

        reason =
            tostring(err)

        HolyDailyDealSetStatus(
            "Error: "
            .. reason
        )
    end

    HOLY_SHOP_STATE.DailyDealManualBusy =
        false

    return success,
        reason
end

function HolyDailyDealCheckNow()

    task.spawn(function()

        local ready,
            reason =
            HolyDailyDealEvaluate(
                "check"
            )

        if ready == true then

            HolyDailyDealSetStatus(
                "Ready / check only"
            )

        else

            HolyDailyDealSetLastText(
                "Last check: "
                .. tostring(reason)
            )
        end
    end)

    return true
end

function HolyDailyDealUseOnce()

    task.spawn(function()

        HolyDailyDealRunUseAll(
            "manual"
        )
    end)

    return true
end

function HolyDailyDealStopWorker(reason)

    HolyDailyDealEnsureState()

    HOLY_SHOP_STATE.AutoDailyDealAll =
        false

    HOLY_SHOP_STATE.DailyDealToken =
        nil

    HOLY_SHOP_STATE.DailyDealWorkerRunning =
        false

    HolySaveShopSettings()

    HolyDailyDealSetStatus(
        tostring(reason or "Off")
    )

    return true
end

function HolyDailyDealStartWorker(reason)

    HolyDailyDealEnsureState()

    if HOLY_SHOP_STATE.AutoDailyDealAll ~= true then
        return false
    end

    if HOLY_SHOP_STATE.DailyDealWorkerRunning == true then
        return false
    end

    local token =
        {}

    HOLY_SHOP_STATE.DailyDealToken =
        token

    HOLY_SHOP_STATE.DailyDealWorkerRunning =
        true

    HolyDailyDealSetStatus(
        "Starting..."
    )

    task.spawn(function()

        while HOLY_SHOP_STATE.AutoDailyDealAll == true
        and HOLY_SHOP_STATE.DailyDealToken == token do

            local ok,
                err =
                pcall(function()

                    HolyDailyDealRunUseAll(
                        "auto"
                    )
                end)

            if ok ~= true then

                HolyDailyDealSetStatus(
                    "Error: "
                    .. tostring(err)
                )

                HolyDailyDealSetNextWait(
                    10
                )
            end

            if HOLY_SHOP_STATE.AutoDailyDealAll ~= true then
                break
            end

            task.wait(
                HolyDailyDealGetNextWait()
            )
        end

        if HOLY_SHOP_STATE.DailyDealToken == token then

            HOLY_SHOP_STATE.DailyDealWorkerRunning =
                false

            HOLY_SHOP_STATE.DailyDealToken =
                nil
        end
    end)

    return true
end

function HolyDailyDealSetAutoEnabled(value, reason)

    HolyDailyDealEnsureState()

    HOLY_SHOP_STATE.AutoDailyDealAll =
        value == true

    HolySaveShopSettings()

    if HOLY_SHOP_STATE.AutoDailyDealAll == true then

        return HolyDailyDealStartWorker(
            reason or "toggle on"
        )
    end

    return HolyDailyDealStopWorker(
        reason or "Off"
    )
end

function HolyDailyDealLiveStopWorker(reason)

    local runtime =
        HOLY_DAILY_DEAL_LIVE_RUNTIME

    runtime.Token =
        nil

    runtime.Running =
        false

    local snapshotConnection =
        runtime.SnapshotConnection

    runtime.SnapshotConnection =
        nil

    runtime.SnapshotConnected =
        false

    if snapshotConnection ~= nil then

        pcall(function()

            snapshotConnection:Disconnect()
        end)
    end

    runtime.LastResult =
        tostring(reason or "Live: stopped")

    return true
end

--==================================================
-- [2.60.1] FRUIT MULTIPLIER WEBHOOKS
--==================================================

local WEBHOOK_SETTINGS_FILE =
    UI_SETTINGS_FOLDER
    .. "/HolyPremiumWebhookSettings.json"

if type(HOLY_WEBHOOK_RUNTIME) == "table" then

    HOLY_WEBHOOK_RUNTIME.Token = nil
    HOLY_WEBHOOK_RUNTIME.Sending = false
end

HOLY_WEBHOOK_STATE = {
    Enabled = false,
    Url = "",
    PingText = "",
    Filters = {},
    SelectedFilterKey = "",
    LastNotifiedRestockKey = "",
}

HOLY_WEBHOOK_RUNTIME = {
    Token = {},
    Queue = {},
    Sending = false,
    UpdatingUI = false,
    DraftFruit = "",
    DraftMinimum = "2",
    LastStockResult = nil,
    PendingRestockKeys = {},
}

HOLY_WEBHOOK_UI = {}

function HolyWebhookReadMultiplier(value)

    local number = nil

    if type(value) == "number" then

        number = value

    else

        local text =
            HolyCleanText(value)
                :lower()
                :gsub("%s+", "")
                :gsub(",", ".")
                :gsub("^x", "")

        number = tonumber(text)
    end

    if number == nil
    or number <= 0
    or number ~= number
    or number == math.huge
    or number == -math.huge then

        return nil
    end

    return math.floor(
        math.clamp(number, 0.01, 100) * 100
        + 0.5
    ) / 100
end

function HolyWebhookFormatMultiplier(value)

    return string.format(
        "%.2f",
        HolyWebhookReadMultiplier(value) or 0
    )
end

function HolyWebhookFilterKey(value)

    return HolyDailyDealNameKey(value)
end

function HolyWebhookNormalizeFilters(value)

    local byKey = {}

    if type(value) == "table" then

        for key, row in pairs(value) do

            local name = ""
            local minimum = nil

            if type(row) == "table" then

                name = HolyCleanText(
                    row.Name
                    or row.Fruit
                    or row.FruitName
                    or (
                        type(key) == "string"
                        and key
                        or ""
                    )
                )

                minimum = HolyWebhookReadMultiplier(
                    row.Minimum
                    or row.MinMultiplier
                    or row.Multiplier
                    or row.Value
                )

            elseif type(key) == "string" then

                name = HolyCleanText(key)
                minimum = HolyWebhookReadMultiplier(row)
            end

            local normalizedKey =
                HolyWebhookFilterKey(name)

            if normalizedKey ~= ""
            and normalizedKey ~= "all"
            and minimum ~= nil then

                byKey[normalizedKey] = {
                    Name = name,
                    Minimum = minimum,
                }
            end
        end
    end

    local output = {}

    for _, entry in pairs(byKey) do

        output[#output + 1] = entry
    end

    table.sort(output, function(a, b)

        return tostring(a.Name):lower()
            < tostring(b.Name):lower()
    end)

    return output
end

function HolyWebhookEnsureState()

    HOLY_WEBHOOK_STATE =
        type(HOLY_WEBHOOK_STATE) == "table"
        and HOLY_WEBHOOK_STATE
        or {}

    HOLY_WEBHOOK_RUNTIME =
        type(HOLY_WEBHOOK_RUNTIME) == "table"
        and HOLY_WEBHOOK_RUNTIME
        or {}

    HOLY_WEBHOOK_UI =
        type(HOLY_WEBHOOK_UI) == "table"
        and HOLY_WEBHOOK_UI
        or {}

    HOLY_WEBHOOK_STATE.Enabled =
        HOLY_WEBHOOK_STATE.Enabled == true

    HOLY_WEBHOOK_STATE.Url =
        HolyCleanText(HOLY_WEBHOOK_STATE.Url)

    HOLY_WEBHOOK_STATE.PingText =
        tostring(
            HOLY_WEBHOOK_STATE.PingText
            or ""
        )

    HOLY_WEBHOOK_STATE.Filters =
        HolyWebhookNormalizeFilters(
            HOLY_WEBHOOK_STATE.Filters
        )

    HOLY_WEBHOOK_STATE.SelectedFilterKey =
        tostring(
            HOLY_WEBHOOK_STATE.SelectedFilterKey
            or ""
        )

    HOLY_WEBHOOK_STATE.LastNotifiedRestockKey =
        tostring(
            HOLY_WEBHOOK_STATE.LastNotifiedRestockKey
            or ""
        )

    HOLY_WEBHOOK_RUNTIME.Queue =
        type(HOLY_WEBHOOK_RUNTIME.Queue) == "table"
        and HOLY_WEBHOOK_RUNTIME.Queue
        or {}

    HOLY_WEBHOOK_RUNTIME.PendingRestockKeys =
        type(HOLY_WEBHOOK_RUNTIME.PendingRestockKeys) == "table"
        and HOLY_WEBHOOK_RUNTIME.PendingRestockKeys
        or {}

    HOLY_WEBHOOK_RUNTIME.DraftFruit =
        tostring(
            HOLY_WEBHOOK_RUNTIME.DraftFruit
            or ""
        )

    HOLY_WEBHOOK_RUNTIME.DraftMinimum =
        tostring(
            HOLY_WEBHOOK_RUNTIME.DraftMinimum
            or "2"
        )

    return HOLY_WEBHOOK_STATE
end

function HolyWebhookValidateUrl(value)

    local url = HolyCleanText(value)
    local lower = url:lower()

    local prefixes = {
        "https://discord.com/api/webhooks/",
        "https://canary.discord.com/api/webhooks/",
        "https://ptb.discord.com/api/webhooks/",
        "https://discordapp.com/api/webhooks/",
    }

    for _, prefix in ipairs(prefixes) do

        if lower:sub(1, #prefix) == prefix then

            local tail = url:sub(#prefix + 1)

            if tail:match("^%d+/.+") then

                return true, url
            end
        end
    end

    return false,
        "Enter a valid Discord webhook URL."
end

function HolySaveWebhookSettings()

    HolyWebhookEnsureState()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local payload = {
        Enabled = HOLY_WEBHOOK_STATE.Enabled == true,
        Url = tostring(HOLY_WEBHOOK_STATE.Url or ""),

        PingText = tostring(
            HOLY_WEBHOOK_STATE.PingText
            or ""
        ),

        Filters = HolyWebhookNormalizeFilters(
            HOLY_WEBHOOK_STATE.Filters
        ),

        LastNotifiedRestockKey = tostring(
            HOLY_WEBHOOK_STATE.LastNotifiedRestockKey
            or ""
        ),
    }

    local encodeOk, encoded = pcall(function()

        return HttpService:JSONEncode(payload)
    end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        return false
    end

    local writeOk = pcall(function()

        writefile(
            WEBHOOK_SETTINGS_FILE,
            encoded
        )
    end)

    return writeOk == true
end

function HolyLoadWebhookSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists = false

    pcall(function()

        exists = isfile(
            WEBHOOK_SETTINGS_FILE
        )
    end)

    if exists ~= true then
        return false
    end

    local readOk, raw = pcall(function()

        return readfile(
            WEBHOOK_SETTINGS_FILE
        )
    end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then

        return false
    end

    local decodeOk, data = pcall(function()

        return HttpService:JSONDecode(raw)
    end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return false
    end

    HOLY_WEBHOOK_STATE.Url = HolyCleanText(
        data.Url
        or data.WebhookUrl
        or ""
    )

    HOLY_WEBHOOK_STATE.PingText =
        tostring(
            data.PingText
            or data.MentionText
            or data.Ping
            or ""
        )

    HOLY_WEBHOOK_STATE.Filters =
        HolyWebhookNormalizeFilters(
            data.Filters
            or data.FruitFilters
        )

    HOLY_WEBHOOK_STATE.LastNotifiedRestockKey =
        tostring(
            data.LastNotifiedRestockKey
            or ""
        )

    local validUrl =
        HolyWebhookValidateUrl(
            HOLY_WEBHOOK_STATE.Url
        )

    HOLY_WEBHOOK_STATE.Enabled =
        data.Enabled == true
        and validUrl == true

    HolyWebhookEnsureState()

    return true
end

function HolyWebhookGetFruitDropdownValues()

    HolyWebhookEnsureState()

    local values = {}
    local seen = {}

    local function add(value)

        local name = HolyCleanText(value)
        local key = HolyWebhookFilterKey(name)

        if name == ""
        or key == ""
        or key == "all"
        or seen[key] == true then

            return
        end

        seen[key] = true
        values[#values + 1] = name
    end

    local ok, available = pcall(function()

        return HolyDailyDealGetTriggerFruitDropdownValues()
    end)

    if ok == true
    and type(available) == "table" then

        for _, fruitName in ipairs(available) do

            add(fruitName)
        end
    end

    for _, entry in ipairs(
        HOLY_WEBHOOK_STATE.Filters
    ) do

        add(entry.Name)
    end

    table.sort(values, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    if #values <= 0 then

        values[1] = "Mushroom"
    end

    return values
end

function HolyWebhookGetFilter(value)

    HolyWebhookEnsureState()

    local wantedKey =
        HolyWebhookFilterKey(value)

    for _, entry in ipairs(
        HOLY_WEBHOOK_STATE.Filters
    ) do

        if HolyWebhookFilterKey(entry.Name)
            == wantedKey then

            return entry
        end
    end

    return nil
end

function HolyWebhookFilterDisplay(entry)

    return tostring(entry.Name)
        .. " ≥ x"
        .. HolyWebhookFormatMultiplier(
            entry.Minimum
        )
end

function HolyWebhookGetFilterDropdownValues()

    HolyWebhookEnsureState()

    local values = {}
    local displayMap = {}

    for _, entry in ipairs(
        HOLY_WEBHOOK_STATE.Filters
    ) do

        local display =
            HolyWebhookFilterDisplay(entry)

        values[#values + 1] = display

        displayMap[display] =
            HolyWebhookFilterKey(entry.Name)
    end

    HOLY_WEBHOOK_RUNTIME.FilterDisplayMap =
        displayMap

    if #values <= 0 then

        values[1] = "No filters added"
    end

    return values
end

function HolyWebhookReadSingleValue(value)

    if type(value) ~= "table" then

        return HolyCleanText(value)
    end

    for key, enabled in pairs(value) do

        if enabled == true then

            return HolyCleanText(key)
        end
    end

    return HolyCleanText(value[1])
end

function HolyWebhookPopulateFilterEditor(entry)

    if type(entry) ~= "table" then
        return false
    end

    HolyWebhookEnsureState()

    HOLY_WEBHOOK_RUNTIME.DraftFruit =
        tostring(entry.Name)

    HOLY_WEBHOOK_RUNTIME.DraftMinimum =
        HolyWebhookFormatMultiplier(
            entry.Minimum
        )

    HOLY_WEBHOOK_RUNTIME.UpdatingUI = true

    pcall(function()

        local dropdown =
            HOLY_WEBHOOK_UI.FruitDropdown

        if type(dropdown) == "table"
        and type(dropdown.SetValue) == "function" then

            dropdown:SetValue(
                HOLY_WEBHOOK_RUNTIME.DraftFruit,
                true
            )
        end
    end)

    pcall(function()

        local input =
            HOLY_WEBHOOK_UI.MinimumInput

        if type(input) == "table"
        and type(input.SetValue) == "function" then

            input:SetValue(
                HOLY_WEBHOOK_RUNTIME.DraftMinimum,
                true
            )
        end
    end)

    task.defer(function()

        HOLY_WEBHOOK_RUNTIME.UpdatingUI = false
    end)

    return true
end

function HolyWebhookRefreshFilterDropdown(selectKey)

    HolyWebhookEnsureState()

    local dropdown =
        HOLY_WEBHOOK_UI.FilterDropdown

    if type(dropdown) ~= "table" then
        return false
    end

    local values =
        HolyWebhookGetFilterDropdownValues()

    local selectedEntry = nil

    local wantedKey = tostring(
        selectKey
        or HOLY_WEBHOOK_STATE.SelectedFilterKey
        or ""
    )

    for _, entry in ipairs(
        HOLY_WEBHOOK_STATE.Filters
    ) do

        if HolyWebhookFilterKey(entry.Name)
            == wantedKey then

            selectedEntry = entry
            break
        end
    end

    if selectedEntry == nil then

        selectedEntry =
            HOLY_WEBHOOK_STATE.Filters[1]
    end

    local selectedDisplay =
        type(selectedEntry) == "table"
        and HolyWebhookFilterDisplay(selectedEntry)
        or "No filters added"

    HOLY_WEBHOOK_STATE.SelectedFilterKey =
        type(selectedEntry) == "table"
        and HolyWebhookFilterKey(selectedEntry.Name)
        or ""

    HOLY_WEBHOOK_RUNTIME.UpdatingUI = true

    pcall(function()

        if type(dropdown.SetValues) == "function" then

            dropdown:SetValues(values)

        elseif type(dropdown.SetItems) == "function" then

            dropdown:SetItems(values)
        end
    end)

    pcall(function()

        if type(dropdown.SetValue) == "function" then

            dropdown:SetValue(
                selectedDisplay,
                true
            )
        end
    end)

    task.defer(function()

        HOLY_WEBHOOK_RUNTIME.UpdatingUI = false

        if type(selectedEntry) == "table" then

            HolyWebhookPopulateFilterEditor(
                selectedEntry
            )
        end
    end)

    return true
end

function HolyWebhookUpsertFilter(fruitName, minimum)

    HolyWebhookEnsureState()

    fruitName = HolyCleanText(fruitName)

    local key =
        HolyWebhookFilterKey(fruitName)

    local parsedMinimum =
        HolyWebhookReadMultiplier(minimum)

    if fruitName == ""
    or key == ""
    or key == "all" then

        return false,
            "Select a fruit first."
    end

    if parsedMinimum == nil then

        return false,
            "Enter a multiplier from 0.01 to 100."
    end

    local existing =
        HolyWebhookGetFilter(fruitName)

    local updated =
        type(existing) == "table"

    if updated == true then

        existing.Name = fruitName
        existing.Minimum = parsedMinimum

    else

        HOLY_WEBHOOK_STATE.Filters[
            #HOLY_WEBHOOK_STATE.Filters + 1
        ] = {
            Name = fruitName,
            Minimum = parsedMinimum,
        }
    end

    HOLY_WEBHOOK_STATE.Filters =
        HolyWebhookNormalizeFilters(
            HOLY_WEBHOOK_STATE.Filters
        )

    HOLY_WEBHOOK_STATE.SelectedFilterKey = key
    HOLY_WEBHOOK_STATE.LastNotifiedRestockKey = ""

    HolySaveWebhookSettings()
    HolyWebhookRefreshFilterDropdown(key)

    if HOLY_WEBHOOK_STATE.Enabled == true
    and type(
        HOLY_WEBHOOK_RUNTIME.LastStockResult
    ) == "table" then

        task.defer(function()

            HolyWebhookProcessFruitStock(
                HOLY_WEBHOOK_RUNTIME.LastStockResult
            )
        end)
    end

    return true,
        updated == true
        and "Filter updated."
        or "Filter added."
end

function HolyWebhookRemoveFilter(value)

    HolyWebhookEnsureState()

    local key = HolyWebhookFilterKey(
        value
        or HOLY_WEBHOOK_STATE.SelectedFilterKey
    )

    local removed = false

    for index = #HOLY_WEBHOOK_STATE.Filters, 1, -1 do

        local entry =
            HOLY_WEBHOOK_STATE.Filters[index]

        if HolyWebhookFilterKey(entry.Name)
            == key then

            table.remove(
                HOLY_WEBHOOK_STATE.Filters,
                index
            )

            removed = true
            break
        end
    end

    if removed ~= true then

        return false,
            "Select a filter first."
    end

    HOLY_WEBHOOK_STATE.SelectedFilterKey = ""

    HolySaveWebhookSettings()
    HolyWebhookRefreshFilterDropdown()

    return true,
        "Filter removed."
end

function HolyWebhookClearFilters()

    HolyWebhookEnsureState()

    HOLY_WEBHOOK_STATE.Filters = {}
    HOLY_WEBHOOK_STATE.SelectedFilterKey = ""

    HolySaveWebhookSettings()
    HolyWebhookRefreshFilterDropdown()

    return true
end

function HolyWebhookResponseStatus(response)

    if type(response) ~= "table" then
        return nil
    end

    return tonumber(
        response.StatusCode
        or response.status_code
        or response.Status
        or response.status
    )
end

function HolyWebhookResponseBody(response)

    if type(response) == "string" then
        return response
    end

    if type(response) ~= "table" then
        return ""
    end

    return tostring(
        response.Body
        or response.body
        or response.ResponseBody
        or response.responseBody
        or ""
    )
end

function HolyWebhookPerformRequest(item)

    local valid, urlOrReason =
        HolyWebhookValidateUrl(item.Url)

    if valid ~= true then

        return false,
            tostring(urlOrReason),
            0
    end

    local requestFunction =
        HolyGetRequestFunction()

    if type(requestFunction) ~= "function" then

        return false,
            "HTTP requests are unavailable.",
            0
    end

    local encodeOk, encoded = pcall(function()

        return HttpService:JSONEncode(
            item.Payload
        )
    end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        return false,
            "Could not encode the webhook.",
            0
    end

    local requestOk, response = pcall(function()

        return requestFunction({
            Url = urlOrReason,
            Method = "POST",

            Headers = {
                ["Content-Type"] =
                    "application/json",
            },

            Body = encoded,
        })
    end)

    if requestOk ~= true then

        return false,
            "Webhook request failed.",
            0
    end

    local status =
        HolyWebhookResponseStatus(response)

    if status == 429 then

        local decoded = nil

        pcall(function()

            decoded = HttpService:JSONDecode(
                HolyWebhookResponseBody(response)
            )
        end)

        local retryAfter =
            type(decoded) == "table"
            and tonumber(decoded.retry_after)
            or 1

        if retryAfter > 60 then

            retryAfter /= 1000
        end

        return false,
            "Discord rate limited the webhook.",
            math.clamp(retryAfter, 0.5, 30)
    end

    if status ~= nil
    and (
        status < 200
        or status >= 300
    ) then

        return false,
            "Webhook returned HTTP "
            .. tostring(status)
            .. ".",
            0
    end

    return true,
        "sent",
        0
end

function HolyWebhookStartQueue()

    HolyWebhookEnsureState()

    local runtime = HOLY_WEBHOOK_RUNTIME

    if runtime.Sending == true then
        return false
    end

    runtime.Sending = true

    local token = runtime.Token

    task.spawn(function()

        while HOLY_WEBHOOK_RUNTIME.Token == token
        and #runtime.Queue > 0 do

            local item =
                table.remove(runtime.Queue, 1)

            item.Attempts =
                tonumber(item.Attempts) or 0

            local success, reason, retryAfter =
                HolyWebhookPerformRequest(item)

            if success ~= true
            and item.Attempts < 2 then

                item.Attempts += 1

                task.wait(
                    retryAfter > 0
                    and retryAfter
                    or 1.5
                )

                table.insert(
                    runtime.Queue,
                    1,
                    item
                )

            else

                if type(item.Callback) == "function" then

                    pcall(
                        item.Callback,
                        success == true,
                        tostring(reason)
                    )
                end

                task.wait(0.4)
            end
        end

        if HOLY_WEBHOOK_RUNTIME.Token == token then

            runtime.Sending = false
        end
    end)

    return true
end

function HolyWebhookEnqueue(payload, callback)

    HolyWebhookEnsureState()

    local valid, urlOrReason =
        HolyWebhookValidateUrl(
            HOLY_WEBHOOK_STATE.Url
        )

    if valid ~= true then

        if type(callback) == "function" then

            pcall(
                callback,
                false,
                tostring(urlOrReason)
            )
        end

        return false
    end

    local queue = HOLY_WEBHOOK_RUNTIME.Queue

    while #queue >= 20 do

        table.remove(queue, 1)
    end

    queue[#queue + 1] = {
        Url = urlOrReason,
        Payload = payload,
        Callback = callback,
        Attempts = 0,
    }

    HolyWebhookStartQueue()

    return true
end

function HolyWebhookLimitText(
    value,
    maximumCharacters
)

    local text = tostring(value or "")

    local maximum =
        math.max(
            0,
            math.floor(
                tonumber(maximumCharacters)
                or 0
            )
        )

    if maximum <= 0 then
        return ""
    end

    local lengthOk, length = pcall(function()

        return utf8.len(text)
    end)

    if lengthOk ~= true
    or type(length) ~= "number" then

        return text:sub(1, maximum)
    end

    if length <= maximum then
        return text
    end

    local offsetOk, byteOffset = pcall(function()

        return utf8.offset(
            text,
            maximum + 1
        )
    end)

    if offsetOk == true
    and type(byteOffset) == "number" then

        return text:sub(
            1,
            byteOffset - 1
        )
    end

    return text
end

function HolyWebhookBuildAllowedMentions(content)

    content = tostring(content or "")

    local output = {
        parse = {},
    }

    local lower = content:lower()

    if lower:find(
        "@everyone",
        1,
        true
    )
    or lower:find(
        "@here",
        1,
        true
    ) then

        output.parse[#output.parse + 1] =
            "everyone"
    end

    local users = {}
    local roles = {}

    local seenUsers = {}
    local seenRoles = {}

    local function addExplicitMention(
        target,
        seen,
        id
    )

        id = tostring(id or "")

        if id == ""
        or seen[id] == true
        or #target >= 100 then

            return
        end

        seen[id] = true
        target[#target + 1] = id
    end

    for userId in content:gmatch(
        "<@!?(%d+)>"
    ) do

        addExplicitMention(
            users,
            seenUsers,
            userId
        )
    end

    for roleId in content:gmatch(
        "<@&(%d+)>"
    ) do

        addExplicitMention(
            roles,
            seenRoles,
            roleId
        )
    end

    if #users > 0 then
        output.users = users
    end

    if #roles > 0 then
        output.roles = roles
    end

    return output
end

function HolyWebhookBuildMobileSummary(matches)

    local count =
        type(matches) == "table"
        and #matches
        or 0

    if count <= 0 then

        return
            "🔥 A fruit multiplier filter matched."
    end

    if count == 1 then

        local match = matches[1]

        return
            "🔥 "
            .. tostring(match.Name)
            .. " reached x"
            .. HolyWebhookFormatMultiplier(
                match.Multiplier
            )
            .. " (required x"
            .. HolyWebhookFormatMultiplier(
                match.Minimum
            )
            .. ")"
    end

    local entries = {}
    local shown = math.min(count, 3)

    for index = 1, shown do

        local match = matches[index]

        entries[#entries + 1] =
            tostring(match.Name)
            .. " x"
            .. HolyWebhookFormatMultiplier(
                match.Multiplier
            )
    end

    local summary =
        "🔥 "
        .. tostring(count)
        .. " fruit matches: "
        .. table.concat(entries, ", ")

    if count > shown then

        summary =
            summary
            .. ", +"
            .. tostring(count - shown)
            .. " more"
    end

    return HolyWebhookLimitText(
        summary,
        500
    )
end

function HolyWebhookResolveAlertRefreshAt(
    stockResult
)

    local now =
        tonumber(
            HolyDailyDealLiveServerNow()
        )
        or os.time()

    local nextRefreshAt =
        tonumber(
            HolyDailyDealLiveResolveNextRestockAt(
                stockResult
            )
        )

    if nextRefreshAt == nil
    or nextRefreshAt ~= nextRefreshAt
    or nextRefreshAt == math.huge
    or nextRefreshAt == -math.huge
    or nextRefreshAt <= now then

        nextRefreshAt =
            math.floor(
                now / 600 + 1
            ) * 600
    end

    return math.floor(nextRefreshAt)
end

function HolyWebhookBuildFruitAlertPayload(
    matches,
    stockResult
)

    matches =
        type(matches) == "table"
        and matches
        or {}

    local pingText =
        tostring(
            HOLY_WEBHOOK_STATE.PingText
            or ""
        )

    pingText =
        pingText
            :gsub("^%s+", "")
            :gsub("%s+$", "")

    pingText =
        HolyWebhookLimitText(
            pingText,
            1400
        )

    local mobileSummary =
        HolyWebhookBuildMobileSummary(
            matches
        )

    local content = mobileSummary

    if pingText ~= "" then

        content =
            pingText
            .. "\n"
            .. mobileSummary
    end

    content =
        HolyWebhookLimitText(
            content,
            2000
        )

    local fields = {}
    local maximumFruitFields = 23
    local shownFruitCount =
        math.min(
            #matches,
            maximumFruitFields
        )

    for index = 1, shownFruitCount do

        local match = matches[index]

        fields[#fields + 1] = {
            name =
                "🌱 "
                .. tostring(match.Name),

            value =
                "**Current Multiplier:** `x"
                .. HolyWebhookFormatMultiplier(
                    match.Multiplier
                )
                .. "`\n"
                .. "**Required Multiplier:** `x"
                .. HolyWebhookFormatMultiplier(
                    match.Minimum
                )
                .. "`",

            inline = false,
        }
    end

    if #matches > maximumFruitFields then

        fields[#fields + 1] = {
            name = "Additional Matches",

            value =
                "`"
                .. tostring(
                    #matches
                    - maximumFruitFields
                )
                .. "` more matching fruit filters.",

            inline = false,
        }
    end

    local nextRefreshAt =
        HolyWebhookResolveAlertRefreshAt(
            stockResult
        )

    fields[#fields + 1] = {
        name = "Next Refresh",

        value =
            "<t:"
            .. tostring(nextRefreshAt)
            .. ":F>\n"
            .. "<t:"
            .. tostring(nextRefreshAt)
            .. ":R>",

        inline = false,
    }

    local matchWord =
        #matches == 1
        and "fruit"
        or "fruits"

    return {
        username = "HOLY",

        content = content,

        allowed_mentions =
            HolyWebhookBuildAllowedMentions(
                content
            ),

        embeds = {
            {
                title =
                    "🔥 Fruit Multiplier Alert",

                description =
                    "**"
                    .. tostring(#matches)
                    .. " "
                    .. matchWord
                    .. "** matched your configured multiplier filters.",

                color = 16753920,

                fields = fields,

                footer = {
                    text =
                        "HOLY • Fruit Price Stock",
                },

                timestamp = os.date(
                    "!%Y-%m-%dT%H:%M:%SZ"
                ),
            },
        },
    }
end

function HolyWebhookProcessFruitStock(stockResult)

    HolyWebhookEnsureState()

    HOLY_WEBHOOK_RUNTIME.LastStockResult =
        type(stockResult) == "table"
        and stockResult
        or nil

    if HOLY_WEBHOOK_STATE.Enabled ~= true
    or type(stockResult) ~= "table"
    or type(stockResult.entries) ~= "table"
    or #HOLY_WEBHOOK_STATE.Filters <= 0 then

        return false
    end

    local validUrl =
        HolyWebhookValidateUrl(
            HOLY_WEBHOOK_STATE.Url
        )

    if validUrl ~= true then
        return false
    end

    local restockKey =
        tostring(
            HolyDailyDealLiveBuildRestockKey(
                stockResult
            )
            or ""
        )

    if restockKey == "" then
        return false
    end

    local previousKey =
        tostring(
            HOLY_WEBHOOK_STATE
                .LastNotifiedRestockKey
            or ""
        )

    local nextRefreshAt =
        HolyDailyDealLiveResolveNextRestockAt(
            stockResult
        )

    local legacyNextKey =
        nextRefreshAt > 0
        and tostring(nextRefreshAt)
        or ""

    if previousKey ~= ""
    and legacyNextKey ~= ""
    and previousKey == legacyNextKey
    and previousKey ~= restockKey then

        HOLY_WEBHOOK_STATE
            .LastNotifiedRestockKey =
                restockKey

        HolySaveWebhookSettings()

        return false
    end

    if previousKey == restockKey
    or HOLY_WEBHOOK_RUNTIME
        .PendingRestockKeys[restockKey] == true then

        return false
    end

    local matches = {}

    for _, filter in ipairs(
        HOLY_WEBHOOK_STATE.Filters
    ) do

        local multiplier, stockName =
            HolyDailyDealStockMultiplier(
                stockResult.entries,
                filter.Name
            )

        local minimum =
            HolyWebhookReadMultiplier(
                filter.Minimum
            )

        if stockName ~= ""
        and minimum ~= nil
        and tonumber(multiplier) ~= nil
        and tonumber(multiplier) + 0.000001
            >= minimum then

            matches[#matches + 1] = {
                Name = stockName,
                Multiplier = tonumber(multiplier),
                Minimum = minimum,
            }
        end
    end

    if #matches <= 0 then
        return false
    end

    table.sort(matches, function(a, b)

        if a.Multiplier ~= b.Multiplier then

            return a.Multiplier > b.Multiplier
        end

        return tostring(a.Name):lower()
            < tostring(b.Name):lower()
    end)

    HOLY_WEBHOOK_RUNTIME
        .PendingRestockKeys[restockKey] = true

    local payload =
        HolyWebhookBuildFruitAlertPayload(
            matches,
            stockResult
        )

    return HolyWebhookEnqueue(
        payload,
        function(success, reason)

            HOLY_WEBHOOK_RUNTIME
                .PendingRestockKeys[restockKey] = nil

            if success == true then

                HOLY_WEBHOOK_STATE
                    .LastNotifiedRestockKey = restockKey

                HolySaveWebhookSettings()

            else

                warn(
                    "[HOLY WEBHOOK] Fruit alert failed: "
                    .. tostring(reason)
                )
            end
        end
    )
end

function HolyWebhookSendTest()

    HolyWebhookEnsureState()

    local valid, reason =
        HolyWebhookValidateUrl(
