                        .. "The configured ping is suppressed for test messages.",

                    color = 10181046,

                    fields = {
                        {
                            name =
                                "🌱 Example — Moon Bloom",

                            value =
                                "**Current Multiplier:** `x4.00`\n"
                                .. "**Required Multiplier:** `x2.00`",

