        end
    )
end

function HolyDailyDealLiveHandleStockResult(
    stockResult,
    source
)

    local runtime =
        HOLY_DAILY_DEAL_LIVE_RUNTIME

    if type(stockResult) ~= "table"
    or type(stockResult.entries) ~= "table" then

        return false,
            "invalid stock result"
    end

    local cycleKey =
        tostring(
            HolyDailyDealLiveBuildRestockKey(
                stockResult
            )
            or ""
        )

    if cycleKey == "" then

        return false,
            "cycle key missing"
    end

    runtime.LastCycleKey =
        cycleKey

    runtime.LastStockResult =
        stockResult

    local newCycle =
        runtime.LastProcessedCycleKey
        ~= cycleKey

    if newCycle == true then

        runtime.LastProcessedCycleKey =
            cycleKey

        HolyDailyDealSendLiveReportAsync(
            stockResult,
            source or "stock"
        )
    end

    HolyWebhookProcessFruitStock(
        stockResult
    )

    runtime.LastResult =
        newCycle == true
        and (
            "Live: new refresh "
            .. cycleKey
        )
        or (
            "Live: current refresh "
            .. cycleKey
        )

    return newCycle,
        cycleKey
end

function HolyDailyDealLiveConnectSnapshot()

    local runtime =
        HOLY_DAILY_DEAL_LIVE_RUNTIME

    if runtime.SnapshotConnection ~= nil then

        runtime.SnapshotConnected =
            true

        return true
    end

    local networking =
        HolyShopRequireModule(
            "SharedModules.Networking"
        )

    local snapshotPacket =
        type(networking) == "table"
        and type(networking.FruitStock) == "table"
        and networking.FruitStock.Snapshot
        or nil

    local snapshotSignal =
        type(snapshotPacket) == "table"
        and snapshotPacket.OnClientEvent
        or nil

    if snapshotSignal == nil
    or type(snapshotSignal.Connect) ~= "function" then

        runtime.SnapshotConnected =
            false

        return false,
            "FruitStock.Snapshot missing"
    end

    local success,
        connection =
        pcall(function()

            return snapshotSignal:Connect(
                function(stockResult)

                    if HOLY_DAILY_DEAL_LIVE_RUNTIME
                    ~= runtime
                    or runtime.Token == nil then

                        return
                    end

                    runtime.LastSnapshotAt =
                        os.clock()

                    task.defer(function()

                        if HOLY_DAILY_DEAL_LIVE_RUNTIME
                        ~= runtime
                        or runtime.Token == nil then

                            return
                        end

                        local handled,
                            handleError =
                            pcall(
                                HolyDailyDealLiveHandleStockResult,
                                stockResult,
                                "snapshot"
                            )

                        if handled ~= true then

                            warn(
                                "[HOLY DAILY DEAL LIVE]",
                                "snapshot handling failed:",
                                tostring(handleError)
                            )
                        end
                    end)
                end
            )
        end)

    if success ~= true
    or connection == nil then

        runtime.SnapshotConnected =
            false

        return false,
            tostring(connection)
    end

    runtime.SnapshotConnection =
        connection

    runtime.SnapshotConnected =
        true

    return true
end

function HolyDailyDealLiveStartWorker(reason)

    local runtime =
        HOLY_DAILY_DEAL_LIVE_RUNTIME

    if runtime.Running == true
    and runtime.Token ~= nil then

        HolyDailyDealLiveConnectSnapshot()

        return false
    end

    local token =
        {}

    runtime.Token =
        token

    runtime.Running =
        true

    runtime.LastResult =
        "Live: starting"

    HolyDailyDealLiveConnectSnapshot()

    task.spawn(function()

        task.wait(
            1
        )

        while runtime.Token == token do

            local waitSeconds =
                15

            local requestOk,
                stockResult,
                stockOk,
                stockReason =
                pcall(function()

                    return HolyDailyDealFireFruitStockRequest()
                end)

            if requestOk == true
            and stockOk == true
            and type(stockResult) == "table"
            and type(stockResult.entries) == "table" then

                local handled,
                    handleError =
                    pcall(
                        HolyDailyDealLiveHandleStockResult,
                        stockResult,
                        "request"
                    )

                if handled ~= true then

                    runtime.LastResult =
                        "Live: processing failed"

                    warn(
                        "[HOLY DAILY DEAL LIVE]",
                        "stock processing failed:",
                        tostring(handleError)
                    )
                end

                waitSeconds =
                    HolyDailyDealLiveResolveWait(
                        stockResult
                    )

            else

                runtime.LastResult =
                    "Live: stock failed"

                local now =
                    os.clock()

                if now - (
                    tonumber(runtime.LastErrorAt)
                    or 0
                ) > 20 then

                    runtime.LastErrorAt =
                        now

                    warn(
                        "[HOLY DAILY DEAL LIVE]",
                        "stock failed:",
                        tostring(
                            stockReason
                            or stockResult
                        )
                    )
                end
            end

            local untilClock =
                os.clock()
                + math.max(
                    tonumber(waitSeconds)
                    or 1,
                    1
                )

            while runtime.Token == token
            and os.clock() < untilClock do

                task.wait(
                    0.5
                )
            end
        end

        if runtime.Token == token then

            runtime.Running =
                false

            runtime.Token =
                nil
        end
    end)

    return true
end

task.defer(function()

    task.wait(
        8
    )

    if type(HolyDailyDealFireFruitStockRequest) == "function" then

        HolyDailyDealLiveStartWorker(
            "script load"
        )
    end
end)

