function HolyVisualSprinklerColorToHex(color)

    return string.format(
        "#%02X%02X%02X",
        math.floor(
            color.R * 255
        ),
        math.floor(
            color.G * 255
        ),
        math.floor(
            color.B * 255
        )
    )
end

function HolyVisualSprinklerFormatTime(seconds)

    seconds =
        math.max(
            0,
            math.floor(
                tonumber(seconds)
                or 0
            )
        )

    local yearSeconds =
        365 * 24 * 60 * 60

    local daySeconds =
        24 * 60 * 60

    local hourSeconds =
        60 * 60

    local years =
        math.floor(
            seconds / yearSeconds
        )

    seconds =
        seconds % yearSeconds

    local days =
        math.floor(
            seconds / daySeconds
        )

    seconds =
        seconds % daySeconds

    local hours =
        math.floor(
            seconds / hourSeconds
        )

    seconds =
        seconds % hourSeconds

    local minutes =
        math.floor(
            seconds / 60
        )

    local remainingSeconds =
        seconds % 60

    if years > 0 then

        return string.format(
            "%dy %dd · %02dh %02dm %02ds",
            years,
            days,
            hours,
            minutes,
            remainingSeconds
        )
    end

    if days > 0 then

        return string.format(
            "%dd · %02dh %02dm %02ds",
            days,
            hours,
            minutes,
            remainingSeconds
        )
    end

    if hours > 0 then

        return string.format(
            "%dh · %02dm %02ds",
            hours,
            minutes,
            remainingSeconds
        )
    end

    if minutes > 0 then

        return string.format(
            "%dm %02ds",
            minutes,
            remainingSeconds
        )
    end

    return string.format(
        "%ds",
        remainingSeconds
    )
end

function HolyVisualSprinklerGetFunctionUpvalues(func)

    local getter =
        type(debug) == "table"
        and debug.getupvalues
        or getupvalues

    if type(getter) ~= "function" then
        return {}
    end

    local success,
        result =
        pcall(function()

            return getter(
                func
            )
        end)

    return success
        and result
        or {}
end

function HolyVisualSprinklerIsTimerData(tbl)

    if type(tbl) ~= "table" then
        return false
    end

    local checked =
        0

    for key, value in pairs(tbl) do

        checked =
            checked + 1

        if type(key) == "string"
        and type(value) == "table"
        and type(value.PlacedAt) == "number"
        and type(value.Lifetime) == "number" then

            return true
        end

        if checked >= 100 then
            break
        end
    end

    return false
end

function HolyVisualSprinklerResolveTimerData()

    local runtime =
        HolyVisualGetRuntime()

    if HolyVisualSprinklerIsTimerData(
        runtime.SprinklerTimerData
    ) then

        return runtime.SprinklerTimerData
    end

    local playerScripts =
        LocalPlayer
        and LocalPlayer:FindFirstChild(
            "PlayerScripts"
        )

    local controllers =
        playerScripts
        and playerScripts:FindFirstChild(
            "Controllers"
        )

    local controllerModule =
        controllers
        and controllers:FindFirstChild(
            "SprinklerVisualizerController"
        )

    if typeof(controllerModule) ~= "Instance"
    or not controllerModule:IsA("ModuleScript") then

        return nil
    end

    local success,
        controller =
        pcall(function()

            return require(
                controllerModule
            )
        end)

    if success ~= true
    or type(controller) ~= "table" then

        return nil
    end

    local updateFunction =
        controller.UpdateSprinklerTimers

    if type(updateFunction) ~= "function" then
        return nil
    end

    for _, upvalue in pairs(
        HolyVisualSprinklerGetFunctionUpvalues(
            updateFunction
        )
    ) do

        if HolyVisualSprinklerIsTimerData(
            upvalue
        ) then

            runtime.SprinklerTimerData =
                upvalue

            return runtime.SprinklerTimerData
        end
    end

    return nil
end

function HolyVisualSprinklerGetOwnGarden()

    local gardens =
        Workspace:FindFirstChild(
            "Gardens"
        )

    if typeof(gardens) ~= "Instance" then
        return nil
    end

    for _, garden in ipairs(
        gardens:GetChildren()
    ) do

        if garden:GetAttribute(
            "OwnerUserId"
        ) == LocalPlayer.UserId then

            return garden
        end
    end

    return nil
end

function HolyVisualSprinklerGetAdornee(model)

    if typeof(model) ~= "Instance" then
        return nil
    end

    local root =
        model:FindFirstChild(
            "Root"
        )

    if typeof(root) == "Instance"
    and root:IsA("BasePart") then

        return root
    end

    if model:IsA("Model")
    and typeof(model.PrimaryPart) == "Instance" then

        return model.PrimaryPart
    end

    return model:FindFirstChildWhichIsA(
        "BasePart",
        true
    )
end

function HolyVisualSprinklerHideDefaultTimer(model)

    local runtime =
        HolyVisualGetRuntime()

    local timerGui =
        model
        and model:FindFirstChild(
            "SprinklerTimerUI"
        )

    if typeof(timerGui) == "Instance"
    and timerGui:IsA("BillboardGui") then

        if runtime.SprinklerTimerOriginalStates[
            timerGui
        ] == nil then

            runtime.SprinklerTimerOriginalStates[
                timerGui
            ] =
                timerGui.Enabled
        end

        timerGui.Enabled =
            false
    end
end

function HolyVisualSprinklerRestoreDefaultTimers()

    local runtime =
        HolyVisualGetRuntime()

    for timerGui, originalState in pairs(
        runtime.SprinklerTimerOriginalStates
        or {}
    ) do

        if typeof(timerGui) == "Instance"
        and timerGui.Parent then

            pcall(function()

                timerGui.Enabled =
                    originalState
            end)
        end

        runtime.SprinklerTimerOriginalStates[
            timerGui
        ] =
            nil
    end

    return true
end

function HolyVisualSprinklerRemoveLabel(model)

    local runtime =
        HolyVisualGetRuntime()

    local label =
        runtime.SprinklerTimerLabels[
            model
        ]

    if typeof(label) == "Instance" then

        pcall(function()

            label:Destroy()
        end)
    end

    runtime.SprinklerTimerLabels[
        model
    ] =
        nil

    return true
end

function HolyVisualClearSprinklerTimerESP()

    local runtime =
        HolyVisualGetRuntime()

    local models =
        {}

    for model in pairs(
        runtime.SprinklerTimerLabels
        or {}
    ) do

        table.insert(
            models,
            model
        )
    end

    for _, model in ipairs(models) do

        HolyVisualSprinklerRemoveLabel(
            model
        )
    end

    HolyVisualSprinklerRestoreDefaultTimers()

    return true
end

function HolyVisualSprinklerApplyESPScale(billboard)

    if typeof(billboard) ~= "Instance"
    or billboard:IsA("BillboardGui") ~= true then

        return false
    end

    local percent =
        HolyVisualReadSprinklerESPScale(
            HOLY_VISUAL_STATE.SprinklerTimerESPScale
            or "80"
        )

    local scale =
        percent / 100

    billboard.Size =
        UDim2.fromOffset(
            205 * scale,
            46 * scale
        )

    local background =
        billboard:FindFirstChild(
            "Background"
        )

    if typeof(background) ~= "Instance" then
        return true
    end

    local corner =
        background:FindFirstChildOfClass(
            "UICorner"
        )

    if typeof(corner) == "Instance" then

        corner.CornerRadius =
            UDim.new(
                0,
                6 * scale
            )
    end

    local stroke =
        background:FindFirstChild(
            "Stroke"
        )

    if typeof(stroke) == "Instance"
    and stroke:IsA("UIStroke") then

        stroke.Thickness =
            scale
    end

    local text =
        background:FindFirstChild(
            "Text"
        )

    if typeof(text) == "Instance"
    and text:IsA("TextLabel") then

        text.Size =
            UDim2.new(
                1,
                -8 * scale,
                1,
                -4 * scale
            )

        text.Position =
            UDim2.fromOffset(
                4 * scale,
                2 * scale
            )

        text.TextSize =
            14 * scale
    end

    return true
end

function HolyVisualSprinklerEnsureLabel(model)

    local runtime =
        HolyVisualGetRuntime()

    local existing =
        runtime.SprinklerTimerLabels[
            model
        ]

    if typeof(existing) == "Instance"
    and existing.Parent then

        return existing
    end

    HolyVisualSprinklerRemoveLabel(
        model
    )

    local adornee =
        HolyVisualSprinklerGetAdornee(
            model
        )

    if typeof(adornee) ~= "Instance" then
        return nil
    end

    local sprinklerName =
        model:GetAttribute(
            "SprinklerName"
        )
        or "Sprinkler"

    local style =
        HOLY_SPRINKLER_TIMER_STYLES[
            sprinklerName
        ]
        or HOLY_SPRINKLER_TIMER_DEFAULT_STYLE

    local billboard =
        Instance.new(
            "BillboardGui"
        )

    billboard.Name =
        "HolySprinklerTimerESP"

    billboard.Adornee =
        adornee

    billboard.AlwaysOnTop =
        true

    billboard.LightInfluence =
        0

    billboard.MaxDistance =
        200

    billboard.Size =
        UDim2.fromOffset(
            205,
            46
        )

    billboard.StudsOffsetWorldSpace =
        Vector3.new(
            0,
            style.Offset,
            0
        )

    billboard.ResetOnSpawn =
        false

    billboard.Parent =
        model

    local background =
        Instance.new(
            "Frame"
        )

    background.Name =
        "Background"

    background.Size =
        UDim2.fromScale(
            1,
            1
        )

    background.BackgroundColor3 =
        Color3.fromRGB(
            8,
            8,
            11
        )

    background.BackgroundTransparency =
        0.42

    background.BorderSizePixel =
        0

    background.Parent =
        billboard

    local corner =
        Instance.new(
            "UICorner"
        )

    corner.CornerRadius =
        UDim.new(
            0,
            6
        )

    corner.Parent =
        background

    local stroke =
        Instance.new(
            "UIStroke"
        )

    stroke.Name =
        "Stroke"

    stroke.Color =
        style.Color

    stroke.Transparency =
        0.5

    stroke.Thickness =
        1

    stroke.Parent =
        background

    local text =
        Instance.new(
            "TextLabel"
        )

    text.Name =
        "Text"

    text.Size =
        UDim2.new(
            1,
            -8,
            1,
            -4
        )

    text.Position =
        UDim2.fromOffset(
            4,
            2
        )

    text.BackgroundTransparency =
        1

    text.RichText =
        true

    text.Text =
        "Loading..."

    text.TextColor3 =
        Color3.fromRGB(
            255,
            255,
            255
        )

    text.TextSize =
        14

    text.TextScaled =
        false

    text.TextWrapped =
        false

    text.TextStrokeColor3 =
        Color3.fromRGB(
            0,
            0,
            0
        )

    text.TextStrokeTransparency =
        0.38

    text.Font =
        Enum.Font.GothamBold

    text.TextXAlignment =
        Enum.TextXAlignment.Center

    text.TextYAlignment =
        Enum.TextYAlignment.Center

    text.Parent =
        background

    HolyVisualSprinklerApplyESPScale(
        billboard
    )

    runtime.SprinklerTimerLabels[
        model
    ] =
        billboard

    return billboard
end

function HolyVisualSprinklerUpdateLabel(
    model,
    timerData
)

    if typeof(model) ~= "Instance"
    or not model.Parent then

        HolyVisualSprinklerRemoveLabel(
            model
        )

        return false
    end

    HolyVisualSprinklerHideDefaultTimer(
        model
    )

    local billboard =
        HolyVisualSprinklerEnsureLabel(
            model
        )

    if typeof(billboard) ~= "Instance" then
        return false
    end

    local background =
        billboard:FindFirstChild(
            "Background"
        )

    local text =
        background
        and background:FindFirstChild(
            "Text"
        )

    local stroke =
        background
        and background:FindFirstChild(
            "Stroke"
        )

    if typeof(text) ~= "Instance" then
        return false
    end

    HolyVisualSprinklerApplyESPScale(
        billboard
    )

    local sprinklerName =
        model:GetAttribute(
            "SprinklerName"
        )
        or "Sprinkler"

    local style =
        HOLY_SPRINKLER_TIMER_STYLES[
            sprinklerName
        ]
        or HOLY_SPRINKLER_TIMER_DEFAULT_STYLE

    billboard.StudsOffsetWorldSpace =
        Vector3.new(
            0,
            style.Offset,
            0
        )

    if typeof(stroke) == "Instance" then

        stroke.Color =
            style.Color
    end

    local record =
        timerData[
            model.Name
        ]

    if type(record) ~= "table"
    or type(record.PlacedAt) ~= "number" then

        text.Text =
            string.format(
                '<font color="%s"><b>%s %s</b></font>\n'
                .. '<font color="#FF7777"><b>Timer unavailable</b></font>',
                HolyVisualSprinklerColorToHex(
                    style.Color
                ),
                style.Emoji,
                sprinklerName
            )

        return false
    end

    local remaining =
        record.PlacedAt
        + (
            tonumber(record.Lifetime)
            or 120
        )
        - os.time()

    text.Text =
        string.format(
            '<font color="%s"><b>%s %s</b></font>\n'
            .. '<font color="#FFD166">⏳</font> '
            .. '<font color="#71FF71"><b>%s</b></font>',
            HolyVisualSprinklerColorToHex(
                style.Color
            ),
            style.Emoji,
            sprinklerName,
            HolyVisualSprinklerFormatTime(
                remaining
            )
        )

    return true
end

function HolyVisualRefreshSprinklerTimerESP()

    HolyVisualEnsureState()

    if HOLY_VISUAL_STATE.SprinklerTimerESP ~= true then

        HolyVisualClearSprinklerTimerESP()

        return false
    end

    local timerData =
        HolyVisualSprinklerResolveTimerData()

    if type(timerData) ~= "table" then
        return false
    end

    local ownGarden =
        HolyVisualSprinklerGetOwnGarden()

    local sprinklersFolder =
        ownGarden
        and ownGarden:FindFirstChild(
            "Sprinklers"
        )

    if typeof(sprinklersFolder) ~= "Instance" then
        return false
    end

    local runtime =
        HolyVisualGetRuntime()

    local touched =
        {}

    for _, model in ipairs(
        sprinklersFolder:GetChildren()
    ) do

        if model:IsA("Model")
        and model:GetAttribute(
            "UserId"
        ) == LocalPlayer.UserId
        and type(
            model:GetAttribute(
                "SprinklerId"
            )
        ) == "string" then

            touched[model] =
                true

            HolyVisualSprinklerUpdateLabel(
                model,
                timerData
            )
        end
    end

    local stale =
        {}

    for model in pairs(
        runtime.SprinklerTimerLabels
        or {}
    ) do

        if touched[model] ~= true
        or not model.Parent then

            table.insert(
                stale,
                model
            )
        end
    end

    for _, model in ipairs(stale) do

        HolyVisualSprinklerRemoveLabel(
            model
        )
    end

    return true
end

function HolyVisualStartSprinklerTimerESP(reason, skipSave)

    HolyVisualEnsureState()

    HOLY_VISUAL_STATE.SprinklerTimerESP =
        true

    if skipSave ~= true then

        HolySaveVisualSettings()
    end

    local runtime =
        HolyVisualGetRuntime()

    if runtime.SprinklerTimerRunning == true then

        HolyVisualRefreshSprinklerTimerESP()

        return true
    end

    local token =
        {}

    runtime.SprinklerTimerToken =
        token

    runtime.SprinklerTimerRunning =
        true

    task.spawn(function()

        while runtime.SprinklerTimerToken == token
        and HOLY_VISUAL_STATE.SprinklerTimerESP == true do

            pcall(function()

                HolyVisualRefreshSprinklerTimerESP()
            end)

            task.wait(
                runtime.SprinklerTimerUpdateDelay
            )
        end

        if runtime.SprinklerTimerToken == token then

            runtime.SprinklerTimerRunning =
                false
        end

        if HOLY_VISUAL_STATE.SprinklerTimerESP ~= true then

            HolyVisualClearSprinklerTimerESP()
        end
    end)

    HolyVisualRefreshSprinklerTimerESP()

    return true
end

function HolyVisualStopSprinklerTimerESP(reason, skipSave)

    HolyVisualEnsureState()

    HOLY_VISUAL_STATE.SprinklerTimerESP =
        false

    if skipSave ~= true then

        HolySaveVisualSettings()
    end

    local runtime =
        HolyVisualGetRuntime()

    runtime.SprinklerTimerToken =
        nil

    runtime.SprinklerTimerRunning =
        false

    HolyVisualClearSprinklerTimerESP()

    return true
end

function HolyVisualSetSprinklerTimerESP(value)

    if value == true then

        return HolyVisualStartSprinklerTimerESP(
            "toggle on",
            false
        )
    end

    return HolyVisualStopSprinklerTimerESP(
        "toggle off",
        false
    )
end

function HolyVisualSetSprinklerESPScale(value)

    HolyVisualEnsureState()

    local normalized =
        tostring(
            HolyVisualReadSprinklerESPScale(
                value
            )
        )

    HOLY_VISUAL_STATE.SprinklerTimerESPScale =
        normalized

    HolySaveVisualSettings()

    if HOLY_VISUAL_STATE.SprinklerTimerESP == true then

        HolyVisualRefreshSprinklerTimerESP()
    end

    return normalized
end

function HolySellPruneRecentFruitIds()

    HOLY_SHOP_STATE.SellRecentFruitIds =
        type(HOLY_SHOP_STATE.SellRecentFruitIds) == "table"
        and HOLY_SHOP_STATE.SellRecentFruitIds
        or {}

    local now =
        os.clock()

    for fruitId, lastAt in pairs(HOLY_SHOP_STATE.SellRecentFruitIds) do

        if now - (
            tonumber(lastAt)
            or 0
        ) > 6 then

            HOLY_SHOP_STATE.SellRecentFruitIds[fruitId] =
                nil
        end
    end
end

function HolySellFindToolByFruitId(fruitId)

    fruitId =
        HolyCleanText(
            fruitId
        )

    if fruitId == "" then
        return nil
    end

    for _, tool in ipairs(HolySellGetFruitTools()) do

        local toolId =
            HolyCleanText(
                HolySellResolveFruitId(
                    tool
                )
            )

        if toolId ~= ""
        and toolId == fruitId then

            return tool
        end
    end

    return nil
end

function HolySellDescribeSkip(tool, fruitId, reason)

    local name =
        typeof(tool) == "Instance"
        and tostring(tool.Name)
        or tostring(fruitId or "unknown")

    return tostring(name)
        .. " skipped: "
        .. tostring(reason or "filter blocked")
end

function HolySellLiveToolStillSafeToSell(fruitId)

    fruitId =
        HolyCleanText(
            fruitId
        )

    if fruitId == "" then
        return false, nil, "missing fruit id"
    end

    local tool =
        HolySellFindToolByFruitId(
            fruitId
        )

    if typeof(tool) ~= "Instance"
    or tool.Parent == nil then

        return false, nil, "tool no longer in inventory"
    end

    if HolySellLooksLikeFruitTool(tool) ~= true then

        return false, tool, "not a fruit tool"
    end

    if HolySellPassesFilters(tool) ~= true then

        return false, tool, "live filters blocked"
    end

    if HolySellValueFilterActive() == true then

        local liveValue =
            HolySellGetToolValue(
                tool
            )

        liveValue =
            tonumber(liveValue)

        if liveValue == nil
        or liveValue <= 0 then

            return false, tool, "value missing"
        end

        local threshold =
            HolySellReadValueThreshold(
                HOLY_SHOP_STATE.SellValueThreshold
                or "0"
            )

        local mode =
            HolySellNormalizeValueMode(
                HOLY_SHOP_STATE.SellValueMode
                or "Below"
            )

        if mode == "Above"
        and liveValue < threshold then

            return false, tool, "value below threshold"
        end

        if mode ~= "Above"
        and liveValue > threshold then

            return false, tool, "value above threshold"
        end
    end

    return true, tool, "ok"
end

function HolySellQueueFruitTool(tool, reason)

    if HOLY_SHOP_STATE.AutoSellFruits ~= true then
        return false
    end

    if HolySellIsFilteredMethod(
        HOLY_SHOP_STATE.SellMethod
    ) ~= true then

        return false
    end

    if HolySellPassesFilters(tool) ~= true then
        return false
    end

    local fruitId =
        HolySellResolveFruitId(
            tool
        )

    if fruitId == "" then
        return false
    end

    local liveSafe =
        HolySellLiveToolStillSafeToSell(
            fruitId
        )

    if liveSafe ~= true then
        return false
    end

    HolySellPruneRecentFruitIds()

    HOLY_SHOP_STATE.SellRecentFruitIds =
        type(HOLY_SHOP_STATE.SellRecentFruitIds) == "table"
        and HOLY_SHOP_STATE.SellRecentFruitIds
        or {}

    local recentAt =
        tonumber(
            HOLY_SHOP_STATE.SellRecentFruitIds[fruitId]
        )
        or 0

    if recentAt > 0
    and os.clock() - recentAt < 6 then

        return false
    end

    HOLY_SHOP_STATE.SellQueue =
        type(HOLY_SHOP_STATE.SellQueue) == "table"
        and HOLY_SHOP_STATE.SellQueue
        or {}

    HOLY_SHOP_STATE.SellQueueMap =
        type(HOLY_SHOP_STATE.SellQueueMap) == "table"
        and HOLY_SHOP_STATE.SellQueueMap
        or {}

    if HOLY_SHOP_STATE.SellQueueMap[fruitId] == true then
        return false
    end

    local value,
        valueText =
        HolySellGetToolValue(
            tool
        )

    value =
        tonumber(value)
        or 0

    HOLY_SHOP_STATE.SellQueueMap[fruitId] =
        true

    table.insert(
        HOLY_SHOP_STATE.SellQueue,
        {
            Id =
                fruitId,

            Name =
                HolySellGetToolFruitName(
                    tool
                ),

            Weight =
                HolySellGetToolWeight(
                    tool
                ),

            Value =
                value,

            ValueText =
                valueText
                or HolySellFormatValue(
                    value
                ),

            QueuedAt =
                os.clock(),

            ValueMode =
                HolySellNormalizeValueMode(
                    HOLY_SHOP_STATE.SellValueMode
                    or "Below"
                ),

            ValueThreshold =
                HolySellReadValueThreshold(
                    HOLY_SHOP_STATE.SellValueThreshold
                    or "0"
                ),

            Reason =
                tostring(reason or "detected"),
        }
    )

    HolySellSortQueue()

    return true
end

function HolySellScanExistingFruitTools(reason)

    if HOLY_SHOP_STATE.AutoSellFruits ~= true then
        return 0
    end

    if HolySellIsFilteredMethod(
        HOLY_SHOP_STATE.SellMethod
    ) ~= true then

        return 0
    end

    local queued =
        0

    for _, tool in ipairs(HolySellGetFruitTools()) do

        if HolySellQueueFruitTool(
            tool,
            reason or "scan"
        ) == true then

            queued =
                queued + 1
        end
    end

    return queued
end

function HolySellHookContainer(container, reason)

    if typeof(container) ~= "Instance" then
        return false
    end

    HOLY_SHOP_STATE.SellConnections =
        type(HOLY_SHOP_STATE.SellConnections) == "table"
        and HOLY_SHOP_STATE.SellConnections
        or {}

    local function tryHandle(child, triggerReason)

        if HOLY_SHOP_STATE.AutoSellFruits ~= true then
            return
        end

        if HolySellIsFilteredMethod(
            HOLY_SHOP_STATE.SellMethod
        ) == true then

            if HolySellQueueFruitTool(
                child,
                triggerReason
            ) == true then

                HolySellStartWorker()
            end

            return
        end

        if HolySellLooksLikeFruitTool(child) == true then

            HolySellScheduleSellAll(
                triggerReason
            )
        end
    end

    table.insert(
        HOLY_SHOP_STATE.SellConnections,
        container.ChildAdded:Connect(function(child)

            task.defer(function()

                tryHandle(
                    child,
                    reason or "child added"
                )
            end)

            task.delay(0.12, function()

                tryHandle(
                    child,
                    tostring(reason or "child added")
                    .. " delayed"
                )
            end)

            task.delay(0.35, function()

                tryHandle(
                    child,
                    tostring(reason or "child added")
                    .. " settled"
                )
            end)
        end)
    )

    return true
end

function HolySellStartWatcher()

    if HOLY_SHOP_STATE.SellWatcherStarted == true then
        return
    end

    HOLY_SHOP_STATE.SellWatcherStarted =
        true

    HOLY_SHOP_STATE.SellConnections =
        type(HOLY_SHOP_STATE.SellConnections) == "table"
        and HOLY_SHOP_STATE.SellConnections
        or {}

    local backpack =
        LocalPlayer
        and (
            LocalPlayer:FindFirstChildOfClass("Backpack")
            or LocalPlayer:WaitForChild("Backpack", 10)
        )
        or nil

    HolySellHookContainer(
        backpack,
        "backpack"
    )

    HolySellHookContainer(
        LocalPlayer and LocalPlayer.Character,
        "character"
    )

    if LocalPlayer then

        table.insert(
            HOLY_SHOP_STATE.SellConnections,
            LocalPlayer.CharacterAdded:Connect(function(character)

                task.defer(function()

                    HolySellHookContainer(
                        character,
                        "character"
                    )

                    task.wait(
                        0.25
                    )

                    HolySellScanExistingFruitTools(
                        "character added"
                    )

                    HolySellStartWorker()
                end)
            end)
        )
    end
end

function HolySellSelectedOnce()

    HolySellScanExistingFruitTools(
        "selected pass"
    )

    HOLY_SHOP_STATE.SellQueue =
        type(HOLY_SHOP_STATE.SellQueue) == "table"
        and HOLY_SHOP_STATE.SellQueue
        or {}

    HOLY_SHOP_STATE.SellQueueMap =
        type(HOLY_SHOP_STATE.SellQueueMap) == "table"
        and HOLY_SHOP_STATE.SellQueueMap
        or {}

    HOLY_SHOP_STATE.SellRecentFruitIds =
        type(HOLY_SHOP_STATE.SellRecentFruitIds) == "table"
        and HOLY_SHOP_STATE.SellRecentFruitIds
        or {}

    HolySellSortQueue()

    local fruitsAtOnce =
        HolySellReadFruitsAtOnce(
            HOLY_SHOP_STATE.FruitsAtOnce
        )

    local batch =
        {}

    while HOLY_SHOP_STATE.AutoSellFruits == true
    and HolySellIsFilteredMethod(
        HOLY_SHOP_STATE.SellMethod
    ) == true
    and #HOLY_SHOP_STATE.SellQueue > 0
    and #batch < fruitsAtOnce do

        local row =
            table.remove(
                HOLY_SHOP_STATE.SellQueue,
                1
            )

        local fruitId =
            row
            and HolyCleanText(row.Id)
            or ""

        if fruitId ~= "" then

            HOLY_SHOP_STATE.SellQueueMap[fruitId] =
                nil

            local liveSafe,
                liveTool,
                liveReason =
                HolySellLiveToolStillSafeToSell(
                    fruitId
                )

            if liveSafe == true then

                table.insert(
                    batch,
                    {
                        Id =
                            fruitId,

                        Tool =
                            liveTool,
                    }
                )

            elseif type(HOLY_SHOP_STATE.LastSellSkipPrintAt) ~= "number"
            or os.clock() - HOLY_SHOP_STATE.LastSellSkipPrintAt >= 1 then

                HOLY_SHOP_STATE.LastSellSkipPrintAt =
                    os.clock()

                print(
                    "[HOLY SELL]",
                    HolySellDescribeSkip(
                        liveTool,
                        fruitId,
                        liveReason
                    )
                )
            end
        end
    end

    local launched =
        #batch

    if launched <= 0 then
        return 0
    end

    local completed =
        0

    local sold =
        0

    for _, item in ipairs(batch) do

        task.spawn(function()

            local success =
                false

            if HOLY_SHOP_STATE.AutoSellFruits == true
            and HolySellIsFilteredMethod(
                HOLY_SHOP_STATE.SellMethod
            ) == true then

                success =
                    HolySellFirePacket(
                        "SellFruit",
                        item.Id
                    ) == true
            end

            if success == true then

                HOLY_SHOP_STATE.SellRecentFruitIds[item.Id] =
                    os.clock()

                sold =
                    sold + 1
            end

            completed =
                completed + 1
        end)
    end

    while completed < launched do
        task.wait()
    end

    return sold
end

function HolySellRunOnce()

    if HOLY_SHOP_STATE.AutoSellFruits ~= true then
        return false
    end

    local method =
        tostring(
            HOLY_SHOP_STATE.SellMethod
            or "Sell All"
        )

    if HolySellIsFilteredMethod(method) == true then

        HolySellSelectedOnce()

        return true
    end

    local fruitTools =
        HolySellGetFruitTools()

    if #fruitTools > 0 then

        HolySellScheduleSellAll(
            "inventory rescan"
        )
    end

    return true
end

function HolySellStartWorker()

    if HOLY_SHOP_STATE.SellWorkerRunning == true then
        return
    end

    HOLY_SHOP_STATE.SellWorkerRunning =
        true

    task.spawn(function()

        while HOLY_SHOP_STATE.AutoSellFruits == true do

            HolySellRunOnce()

            local filtered =
                HolySellIsFilteredMethod(
                    HOLY_SHOP_STATE.SellMethod
                )

            local waitTime

            if filtered == true then

                if type(HOLY_SHOP_STATE.SellQueue) == "table"
                and #HOLY_SHOP_STATE.SellQueue > 0 then

                    waitTime =
                        0

                else

                    waitTime =
                        math.clamp(
                            tonumber(HOLY_SHOP_STATE.SelectedScanInterval)
                            or 0.10,
                            0.03,
                            2
                        )
                end

            else

                waitTime =
                    math.clamp(
                        tonumber(HOLY_SHOP_STATE.SellAllRescanInterval)
                        or 0.50,
                        0.10,
                        5
                    )
            end

            task.wait(
                waitTime
            )
        end

        HOLY_SHOP_STATE.SellWorkerRunning =
            false
    end)
end

function HolySellStopWorker()

    HOLY_SHOP_STATE.AutoSellFruits =
        false
end

function HolyPerformanceBuildStatusText()

    return "Status: "
        .. tostring(
            HOLY_PERFORMANCE_STATE
            and HOLY_PERFORMANCE_STATE.LastStatus
            or "Ready."
        )
end

function HolyPerformanceRefreshUI()

    return false
end

function HolyPerformanceSetStatus(status)

    HOLY_PERFORMANCE_STATE =
        type(HOLY_PERFORMANCE_STATE) == "table"
        and HOLY_PERFORMANCE_STATE
        or {}

    HOLY_PERFORMANCE_STATE.LastStatus =
        tostring(status or "Ready.")

    return true
end

function HolyPerformanceDisconnectBackpackWatcher()

    local connection =
        HOLY_PERFORMANCE_STATE.BackpackConnection

    if connection then

        pcall(function()

            connection:Disconnect()
        end)
    end

    HOLY_PERFORMANCE_STATE.BackpackConnection =
        nil
end

function HolyPerformanceDeleteBackpackOnce(reason)

    if HOLY_DEV_UI_STATE.DeleteBackpack ~= true
    or not LocalPlayer then

        return false
    end

    local backpack =
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )

    if typeof(backpack) ~= "Instance" then
        return false
    end

    local toolCount =
        0

    for _, child in ipairs(
        backpack:GetChildren()
    ) do

        if child:IsA("Tool") then

            toolCount +=
                1
        end
    end

    local ok =
        pcall(function()

            backpack:Destroy()
        end)

    if ok == true then

        HOLY_PERFORMANCE_STATE.DeletedCount =
            (
                tonumber(
                    HOLY_PERFORMANCE_STATE.DeletedCount
                )
                or 0
            )
            + toolCount
            + 1

        HolyPerformanceSetStatus(
            "Backpack deleted."
        )
    end

    return ok == true
end

function HolyPerformanceConnectBackpackWatcher()

    HolyPerformanceDisconnectBackpackWatcher()

    if HOLY_DEV_UI_STATE.DeleteBackpack ~= true
    or not LocalPlayer then

        return false
    end

    HOLY_PERFORMANCE_STATE.BackpackConnection =
        LocalPlayer.ChildAdded:Connect(function(child)

            if child:IsA("Backpack") then

                task.defer(function()

                    if HOLY_DEV_UI_STATE.DeleteBackpack == true
                    and child.Parent == LocalPlayer then

                        pcall(function()

                            child:Destroy()
                        end)
                    end
                end)
            end
        end)

    return true
end

function HolyPerformanceStartDeleteBackpack(reason)

    HOLY_DEV_UI_STATE.DeleteBackpack =
        true

    HolySaveUISettings()

    HolyPerformanceConnectBackpackWatcher()

    HolyPerformanceDeleteBackpackOnce(
        reason
        or "performance"
    )

    return true
end

function HolyPerformanceStopDeleteBackpack(reason)

    HOLY_DEV_UI_STATE.DeleteBackpack =
        false

    HolySaveUISettings()

    HolyPerformanceDisconnectBackpackWatcher()

    HolyPerformanceSetStatus(
        "Backpack deletion stopped. Rejoin to restore."
    )

    return true
end

function HolyPerformanceGetGardensRoot()

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if typeof(gardens) == "Instance" then
        return gardens
    end

    gardens =
        workspace:FindFirstChild(
            "Gardens",
            true
        )

    if typeof(gardens) == "Instance" then
        return gardens
    end

    return nil
end

function HolyPerformanceIsPlot(instance)

    return typeof(instance) == "Instance"
        and (
            instance:IsA("Model")
            or instance:IsA("Folder")
        )
end

function HolyPerformanceDisconnectConnectionMap(map)

    if type(map) ~= "table" then
        return
    end

    for _, connection in pairs(map) do

        if connection then

            pcall(function()

                connection:Disconnect()
            end)
        end
    end
end

function HolyPerformanceDisconnectConnections()

    HOLY_PERFORMANCE_STATE =
        type(HOLY_PERFORMANCE_STATE) == "table"
        and HOLY_PERFORMANCE_STATE
        or {}

    HolyPerformanceDisconnectConnectionMap(
        HOLY_PERFORMANCE_STATE.Connections
    )

    HolyPerformanceDisconnectConnectionMap(
        HOLY_PERFORMANCE_STATE.PlotConnections
    )

    HolyPerformanceDisconnectConnectionMap(
        HOLY_PERFORMANCE_STATE.MapConnections
    )

    HOLY_PERFORMANCE_STATE.Connections =
        {}

    HOLY_PERFORMANCE_STATE.PlotConnections =
        {}

    HOLY_PERFORMANCE_STATE.MapConnections =
        {}
end

function HolyPerformanceReadPlotAttribute(plot, attributeName)

    if typeof(plot) ~= "Instance" then
        return nil
    end

    local value =
        nil

    pcall(function()

        value =
            plot:GetAttribute(
                attributeName
            )
    end)

    return value
end

function HolyPerformancePlotOwnedByLocal(plot)

    if HolyPerformanceIsPlot(plot) ~= true then
        return false,
            ""
    end

    local localUserId =
        tostring(
            LocalPlayer
            and LocalPlayer.UserId
            or ""
        )

    local localName =
        HolyCleanText(
            LocalPlayer
            and LocalPlayer.Name
            or ""
        )

    local ownerUserId =
        HolyPerformanceReadPlotAttribute(
            plot,
            "OwnerUserId"
        )

    if ownerUserId ~= nil
    and tostring(ownerUserId) == localUserId then

        return true,
            "OwnerUserId="
                .. tostring(ownerUserId)
    end

    local ownerName =
        HolyCleanText(
            HolyPerformanceReadPlotAttribute(
                plot,
                "Owner"
            )
        )

    if ownerName ~= ""
    and localName ~= ""
    and ownerName == localName then

        return true,
            "Owner="
                .. tostring(ownerName)
    end

    return false,
        ""
end

function HolyPerformanceFindOwnPlotOnce(gardens)

    if typeof(gardens) ~= "Instance" then
        return nil,
            "gardens missing"
    end

    for _, plot in ipairs(gardens:GetChildren()) do

        if HolyPerformanceIsPlot(plot) == true then

            local owned,
                marker =
                HolyPerformancePlotOwnedByLocal(
                    plot
                )

            if owned == true then

                return plot,
                    marker
            end
        end
    end

    return nil,
        "no owner attribute match"
end

function HolyPerformanceResolveOwnPlot(gardens)

    HOLY_PERFORMANCE_STATE =
        type(HOLY_PERFORMANCE_STATE) == "table"
        and HOLY_PERFORMANCE_STATE
        or {}

    if typeof(gardens) ~= "Instance" then
        return nil,
            "gardens missing"
    end

    local cached =
        HOLY_PERFORMANCE_STATE.OwnPlot

    if typeof(cached) == "Instance"
    and cached.Parent == gardens then

        local owned,
            marker =
            HolyPerformancePlotOwnedByLocal(
                cached
            )

        if owned == true then

            HOLY_PERFORMANCE_STATE.OwnMarker =
                marker

            return cached,
                marker
        end
    end

    local startedAt =
        os.clock()

    local lastReason =
        ""

    while os.clock() - startedAt <= 4 do

        local plot,
            reason =
            HolyPerformanceFindOwnPlotOnce(
                gardens
            )

        lastReason =
            tostring(reason or "")

        if typeof(plot) == "Instance" then

            HOLY_PERFORMANCE_STATE.OwnPlot =
                plot

            HOLY_PERFORMANCE_STATE.OwnMarker =
                lastReason

            return plot,
                lastReason
        end

        task.wait(
            0.10
        )
    end

    return nil,
        lastReason
end

function HolyPerformanceModeDisconnectSingle(connection)

    if connection then

        pcall(function()

            connection:Disconnect()
        end)
    end
end

function HolyPerformanceModeDisconnect()

    HOLY_PERFORMANCE_STATE =
        type(HOLY_PERFORMANCE_STATE) == "table"
        and HOLY_PERFORMANCE_STATE
        or {}

    local connections =
        HOLY_PERFORMANCE_STATE.PerformanceModeConnections

    if type(connections) == "table" then

        for _, connection in pairs(connections) do

            HolyPerformanceModeDisconnectSingle(
                connection
            )
        end
    end

    HolyPerformanceModeDisconnectSingle(
        HOLY_PERFORMANCE_STATE.PerformanceModePlotConnection
    )

    HolyPerformanceModeDisconnectSingle(
        HOLY_PERFORMANCE_STATE.PerformanceModePlantsConnection
    )

    HOLY_PERFORMANCE_STATE.PerformanceModeConnections =
        {}

    HOLY_PERFORMANCE_STATE.PerformanceModePlotConnection =
        nil

    HOLY_PERFORMANCE_STATE.PerformanceModePlantsConnection =
        nil
end

function HolyPerformanceModeDestroy(instance)

    if typeof(instance) ~= "Instance"
    or instance.Parent == nil then

        return 0
    end

    local removedCount =
        1

    pcall(function()

        removedCount =
            removedCount
            + #instance:GetDescendants()
    end)

    local destroyed =
        pcall(function()

            instance:Destroy()
        end)

    if destroyed ~= true then
        return 0
    end

    HOLY_PERFORMANCE_STATE.DeletedCount =
        (
            tonumber(
                HOLY_PERFORMANCE_STATE.DeletedCount
            )
            or 0
        )
        + removedCount

    HOLY_PERFORMANCE_STATE.RemovedCount =
        (
            tonumber(
                HOLY_PERFORMANCE_STATE.RemovedCount
            )
            or 0
        )
        + removedCount

    return removedCount
end

function HolyPerformanceModeShouldDestroyVisual(instance)

    if typeof(instance) ~= "Instance" then
        return false
    end

    return instance:IsA("Decal")
        or instance:IsA("Texture")
        or instance:IsA("ParticleEmitter")
        or instance:IsA("Trail")
        or instance:IsA("Beam")
        or instance:IsA("Smoke")
        or instance:IsA("Fire")
        or instance:IsA("Sparkles")
        or instance:IsA("Highlight")
        or instance:IsA("PostEffect")
        or instance:IsA("Atmosphere")
        or instance:IsA("Sky")
end

function HolyPerformanceModeSimplifyInstance(instance)

    if typeof(instance) ~= "Instance"
    or instance.Parent == nil then

        return false
    end

    if HolyPerformanceModeShouldDestroyVisual(
        instance
    ) == true then

        return HolyPerformanceModeDestroy(
            instance
        ) > 0
    end

    if instance:IsA("BasePart") then

        pcall(function()

            instance.Material =
                Enum.Material.SmoothPlastic

            instance.CastShadow =
                false

            instance.Reflectance =
                0
        end)

        return true
    end

    return false
end

function HolyPerformanceModeApplyEnvironment()

    pcall(function()

        Lighting.Brightness =
            0

        Lighting.GlobalShadows =
            false

        Lighting.EnvironmentDiffuseScale =
            0

        Lighting.EnvironmentSpecularScale =
            0

        Lighting.FogEnd =
            9000000000
    end)

    local terrain =
        workspace:FindFirstChildOfClass(
            "Terrain"
        )

    if typeof(terrain) == "Instance" then

        pcall(function()

            terrain.WaterWaveSize =
                0

            terrain.WaterWaveSpeed =
                0

            terrain.WaterReflectance =
                0

            terrain.WaterTransparency =
                0
        end)
    end
end

function HolyPerformanceModeApplyWorld(token)

    HolyPerformanceModeApplyEnvironment()

    local workspaceObjects =
        {}

    pcall(function()

        workspaceObjects =
            workspace:GetDescendants()
    end)

    for index, instance in ipairs(workspaceObjects) do

        if HOLY_DEV_UI_STATE.PerformanceMode ~= true
        or HOLY_PERFORMANCE_STATE.PerformanceModeToken ~= token then

            return false
        end

        HolyPerformanceModeSimplifyInstance(
            instance
        )

        if index % 400 == 0 then

            task.wait()
        end
    end

    local lightingObjects =
        {}

    pcall(function()

        lightingObjects =
            Lighting:GetDescendants()
    end)

    for index, instance in ipairs(lightingObjects) do

        if HOLY_DEV_UI_STATE.PerformanceMode ~= true
        or HOLY_PERFORMANCE_STATE.PerformanceModeToken ~= token then

            return false
        end

        HolyPerformanceModeSimplifyInstance(
            instance
        )

        if index % 200 == 0 then

            task.wait()
        end
    end

    return true
end

function HolyPerformanceModeClearPlants(plants)

    if HOLY_DEV_UI_STATE.PerformanceMode ~= true
    or typeof(plants) ~= "Instance" then

        return 0
    end

    local children =
        {}

    pcall(function()

        children =
            plants:GetChildren()
    end)

    local removed =
        0

    for _, child in ipairs(children) do

        if HOLY_DEV_UI_STATE.PerformanceMode ~= true then
            break
        end

        if typeof(child) == "Instance"
        and child.Parent == plants then

            removed =
                removed
                + HolyPerformanceModeDestroy(
                    child
                )
        end
    end

    if removed > 0 then

        HolyPerformanceSetStatus(
            "Performance mode removed "
            .. tostring(removed)
            .. " plant instances."
        )
    end

    return removed
end

function HolyPerformanceModeBindOwnPlants()

    if HOLY_DEV_UI_STATE.PerformanceMode ~= true then
        return false
    end

    local gardens =
        HolyPerformanceGetGardensRoot()

    if typeof(gardens) ~= "Instance" then
        return false
    end

    local ownPlot =
        select(
            1,
            HolyPerformanceResolveOwnPlot(
                gardens
            )
        )

    if typeof(ownPlot) ~= "Instance" then
        return false
    end

    HolyPerformanceModeDisconnectSingle(
        HOLY_PERFORMANCE_STATE.PerformanceModePlotConnection
    )

    HolyPerformanceModeDisconnectSingle(
        HOLY_PERFORMANCE_STATE.PerformanceModePlantsConnection
    )

    HOLY_PERFORMANCE_STATE.PerformanceModePlotConnection =
        ownPlot.ChildAdded:Connect(function(child)

            if child.Name == "Plants" then

                task.defer(function()

                    if HOLY_DEV_UI_STATE.PerformanceMode == true
                    and child.Parent == ownPlot then

                        HolyPerformanceModeBindOwnPlants()
                    end
                end)
            end
        end)

    local plants =
        ownPlot:FindFirstChild(
            "Plants"
        )

    if typeof(plants) ~= "Instance" then

        HolyPerformanceSetStatus(
            "Performance mode waiting for Plants."
        )

        return true
    end

    HOLY_PERFORMANCE_STATE.PerformanceModePlantsConnection =
        plants.ChildAdded:Connect(function(child)

            task.defer(function()

                if HOLY_DEV_UI_STATE.PerformanceMode == true
                and child.Parent == plants then

                    HolyPerformanceModeDestroy(
                        child
                    )
                end
            end)
        end)

    HolyPerformanceModeClearPlants(
        plants
    )

    return true
end

function HolyPerformanceModeStart(reason)

    HOLY_DEV_UI_STATE.PerformanceMode =
        true

    HolySaveUISettings()

    HolyPerformanceModeDisconnect()

    HOLY_PERFORMANCE_STATE.PerformanceModeToken =
        (
            tonumber(
                HOLY_PERFORMANCE_STATE.PerformanceModeToken
            )
            or 0
        )
        + 1

    local token =
        HOLY_PERFORMANCE_STATE.PerformanceModeToken

    HOLY_PERFORMANCE_STATE.PerformanceModeConnections =
        {}

    table.insert(
        HOLY_PERFORMANCE_STATE.PerformanceModeConnections,
        workspace.DescendantAdded:Connect(function(instance)

            task.defer(function()

                if HOLY_DEV_UI_STATE.PerformanceMode ~= true
                or HOLY_PERFORMANCE_STATE.PerformanceModeToken
                    ~= token then

                    return
                end

                HolyPerformanceModeSimplifyInstance(
                    instance
                )

                if instance.Name == "Plants" then

                    HolyPerformanceModeBindOwnPlants()
                end
            end)
        end)
    )

    table.insert(
        HOLY_PERFORMANCE_STATE.PerformanceModeConnections,
        Lighting.DescendantAdded:Connect(function(instance)

            task.defer(function()

                if HOLY_DEV_UI_STATE.PerformanceMode == true
                and HOLY_PERFORMANCE_STATE.PerformanceModeToken
                    == token then

                    HolyPerformanceModeSimplifyInstance(
                        instance
                    )
                end
            end)
        end)
    )

    task.spawn(function()

        local deadline =
            os.clock() + 6

        while HOLY_DEV_UI_STATE.PerformanceMode == true
        and HOLY_PERFORMANCE_STATE.PerformanceModeToken == token
        and os.clock() <= deadline do

            if HolyPerformanceModeBindOwnPlants() == true then
                break
            end

            task.wait(
                0.25
            )
        end

        if HOLY_DEV_UI_STATE.PerformanceMode ~= true
        or HOLY_PERFORMANCE_STATE.PerformanceModeToken ~= token then

            return
        end

        HolyPerformanceModeApplyWorld(
            token
        )

        if HOLY_DEV_UI_STATE.PerformanceMode == true
        and HOLY_PERFORMANCE_STATE.PerformanceModeToken == token then

            HolyPerformanceSetStatus(
                "Performance mode applied."
            )
        end
    end)

    return true
end

function HolyPerformanceModeStop(reason)

    HOLY_DEV_UI_STATE.PerformanceMode =
        false

    HolySaveUISettings()

    HOLY_PERFORMANCE_STATE.PerformanceModeToken =
        (
            tonumber(
                HOLY_PERFORMANCE_STATE.PerformanceModeToken
            )
            or 0
        )
        + 1

    HolyPerformanceModeDisconnect()

    HolyPerformanceSetStatus(
        "Performance mode stopped. Rejoin to restore visuals."
    )

    return true
end


function HolyPerformanceIsOwnGarden(garden, ownGarden)

    if typeof(garden) ~= "Instance"
    or typeof(ownGarden) ~= "Instance" then

        return false
    end

    return garden == ownGarden
end

function HolyPerformanceAnyGardenUnloadEnabled()

    return HOLY_DEV_UI_STATE.UnloadOtherGardens == true
        or HOLY_DEV_UI_STATE.UnloadOwnGarden == true
end

function HolyPerformanceAnyUnloadEnabled()

    return HolyPerformanceAnyGardenUnloadEnabled() == true
        or HOLY_DEV_UI_STATE.HideMiddle == true
end

function HolyPerformanceShouldProcessPlot(plot, ownPlot)

    if HolyPerformanceIsPlot(plot) ~= true then
        return false
    end

    if plot == ownPlot then

        return HOLY_DEV_UI_STATE.UnloadOwnGarden == true
    end

    -- Other plots are handled by the early fast loader. Keeping the legacy
    -- cleaner away from them prevents it from detaching Visual and containers.
    return false
end

function HolyPerformanceShouldRemoveChild(child)

    if typeof(child) ~= "Instance" then
        return false
    end

    local removeNames = {
        Plants = true,
        Sprinklers = true,
        Props = true,
    }

    return removeNames[
        tostring(child.Name)
    ] == true
end

function HolyPerformanceShouldHideChild(child)

    if typeof(child) ~= "Instance" then
        return false
    end

    local hideNames = {
        Signs = true,
        SpawnPoint = true,
        PlotSizeReference = true,
        LoadingCam = true,
        LoadingScreenCam = true,
    }

    return hideNames[
        tostring(child.Name)
    ] == true
end

function HolyPerformanceGetMapRoot()

    local map =
        workspace:FindFirstChild(
            "Map"
        )

    if typeof(map) == "Instance" then
        return map
    end

    map =
        workspace:FindFirstChild(
            "Map",
            true
        )

    if typeof(map) == "Instance" then
        return map
    end

    return nil
end

function HolyPerformanceGetMiddleRoot()

    local map =
        HolyPerformanceGetMapRoot()

    if typeof(map) ~= "Instance" then
        return nil,
            nil
    end

    local middle =
        map:FindFirstChild(
            "Middle"
        )

    if typeof(middle) == "Instance" then
        return middle,
            map
    end

    return nil,
        map
end

function HolyPerformanceGetStandsRoot()

    local map =
        HolyPerformanceGetMapRoot()

    if typeof(map) ~= "Instance" then
        return nil
    end

    local stands =
        map:FindFirstChild(
            "Stands"
        )

    if typeof(stands) == "Instance" then
        return stands
    end

    return nil
end

function HolyPerformanceGetNpcsRoot()

    local npcs =
        workspace:FindFirstChild(
            "NPCS"
        )

    if typeof(npcs) == "Instance" then
        return npcs
    end

    npcs =
        workspace:FindFirstChild(
            "NPCS",
            true
        )

    if typeof(npcs) == "Instance" then
        return npcs
    end

    return nil
end

function HolyPerformanceHideInstanceVisual(instance)

    if typeof(instance) ~= "Instance" then
        return false
    end

    local changed =
        false

    if instance:IsA("BasePart") then

        pcall(function()

            instance.Transparency =
                1

            instance.LocalTransparencyModifier =
                1

            instance.CanCollide =
                false

            instance.CanTouch =
                false

            instance.CanQuery =
                false

            instance.CastShadow =
                false
        end)

        changed =
            true
    end

    if instance:IsA("Decal")
    or instance:IsA("Texture") then

        pcall(function()

            instance.Transparency =
                1
        end)

        changed =
            true
    end

    if instance:IsA("ParticleEmitter")
    or instance:IsA("Beam")
    or instance:IsA("Trail")
    or instance:IsA("Fire")
    or instance:IsA("Smoke")
    or instance:IsA("Sparkles") then

        pcall(function()

            instance.Enabled =
                false
        end)

        changed =
            true
    end

    if instance:IsA("BillboardGui")
    or instance:IsA("SurfaceGui") then

        pcall(function()

            instance.Enabled =
                false
        end)

        changed =
            true
    end

    if instance:IsA("ProximityPrompt") then

        pcall(function()

            instance.Enabled =
                false
        end)

        changed =
            true
    end

    if instance:IsA("TextLabel")
    or instance:IsA("TextButton")
    or instance:IsA("TextBox") then

        pcall(function()

            instance.TextTransparency =
                1

            instance.TextStrokeTransparency =
                1

            instance.BackgroundTransparency =
                1
        end)

        changed =
            true
    end

    return changed
end

function HolyPerformanceHideVisualTree(root)

    if typeof(root) ~= "Instance" then
        return 0
    end

    local changed =
        0

    if HolyPerformanceHideInstanceVisual(root) == true then

        changed =
            changed + 1
    end

    local descendants =
        {}

    pcall(function()

        descendants =
            root:GetDescendants()
    end)

    for _, descendant in ipairs(descendants) do

        if HolyPerformanceHideInstanceVisual(
            descendant
        ) == true then

            changed =
                changed + 1
        end
    end

    HOLY_PERFORMANCE_STATE.HiddenCount =
        (
            tonumber(
                HOLY_PERFORMANCE_STATE.HiddenCount
            )
            or 0
        )
        + changed

    return changed
end

function HolyPerformanceRemoveChild(child)

    if typeof(child) ~= "Instance" then
        return false
    end

    local ok =
        pcall(function()

            child.Parent =
                nil
        end)

    if ok == true then

        HOLY_PERFORMANCE_STATE.RemovedCount =
            (
                tonumber(
                    HOLY_PERFORMANCE_STATE.RemovedCount
                )
                or 0
            )
            + 1

        HOLY_PERFORMANCE_STATE.DeletedCount =
            HOLY_PERFORMANCE_STATE.RemovedCount

        return true
    end

    return false
end

function HolyPerformanceRemoveMiddleChildren(middle)

    if typeof(middle) ~= "Instance" then
        return 0
    end

    local children =
        {}

    pcall(function()

        children =
            middle:GetChildren()
    end)

    local removed =
        0

    for _, child in ipairs(children) do

        if typeof(child) == "Instance"
        and child.Parent == middle then

            if HolyPerformanceRemoveChild(child) == true then

                removed =
                    removed + 1
            end
        end
    end

    return removed
end

function HolyPerformanceHideMiddleOnce(reason)

    if HOLY_DEV_UI_STATE.HideMiddle ~= true then
        return 0
    end

    local totalChanged =
        0

    local middle =
        HolyPerformanceGetMiddleRoot()

    if typeof(middle) == "Instance" then

        totalChanged =
            totalChanged
            + HolyPerformanceRemoveMiddleChildren(
                middle
            )
    end

    local stands =
        HolyPerformanceGetStandsRoot()

    if typeof(stands) == "Instance" then

        totalChanged =
            totalChanged
            + HolyPerformanceHideVisualTree(
                stands
            )
    end

    local npcs =
        HolyPerformanceGetNpcsRoot()

    if typeof(npcs) == "Instance" then

        totalChanged =
            totalChanged
            + HolyPerformanceHideVisualTree(
                npcs
            )
    end

    if totalChanged > 0 then

        HolyPerformanceSetStatus(
            "Applied."
        )

    else

        HolyPerformanceSetStatus(
            "Waiting."
        )
    end

    return totalChanged
end

function HolyPerformanceConnectHideTreeWatcher(root)

    if HOLY_DEV_UI_STATE.HideMiddle ~= true then
        return false
    end

    if typeof(root) ~= "Instance" then
        return false
    end

    HOLY_PERFORMANCE_STATE.MapConnections =
        type(HOLY_PERFORMANCE_STATE.MapConnections) == "table"
        and HOLY_PERFORMANCE_STATE.MapConnections
        or {}

    if HOLY_PERFORMANCE_STATE.MapConnections[root] then
        return true
    end

    HOLY_PERFORMANCE_STATE.MapConnections[root] =
        root.ChildAdded:Connect(function(child)

            task.defer(function()

                if HOLY_DEV_UI_STATE.HideMiddle ~= true
                or HOLY_PERFORMANCE_STATE.Active ~= true then

                    return
                end

                if typeof(child) == "Instance"
                and child.Parent == root then

                    HolyPerformanceHideVisualTree(
                        child
                    )
                end
            end)
        end)

    return true
end

function HolyPerformanceConnectMiddleWatcher()

    if HOLY_DEV_UI_STATE.HideMiddle ~= true then
        return false
    end

    HOLY_PERFORMANCE_STATE.MapConnections =
        type(HOLY_PERFORMANCE_STATE.MapConnections) == "table"
        and HOLY_PERFORMANCE_STATE.MapConnections
        or {}

    local middle,
        map =
        HolyPerformanceGetMiddleRoot()

    if typeof(middle) == "Instance"
    and HOLY_PERFORMANCE_STATE.MapConnections[middle] == nil then

        HOLY_PERFORMANCE_STATE.MapConnections[middle] =
            middle.ChildAdded:Connect(function(child)

                task.defer(function()

                    if HOLY_DEV_UI_STATE.HideMiddle ~= true
                    or HOLY_PERFORMANCE_STATE.Active ~= true then

                        return
                    end

                    if typeof(child) == "Instance"
                    and typeof(middle) == "Instance"
                    and child.Parent == middle then

                        HolyPerformanceRemoveChild(
                            child
                        )
                    end
                end)
            end)
    end

    local stands =
        HolyPerformanceGetStandsRoot()

    if typeof(stands) == "Instance" then

        HolyPerformanceConnectHideTreeWatcher(
            stands
        )
    end

    local npcs =
        HolyPerformanceGetNpcsRoot()

    if typeof(npcs) == "Instance" then

        HolyPerformanceConnectHideTreeWatcher(
            npcs
        )
    end

    if typeof(map) == "Instance"
    and HOLY_PERFORMANCE_STATE.MapConnections.__MapChildAdded == nil then

        HOLY_PERFORMANCE_STATE.MapConnections.__MapChildAdded =
            map.ChildAdded:Connect(function(child)

                task.delay(0.25, function()

                    if HOLY_DEV_UI_STATE.HideMiddle ~= true
                    or HOLY_PERFORMANCE_STATE.Active ~= true then

                        return
                    end

                    if typeof(child) ~= "Instance" then
                        return
                    end

                    if child.Name == "Middle" then

                        HolyPerformanceHideMiddleOnce(
                            "middle added"
                        )

                        HolyPerformanceConnectMiddleWatcher()

                    elseif child.Name == "Stands" then

                        HolyPerformanceHideVisualTree(
                            child
                        )

                        HolyPerformanceConnectHideTreeWatcher(
                            child
                        )
                    end
                end)
            end)
    end

    if HOLY_PERFORMANCE_STATE.MapConnections.__WorkspaceChildAdded == nil then

        HOLY_PERFORMANCE_STATE.MapConnections.__WorkspaceChildAdded =
            workspace.ChildAdded:Connect(function(child)

                task.delay(0.25, function()

                    if HOLY_DEV_UI_STATE.HideMiddle ~= true
                    or HOLY_PERFORMANCE_STATE.Active ~= true then

                        return
                    end

                    if typeof(child) == "Instance"
                    and child.Name == "NPCS" then

                        HolyPerformanceHideVisualTree(
                            child
                        )

                        HolyPerformanceConnectHideTreeWatcher(
                            child
                        )
                    end
                end)
            end)
    end

    return true
end

function HolyPerformanceProcessPlotChild(child)

    if typeof(child) ~= "Instance" then

        return "skip",
            0
    end

    if HolyPerformanceShouldRemoveChild(child) == true then

        if HolyPerformanceRemoveChild(child) == true then

            return "removed",
                1
        end

        return "failed",
            0
    end

    if HolyPerformanceShouldHideChild(child) == true then

        return "hidden",
            HolyPerformanceHideVisualTree(
                child
            )
    end

    return "kept",
        0
end

function HolyPerformanceConnectPlotCleaner(plot)

    if HolyPerformanceIsPlot(plot) ~= true then
        return false
    end

    HOLY_PERFORMANCE_STATE.PlotConnections =
        type(HOLY_PERFORMANCE_STATE.PlotConnections) == "table"
        and HOLY_PERFORMANCE_STATE.PlotConnections
        or {}

    if HOLY_PERFORMANCE_STATE.PlotConnections[plot] then
        return true
    end

    HOLY_PERFORMANCE_STATE.PlotConnections[plot] =
        plot.ChildAdded:Connect(function(child)

            task.defer(function()

                if HolyPerformanceAnyUnloadEnabled() ~= true
                or HOLY_PERFORMANCE_STATE.Active ~= true then

                    return
                end

                local gardens =
                    HolyPerformanceGetGardensRoot()

                if typeof(gardens) ~= "Instance" then
                    return
                end

                local ownPlot =
                    HOLY_PERFORMANCE_STATE.OwnPlot

                if typeof(ownPlot) ~= "Instance"
                or ownPlot.Parent ~= gardens then

                    ownPlot =
                        select(
                            1,
                            HolyPerformanceResolveOwnPlot(
                                gardens
                            )
                        )
                end

                if typeof(ownPlot) ~= "Instance" then
                    return
                end

                if HolyPerformanceShouldProcessPlot(
                    plot,
                    ownPlot
                ) ~= true then

                    return
                end

                HolyPerformanceProcessPlotChild(
                    child
                )
            end)
        end)

    return true
end

function HolyPerformanceProcessPlot(plot, ownPlot)

    if HolyPerformanceIsPlot(plot) ~= true then
        return 0,
            0
    end

    if HolyPerformanceShouldProcessPlot(
        plot,
        ownPlot
    ) ~= true then

        return 0,
            0
    end

    local children =
        {}

    pcall(function()

        children =
            plot:GetChildren()
    end)

    local removed =
        0

    local hidden =
        0

    for _, child in ipairs(children) do

        if typeof(child) == "Instance"
        and child.Parent == plot then

            local action,
                amount =
                HolyPerformanceProcessPlotChild(
                    child
                )

            if action == "removed" then

                removed =
                    removed + amount

            elseif action == "hidden" then

                hidden =
                    hidden + amount
            end
        end
    end

    if removed > 0
    or hidden > 0 then

        HOLY_PERFORMANCE_STATE.ProcessedPlots =
            type(HOLY_PERFORMANCE_STATE.ProcessedPlots) == "table"
            and HOLY_PERFORMANCE_STATE.ProcessedPlots
            or {}

        HOLY_PERFORMANCE_STATE.ProcessedPlots[plot] =
            true
    end

    HolyPerformanceConnectPlotCleaner(
        plot
    )

    return removed,
        hidden
end

function HolyPerformanceProcessOtherPlot(plot, ownPlot)

    return HolyPerformanceProcessPlot(
        plot,
        ownPlot
    )
end

function HolyPerformanceDeleteOtherGardensOnce(reason)

    if HolyPerformanceAnyUnloadEnabled() ~= true then
        return 0
    end

    local totalRemoved =
        0

    if HOLY_DEV_UI_STATE.HideMiddle == true then

        totalRemoved =
            totalRemoved
            + HolyPerformanceHideMiddleOnce(
                reason
                or "apply"
            )
    end

    if HolyPerformanceAnyGardenUnloadEnabled() ~= true then

        HolyPerformanceSetStatus(
            "Applied."
        )

        return totalRemoved
    end

    local gardens =
        HolyPerformanceGetGardensRoot()

    if typeof(gardens) ~= "Instance" then

        HolyPerformanceSetStatus(
            "Waiting."
        )

        return totalRemoved
    end

    local ownPlot =
        select(
            1,
            HolyPerformanceResolveOwnPlot(
                gardens
            )
        )

    if typeof(ownPlot) ~= "Instance" then

        HolyPerformanceSetStatus(
            "Waiting."
        )

        return totalRemoved
    end

    local removedThisPass =
        0

    local hiddenThisPass =
        0

    for _, plot in ipairs(gardens:GetChildren()) do

        if HolyPerformanceIsPlot(plot) == true then

            local removed,
                hidden =
                HolyPerformanceProcessPlot(
                    plot,
                    ownPlot
                )

            removedThisPass =
                removedThisPass + removed

            hiddenThisPass =
                hiddenThisPass + hidden
        end
    end

    HolyPerformanceSetStatus(
        "Applied."
    )

    return totalRemoved
        + removedThisPass
end

function HolyPerformanceConnectGardenWatcher()

    HolyPerformanceDisconnectConnections()

    HOLY_PERFORMANCE_STATE.Connections =
        {}

    HOLY_PERFORMANCE_STATE.PlotConnections =
        {}

    HOLY_PERFORMANCE_STATE.MapConnections =
        {}

    if HOLY_DEV_UI_STATE.HideMiddle == true then

        HolyPerformanceConnectMiddleWatcher()
    end

    if HolyPerformanceAnyGardenUnloadEnabled() ~= true then
        return true
    end

    local gardens =
        HolyPerformanceGetGardensRoot()

    if typeof(gardens) ~= "Instance" then
        return false
    end

    local ownPlot =
        HOLY_PERFORMANCE_STATE.OwnPlot

    if typeof(ownPlot) ~= "Instance"
    or ownPlot.Parent ~= gardens then

        ownPlot =
            select(
                1,
                HolyPerformanceResolveOwnPlot(
                    gardens
                )
            )
    end

    for _, plot in ipairs(gardens:GetChildren()) do

        if HolyPerformanceIsPlot(plot) == true
        and typeof(ownPlot) == "Instance"
        and HolyPerformanceShouldProcessPlot(
            plot,
            ownPlot
        ) == true then

            HolyPerformanceConnectPlotCleaner(
                plot
            )
        end
    end

    table.insert(
        HOLY_PERFORMANCE_STATE.Connections,
        gardens.ChildAdded:Connect(function(plot)

            task.delay(0.45, function()

                if HolyPerformanceAnyUnloadEnabled() ~= true
                or HOLY_PERFORMANCE_STATE.Active ~= true then

                    return
                end

                if HolyPerformanceIsPlot(plot) ~= true then
                    return
                end

                if typeof(plot) ~= "Instance"
                or plot.Parent ~= gardens then

                    return
                end

                local owned,
                    marker =
                    HolyPerformancePlotOwnedByLocal(
                        plot
                    )

                if owned == true then

                    HOLY_PERFORMANCE_STATE.OwnPlot =
                        plot

                    HOLY_PERFORMANCE_STATE.OwnMarker =
                        marker
                end

                local resolvedOwnPlot =
                    HOLY_PERFORMANCE_STATE.OwnPlot

                if typeof(resolvedOwnPlot) ~= "Instance"
                or resolvedOwnPlot.Parent ~= gardens then

                    resolvedOwnPlot =
                        select(
                            1,
                            HolyPerformanceResolveOwnPlot(
                                gardens
                            )
                        )
                end

                if typeof(resolvedOwnPlot) ~= "Instance" then
                    return
                end

                if HolyPerformanceShouldProcessPlot(
                    plot,
                    resolvedOwnPlot
                ) == true then

                    HolyPerformanceProcessPlot(
                        plot,
                        resolvedOwnPlot
                    )
                end
            end)
        end)
    )

    return true
end

function HolyPerformanceStartApply(reason)

    if HolyPerformanceAnyUnloadEnabled() ~= true then
        return false
    end

    HOLY_PERFORMANCE_STATE.Active =
        true

    HolySaveUISettings()

    if HOLY_PERFORMANCE_STATE.Applying == true then
        return true
    end

    HOLY_PERFORMANCE_STATE.Applying =
        true

    task.spawn(function()

        local deadline =
            os.clock() + 6

        while HolyPerformanceAnyUnloadEnabled() == true
        and HOLY_PERFORMANCE_STATE.Active == true
        and os.clock() <= deadline do

            if HOLY_DEV_UI_STATE.HideMiddle == true then

                HolyPerformanceHideMiddleOnce(
                    reason
                    or "apply"
                )

                HolyPerformanceConnectMiddleWatcher()
            end

            if HolyPerformanceAnyGardenUnloadEnabled() ~= true then

                HolyPerformanceConnectGardenWatcher()

                break
            end

            local gardens =
                HolyPerformanceGetGardensRoot()

            if typeof(gardens) == "Instance" then

                local ownPlot =
                    select(
                        1,
                        HolyPerformanceResolveOwnPlot(
                            gardens
                        )
                    )

                if typeof(ownPlot) == "Instance" then

                    HolyPerformanceDeleteOtherGardensOnce(
                        reason
                        or "apply"
                    )

                    HolyPerformanceConnectGardenWatcher()

                    break
                end
            end

            task.wait(
                0.10
            )
        end

        HOLY_PERFORMANCE_STATE.Applying =
            false
    end)

    return true
end

function HolyPerformanceStartUnloadOtherGardens(reason)

    HOLY_DEV_UI_STATE.UnloadOtherGardens =
        true

    HOLY_PERFORMANCE_STATE.Active =
        true

    HolySaveUISettings()

    local env =
        (
            type(getgenv) == "function"
            and getgenv()
        )
        or _G

    env.HOLY_FAST_LOADER_FORCE_ENABLED =
        true

    local queued =
        type(env.HOLY_FAST_LOADER_QUEUE) == "function"
        and env.HOLY_FAST_LOADER_QUEUE() == true

    local started =
        type(env.HOLY_FAST_LOADER_RUN) == "function"
        and env.HOLY_FAST_LOADER_RUN() == true

    HolyPerformanceSetStatus(
        started == true
        and (
            queued == true
            and "Fast loader active and queued for the next server."
            or "Fast loader active. Rejoin for the earliest startup patch."
        )
        or "Fast loader saved. Rejoin to apply it."
    )

    return started == true
        or queued == true
end

function HolyPerformanceStopUnloadOtherGardens(reason)

    HOLY_DEV_UI_STATE.UnloadOtherGardens =
        false

    HolySaveUISettings()

    local env =
        (
            type(getgenv) == "function"
            and getgenv()
        )
        or _G

    env.HOLY_FAST_LOADER_FORCE_ENABLED =
        false

    if type(env.HOLY_FAST_LOADER_STOP) == "function" then

        pcall(
            env.HOLY_FAST_LOADER_STOP
        )
    end

    if HolyPerformanceAnyUnloadEnabled() == true then

        HOLY_PERFORMANCE_STATE.Active =
            true

        HolyPerformanceConnectGardenWatcher()

        return true
    end

    HOLY_PERFORMANCE_STATE.Active =
        false

    HOLY_PERFORMANCE_STATE.Applying =
        false

    HolyPerformanceDisconnectConnections()

    HolyPerformanceSetStatus(
        "Fast loader off. Rejoin to restore suppressed visuals."
    )

    return true
end

function HolyPerformanceStartUnloadOwnGarden(reason)

    HOLY_DEV_UI_STATE.UnloadOwnGarden =
        true

    HOLY_PERFORMANCE_STATE.Active =
        true

    return HolyPerformanceStartApply(
        reason
        or "performance"
    )
end

function HolyPerformanceStopUnloadOwnGarden(reason)

    HOLY_DEV_UI_STATE.UnloadOwnGarden =
        false

    HolySaveUISettings()

    if HolyPerformanceAnyUnloadEnabled() == true then

        HOLY_PERFORMANCE_STATE.Active =
            true

        HolyPerformanceConnectGardenWatcher()

        return true
    end

    HOLY_PERFORMANCE_STATE.Active =
        false

    HOLY_PERFORMANCE_STATE.Applying =
        false

    HolyPerformanceDisconnectConnections()

    HolyPerformanceSetStatus(
        "Off."
    )

    return true
end

function HolyPerformanceStartHideMiddle(reason)

    HOLY_DEV_UI_STATE.HideMiddle =
        true

    HOLY_PERFORMANCE_STATE.Active =
        true

    return HolyPerformanceStartApply(
        reason
        or "performance"
    )
end

function HolyPerformanceStopHideMiddle(reason)

    HOLY_DEV_UI_STATE.HideMiddle =
        false

    HolySaveUISettings()

    if HolyPerformanceAnyUnloadEnabled() == true then

        HOLY_PERFORMANCE_STATE.Active =
            true

        HolyPerformanceConnectGardenWatcher()

        return true
    end

    HOLY_PERFORMANCE_STATE.Active =
        false

    HOLY_PERFORMANCE_STATE.Applying =
        false

    HolyPerformanceDisconnectConnections()

    HolyPerformanceSetStatus(
        "Off."
    )

    return true
end

--==================================================
-- ROLLBACK SYSTEM
--==================================================

function HolyRollbackResolvePacket()

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    if type(runtime.Packet) == "table"
    and type(runtime.Packet.Fire) == "function" then

        return runtime.Packet
    end

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        local networkingModule =
            sharedModules
            and sharedModules:FindFirstChild(
                "Networking"
            )

        if typeof(networkingModule) == "Instance"
        and networkingModule:IsA("ModuleScript") then

            local success,
                result =
                pcall(function()

                    return require(
                        networkingModule
                    )
                end)

            if success == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    local packet =
        type(networking) == "table"
        and type(networking.SignTool) == "table"
        and networking.SignTool.SetSignImage
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        warn(
            "[HOLY Rollback] SetSignImage packet is missing."
        )

        return nil
    end

    runtime.Packet =
        packet

    return packet
end

function HolyRollbackFire(payload)

    local packet =
        HolyRollbackResolvePacket()

    if packet == nil then
        return false
    end

    local success,
        errorMessage =
        pcall(function()

            packet:Fire(
                payload
            )
        end)

    if success ~= true then

        warn(
            "[HOLY Rollback] "
            .. tostring(errorMessage)
        )
    end

    return success == true
end

function HolyRollbackHasAnyOwner()

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    return runtime.ManualRequested == true
        or runtime.WateringRequested == true
        or runtime.PersistenceRequested == true
end

function HolyRollbackRefreshWorker()

    local state =
        HOLY_ROLLBACK_STATE

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    if HolyRollbackHasAnyOwner() ~= true then

        runtime.Running =
            false

        runtime.Generation +=
            1

        HolyRollbackFire(
            ""
        )

        return true
    end

    local packet =
        HolyRollbackResolvePacket()

    if packet == nil then

        runtime.Running =
            false

        return false
    end

    if runtime.Running == true then

        return true
    end

    runtime.Running =
        true

    runtime.Generation +=
        1

    local generation =
        runtime.Generation

    task.spawn(function()

        while runtime.Running == true
        and runtime.Generation == generation
        and HolyRollbackHasAnyOwner() == true do

            local success =
                HolyRollbackFire(
                    string.char(255)
                )

            if success ~= true then

                runtime.Running =
                    false

                runtime.Generation +=
                    1

                break
            end

            local delay =
                10

            if runtime.ManualRequested == true then

                delay =
                    math.min(
                        delay,
                        math.clamp(
                            tonumber(
                                state.FireDelay
                            )
                            or 0.1,
                            0,
                            10
                        )
                    )
            end

            if runtime.WateringRequested == true then

                delay =
                    math.min(
                        delay,
                        math.clamp(
                            tonumber(
                                runtime.WateringFireDelay
                            )
                            or 0.1,
                            0,
                            10
                        )
                    )
            end

            if runtime.PersistenceRequested == true then

                delay =
                    math.min(
                        delay,
                        0.1
                    )
            end

            task.wait(
                delay
            )
        end

        if runtime.Generation == generation then

            runtime.Running =
                false
        end
    end)

    return true
end

function HolyRollbackSetOwner(
    owner,
    value
)

    local state =
        HOLY_ROLLBACK_STATE

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    value =
        value == true

    if owner == "Manual" then

        runtime.ManualRequested =
            value

        state.Enabled =
            value

    elseif owner == "Watering" then

        runtime.WateringRequested =
            value

    elseif owner == "Persistence" then

        runtime.PersistenceRequested =
            value

    else

        return false
    end

    if HolyRollbackHasAnyOwner() == true then

        return HolyRollbackRefreshWorker()
    end

    runtime.Running =
        false

    runtime.Generation +=
        1

    HolyRollbackFire(
        ""
    )

    return true
end

function HolyRollbackStop(reason)

    return HolyRollbackSetOwner(
        "Manual",
        false
    )
end

function HolyRollbackStart(reason)

    return HolyRollbackSetOwner(
        "Manual",
        true
    )
end

function HolyRollbackSetEnabled(value)

    return HolyRollbackSetOwner(
        "Manual",
        value == true
    )
end

function HolyRollbackStopAll(reason)

    local state =
        HOLY_ROLLBACK_STATE

    local runtime =
        HOLY_ROLLBACK_RUNTIME

    state.Enabled =
        false

    runtime.ManualRequested =
        false

    runtime.WateringRequested =
        false

    runtime.PersistenceRequested =
        false

    runtime.Running =
        false

    runtime.Generation +=
        1

    HolyRollbackFire(
        ""
    )

    return true
end

function HolyRollbackSetFireDelay(value)

    HOLY_ROLLBACK_STATE.FireDelay =
        math.clamp(
            tonumber(value)
            or 0.1,
            0,
            10
        )

    return HOLY_ROLLBACK_STATE.FireDelay
end

HOLY_ROLLBACK_RUNTIME.Stop =
    HolyRollbackStopAll

--==================================================
-- WATERING REJOIN SYSTEM
--==================================================

function HolyWateringRejoinNormalizeState()

    local state =
        HOLY_WATERING_REJOIN_STATE

    state.Enabled =
        state.Enabled == true

    if state.WateringCan ~= "Common Watering Can"
    and state.WateringCan ~= "Super Watering Can" then

        state.WateringCan =
            "Super Watering Can"
    end

    if state.UseMode ~= "All Available"
    and state.UseMode ~= "Custom Amount" then

        state.UseMode =
            "All Available"
    end

    local useAmount =
        tonumber(
            state.UseAmount
        )

    if not useAmount
    or useAmount ~= useAmount
    or useAmount == math.huge
    or useAmount == -math.huge then

        useAmount =
            1
    end

    state.UseAmount =
        math.max(
            1,
            math.floor(
                useAmount
            )
        )

    if state.WateringMode ~= "Delay"
    and state.WateringMode ~= "Decay" then

        state.WateringMode =
            "Delay"
    end

    state.WateringDelay =
        math.clamp(
            tonumber(
                state.WateringDelay
            )
            or 3,
            0.1,
            10
        )

    state.RejoinDelay =
        math.clamp(
            tonumber(
                state.RejoinDelay
            )
            or 5,
            1,
            60
        )

    if state.MovementMode ~= "Walk"
    and state.MovementMode ~= "Tween" then

        state.MovementMode =
            "Tween"
    end

    state.TweenSpeed =
        math.clamp(
            tonumber(
                state.TweenSpeed
            )
            or 30,
            5,
            100
        )

    state.HidePlants =
        state.HidePlants ~= false

    if state.AvoidPlantAttacksMode ~= "Off"
    and state.AvoidPlantAttacksMode ~= "Night Only"
    and state.AvoidPlantAttacksMode ~= "Always" then

        state.AvoidPlantAttacksMode =
            "Night Only"
    end

    state.RetreatDistance =
        math.clamp(
            tonumber(
                state.RetreatDistance
            )
            or 30,
            15,
            80
        )

    state.TargetUsername =
        tostring(
            state.TargetUsername
            or ""
        )

    state.TargetOwnerUserId =
        tonumber(
            state.TargetOwnerUserId
        )

    if type(state.StandOffset) ~= "table" then

        state.StandOffset =
            nil
    end

    if type(state.AimOffset) ~= "table" then

        state.AimOffset =
            nil
    end

    return state
end

function HolyWateringRejoinHasSetup()

    local state =
        HolyWateringRejoinNormalizeState()

    return tonumber(
        state.TargetOwnerUserId
    ) ~= nil
        and type(state.StandOffset) == "table"
        and #state.StandOffset == 12
        and type(state.AimOffset) == "table"
end

function HolyWateringRejoinSaveSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local state =
        HolyWateringRejoinNormalizeState()

    local payload = {
        Version = 5,

        Enabled =
            state.Enabled == true,

        WateringCan =
            state.WateringCan,

        ToolName =
            state.WateringCan,

        UseMode =
            state.UseMode,

        UseAmount =
            state.UseAmount,

        WateringMode =
            state.WateringMode,

        WateringDelay =
            state.WateringDelay,

        RejoinDelay =
            state.RejoinDelay,

        MovementMode =
            state.MovementMode,

        TweenSpeed =
            state.TweenSpeed,

        HidePlants =
            state.HidePlants == true,

        AvoidPlantAttacksMode =
            state.AvoidPlantAttacksMode,

        RetreatDistance =
            state.RetreatDistance,

        TargetUsername =
            state.TargetUsername,

        TargetOwnerUserId =
            state.TargetOwnerUserId,

        StandOffset =
            state.StandOffset,

        AimOffset =
            state.AimOffset,
    }

    local encodeSuccess,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeSuccess ~= true
    or type(encoded) ~= "string" then

        return false
    end

    local writeSuccess =
        pcall(function()

            writefile(
                WATERING_REJOIN_SETTINGS_FILE,
                encoded
            )
        end)

    return writeSuccess == true
end

function HolyWateringRejoinLoadSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local selectedFile =
        nil

    pcall(function()

        if isfile(
            WATERING_REJOIN_SETTINGS_FILE
        ) then

            selectedFile =
                WATERING_REJOIN_SETTINGS_FILE
        elseif isfile(
            WATERING_REJOIN_LEGACY_FILE
        ) then

            selectedFile =
                WATERING_REJOIN_LEGACY_FILE
        end
    end)

    if not selectedFile then
        return false
    end

    local readSuccess,
        raw =
        pcall(function()

            return readfile(
                selectedFile
            )
        end)

    if readSuccess ~= true
    or type(raw) ~= "string" then

        return false
    end

    local decodeSuccess,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeSuccess ~= true
    or type(data) ~= "table" then

        return false
    end

    local state =
        HOLY_WATERING_REJOIN_STATE

    state.Enabled =
        data.Enabled == true

    state.WateringCan =
        tostring(
            data.WateringCan
            or data.ToolName
            or state.WateringCan
        )

    state.UseMode =
        tostring(
            data.UseMode
            or state.UseMode
            or "All Available"
        )

    state.UseAmount =
        tonumber(
            data.UseAmount
        )
        or state.UseAmount
        or 1

    state.WateringMode =
        tostring(
            data.WateringMode
            or state.WateringMode
        )

    state.WateringDelay =
        tonumber(
            data.WateringDelay
        )
        or state.WateringDelay

    state.RejoinDelay =
        tonumber(
            data.RejoinDelay
        )
        or state.RejoinDelay

    state.MovementMode =
        tostring(
            data.MovementMode
            or state.MovementMode
            or "Tween"
        )

    state.TweenSpeed =
        tonumber(
            data.TweenSpeed
        )
        or state.TweenSpeed
        or 30

    if data.HidePlants ~= nil then

        state.HidePlants =
            data.HidePlants == true
    end

    if data.AvoidPlantAttacksMode ~= nil then

        state.AvoidPlantAttacksMode =
            tostring(
                data.AvoidPlantAttacksMode
            )

    elseif data.AvoidPlantAttacks ~= nil then

        state.AvoidPlantAttacksMode =
            data.AvoidPlantAttacks == true
            and "Night Only"
            or "Off"
    end

    state.RetreatDistance =
        tonumber(
            data.RetreatDistance
        )
        or state.RetreatDistance
        or 30

    state.TargetUsername =
        tostring(
            data.TargetUsername
            or state.TargetUsername
            or ""
        )

    state.TargetOwnerUserId =
        tonumber(
            data.TargetOwnerUserId
        )

    state.StandOffset =
        type(data.StandOffset) == "table"
        and data.StandOffset
        or nil

    state.AimOffset =
        type(data.AimOffset) == "table"
        and data.AimOffset
        or nil

    HolyWateringRejoinNormalizeState()

    if HolyWateringRejoinHasSetup() ~= true then

        state.Enabled =
            false
    end

    if selectedFile == WATERING_REJOIN_LEGACY_FILE then

        HolyWateringRejoinSaveSettings()
    end

    return true
end

function HolyWateringRejoinCFrameToData(value)

    if typeof(value) ~= "CFrame" then
        return nil
    end

    return {
        value:GetComponents()
    }
end

function HolyWateringRejoinDataToCFrame(value)

    if type(value) ~= "table"
    or #value ~= 12 then

        return nil
    end

    return CFrame.new(
        table.unpack(
            value
        )
    )
end

function HolyWateringRejoinVectorToData(value)

    if typeof(value) ~= "Vector3" then
        return nil
    end

    return {
        X = value.X,
        Y = value.Y,
        Z = value.Z,
    }
end

function HolyWateringRejoinDataToVector(value)

    if type(value) ~= "table" then
        return nil
    end

    local x =
        tonumber(value.X)

    local y =
        tonumber(value.Y)

    local z =
        tonumber(value.Z)

    if not x
    or not y
    or not z then

        return nil
    end

    return Vector3.new(
        x,
        y,
        z
    )
end

function HolyWateringRejoinGetCharacter()

    local character =
        LocalPlayer.Character

    if typeof(character) ~= "Instance" then
        return nil
    end

    local humanoid =
        character:FindFirstChildOfClass(
            "Humanoid"
        )

    local root =
        character:FindFirstChild(
            "HumanoidRootPart"
        )

    return character,
        humanoid,
        root
end

function HolyWateringRejoinFindTool(toolName)

    toolName =
        tostring(
            toolName
            or HOLY_WATERING_REJOIN_STATE.WateringCan
        )

    local character =
        LocalPlayer.Character

    local backpack =
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )

    return (
        character
        and character:FindFirstChild(
            toolName
        )
    )
        or (
            backpack
            and backpack:FindFirstChild(
                toolName
            )
        )
end

function HolyWateringRejoinFindUsableTool(toolName)

    toolName =
        tostring(
            toolName
            or HOLY_WATERING_REJOIN_STATE.WateringCan
        )

    local function scanContainer(container)

        if typeof(container) ~= "Instance" then

            return nil,
                0
        end

        for _, object in ipairs(
            container:GetChildren()
        ) do

            if object.Name == toolName
            and object:IsA("Tool") then

                local count =
                    tonumber(
                        object:GetAttribute(
                            "Count"
                        )
                    )
                    or 0

                if count > 0 then

                    return object,
                        count
                end
            end
        end

        return nil,
            0
    end

    local characterTool,
        characterCount =
        scanContainer(
            LocalPlayer.Character
        )

    if characterTool then

        return characterTool,
            characterCount
    end

    local backpack =
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        )

    return scanContainer(
        backpack
    )
end

function HolyWateringRejoinEquipTool(tool)

    local character,
        humanoid =
        HolyWateringRejoinGetCharacter()

    if typeof(character) ~= "Instance"
    or typeof(humanoid) ~= "Instance"
    or typeof(tool) ~= "Instance"
    or tool:IsA("Tool") ~= true then

        return false
    end

    if tool.Parent ~= character then

        humanoid:EquipTool(
            tool
        )

        task.wait(
            0.25
        )
    end

    return tool.Parent == character
end

function HolyWateringRejoinResolvePacket()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if type(runtime.Packet) == "table"
    and type(runtime.Packet.Fire) == "function" then

        return runtime.Packet
    end

    local networking =
        nil

    if type(HolyShopRequireModule) == "function" then

        networking =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )
    end

    if type(networking) ~= "table" then

        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        local networkingModule =
            sharedModules
            and sharedModules:FindFirstChild(
                "Networking"
            )

        if typeof(networkingModule) == "Instance"
        and networkingModule:IsA("ModuleScript") then

            local success,
                result =
                pcall(function()

                    return require(
                        networkingModule
                    )
                end)

            if success == true
            and type(result) == "table" then

                networking =
                    result
            end
        end
    end

    local packet =
        type(networking) == "table"
        and type(networking.WateringCan) == "table"
        and networking.WateringCan.UseWateringCan
        or nil

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        warn(
            "[HOLY Watering Rejoin] UseWateringCan packet is missing."
        )

        return nil
    end

    runtime.Packet =
        packet

    return packet
end

function HolyWateringRejoinGetGardenAnchor(garden)

    if typeof(garden) ~= "Instance" then
        return nil
    end

    local visual =
        garden:FindFirstChild(
            "Visual"
        )

    local anchor =
        visual
        and visual:FindFirstChild(
            "GardenZonePart"
        )

    if not anchor then

        anchor =
            garden:FindFirstChild(
                "GardenZonePart",
                true
            )
    end

    if typeof(anchor) == "Instance"
    and anchor:IsA("BasePart") then

        return anchor.CFrame,
            anchor
    end

    return nil
end

function HolyWateringRejoinGetGardenOwner(garden)

    if typeof(garden) ~= "Instance" then
        return nil
    end

    local ownerUserId =
        tonumber(
            garden:GetAttribute(
                "OwnerUserId"
            )
        )

    local ownerName =
        tostring(
            garden:GetAttribute(
                "Owner"
            )
            or ""
        )

    if not ownerUserId
    and ownerName ~= "" then

        local ownerPlayer =
            Players:FindFirstChild(
                ownerName
            )

        if ownerPlayer then

            ownerUserId =
                ownerPlayer.UserId
        else

            pcall(function()

                ownerUserId =
                    Players:GetUserIdFromNameAsync(
                        ownerName
                    )
            end)
        end
    end

    if ownerUserId
    and ownerName == "" then

        local ownerPlayer =
            Players:GetPlayerByUserId(
                ownerUserId
            )

        if ownerPlayer then

            ownerName =
                ownerPlayer.Name
        end
    end

    return ownerUserId,
        ownerName
end

function HolyWateringRejoinFindGardenByOwner(
    ownerUserId,
    ownerName
)

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if not gardens then
        return nil
    end

    for _, garden in ipairs(
        gardens:GetChildren()
    ) do

        local gardenOwnerUserId =
            tonumber(
                garden:GetAttribute(
                    "OwnerUserId"
                )
            )

        local gardenOwnerName =
            tostring(
                garden:GetAttribute(
                    "Owner"
                )
                or ""
            )

        if ownerUserId
        and gardenOwnerUserId == tonumber(ownerUserId) then

            return garden
        end

        if tostring(ownerName or "") ~= ""
        and gardenOwnerName == tostring(ownerName) then

            return garden
        end
    end

    return nil
end

function HolyWateringRejoinFindGardenAtPosition(position)

    if typeof(position) ~= "Vector3" then
        return nil
    end

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if not gardens then
        return nil
    end

    local bestGarden =
        nil

    local bestScore =
        math.huge

    for _, garden in ipairs(
        gardens:GetChildren()
    ) do

        local anchorCFrame,
            anchor =
            HolyWateringRejoinGetGardenAnchor(
                garden
            )

        if anchorCFrame
        and anchor then

            local localPosition =
                anchorCFrame:PointToObjectSpace(
                    position
                )

            local overflowX =
                math.max(
                    0,
                    math.abs(localPosition.X)
                    - (
                        anchor.Size.X / 2
                    )
                )

            local overflowZ =
                math.max(
                    0,
                    math.abs(localPosition.Z)
                    - (
                        anchor.Size.Z / 2
                    )
                )

            local score =
                overflowX
                + overflowZ

            if score < bestScore then

                bestScore =
                    score

                bestGarden =
                    garden
            end
        end
    end

    if bestScore <= 12 then

        return bestGarden
    end

    return nil
end

function HolyWateringRejoinResolveSavedPositions()

    local state =
        HOLY_WATERING_REJOIN_STATE

    local garden =
        HolyWateringRejoinFindGardenByOwner(
            state.TargetOwnerUserId,
            state.TargetUsername
        )

    local anchorCFrame,
        anchor =
        HolyWateringRejoinGetGardenAnchor(
            garden
        )

    local standOffset =
        HolyWateringRejoinDataToCFrame(
            state.StandOffset
        )

    local aimOffset =
        HolyWateringRejoinDataToVector(
            state.AimOffset
        )

    if not garden
    or not anchorCFrame
    or not standOffset
    or not aimOffset then

        return nil
    end

    return garden,
        anchor,
        anchorCFrame * standOffset,
        anchorCFrame:PointToWorldSpace(
            aimOffset
        )
end

function HolyWateringRejoinSyncToggle(value)

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.ToggleSyncing == true then
        return false
    end

    local toggle =
        HOLY_WATERING_REJOIN_UI
        and HOLY_WATERING_REJOIN_UI.Toggle
        or nil

    if type(toggle) ~= "table"
    or type(toggle.SetValue) ~= "function" then

        return false
    end

    runtime.ToggleSyncing =
        true

    task.defer(function()

        pcall(function()

            toggle:SetValue(
                value == true
            )
        end)

        runtime.ToggleSyncing =
            false
    end)

    return true
end

function HolyWateringRejoinSyncRollbackToggle()

    local library =
        HOLY_DEV_LIBRARY

    local toggles =
        type(library) == "table"
        and library.Toggles
        or nil

    local toggle =
        type(toggles) == "table"
        and toggles.HolyRollbackEnabled
        or nil

    if type(toggle) == "table"
    and type(toggle.SetValue) == "function" then

        task.defer(function()

            pcall(function()

                toggle:SetValue(
                    true
                )
            end)
        end)
    end
end

function HolyWateringRejoinEnsureRollback()

    if HOLY_WATERING_REJOIN_STATE.Enabled ~= true then

        return false
    end

    HOLY_ROLLBACK_RUNTIME.WateringFireDelay =
        0.1

    return HolyRollbackSetOwner(
        "Watering",
        true
    )
end

function HolyWateringRejoinRestorePlantCollision()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    for _, connection in ipairs(
        runtime.PlantConnections
        or {}
    ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.PlantConnections =
        {}

    for object, original in pairs(
        runtime.PlantCollisionOriginal
        or {}
    ) do

        if typeof(object) == "Instance"
        and object:IsA("BasePart")
        and type(original) == "table" then

            pcall(function()

                object.CanCollide =
                    original.CanCollide == true

                object.LocalTransparencyModifier =
                    tonumber(
                        original.LocalTransparencyModifier
                    )
                    or 0
            end)
        end
    end

    runtime.PlantCollisionOriginal =
        {}
end

function HolyWateringRejoinApplyPlantCollision(garden)

    HolyWateringRejoinRestorePlantCollision()

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local gardensRoot =
        workspace:FindFirstChild(
            "Gardens"
        )

    local scanRoot =
        gardensRoot
        or garden

    if typeof(scanRoot) ~= "Instance" then

        return false
    end

    local function isInsidePlants(object)

        local current =
            object.Parent

        while current do

            if current.Name == "Plants" then

                return true
            end

            if current == scanRoot then
                break
            end

            current =
                current.Parent
        end

        return false
    end

    local function apply(object)

        if typeof(object) ~= "Instance"
        or object:IsA("BasePart") ~= true
        or isInsidePlants(object) ~= true then

            return
        end

        if runtime.PlantCollisionOriginal[object] == nil then

            runtime.PlantCollisionOriginal[object] = {
                CanCollide =
                    object.CanCollide == true,

                LocalTransparencyModifier =
                    object.LocalTransparencyModifier,
            }
        end

        pcall(function()

            object.CanCollide =
                false

            if state.HidePlants == true then

                object.LocalTransparencyModifier =
                    1
            end
        end)
    end

    for _, object in ipairs(
        scanRoot:GetDescendants()
    ) do

        apply(
            object
        )
    end

    table.insert(
        runtime.PlantConnections,
        scanRoot.DescendantAdded:Connect(function(object)

            task.defer(function()

                if state.Enabled == true then

                    apply(
                        object
                    )
                end
            end)
        end)
    )

    return true
end

function HolyWateringRejoinDistanceTo(
    root,
    destination
)

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or typeof(destination) ~= "Vector3" then

        return math.huge
    end

    return (
        root.Position
        - destination
    ).Magnitude
end

function HolyWateringRejoinHorizontalDistanceTo(
    root,
    destination
)

    if typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or typeof(destination) ~= "Vector3" then

        return math.huge
    end

    local difference =
        root.Position
        - destination

    return Vector3.new(
        difference.X,
        0,
        difference.Z
    ).Magnitude
end

function HolyWateringRejoinBuildRoute(
    root,
    destination
)

    local route =
        {}

    local path =
        PathfindingService:CreatePath({
            AgentRadius = 1,
            AgentHeight = 4,
            AgentCanJump = true,
            AgentCanClimb = true,
            WaypointSpacing = 6,
        })

    local success =
        pcall(function()

            path:ComputeAsync(
                root.Position,
                destination
            )
        end)

    if success == true
    and path.Status == Enum.PathStatus.Success then

        local waypoints =
            path:GetWaypoints()

        for index = 2, #waypoints do

            table.insert(
                route,
                waypoints[index]
            )
        end
    end

    if #route == 0 then

        table.insert(
            route,
            {
                Position =
                    destination,

                Action =
                    Enum.PathWaypointAction.Walk,
            }
        )
    end

    return route
end

function HolyWateringRejoinWalkTo(
    destinationCFrame,
    generation
)

    if typeof(destinationCFrame) ~= "CFrame" then

        return false,
            math.huge
    end

    local character,
        humanoid,
        root =
        HolyWateringRejoinGetCharacter()

    if typeof(character) ~= "Instance"
    or typeof(humanoid) ~= "Instance"
    or typeof(root) ~= "Instance"
    or root:IsA("BasePart") ~= true
    or humanoid.Health <= 0 then

        return false,
            math.huge
    end

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local destination =
        destinationCFrame.Position

    local arrivalDistance =
        4

    local startedAt =
        os.clock()

    local maximumDuration =
        90

    local lastMoveCommandAt =
        0

    local lastProgressPosition =
        root.Position

    local lastProgressAt =
        os.clock()

    local lastJumpAt =
        0

    local function isActive()

        return HOLY_WATERING_REJOIN_STATE.Enabled == true
            and runtime.Running == true
            and runtime.Generation == generation
            and runtime.RespawnPending ~= true
            and LocalPlayer.Character == character
            and character.Parent ~= nil
            and humanoid.Parent ~= nil
            and humanoid.Health > 0
            and root.Parent ~= nil
            and os.clock() - startedAt < maximumDuration
    end

    local function faceSavedDirection()

        local lookVector =
            destinationCFrame.LookVector

        local flatLook =
            Vector3.new(
                lookVector.X,
                0,
                lookVector.Z
            )

        if flatLook.Magnitude <= 0.01 then
            return
        end

        pcall(function()

            root.CFrame =
                CFrame.lookAt(
                    root.Position,
                    root.Position
                    + flatLook.Unit
                )
        end)
    end

    local function stopAtDestination()

        pcall(function()

            humanoid:MoveTo(
                root.Position
            )

            humanoid:Move(
                Vector3.zero,
                false
            )

            humanoid.AutoRotate =
                true
        end)

        faceSavedDirection()
    end

    pcall(function()

        humanoid:UnequipTools()

        humanoid.Sit =
            false

        humanoid.PlatformStand =
            false

        humanoid.AutoRotate =
            true
    end)

    while isActive() do

        local currentDistance =
            HolyWateringRejoinHorizontalDistanceTo(
                root,
                destination
            )

        if currentDistance <= arrivalDistance then

            stopAtDestination()

            return true,
                currentDistance
        end

        local now =
            os.clock()

        local progressDelta =
            root.Position
            - lastProgressPosition

        local horizontalProgress =
            Vector3.new(
                progressDelta.X,
                0,
                progressDelta.Z
            ).Magnitude

        if horizontalProgress >= 0.35 then

            lastProgressPosition =
                root.Position

            lastProgressAt =
                now

        elseif now - lastProgressAt >= 1.25
        and now - lastJumpAt >= 1 then

            lastJumpAt =
                now

            lastProgressAt =
                now

            lastProgressPosition =
                root.Position

            pcall(function()

                humanoid.Sit =
                    false

                humanoid.PlatformStand =
                    false

                humanoid.Jump =
                    true
            end)
        end

        if now - lastMoveCommandAt >= 0.12 then

            lastMoveCommandAt =
                now

            pcall(function()

                humanoid.Sit =
                    false

                humanoid.PlatformStand =
                    false

                humanoid.AutoRotate =
                    true

                humanoid:MoveTo(
                    destination
                )
            end)
        end

        task.wait(
            0.04
        )
    end

    local finalDistance =
        HolyWateringRejoinHorizontalDistanceTo(
            root,
            destination
        )

    if finalDistance <= arrivalDistance then

        stopAtDestination()

        return true,
            finalDistance
    end

    -- Do not issue MoveTo(root.Position) here.
    -- Keeping the existing destination prevents a visible pause
    -- while recovery prepares the next movement worker.

    return false,
        finalDistance
end

function HolyWateringRejoinCancelTween()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local tween =
        runtime.ActiveTween

    runtime.ActiveTween =
        nil

    if tween then

        pcall(function()

            tween:Cancel()
        end)
    end
end

function HolyWateringRejoinTweenTo(
    destinationCFrame,
    generation
)

    if typeof(destinationCFrame) ~= "CFrame" then

        return false,
            math.huge
    end

    local character,
        humanoid,
        root =
        HolyWateringRejoinGetCharacter()

    if not character
    or not humanoid
    or not root then

        return false,
            math.huge
    end

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local destination =
        destinationCFrame.Position

    local startingDistance =
        HolyWateringRejoinHorizontalDistanceTo(
            root,
            destination
        )

    if startingDistance <= 4 then

        pcall(function()

            root.CFrame =
                destinationCFrame
        end)

        return true,
            startingDistance
    end

    pcall(function()

        humanoid:UnequipTools()

        humanoid.Sit =
            false

        humanoid.PlatformStand =
            false

        humanoid.AutoRotate =
            false
    end)

    local speed =
        math.clamp(
            tonumber(
                state.TweenSpeed
            )
            or 30,
            5,
            100
        )

    local duration =
        math.max(
            0.1,
            (
                root.Position
                - destination
            ).Magnitude
            / speed
        )

    local TweenService =
        game:GetService(
            "TweenService"
        )

    local tween =
        TweenService:Create(
            root,
            TweenInfo.new(
                duration,
                Enum.EasingStyle.Linear,
                Enum.EasingDirection.Out
            ),
            {
                CFrame =
                    destinationCFrame,
            }
        )

    runtime.ActiveTween =
        tween

    local completed =
        false

    local completedConnection =
        tween.Completed:Connect(function()

            completed =
                true
        end)

    tween:Play()

    local deadline =
        os.clock()
        + duration
        + 3

    while state.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and runtime.RespawnPending ~= true
    and completed ~= true
    and os.clock() < deadline do

        task.wait(
            0.05
        )
    end

    pcall(function()

        completedConnection:Disconnect()
    end)

    if runtime.ActiveTween == tween then

        runtime.ActiveTween =
            nil
    end

    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation
    or runtime.RespawnPending == true then

        pcall(function()

            tween:Cancel()
        end)

        return false,
            HolyWateringRejoinHorizontalDistanceTo(
                root,
                destination
            )
    end

    pcall(function()

        humanoid.AutoRotate =
            true
    end)

    local finalDistance =
        HolyWateringRejoinHorizontalDistanceTo(
            root,
            destination
        )

    return finalDistance <= 4,
        finalDistance
end

function HolyWateringRejoinMoveTo(
    destinationCFrame,
    generation
)

    if HOLY_WATERING_REJOIN_STATE.MovementMode
        == "Tween" then

        return HolyWateringRejoinTweenTo(
            destinationCFrame,
            generation
        )
    end

    return HolyWateringRejoinWalkTo(
        destinationCFrame,
        generation
    )
end

function HolyWateringRejoinBuildSafeCFrame(
    savedStandCFrame,
    savedAimPosition
)

    if typeof(savedStandCFrame) ~= "CFrame"
    or typeof(savedAimPosition) ~= "Vector3" then

        return nil
    end

    local standPosition =
        savedStandCFrame.Position

    local awayDirection =
        Vector3.new(
            standPosition.X - savedAimPosition.X,
            0,
            standPosition.Z - savedAimPosition.Z
        )

    if awayDirection.Magnitude <= 0.01 then

        local lookVector =
            savedStandCFrame.LookVector

        awayDirection =
            Vector3.new(
                -lookVector.X,
                0,
                -lookVector.Z
            )
    end

    if awayDirection.Magnitude <= 0.01 then

        return nil
    end

    local retreatDistance =
        math.clamp(
            tonumber(
                HOLY_WATERING_REJOIN_STATE.RetreatDistance
            )
            or 30,
            15,
            80
        )

    local safePosition =
        standPosition
        + awayDirection.Unit
        * retreatDistance

    local flatAim =
        Vector3.new(
            savedAimPosition.X,
            safePosition.Y,
            savedAimPosition.Z
        )

    if (
        flatAim
        - safePosition
    ).Magnitude <= 0.01 then

        return CFrame.new(
            safePosition
        )
    end

    return CFrame.lookAt(
        safePosition,
        flatAim
    )
end

function HolyWateringRejoinIsNight()

    return workspace:GetAttribute(
        "ActivePhase"
    ) == "Night"
end

function HolyWateringRejoinShouldAvoidPlantAttacks()

    local mode =
        tostring(
            HOLY_WATERING_REJOIN_STATE.AvoidPlantAttacksMode
            or "Night Only"
        )

    if mode == "Always" then

        return true
    end

    if mode == "Night Only" then

        return HolyWateringRejoinIsNight()
    end

    return false
end

function HolyWateringRejoinRetreatToSafety(
    savedStandCFrame,
    savedAimPosition,
    generation
)

    local safeCFrame =
        HolyWateringRejoinBuildSafeCFrame(
            savedStandCFrame,
            savedAimPosition
        )

    if typeof(safeCFrame) ~= "CFrame" then

        return false
    end

    local arrived =
        HolyWateringRejoinMoveTo(
            safeCFrame,
            generation
        )

    return arrived == true
end

function HolyWateringRejoinRestoreSetupHook()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if type(runtime.SetupHookRestore) == "function" then

        pcall(
            runtime.SetupHookRestore
        )
    end

    runtime.SetupHookRestore =
        nil

    runtime.SetupArmed =
        false
end

function HolyWateringRejoinFinishSetupCapture(
    aimPosition,
    canName,
    tool,
    standCFrame,
    startingCount,
    setupGeneration
)

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local deadline =
        os.clock()
        + 5

    local finalCount =
        startingCount

    while runtime.SetupGeneration == setupGeneration
    and os.clock() < deadline do

        finalCount =
            tonumber(
                tool:GetAttribute(
                    "Count"
                )
            )
            or startingCount

        if finalCount < startingCount then
            break
        end

        task.wait(
            0.02
        )
    end

    HolyWateringRejoinRestoreSetupHook()

    pcall(function()

        tool:Deactivate()
    end)

    if finalCount >= startingCount then

        HolyNotify(
            "Watering Rejoin",
            "Position was not saved because watering was not confirmed.",
            5
        )

        return false
    end

    local garden =
        HolyWateringRejoinFindGardenAtPosition(
            aimPosition
        )

    local anchorCFrame =
        HolyWateringRejoinGetGardenAnchor(
            garden
        )

    local ownerUserId,
        ownerName =
        HolyWateringRejoinGetGardenOwner(
            garden
        )

    if not garden
    or not anchorCFrame
    or not ownerUserId then

        HolyNotify(
            "Watering Rejoin",
            "Could not detect the target garden owner.",
            5
        )

        return false
    end

    local state =
        HOLY_WATERING_REJOIN_STATE

    state.TargetOwnerUserId =
        ownerUserId

    state.TargetUsername =
        ownerName

    state.WateringCan =
        canName

    state.StandOffset =
        HolyWateringRejoinCFrameToData(
            anchorCFrame:ToObjectSpace(
                standCFrame
            )
        )

    state.AimOffset =
        HolyWateringRejoinVectorToData(
            anchorCFrame:PointToObjectSpace(
                aimPosition
            )
        )

    HolyWateringRejoinSaveSettings()

    HolyNotify(
        "Watering Rejoin",
        "Target position saved for "
        .. tostring(
            ownerName ~= ""
            and ownerName
            or ownerUserId
        )
        .. ".",
        5
    )

    return true
end

function HolyWateringRejoinInstallSetupHook()

    if type(hookfunction) ~= "function" then

        HolyNotify(
            "Watering Rejoin",
            "Position capture is unavailable.",
            5
        )

        return false
    end

    HolyWateringRejoinRestoreSetupHook()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local packet =
        HolyWateringRejoinResolvePacket()

    if not packet then
        return false
    end

    local hookTarget =
        packet.Fire

    local originalFunction =
        nil

    local wrapper =
        function(self, ...)

            local arguments =
                table.pack(...)

            local shouldCapture =
                runtime.SetupArmed == true
                and self == packet
                and typeof(arguments[1]) == "Vector3"
                and type(arguments[2]) == "string"
                and typeof(arguments[3]) == "Instance"
                and arguments[2] == HOLY_WATERING_REJOIN_STATE.WateringCan

            local aimPosition =
                nil

            local canName =
                nil

            local tool =
                nil

            local standCFrame =
                nil

            local startingCount =
                nil

            local setupGeneration =
                nil

            if shouldCapture then

                local _,
                    _,
                    root =
                    HolyWateringRejoinGetCharacter()

                if root then

                    aimPosition =
                        arguments[1]

                    canName =
                        arguments[2]

                    tool =
                        arguments[3]

                    standCFrame =
                        root.CFrame

                    startingCount =
                        tonumber(
                            tool:GetAttribute(
                                "Count"
                            )
                        )

                    if startingCount then

                        runtime.SetupArmed =
                            false

                        runtime.SetupGeneration +=
                            1

                        setupGeneration =
                            runtime.SetupGeneration
                    else

                        shouldCapture =
                            false
                    end
                else

                    shouldCapture =
                        false
                end
            end

            local returnValues =
                table.pack(
                    originalFunction(
                        self,
                        table.unpack(
                            arguments,
                            1,
                            arguments.n
                        )
                    )
                )

            if shouldCapture then

                task.defer(function()

                    pcall(function()

                        tool:Deactivate()
                    end)
                end)

                task.spawn(
                    HolyWateringRejoinFinishSetupCapture,
                    aimPosition,
                    canName,
                    tool,
                    standCFrame,
                    startingCount,
                    setupGeneration
                )
            end

            return table.unpack(
                returnValues,
                1,
                returnValues.n
            )
        end

    if type(newcclosure) == "function" then

        wrapper =
            newcclosure(
                wrapper
            )
    end

    local success,
        result =
        pcall(
            hookfunction,
            hookTarget,
            wrapper
        )

    if success ~= true
    or type(result) ~= "function" then

        HolyNotify(
            "Watering Rejoin",
            "Could not install position capture.",
            5
        )

        return false
    end

    originalFunction =
        result

    runtime.SetupHookRestore =
        function()

            hookfunction(
                hookTarget,
                originalFunction
            )
        end

    return true
end

function HolyWateringRejoinArmSetup()

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if state.Enabled == true
    or runtime.Running == true then

        HolyNotify(
            "Watering Rejoin",
            "Disable Auto Watering Rejoin before setting a position.",
            5
        )

        return false
    end

    local tool =
        HolyWateringRejoinFindTool(
            state.WateringCan
        )

    if not tool then

        HolyNotify(
            "Watering Rejoin",
            state.WateringCan
            .. " was not found.",
            5
        )

        return false
    end

    if HolyWateringRejoinEquipTool(
        tool
    ) ~= true then

        HolyNotify(
            "Watering Rejoin",
            "Could not equip "
            .. state.WateringCan
            .. ".",
            5
        )

        return false
    end

    pcall(function()

        tool:Deactivate()
    end)

    if HolyWateringRejoinInstallSetupHook() ~= true then
        return false
    end

    runtime.SetupArmed =
        true

    runtime.SetupGeneration +=
        1

    local generation =
        runtime.SetupGeneration

    HolyNotify(
        "Watering Rejoin",
        "Manually water the target spot once to save it.",
        6
    )

    task.delay(
        15,
        function()

            if runtime.SetupArmed == true
            and runtime.SetupGeneration == generation then

                HolyWateringRejoinRestoreSetupHook()

                HolyNotify(
                    "Watering Rejoin",
                    "Position capture timed out.",
                    4
                )
            end
        end
    )

    return true
end

function HolyWateringRejoinConfirmUse(
    packet,
    aimPosition,
    toolName,
    tool,
    generation
)

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local startingCount =
        tonumber(
            tool:GetAttribute(
                "Count"
            )
        )

    if not startingCount
    or startingCount <= 0 then

        return false,
            startingCount or 0,
            false
    end

    local fireSuccess,
        fireError =
        pcall(function()

            packet:Fire(
                aimPosition,
                toolName,
                tool
            )
        end)

    if fireSuccess ~= true then

        warn(
            "[HOLY Watering Rejoin] "
            .. tostring(fireError)
        )

        return false,
            startingCount,
            false
    end

    local deadline =
        os.clock()
        + 5

    local finalCount =
        startingCount

    local missingSince =
        nil

    while HOLY_WATERING_REJOIN_STATE.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and os.clock() < deadline do

        local observedCount =
            tonumber(
                tool:GetAttribute(
                    "Count"
                )
            )

        if observedCount then

            finalCount =
                observedCount
        end

        if finalCount < startingCount then

            return true,
                finalCount,
                true
        end

        local usableTool =
            HolyWateringRejoinFindUsableTool(
                toolName
            )

        if not usableTool then

            missingSince =
                missingSince
                or os.clock()

            if os.clock() - missingSince >= 0.25 then

                return true,
                    0,
                    true
            end

        else

            missingSince =
                nil
        end

        task.wait(
            0.02
        )
    end

    return false,
        finalCount,
        true
end

function HolyWateringRejoinOfflineAnimationActive()

    local playerGui =
        LocalPlayer
        and LocalPlayer:FindFirstChild(
            "PlayerGui"
        )

    local offlineAnimation =
        playerGui
        and playerGui:FindFirstChild(
            "OfflineAnimation"
        )

    if typeof(offlineAnimation) ~= "Instance" then

        return false
    end

    if offlineAnimation:IsA("ScreenGui")
    and offlineAnimation.Enabled ~= true then

        return false
    end

    local holdLabel =
        offlineAnimation:FindFirstChild(
            "HTSLabel",
            true
        )

    if typeof(holdLabel) == "Instance"
    and holdLabel:IsA("GuiObject") then

        return holdLabel.Visible == true
    end

    return true
end

function HolyWateringRejoinScheduleRecovery(
    reason,
    delay
)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if state.Enabled ~= true
    or runtime.Teleporting == true then

        return false
    end

    if runtime.RecoveryScheduled == true then

        return true
    end

    runtime.RecoveryScheduled =
        true

    runtime.Running =
        false

    runtime.Busy =
        false

    runtime.Generation +=
        1

    local recoveryGeneration =
        runtime.Generation

    HolyWateringRejoinCancelTween()
    HolyWateringRejoinEnsureRollback()

    task.spawn(function()

        task.wait(
            math.clamp(
                tonumber(delay)
                or 1,
                0.25,
                10
            )
        )

        local readyDeadline =
            os.clock()
            + 30

        while state.Enabled == true
        and runtime.Teleporting ~= true
        and runtime.Generation == recoveryGeneration
        and os.clock() < readyDeadline do

            local character,
                humanoid,
                root =
                HolyWateringRejoinGetCharacter()

            if character
            and humanoid
            and root
            and humanoid.Health > 0
            and HolyWateringRejoinOfflineAnimationActive() ~= true then

                runtime.RecoveryScheduled =
                    false

                runtime.RespawnPending =
                    false

                HolyWateringRejoinStart(
                    "recovery"
                )

                return
            end

            task.wait(
                0.25
            )
        end

        if runtime.Generation == recoveryGeneration then

            runtime.RecoveryScheduled =
                false
        end
    end)

    return true
end

function HolyWateringRejoinAbort(message)

    if type(HolyNotify) == "function" then

        HolyNotify(
            "Watering Rejoin",
            tostring(message),
            5
        )
    end

    if type(HOLY_WATERING_REJOIN_RUNTIME.Stop) == "function" then

        HOLY_WATERING_REJOIN_RUNTIME.Stop(
            "abort",
            false
        )
    end

    return false
end

function HolyWateringRejoinFinishRejoin(generation)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.RejoinAt == nil then

        runtime.RejoinAt =
            os.clock()
            + math.clamp(
                tonumber(
                    state.RejoinDelay
                )
                or 5,
                1,
                60
            )
    end

    HolyWateringRejoinEnsureRollback()

    while state.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and os.clock() < runtime.RejoinAt do

        task.wait(
            0.05
        )
    end

    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation then

        return false
    end

    HolyWateringRejoinEnsureRollback()
    HolyWateringRejoinSaveSettings()

    runtime.Teleporting =
        true

    local teleportSuccess,
        teleportError =
        pcall(function()

            TeleportService:Teleport(
                game.PlaceId,
                LocalPlayer
            )
        end)

    if teleportSuccess ~= true then

        runtime.Teleporting =
            false

        warn(
            "[HOLY Watering Rejoin] Rejoin failed: "
            .. tostring(teleportError)
        )

        HolyWateringRejoinAbort(
            "Rejoin failed."
        )

        return false
    end

    return true
end

function HolyWateringRejoinRunCycle(generation)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    local packet =
        HolyWateringRejoinResolvePacket()

    if not packet then

        HolyWateringRejoinAbort(
            "Watering packet is unavailable."
        )

        return
    end

    if HolyWateringRejoinEnsureRollback() ~= true then

        HolyWateringRejoinAbort(
            "Rollback could not be started."
        )

        return
    end

    if runtime.WateringFinished == true then

        HolyWateringRejoinFinishRejoin(
            generation
        )

        return
    end

    local garden,
        anchor,
        savedStandCFrame,
        savedAimPosition =
        nil,
        nil,
        nil,
        nil

    local tool =
        nil

    local loadDeadline =
        os.clock()
        + 30

    while state.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and os.clock() < loadDeadline do

        garden,
            anchor,
            savedStandCFrame,
            savedAimPosition =
            HolyWateringRejoinResolveSavedPositions()

        tool =
            HolyWateringRejoinFindTool(
                state.WateringCan
            )

        local _,
            humanoid,
            root =
            HolyWateringRejoinGetCharacter()

        if garden
        and anchor
        and savedStandCFrame
        and savedAimPosition
        and tool
        and humanoid
        and root then

            break
        end

        task.wait(
            0.5
        )
    end

    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation then

        return
    end

    if not garden
    or not savedStandCFrame
    or not savedAimPosition then

        HolyWateringRejoinAbort(
            "The saved target garden is unavailable."
        )

        return
    end

    if not tool then

        HolyWateringRejoinScheduleRecovery(
            state.WateringCan
            .. " is not ready yet.",
            1
        )

        return
    end

    HolyWateringRejoinApplyPlantCollision(
        garden
    )

    local arrived,
        finalDistance =
        HolyWateringRejoinMoveTo(
            savedStandCFrame,
            generation
        )

    if arrived ~= true then

        if state.Enabled == true
        and (
            runtime.Generation ~= generation
            or runtime.RespawnPending == true
        ) then

            return
        end

        HolyWateringRejoinScheduleRecovery(
            "Movement to the saved position was interrupted.",
            1
        )

        return
    end

    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation then

        return
    end

    HolyWateringRejoinEnsureRollback()

    tool =
        HolyWateringRejoinFindTool(
            state.WateringCan
        )

    if not tool
    or HolyWateringRejoinEquipTool(tool) ~= true then

        HolyWateringRejoinScheduleRecovery(
            "Could not equip "
            .. state.WateringCan
            .. ".",
            1
        )

        return
    end

    local useLimit =
        math.huge

    if state.UseMode == "Custom Amount" then

        useLimit =
            math.max(
                1,
                math.floor(
                    tonumber(
                        state.UseAmount
                    )
                    or 1
                )
            )
    end

    local attemptedUses =
        math.max(
            0,
            math.floor(
                tonumber(
                    runtime.CompletedUses
                )
                or 0
            )
        )

    local confirmedUses =
        0

    local depleted =
        false

    local wateringFailure =
        nil

    while state.Enabled == true
    and runtime.Running == true
    and runtime.Generation == generation
    and attemptedUses < useLimit do

        HolyWateringRejoinEnsureRollback()

        local usableCount

        tool,
            usableCount =
            HolyWateringRejoinFindUsableTool(
                state.WateringCan
            )

        if not tool
        or usableCount <= 0 then

            depleted =
                true

            break
        end

        if HolyWateringRejoinEquipTool(tool) ~= true then

            wateringFailure =
                "Could not equip "
                .. state.WateringCan
                .. " while watering."

            break
        end

        local sentAt =
            os.clock()

        local confirmed,
            remainingCount,
            packetSent =
            HolyWateringRejoinConfirmUse(
                packet,
                savedAimPosition,
                state.WateringCan,
                tool,
                generation
            )

        if state.Enabled ~= true
        or runtime.Running ~= true
        or runtime.Generation ~= generation then

            return
        end

        if packetSent ~= true then

            wateringFailure =
                "The watering packet could not be fired."

            break
        end

        attemptedUses +=
            1

        runtime.CompletedUses =
            attemptedUses

        if confirmed == true then

            confirmedUses +=
                1
        end

        local remainingTool,
            detectedRemainingCount =
            HolyWateringRejoinFindUsableTool(
                state.WateringCan
            )

        remainingCount =
            tonumber(
                remainingCount
            )
            or detectedRemainingCount
            or 0

        if not remainingTool
        or detectedRemainingCount <= 0
        or remainingCount <= 0 then

            depleted =
                true
        end

        local shouldContinue =
            attemptedUses < useLimit
            and depleted ~= true
            and not (
                confirmed ~= true
                and state.UseMode == "All Available"
            )

        local retreatedForPlantAttacks =
            false

        local function retreatFromPlantAttacks()

            if retreatedForPlantAttacks == true then

                return true
            end

            local retreated =
                HolyWateringRejoinRetreatToSafety(
                    savedStandCFrame,
                    savedAimPosition,
                    generation
                )

            if retreated ~= true then

                if state.Enabled == true
                and runtime.Generation == generation
                and runtime.RespawnPending ~= true then

                    HolyWateringRejoinScheduleRecovery(
                        "Could not retreat from the plants.",
                        1
                    )
                end

                return false
            end

            retreatedForPlantAttacks =
                true

            return true
        end

        local function returnToWateringPosition()

            if retreatedForPlantAttacks ~= true then

                return true
            end

            local returnedToTarget =
                HolyWateringRejoinMoveTo(
                    savedStandCFrame,
                    generation
                )

            if returnedToTarget ~= true then

                if state.Enabled == true
                and runtime.Generation == generation
                and runtime.RespawnPending ~= true then

                    HolyWateringRejoinScheduleRecovery(
                        "Could not return to the watering position.",
                        1
                    )
                end

                return false
            end

            retreatedForPlantAttacks =
                false

            return true
        end

        if HolyWateringRejoinShouldAvoidPlantAttacks() == true then

            if retreatFromPlantAttacks() ~= true then

                return
            end
        end

        if shouldContinue ~= true then

            break
        end

        local interval

        if state.WateringMode == "Decay" then

            interval =
                state.WateringCan == "Super Watering Can"
                and 15
                or 10
        else

            interval =
                math.clamp(
                    tonumber(
                        state.WateringDelay
                    )
                    or 1,
                    0.1,
                    10
                )
        end

        local nextUseAt =
            sentAt
            + interval

        while state.Enabled == true
        and runtime.Running == true
        and runtime.Generation == generation
        and os.clock() < nextUseAt do

            local shouldAvoidNow =
                HolyWateringRejoinShouldAvoidPlantAttacks()

            if shouldAvoidNow == true
            and retreatedForPlantAttacks ~= true then

                if retreatFromPlantAttacks() ~= true then

                    return
                end

            elseif shouldAvoidNow ~= true
            and retreatedForPlantAttacks == true then

                if returnToWateringPosition() ~= true then

                    return
                end
            end

            task.wait(
                0.05
            )
        end

        if state.Enabled ~= true
        or runtime.Running ~= true
        or runtime.Generation ~= generation then

            return
        end

        if retreatedForPlantAttacks == true then

            if returnToWateringPosition() ~= true then

                return
            end
        end
    end

    if wateringFailure then

        HolyWateringRejoinScheduleRecovery(
            wateringFailure,
            1
        )

        return
    end

    local requestedAmountReached =
        attemptedUses >= useLimit

    local wateringCompleted =
        requestedAmountReached == true
        or depleted == true
        or attemptedUses > 0
        or confirmedUses > 0

    if wateringCompleted ~= true then

        HolyWateringRejoinAbort(
            "No watering attempt was completed. Rejoin cancelled."
        )

        return
    end
    if state.Enabled ~= true
    or runtime.Running ~= true
    or runtime.Generation ~= generation then

        return
    end

    runtime.WateringFinished =
        true

    if runtime.RejoinAt == nil then

        runtime.RejoinAt =
            os.clock()
            + math.clamp(
                tonumber(
                    state.RejoinDelay
                )
                or 5,
                1,
                60
            )
    end

    HolyWateringRejoinFinishRejoin(
        generation
    )
end

function HolyWateringRejoinDisconnectCharacterWatcher()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.CharacterConnection then

        pcall(function()

            runtime.CharacterConnection:Disconnect()
        end)

        runtime.CharacterConnection =
            nil
    end

    if runtime.DiedConnection then

        pcall(function()

            runtime.DiedConnection:Disconnect()
        end)

        runtime.DiedConnection =
            nil
    end
end

function HolyWateringRejoinHandleDeath()

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if state.Enabled ~= true
    or runtime.Teleporting == true then

        return
    end

    runtime.RespawnPending =
        true

    runtime.RecoveryScheduled =
        false

    runtime.Running =
        false

    runtime.Busy =
        false

    runtime.Generation +=
        1

    HolyWateringRejoinCancelTween()
    HolyWateringRejoinEnsureRollback()
end

function HolyWateringRejoinBindCharacter(character)

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.DiedConnection then

        pcall(function()

            runtime.DiedConnection:Disconnect()
        end)

        runtime.DiedConnection =
            nil
    end

    if typeof(character) ~= "Instance" then

        return false
    end

    local humanoid =
        character:FindFirstChildOfClass(
            "Humanoid"
        )
        or character:WaitForChild(
            "Humanoid",
            10
        )

    if typeof(humanoid) ~= "Instance" then

        return false
    end

    runtime.DiedConnection =
        humanoid.Died:Connect(function()

            HolyWateringRejoinHandleDeath()
        end)

    return true
end

function HolyWateringRejoinConnectCharacterWatcher()

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if runtime.CharacterConnection then

        return true
    end

    HolyWateringRejoinBindCharacter(
        LocalPlayer.Character
    )

    runtime.CharacterConnection =
        LocalPlayer.CharacterAdded:Connect(function(character)

            task.spawn(function()

                runtime.RespawnPending =
                    true

                runtime.RecoveryScheduled =
                    false

                runtime.Running =
                    false

                runtime.Busy =
                    false

                runtime.Generation +=
                    1

                local respawnGeneration =
                    runtime.Generation

                HolyWateringRejoinCancelTween()
                HolyWateringRejoinEnsureRollback()

                HolyWateringRejoinBindCharacter(
                    character
                )

                local humanoid =
                    character:WaitForChild(
                        "Humanoid",
                        15
                    )

                local root =
                    character:WaitForChild(
                        "HumanoidRootPart",
                        15
                    )

                if LocalPlayer.Character ~= character
                or typeof(humanoid) ~= "Instance"
                or typeof(root) ~= "Instance"
                or humanoid.Health <= 0 then

                    return
                end

                local readyDeadline =
                    os.clock()
                    + 15

                while HOLY_WATERING_REJOIN_STATE.Enabled == true
                and runtime.Teleporting ~= true
                and runtime.Generation == respawnGeneration
                and LocalPlayer.Character == character
                and humanoid.Health > 0
                and HolyWateringRejoinOfflineAnimationActive() == true
                and os.clock() < readyDeadline do

                    task.wait(
                        0.25
                    )
                end

                if HOLY_WATERING_REJOIN_STATE.Enabled == true
                and runtime.Teleporting ~= true
                and runtime.Generation == respawnGeneration
                and LocalPlayer.Character == character
                and humanoid.Health > 0 then

                    runtime.RespawnPending =
                        false

                    HolyWateringRejoinStart(
                        "respawn"
                    )
                end
            end)
        end)

    return true
end

function HolyWateringRejoinStart(reason)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    if HolyWateringRejoinHasSetup() ~= true then

        state.Enabled =
            false

        HolyWateringRejoinSaveSettings()

        HolyWateringRejoinSyncToggle(
            false
        )

        HolyNotify(
            "Watering Rejoin",
            "Set a target position before enabling.",
            5
        )

        return false
    end

    if runtime.Running == true
    and state.Enabled == true then

        HolyWateringRejoinEnsureRollback()

        return true
    end

    if tostring(reason) ~= "recovery"
    and tostring(reason) ~= "respawn"
    and type(HolyFarmMiddlePauseForWatering)
        == "function" then

        HolyFarmMiddlePauseForWatering(
            "watering rejoin started"
        )
    end

    state.Enabled =
        true

    if tostring(reason) ~= "respawn"
    and tostring(reason) ~= "recovery" then

        runtime.CompletedUses =
            0

        runtime.WateringFinished =
            false

        runtime.RejoinAt =
            nil
    end

    runtime.RespawnPending =
        false

    runtime.RecoveryScheduled =
        false

    runtime.Running =
        true

    runtime.Busy =
        true

    runtime.Teleporting =
        false

    runtime.Generation +=
        1

    local generation =
        runtime.Generation

    HolyWateringRejoinConnectCharacterWatcher()
    HolyWateringRejoinSaveSettings()

    HolyWateringRejoinSyncToggle(
        true
    )

    HolyWateringRejoinEnsureRollback()

    task.spawn(function()

        HolyWateringRejoinRunCycle(
            generation
        )

        if runtime.Generation == generation
        and runtime.Teleporting ~= true then

            runtime.Running =
                false

            runtime.Busy =
                false
        end
    end)

    return true
end

function HolyWateringRejoinStop(
    reason,
    preserveEnabled
)

    local state =
        HOLY_WATERING_REJOIN_STATE

    local runtime =
        HOLY_WATERING_REJOIN_RUNTIME

    runtime.Running =
        false

    runtime.Busy =
        false

    runtime.Teleporting =
        false

    runtime.RespawnPending =
        false

    runtime.RecoveryScheduled =
        false

    runtime.Generation +=
        1

    runtime.CompletedUses =
        0

    runtime.WateringFinished =
        false

    runtime.RejoinAt =
        nil

    HolyWateringRejoinCancelTween()
    HolyWateringRejoinDisconnectCharacterWatcher()
    HolyWateringRejoinRestoreSetupHook()
    HolyWateringRejoinRestorePlantCollision()

    if type(HolyRollbackSetOwner) == "function" then

        HolyRollbackSetOwner(
            "Watering",
            false
        )
    end

    local _,
        humanoid,
        root =
        HolyWateringRejoinGetCharacter()

    if humanoid
    and root then

        pcall(function()

            humanoid:MoveTo(
                root.Position
            )

            humanoid.AutoRotate =
                true
        end)
    end

    if preserveEnabled ~= true then

        state.Enabled =
            false

        HolyWateringRejoinSaveSettings()

        HolyWateringRejoinSyncToggle(
            false
        )

        if type(HolyFarmMiddleResumeAfterWatering)
            == "function" then

            task.defer(function()

                task.wait(
                    0.1
                )

                HolyFarmMiddleResumeAfterWatering()
            end)
        end
    end

    return true
end

function HolyWateringRejoinSetEnabled(value)

    if HOLY_WATERING_REJOIN_RUNTIME.ToggleSyncing == true then
        return false
    end

    if value == true then

        return HolyWateringRejoinStart(
            "toggle"
        )
    end

    return HolyWateringRejoinStop(
        "toggle",
        false
    )
end

