function HolyWateringRejoinSetUseAmount(value)

    local amount =
        tonumber(value)

    if not amount
    or amount ~= amount
    or amount == math.huge
    or amount == -math.huge then

        amount =
            1
    end

    amount =
        math.max(
            1,
            math.floor(
                amount
            )
        )

    HOLY_WATERING_REJOIN_STATE.UseAmount =
        amount

    HolyWateringRejoinSaveSettings()

    return amount
end

