HOLY_WATERING_REJOIN_RUNTIME.Stop =
    HolyWateringRejoinStop

function HolyMergeAutomationReadDelay(value)

    local number =
        tonumber(value)

    if number == nil
    or number ~= number
    or number == math.huge
    or number == -math.huge then

        number =
            3
    end

    return math.max(
        0,
        number
    )
end

function HolyMergeAutomationNormalizeCan(value)

    value =
        tostring(value or "")

    if value == "Common Watering Can" then
        return value
    end

    return "Super Watering Can"
end

function HolyMergeAutomationSelectionArray(value)

    local output =
        {}

    local seen =
        {}

    if type(value) ~= "table" then

        value = {
            value,
        }
    end

    for key, selected in pairs(value) do

        local item =
            nil

        if type(key) == "number" then

            item =
                selected

        elseif selected == true then

            item =
                key
        end

        item =
            HolyCleanText(
                item
            )

        if item ~= ""
        and seen[item] ~= true then

            seen[item] =
                true

            table.insert(
                output,
                item
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyMergeAutomationGetSettingsData()

    local state =
        HOLY_MERGE_AUTOMATION_STATE

    return {
        AutoMergePlants =
            state.AutoMergePlants == true,

        SelectedRecipes =
            HolyMergeAutomationSelectionArray(
                state.SelectedRecipes
            ),

        AutoWatering =
            state.AutoWatering == true,

        WateringCan =
            HolyMergeAutomationNormalizeCan(
                state.WateringCan
            ),

        WateringDelay =
            HolyMergeAutomationReadDelay(
                state.WateringDelay
            ),

        AutoPotPlants =
            state.AutoPotPlants == true,

        SelectedPotPlants =
            HolyMergeAutomationSelectionArray(
                state.SelectedPotPlants
            ),

        OnlyPotFullyGrown =
            state.OnlyPotFullyGrown ~= false,

        AutoPickupPottedPlants =
            state.AutoPickupPottedPlants == true,

        SelectedPickupPlants =
            HolyMergeAutomationSelectionArray(
                state.SelectedPickupPlants
            ),

        PottedActionDelay =
            HolyMergeAutomationReadDelay(
                state.PottedActionDelay
            ),

        AutoEclipseLoop =
            state.AutoEclipseLoop == true,

        LoopDelay =
            HolyMergeAutomationReadDelay(
                state.LoopDelay
            ),
    }
end

function HolyMergeAutomationLoadSettingsData(data)

    if type(data) ~= "table" then
        return false
    end

    local state =
        HOLY_MERGE_AUTOMATION_STATE

    state.AutoMergePlants =
        data.AutoMergePlants == true

    if type(data.SelectedRecipes) == "table" then

        state.SelectedRecipes =
            HolyMergeAutomationSelectionArray(
                data.SelectedRecipes
            )
    end

    state.AutoWatering =
        data.AutoWatering == true

    state.WateringCan =
        HolyMergeAutomationNormalizeCan(
            data.WateringCan
        )

    state.WateringDelay =
        HolyMergeAutomationReadDelay(
            data.WateringDelay
        )

    state.AutoPotPlants =
        data.AutoPotPlants == true

    state.SelectedPotPlants =
        HolyMergeAutomationSelectionArray(
            data.SelectedPotPlants
            or {}
        )

    if type(data.OnlyPotFullyGrown) == "boolean" then

        state.OnlyPotFullyGrown =
            data.OnlyPotFullyGrown
    else

        state.OnlyPotFullyGrown =
            true
    end

    state.AutoPickupPottedPlants =
        data.AutoPickupPottedPlants == true

    state.SelectedPickupPlants =
        HolyMergeAutomationSelectionArray(
            data.SelectedPickupPlants
            or {}
        )

    state.PottedActionDelay =
        HolyMergeAutomationReadDelay(
            data.PottedActionDelay
        )

    state.AutoEclipseLoop =
        data.AutoEclipseLoop == true

    state.LoopDelay =
        HolyMergeAutomationReadDelay(
            data.LoopDelay
        )

    return true
end

function HolyMergeAutomationFlagValue(value, fallback)

    if type(value) == "table"
    and value.Value ~= nil then

        value =
            value.Value
    end

    if value == nil then
        return fallback
    end

    return value
end

function HolyMergeAutomationLoadRecipes(forceRefresh)

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    if forceRefresh ~= true
    and runtime.RecipesLoaded == true
    and type(runtime.Recipes) == "table" then

        return runtime.Recipes
    end

    local flags =
        HolyShopRequireModule(
            "SharedModules.Flags.MergeFlags"
        )

    local recipes =
        type(flags) == "table"
        and HolyMergeAutomationFlagValue(
            flags.Recipes,
            {}
        )
        or {}

    runtime.Recipes =
        {}

    runtime.RecipeDisplayToKey =
        {}

    runtime.RecipeKeyToDisplay =
        {}

    runtime.RangeStuds =
        math.max(
            0,
            tonumber(
                type(flags) == "table"
                and HolyMergeAutomationFlagValue(
                    flags.RangeStuds,
                    30
                )
                or 30
            )
            or 30
        )

    for recipeKey, resultName in pairs(recipes) do

        recipeKey =
            HolyCleanText(
                recipeKey
            )

        resultName =
            HolyCleanText(
                HolyMergeAutomationFlagValue(
                    resultName,
                    ""
                )
            )

        local left,
            right =
            recipeKey:match(
                "^%s*(.-)%s*%+%s*(.-)%s*$"
            )

        left =
            HolyCleanText(
                left
            )

        right =
            HolyCleanText(
                right
            )

        if recipeKey ~= ""
        and left ~= ""
        and right ~= ""
        and resultName ~= "" then

            local display =
                left
                .. " + "
                .. right
                .. " -> "
                .. resultName

            local row = {
                Key =
                    recipeKey,

                Left =
                    left,

                Right =
                    right,

                Result =
                    resultName,

                Display =
                    display,
            }

            runtime.Recipes[recipeKey] =
                row

            runtime.RecipeDisplayToKey[display] =
                recipeKey

            runtime.RecipeKeyToDisplay[recipeKey] =
                display
        end
    end

    runtime.RecipesLoaded =
        true

    return runtime.Recipes
end

function HolyMergeAutomationGetRecipeDisplays(forceRefresh)

    HolyMergeAutomationLoadRecipes(
        forceRefresh == true
    )

    local values =
        {}

    for _, row in pairs(
        HOLY_MERGE_AUTOMATION_RUNTIME.Recipes
    ) do

        table.insert(
            values,
            row.Display
        )
    end

    table.sort(values, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return values
end

function HolyMergeAutomationGetSelectedRecipeDisplays()

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    local output =
