    for _, recipeKey in ipairs(
        HOLY_MERGE_AUTOMATION_STATE.SelectedRecipes
        or {}
    ) do

        local display =
            runtime.RecipeKeyToDisplay[recipeKey]

        if display then

            table.insert(
                output,
                display
            )
        end
    end

    return output
end

function HolyMergeAutomationGetSelectedRecipes()

    HolyMergeAutomationLoadRecipes(
        false
    )

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    local output =
        {}

    for _, recipeKey in ipairs(
        HOLY_MERGE_AUTOMATION_STATE.SelectedRecipes
        or {}
    ) do

        local row =
            runtime.Recipes[recipeKey]

        if row then

            table.insert(
                output,
                row
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(a.Display):lower()
            < tostring(b.Display):lower()
    end)

    return output
end

function HolyMergeAutomationSetSelectedRecipes(value)

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    local selected =
        {}

    for _, item in ipairs(
        HolyMergeAutomationSelectionArray(
            value
        )
    ) do

        local recipeKey =
            runtime.RecipeDisplayToKey[item]
            or (
                runtime.Recipes[item]
                and item
            )

        if recipeKey then

            table.insert(
                selected,
                recipeKey
            )
        end
    end

    HOLY_MERGE_AUTOMATION_STATE.SelectedRecipes =
        selected

    HolySaveFarmSettings()
    HolyMergeAutomationWake()

    return selected
end

function HolyMergeAutomationRefreshRecipes(notifyPlayer)

    local values =
        HolyMergeAutomationGetRecipeDisplays(
            true
        )

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    local validSelection =
        {}

    for _, recipeKey in ipairs(
        HOLY_MERGE_AUTOMATION_STATE.SelectedRecipes
        or {}
    ) do

        if runtime.Recipes[recipeKey] then

            table.insert(
                validSelection,
                recipeKey
            )
        end
    end

    HOLY_MERGE_AUTOMATION_STATE.SelectedRecipes =
        validSelection

    local dropdown =
        HOLY_MERGE_AUTOMATION_UI.RecipesDropdown

    if type(dropdown) == "table" then

        runtime.UpdatingRecipes =
            true

        pcall(function()

            if type(dropdown.SetValues) == "function" then

                dropdown:SetValues(
                    values
                )

            elseif type(dropdown.SetItems) == "function" then

                dropdown:SetItems(
                    values
                )
            end
        end)

        pcall(function()

            if type(dropdown.SetValue) == "function" then

                dropdown:SetValue(
                    HolyMergeAutomationGetSelectedRecipeDisplays()
                )
            end
        end)

        runtime.UpdatingRecipes =
            false
    end

    if notifyPlayer == true then

        HolyNotify(
            "Plant Merging",
            tostring(#values)
                .. " merge recipe(s) found. New recipes are left unselected.",
            4
        )
    end

    HolySaveFarmSettings()
    HolyMergeAutomationWake()

    return values
end

function HolyMergeAutomationEscapeRichText(value)

    return tostring(value or "")
        :gsub("&", "&amp;")
        :gsub("<", "&lt;")
        :gsub(">", "&gt;")
        :gsub('"', "&quot;")
        :gsub("'", "&apos;")
end

function HolyMergeAutomationStatusColor(status)

    local lower =
        tostring(status or "")
            :lower()

    if lower:find("disabled", 1, true) then
        return "154, 147, 168"
    end

    if lower:find("complete", 1, true)
    or lower:find("ready", 1, true)
    or lower == "plant potted"
    or lower == "potted plant picked up"
    or lower:find("growth complete", 1, true) then

        return "73, 230, 133"
    end

    if lower:find("waiting", 1, true)
    or lower:find("paused", 1, true) then

        return "255, 190, 85"
    end

    if lower:find("failed", 1, true)
    or lower:find("error", 1, true)
    or lower:find("missing", 1, true)
    or lower:find("rejected", 1, true) then

        return "255, 98, 109"
    end

    return "85, 215, 255"
end

function HolyMergeAutomationBuildStatusText()

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    local status =
        HolyMergeAutomationEscapeRichText(
            runtime.Status
            or "Disabled"
        )

    local color =
        HolyMergeAutomationStatusColor(
            runtime.Status
        )

    local text =
        'Status: <font color="rgb('
        .. color
        .. ')"><b>'
        .. status
        .. "</b></font>"

    if tostring(runtime.Detail or "") ~= "" then

        text =
            text
            .. '\n<font color="rgb(190, 185, 205)">'
            .. HolyMergeAutomationEscapeRichText(
                runtime.Detail
            )
            .. "</font>"
    end

    return text
end

function HolyMergeAutomationColoredCount(value)

    return '<font color="rgb(181, 108, 255)"><b>'
        .. tostring(
            tonumber(value)
            or 0
        )
        .. "</b></font>"
end

