function HolyMergeAutomationSetStatus(status, detail)

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    runtime.Status =
        tostring(status or "Ready")

    runtime.Detail =
        tostring(detail or "")

    HolyMergeAutomationRefreshUI()

    return true
end

function HolyMergeAutomationResolvePackets()

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    if type(runtime.Packets) == "table"
    and type(runtime.Packets.RequestMerge) == "table" then

        return runtime.Packets
    end

    local networking =
        HolyShopRequireModule(
            "SharedModules.Networking"
        )

    local garden =
        type(networking) == "table"
        and type(networking.Garden) == "table"
        and networking.Garden
        or {}

    local potPlacement =
        type(networking) == "table"
        and type(networking.PotPlacement) == "table"
        and networking.PotPlacement
        or {}

    local wateringCan =
        type(networking) == "table"
        and type(networking.WateringCan) == "table"
        and networking.WateringCan
        or {}

    runtime.Packets = {
        RequestMerge =
            garden.RequestMerge,

        PotPlant =
            garden.PotPlant,

        PickUpPottedPlant =
            potPlacement.PickUpPottedPlant,

        PlacePottedPlant =
            potPlacement.PlacePottedPlant,

        UseWateringCan =
            wateringCan.UseWateringCan,
    }

    return runtime.Packets
end

function HolyMergeAutomationGetPlantsFolder()

    local plot =
        HolyFarmResolveOwnPlot(
            false
        )

    local plantsFolder =
        plot
        and plot:FindFirstChild(
            "Plants"
        )

    if typeof(plantsFolder) == "Instance" then
        return plantsFolder
    end

    plot =
        HolyFarmResolveOwnPlot(
            true
        )

    plantsFolder =
        plot
        and plot:FindFirstChild(
            "Plants"
        )

    if typeof(plantsFolder) == "Instance" then
        return plantsFolder
    end

    return nil
end

function HolyMergeAutomationPlantName(plant)

    return HolyFarmCleanPlantName(
        HolyFarmReadPlantName(
            plant
        )
    )
end

function HolyMergeAutomationIsPotted(plant)

    if typeof(plant) ~= "Instance" then
        return false
    end

    local value =
        HolyFarmReadBooleanAttribute(
            plant,
            {
                "IsPotted",
                "Potted",
            }
        )

    if value ~= nil then
        return value == true
    end

    return plant:FindFirstChild(
        "PotVisual"
    ) ~= nil
end

function HolyMergeAutomationPlantPosition(plant)

    if typeof(plant) ~= "Instance" then
        return nil
    end

    local ok,
        pivot =
        pcall(function()

            return plant:GetPivot()
        end)

    if ok == true
    and typeof(pivot) == "CFrame" then

        return pivot.Position,
            pivot
    end

    local part =
        plant:IsA("BasePart")
        and plant
        or plant:FindFirstChildWhichIsA(
            "BasePart",
            true
        )

    if typeof(part) == "Instance" then

        return part.Position,
            part.CFrame
    end

    return nil
end

function HolyMergeAutomationFindPlantById(plantId)

    plantId =
        HolyCleanText(
            plantId
        )

    if plantId == "" then
        return nil
    end

    local plantsFolder =
        HolyMergeAutomationGetPlantsFolder()

    if typeof(plantsFolder) ~= "Instance" then
        return nil
    end

    for _, plant in ipairs(
        plantsFolder:GetChildren()
    ) do

        if HolyAutoTrowelOwnsPlant(
            plant,
            plantsFolder
        ) == true
        and HolyFarmReadPlantId(plant) == plantId then

            return plant
        end
    end

    return nil
end

function HolyMergeAutomationFindPlantsByName(plantName)

    local wanted =
        HolyFarmPlantKey(
            plantName
        )

    local plantsFolder =
        HolyMergeAutomationGetPlantsFolder()

    local output =
        {}

    if typeof(plantsFolder) ~= "Instance" then
        return output
    end

    for _, plant in ipairs(
        plantsFolder:GetChildren()
    ) do

        if HolyAutoTrowelOwnsPlant(
            plant,
            plantsFolder
        ) == true
        and HolyFarmPlantKey(
            HolyMergeAutomationPlantName(
                plant
            )
        ) == wanted then

            table.insert(
                output,
                plant
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(
            HolyFarmReadPlantId(a)
        ) < tostring(
            HolyFarmReadPlantId(b)
        )
    end)

    return output
end

function HolyMergeAutomationFindPlantByName(plantName, preferGrowing)

    local plants =
        HolyMergeAutomationFindPlantsByName(
            plantName
        )

    if preferGrowing == true then

        for _, plant in ipairs(plants) do

            if HolyFarmInstanceReady(plant) ~= true then
                return plant
            end
        end
    end

    return plants[1]
end

function HolyMergeAutomationToolPlantId(tool)

    if typeof(tool) ~= "Instance" then
        return ""
    end

    return HolyFarmReadAttribute(
        tool,
        {
            "PlantId",
            "PlantID",
            "PlantUUID",
            "UUID",
            "Id",
            "ID",
        }
    )
end

function HolyMergeAutomationFindPottedTool(plantName, plantId)

    local wantedName =
        HolyFarmPlantKey(
            plantName
        )

    plantId =
        HolyCleanText(
            plantId
        )

    for _, container in ipairs({
        LocalPlayer.Character,
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        ),
    }) do

        if typeof(container) == "Instance" then

            for _, tool in ipairs(
                container:GetChildren()
            ) do

                if tool:IsA("Tool") then

                    local toolName =
                        tostring(tool.Name or "")

                    local nameMatches =
                        wantedName ~= ""
                        and HolyFarmPlantKey(toolName):find(
                            wantedName,
                            1,
                            true
                        ) ~= nil

                    local idMatches =
                        plantId ~= ""
                        and HolyMergeAutomationToolPlantId(tool)
                            == plantId

                    local looksPotted =
                        toolName:lower():find(
                            "potted",
                            1,
                            true
                        ) ~= nil
                        or tool:GetAttribute("IsPotted") == true

                    if looksPotted == true
                    and (
                        idMatches == true
                        or nameMatches == true
                    ) then

                        return tool
                    end
                end
            end
        end
    end

    return nil
end

function HolyMergeAutomationOutputExists(plantName)

    if HolyMergeAutomationFindPlantByName(
        plantName,
        false
    ) then

        return true
    end

    return HolyMergeAutomationFindPottedTool(
        plantName
    ) ~= nil
end

function HolyMergeAutomationFindMergePair(recipe)

    local leftPlants =
        HolyMergeAutomationFindPlantsByName(
            recipe.Left
        )

    local rightPlants =
        HolyMergeAutomationFindPlantsByName(
            recipe.Right
        )

    local samePlant =
        HolyFarmPlantKey(recipe.Left)
        == HolyFarmPlantKey(recipe.Right)

    local bestLeft =
        nil

    local bestRight =
        nil

    local bestDistance =
        math.huge

    local range =
        tonumber(
            HOLY_MERGE_AUTOMATION_RUNTIME.RangeStuds
        )
        or 30

    for _, left in ipairs(leftPlants) do

        if HolyFarmInstanceReady(left) == true
        and HolyMergeAutomationIsPotted(left) ~= true then

            local leftPosition =
                HolyMergeAutomationPlantPosition(
                    left
                )

            if leftPosition then

                for _, right in ipairs(rightPlants) do

                    if right ~= left
                    and (
                        samePlant ~= true
                        or HolyFarmReadPlantId(right)
                            ~= HolyFarmReadPlantId(left)
                    )
                    and HolyFarmInstanceReady(right) == true
                    and HolyMergeAutomationIsPotted(right) ~= true then

                        local rightPosition =
                            HolyMergeAutomationPlantPosition(
                                right
                            )

                        if rightPosition then

                            local distance =
                                (
                                    leftPosition
                                    - rightPosition
                                ).Magnitude

                            if distance <= range
                            and distance < bestDistance then

                                bestLeft =
                                    left

                                bestRight =
                                    right

                                bestDistance =
                                    distance
                            end
                        end
                    end
                end
            end
        end
    end

    return bestLeft,
        bestRight,
        bestDistance
end

function HolyMergeAutomationWaitFor(callback, timeout)

    local deadline =
        os.clock()
        + math.max(
            0,
            tonumber(timeout)
            or 0
        )

    repeat

        local ok,
            result =
            pcall(
                callback
            )

        if ok == true
        and result then

            return result
        end

        task.wait(
            0.10
        )

    until os.clock() >= deadline

    return nil
end

function HolyMergeAutomationWaitDelay(token, seconds)

    seconds =
        HolyMergeAutomationReadDelay(
            seconds
        )

    if seconds <= 0 then

        task.wait()

        return HOLY_MERGE_AUTOMATION_RUNTIME.Token
            == token
    end

    local deadline =
        os.clock()
        + seconds

    while os.clock() < deadline do

        if HOLY_MERGE_AUTOMATION_RUNTIME.Token
            ~= token then

            return false
        end

        task.wait(
            math.min(
                0.10,
                math.max(
                    0,
                    deadline - os.clock()
                )
            )
        )
    end

    return HOLY_MERGE_AUTOMATION_RUNTIME.Token
        == token
end

function HolyMergeAutomationMergeRecipe(recipe)

    if HolyMergeAutomationOutputExists(
        recipe.Result
    ) == true then

        return true,
            "already exists"
    end

    local left,
        right =
        HolyMergeAutomationFindMergePair(
            recipe
        )

    if not left
    or not right then

        return false,
            "Needs fully grown "
                .. recipe.Left
                .. " and "
                .. recipe.Right
                .. " within "
                .. tostring(
                    HOLY_MERGE_AUTOMATION_RUNTIME.RangeStuds
                    or 30
                )
                .. " studs."
    end

    local packet =
        HolyMergeAutomationResolvePackets()
            .RequestMerge

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false,
            "Garden.RequestMerge is missing."
    end

    local leftId =
        HolyFarmReadPlantId(
            left
        )

    local rightId =
        HolyFarmReadPlantId(
            right
        )

    HolyMergeAutomationSetStatus(
        "Merging plants",
        recipe.Display
    )

    local callOk,
        accepted,
        message =
        pcall(function()

            return packet:Fire(
                leftId,
                rightId
            )
        end)

    if callOk ~= true then

        return false,
            tostring(accepted)
    end

    if accepted == false then

        return false,
            tostring(
                message
                or "The server rejected the merge."
            )
    end

    local result =
        HolyMergeAutomationWaitFor(function()

            return HolyMergeAutomationFindPlantByName(
                recipe.Result,
                false
            )
        end, 12)

    if not result then

        return false,
            "Merge was sent, but "
                .. recipe.Result
                .. " did not appear."
    end

    HOLY_MERGE_AUTOMATION_RUNTIME.Merges =
        (
            HOLY_MERGE_AUTOMATION_RUNTIME.Merges
            or 0
        )
        + 1

    HolyMergeAutomationSetStatus(
        "Merge complete",
        recipe.Result
            .. " is now in your garden."
    )

    return true,
        "merged"
end

function HolyMergeAutomationFindUsableWateringCan()

    local wanted =
        HolyMergeAutomationNormalizeCan(
            HOLY_MERGE_AUTOMATION_STATE.WateringCan
        )

    for _, container in ipairs({
        LocalPlayer.Character,
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        ),
    }) do

        if typeof(container) == "Instance" then

            for _, tool in ipairs(
                container:GetChildren()
            ) do

                if tool:IsA("Tool")
                and tool.Name == wanted
                and (
                    tonumber(
                        tool:GetAttribute("Count")
                    )
                    or 0
                ) > 0 then

                    return tool
                end
            end
        end
    end

    return nil
end

function HolyMergeAutomationCountWateringUses()

    local wanted =
        HolyMergeAutomationNormalizeCan(
            HOLY_MERGE_AUTOMATION_STATE.WateringCan
        )

    local total =
        0

    for _, container in ipairs({
        LocalPlayer.Character,
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        ),
    }) do

        if typeof(container) == "Instance" then

            for _, tool in ipairs(
                container:GetChildren()
            ) do

                if tool:IsA("Tool")
                and tool.Name == wanted then

                    total =
                        total
                        + math.max(
                            0,
                            tonumber(
                                tool:GetAttribute("Count")
                            )
                            or 0
                        )
                end
            end
        end
    end

    return total
end

function HolyMergeAutomationEquipTool(tool)

    local character =
        LocalPlayer.Character

    local humanoid =
        character
        and character:FindFirstChildOfClass(
            "Humanoid"
        )

    if typeof(tool) ~= "Instance"
    or typeof(character) ~= "Instance"
    or typeof(humanoid) ~= "Instance" then

        return false
    end

    if tool.Parent ~= character then

        pcall(function()

            humanoid:EquipTool(
                tool
            )
        end)

        task.wait(
            0.20
        )
    end

    return tool.Parent == character
end

function HolyMergeAutomationWaterOnce(plant)

    if typeof(plant) ~= "Instance"
    or plant.Parent == nil then

        return false,
            "The target plant disappeared."
    end

    local tool =
        HolyMergeAutomationFindUsableWateringCan()

    local canName =
        HolyMergeAutomationNormalizeCan(
            HOLY_MERGE_AUTOMATION_STATE.WateringCan
        )

    if not tool then

        return false,
            "No usable "
                .. canName
                .. " was found."
    end

    if HolyMergeAutomationEquipTool(tool) ~= true then

        return false,
            canName
                .. " could not be equipped."
    end

    local packet =
        HolyMergeAutomationResolvePackets()
            .UseWateringCan

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false,
            "WateringCan.UseWateringCan is missing."
    end

    local position =
        HolyMergeAutomationPlantPosition(
            plant
        )

    if not position then

        return false,
            "The target plant has no usable position."
    end

    local beforeCount =
        HolyMergeAutomationCountWateringUses()

    local beforeAge =
        HolyFarmReadNumberAttribute(
            plant,
            {
                "Age",
                "Growth",
                "GrowAge",
                "CurrentAge",
            }
        )

    local callOk,
        callError =
        pcall(function()

            packet:Fire(
                position,
                canName,
                tool
            )
        end)

    if callOk ~= true then

        return false,
            tostring(callError)
    end

    local confirmed =
        HolyMergeAutomationWaitFor(function()

            local afterCount =
                HolyMergeAutomationCountWateringUses()

            if afterCount < beforeCount then
                return true
            end

            if typeof(plant) == "Instance"
            and plant.Parent ~= nil
            and beforeAge ~= nil then

                local afterAge =
                    HolyFarmReadNumberAttribute(
                        plant,
                        {
                            "Age",
                            "Growth",
                            "GrowAge",
                            "CurrentAge",
                        }
                    )

                if afterAge ~= nil
                and afterAge > beforeAge then

                    return true
                end
            end

            return false
        end, 3)

    if confirmed ~= true then

        return false,
            "Watering was not confirmed; no extra use was sent."
    end

    HOLY_MERGE_AUTOMATION_RUNTIME.WaterUses =
        (
            HOLY_MERGE_AUTOMATION_RUNTIME.WaterUses
            or 0
        )
        + 1

    HolyMergeAutomationRefreshUI()

    return true
end

function HolyMergeAutomationGrowPlant(plant, token)

    local plantId =
        HolyFarmReadPlantId(
            plant
        )

    while HOLY_MERGE_AUTOMATION_RUNTIME.Token == token
    and HOLY_MERGE_AUTOMATION_STATE.AutoWatering == true do

        plant =
            HolyMergeAutomationFindPlantById(
                plantId
            )

        if not plant then

            return false,
                "The merged plant disappeared."
        end

        if HolyFarmInstanceReady(plant) == true then

            HolyMergeAutomationSetStatus(
                "Growth complete",
                HolyMergeAutomationPlantName(plant)
                    .. " reached MaxAge."
            )

            return true
        end

        local age =
            HolyFarmReadNumberAttribute(
                plant,
                {
                    "Age",
                    "Growth",
                    "CurrentAge",
                }
            )
            or 0

        local maxAge =
            HolyFarmReadNumberAttribute(
                plant,
                {
                    "MaxAge",
                    "MaxGrowth",
                    "RequiredAge",
                }
            )
            or "?"

        HolyMergeAutomationSetStatus(
            "Growing "
                .. HolyMergeAutomationPlantName(plant),
            tostring(age)
                .. " / "
                .. tostring(maxAge)
                .. " using "
                .. HolyMergeAutomationNormalizeCan(
                    HOLY_MERGE_AUTOMATION_STATE.WateringCan
                )
        )

        local watered,
            reason =
            HolyMergeAutomationWaterOnce(
                plant
            )

        if watered ~= true then

            return false,
                reason
        end

        if HolyFarmInstanceReady(plant) ~= true then

            if HolyMergeAutomationWaitDelay(
                token,
                HOLY_MERGE_AUTOMATION_STATE.WateringDelay
            ) ~= true then

                return false,
                    "Stopped."
            end
        end
    end

    return HolyFarmInstanceReady(plant) == true,
        "Auto Watering is disabled."
end

function HolyMergeAutomationPotPlant(plant)

    if HolyMergeAutomationIsPotted(plant) == true then

        return true,
            plant
    end

    local packet =
        HolyMergeAutomationResolvePackets()
            .PotPlant

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false,
            "Garden.PotPlant is missing."
    end

    local plantId =
        HolyFarmReadPlantId(
            plant
        )

    local callOk,
        callError =
        pcall(function()

            packet:Fire(
                plantId
            )
        end)

    if callOk ~= true then

        return false,
            tostring(callError)
    end

    local potted =
        HolyMergeAutomationWaitFor(function()

            local current =
                HolyMergeAutomationFindPlantById(
                    plantId
                )

            if current
            and HolyMergeAutomationIsPotted(current) == true then

                return current
            end

            return nil
        end, 6)

    if not potted then

        return false,
            "Potting was not confirmed. Make sure you own an empty pot."
    end

    return true,
        potted
end

function HolyMergeAutomationPickUpPlant(plant)

    local packet =
        HolyMergeAutomationResolvePackets()
            .PickUpPottedPlant

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false,
            "PotPlacement.PickUpPottedPlant is missing."
    end

    local plantId =
        HolyFarmReadPlantId(
            plant
        )

    local plantName =
        HolyMergeAutomationPlantName(
            plant
        )

    local callOk,
        callError =
        pcall(function()

            packet:Fire(
                plantId
            )
        end)

    if callOk ~= true then

        return false,
            tostring(callError)
    end

    local removedAt =
        nil

    local pickedUp =
        HolyMergeAutomationWaitFor(function()

            if HolyMergeAutomationFindPlantById(
                plantId
            ) == nil then

                local pottedTool =
                    HolyMergeAutomationFindPottedTool(
                        plantName,
                        plantId
                    )

                if pottedTool then
                    return pottedTool
                end

                removedAt =
                    removedAt
                    or os.clock()

                if os.clock() - removedAt >= 0.50 then
                    return true
                end

                return nil
            end

            removedAt =
                nil

            return nil
        end, 6)

    if not pickedUp then

        return false,
            "Potted plant pickup was not confirmed."
    end

    return true
end

function HolyMergeAutomationPlacePlant(
    plantId,
    position,
    rotationDegrees
)

    local packet =
        HolyMergeAutomationResolvePackets()
            .PlacePottedPlant

    if type(packet) ~= "table"
    or type(packet.Fire) ~= "function" then

        return false,
            "PotPlacement.PlacePottedPlant is missing."
    end

    local callOk,
        callError =
        pcall(function()

            packet:Fire(
                position,
                rotationDegrees,
                plantId
            )
        end)

    if callOk ~= true then

        return false,
            tostring(callError)
    end

    local placed =
        HolyMergeAutomationWaitFor(function()

            local plant =
                HolyMergeAutomationFindPlantById(
                    plantId
                )

            if plant
            and HolyMergeAutomationIsPotted(plant) == true then

                return plant
            end

            return nil
        end, 6)

    if not placed then

        return false,
            "Potted plant placement was not confirmed."
    end

    return true,
        placed
end

function HolyMergeAutomationRecoverHeldPlant()

    local recovery =
        HOLY_MERGE_AUTOMATION_RUNTIME.Recovery

    if type(recovery) ~= "table" then
        return true
    end

    if HolyMergeAutomationFindPlantById(
        recovery.PlantId
    ) then

        HOLY_MERGE_AUTOMATION_RUNTIME.Recovery =
            nil

        return true
    end

    HolyMergeAutomationSetStatus(
        "Recovering potted plant",
        "Placing it back at the saved position."
    )

    local placed,
        reason =
        HolyMergeAutomationPlacePlant(
            recovery.PlantId,
            recovery.Position,
            recovery.RotationDegrees
        )

    if placed == true then

        HOLY_MERGE_AUTOMATION_RUNTIME.Recovery =
            nil

        return true
    end

    return false,
        reason
end

function HolyMergeAutomationResolveEclipseTarget()

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    local target =
        HolyMergeAutomationFindPlantById(
            runtime.EclipseTargetId
        )

    if target
    and HolyFarmPlantKey(
        HolyMergeAutomationPlantName(target)
    ) == HolyFarmPlantKey("Eclipse Bloom") then

        return target
    end

    target =
        HolyMergeAutomationFindPlantByName(
            "Eclipse Bloom",
            true
        )
        or HolyMergeAutomationFindPlantByName(
            "Eclipse Bloom",
            false
        )

    if target then

        runtime.EclipseTargetId =
            HolyFarmReadPlantId(
                target
            )
    end

    return target
end

function HolyMergeAutomationRunEclipseCycle(token)

    local recovered,
        recoveryReason =
        HolyMergeAutomationRecoverHeldPlant()

    if recovered ~= true then

        return false,
            recoveryReason
    end

    local plant =
        HolyMergeAutomationResolveEclipseTarget()

    if not plant then

        if HolyMergeAutomationFindPottedTool(
            "Eclipse Bloom"
        ) then

            return false,
                "Place your potted Eclipse Bloom in the garden once so its position can be captured."
        end

        return false,
            "No planted Eclipse Bloom was found."
    end

    if HolyFarmInstanceReady(plant) ~= true then

        if HOLY_MERGE_AUTOMATION_STATE.AutoWatering ~= true then

            return false,
                "Enable Auto Watering to finish growing the Eclipse Bloom."
        end

        local grown,
            growReason =
            HolyMergeAutomationGrowPlant(
                plant,
                token
            )

        if grown ~= true then

            return false,
                growReason
        end

        plant =
            HolyMergeAutomationResolveEclipseTarget()

        if not plant then

            return false,
                "Eclipse Bloom disappeared after growing."
        end
    end

    if HOLY_MERGE_AUTOMATION_STATE.AutoWatering ~= true then

        return false,
            "Enable Auto Watering; every Eclipse cycle needs one watering-can use."
    end

    HolyMergeAutomationSetStatus(
        "Preparing Eclipse Bloom",
        "Potting the fully grown plant."
    )

    local potted,
        pottedPlantOrReason =
        HolyMergeAutomationPotPlant(
            plant
        )

    if potted ~= true then

        return false,
            pottedPlantOrReason
    end

    plant =
        pottedPlantOrReason

    HolyMergeAutomationSetStatus(
        "Triggering Eclipse",
        "Using one "
            .. HolyMergeAutomationNormalizeCan(
                HOLY_MERGE_AUTOMATION_STATE.WateringCan
            )
            .. "."
    )

    local watered,
        waterReason =
        HolyMergeAutomationWaterOnce(
            plant
        )

    if watered ~= true then

        return false,
            waterReason
    end

    local position,
        pivot =
        HolyMergeAutomationPlantPosition(
            plant
        )

    if not position
    or typeof(pivot) ~= "CFrame" then

        return false,
            "Could not save the Eclipse Bloom placement."
    end

    local _,
        yawRadians =
        pivot:ToOrientation()

    local plantId =
        HolyFarmReadPlantId(
            plant
        )

    HOLY_MERGE_AUTOMATION_RUNTIME.Recovery = {
        PlantId =
            plantId,

        Position =
            position,

        RotationDegrees =
            math.deg(
                yawRadians
            ),
    }

    HolyMergeAutomationSetStatus(
        "Cycling Eclipse Bloom",
        "Picking up and placing the pot back."
    )

    local pickedUp,
        pickupReason =
        HolyMergeAutomationPickUpPlant(
            plant
        )

    if pickedUp ~= true then

        HOLY_MERGE_AUTOMATION_RUNTIME.Recovery =
            nil

        return false,
            pickupReason
    end

    local placed,
        placedPlantOrReason =
        HolyMergeAutomationPlacePlant(
            plantId,
            position,
            math.deg(
                yawRadians
            )
        )

    if placed ~= true then

        return false,
            placedPlantOrReason
    end

    HOLY_MERGE_AUTOMATION_RUNTIME.Recovery =
        nil

    HOLY_MERGE_AUTOMATION_RUNTIME.EclipseTargetId =
        plantId

    HOLY_MERGE_AUTOMATION_RUNTIME.Cycles =
        (
            HOLY_MERGE_AUTOMATION_RUNTIME.Cycles
            or 0
        )
        + 1

    HolyMergeAutomationSetStatus(
        "Eclipse cycle complete",
        "Waiting "
            .. tostring(
                HolyMergeAutomationReadDelay(
                    HOLY_MERGE_AUTOMATION_STATE.LoopDelay
                )
            )
            .. " second(s)."
    )

    return true,
        placedPlantOrReason
end

function HolyMergeAutomationPlantSelectionMap(selection)

    local map =
        {}

    for _, plantName in ipairs(selection or {}) do

        plantName =
            HolyCleanText(
                plantName
            )

        if plantName ~= "" then

            map[plantName] =
                true
        end
    end

    return map
end

function HolyMergeAutomationNormalizePlantSelection(
    value,
    displayToPlant,
    allValue
)

    local output =
        {}

    local seen =
        {}

    for _, selectedValue in ipairs(
        HolyMergeAutomationSelectionArray(
            value
        )
    ) do

        local plantName =
            type(displayToPlant) == "table"
            and displayToPlant[selectedValue]
            or nil

        plantName =
            HolyCleanText(
                plantName
                or selectedValue:gsub(
                    "%s+%([^)]*%)$",
                    ""
                )
            )

        if plantName == allValue then

            return {
                allValue,
            }
        end

        if plantName ~= ""
        and seen[plantName] ~= true then

            seen[plantName] =
                true

            table.insert(
                output,
                plantName
            )
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyMergeAutomationSelectionAllows(
    selection,
    plantName,
    allValue
)

    local map =
        HolyMergeAutomationPlantSelectionMap(
            selection
        )

    if map[allValue] == true then
        return true
    end

    return map[
        HolyCleanText(
            plantName
        )
    ] == true
end

function HolyMergeAutomationGetOwnedPlantsSorted()

    local plantsFolder =
        HolyMergeAutomationGetPlantsFolder()

    local plants =
        {}

    if typeof(plantsFolder) ~= "Instance" then
        return plants
    end

    for _, plant in ipairs(
        plantsFolder:GetChildren()
    ) do

        if HolyAutoTrowelOwnsPlant(
            plant,
            plantsFolder
        ) == true then

            table.insert(
                plants,
                plant
            )
        end
    end

    table.sort(plants, function(a, b)

        local aName =
            HolyMergeAutomationPlantName(
                a
            )

        local bName =
            HolyMergeAutomationPlantName(
                b
            )

        if aName ~= bName then

            return tostring(aName):lower()
                < tostring(bName):lower()
        end

        return tostring(
            HolyFarmReadPlantId(a)
        ) < tostring(
            HolyFarmReadPlantId(b)
        )
    end)

    return plants
end

function HolyMergeAutomationBuildPlantDropdownValues()

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    local counts =
        {}

    local function ensureRow(plantName)

        plantName =
            HolyCleanText(
                plantName
            )

        if plantName == ""
        or plantName == "Unknown"
        or plantName == "All Plants"
        or plantName == "All Potted Plants" then

            return nil
        end

        counts[plantName] =
            counts[plantName]
            or {
                Ready = 0,
                Unpotted = 0,
                Potted = 0,
            }

        return counts[plantName]
    end

    for _, plant in ipairs(
        HolyMergeAutomationGetOwnedPlantsSorted()
    ) do

        local plantName =
            HolyMergeAutomationPlantName(
                plant
            )

        local row =
            ensureRow(
                plantName
            )

        if row then

            if HolyMergeAutomationIsPotted(
                plant
            ) == true then

                row.Potted =
                    row.Potted + 1
            else

                row.Unpotted =
                    row.Unpotted + 1

                if HolyFarmInstanceReady(
                    plant
                ) == true then

                    row.Ready =
                        row.Ready + 1
                end
            end
        end
    end

    for _, plantName in ipairs(
        HOLY_MERGE_AUTOMATION_STATE.SelectedPotPlants
        or {}
    ) do

        ensureRow(
            plantName
        )
    end

    for _, plantName in ipairs(
        HOLY_MERGE_AUTOMATION_STATE.SelectedPickupPlants
        or {}
    ) do

        ensureRow(
            plantName
        )
    end

    local names =
        {}

    for plantName in pairs(counts) do

        table.insert(
            names,
            plantName
        )
    end

    table.sort(names, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    runtime.PotDisplayToPlant = {
        ["All Plants"] =
            "All Plants",
    }

    runtime.PotPlantToDisplay = {
        ["All Plants"] =
            "All Plants",
    }

    runtime.PickupDisplayToPlant = {
        ["All Potted Plants"] =
            "All Potted Plants",
    }

    runtime.PickupPlantToDisplay = {
        ["All Potted Plants"] =
            "All Potted Plants",
    }

    local potValues = {
        "All Plants",
    }

    local pickupValues = {
        "All Potted Plants",
    }

    for _, plantName in ipairs(names) do

        local row =
            counts[plantName]

        local potDisplay =
            plantName
            .. " ("
            .. tostring(row.Ready)
            .. " ready / "
            .. tostring(row.Unpotted)
            .. ")"

        local pickupDisplay =
            plantName
            .. " ("
            .. tostring(row.Potted)
            .. " potted)"

        runtime.PotDisplayToPlant[potDisplay] =
            plantName

        runtime.PotPlantToDisplay[plantName] =
            potDisplay

        runtime.PickupDisplayToPlant[pickupDisplay] =
            plantName

        runtime.PickupPlantToDisplay[plantName] =
            pickupDisplay

        table.insert(
            potValues,
            potDisplay
        )

        table.insert(
            pickupValues,
            pickupDisplay
        )
    end

    return potValues,
        pickupValues
end

function HolyMergeAutomationGetSelectedPlantDisplays(
    selection,
    plantToDisplay
)

    local output =
        {}

    for _, plantName in ipairs(selection or {}) do

        local display =
            type(plantToDisplay) == "table"
            and plantToDisplay[plantName]
            or nil

        if display then

            table.insert(
                output,
                display
            )
        end
    end

    return output
end

function HolyMergeAutomationRefreshPlantDropdowns(forceRefresh)

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    local ui =
        HOLY_MERGE_AUTOMATION_UI

    local potValues,
        pickupValues =
        HolyMergeAutomationBuildPlantDropdownValues()

    local potSelected =
        HolyMergeAutomationGetSelectedPlantDisplays(
            HOLY_MERGE_AUTOMATION_STATE.SelectedPotPlants,
            runtime.PotPlantToDisplay
        )

    local pickupSelected =
        HolyMergeAutomationGetSelectedPlantDisplays(
            HOLY_MERGE_AUTOMATION_STATE.SelectedPickupPlants,
            runtime.PickupPlantToDisplay
        )

    local signature =
        table.concat(
            potValues,
            "\31"
        )
        .. "\30"
        .. table.concat(
            pickupValues,
            "\31"
        )
        .. "\30"
        .. table.concat(
            potSelected,
            "\31"
        )
        .. "\30"
        .. table.concat(
            pickupSelected,
            "\31"
        )

    if forceRefresh ~= true
    and signature == runtime.PlantListSignature then

        return false
    end

    runtime.PlantListSignature =
        signature

    runtime.UpdatingPlantLists =
        true

    local function refreshDropdown(
        dropdown,
        values,
        selected
    )

        if type(dropdown) ~= "table" then
            return
        end

        pcall(function()

            if type(dropdown.SetValues) == "function" then

                dropdown:SetValues(
                    values
                )

            elseif type(dropdown.SetItems) == "function" then

                dropdown:SetItems(
                    values
                )
            end
        end)

        pcall(function()

            if type(dropdown.SetValue) == "function" then

                dropdown:SetValue(
                    selected
                )
            end
        end)
    end

    refreshDropdown(
        ui.PotPlantsDropdown,
        potValues,
        potSelected
    )

    refreshDropdown(
        ui.PickupPlantsDropdown,
        pickupValues,
        pickupSelected
    )

    runtime.UpdatingPlantLists =
        false

    return true
end

function HolyMergeAutomationSetSelectedPotPlants(value)

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    HOLY_MERGE_AUTOMATION_STATE.SelectedPotPlants =
        HolyMergeAutomationNormalizePlantSelection(
            value,
            runtime.PotDisplayToPlant,
            "All Plants"
        )

    runtime.PlantListSignature =
        nil

    HolySaveFarmSettings()
    HolyMergeAutomationRefreshPlantDropdowns(true)
    HolyMergeAutomationWake()

    return HOLY_MERGE_AUTOMATION_STATE.SelectedPotPlants
end

function HolyMergeAutomationSetSelectedPickupPlants(value)

