function HolyMergeAutomationShouldRun()

    local state =
        HOLY_MERGE_AUTOMATION_STATE

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    return state.AutoMergePlants == true
        or state.AutoWatering == true
        or state.AutoPotPlants == true
        or state.AutoPickupPottedPlants == true
        or state.AutoEclipseLoop == true
        or runtime.RunOnceRequested == true
        or runtime.ManualPotRequested == true
        or runtime.ManualPickupRequested == true
end

function HolyMergeAutomationStop(status)

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    runtime.Token =
        nil

    runtime.Running =
        false

    if status then

        HolyMergeAutomationSetStatus(
            status
        )
    end

    return true
end

function HolyMergeAutomationWorker(token)

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    local startedForOneShot =
        runtime.RunOnceRequested == true
        or runtime.ManualPotRequested == true
        or runtime.ManualPickupRequested == true

    HolyMergeAutomationSetStatus(
        "Starting",
        "Checking your garden and selected automation."
    )

    while runtime.Token == token
    and HolyMergeAutomationShouldRun() == true do

        local didWork =
            false

        local eclipseNextAt =
            nil

        local selectedRecipes =
            HolyMergeAutomationGetSelectedRecipes()

        if HOLY_MERGE_AUTOMATION_STATE.AutoMergePlants == true then

            if #selectedRecipes <= 0 then

                HolyMergeAutomationSetStatus(
                    "Waiting",
                    "Select at least one merge recipe."
                )
            else

                for _, recipe in ipairs(selectedRecipes) do

                    if HolyMergeAutomationOutputExists(
                        recipe.Result
                    ) ~= true then

                        local merged,
                            mergeReason =
                            HolyMergeAutomationMergeRecipe(
                                recipe
                            )

                        didWork =
                            merged == true

                        if merged ~= true then

                            HolyMergeAutomationSetStatus(
                                "Waiting to merge",
                                mergeReason
                            )
                        end

                        break
                    end
                end
            end
        end

        if runtime.Token ~= token then
            break
        end

        if HOLY_MERGE_AUTOMATION_STATE.AutoWatering == true then

            for _, recipe in ipairs(selectedRecipes) do

                local plant =
                    HolyMergeAutomationFindPlantByName(
                        recipe.Result,
                        true
                    )

                if plant
                and HolyFarmInstanceReady(
                    plant
                ) ~= true then

                    local grown,
                        growReason =
                        HolyMergeAutomationGrowPlant(
                            plant,
                            token
                        )

                    didWork =
                        didWork
                        or grown == true

                    if grown ~= true
                    and tostring(growReason or "") ~= "Stopped." then

                        HolyMergeAutomationSetStatus(
                            "Watering paused",
                            growReason
                        )
                    end

                    break
                end
            end
        end

        if runtime.Token ~= token then
            break
        end

        local runOnce =
            runtime.RunOnceRequested == true

        if HOLY_MERGE_AUTOMATION_STATE.AutoEclipseLoop == true
        or runOnce == true then

            local completed,
                cycleReason =
                HolyMergeAutomationRunEclipseCycle(
                    token
                )

            didWork =
                didWork
                or completed == true

            if runOnce == true then

                runtime.RunOnceRequested =
                    false
            end

            if completed ~= true then

                HolyMergeAutomationSetStatus(
                    "Eclipse loop waiting",
                    cycleReason
                )
            elseif HOLY_MERGE_AUTOMATION_STATE.AutoEclipseLoop == true then

                eclipseNextAt =
                    os.clock()
                    + HolyMergeAutomationReadDelay(
                        HOLY_MERGE_AUTOMATION_STATE.LoopDelay
                    )
            end
        end

        if runtime.Token ~= token then
            break
        end

        local pottedActionAttempted =
            false

        local wantsPickup =
            HOLY_MERGE_AUTOMATION_STATE.AutoPickupPottedPlants == true
            or runtime.ManualPickupRequested == true

        if wantsPickup == true then

            local attempted,
                completed =
                HolyMergeAutomationProcessPickupAction(
                    token,
                    runtime.ManualPickupRequested == true
                )

            pottedActionAttempted =
                attempted == true

            didWork =
                didWork
                or completed == true
        end

        if runtime.Token ~= token then
            break
        end

        local wantsPot =
            HOLY_MERGE_AUTOMATION_STATE.AutoPotPlants == true
            or runtime.ManualPotRequested == true

        if pottedActionAttempted ~= true
        and wantsPot == true then

            local attempted,
                completed =
                HolyMergeAutomationProcessPotAction(
                    token,
                    runtime.ManualPotRequested == true
                )

            pottedActionAttempted =
                attempted == true

            didWork =
                didWork
                or completed == true
        end

        if runtime.Token ~= token then
            break
        end

        if eclipseNextAt ~= nil then

            local remaining =
                math.max(
                    0,
                    eclipseNextAt - os.clock()
                )

            if HolyMergeAutomationWaitDelay(
                token,
                remaining
            ) ~= true then

                break
            end
        elseif didWork ~= true
        and pottedActionAttempted ~= true then

            if HolyMergeAutomationWaitDelay(
                token,
                0.50
            ) ~= true then

                break
            end
        end
    end

    if runtime.Token == token then

        runtime.Token =
            nil

        runtime.Running =
            false

        if startedForOneShot ~= true then

            HolyMergeAutomationSetStatus(
                "Disabled"
            )
        end
    end
end

function HolyMergeAutomationWake()

    local runtime =
        HOLY_MERGE_AUTOMATION_RUNTIME

    if HolyMergeAutomationShouldRun() ~= true then

        HolyMergeAutomationStop(
            "Disabled"
        )

        return false
    end

    if runtime.Running == true
    and runtime.Token ~= nil then

        return true
    end

    runtime.Running =
        true

    runtime.Token =
        {}

    local token =
        runtime.Token

    task.spawn(function()

        HolyMergeAutomationWorker(
            token
        )
    end)

    return true
end

