function HolyNotify(title, description, duration)

    if type(HolyDevTrace) == "function" then

        pcall(
            HolyDevTrace,
            "UI & Notifications",
            "HolyNotify",
            {
                Title =
                    tostring(
                        title
                        or "HOLY"
                    ),

                Text =
                    tostring(
                        description
                        or ""
                    ),

                Duration =
                    tonumber(duration)
                    or 4,
            },
            "Info"
        )
    end

    if Library
    and type(Library.Notify) == "function" then

        Library:Notify({
            Title =
                tostring(title or "HOLY"),

            Description =
                tostring(description or ""),

            Time =
                tonumber(duration)
                or 4,
        })

        return
    end

    print(
        "[HOLY]",
        tostring(title),
        tostring(description)
    )
end

function HolyOpenDevTool(url, name)

    url =
        HolyCleanText(url)

    name =
        tostring(name or "Dev Tool")

    if url == "" then

        HolyNotify(
            "HOLY",
            "Missing URL for "
            .. name,
            4
        )

        return false
    end

    HolyNotify(
        "HOLY",
        "Loading "
        .. name
        .. "...",
        3
    )

    task.spawn(function()

        local ok,
            result =
            pcall(function()

                return HolyLoadUrl(
                    url,
                    name
                )
            end)

        if ok == true then

            HolyNotify(
                "HOLY",
                name
                .. " loaded.",
                3
            )

        else

            warn(
                "[HOLY DEV TOOL]",
                name,
                tostring(result)
            )

            HolyNotify(
                "HOLY",
                name
                .. " failed: "
                .. tostring(result),
                7
            )
        end
    end)

    return true
end

