function HolyDevSensitiveKey(key)

    local normalized =
        tostring(
            key
            or ""
        ):lower():gsub(
            "[^%w]",
            ""
        )

    for _, fragment in ipairs({
        "password",
        "secret",
        "authorization",
        "apikey",
        "webhook",
        "sessionid",
        "cookie",
        "privatekey",
        "adminkey",
        "readkey",
        "writekey",
        "accesskey",
        "token",
        "bearertoken",
        "authtoken",
    }) do

        if normalized:find(
            fragment,
            1,
            true
        ) then

            return true
        end
    end

    return false
end

function HolyDevSensitiveString(value)

    local lower =
        tostring(
            value
            or ""
        ):lower()

    return lower:find(
        "discord.com/api/webhooks/",
        1,
        true
    ) ~= nil
    or lower:find(
        "discordapp.com/api/webhooks/",
        1,
        true
    ) ~= nil
end

function HolyDevSafeValue(
    value,
    depth,
    seen,
    options,
    keyName
)

    depth =
        tonumber(depth)
        or 0

    seen =
        type(seen) == "table"
        and seen
        or {}

    options =
        type(options) == "table"
        and options
        or {}

    if keyName ~= nil
    and HolyDevSensitiveKey(
        keyName
    ) == true then

        return "<redacted>"
    end

    local valueType =
        typeof(value)

    if value == nil then

        return {
            Type = "nil",
        }
    end

    if valueType == "boolean" then
        return value
    end

    if valueType == "number" then

        if value ~= value
        or value == math.huge
        or value == -math.huge then

            return tostring(value)
        end

        return value
    end

    if valueType == "string" then

        if HolyDevSensitiveString(
            value
        ) == true then

            return "<redacted webhook URL>"
        end

        local valid,
            length =
            pcall(
                utf8.len,
                value
            )

        if valid == true
        and length ~= nil then

            local maximum =
                math.max(
                    250,
                    math.floor(
                        tonumber(
                            options.MaxStringLength
                        )
                        or 4000
                    )
                )

            if #value > maximum then

                return value:sub(
                    1,
                    maximum
                )
                    .. "...<truncated "
                    .. tostring(
                        #value - maximum
                    )
                    .. " bytes>"
            end

            return value
        end

        local bytes =
            {}

        local byteLimit =
            math.min(
                #value,
                512
            )

        for index = 1, byteLimit do

            bytes[#bytes + 1] =
                string.format(
                    "%02X",
                    string.byte(
                        value,
                        index
                    )
                )
        end

        return {
            Type = "binary-string",
            Length = #value,
            CapturedBytes = byteLimit,
            Truncated = byteLimit < #value,
            Hex = table.concat(bytes, " "),
        }
    end

    if valueType == "Instance" then

        local fullName =
            value.Name

        pcall(function()

            fullName =
                value:GetFullName()
        end)

        return {
            Type = "Instance",
            ClassName = value.ClassName,
            Name = value.Name,
            FullName = fullName,
        }
    end

    if valueType == "Vector2"
    or valueType == "Vector3" then

        local output = {
            Type = valueType,
            X = value.X,
            Y = value.Y,
        }

        if valueType == "Vector3" then

            output.Z =
                value.Z
        end

        return output
    end

    if valueType == "CFrame" then

        return {
            Type = "CFrame",
            Components = {
                value:GetComponents()
            },
        }
    end

    if valueType == "Color3" then

        return {
            Type = "Color3",
            R = value.R,
            G = value.G,
            B = value.B,
        }
    end

    if valueType == "UDim" then

        return {
            Type = "UDim",
            Scale = value.Scale,
            Offset = value.Offset,
        }
    end

    if valueType == "UDim2" then

        return {
            Type = "UDim2",

            X = {
                Scale = value.X.Scale,
                Offset = value.X.Offset,
            },

            Y = {
                Scale = value.Y.Scale,
                Offset = value.Y.Offset,
            },
        }
    end

    if valueType == "EnumItem" then
        return tostring(value)
    end

    if valueType == "function" then
        return "<function>"
    end

    if valueType == "buffer" then

        local length =
            0

        pcall(function()

            length =
                buffer.len(value)
        end)

        return {
            Type = "buffer",
            Length = length,
        }
    end

    if valueType == "table" then

        if seen[value] == true then
            return "<cycle>"
        end

        local maxDepth =
            math.max(
                2,
                math.floor(
                    tonumber(
                        options.MaxDepth
                    )
                    or 8
                )
            )

        if depth >= maxDepth then
            return "<maximum depth>"
        end

        seen[value] =
            true

        local count =
            0

        local maxIndex =
            0

        local sequential =
            true

        for key in pairs(value) do

            count +=
                1

            if type(key) ~= "number"
            or key < 1
            or key % 1 ~= 0 then

                sequential =
                    false

            else

                maxIndex =
                    math.max(
                        maxIndex,
                        key
                    )
            end
        end

        sequential =
            sequential == true
            and count > 0
            and maxIndex == count

        local output =
            {}

        if sequential == true then

            local maximum =
                math.max(
                    100,
                    math.floor(
                        tonumber(
                            options.MaxArrayEntries
                        )
                        or 10000
                    )
                )

            local captured =
                math.min(
                    count,
                    maximum
                )

            for index = 1, captured do

                output[index] =
                    HolyDevSafeValue(
                        value[index],
                        depth + 1,
                        seen,
                        options,
                        index
                    )
            end

            if captured < count then

                output[captured + 1] = {
                    __Truncated = true,
                    TotalEntries = count,
                    CapturedEntries = captured,
                }
            end

        else

            local maximum =
                math.max(
                    100,
                    math.floor(
                        tonumber(
                            options.MaxMapEntries
                        )
                        or 1000
                    )
                )

            local captured =
                0

            for key, child in pairs(value) do

                captured +=
                    1

                if captured > maximum then

                    output.__Truncated =
                        true

                    output.__TotalEntries =
                        count

                    output.__CapturedEntries =
                        maximum

                    break
                end

                local outputKey =
                    tostring(key)

                output[outputKey] =
                    HolyDevSafeValue(
                        child,
                        depth + 1,
                        seen,
                        options,
                        outputKey
                    )
            end
        end

        seen[value] =
            nil

        return output
    end

    return {
        Type = valueType,
        Text = tostring(value),
    }
end

function HolyDevEncode(value)

    local success,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                HolyDevSafeValue(value)
            )
        end)

    if success == true
    and type(encoded) == "string" then

        return encoded
    end

    return nil,
        encoded
end

function HolyDevReadJson(fileName)

    if HolyCanUseFiles() ~= true then
        return nil
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(fileName)
    end)

    if exists ~= true then
        return nil
    end

    local success,
        result =
        pcall(function()

            return HttpService:JSONDecode(
                readfile(fileName)
            )
        end)

    if success == true
    and type(result) == "table" then

        return result
    end

    return nil
end

function HolyDevWriteJson(fileName, value)

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local encoded =
        HolyDevEncode(value)

    if type(encoded) ~= "string" then
        return false
    end

    local success =
        pcall(function()

            writefile(
                fileName,
                encoded
            )
        end)

    return success == true
end

function HolyDevCopyReport(value)

    local encoded =
        type(value) == "string"
        and value
        or HolyDevEncode(value)

    if type(encoded) ~= "string" then
        return false
    end

    return HolyCopyText(encoded)
end

