function HolyDevIsUsableGear(tool)

    if typeof(tool) ~= "Instance"
    or tool:IsA("Tool") ~= true then

        return false
    end

    local category =
        tostring(
            tool:GetAttribute(
                "MainCategory"
            )
            or ""
        )

    if category == "Gear" then
        return true
    end

    if tool:GetAttribute("WateringCan") ~= nil then
        return true
    end

    return false
end

function HolyDevCollectOwnedTools()

    local byName =
        {}

    local roots = {
        LocalPlayer:FindFirstChildOfClass(
            "Backpack"
        ),

        LocalPlayer.Character,
    }

    for _, root in ipairs(roots) do

        if root then

            for _, child in ipairs(
                root:GetChildren()
            ) do

                if HolyDevIsUsableGear(child) == true then

                    local name =
                        tostring(child.Name)

                    local count =
                        tonumber(
                            child:GetAttribute(
                                "Count"
                            )
                        )

                    if count == nil then
                        count = 1
                    end

                    local current =
                        byName[name]

                    if current == nil
                    or count > current.Count then

                        byName[name] = {
                            Name = name,
                            Count = count,
                            Tool = child,

                            Location =
                                root == LocalPlayer.Character
                                and "Character"
                                or "Backpack",
                        }
                    end
                end
            end
        end
    end

    local rows =
        {}

    for _, row in pairs(byName) do

        if row.Count > 0 then

            rows[#rows + 1] =
                row
        end
    end

    table.sort(rows, function(a, b)

        return a.Name:lower()
            < b.Name:lower()
    end)

    return rows
end

function HolyDevGetToolCount(toolName)

    toolName =
        tostring(toolName or "")

    for _, row in ipairs(
        HolyDevCollectOwnedTools()
    ) do

        if row.Name == toolName then

            return row.Count,
                true
        end
    end

    return nil,
        false
end

function HolyDevRefreshToolDropdown()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local rows =
        HolyDevCollectOwnedTools()

    local values =
        {}

    local displayToName =
        {}

    local nameToDisplay =
        {}

    for _, row in ipairs(rows) do

        local display =
            row.Name
            .. " — "
            .. tostring(
                math.floor(row.Count)
            )

        values[#values + 1] =
            display

        displayToName[display] =
            row.Name

        nameToDisplay[row.Name] =
            display
    end

    if #values == 0 then

        values[1] =
            "No usable gear found"
    end

    runtime.ToolRows =
        rows

    runtime.ToolDisplayToName =
        displayToName

    runtime.ToolNameToDisplay =
        nameToDisplay

    local signature =
        table.concat(
            values,
            "\0"
        )

    local selectedName =
        tostring(
            HOLY_DEV_SUITE_STATE.PersistenceTarget
            or ""
        )

    if nameToDisplay[selectedName] == nil then

        selectedName =
            rows[1]
            and rows[1].Name
            or ""

        HOLY_DEV_SUITE_STATE.PersistenceTarget =
            selectedName
    end

    local dropdown =
        runtime.UI.PersistenceDropdown

    if type(dropdown) == "table" then

        if runtime.ToolSignature == signature then
            return true
        end

        runtime.ToolSignature =
            signature

        pcall(function()

            if type(dropdown.SetValues) == "function" then

                dropdown:SetValues(
                    values
                )

            elseif type(dropdown.SetItems) == "function" then

                dropdown:SetItems(
                    values
                )
            end
        end)

        local selectedDisplay =
            nameToDisplay[selectedName]
            or values[1]

        pcall(function()

            if type(dropdown.SetValue) == "function" then

                dropdown:SetValue(
                    selectedDisplay
                )
            end
        end)
    end

    return true
end

function HolyDevStartToolRefresh()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    runtime.RefreshGeneration +=
        1

    local generation =
        runtime.RefreshGeneration

    task.spawn(function()

        while runtime.Active == true
        and runtime.RefreshGeneration == generation do

            HolyDevRefreshToolDropdown()

            task.wait(
                2
            )
        end
    end)
end

function HolyDevSnapshotToolRows()

    local output =
        {}

    for _, row in ipairs(
        HolyDevCollectOwnedTools()
    ) do

        output[row.Name] = {
            Count = row.Count,
            Location = row.Location,

            Attributes =
                HolyDevSafeValue(
                    row.Tool:GetAttributes()
                ),
        }
    end

    return output
end

function HolyDevSnapshotAttributedRoot(root, output)

    if typeof(root) ~= "Instance" then
        return output
    end

    output =
        type(output) == "table"
        and output
        or {}

    local objects = {
        root,
    }

    for _, descendant in ipairs(
        root:GetDescendants()
    ) do

        objects[#objects + 1] =
            descendant
    end

    for _, object in ipairs(objects) do

        local attributes =
            object:GetAttributes()

        if next(attributes) ~= nil then

            output[
                HolyDevGetFullName(object)
            ] = {
                ClassName = object.ClassName,

                Attributes =
                    HolyDevSafeValue(
                        attributes
                    ),
            }
        end
    end

    return output
end

function HolyDevFindOwnPlot()

    local gardens =
        workspace:FindFirstChild(
            "Gardens"
        )

    if not gardens then
        return nil
    end

    for _, plot in ipairs(
        gardens:GetChildren()
    ) do

        if tonumber(
            plot:GetAttribute(
                "OwnerUserId"
            )
        ) == LocalPlayer.UserId then

            return plot
        end
    end

    return nil
end

function HolyDevCaptureActionScope(scope)

    scope =
        tostring(
            scope
            or HOLY_DEV_SUITE_STATE.ActionScope
            or "Player Tools"
        )

    local snapshot = {
        Scope = scope,
        Time = os.time(),
        JobId = game.JobId,
        Values = {},
    }

    if scope == "Player Tools"
    or scope == "Everything" then

        snapshot.Values.PlayerTools =
            HolyDevSnapshotToolRows()
    end

    if scope == "Own Garden"
    or scope == "Everything" then

        local plot =
            HolyDevFindOwnPlot()

        if plot then

            snapshot.Values.OwnGarden =
                HolyDevSnapshotAttributedRoot(
                    plot,
                    {}
                )
        end
    end

    if scope == "Wild Pets"
    or scope == "Everything" then

        local map =
            workspace:FindFirstChild(
                "Map"
            )

        local wildPets =
            map
            and map:FindFirstChild(
                "WildPetRef"
            )

        if wildPets then

            snapshot.Values.WildPets =
                HolyDevSnapshotAttributedRoot(
                    wildPets,
                    {}
                )
        end
    end

    return snapshot
end

function HolyDevRecorderArea(value)

    value =
        tostring(
            value
            or "Auction"
        )

    local allowed = {
        ["Auction"] = true,
        ["Player Tools"] = true,
        ["Own Garden"] = true,
        ["Wild Pets"] = true,
        ["Sniper"] = true,
        ["UI & Notifications"] = true,
        ["Everything"] = true,
    }

    return allowed[value] == true
        and value
        or "Auction"
end

function HolyDevRecorderMode(value)

    return tostring(value)
        == "Rolling 30 Seconds"
        and "Rolling 30 Seconds"
        or "Manual Test"
end

function HolyDevRecorderCount()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    return math.max(
        0,
        (
            runtime.RecorderTimelineTail
            or 0
        )
        - (
            runtime.RecorderTimelineHead
            or 1
        )
        + 1
    )
end

function HolyDevRecorderMatches(
    source,
    area,
    eventName,
    data
)

    local selected =
        HolyDevRecorderArea(
            HOLY_DEV_SUITE_STATE.RecorderArea
        )

    if selected == "Everything"
    or source == "Recorder"
    or source == "Marker"
    or source == "Error"
    or tostring(area) == "Errors" then

        return true
    end

    if selected == "UI & Notifications"
    and (
        source == "UI"
        or tostring(area)
            == "UI & Notifications"
    ) then

        return true
    end

    local extra =
        ""

    if type(data) == "table" then

        extra =
            tostring(
                data.Packet
                or data.Text
                or data.Title
                or data.Reason
                or data.Name
                or ""
            )

    else

        extra =
            tostring(
                data
                or ""
            )
    end

    local searchable =
        (
            tostring(area)
            .. " "
            .. tostring(eventName)
            .. " "
            .. extra
        ):lower()

    local keywords = {
        Auction = {
            "auction",
            "purchaselot",
            "purchaseresult",
            "stockupdate",
            "wait a moment",
            "please wait",
            "cooldown",
        },

        ["Player Tools"] = {
            "player tools",
            "tool",
            "gear",
            "watering",
            "trowel",
            "shovel",
        },

        ["Own Garden"] = {
            "own garden",
            "garden",
            "plant",
            "fruit",
            "sprinkler",
            "seed",
        },

        ["Wild Pets"] = {
            "wild pets",
            "wildpet",
            "pet",
        },

        Sniper = {
            "sniper",
            "wildpet",
            "teleport",
            "serverhop",
            "server finder",
            "purchasepet",
        },
    }

    for _, keyword in ipairs(
        keywords[selected]
        or {}
    ) do

        if searchable:find(
            keyword,
            1,
            true
        ) then

            return true
        end
    end

    return false
end

function HolyDevRecorderRefreshStatus(extra)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local now =
        os.clock()

    if tostring(
        extra
        or ""
    ) == ""
    and now - (
        runtime.RecorderStatusClock
        or 0
    ) < 0.15 then

        return
    end

    runtime.RecorderStatusClock =
        now

    local status =
        runtime.RecorderActive == true
        and "Recording"
        or "Ready"

    if runtime.RecorderActive == true then

        status =
            status
            .. " · "
            .. HolyDevRecorderArea(
                HOLY_DEV_SUITE_STATE.RecorderArea
            )
            .. " · "
            .. tostring(
                HolyDevRecorderCount()
            )
            .. " events"

        if runtime.RecorderTrigger then

            status =
                status
                .. " · issue marked"
        end
    end

    if tostring(
        extra
        or ""
    ) ~= "" then

        status =
            tostring(extra)
    end

    HolyDevSetStatus(
        "RecorderStatusLabel",
        status
    )
end

function HolyDevRecorderPush(
    source,
    area,
    eventName,
    data,
    severity
)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.RecorderActive ~= true then
        return nil
    end

    if HolyDevRecorderMatches(
        source,
        area,
        eventName,
        data
    ) ~= true then

        return nil
    end

    local now =
        os.clock()

    runtime.RecorderSequence =
        (
            runtime.RecorderSequence
            or 0
        )
        + 1

    local safeData =
        nil

    local safeOk =
        pcall(function()

            safeData =
                HolyDevPacketSafeValue(
                    data
                )
        end)

    if safeOk ~= true then

        safeData = {
            SerializationError = true,
            Text = tostring(data),
        }
    end

    local row = {
        Sequence =
            runtime.RecorderSequence,

        Elapsed =
            now
            - (
                runtime.RecorderStartedClock
                or now
            ),

        Clock =
            now,

        UnixTime =
            os.time(),

        Source =
            tostring(
                source
                or "Internal"
            ),

        Area =
            tostring(
                area
                or "Unknown"
            ),

        Event =
            tostring(
                eventName
                or "Event"
            ),

        Severity =
            tostring(
                severity
                or "Info"
            ),

        Data =
            safeData,
    }

    local tail =
        (
            runtime.RecorderTimelineTail
            or 0
        )
        + 1

    runtime.RecorderTimelineTail =
        tail

    runtime.RecorderTimeline[tail] =
        row

    local head =
        runtime.RecorderTimelineHead
        or 1

    local cutoff =
        HolyDevRecorderMode(
            HOLY_DEV_SUITE_STATE.RecorderMode
        ) == "Rolling 30 Seconds"
        and now - 30
        or -math.huge

    while head <= tail do

        local first =
            runtime.RecorderTimeline[head]

        if first
        and first.Clock >= cutoff
        and tail - head + 1 <= 5000 then

            break
        end

        runtime.RecorderTimeline[head] =
            nil

        head +=
            1

        runtime.RecorderDropped =
            (
                runtime.RecorderDropped
                or 0
            )
            + 1
    end

    runtime.RecorderTimelineHead =
        head

    HolyDevRecorderRefreshStatus()

    return row
end

function HolyDevTrace(
    area,
    eventName,
    data,
    severity
)

    local ok,
        row =
        pcall(
            HolyDevRecorderPush,
            "Internal",
            area,
            eventName,
            data,
            severity
        )

    if ok ~= true then
        return nil
    end

    if row
    and tostring(area) == "Auction"
    and tostring(eventName)
        == "PurchaseResult"
    and type(data) == "table"
    and data.Success ~= true then

        pcall(
            HolyDevRecorderAutoTrigger,
            "Auction purchase failed",
            data
        )
    end

    return row
end

function HolyDevRecorderRecordPacket(
    direction,
    entry,
    ...
)

    return HolyDevRecorderPush(
        "Packet",
        tostring(
            entry
            and entry.Path
            or "Unknown"
        ),
        tostring(direction),
        {
            Packet =
                tostring(
                    entry
                    and entry.Path
                    or "Unknown"
                ),

            PacketId =
                entry
                and entry.PacketId
                or nil,

            Arguments =
                HolyDevPacketArguments(...),
        },
        "Info"
    )
end

function HolyDevRecorderAuctionDecisionState()

    local state =
        type(HOLY_SHOP_STATE) == "table"
        and HOLY_SHOP_STATE
        or {}

    local eligible =
        {}

    for _, row in ipairs(
        type(state.AuctionLastLots) == "table"
        and state.AuctionLastLots
        or {}
    ) do

        if type(row) ~= "table" then
            continue
        end

        local entry,
            watchIndex =
            nil,
            nil

        if type(HolyAuctionGetWatchEntry)
        == "function" then

            local ok,
                foundEntry,
                foundIndex =
                pcall(
                    HolyAuctionGetWatchEntry,
                    row.Name
                )

            if ok == true then

                entry =
                    foundEntry

                watchIndex =
                    foundIndex
            end
        end

        if type(entry) == "table" then

            local stale =
                true

            local allowed =
                false

            if type(HolyAuctionRowStale)
            == "function" then

                local ok,
                    value =
                    pcall(
                        HolyAuctionRowStale,
                        row,
                        true
                    )

                if ok == true then

                    stale =
                        value == true
                end
            end

            if type(HolyAuctionPriceAllows)
            == "function" then

                local ok,
                    value =
                    pcall(
                        HolyAuctionPriceAllows,
                        row
                    )

                if ok == true then

                    allowed =
                        value == true
                end
            end

            local attempted =
                type(state.AuctionAttemptedLots)
                    == "table"
                and state.AuctionAttemptedLots[
                    tostring(row.LotId)
                ] == true

            if row.Active == true
            and stale ~= true
            and allowed == true
            and (
                state.AuctionBuyUntilSoldOut
                    == true
                or attempted ~= true
            ) then

                eligible[#eligible + 1] = {
                    LotId = row.LotId,
                    Name = row.Name,
                    Price = row.Price,
                    WatchlistIndex = watchIndex,
                }
            end
        end
    end

    return {
        EligibleCount =
            #eligible,

        EligibleItems =
            eligible,

        RoundRobinIndex =
            state.AuctionRoundRobinIndex,

        SchedulerState =
            state.AuctionSchedulerState,

        CooldownRemaining =
            math.max(
                0,
                (
                    tonumber(
                        state.AuctionNextBuyAt
                    )
                    or 0
                ) - os.clock()
            ),

        CooldownSynchronized =
            state.AuctionCooldownSynchronized
            == true,

        CooldownSource =
            state.AuctionCooldownAnchorReason,

        UnknownOutcome =
            state.AuctionUnknownOutcome
            == true,
    }
end

function HolyDevRecorderAuctionSnapshot()

    if type(HolyAuctionEnsureState)
    == "function" then

        pcall(
            HolyAuctionEnsureState
        )
    end

    local state =
        type(HOLY_SHOP_STATE) == "table"
        and HOLY_SHOP_STATE
        or {}

    local rows =
        state.AuctionLastLots

    if type(HolyAuctionScanLiveLots)
    == "function" then

        local ok,
            result =
            pcall(
                HolyAuctionScanLiveLots
            )

        if ok == true
        and type(result) == "table" then

            rows =
                result
        end
    end

    rows =
        type(rows) == "table"
        and rows
        or {}

    local live =
        {}

    local eligible =
        {}

    for _, row in ipairs(rows) do

        if type(row) ~= "table" then
            continue
        end

        local primitive = {
            LotId = tostring(row.LotId or ""),
            Name = tostring(row.Name or "Unknown"),
            Stock = tonumber(row.Stock),
            StockKnown = row.StockKnown == true,
            Active = row.Active == true,
            SoldOut = row.SoldOut == true,
            Expired = row.Expired == true,
            Price = tonumber(row.Price),
            PriceText = tostring(row.PriceText or ""),
            NetworkReady = row.NetworkReady == true,
        }

        local entry,
            watchIndex =
            nil,
            nil

        if type(HolyAuctionGetWatchEntry)
        == "function" then

            local ok,
                foundEntry,
                foundIndex =
                pcall(
                    HolyAuctionGetWatchEntry,
                    row.Name
                )

            if ok == true then

                entry =
                    foundEntry

                watchIndex =
                    foundIndex
            end
        end

        if type(entry) == "table" then

            primitive.WatchlistIndex =
                watchIndex

            primitive.MaxPrice =
                tonumber(entry.MaxPrice)

            if type(HolyAuctionReadMoney)
            == "function" then

                primitive.MaxPrice =
                    HolyAuctionReadMoney(
                        entry.MaxPrice
                    )
            end

            local stale =
                true

            local staleReason =
                "unavailable"

            if type(HolyAuctionRowStale)
            == "function" then

                local ok,
                    result,
                    reason =
                    pcall(
                        HolyAuctionRowStale,
                        row,
                        true
                    )

                if ok == true then

                    stale =
                        result == true

                    staleReason =
                        reason
                end
            end

            local priceAllowed =
                false

            if type(HolyAuctionPriceAllows)
            == "function" then

                local ok,
                    result =
                    pcall(
                        HolyAuctionPriceAllows,
                        row
                    )

                priceAllowed =
                    ok == true
                    and result == true
            end

            local attempted =
                type(state.AuctionAttemptedLots)
                    == "table"
                and state.AuctionAttemptedLots[
                    tostring(row.LotId)
                ] == true

            primitive.Stale =
                stale

            primitive.StaleReason =
                staleReason

            primitive.PriceAllowed =
                priceAllowed

            primitive.AlreadyAttempted =
                attempted

            primitive.Eligible =
                row.Active == true
                and stale ~= true
                and priceAllowed == true
                and (
                    state.AuctionBuyUntilSoldOut
                        == true
                    or attempted ~= true
                )

            if primitive.Eligible == true then

                eligible[#eligible + 1] =
                    primitive
            end
        end

        live[#live + 1] =
            primitive
    end

    local now =
        os.clock()

    local cooldown =
        nil

    local debounce =
        nil

    if type(HolyAuctionReadCooldown)
    == "function" then

        pcall(function()

            cooldown =
                HolyAuctionReadCooldown()
        end)
    end

    if type(HolyAuctionReadDebounce)
    == "function" then

        pcall(function()

            debounce =
                HolyAuctionReadDebounce()
        end)
    end

    return {
        CapturedClock = now,
        AutoBuy = state.AutoBuyAuctions == true,
        DryRun = state.AuctionDryRun == true,
        BuyUntilSoldOut = state.AuctionBuyUntilSoldOut == true,
        NetworkReady = state.AuctionNetworkReady == true,
        WorkerRunning = state.AuctionWorkerRunning == true,

        Pending = {
            LotId = state.AuctionPendingLotId,
            Name = state.AuctionPendingName,
            Price = state.AuctionPendingPrice,
            SentAt = state.AuctionPendingSentAt,
        },

        LastSent = {
            LotId = state.AuctionLastSentLotId,
            Name = state.AuctionLastSentName,
            SentAt = state.AuctionLastSentAt,
        },

        RoundRobinIndex =
            state.AuctionRoundRobinIndex,

        NextBuyAt =
            state.AuctionNextBuyAt,

        NextBuyIn =
            math.max(
                0,
                (
                    tonumber(
                        state.AuctionNextBuyAt
                    )
                    or 0
                ) - now
            ),

        NextRetryAt =
            state.AuctionNextRetryAt,

        NextRetryIn =
            math.max(
                0,
                (
                    tonumber(
                        state.AuctionNextRetryAt
                    )
                    or 0
                ) - now
            ),

        LastDecision =
            state.AuctionLastDecision,

        LastBlockReason =
            state.AuctionLastBlockReason,

        CooldownSeconds =
            cooldown,

        DebounceSeconds =
            debounce,

        Scheduler = {
            State =
                state.AuctionSchedulerState,

            CooldownAnchorAt =
                state.AuctionCooldownAnchorAt,

            CooldownSource =
                state.AuctionCooldownAnchorReason,

            CooldownBase =
                state.AuctionCooldownBase,

            CooldownGuard =
                state.AuctionCooldownGuard,

            AppliedGuard =
                state.AuctionCooldownAppliedGuard,

            CooldownUntil =
                state.AuctionNextBuyAt,

            CooldownRemaining =
                math.max(
                    0,
                    (
                        tonumber(
                            state.AuctionNextBuyAt
                        )
                        or 0
                    ) - now
                ),

            Synchronized =
                state.AuctionCooldownSynchronized
                == true,

            UnknownOutcome =
                state.AuctionUnknownOutcome
                == true,

            LastResultAt =
                state.AuctionLastResultAt,

            LastResultSuccess =
                state.AuctionLastResultSuccess
                == true,

            LastResultReason =
                state.AuctionLastResultReason,

            LastResultLotId =
                state.AuctionLastResultLotId,

            LastResultName =
                state.AuctionLastResultName,

            LastResultLatency =
                state.AuctionLastResultLatency,
        },

        Watchlist =
            HolyDevSafeValue(
                state.AuctionWatchlist
                or {}
            ),

        LiveLots =
            live,

        EligibleItems =
            eligible,

        EligibleCount =
            #eligible,
    }
end

function HolyDevRecorderSnapshot(area)

    area =
        HolyDevRecorderArea(area)

    local snapshot = {
        Area = area,
        Time = os.time(),
        Clock = os.clock(),
        Values = {},
    }

    if area == "Auction"
    or area == "Everything" then

        snapshot.Values.Auction =
            HolyDevRecorderAuctionSnapshot()
    end

    if area == "Player Tools"
    or area == "Own Garden"
    or area == "Wild Pets"
    or area == "Everything" then

        local captured =
            HolyDevCaptureActionScope(
                area
            )

        snapshot.Values.Replicated =
            captured.Values
    end

    if area == "Sniper"
    or area == "Everything" then

        snapshot.Values.Sniper = {
            State =
                HolyDevSafeValue(
                    type(HOLY_SNIPER_STATE)
                        == "table"
                    and HOLY_SNIPER_STATE
                    or {}
                ),

            Runtime =
                HolyDevSafeValue({
                    Running =
                        type(HOLY_SNIPER_RUNTIME)
                            == "table"
                        and HOLY_SNIPER_RUNTIME.Running,

                    Buying =
                        type(HOLY_SNIPER_RUNTIME)
                            == "table"
                        and HOLY_SNIPER_RUNTIME.Buying,

                    LastStatus =
                        type(HOLY_SNIPER_RUNTIME)
                            == "table"
                        and HOLY_SNIPER_RUNTIME.LastStatus,

                    LastReason =
                        type(HOLY_SNIPER_RUNTIME)
                            == "table"
                        and HOLY_SNIPER_RUNTIME.LastReason,
                }),
        }
    end

    return snapshot
end

function HolyDevRecorderEvents(
    windowStart,
    windowEnd
)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local output =
        {}

    for index =
        runtime.RecorderTimelineHead
        or 1,
        runtime.RecorderTimelineTail
        or 0
    do

        local row =
            runtime.RecorderTimeline[index]

        if row
        and (
            windowStart == nil
            or row.Clock >= windowStart
        )
        and (
            windowEnd == nil
            or row.Clock <= windowEnd
        ) then

            output[#output + 1] =
                row
        end
    end

    return output
end

function HolyDevRecorderAnalyzeAuction(
    events,
    before,
    after
)

    local analysis = {
        PurchaseSends = 0,
        PurchaseResults = 0,
        SuccessfulResults = 0,
        FailedResults = 0,
        CooldownNotifications = 0,
        OverlappingRequests = 0,
        SendToSendIntervals = {},
        SendToResultLatency = {},
        MaxEligibleItems = 0,
    }

    local pending =
        {}

    local lastSend =
        nil

    for _, row in ipairs(
        events
        or {}
    ) do

        local data =
            type(row.Data) == "table"
            and row.Data
            or {}

        local packet =
            tostring(
                data.Packet
                or row.Area
                or ""
            ):lower()

        if row.Source == "Packet"
        and row.Event == "Sent"
        and packet:find(
            "purchaselot",
            1,
            true
        ) then

            analysis.PurchaseSends +=
                1

            if #pending > 0 then

                analysis.OverlappingRequests +=
                    1
            end

            if lastSend then

                analysis.SendToSendIntervals[
                    #analysis.SendToSendIntervals
                    + 1
                ] =
                    row.Clock - lastSend
            end

            lastSend =
                row.Clock

            pending[#pending + 1] =
                row.Clock

        elseif row.Source == "Internal"
        and row.Event == "PurchaseResult" then

            analysis.PurchaseResults +=
                1

            if data.Success == true then

                analysis.SuccessfulResults +=
                    1

            else

                analysis.FailedResults +=
                    1
            end

            if #pending > 0 then

                analysis.SendToResultLatency[
                    #analysis.SendToResultLatency
                    + 1
                ] =
                    math.max(
                        0,
                        row.Clock - pending[1]
                    )

                table.remove(
                    pending,
                    1
                )
            end

        elseif row.Source == "UI"
        or row.Event == "HolyNotify" then

            local text =
                (
                    tostring(
                        data.Text
                        or ""
                    )
                    .. " "
                    .. tostring(
                        data.Title
                        or ""
                    )
                ):lower()

            if text:find(
                "please wait",
                1,
                true
            )
            or text:find(
                "wait a moment",
                1,
                true
            )
            or text:find(
                "cooldown",
                1,
                true
            ) then

                analysis.CooldownNotifications +=
                    1
            end
        end

        local eligible =
            tonumber(
                data.EligibleCount
            )
            or tonumber(
                type(data.Decision) == "table"
                and data.Decision.EligibleCount
            )

        if eligible then

            analysis.MaxEligibleItems =
                math.max(
                    analysis.MaxEligibleItems,
                    eligible
                )
        end
    end

    local beforeAuction =
        before
        and before.Values
        and before.Values.Auction

    local afterAuction =
        after
        and after.Values
        and after.Values.Auction

    analysis.MaxEligibleItems =
        math.max(
            analysis.MaxEligibleItems,
            tonumber(
                beforeAuction
                and beforeAuction.EligibleCount
            )
            or 0,
            tonumber(
                afterAuction
                and afterAuction.EligibleCount
            )
            or 0
        )

    analysis.UnansweredRequests =
        #pending

    analysis.HasFailure =
        analysis.FailedResults > 0
        or analysis.CooldownNotifications > 0
        or analysis.OverlappingRequests > 0

    if analysis.OverlappingRequests > 0 then

        analysis.Finding =
            "More than one PurchaseLot was sent before the previous result."

    elseif analysis.FailedResults > 0
    and analysis.MaxEligibleItems > 1 then

        analysis.Finding =
            "Multiple items were eligible, but no overlapping send was proven. Check the packet order and result reason."

    elseif analysis.FailedResults > 0 then

        analysis.Finding =
            "A purchase failed without a proven overlapping request."

    elseif analysis.PurchaseSends > 0 then

        analysis.Finding =
            "No overlapping purchase request was observed."

    else

        analysis.Finding =
            "No purchase request was captured."
    end

    return analysis
end

function HolyDevRecorderVisible(object)

    local current =
        object

    local playerGui =
        LocalPlayer:FindFirstChildOfClass(
            "PlayerGui"
        )

    while typeof(current) == "Instance"
    and current ~= playerGui do

        if current:IsA("GuiObject")
        and current.Visible ~= true then

            return false
        end

        if current:IsA("LayerCollector")
        and current.Enabled ~= true then

            return false
        end

        current =
            current.Parent
    end

    return true
end

function HolyDevRecorderIsTextObject(object)

    return typeof(object) == "Instance"
    and (
        object:IsA("TextLabel")
        or object:IsA("TextButton")
        or object:IsA("TextBox")
    )
end

function HolyDevRecorderIsOwnedUi(object)

    local library =
        type(HOLY_DEV_LIBRARY) == "table"
        and HOLY_DEV_LIBRARY
        or nil

    local screenGui =
        library
        and library.ScreenGui
        or nil

    if typeof(screenGui) == "Instance"
    and typeof(object) == "Instance" then

        local ok,
            result =
            pcall(function()

                return object:IsDescendantOf(
                    screenGui
                )
            end)

        if ok == true
        and result == true then

            return true
        end
    end

    return false
end

function HolyDevRecorderObserveUiObject(
    object,
    baseline
)

    if HolyDevRecorderIsTextObject(
        object
    ) ~= true
    or HolyDevRecorderIsOwnedUi(
        object
    ) == true then

        return
    end

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local text =
        tostring(
            object.Text
            or ""
        )

    local visible =
        HolyDevRecorderVisible(
            object
        )

    local previous =
        runtime.RecorderUiState[object]

    runtime.RecorderUiState[object] = {
        Text = text,
        Visible = visible,
    }

    if baseline == true
    or text == "" then
        return
    end

    if previous == nil
    or (
        visible == true
        and (
            previous.Visible ~= true
            or previous.Text ~= text
        )
    ) then

        local payload = {
            Text = text,
            Path = HolyDevGetFullName(object),
            ClassName = object.ClassName,
        }

        HolyDevRecorderPush(
            "UI",
            "UI & Notifications",
            "TextShown",
            payload,
            "Info"
        )

        local lower =
            text:lower()

        if lower:find(
            "please wait",
            1,
            true
        )
        or lower:find(
            "wait a moment",
            1,
            true
        )
        or lower:find(
            "cooldown",
            1,
            true
        ) then

            HolyDevRecorderAutoTrigger(
                "Cooldown notification",
                payload
            )
        end
    end
end

function HolyDevRecorderStartUiCapture()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    runtime.RecorderGeneration =
        (
            runtime.RecorderGeneration
            or 0
        )
        + 1

    local generation =
        runtime.RecorderGeneration

    runtime.RecorderUiState =
        setmetatable(
            {},
            {
                __mode = "k",
            }
        )

    runtime.RecorderUiTracked =
        0

    local playerGui =
        LocalPlayer:FindFirstChildOfClass(
            "PlayerGui"
        )

    if not playerGui then
        return false
    end

    for _, object in ipairs(
        playerGui:GetDescendants()
    ) do

        if runtime.RecorderUiTracked < 1500
        and HolyDevRecorderIsTextObject(
            object
        )
        and HolyDevRecorderIsOwnedUi(
            object
        ) ~= true then

            runtime.RecorderUiTracked +=
                1

            HolyDevRecorderObserveUiObject(
                object,
                true
            )
        end
    end

    local connection =
        playerGui.DescendantAdded:Connect(function(object)

            if HolyDevRecorderIsTextObject(
                object
            )
            and HolyDevRecorderIsOwnedUi(
                object
            ) ~= true
            and runtime.RecorderUiTracked < 1500 then

                runtime.RecorderUiTracked +=
                    1

                runtime.RecorderUiState[object] = {
                    Text = "",
                    Visible = false,
                }
            end
        end)

    runtime.RecorderConnections[
        #runtime.RecorderConnections + 1
    ] =
        connection

    task.spawn(function()

        while runtime.RecorderActive == true
        and runtime.RecorderGeneration
            == generation do

            for object in pairs(
                runtime.RecorderUiState
            ) do

                if object.Parent then

                    pcall(
                        HolyDevRecorderObserveUiObject,
                        object,
                        false
                    )
                end
            end

            task.wait(0.5)
        end
    end)

    return true
end

function HolyDevRecorderCleanupSources()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    runtime.RecorderGeneration =
        (
            runtime.RecorderGeneration
            or 0
        )
        + 1

    for _, connection in ipairs(
        runtime.RecorderConnections
        or {}
    ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.RecorderConnections =
        {}

    runtime.RecorderUiState =
        {}

    runtime.RecorderUiTracked =
        0

    if runtime.RecorderOwnsPacketCapture
    == true then

        runtime.PacketActive =
            false

        HolyDevPacketCleanup()

        local config =
            runtime.RecorderSavedPacketConfig
            or {}

        HOLY_DEV_SUITE_STATE.PacketDirection =
            config.Direction
            or HOLY_DEV_SUITE_STATE.PacketDirection

        HOLY_DEV_SUITE_STATE.PacketFilter =
            config.Filter
            or HOLY_DEV_SUITE_STATE.PacketFilter

        HOLY_DEV_SUITE_STATE.PacketMaxEvents =
            config.MaxEvents
            or HOLY_DEV_SUITE_STATE.PacketMaxEvents

        runtime.RecorderOwnsPacketCapture =
            false

        runtime.RecorderSavedPacketConfig =
            nil

        HolyDevPacketRefreshStatus(
            true
        )
    end
end

function HolyDevRecorderStartPackets()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    runtime.RecorderSavedPacketConfig = {
        Direction =
            HOLY_DEV_SUITE_STATE.PacketDirection,

        Filter =
            HOLY_DEV_SUITE_STATE.PacketFilter,

        MaxEvents =
            HOLY_DEV_SUITE_STATE.PacketMaxEvents,
    }

    HOLY_DEV_SUITE_STATE.PacketDirection =
        "Both"

    HOLY_DEV_SUITE_STATE.PacketFilter =
        ""

    HOLY_DEV_SUITE_STATE.PacketMaxEvents =
        10000

    local ok =
        HolyDevPacketStart() == true

    runtime.RecorderOwnsPacketCapture =
        ok

    runtime.RecorderCapabilities.Packets =
        ok

    if ok ~= true then

        local config =
            runtime.RecorderSavedPacketConfig

        HOLY_DEV_SUITE_STATE.PacketDirection =
            config.Direction

        HOLY_DEV_SUITE_STATE.PacketFilter =
            config.Filter

        HOLY_DEV_SUITE_STATE.PacketMaxEvents =
            config.MaxEvents

        runtime.RecorderSavedPacketConfig =
            nil
    end

    return ok
end

function HolyDevRecorderAutoTrigger(name, data)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.RecorderActive ~= true
    or runtime.RecorderTrigger ~= nil then

        return false
    end

    local area =
        HolyDevRecorderArea(
            HOLY_DEV_SUITE_STATE.RecorderArea
        )

    if area ~= "Auction"
    and area ~= "Everything" then

        return false
    end

    runtime.RecorderTriggerGeneration =
        (
            runtime.RecorderTriggerGeneration
            or 0
        )
        + 1

    local generation =
        runtime.RecorderTriggerGeneration

    runtime.RecorderTrigger = {
        Name = tostring(name),
        Clock = os.clock(),
        Time = os.time(),
        Data = HolyDevSafeValue(data),
    }

    HolyDevRecorderPush(
        "Recorder",
        "Auction",
        "AutoTrigger",
        runtime.RecorderTrigger,
        "Warning"
    )

    HolyDevRecorderRefreshStatus()

    if HolyDevRecorderMode(
        HOLY_DEV_SUITE_STATE.RecorderMode
    ) ~= "Rolling 30 Seconds" then

        return true
    end

    task.delay(5, function()

        if runtime.RecorderActive == true
        and runtime.RecorderTriggerGeneration
            == generation
        and runtime.RecorderTrigger then

            HolyDevRecorderSaveReport(
                "automatic issue capture",
                false,
                {
                    WindowStart =
                        runtime.RecorderTrigger.Clock
                        - 20,

                    WindowEnd =
                        runtime.RecorderTrigger.Clock
                        + 5,
                }
            )

            runtime.RecorderTrigger =
                nil

            HolyDevRecorderRefreshStatus(
                "Issue captured · use Copy Last"
            )
        end
    end)

    return true
end

function HolyDevRecorderBuildReport(
    reason,
    options
)

    options =
        type(options) == "table"
        and options
        or {}

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local events =
        HolyDevRecorderEvents(
            options.WindowStart,
            options.WindowEnd
        )

    local area =
        HolyDevRecorderArea(
            HOLY_DEV_SUITE_STATE.RecorderArea
        )

    local after =
        runtime.RecorderAfter
        or HolyDevRecorderSnapshot(
            area
        )

    local before =
        runtime.RecorderBefore

    local beforeFlat =
        before
        and HolyDevFlatten(
            before.Values,
            "Snapshot",
            {}
        )
        or {}

    local afterFlat =
        after
        and HolyDevFlatten(
            after.Values,
            "Snapshot",
            {}
        )
        or {}

    local placeVersion =
        nil

    pcall(function()

        placeVersion =
            game.PlaceVersion
    end)

    local report = {
        Version = "HOLY_DEV_TEST_RECORDER_V1",
        PlaceId = game.PlaceId,
        PlaceVersion = placeVersion,
        JobId = game.JobId,

        Player = {
            Name = LocalPlayer.Name,
            UserId = LocalPlayer.UserId,
        },

        Area = area,

        Mode =
            HolyDevRecorderMode(
                HOLY_DEV_SUITE_STATE.RecorderMode
            ),

        Note =
            tostring(
                HOLY_DEV_SUITE_STATE.RecorderNote
                or ""
            ),

        StartedAt =
            runtime.RecorderStartedAt,

        FinishedAt =
            os.time(),

        Runtime =
            os.clock()
            - (
                runtime.RecorderStartedClock
                or os.clock()
            ),

        FinishReason =
            tostring(
                reason
                or "manual"
            ),

        Trigger =
            runtime.RecorderTrigger,

        Capabilities =
            runtime.RecorderCapabilities,

        StoredEvents =
            #events,

        DroppedEvents =
            runtime.RecorderDropped
            or 0,

        Before =
            before,

        After =
            after,

        Diff =
            HolyDevDiffMaps(
                beforeFlat,
                afterFlat
            ),

        Timeline =
            events,
    }

    if area == "Auction"
    or area == "Everything" then

        report.Analysis =
            HolyDevRecorderAnalyzeAuction(
                events,
                before,
                after
            )
    end

    return report
end

function HolyDevRecorderSaveReport(
    reason,
    copyResult,
    options
)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    runtime.RecorderAfter =
        HolyDevRecorderSnapshot(
            HOLY_DEV_SUITE_STATE.RecorderArea
        )

    local report =
        HolyDevRecorderBuildReport(
            reason,
            options
        )

    runtime.LastRecorderReport =
        report

    local saved =
        HolyDevWriteJson(
            DEV_TEST_RECORDER_FILE,
            report
        )

    local copied =
        copyResult == true
        and HolyDevCopyReport(report)
        or false

    local status =
        tostring(
            report.StoredEvents
        )
        .. " events"

    if report.Analysis
    and report.Analysis.HasFailure then

        status =
            status
            .. " · issue found"
    end

    if copied == true then

        status =
            status
            .. " · copied"
    end

    if saved == true then

        status =
            status
            .. " · saved"
    end

    HolyDevRecorderRefreshStatus(
        status
    )

    return report
end

function HolyDevRecorderDeleteCheckpoint()

    if HolyCanUseFiles() == true
    and type(delfile) == "function" then

        pcall(function()

            if isfile(
                DEV_TEST_CHECKPOINT_FILE
            ) then

                delfile(
                    DEV_TEST_CHECKPOINT_FILE
                )
            end
        end)
    end
end

function HolyDevRecorderStartCheckpointWorker()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local generation =
        runtime.RecorderGeneration

    task.spawn(function()

        while runtime.RecorderActive == true
        and runtime.RecorderGeneration
            == generation do

            task.wait(30)

            if runtime.RecorderActive == true
            and runtime.RecorderGeneration
                == generation then

                HolyDevWriteJson(
                    DEV_TEST_CHECKPOINT_FILE,
                    {
                        Version =
                            "HOLY_DEV_TEST_CHECKPOINT_V1",

                        Active =
                            true,

                        Area =
                            HOLY_DEV_SUITE_STATE.RecorderArea,

                        Mode =
                            HOLY_DEV_SUITE_STATE.RecorderMode,

                        Note =
                            HOLY_DEV_SUITE_STATE.RecorderNote,

                        StartedAt =
                            runtime.RecorderStartedAt,

                        SavedAt =
                            os.time(),

                        DroppedEvents =
                            runtime.RecorderDropped,

                        Timeline =
                            HolyDevRecorderEvents(),
                    }
                )
            end
        end
    end)
end

function HolyDevRecorderStart()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.RecorderActive == true then

        HolyNotify(
            "HOLY Dev",
            "Test Recorder is already running.",
            4
        )

        return false
    end

    if runtime.PacketActive == true then

        HolyNotify(
            "HOLY Dev",
            "Stop Packet Watcher before starting Test Recorder so both sent and received hooks are complete.",
            6
        )

        HolyDevRecorderRefreshStatus(
            "Stop Packet Watcher first"
        )

        return false
    end

    HOLY_DEV_SUITE_STATE.RecorderArea =
        HolyDevRecorderArea(
            HOLY_DEV_SUITE_STATE.RecorderArea
        )

    HOLY_DEV_SUITE_STATE.RecorderMode =
        HolyDevRecorderMode(
            HOLY_DEV_SUITE_STATE.RecorderMode
        )

    runtime.RecorderActive =
        true

    runtime.RecorderStartedAt =
        os.time()

    runtime.RecorderStartedClock =
        os.clock()

    runtime.RecorderSequence =
        0

    runtime.RecorderTimeline =
        {}

    runtime.RecorderTimelineHead =
        1

    runtime.RecorderTimelineTail =
        0

    runtime.RecorderDropped =
        0

    runtime.RecorderTrigger =
        nil

    runtime.RecorderAfter =
        nil

    runtime.RecorderConnections =
        {}

    runtime.RecorderCapabilities = {
        State = true,
        UI = false,
        Errors = runtime.ErrorConnection ~= nil,
        Packets = false,
        CheckpointFile = HolyCanUseFiles() == true,
    }

    runtime.RecorderBefore =
        HolyDevRecorderSnapshot(
            HOLY_DEV_SUITE_STATE.RecorderArea
        )

    runtime.RecorderCapabilities.UI =
        HolyDevRecorderStartUiCapture()

    HolyDevRecorderStartPackets()

    HolyDevRecorderPush(
        "Recorder",
        HOLY_DEV_SUITE_STATE.RecorderArea,
        "Started",
        {
            Mode =
                HOLY_DEV_SUITE_STATE.RecorderMode,

            Note =
                HOLY_DEV_SUITE_STATE.RecorderNote,

            Capabilities =
                runtime.RecorderCapabilities,
        },
        "Info"
    )

    HolyDevSetStatus(
        "RecorderSourcesLabel",
        "Sources: Packets "
            .. (
                runtime.RecorderCapabilities.Packets
                and "yes"
                or "no"
            )
            .. " · State yes · UI "
            .. (
                runtime.RecorderCapabilities.UI
                and "yes"
                or "no"
            )
            .. " · Errors "
            .. (
                runtime.RecorderCapabilities.Errors
                and "yes"
                or "no"
            )
    )

    HolyDevRecorderRefreshStatus()

    HolyDevRecorderStartCheckpointWorker()

    return true
end

function HolyDevRecorderFinish(
    copyResult,
    reason
)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.RecorderActive ~= true then

        HolyNotify(
            "HOLY Dev",
            "Start Test Recorder first.",
            4
        )

        return false
    end

    HolyDevRecorderPush(
        "Recorder",
        HOLY_DEV_SUITE_STATE.RecorderArea,
        "Finished",
        {
            Reason =
                reason
                or "manual finish",
        },
        "Info"
    )

    runtime.RecorderAfter =
        HolyDevRecorderSnapshot(
            HOLY_DEV_SUITE_STATE.RecorderArea
        )

    local report =
        HolyDevRecorderBuildReport(
            reason
            or "manual finish"
        )

    runtime.RecorderActive =
        false

    runtime.RecorderTriggerGeneration =
        (
            runtime.RecorderTriggerGeneration
            or 0
        )
        + 1

    HolyDevRecorderCleanupSources()

    runtime.LastRecorderReport =
        report

    local saved =
        HolyDevWriteJson(
            DEV_TEST_RECORDER_FILE,
            report
        )

    local copied =
        copyResult == true
        and HolyDevCopyReport(report)
        or false

    HolyDevRecorderDeleteCheckpoint()

    local status =
        tostring(
            report.StoredEvents
        )
        .. " events"

    if report.Analysis
    and report.Analysis.HasFailure then

        status =
            status
            .. " · issue found"
    end

    if copied == true then

        status =
            status
            .. " · copied"
    end

    if saved == true then

        status =
            status
            .. " · saved"
    end

    HolyDevRecorderRefreshStatus(
        status
    )

    HolyNotify(
        "HOLY Dev",
        status,
        5
    )

    return true
end

function HolyDevRecorderSaveRecent(copyResult)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.RecorderActive ~= true
    or HolyDevRecorderMode(
        HOLY_DEV_SUITE_STATE.RecorderMode
    ) ~= "Rolling 30 Seconds" then

        HolyNotify(
            "HOLY Dev",
            "Start Rolling 30 Seconds mode first.",
            4
        )

        return false
    end

    local now =
        os.clock()

    HolyDevRecorderSaveReport(
        "save recent",
        copyResult == true,
        {
            WindowStart = now - 30,
            WindowEnd = now,
        }
    )

    return true
end

function HolyDevRecorderMarkMoment()

    if HOLY_DEV_SUITE_RUNTIME.RecorderActive
    ~= true then

        HolyNotify(
            "HOLY Dev",
            "Start Test Recorder first.",
            4
        )

        return false
    end

    local note =
        HolyCleanText(
            HOLY_DEV_SUITE_STATE.RecorderNote
        )

    if note == "" then

        note =
            "Manual marker"
    end

    HolyDevRecorderPush(
        "Marker",
        HOLY_DEV_SUITE_STATE.RecorderArea,
        "Mark Moment",
        {
            Note = note,
        },
        "Info"
    )

    HolyDevRecorderRefreshStatus(
        "Moment marked · "
            .. note
    )

    return true
end

function HolyDevRecorderCopyLast()

    local report =
        HOLY_DEV_SUITE_RUNTIME.LastRecorderReport
        or HolyDevReadJson(
            DEV_TEST_RECORDER_FILE
        )

    if type(report) ~= "table" then

        HolyNotify(
            "HOLY Dev",
            "No Test Recorder report is available yet.",
            4
        )

        return false
    end

    local copied =
        HolyDevCopyReport(report)

    if copied == true then

        HolyNotify(
            "HOLY Dev",
            "Test Recorder report copied.",
            4
        )
    end

    return copied
end

function HolyDevRecorderClear()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.RecorderActive == true then

        runtime.RecorderActive =
            false

        runtime.RecorderTriggerGeneration =
            (
                runtime.RecorderTriggerGeneration
                or 0
            )
            + 1

        HolyDevRecorderCleanupSources()
    end

    runtime.LastRecorderReport =
        nil

    runtime.RecorderTimeline =
        {}

    runtime.RecorderTimelineHead =
        1

    runtime.RecorderTimelineTail =
        0

    runtime.RecorderBefore =
        nil

    runtime.RecorderAfter =
        nil

    runtime.RecorderTrigger =
        nil

    if HolyCanUseFiles() == true
    and type(delfile) == "function" then

        pcall(function()

            if isfile(
                DEV_TEST_RECORDER_FILE
            ) then

                delfile(
                    DEV_TEST_RECORDER_FILE
                )
            end
        end)
    end

    HolyDevRecorderDeleteCheckpoint()

    HolyDevRecorderRefreshStatus(
        "Ready · cleared"
    )

    return true
end

function HolyDevQuickSnapshotScope(value)

    value =
        tostring(
            value
            or "Auction"
        )

    local allowed = {
        ["Auction"] = true,
        ["HOLY Runtime"] = true,
        ["Player Tools"] = true,
        ["Own Garden"] = true,
        ["Wild Pets"] = true,
        ["Time & Weather"] = true,
        ["Everything"] = true,
    }

    return allowed[value] == true
        and value
        or "Auction"
end

function HolyDevQuickSnapshotWants(
    scope,
    section
)

    return scope == "Everything"
        or scope == section
end

function HolyDevQuickSnapshotPick(
    source,
    keys
)

    local output =
        {}

    if type(source) ~= "table" then
        return output
    end

    for _, key in ipairs(keys) do

        if source[key] ~= nil then

            output[key] =
                source[key]
        end
    end

    return output
end

