function HolyDevQuickSnapshotTimeWeather()

    local serverNow =
        nil

    pcall(function()

        serverNow =
            workspace:GetServerTimeNow()
    end)

    local function readModule(path)

        local ok,
            result =
            pcall(function()

                return HolyShopRequireModule(
                    path
                )
            end)

        if ok == true
        and type(result) == "table" then

            return result,
                nil
        end

        return nil,
            tostring(
                result
                or "module unavailable"
            )
    end

    local timeCycleData,
        timeCycleError =
        readModule(
            "SharedModules.TimeCycleData"
        )

    local weatherData,
        weatherError =
        readModule(
            "SharedModules.WeatherData"
        )

    local predictor =
        type(HOLY_MOON_PREDICTOR_STATE)
            == "table"
        and HOLY_MOON_PREDICTOR_STATE
        or {}

    return {
        ClientClock = os.clock(),
        ClientUnix = os.time(),
        ServerNow = serverNow,

        WorkspaceAttributes =
            workspace:GetAttributes(),

        Current = {
            ActiveWeather =
                workspace:GetAttribute(
                    "ActiveWeather"
                ),

            Phase =
                workspace:GetAttribute(
                    "Phase"
                ),

            PhaseDuration =
                workspace:GetAttribute(
                    "PhaseDuration"
                ),
        },

        Predictor = {
            CycleInfo =
                predictor.CycleInfo,

            MoonTypes =
                predictor.MoonTypes,

            WeatherRecords =
                predictor.WeatherRecords,

            LastBuildCycle =
                predictor.LastBuildCycle,

            Predictions =
                predictor.Predictions,
        },

        Modules = {
            TimeCycleData =
                timeCycleData,

            WeatherData =
                weatherData,
        },

        ModuleErrors = {
            TimeCycleData =
                timeCycleError,

            WeatherData =
                weatherError,
        },
    }
end

function HolyDevQuickSnapshotCapture(copyReport)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local scope =
        HolyDevQuickSnapshotScope(
            HOLY_DEV_SUITE_STATE.SnapshotScope
        )

    HOLY_DEV_SUITE_STATE.SnapshotScope =
        scope

    HolyDevSetStatus(
        "SnapshotStatusLabel",
        "Capturing "
            .. scope
            .. "..."
    )

    local placeVersion =
        nil

    pcall(function()

        placeVersion =
            game.PlaceVersion
    end)

    local report = {
        Version = "HOLY_DEV_QUICK_SNAPSHOT_V1",
        Scope = scope,
        PlaceId = game.PlaceId,
        PlaceVersion = placeVersion,
        JobId = game.JobId,
        CapturedAt = os.time(),

        Player = {
            Name = LocalPlayer.Name,
            UserId = LocalPlayer.UserId,
        },

        Capabilities = {},
        Errors = {},
        Data = {},
    }

    local function capture(
        section,
        callback
    )

        if HolyDevQuickSnapshotWants(
            scope,
            section
        ) ~= true then

            return
        end

        local ok,
            value =
            pcall(callback)

        report.Capabilities[section] =
            ok == true

        if ok == true then

            report.Data[section] =
                value

        else

            report.Errors[section] =
                tostring(value)
        end
    end

    capture(
        "Auction",
        HolyDevRecorderAuctionSnapshot
    )

    capture(
        "HOLY Runtime",
        HolyDevQuickSnapshotRuntime
    )

    capture(
        "Player Tools",
        function()

            return {
                PlayerAttributes =
                    LocalPlayer:GetAttributes(),

                Tools =
                    HolyDevSnapshotToolRows(),
            }
        end
    )

    capture(
        "Own Garden",
        function()

            local plot =
                HolyDevFindOwnPlot()

            if typeof(plot) ~= "Instance" then

                return {
                    Found = false,
                }
            end

            return {
                Found = true,
                Name = plot.Name,
                FullName = HolyDevGetFullName(plot),
                Attributes = plot:GetAttributes(),

                AttributedObjects =
                    HolyDevSnapshotAttributedRoot(
                        plot,
                        {}
                    ),
            }
        end
    )

    capture(
        "Wild Pets",
        function()

            local map =
                workspace:FindFirstChild(
                    "Map"
                )

            local root =
                map
                and map:FindFirstChild(
                    "WildPetRef"
                )

            if typeof(root) ~= "Instance" then

                return {
                    Found = false,
                }
            end

            return {
                Found = true,
                Count = #root:GetChildren(),
                Attributes = root:GetAttributes(),

                AttributedObjects =
                    HolyDevSnapshotAttributedRoot(
                        root,
                        {}
                    ),
            }
        end
    )

    capture(
        "Time & Weather",
        HolyDevQuickSnapshotTimeWeather
    )

    runtime.LastQuickSnapshot =
        report

    local saved =
        HolyDevWriteJson(
            DEV_QUICK_SNAPSHOT_FILE,
            report
        )

    local copied =
        copyReport == true
        and HolyDevCopyReport(report)
        or false

    local sectionCount =
        0

    for _ in pairs(
        report.Data
    ) do

        sectionCount +=
            1
    end

    local status =
        scope
        .. " · "
        .. tostring(sectionCount)
        .. (
            sectionCount == 1
            and " section"
            or " sections"
        )

    if copied == true then

        status =
            status
            .. " · copied"
    end

    if saved == true then

        status =
            status
            .. " · saved"
    end

    HolyDevSetStatus(
        "SnapshotStatusLabel",
        status
    )

    HolyNotify(
        "HOLY Dev",
        status,
        4
    )

    return report
end

function HolyDevQuickSnapshotCopyLast()

    local report =
        HOLY_DEV_SUITE_RUNTIME.LastQuickSnapshot
        or HolyDevReadJson(
            DEV_QUICK_SNAPSHOT_FILE
        )

    if type(report) ~= "table" then

        HolyNotify(
            "HOLY Dev",
            "No Quick Snapshot is available yet.",
            4
        )

        return false
    end

    local copied =
        HolyDevCopyReport(report)

    if copied == true then

        HolyDevSetStatus(
            "SnapshotStatusLabel",
            tostring(
                report.Scope
                or "Snapshot"
            )
            .. " · copied"
        )

        HolyNotify(
            "HOLY Dev",
            "Quick Snapshot copied.",
            4
        )
    end

    return copied
end

function HolyDevFlatten(
    value,
    prefix,
    output,
    depth,
    seen
)

    output =
        type(output) == "table"
        and output
        or {}

    prefix =
        tostring(prefix or "Root")

    depth =
        tonumber(depth)
        or 0

    seen =
        type(seen) == "table"
        and seen
        or {}

    local valueType =
        typeof(value)

    if valueType ~= "table"
    or depth >= 6 then

        local encoded =
            HolyDevEncode(value)

        output[prefix] =
            encoded
            or tostring(value)

        return output
    end

    if seen[value] == true then

        output[prefix] =
            "<cycle>"

        return output
    end

    seen[value] =
        true

    local found =
        false

    for key, child in pairs(value) do

        found =
            true

        HolyDevFlatten(
            child,
            prefix
                .. "."
                .. tostring(key),
            output,
            depth + 1,
            seen
        )
    end

    if found ~= true then

        output[prefix] =
            "{}"
    end

    seen[value] =
        nil

    return output
end

function HolyDevDiffMaps(beforeMap, afterMap)

    beforeMap =
        type(beforeMap) == "table"
        and beforeMap
        or {}

    afterMap =
        type(afterMap) == "table"
        and afterMap
        or {}

    local report = {
        Added = {},
        Removed = {},
        Changed = {},
    }

    for key, afterValue in pairs(afterMap) do

        local beforeValue =
            beforeMap[key]

        if beforeValue == nil then

            report.Added[#report.Added + 1] = {
                Path = key,
                Value = afterValue,
            }

        elseif beforeValue ~= afterValue then

            report.Changed[#report.Changed + 1] = {
                Path = key,
                Before = beforeValue,
                After = afterValue,
            }
        end
    end

    for key, beforeValue in pairs(beforeMap) do

        if afterMap[key] == nil then

            report.Removed[#report.Removed + 1] = {
                Path = key,
                Value = beforeValue,
            }
        end
    end

    local function sortRows(rows)

        table.sort(rows, function(a, b)

            return tostring(a.Path):lower()
                < tostring(b.Path):lower()
        end)
    end

    sortRows(report.Added)
    sortRows(report.Removed)
    sortRows(report.Changed)

    report.AddedCount =
        #report.Added

    report.RemovedCount =
        #report.Removed

    report.ChangedCount =
        #report.Changed

    return report
end

function HolyDevBeginActionCapture()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    runtime.ActionBefore =
        HolyDevCaptureActionScope(
            HOLY_DEV_SUITE_STATE.ActionScope
        )

    HolyDevSetStatus(
        "ActionStatusLabel",
        "Capturing — perform one action."
    )

    HolyNotify(
        "HOLY Dev",
        "Action capture started.",
        4
    )

    return true
end

function HolyDevEndActionCapture()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if type(runtime.ActionBefore) ~= "table" then

        HolyNotify(
            "HOLY Dev",
            "Press Begin Capture first.",
            4
        )

        return false
    end

    local after =
        HolyDevCaptureActionScope(
            runtime.ActionBefore.Scope
        )

    local beforeFlat =
        HolyDevFlatten(
            runtime.ActionBefore.Values,
            "Action",
            {}
        )

    local afterFlat =
        HolyDevFlatten(
            after.Values,
            "Action",
            {}
        )

    local diff =
        HolyDevDiffMaps(
            beforeFlat,
            afterFlat
        )

    local report = {
        Version =
            "HOLY_DEV_ACTION_CAPTURE_V1",

        Scope =
            runtime.ActionBefore.Scope,

        StartedAt =
            runtime.ActionBefore.Time,

        FinishedAt =
            os.time(),

        JobId =
            game.JobId,

        Diff =
            diff,

        Before =
            runtime.ActionBefore,

        After =
            after,
    }

    runtime.LastActionReport =
        report

    runtime.ActionBefore =
        nil

    HolyDevCopyReport(
        report
    )

    HolyDevSetStatus(
        "ActionStatusLabel",
        "+"
            .. tostring(diff.AddedCount)
            .. "  -"
            .. tostring(diff.RemovedCount)
            .. "  ~"
            .. tostring(diff.ChangedCount)
            .. " — copied"
    )

    return true
end

local HOLY_DEV_UPDATE_IGNORED_KEYS = {
    onclientevent = true,
    onserverevent = true,
    onclientinvoke = true,
    onserverinvoke = true,
    next = true,
    previous = true,
    once = true,
    ["function"] = true,
    callback = true,
    callbacks = true,
    connection = true,
    connections = true,
    signal = true,
    changed = true,
    loaded = true,
    cs = true,
    maid = true,
    janitor = true,
    trove = true,
}

local HOLY_DEV_UPDATE_SAFE_DATA_MODULES = {
    itemcatalog = true,
    gearshopdata = true,
    wateringcandata = true,
    sprinklerdata = true,
    seeddata = true,
    eggdata = true,
    cratedata = true,
    propdata = true,
    fencedata = true,
    raritydata = true,
    weatherdata = true,
    timecycledata = true,
    mushroomdata = true,
    plantsizemultipliers = true,
    growratedata = true,
    growthboostsources = true,
    petteleporterdata = true,
    troweldata = true,
    sellvaluedata = true,
    devproducts = true,
    exclusiveshopdata = true,
    robuxshopcontent = true,
    seedpackdata = true,
    petgating = true,
    crateshopenabled = true,
    crateshoplimited = true,
    seedshoplimited = true,
}

function HolyDevUpdateScope(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower:find("script", 1, true)
    or lower:find("controller", 1, true) then

        return "Scripts & Controllers"
    end

    if lower:find("network", 1, true) then
        return "Networking"
    end

    if lower:find("catalog", 1, true)
    or lower:find("data", 1, true) then

        return "Catalogs & Data"
    end

    if lower:find("structure", 1, true) then
        return "Structure"
    end

    return "Everything"
end

function HolyDevUpdateWants(scope, category)

    scope =
        HolyDevUpdateScope(
            scope
        )

    return scope == "Everything"
        or scope == category
end

function HolyDevUpdateEncodeExact(value)

    local success,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                value
            )
        end)

    if success == true
    and type(encoded) == "string" then

        return encoded
    end

    return nil,
        encoded
end

function HolyDevUpdateWriteExact(fileName, value)

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local encoded =
        HolyDevUpdateEncodeExact(
            value
        )

    if type(encoded) ~= "string" then
        return false
    end

    return pcall(function()

        writefile(
            fileName,
            encoded
        )
    end)
end

function HolyDevUpdateHistoryFile(placeVersion)

    local safeVersion =
        tostring(
            placeVersion
            or "unknown"
        ):gsub(
            "[^%w_%-]",
            "_"
        )

    return DEV_UPDATE_HISTORY_PREFIX
        .. safeVersion
        .. ".json"
end

function HolyDevUpdateHashText(value)

    if type(value) ~= "string" then

        value =
            tostring(
                value
                or ""
            )
    end

    local hash =
        5381

    for index = 1, #value do

        hash =
            (
                hash * 33
                + string.byte(
                    value,
                    index
                )
            )
            % 4294967296
    end

    return string.format(
        "%08x:%d",
        math.floor(hash),
        #value
    )
end

function HolyDevUpdateBytecodeReader()

    local candidates =
        {}

    local function addCandidate(value)

        if type(value) == "function" then

            candidates[#candidates + 1] =
                value
        end
    end

    addCandidate(
        getscriptbytecode
    )

    addCandidate(
        get_script_bytecode
    )

    if type(getgenv) == "function" then

        pcall(function()

            local environment =
                getgenv()

            if type(environment) == "table" then

                addCandidate(
                    environment.getscriptbytecode
                )

                addCandidate(
                    environment.get_script_bytecode
                )
            end
        end)
    end

    return candidates[1]
end

function HolyDevUpdateWarn(snapshot, message)

    if type(snapshot) ~= "table" then
        return false
    end

    message =
        HolyCleanText(
            message
        )

    if message == "" then
        return false
    end

    snapshot._WarningMap =
        type(snapshot._WarningMap) == "table"
        and snapshot._WarningMap
        or {}

    if snapshot._WarningMap[message] == true then
        return false
    end

    snapshot._WarningMap[message] =
        true

    snapshot.Warnings[#snapshot.Warnings + 1] =
        message

    return true
end

function HolyDevUpdatePrimitive(value, path)

    local valueType =
        typeof(value)

    if valueType == "boolean" then
        return value,
            true
    end

    if valueType == "number" then

        if value ~= value
        or value == math.huge
        or value == -math.huge then

            return tostring(value),
                true
        end

        return value,
            true
    end

    if valueType == "string" then

        if HolyDevSensitiveKey(path) == true then
            return "<redacted>",
                true
        end

        if HolyDevSensitiveString(value) == true then
            return "<redacted sensitive string>",
                true
        end

        local utf8Success,
            utf8Length =
            pcall(
                utf8.len,
                value
            )

        if utf8Success ~= true
        or utf8Length == nil then

            return "<binary "
                .. HolyDevUpdateHashText(value)
                .. ">",
                true
        end

        if #value > 4000 then

            return "<long-string "
                .. HolyDevUpdateHashText(value)
                .. ">",
                true
        end

        return value,
            true
    end

    if valueType == "EnumItem" then
        return tostring(value),
            true
    end

    if valueType == "Instance" then

        return value.ClassName
            .. ":"
            .. HolyDevGetFullName(value),
            true
    end

    if valueType == "buffer" then

        local length =
            0

        local content =
            ""

        pcall(function()

            length =
                buffer.len(value)

            content =
                buffer.tostring(value)
        end)

        return "buffer:"
            .. HolyDevUpdateHashText(content)
            .. ":"
            .. tostring(length),
            true
    end

    if valueType == "Vector2"
    or valueType == "Vector3"
    or valueType == "CFrame"
    or valueType == "Color3"
    or valueType == "UDim"
    or valueType == "UDim2"
    or valueType == "BrickColor"
    or valueType == "NumberRange"
    or valueType == "NumberSequence"
    or valueType == "ColorSequence"
    or valueType == "Rect"
    or valueType == "Ray" then

        return valueType
            .. ":"
            .. tostring(value),
            true
    end

    return nil,
        false
end

function HolyDevUpdateAdd(snapshot, path, value)

    if type(snapshot) ~= "table"
    or type(snapshot.Values) ~= "table" then

        return false
    end

    if snapshot.EntryLimitHit == true then
        return false
    end

    path =
        tostring(
            path
            or ""
        )

    if path == "" then
        return false
    end

    local normalized,
        supported =
        HolyDevUpdatePrimitive(
            value,
            path
        )

    if supported ~= true then

        snapshot.Stats.UnsupportedValues +=
            1

        return false
    end

    if snapshot.Values[path] == nil then

        snapshot._EntryCount +=
            1

        if snapshot._EntryCount
        > snapshot.EntryLimit then

            snapshot.EntryLimitHit =
                true

            snapshot.Complete =
                false

            HolyDevUpdateWarn(
                snapshot,
                "Stable entry limit reached; this capture cannot become a baseline."
            )

            return false
        end
    end

    snapshot.Values[path] =
        normalized

    return true
end

function HolyDevUpdateSortedKeys(value)

    local keys =
        {}

    if type(value) ~= "table" then
        return keys
    end

    for key in pairs(value) do

        keys[#keys + 1] =
            key
    end

    table.sort(keys, function(a, b)

        local aType =
            typeof(a)

        local bType =
            typeof(b)

        if aType ~= bType then
            return aType < bType
        end

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return keys
end

function HolyDevUpdateIgnoreKey(key)

    local text =
        tostring(
            key
            or ""
        )

    local lower =
        text:lower()

    if HOLY_DEV_UPDATE_IGNORED_KEYS[lower] == true then
        return true
    end

    if lower:sub(1, 2) == "__" then
        return true
    end

    return false
end

function HolyDevUpdateFlattenData(
    snapshot,
    value,
    prefix,
    depth,
    seen
)

    depth =
        tonumber(depth)
        or 0

    seen =
        type(seen) == "table"
        and seen
        or {}

    if typeof(value) ~= "table" then

        return HolyDevUpdateAdd(
            snapshot,
            prefix,
            value
        )
    end

    if depth >= 12 then

        snapshot.Stats.DepthLimited +=
            1

        return false
    end

    if seen[value] == true then

        snapshot.Stats.CyclesIgnored +=
            1

        return false
    end

    seen[value] =
        true

    local captured =
        false

    local visibleKeys =
        0

    for _, key in ipairs(
        HolyDevUpdateSortedKeys(value)
    ) do

        if HolyDevUpdateIgnoreKey(key) == true then

            snapshot.Stats.RuntimeKeysIgnored +=
                1

        else

            visibleKeys +=
                1

            local child =
                value[key]

            local childPath =
                prefix
                .. "."
                .. tostring(key)

            if typeof(child) == "table" then

                if HolyDevUpdateFlattenData(
                    snapshot,
                    child,
                    childPath,
                    depth + 1,
                    seen
                ) == true then

                    captured =
                        true
                end

            elseif typeof(child) == "function"
            or typeof(child) == "thread" then

                snapshot.Stats.RuntimeValuesIgnored +=
                    1

            elseif HolyDevUpdateAdd(
                snapshot,
                childPath,
                child
            ) == true then

                captured =
                    true
            end
        end

        if snapshot.EntryLimitHit == true then
            break
        end
    end

    if visibleKeys <= 0 then

        captured =
            HolyDevUpdateAdd(
                snapshot,
                prefix .. ".Present",
                true
            )
            or captured
    end

    seen[value] =
        nil

    return captured
end

function HolyDevUpdateRelativePath(object, root, prefix)

    prefix =
        tostring(
            prefix
            or "Root"
        )

    if object == root then
        return prefix
    end

    local parts =
        {}

    local current =
        object

    while current
    and current ~= root do

        table.insert(
            parts,
            1,
            tostring(current.Name)
        )

        current =
            current.Parent
    end

    if current ~= root then

        return prefix
            .. "."
            .. tostring(object.Name)
    end

    if #parts <= 0 then
        return prefix
    end

    return prefix
        .. "."
        .. table.concat(
            parts,
            "."
        )
end

function HolyDevUpdateSortedDescendants(root, prefix)

    local objects =
        {}

    if typeof(root) ~= "Instance" then
        return objects
    end

    objects[1] =
        root

    for _, object in ipairs(
        root:GetDescendants()
    ) do

        objects[#objects + 1] =
            object
    end

    table.sort(objects, function(a, b)

        return HolyDevUpdateRelativePath(
            a,
            root,
            prefix
        ):lower()
            < HolyDevUpdateRelativePath(
                b,
                root,
                prefix
            ):lower()
    end)

    return objects
end

function HolyDevUpdateCaptureStructure(
    snapshot,
    root,
    prefix
)

    if typeof(root) ~= "Instance" then
        return false
    end

    for _, object in ipairs(
        HolyDevUpdateSortedDescendants(
            root,
            prefix
        )
    ) do

        local path =
            HolyDevUpdateRelativePath(
                object,
                root,
                prefix
            )

        HolyDevUpdateAdd(
            snapshot,
            "Structure."
                .. path
                .. ".Class",
            object.ClassName
        )

        local attributes =
            {}

        pcall(function()

            attributes =
                object:GetAttributes()
        end)

        for _, attributeName in ipairs(
            HolyDevUpdateSortedKeys(attributes)
        ) do

            HolyDevUpdateAdd(
                snapshot,
                "Structure."
                    .. path
                    .. ".Attribute."
                    .. tostring(attributeName),
                attributes[attributeName]
            )
        end

        if snapshot.EntryLimitHit == true then
            break
        end
    end

    return true
end

function HolyDevUpdateCaptureScripts(snapshot, roots)

    local reader =
        HolyDevUpdateBytecodeReader()

    snapshot.Capabilities.BytecodeHashing =
        type(reader) == "function"

    if type(reader) ~= "function" then

        HolyDevUpdateWarn(
            snapshot,
            "Bytecode hashing is unavailable; script additions and removals will still be detected."
        )
    end

    for _, rootRecord in ipairs(roots) do

        local root =
            rootRecord.Root

        local prefix =
            rootRecord.Prefix

        if typeof(root) == "Instance" then

            for _, object in ipairs(
                HolyDevUpdateSortedDescendants(
                    root,
                    prefix
                )
            ) do

                if object:IsA("LuaSourceContainer") then

                    local path =
                        HolyDevUpdateRelativePath(
                            object,
                            root,
                            prefix
                        )

                    HolyDevUpdateAdd(
                        snapshot,
                        "Scripts."
                            .. path
                            .. ".Class",
                        object.ClassName
                    )

                    if object:IsA("LocalScript")
                    or object:IsA("Script") then

                        HolyDevUpdateAdd(
                            snapshot,
                            "Scripts."
                                .. path
                                .. ".Disabled",
                            object.Disabled
                        )
                    end

                    if type(reader) == "function" then

                        snapshot.Stats.BytecodeAttempted +=
                            1

                        local success,
                            bytecode =
                            pcall(
                                reader,
                                object
                            )

                        if success == true
                        and type(bytecode) == "string"
                        and bytecode ~= "" then

                            snapshot.Stats.BytecodeHashed +=
                                1

                            HolyDevUpdateAdd(
                                snapshot,
                                "Scripts."
                                    .. path
                                    .. ".BytecodeHash",
                                HolyDevUpdateHashText(
                                    bytecode
                                )
                            )

                        else

                            snapshot.Stats.BytecodeFailed +=
                                1

                            if snapshot.Stats.BytecodeFailed <= 5 then

                                HolyDevUpdateWarn(
                                    snapshot,
                                    "Could not hash "
                                        .. path
                                        .. "."
                                )
                            end
                        end
                    end
                end

                if snapshot.EntryLimitHit == true then
                    break
                end
            end
        end
    end

    return true
end

function HolyDevUpdateCaptureNetworkSchema(
    snapshot,
    endpoint,
    path,
    schemaName
)

    local schema =
        rawget(
            endpoint,
            schemaName
        )

    if type(schema) ~= "table" then
        return false
    end

    local keys =
        HolyDevUpdateSortedKeys(
            schema
        )

    HolyDevUpdateAdd(
        snapshot,
        path
            .. "."
            .. schemaName
            .. ".Count",
        #keys
    )

    for index, key in ipairs(keys) do

        HolyDevUpdateAdd(
            snapshot,
            path
                .. "."
                .. schemaName
                .. "."
                .. tostring(index)
                .. ".Type",
            typeof(schema[key])
        )
    end

    return true
end

function HolyDevUpdateCaptureNetworkingTable(
    snapshot,
    value,
    path,
    depth,
    seen
)

    if type(value) ~= "table"
    or depth >= 12 then

        return false
    end

    if seen[value] == true then

        snapshot.Stats.CyclesIgnored +=
            1

        return false
    end

    seen[value] =
        true

    local endpointId =
        tonumber(
            rawget(
                value,
                "Id"
            )
        )

    local endpointName =
        rawget(
            value,
            "Name"
        )

    if endpointId ~= nil
    or type(endpointName) == "string" then

        HolyDevUpdateAdd(
            snapshot,
            path .. ".Present",
            true
        )

        if endpointId ~= nil then

            HolyDevUpdateAdd(
                snapshot,
                path .. ".Id",
                endpointId
            )
        end

        if type(endpointName) == "string" then

            HolyDevUpdateAdd(
                snapshot,
                path .. ".Name",
                endpointName
            )
        end

        local responseTimeout =
            rawget(
                value,
                "ResponseTimeout"
            )

        if tonumber(responseTimeout) ~= nil then

            HolyDevUpdateAdd(
                snapshot,
                path .. ".ResponseTimeout",
                tonumber(responseTimeout)
            )
        end

        for _, schemaName in ipairs({
            "Reads",
            "Writes",
            "ResponseReads",
            "ResponseWrites",
        }) do

            HolyDevUpdateCaptureNetworkSchema(
                snapshot,
                value,
                path,
                schemaName
            )
        end

        seen[value] =
            nil

        return true
    end

    HolyDevUpdateAdd(
        snapshot,
        path .. ".Present",
        true
    )

    for _, key in ipairs(
        HolyDevUpdateSortedKeys(value)
    ) do

        if HolyDevUpdateIgnoreKey(key) == true then

            snapshot.Stats.RuntimeKeysIgnored +=
                1

        else

            local child =
                value[key]

            if type(child) == "table" then

                HolyDevUpdateCaptureNetworkingTable(
                    snapshot,
                    child,
                    path
                        .. "."
                        .. tostring(key),
                    depth + 1,
                    seen
                )
            end
        end

        if snapshot.EntryLimitHit == true then
            break
        end
    end

    seen[value] =
        nil

    return true
end

function HolyDevUpdateCaptureNetworking(
    snapshot,
    sharedModules
)

    local networkingModule =
        sharedModules
        and sharedModules:FindFirstChild(
            "Networking"
        )

    if typeof(networkingModule) ~= "Instance"
    or networkingModule:IsA("ModuleScript") ~= true then

        HolyDevUpdateWarn(
            snapshot,
            "SharedModules.Networking was not found."
        )

        return false
    end

    local success,
        result =
        pcall(
            require,
            networkingModule
        )

    if success ~= true
    or type(result) ~= "table" then

        HolyDevUpdateWarn(
            snapshot,
            "Networking could not be inspected."
        )

        return false
    end

    return HolyDevUpdateCaptureNetworkingTable(
        snapshot,
        result,
        "Networking",
        0,
        {}
    )
end

function HolyDevUpdateDataModuleAllowed(module)

    if typeof(module) ~= "Instance"
    or module:IsA("ModuleScript") ~= true then

        return false
    end

    local lower =
        module.Name:lower()

    if lower == "networking" then
        return false
    end

    if HOLY_DEV_UPDATE_SAFE_DATA_MODULES[lower] == true then
        return true
    end

    local parentName =
        module.Parent
        and module.Parent.Name:lower()
        or ""

    if parentName == "flags"
    or parentName == "mutationdata" then

        return true
    end

    return false
end

function HolyDevUpdateRequireWithTimeout(module, timeout)

    local finished =
        false

    local success =
        false

    local result =
        nil

    local thread =
        task.spawn(function()

            success,
                result =
                pcall(
                    require,
                    module
                )

            finished =
                true
        end)

    local deadline =
        os.clock()
        + (
            tonumber(timeout)
            or 0.75
        )

    while finished ~= true
    and os.clock() < deadline do

        task.wait()
    end

    if finished ~= true then

        pcall(function()

            task.cancel(
                thread
            )
        end)

        return false,
            "timeout",
            true
    end

    return success,
        result,
        false
end

function HolyDevUpdateCaptureDataModules(
    snapshot,
    sharedModules
)

    if typeof(sharedModules) ~= "Instance" then
        return false
    end

    local modules =
        {}

    for _, object in ipairs(
        sharedModules:GetDescendants()
    ) do

        if HolyDevUpdateDataModuleAllowed(object) == true then

            modules[#modules + 1] =
                object
        end
    end

    table.sort(modules, function(a, b)

        return HolyDevUpdateRelativePath(
            a,
            sharedModules,
            "SharedModules"
        ):lower()
            < HolyDevUpdateRelativePath(
                b,
                sharedModules,
                "SharedModules"
            ):lower()
    end)

    for _, module in ipairs(modules) do

        local modulePath =
            HolyDevUpdateRelativePath(
                module,
                sharedModules,
                "SharedModules"
            )

        snapshot.Stats.DataModulesAttempted +=
            1

        local success,
            result,
            timedOut =
            HolyDevUpdateRequireWithTimeout(
                module,
                0.75
            )

        if success == true then

            snapshot.Stats.DataModulesCaptured +=
                1

            HolyDevUpdateAdd(
                snapshot,
                "Data."
                    .. modulePath
                    .. ".Present",
                true
            )

            HolyDevUpdateFlattenData(
                snapshot,
                result,
                "Data." .. modulePath,
                0,
                {}
            )

        else

            snapshot.Stats.DataModulesFailed +=
                1

            if timedOut == true then

                snapshot.Stats.DataModulesTimedOut +=
                    1
            end

            if snapshot.Stats.DataModulesFailed <= 8 then

                HolyDevUpdateWarn(
                    snapshot,
                    "Skipped "
                        .. modulePath
                        .. " ("
                        .. tostring(result)
                        .. ")."
                )
            end
        end

        if snapshot.EntryLimitHit == true then
            break
        end
    end

    return true
end

function HolyDevUpdateCaptureCatalogValues(
    snapshot,
    sharedModules
)

    if typeof(sharedModules) ~= "Instance" then
        return false
    end

    for _, object in ipairs(
        HolyDevUpdateSortedDescendants(
            sharedModules,
            "SharedModules"
        )
    ) do

        if object:IsA("ValueBase") then

            local path =
                HolyDevUpdateRelativePath(
                    object,
                    sharedModules,
                    "SharedModules"
                )

            HolyDevUpdateAdd(
                snapshot,
                "Catalogs."
                    .. path
                    .. ".Class",
                object.ClassName
            )

            pcall(function()

                HolyDevUpdateAdd(
                    snapshot,
                    "Catalogs."
                        .. path
                        .. ".Value",
                    object.Value
                )
            end)
        end

        if snapshot.EntryLimitHit == true then
            break
        end
    end

    return true
end

function HolyDevUpdateNewPass(scope)

    local placeVersion =
        nil

    pcall(function()

        placeVersion =
            game.PlaceVersion
    end)

    return {
        Schema =
            "HOLY_DEV_STABLE_UPDATE_SNAPSHOT_V2",

        SnapshotVersion =
            2,

        PlaceId =
            game.PlaceId,

        PlaceVersion =
            placeVersion,

        JobId =
            game.JobId,

        Scope =
            HolyDevUpdateScope(scope),

        CapturedAt =
            os.time(),

        Complete =
            true,

        EntryLimit =
            75000,

        EntryLimitHit =
            false,

        Values =
            {},

        Warnings =
            {},

        Capabilities = {
            BytecodeHashing = false,
        },

        Stats = {
            UnsupportedValues = 0,
            RuntimeKeysIgnored = 0,
            RuntimeValuesIgnored = 0,
            CyclesIgnored = 0,
            DepthLimited = 0,
            BytecodeAttempted = 0,
            BytecodeHashed = 0,
            BytecodeFailed = 0,
            DataModulesAttempted = 0,
            DataModulesCaptured = 0,
            DataModulesFailed = 0,
            DataModulesTimedOut = 0,
        },

        _EntryCount =
            0,

        _WarningMap =
            {},
    }
end

function HolyDevCaptureUpdatePass(scope)

    local snapshot =
        HolyDevUpdateNewPass(
            scope
        )

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local clientModules =
        ReplicatedStorage:FindFirstChild(
            "ClientModules"
        )

    local playerScripts =
        LocalPlayer
        and LocalPlayer:FindFirstChild(
            "PlayerScripts"
        )

    local playerGui =
        LocalPlayer
        and LocalPlayer:FindFirstChild(
            "PlayerGui"
        )

    local roots = {
        {
            Root = sharedModules,
            Prefix = "ReplicatedStorage.SharedModules",
        },
        {
            Root = clientModules,
            Prefix = "ReplicatedStorage.ClientModules",
        },
        {
            Root = playerScripts,
            Prefix = "PlayerScripts",
        },
        {
            Root = playerGui,
            Prefix = "PlayerGui",
        },
    }

    if HolyDevUpdateWants(
        scope,
        "Structure"
    ) then

        for _, rootRecord in ipairs(roots) do

            HolyDevUpdateCaptureStructure(
                snapshot,
                rootRecord.Root,
                rootRecord.Prefix
            )
        end
    end

    if HolyDevUpdateWants(
        scope,
        "Scripts & Controllers"
    ) then

        HolyDevUpdateCaptureScripts(
            snapshot,
            roots
        )
    end

    if HolyDevUpdateWants(
        scope,
        "Networking"
    ) then

        HolyDevUpdateCaptureNetworking(
            snapshot,
            sharedModules
        )
    end

    if HolyDevUpdateWants(
        scope,
        "Catalogs & Data"
    ) then

        HolyDevUpdateCaptureCatalogValues(
            snapshot,
            sharedModules
        )

        HolyDevUpdateCaptureDataModules(
            snapshot,
            sharedModules
        )
    end

    snapshot.ValueCount =
        snapshot._EntryCount

    snapshot._EntryCount =
        nil

    snapshot._WarningMap =
        nil

    return snapshot
end

function HolyDevUpdateCategory(path)

    path =
        tostring(
            path
            or ""
        )

    if path:sub(1, 8) == "Scripts." then
        return "Scripts"
    end

    if path:sub(1, 11) == "Networking." then
        return "Networking"
    end

    if path:sub(1, 9) == "Catalogs."
    or path:sub(1, 5) == "Data." then

        return "Catalogs & Data"
    end

    if path:sub(1, 10) == "Structure." then
        return "Structure"
    end

    return "Other"
end

function HolyDevUpdateCountCategories(values)

    local counts = {
        Scripts = 0,
        Networking = 0,
        ["Catalogs & Data"] = 0,
        Structure = 0,
        Other = 0,
    }

    for path in pairs(
        values
        or {}
    ) do

        local category =
            HolyDevUpdateCategory(path)

        counts[category] =
            (counts[category] or 0)
            + 1
    end

    return counts
end

function HolyDevStabilizeUpdatePasses(first, second)

    local stable = {
        Schema =
            "HOLY_DEV_STABLE_UPDATE_SNAPSHOT_V2",

        SnapshotVersion =
            2,

        PlaceId =
            second.PlaceId,

        PlaceVersion =
            second.PlaceVersion,

        Scope =
            second.Scope,

        CapturedAt =
            second.CapturedAt,

        FirstCapturedAt =
            first.CapturedAt,

        Complete =
            first.Complete == true
            and second.Complete == true,

        Values =
            {},

        Warnings =
            {},

        VolatileExamples =
            {},

        VolatileIgnored =
            0,

        Capabilities =
            second.Capabilities,

        PassStats = {
            First = first.Stats,
            Second = second.Stats,
        },
    }

    local warningMap =
        {}

    for _, source in ipairs({
        first.Warnings,
        second.Warnings,
    }) do

        for _, warning in ipairs(
            source
            or {}
        ) do

            if warningMap[warning] ~= true then

                warningMap[warning] =
                    true

                stable.Warnings[#stable.Warnings + 1] =
                    warning
            end
        end
    end

    local allPaths =
        {}

    for path in pairs(
        first.Values
        or {}
    ) do

        allPaths[path] =
            true
    end

    for path in pairs(
        second.Values
        or {}
    ) do

        allPaths[path] =
            true
    end

    local sortedPaths =
        HolyDevUpdateSortedKeys(
            allPaths
        )

    for _, path in ipairs(sortedPaths) do

        local beforeValue =
            first.Values[path]

        local afterValue =
            second.Values[path]

        if beforeValue ~= nil
        and afterValue ~= nil
        and beforeValue == afterValue then

            stable.Values[path] =
                afterValue

        else

            stable.VolatileIgnored +=
                1

            if #stable.VolatileExamples < 75 then

                stable.VolatileExamples[
                    #stable.VolatileExamples + 1
                ] = {
                    Path = path,
                    First = beforeValue,
                    Second = afterValue,
                }
            end
        end
    end

    stable.ValueCount =
        0

    for _ in pairs(stable.Values) do

        stable.ValueCount +=
            1
    end

    stable.CategoryCounts =
        HolyDevUpdateCountCategories(
            stable.Values
        )

    if stable.ValueCount <= 0 then

        stable.Complete =
            false

        stable.Warnings[#stable.Warnings + 1] =
            "No stable values were captured."
    end

    return stable
end

function HolyDevCaptureStableUpdateSnapshot(scope)

    scope =
        HolyDevUpdateScope(
            scope
        )

    HolyDevSetStatus(
        "UpdateStatusLabel",
        "Scanning "
            .. scope
            .. " · pass 1/2..."
    )

    local first =
        HolyDevCaptureUpdatePass(
            scope
        )

    task.wait(
        0.75
    )

    HolyDevSetStatus(
        "UpdateStatusLabel",
        "Scanning "
            .. scope
            .. " · pass 2/2..."
    )

    local second =
        HolyDevCaptureUpdatePass(
            scope
        )

    return HolyDevStabilizeUpdatePasses(
        first,
        second
    )
end

function HolyDevValidateUpdateSnapshot(snapshot)

    if type(snapshot) ~= "table" then
        return false,
            "snapshot is missing"
    end

    if snapshot.Schema
    ~= "HOLY_DEV_STABLE_UPDATE_SNAPSHOT_V2"
    or tonumber(snapshot.SnapshotVersion) ~= 2 then

        return false,
            "old or unsupported baseline format"
    end

    if tostring(snapshot.PlaceId)
    ~= tostring(game.PlaceId) then

        return false,
            "baseline belongs to another place"
    end

    if snapshot.Complete ~= true then
        return false,
            "snapshot is incomplete"
    end

    if type(snapshot.Values) ~= "table"
    or tonumber(snapshot.ValueCount) == nil
    or tonumber(snapshot.ValueCount) <= 0 then

        return false,
            "snapshot contains no stable values"
    end

    if snapshot.Values.__Truncated ~= nil
    or snapshot.Values.__CapturedEntries ~= nil
    or snapshot.Values.__TotalEntries ~= nil then

        return false,
            "snapshot was truncated"
    end

    return true
end

function HolyDevUpdateDiffCategoryCounts(diff)

    local output = {
        Scripts = {
            Added = 0,
            Removed = 0,
            Changed = 0,
        },
        Networking = {
            Added = 0,
            Removed = 0,
            Changed = 0,
        },
        ["Catalogs & Data"] = {
            Added = 0,
            Removed = 0,
            Changed = 0,
        },
        Structure = {
            Added = 0,
            Removed = 0,
            Changed = 0,
        },
        Other = {
            Added = 0,
            Removed = 0,
            Changed = 0,
        },
    }

    for _, operation in ipairs({
        "Added",
        "Removed",
        "Changed",
    }) do

        for _, row in ipairs(
            diff[operation]
            or {}
        ) do

            local category =
                HolyDevUpdateCategory(
                    row.Path
                )

            output[category][operation] +=
                1
        end
    end

    return output
end

function HolyDevUpdateSummaryValue(value)

    if value == nil then
        return "nil"
    end

    local text =
        tostring(value)

    if #text > 100 then

        text =
            text:sub(1, 97)
            .. "..."
    end

    return text
end

function HolyDevBuildUpdateSummary(report)

    local diff =
        report.Diff
        or {}

    local categoryCounts =
        report.CategoryCounts
        or {}

    local lines = {
        "HOLY GAME UPDATE REPORT V2",
        "PlaceId=" .. tostring(report.PlaceId or "?"),
        "BaselineVersion=" .. tostring(report.BaselinePlaceVersion or "?"),
        "CurrentVersion=" .. tostring(report.CurrentPlaceVersion or "?"),
        "Scope=" .. tostring(report.Scope or "Everything"),
        "CaptureStatus=" .. tostring(report.CaptureStatus or "Unknown"),
        "Confidence=" .. tostring(report.Confidence or "Unknown"),
        "StableValues=" .. tostring(report.StableValueCount or 0),
        "RuntimeNoiseIgnored=" .. tostring(report.VolatileIgnored or 0),
        "",
        "CHANGE TOTALS",
        "  Added=" .. tostring(diff.AddedCount or 0),
        "  Removed=" .. tostring(diff.RemovedCount or 0),
        "  Changed=" .. tostring(diff.ChangedCount or 0),
        "",
        "CATEGORY SUMMARY",
    }

    local categoryOrder = {
        "Scripts",
        "Networking",
        "Catalogs & Data",
        "Structure",
        "Other",
    }

    for _, category in ipairs(categoryOrder) do

        local counts =
            categoryCounts[category]
            or {}

        lines[#lines + 1] =
            "  "
            .. category
            .. ": +"
            .. tostring(counts.Added or 0)
            .. " -"
            .. tostring(counts.Removed or 0)
            .. " ~"
            .. tostring(counts.Changed or 0)
    end

    local totalChanges =
        (diff.AddedCount or 0)
        + (diff.RemovedCount or 0)
        + (diff.ChangedCount or 0)

    lines[#lines + 1] =
        ""

    if totalChanges <= 0 then

        lines[#lines + 1] =
            "MEANINGFUL CHANGES"

        lines[#lines + 1] =
            "  None found."

    else

        lines[#lines + 1] =
            "MEANINGFUL CHANGES"

        local included =
            0

        local maximum =
            60

        for _, category in ipairs(categoryOrder) do

            for _, operation in ipairs({
                "Changed",
                "Added",
                "Removed",
            }) do

                for _, row in ipairs(
                    diff[operation]
                    or {}
                ) do

                    if included >= maximum then
                        break
                    end

                    if HolyDevUpdateCategory(row.Path)
                    == category then

                        local line =
                            "  ["
                            .. operation:upper()
                            .. "]["
                            .. category
                            .. "] "
                            .. tostring(row.Path)

                        if operation == "Changed" then

                            line =
                                line
                                .. " | "
                                .. HolyDevUpdateSummaryValue(row.Before)
                                .. " -> "
                                .. HolyDevUpdateSummaryValue(row.After)

                        else

                            line =
                                line
                                .. " | "
                                .. HolyDevUpdateSummaryValue(row.Value)
                        end

                        lines[#lines + 1] =
                            line

                        included +=
                            1
                    end
                end
            end
        end

        if totalChanges > maximum then

            lines[#lines + 1] =
                "  ... "
                .. tostring(totalChanges - maximum)
                .. " more changes are available in Copy Full Report."
        end
    end

    if type(report.Warnings) == "table"
    and #report.Warnings > 0 then

        lines[#lines + 1] =
            ""

        lines[#lines + 1] =
            "WARNINGS"

        for index = 1, math.min(
            #report.Warnings,
            12
        ) do

            lines[#lines + 1] =
                "  "
                .. tostring(report.Warnings[index])
        end
    end

    return table.concat(
        lines,
        "\n"
    )
end

function HolyDevCopyUpdateSummary()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local summary =
        runtime.LastUpdateSummary

    if type(summary) ~= "string"
    or summary == "" then

        HolyNotify(
            "HOLY Dev",
            "Run Scan Current first.",
            4
        )

        return false
    end

    local copied =
        HolyCopyText(
            summary
        )

    if copied == true then

        HolyNotify(
            "HOLY Dev",
            "Update summary copied.",
            4
        )
    end

    return copied
end

function HolyDevCopyUpdateFull()

    local report =
        HOLY_DEV_SUITE_RUNTIME.LastUpdateDiff

    if type(report) ~= "table" then

        HolyNotify(
            "HOLY Dev",
            "Run Scan Current first.",
            4
        )

        return false
    end

    local encoded =
        HolyDevUpdateEncodeExact(
            report
        )

    if type(encoded) ~= "string" then

        HolyNotify(
            "HOLY Dev",
            "Could not encode the full report.",
            4
        )

        return false
    end

    local copied =
        HolyCopyText(
            encoded
        )

    if copied == true then

        HolyNotify(
            "HOLY Dev",
            "Full update report copied.",
            4
        )
    end

    return copied
end

function HolyDevSaveUpdateBaseline()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.UpdateScanning == true then

        HolyNotify(
            "HOLY Dev",
            "An update capture is already running.",
            4
        )

        return false
    end

    runtime.UpdateScanning =
        true

    local scope =
        HolyDevUpdateScope(
            HOLY_DEV_SUITE_STATE.UpdateScope
        )

    task.spawn(function()

        local success,
            result =
            xpcall(function()

                local snapshot =
                    HolyDevCaptureStableUpdateSnapshot(
                        scope
                    )

                local valid,
                    reason =
                    HolyDevValidateUpdateSnapshot(
                        snapshot
                    )

                if valid ~= true then
                    error(reason, 0)
                end

                if HolyDevUpdateWriteExact(
                    DEV_UPDATE_BASELINE_FILE,
                    snapshot
                ) ~= true then

                    error(
                        "could not write baseline",
                        0
                    )
                end

                HolyDevUpdateWriteExact(
                    HolyDevUpdateHistoryFile(
                        snapshot.PlaceVersion
                    ),
                    snapshot
                )

                runtime.PendingUpdateSnapshot =
                    nil

                runtime.LastUpdateDiff =
                    nil

                runtime.LastUpdateSummary =
                    nil

                if type(delfile) == "function" then

                    pcall(function()

                        if isfile(
                            DEV_UPDATE_PENDING_FILE
                        ) then

                            delfile(
                                DEV_UPDATE_PENDING_FILE
                            )
                        end
                    end)
                end

                HolyDevSetStatus(
                    "UpdateStatusLabel",
                    "Baseline ready · v"
                        .. tostring(snapshot.PlaceVersion or "?")
                        .. " · "
                        .. tostring(snapshot.ValueCount or 0)
                        .. " stable values"
                )

                HolyNotify(
                    "HOLY Dev",
                    "Stable V2 baseline saved.",
                    4
                )

                return true
            end, debug.traceback)

        runtime.UpdateScanning =
            false

        if success ~= true then

            HolyDevSetStatus(
                "UpdateStatusLabel",
                "Baseline failed · "
                    .. HolyCleanText(result)
            )

            HolyNotify(
                "HOLY Dev",
                "Baseline failed: "
                    .. HolyCleanText(result),
                6
            )
        end
    end)

    return true
end

function HolyDevScanUpdateChanges(copyResult)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.UpdateScanning == true then

        HolyNotify(
            "HOLY Dev",
            "An update capture is already running.",
            4
        )

        return false
    end

    local baseline =
        HolyDevReadJson(
            DEV_UPDATE_BASELINE_FILE
        )

    local baselineValid,
        baselineReason =
        HolyDevValidateUpdateSnapshot(
            baseline
        )

    if baselineValid ~= true then

        HolyDevSetStatus(
            "UpdateStatusLabel",
            "Capture a new V2 baseline · "
                .. tostring(baselineReason)
        )

        return false
    end

    runtime.UpdateScanning =
        true

    task.spawn(function()

        local success,
            result =
            xpcall(function()

                local current =
                    HolyDevCaptureStableUpdateSnapshot(
                        baseline.Scope
                    )

                local currentValid,
                    currentReason =
                    HolyDevValidateUpdateSnapshot(
                        current
                    )

                if currentValid ~= true then
                    error(currentReason, 0)
                end

                local diff =
                    HolyDevDiffMaps(
                        baseline.Values,
                        current.Values
                    )

                local categoryCounts =
                    HolyDevUpdateDiffCategoryCounts(
                        diff
                    )

                local warnings =
                    {}

                for _, warning in ipairs(
                    current.Warnings
                    or {}
                ) do

                    warnings[#warnings + 1] =
                        warning
                end

                if type(baseline.Capabilities) == "table"
                and type(current.Capabilities) == "table"
                and baseline.Capabilities.BytecodeHashing
                ~= current.Capabilities.BytecodeHashing then

                    warnings[#warnings + 1] =
                        "Bytecode capability changed since the baseline; script hash removals may be capability-related."
                end

                local confidence =
                    #warnings <= 0
                    and "High"
                    or "High with warnings"

                local report = {
                    Version =
                        "HOLY_DEV_UPDATE_DIFF_V2",

                    PlaceId =
                        game.PlaceId,

                    BaselinePlaceVersion =
                        baseline.PlaceVersion,

                    CurrentPlaceVersion =
                        current.PlaceVersion,

                    Scope =
                        current.Scope,

                    ScannedAt =
                        os.time(),

                    CaptureStatus =
                        "Complete",

                    Confidence =
                        confidence,

                    StableValueCount =
                        current.ValueCount,

                    VolatileIgnored =
                        current.VolatileIgnored,

                    VolatileExamples =
                        current.VolatileExamples,

                    CategoryCounts =
                        categoryCounts,

                    Warnings =
                        warnings,

                    Capabilities =
                        current.Capabilities,

                    Diff =
                        diff,
                }

                report.Summary =
                    HolyDevBuildUpdateSummary(
                        report
                    )

                runtime.PendingUpdateSnapshot =
                    current

                runtime.LastUpdateDiff =
                    report

                runtime.LastUpdateSummary =
                    report.Summary

                HolyDevUpdateWriteExact(
                    DEV_UPDATE_PENDING_FILE,
                    current
                )

                HolyDevSetStatus(
                    "UpdateStatusLabel",
                    "v"
                        .. tostring(baseline.PlaceVersion or "?")
                        .. " → v"
                        .. tostring(current.PlaceVersion or "?")
                        .. "  +"
                        .. tostring(diff.AddedCount)
                        .. " -"
                        .. tostring(diff.RemovedCount)
                        .. " ~"
                        .. tostring(diff.ChangedCount)
                        .. " · noise "
                        .. tostring(current.VolatileIgnored or 0)
                )

                if copyResult == true then

                    HolyCopyText(
                        report.Summary
                    )
                end

                HolyNotify(
                    "HOLY Dev",
                    "Stable update scan finished.",
                    4
                )

                return true
            end, debug.traceback)

        runtime.UpdateScanning =
            false

        if success ~= true then

            HolyDevSetStatus(
                "UpdateStatusLabel",
                "Scan failed · "
                    .. HolyCleanText(result)
            )

            HolyNotify(
                "HOLY Dev",
                "Update scan failed: "
                    .. HolyCleanText(result),
                6
            )
        end
    end)

    return true
end

function HolyDevAcceptCurrentUpdateBaseline()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.UpdateScanning == true then
        return false
    end

    local current =
        runtime.PendingUpdateSnapshot
        or HolyDevReadJson(
            DEV_UPDATE_PENDING_FILE
        )

    local valid,
        reason =
        HolyDevValidateUpdateSnapshot(
            current
        )

    if valid ~= true then

        HolyNotify(
            "HOLY Dev",
            "No valid pending scan: "
                .. tostring(reason),
            5
        )

        return false
    end

    local oldBaseline =
        HolyDevReadJson(
            DEV_UPDATE_BASELINE_FILE
        )

    if type(oldBaseline) == "table"
    and oldBaseline.PlaceVersion ~= nil then

        HolyDevUpdateWriteExact(
            HolyDevUpdateHistoryFile(
                oldBaseline.PlaceVersion
            ),
            oldBaseline
        )
    end

    if HolyDevUpdateWriteExact(
        DEV_UPDATE_BASELINE_FILE,
        current
    ) ~= true then

        HolyNotify(
            "HOLY Dev",
            "Could not promote the pending baseline.",
            5
        )

        return false
    end

    HolyDevUpdateWriteExact(
        HolyDevUpdateHistoryFile(
            current.PlaceVersion
        ),
        current
    )

    runtime.PendingUpdateSnapshot =
        nil

    HOLY_DEV_SUITE_STATE.UpdateScope =
        current.Scope

    if type(delfile) == "function" then

        pcall(function()

            if isfile(
                DEV_UPDATE_PENDING_FILE
            ) then

                delfile(
                    DEV_UPDATE_PENDING_FILE
                )
            end
        end)
    end

    HolyDevSetStatus(
        "UpdateStatusLabel",
        "Baseline accepted · v"
            .. tostring(current.PlaceVersion or "?")
    )

    HolyNotify(
        "HOLY Dev",
        "Current scan accepted as the new baseline.",
        4
    )

    return true
end

function HolyDevClearPendingUpdate()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.UpdateScanning == true then
        return false
    end

    runtime.PendingUpdateSnapshot =
        nil

    runtime.LastUpdateDiff =
        nil

    runtime.LastUpdateSummary =
        nil

    if type(delfile) == "function" then

        pcall(function()

            if isfile(
                DEV_UPDATE_PENDING_FILE
            ) then

                delfile(
                    DEV_UPDATE_PENDING_FILE
                )
            end
        end)
    end

    HolyDevAutoCheckUpdate()

    return true
end

function HolyDevStartPersistenceTest()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if type(runtime.PersistenceSession) == "table" then

        HolyNotify(
            "HOLY Dev",
            "A persistence test is already running.",
            4
        )

        return false
    end

    local target =
        tostring(
            HOLY_DEV_SUITE_STATE.PersistenceTarget
            or ""
        )

    local count,
        found =
        HolyDevGetToolCount(
            target
        )

    if target == ""
    or found ~= true then

        HolyNotify(
            "HOLY Dev",
            "Select an owned usable tool first.",
            5
        )

        return false
    end

    runtime.PersistenceSession = {
        Target = target,
        BeforeCount = count,
        StartedAt = os.time(),
        JobId = game.JobId,
    }

    HolyRollbackSetOwner(
        "Persistence",
        true
    )

    HolyDevSetStatus(
        "PersistenceStatusLabel",
        target
            .. ": "
            .. tostring(count)
            .. " • use it once"
    )

    HolyNotify(
        "HOLY Dev",
        "Test running. Use "
            .. target
            .. " once, then press Finish + Save.",
        7
    )

    return true
end

function HolyDevFinishPersistenceTest()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local session =
        runtime.PersistenceSession

    if type(session) ~= "table" then

        HolyNotify(
            "HOLY Dev",
            "Press Begin Test first.",
            4
        )

        return false
    end

    HolyRollbackSetOwner(
        "Persistence",
        false
    )

    task.wait(
        0.75
    )

    local afterCount,
        found =
        HolyDevGetToolCount(
            session.Target
        )

    local payload = {
        Version =
            "HOLY_DEV_PERSISTENCE_V1",

        Phase =
            "AwaitingRejoin",

        PlaceId =
            game.PlaceId,

        JobId =
            game.JobId,

        Player = {
            Name = LocalPlayer.Name,
            UserId = LocalPlayer.UserId,
        },

        Target =
            session.Target,

        BeforeCount =
            session.BeforeCount,

        AfterUseCount =
            found == true
            and afterCount
            or nil,

        StartedAt =
            session.StartedAt,

        SavedAt =
            os.time(),
    }

    local saved =
        HolyDevWriteJson(
            DEV_PERSISTENCE_FILE,
            payload
        )

    HolyDevCopyReport(
        payload
    )

    runtime.PersistenceSession =
        nil

    HolyDevSetStatus(
        "PersistenceStatusLabel",
        saved == true
        and "Saved • rejoin, then execute again."
        or "Could not save test state."
    )

    return saved
end

function HolyDevCheckPersistenceRejoin()

    local payload =
        HolyDevReadJson(
            DEV_PERSISTENCE_FILE
        )

    if type(payload) ~= "table"
    or payload.Phase ~= "AwaitingRejoin" then

        return false
    end

    if tostring(payload.JobId)
    == tostring(game.JobId) then

        HolyDevSetStatus(
            "PersistenceStatusLabel",
            "Saved • rejoin to complete."
        )

        return false
    end

    task.wait(
        3
    )

    local afterRejoin,
        found =
        HolyDevGetToolCount(
            payload.Target
        )

    local verdict =
        "INCONCLUSIVE"

    if found == true then

        if tonumber(afterRejoin)
        == tonumber(payload.AfterUseCount) then

            verdict =
                "PERSISTED"

        elseif tonumber(afterRejoin)
        == tonumber(payload.BeforeCount) then

            verdict =
                "ROLLED BACK"

        else

            verdict =
                "CHANGED"
        end
    end

    local finalReport = {
        Version =
            "HOLY_DEV_PERSISTENCE_V1",

        Phase =
            "Complete",

        PlaceId =
            game.PlaceId,

        PreviousJobId =
            payload.JobId,

        CurrentJobId =
            game.JobId,

        Target =
            payload.Target,

        BeforeCount =
            payload.BeforeCount,

        AfterUseCount =
            payload.AfterUseCount,

        AfterRejoinCount =
            found == true
            and afterRejoin
            or nil,

        Verdict =
            verdict,

        FinishedAt =
            os.time(),
    }

    HolyDevWriteJson(
        DEV_PERSISTENCE_FILE,
        finalReport
    )

    HolyDevCopyReport(
        finalReport
    )

    HOLY_DEV_SUITE_RUNTIME.LastPersistenceReport =
        finalReport

    HolyDevSetStatus(
        "PersistenceStatusLabel",
        tostring(payload.BeforeCount)
            .. " → "
            .. tostring(payload.AfterUseCount)
            .. " → "
            .. tostring(
                found == true
                and afterRejoin
                or "?"
            )
            .. " • "
            .. verdict
            .. " • copied"
    )

    HolyNotify(
        "HOLY Dev",
        payload.Target
            .. ": "
            .. verdict
            .. ". Report copied.",
        8
    )

    return true
end

function HolyDevRefreshModuleDropdown()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local values =
        {}

    local moduleMap =
        {}

    if sharedModules then

        for _, object in ipairs(
            sharedModules:GetDescendants()
        ) do

            if object:IsA("ModuleScript") then

                local fullName =
                    HolyDevGetFullName(object)

                local display =
                    fullName:gsub(
                        "^ReplicatedStorage%.SharedModules%.",
                        ""
                    )

                values[#values + 1] =
                    display

                moduleMap[display] =
                    object
            end
        end
    end

    table.sort(values, function(a, b)

        return a:lower()
            < b:lower()
    end)

    if #values == 0 then

        values[1] =
            "No modules found"
    end

    runtime.ModuleMap =
        moduleMap

    local selected =
        tostring(
            HOLY_DEV_SUITE_STATE.DataModule
            or ""
        )

    if moduleMap[selected] == nil then

        selected =
            moduleMap["ItemCatalog"]
            and "ItemCatalog"
            or values[1]

        HOLY_DEV_SUITE_STATE.DataModule =
            selected
    end

    local dropdown =
        runtime.UI.DataDropdown

    if type(dropdown) == "table" then

        pcall(function()

            if type(dropdown.SetValues) == "function" then

                dropdown:SetValues(
                    values
                )
            end

            if type(dropdown.SetValue) == "function" then

                dropdown:SetValue(
                    selected
                )
            end
        end)
    end

    return true
end

function HolyDevInspectSelectedModule()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local selected =
        tostring(
            HOLY_DEV_SUITE_STATE.DataModule
            or ""
        )

    local module =
        runtime.ModuleMap
        and runtime.ModuleMap[selected]

    if typeof(module) ~= "Instance"
    or module:IsA("ModuleScript") ~= true then

        HolyDevSetStatus(
            "DataStatusLabel",
            "Select a module first."
        )

        return false
    end

    local success,
        result =
        pcall(
            require,
            module
        )

    local report = {
        Version =
            "HOLY_DEV_DATA_INSPECTOR_V1",

        Module =
            selected,

        FullName =
            HolyDevGetFullName(module),

        Success =
            success,

        CapturedAt =
            os.time(),

        Data =
            success == true
            and HolyDevSafeValue(result)
            or nil,

        Error =
            success ~= true
            and tostring(result)
            or nil,
    }

    runtime.LastDataReport =
        report

    HolyDevCopyReport(
        report
    )

    HolyDevSetStatus(
        "DataStatusLabel",
        success == true
        and selected
            .. " copied."
        or selected
            .. " require failed."
    )

    return success == true
end

function HolyDevRefreshErrorStatus()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local uniqueCount =
        #runtime.ErrorOrder

    local totalCount =
        0

    local latest =
        nil

    for _, key in ipairs(
        runtime.ErrorOrder
    ) do

        local row =
            runtime.Errors[key]

        if row then

            totalCount +=
                tonumber(row.Count)
                or 0

            latest =
                row
        end
    end

    local text =
        "Capturing • 0 errors"

    if totalCount > 0 then

        text =
            tostring(totalCount)
            .. " errors • "
            .. tostring(uniqueCount)
            .. " unique"

        if latest then

            local preview =
                tostring(
                    latest.Message
                    or ""
                )

            if #preview > 42 then

                preview =
                    preview:sub(1, 42)
                    .. "..."
            end

            text =
                text
                .. " • "
                .. preview
        end
    end

    HolyDevSetStatus(
        "ErrorStatusLabel",
        text
    )
end

function HolyDevStartErrorMonitor()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.ErrorConnection then
        return true
    end

    local ScriptContext =
        game:GetService(
            "ScriptContext"
        )

    local success,
        connection =
        pcall(function()

            return ScriptContext.Error:Connect(function(
                message,
                stackTrace,
                source
            )

                local key =
                    tostring(message)
                    .. "\n"
                    .. tostring(stackTrace)

                local row =
                    runtime.Errors[key]

                if row == nil then

                    row = {
                        Message = tostring(message),
                        StackTrace = tostring(stackTrace),
                        Source = HolyDevSafeValue(source),
                        Count = 0,
                        FirstAt = os.time(),
                    }

                    runtime.Errors[key] =
                        row

                    runtime.ErrorOrder[
                        #runtime.ErrorOrder + 1
                    ] =
                        key
                end

                row.Count +=
                    1

                row.LastAt =
                    os.time()

                if type(HolyDevTrace)
                == "function" then

                    pcall(
                        HolyDevTrace,
                        "Errors",
                        "ScriptError",
                        {
                            Message =
                                tostring(message),

                            StackTrace =
                                tostring(stackTrace),

                            Source =
                                HolyDevSafeValue(
                                    source
                                ),
                        },
                        "Error"
                    )
                end

                HolyDevRefreshErrorStatus()
            end)
        end)

    if success == true then

        runtime.ErrorConnection =
            connection

        HolyDevRefreshErrorStatus()

        return true
    end

    HolyDevSetStatus(
        "ErrorStatusLabel",
        "Error capture unavailable."
    )

    return false
end

function HolyDevCopyErrors()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local rows =
        {}

    for _, key in ipairs(
        runtime.ErrorOrder
    ) do

        if runtime.Errors[key] then

            rows[#rows + 1] =
                runtime.Errors[key]
        end
    end

    return HolyDevCopyReport({
        Version = "HOLY_DEV_ERRORS_V1",
        PlaceId = game.PlaceId,
        JobId = game.JobId,
        CapturedAt = os.time(),
        Errors = rows,
    })
end

function HolyDevClearErrors()

    HOLY_DEV_SUITE_RUNTIME.Errors =
        {}

    HOLY_DEV_SUITE_RUNTIME.ErrorOrder =
        {}

    HolyDevRefreshErrorStatus()

    return true
end

function HolyDevPacketLimit(value)

    return math.clamp(
        math.floor(
            tonumber(value)
            or 300
        ),
        10,
        10000
    )
end

function HolyDevPacketDirection(value)

    value =
        tostring(
            value
            or "Both"
        )

    if value == "Sent"
    or value == "Received" then

        return value
    end

    return "Both"
end

function HolyDevPacketId(packet)

    for _, key in ipairs({
        "PacketId",
        "PacketID",
        "Id",
        "ID",
        "id",
    }) do

        local ok,
            value =
            pcall(function()

                return packet[key]
            end)

        value =
            ok == true
            and tonumber(value)
            or nil

        if value
        and value >= 0
        and value <= 65535
        and value % 1 == 0 then

            return value
        end
    end

    return nil
end

function HolyDevPacketSafeValue(value)

    return HolyDevSafeValue(
        value,
        0,
        {},
        {
            MaxDepth = 8,
            MaxMapEntries = 500,
            MaxArrayEntries = 2000,
            MaxStringLength = 2000,
        }
    )
end

function HolyDevPacketArguments(...)

    local packed =
        table.pack(...)

    local output =
        {}

    for index = 1, packed.n do

        output[index] =
            HolyDevPacketSafeValue(
                packed[index]
            )
    end

    return output
end

function HolyDevPacketMatches(direction, entry)

    local wantedDirection =
        HolyDevPacketDirection(
            HOLY_DEV_SUITE_STATE.PacketDirection
        )

    if wantedDirection ~= "Both"
    and wantedDirection ~= direction then

        return false
    end

    local filter =
        tostring(
            HOLY_DEV_SUITE_STATE.PacketFilter
            or ""
        ):lower()

    if filter == "" then
        return true
    end

    local searchable =
        (
            tostring(
                entry.Path
                or ""
            )
            .. " "
            .. tostring(
                entry.PacketId
                or ""
            )
        ):lower()

    return searchable:find(
        filter,
        1,
        true
    ) ~= nil
end

function HolyDevPacketRefreshStatus(force)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local now =
        os.clock()

    if force ~= true
    and now - (
        runtime.PacketStatusClock
        or 0
    ) < 0.15 then

        return
    end

    runtime.PacketStatusClock =
        now

    local count =
        #(
            runtime.PacketEvents
            or {}
        )

    local limit =
        HolyDevPacketLimit(
            HOLY_DEV_SUITE_STATE.PacketMaxEvents
        )

    local text =
        runtime.PacketActive == true
        and "Capturing"
        or "Ready"

    text =
        text
        .. " · "
        .. tostring(count)
        .. "/"
        .. tostring(limit)

    if (
        runtime.PacketSkipped
        or 0
    ) > 0 then

        text =
            text
            .. " · "
            .. tostring(
                runtime.PacketSkipped
            )
            .. " skipped"
    end

    if tostring(
        runtime.PacketLastName
        or ""
    ) ~= "" then

        text =
            text
            .. " · "
            .. tostring(
                runtime.PacketLastName
            )
    end

    HolyDevSetStatus(
        "PacketStatusLabel",
        text
    )
end

function HolyDevPacketRecord(direction, entry, ...)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.PacketActive ~= true then
        return
    end

    runtime.PacketObserved[direction] =
        (
            runtime.PacketObserved[direction]
            or 0
        )
        + 1

    if type(HolyDevRecorderRecordPacket)
        == "function" then

        pcall(
            HolyDevRecorderRecordPacket,
            direction,
            entry,
            ...
        )
    end

    if HolyDevPacketMatches(
        direction,
        entry
    ) ~= true then

        runtime.PacketFiltered +=
            1

        return
    end

    runtime.PacketCounts[direction] =
        (
            runtime.PacketCounts[direction]
            or 0
        )
        + 1

    runtime.PacketLastName =
        entry.Path

    local limit =
        HolyDevPacketLimit(
            HOLY_DEV_SUITE_STATE.PacketMaxEvents
        )

    if #runtime.PacketEvents >= limit then

        runtime.PacketSkipped +=
            1

        HolyDevPacketRefreshStatus(
            false
        )

        return
    end

    runtime.PacketEvents[
        #runtime.PacketEvents + 1
    ] = {
        Index =
            #runtime.PacketEvents + 1,

        Time =
            os.clock()
            - runtime.PacketStartedClock,

        Direction =
            direction,

        Packet =
            entry.Path,

        PacketId =
            entry.PacketId,

        Arguments =
            HolyDevPacketArguments(...),
    }

    HolyDevPacketRefreshStatus(
        false
    )
end

function HolyDevPacketCleanup()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    for _, connection in ipairs(
        runtime.PacketConnections
        or {}
    ) do

        pcall(function()

            connection:Disconnect()
        end)
    end

    runtime.PacketConnections =
        {}

    for index = #(
        runtime.PacketWrappers
        or {}
    ), 1, -1 do

        local row =
            runtime.PacketWrappers[index]

        pcall(function()

            if row.Packet[row.Method]
            == row.Wrapper then

                row.Packet[row.Method] =
                    row.Original
            end
        end)
    end

    runtime.PacketWrappers =
        {}
end

function HolyDevPacketNetworking()

    if type(HolyShopRequireModule)
    == "function" then

        local result =
            HolyShopRequireModule(
                "SharedModules.Networking"
            )

        if type(result) == "table" then
            return result
        end
    end

    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local module =
        sharedModules
        and sharedModules:FindFirstChild(
            "Networking"
        )

    if typeof(module) ~= "Instance"
    or module:IsA("ModuleScript") ~= true then

        return nil
    end

    local ok,
        result =
        pcall(
            require,
            module
        )

    if ok == true
    and type(result) == "table" then

        return result
    end

    return nil
end

function HolyDevPacketStart()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.PacketActive == true then

        HolyNotify(
            "HOLY Dev",
            "Packet capture is already running.",
            3
        )

        return false
    end

    HolyDevPacketCleanup()

    local networking =
        HolyDevPacketNetworking()

    if type(networking) ~= "table" then

        HolyDevSetStatus(
            "PacketStatusLabel",
            "Networking module unavailable."
        )

        HolyNotify(
            "HOLY Dev",
            "Networking module unavailable.",
            5
        )

        return false
    end

    HOLY_DEV_SUITE_STATE.PacketMaxEvents =
        HolyDevPacketLimit(
            HOLY_DEV_SUITE_STATE.PacketMaxEvents
        )

    runtime.PacketActive =
        true

    runtime.PacketStartedAt =
        os.time()

    runtime.PacketStartedClock =
        os.clock()

    runtime.PacketEvents =
        {}

    runtime.PacketConnections =
        {}

    runtime.PacketWrappers =
        {}

    runtime.PacketRegistry =
        {}

    runtime.PacketCounts = {
        Sent = 0,
        Received = 0,
    }

    runtime.PacketObserved = {
        Sent = 0,
        Received = 0,
    }

    runtime.PacketFiltered =
        0

    runtime.PacketSkipped =
        0

    runtime.PacketLastName =
        ""

    runtime.PacketStatusClock =
        0

    local direction =
        HolyDevPacketDirection(
            HOLY_DEV_SUITE_STATE.PacketDirection
        )

    local seen =
        {}

    local packetSeen =
        {}

    local nodes =
        0

    local coverage = {
        PacketTables = 0,
        SentHooks = 0,
        ReceivedHooks = 0,
        FailedSentHooks = 0,
        FailedReceivedHooks = 0,
        NodesScanned = 0,
        Truncated = false,
    }

    local function installSent(entry, methodName)

        local packet =
            entry.Packet

        local original =
            packet[methodName]

        if type(original) ~= "function" then
            return false
        end

        local wrapper

        wrapper =
            function(self, ...)

                HolyDevPacketRecord(
                    "Sent",
                    entry,
                    ...
                )

                return original(
                    self,
                    ...
                )
            end

        local ok =
            pcall(function()

                packet[methodName] =
                    wrapper
            end)

        if ok ~= true
        or packet[methodName] ~= wrapper then

            return false
        end

        runtime.PacketWrappers[
            #runtime.PacketWrappers + 1
        ] = {
            Packet = packet,
            Method = methodName,
            Original = original,
            Wrapper = wrapper,
        }

        entry.SentMethods[
            #entry.SentMethods + 1
        ] =
            methodName

        return true
    end

    local function installReceived(entry)

        local signal

        pcall(function()

            signal =
                entry.Packet.OnClientEvent
        end)

        if signal == nil then
            return false
        end

        local ok,
            connection =
            pcall(function()

                return signal:Connect(function(...)

                    HolyDevPacketRecord(
                        "Received",
                        entry,
                        ...
                    )
                end)
            end)

        if ok ~= true
        or connection == nil then

            return false
        end

        runtime.PacketConnections[
            #runtime.PacketConnections + 1
        ] =
            connection

        entry.Received =
            true

        return true
    end

    local function scan(node, path, depth)

        if type(node) ~= "table"
        or seen[node] == true
        or depth > 12 then

            return
        end

        if nodes >= 30000 then

            coverage.Truncated =
                true

            return
        end

        seen[node] =
            true

        nodes +=
            1

        local hasSent =
            type(node.Fire) == "function"
            or type(node.Invoke) == "function"

        local hasReceived =
            false

        pcall(function()

            hasReceived =
                node.OnClientEvent ~= nil
        end)

        if hasSent == true
        or hasReceived == true then

            if packetSeen[node] ~= true then

                packetSeen[node] =
                    true

                local entry = {
                    Packet = node,

                    Path =
                        path ~= ""
                        and path
                        or "<root>",

                    PacketId =
                        HolyDevPacketId(node),

                    SentMethods = {},
                    Received = false,
                }

                runtime.PacketRegistry[
                    #runtime.PacketRegistry + 1
                ] =
                    entry

                coverage.PacketTables +=
                    1

                if direction == "Both"
                or direction == "Sent" then

                    for _, methodName in ipairs({
                        "Fire",
                        "Invoke",
                    }) do

                        if type(node[methodName])
                        == "function" then

                            if installSent(
                                entry,
                                methodName
                            ) then

                                coverage.SentHooks +=
                                    1

                            else

                                coverage.FailedSentHooks +=
                                    1
                            end
                        end
                    end
                end

                if hasReceived == true
                and (
                    direction == "Both"
                    or direction == "Received"
                ) then

                    if installReceived(entry) then

                        coverage.ReceivedHooks +=
                            1

                    else

                        coverage.FailedReceivedHooks +=
                            1
                    end
                end
            end

            return
        end

        local children =
            {}

        pcall(function()

            for key, child in pairs(node) do

                if type(child) == "table" then

                    children[
                        #children + 1
                    ] = {
                        Key = key,
                        Value = child,
                    }
                end
            end
        end)

        table.sort(
            children,
            function(left, right)

                return tostring(left.Key)
                    < tostring(right.Key)
            end
        )

        for _, child in ipairs(children) do

            local childPath =
                path == ""
                and tostring(child.Key)
                or path
                    .. "."
                    .. tostring(child.Key)

            scan(
                child.Value,
                childPath,
                depth + 1
            )
        end
    end

    scan(
        networking,
        "",
        0
    )

    coverage.NodesScanned =
        nodes

    runtime.PacketCoverage =
        coverage

    if coverage.PacketTables <= 0 then

        runtime.PacketActive =
            false

        HolyDevPacketCleanup()

        HolyDevSetStatus(
            "PacketStatusLabel",
            "No packet tables found."
        )

        HolyNotify(
            "HOLY Dev",
            "No packet tables were found.",
            5
        )

        return false
    end

    HolyDevPacketRefreshStatus(
        true
    )

    HolyNotify(
        "HOLY Dev",
        "Packet capture started.",
        3
    )

    return true
end

function HolyDevPacketBuildReport(reason)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    local registry =
        {}

    local placeVersion

    pcall(function()

        placeVersion =
            game.PlaceVersion
    end)

    for _, entry in ipairs(
        runtime.PacketRegistry
        or {}
    ) do

        registry[
            #registry + 1
        ] = {
            Path = entry.Path,
            PacketId = entry.PacketId,
            SentMethods = entry.SentMethods,
            Received = entry.Received,
        }
    end

    return {
        Version =
            "HOLY_PACKET_WATCHER_V1",

        PlaceId =
            game.PlaceId,

        PlaceVersion =
            placeVersion,

        JobId =
            game.JobId,

        StartedAt =
            runtime.PacketStartedAt,

        FinishedAt =
            os.time(),

        Runtime =
            os.clock()
            - (
                runtime.PacketStartedClock
                or os.clock()
            ),

        FinishReason =
            tostring(
                reason
                or "manual stop"
            ),

        Config = {
            Direction =
                HolyDevPacketDirection(
                    HOLY_DEV_SUITE_STATE.PacketDirection
                ),

            Filter =
                tostring(
                    HOLY_DEV_SUITE_STATE.PacketFilter
                    or ""
                ),

            MaxEvents =
                HolyDevPacketLimit(
                    HOLY_DEV_SUITE_STATE.PacketMaxEvents
                ),
        },

        Counts =
            runtime.PacketCounts,

        ObservedCounts =
            runtime.PacketObserved,

        FilteredEvents =
            runtime.PacketFiltered,

        StoredEvents =
            #runtime.PacketEvents,

        SkippedAtLimit =
            runtime.PacketSkipped,

        Coverage =
            runtime.PacketCoverage,

        Registry =
            registry,

        Events =
            runtime.PacketEvents,

        Safety = {
            Passive = true,
            PacketsFiredByWatcher = 0,
        },
    }
end

function HolyDevPacketStop(copyResult, reason)

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    if runtime.PacketActive ~= true then

        HolyNotify(
            "HOLY Dev",
            "Packet capture is not running.",
            3
        )

        return false
    end

    runtime.PacketActive =
        false

    local report =
        HolyDevPacketBuildReport(
            reason
        )

    HolyDevPacketCleanup()

    runtime.LastPacketReport =
        report

    local saved =
        HolyDevWriteJson(
            DEV_PACKET_WATCHER_FILE,
            report
        )

    local copied =
        copyResult == true
        and HolyDevCopyReport(
            report
        )
        or false

    local status =
        "Stopped · "
        .. tostring(
            report.StoredEvents
        )
        .. " events"

    if report.SkippedAtLimit > 0 then

        status =
            status
            .. " · "
            .. tostring(
                report.SkippedAtLimit
            )
            .. " skipped"
    end

    if copied == true then

        status =
            status
            .. " · copied"
    end

    if saved == true then

        status =
            status
            .. " · saved"
    end

    HolyDevSetStatus(
        "PacketStatusLabel",
        status
    )

    HolyNotify(
        "HOLY Dev",
        status,
        5
    )

    return true
end

function HolyDevPacketCopyLast()

    local report =
        HOLY_DEV_SUITE_RUNTIME.LastPacketReport
        or HolyDevReadJson(
            DEV_PACKET_WATCHER_FILE
        )

    if type(report) ~= "table" then

        HolyNotify(
            "HOLY Dev",
            "No packet report is available yet.",
            4
        )

        return false
    end

    local copied =
        HolyDevCopyReport(
            report
        )

    if copied == true then

        HolyNotify(
            "HOLY Dev",
            "Packet report copied.",
            4
        )
    end

    return copied
end

function HolyDevPacketClear()

    local runtime =
        HOLY_DEV_SUITE_RUNTIME

    runtime.PacketEvents =
        {}

    runtime.PacketCounts = {
        Sent = 0,
        Received = 0,
    }

    runtime.PacketObserved = {
        Sent = 0,
        Received = 0,
    }

    runtime.PacketFiltered =
        0

    runtime.PacketSkipped =
        0

    runtime.PacketLastName =
        ""

    runtime.LastPacketReport =
        nil

    if runtime.PacketActive == true then

        runtime.PacketStartedAt =
            os.time()

        runtime.PacketStartedClock =
            os.clock()
    end

    if HolyCanUseFiles() == true
    and type(delfile) == "function" then

        pcall(function()

            if isfile(
                DEV_PACKET_WATCHER_FILE
            ) then

                delfile(
                    DEV_PACKET_WATCHER_FILE
                )
            end
        end)
    end

    HolyDevPacketRefreshStatus(
        true
    )

    return true
end

function HolyDevAutoCheckUpdate()

    local baseline =
        HolyDevReadJson(
            DEV_UPDATE_BASELINE_FILE
        )

    local valid,
        reason =
        HolyDevValidateUpdateSnapshot(
            baseline
        )

    if valid ~= true then

        HolyDevSetStatus(
            "UpdateStatusLabel",
            "Capture a V2 baseline · "
                .. tostring(reason)
        )

        return false
    end

    local currentVersion =
        nil

    pcall(function()

        currentVersion =
            game.PlaceVersion
    end)

    if tostring(currentVersion)
    ~= tostring(baseline.PlaceVersion) then

        HolyDevSetStatus(
            "UpdateStatusLabel",
            "Update found · v"
                .. tostring(baseline.PlaceVersion or "?")
                .. " → v"
                .. tostring(currentVersion or "?")
                .. " · press Scan Current"
        )

        return true
    end

    HolyDevSetStatus(
        "UpdateStatusLabel",
        "Baseline ready · v"
            .. tostring(currentVersion or "?")
            .. " · "
            .. tostring(baseline.ValueCount or 0)
            .. " stable values"
    )

    return true
end

HOLY_DEV_SUITE_RUNTIME.Stop =
    function(reason)

        local runtime =
            HOLY_DEV_SUITE_RUNTIME

        runtime.RecorderActive =
            false

        runtime.RecorderTriggerGeneration =
            (
                runtime.RecorderTriggerGeneration
                or 0
            )
            + 1

        if type(HolyDevRecorderCleanupSources)
        == "function" then

            pcall(
                HolyDevRecorderCleanupSources
            )
        end

        runtime.Active =
            false

        runtime.RefreshGeneration +=
            1

        if runtime.ErrorConnection then

            pcall(function()

                runtime.ErrorConnection:Disconnect()
            end)

            runtime.ErrorConnection =
                nil
        end

        runtime.PacketActive =
            false

        HolyDevPacketCleanup()

        if type(HolyRollbackSetOwner) == "function" then

            pcall(function()

                HolyRollbackSetOwner(
                    "Persistence",
                    false
                )
            end)
        end

        return true
    end

