local HOLY_MOON_PREDICTOR_SETTINGS_FILE =
    UI_SETTINGS_FOLDER
    .. "/HolyPremiumMoonPredictorSettings.json"

function HolyMoonEscape(value)

    return tostring(value or "")
        :gsub("&", "&amp;")
        :gsub("<", "&lt;")
        :gsub(">", "&gt;")
end

function HolyMoonKey(value)

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-]", "")
end

function HolyMoonDisplayName(value)

    local text =
        HolyCleanText(
            value
        )

    local key =
        HolyMoonKey(
            text
        )

    if key == "goldmoon" then
        return "Gold Moon"
    end

    if key == "bloodmoon" then
        return "Blood Moon"
    end

    if key == "megamoon" then
        return "Mega Moon"
    end

    return text ~= ""
        and text
        or "Unknown Moon"
end

function HolyMoonReadAmount(value)

    local number =
        tonumber(
            tostring(value or "")
                :match("%d+")
        )
        or 30

    return math.clamp(
        math.floor(number),
        1,
        500
    )
end

function HolyMoonReadHudScale(value)

    local number =
        tonumber(
            tostring(value or "")
                :match("%d+")
        )
        or 80

    number =
        math.floor(
            number / 10
            + 0.5
        )
        * 10

    return math.clamp(
        number,
        10,
        120
    )
end

function HolyMoonFormatHudScale(value)

    return tostring(
        HolyMoonReadHudScale(
            value
        )
    )
        .. "%"
end

function HolyMoonGetNow()

    local ok,
        value =
        pcall(function()

            return workspace:GetServerTimeNow()
        end)

    if ok == true
    and tonumber(value) then

        return math.floor(
            tonumber(value)
        )
    end

    return os.time()
end

function HolyMoonFormatSeconds(seconds)

    seconds =
        math.max(
            0,
            math.floor(
                tonumber(seconds)
                or 0
            )
        )

    local days =
        math.floor(
            seconds / 86400
        )

    local hours =
        math.floor(
            (seconds % 86400) / 3600
        )

    local minutes =
        math.floor(
            (seconds % 3600) / 60
        )

    local remain =
        seconds % 60

    if days > 0 then

        return tostring(days)
            .. "d "
            .. tostring(hours)
            .. "h "
            .. tostring(minutes)
            .. "m"
    end

    if hours > 0 then

        return tostring(hours)
            .. "h "
            .. tostring(minutes)
            .. "m"
    end

    if minutes > 0 then

        return tostring(minutes)
            .. "m "
            .. tostring(remain)
            .. "s"
    end

    return tostring(remain)
        .. "s"
end

function HolyMoonColor(value, weatherData)

    local key =
        HolyMoonKey(
            value
        )

    if key == "moon"
    or key == "day" then

        return Color3.fromRGB(
            147,
            197,
            253
        )
    end

    if key == "sunset" then

        return Color3.fromRGB(
            251,
            191,
            36
        )
    end

    if key == "goldmoon" then

        return Color3.fromRGB(
            250,
            204,
            21
        )
    end

    if key == "rainbowmoon" then

        return Color3.fromRGB(
            255,
            64,
            255
        )
    end

    if key == "bloodmoon" then

        return Color3.fromRGB(
            248,
            64,
            64
        )
    end

    if key == "megamoon" then

        return Color3.fromRGB(
            196,
            181,
            253
        )
    end

    local moduleColor =
        type(weatherData) == "table"
        and weatherData.Color
        or nil

    if typeof(moduleColor) == "Color3" then
        return moduleColor
    end

    return Color3.fromRGB(
        196,
        181,
        253
    )
end

function HolyMoonRichColor(color)

    color =
        typeof(color) == "Color3"
        and color
        or Color3.fromRGB(
            196,
            181,
            253
        )

    return string.format(
        "rgb(%d,%d,%d)",
        math.floor(color.R * 255 + 0.5),
        math.floor(color.G * 255 + 0.5),
        math.floor(color.B * 255 + 0.5)
    )
end

function HolyMoonSaveSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local selected =
        {}

    for rawName, enabled in pairs(
        HOLY_MOON_PREDICTOR_STATE.SelectedMoons
    ) do

        if enabled == true then

            table.insert(
                selected,
                tostring(rawName)
            )
        end
    end

    table.sort(selected, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    local payload = {
        Amount =
            HolyMoonReadAmount(
                HOLY_MOON_PREDICTOR_STATE.Amount
            ),

        HudEnabled =
            HOLY_MOON_PREDICTOR_STATE.HudEnabled == true,

        HudScale =
            HolyMoonReadHudScale(
                HOLY_MOON_PREDICTOR_STATE.HudScale
            ),

        HudPosition =
            type(HOLY_MOON_PREDICTOR_STATE.HudPosition) == "table"
            and {
                X =
                    tonumber(
                        HOLY_MOON_PREDICTOR_STATE.HudPosition.X
                    ),

                Y =
                    tonumber(
                        HOLY_MOON_PREDICTOR_STATE.HudPosition.Y
                    ),
            }
            or nil,

        SelectedMoons =
            selected,
    }

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                payload
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then

        return false
    end

    return pcall(function()

        writefile(
            HOLY_MOON_PREDICTOR_SETTINGS_FILE,
            encoded
        )
    end)
end

function HolyMoonLoadSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                HOLY_MOON_PREDICTOR_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                HOLY_MOON_PREDICTOR_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then

        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return false
    end

    HOLY_MOON_PREDICTOR_STATE.Amount =
        HolyMoonReadAmount(
            data.Amount
        )

    HOLY_MOON_PREDICTOR_STATE.HudEnabled =
        data.HudEnabled == true

    HOLY_MOON_PREDICTOR_STATE.HudScale =
        HolyMoonReadHudScale(
            data.HudScale
        )

    if type(data.HudPosition) == "table" then

        local x =
            tonumber(
                data.HudPosition.X
                or data.HudPosition.x
                or data.HudPosition[1]
            )

        local y =
            tonumber(
                data.HudPosition.Y
                or data.HudPosition.y
                or data.HudPosition[2]
            )

        if x ~= nil
        and y ~= nil then

            HOLY_MOON_PREDICTOR_STATE.HudPosition = {
                X =
                    math.floor(x + 0.5),

                Y =
                    math.floor(y + 0.5),
            }
        end
    end

    if type(data.SelectedMoons) == "table" then

        HOLY_MOON_PREDICTOR_STATE.HasSavedSelection =
            true

        HOLY_MOON_PREDICTOR_STATE.SelectedMoons =
            {}

        for _, rawName in ipairs(
            HolyShopSelectionArray(
                data.SelectedMoons
            )
        ) do

            HOLY_MOON_PREDICTOR_STATE.SelectedMoons[
                tostring(rawName)
            ] =
                true
        end
    end

    return true
end

