local function HolyMailAccountFileExists(
    filePath
)
    if type(filePath) ~= "string"
        or filePath == ""
        or type(isfile) ~= "function"
    then
        return false
    end

    local success,
        exists =
        pcall(
            isfile,
            filePath
        )

    return success == true
        and exists == true
end

local function HolyMailReadJsonFile(
    filePath
)
    if not HolyMailAccountFileExists(
        filePath
    ) then
        return nil,
            nil
    end

    local readOk,
        raw =
        pcall(
            readfile,
            filePath
        )

    if readOk ~= true
        or type(raw) ~= "string"
        or raw == ""
    then
        return nil,
            nil
    end

    local decodeOk,
        decoded =
        pcall(function()
            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
        or type(decoded) ~= "table"
    then
        return nil,
            raw
    end

    return decoded,
        raw
end

local function HolyMailWriteJsonFile(
    filePath,
    data
)
    if HolyCanUseFiles() ~= true
        or type(filePath) ~= "string"
        or type(data) ~= "table"
    then
        return false
    end

    HolyEnsureFolder()

    local encodeOk,
        encoded =
        pcall(function()
            return HttpService:JSONEncode(
                data
            )
        end)

    if encodeOk ~= true
        or type(encoded) ~= "string"
    then
        return false
    end

    local writeOk =
        pcall(
            writefile,
            filePath,
            encoded
        )

    return writeOk == true
end

local function HolyMailCopyLegacyFile(
    legacyPath,
    accountPath
)
    if HolyMailAccountFileExists(
        accountPath
    ) then
        return true
    end

    local decoded,
        raw =
        HolyMailReadJsonFile(
            legacyPath
        )

    if type(decoded) ~= "table"
        or type(raw) ~= "string"
        or raw == ""
    then
        return false
    end

    local writeOk =
        pcall(
            writefile,
            accountPath,
            raw
        )

    return writeOk == true
end

local function HolyMailPrepareAccountFiles()
    if HolyCanUseFiles() ~= true
        or HOLY_MAIL_ACCOUNT_USER_ID <= 0
    then
        return false
    end

    HolyEnsureFolder()

    local migration =
        HolyMailReadJsonFile(
            HOLY_MAIL_MIGRATION_FILE
        )

    if type(migration) ~= "table" then
        migration = {
            Version = 1,
        }
    end

    local migrationOwner =
        math.floor(
            tonumber(
                migration.OwnerUserId
            )
            or 0
        )

    if migrationOwner <= 0 then
        migrationOwner =
            HOLY_MAIL_ACCOUNT_USER_ID

        migration.OwnerUserId =
            HOLY_MAIL_ACCOUNT_USER_ID

        migration.OwnerName =
            tostring(
                LocalPlayer.Name
            )

        migration.ClaimedAt =
            os.time()

        if not HolyMailWriteJsonFile(
            HOLY_MAIL_MIGRATION_FILE,
            migration
        ) then
            return false
        end
    end

    if migrationOwner
        ~= HOLY_MAIL_ACCOUNT_USER_ID
    then
        return true
    end

    local settingsReady =
        HolyMailAccountFileExists(
            HOLY_MAIL_SETTINGS_FILE
        )

    if not settingsReady then
        settingsReady =
            HolyMailCopyLegacyFile(
                HOLY_MAIL_LEGACY_SETTINGS_FILE,
                HOLY_MAIL_SETTINGS_FILE
            )
    end

    local historyReady =
        HolyMailAccountFileExists(
            HOLY_MAIL_HISTORY_FILE
        )

    if not historyReady then
        historyReady =
            HolyMailCopyLegacyFile(
                HOLY_MAIL_LEGACY_HISTORY_FILE,
                HOLY_MAIL_HISTORY_FILE
            )
    end

    migration.Version =
        1

    migration.OwnerUserId =
        HOLY_MAIL_ACCOUNT_USER_ID

    migration.OwnerName =
        tostring(
            LocalPlayer.Name
        )

    migration.SettingsMigrated =
        settingsReady == true

    migration.HistoryMigrated =
        historyReady == true

    migration.LastCheckedAt =
        os.time()

    HolyMailWriteJsonFile(
        HOLY_MAIL_MIGRATION_FILE,
        migration
    )

    return true
end

