function HolyMailHistoryNormalizeIcon(value)
    if type(value) == "number" then
        if value <= 0 then
            return ""
        end

        return "rbxassetid://"
            .. tostring(
                math.floor(value)
            )
    end

    if type(value) ~= "string" then
        return ""
    end

    local result =
        value:gsub("^%s+", "")
            :gsub("%s+$", "")

    if result == "" then
        return ""
    end

    if result:match("^%d+$") then
        return "rbxassetid://"
            .. result
    end

    return result
end

function HolyMailHistorySave()
    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local encodeOk, encoded =
        pcall(function()
            return HttpService:JSONEncode(
                HOLY_MAIL_HISTORY
            )
        end)

    if encodeOk ~= true
        or type(encoded) ~= "string"
    then
        return false
    end

    return pcall(function()
        writefile(
            HOLY_MAIL_HISTORY_FILE,
            encoded
        )
    end)
end

function HolyMailHistoryLoad()
    HOLY_MAIL_HISTORY = {
        Version = 2,

        UserId =
            HOLY_MAIL_ACCOUNT_USER_ID,

        Username =
            tostring(
                LocalPlayer.Name
            ),

        Records = {},
    }

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists = false

    pcall(function()
        exists =
            isfile(
                HOLY_MAIL_HISTORY_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk, raw =
        pcall(function()
            return readfile(
                HOLY_MAIL_HISTORY_FILE
            )
        end)

    if readOk ~= true
        or type(raw) ~= "string"
        or raw == ""
    then
        return false
    end

    local decodeOk, decoded =
        pcall(function()
            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
        or type(decoded) ~= "table"
        or type(decoded.Records) ~= "table"
    then
        return false
    end

    local storedUserId =
        math.floor(
            tonumber(
                decoded.UserId
            )
            or 0
        )

    if storedUserId > 0
        and storedUserId
            ~= HOLY_MAIL_ACCOUNT_USER_ID
    then
        return false
    end

    HOLY_MAIL_HISTORY.Version =
        2

    HOLY_MAIL_HISTORY.UserId =
        HOLY_MAIL_ACCOUNT_USER_ID

    HOLY_MAIL_HISTORY.Username =
        tostring(
            LocalPlayer.Name
        )

    for _, record in ipairs(
        decoded.Records
    ) do
        if type(record) == "table" then
            table.insert(
                HOLY_MAIL_HISTORY.Records,
                record
            )

            if #HOLY_MAIL_HISTORY.Records
                >= HOLY_MAIL_HISTORY_LIMIT
            then
                break
            end
        end
    end

    return true
end

function HolyMailHistoryAdd(record)
    if type(record) ~= "table" then
        return false
    end

    record.Id =
        tostring(
            record.Id
                or (
                    tostring(os.time())
                    .. "-"
                    .. tostring(
                        math.floor(
                            os.clock() * 1000
                        )
                    )
                    .. "-"
                    .. tostring(
                        math.random(
                            1000,
                            9999
                        )
                    )
                )
        )

    record.Timestamp =
        math.floor(
            tonumber(record.Timestamp)
                or os.time()
        )

    record.Items =
        type(record.Items) == "table"
            and record.Items
            or {}

    record.AccountUserId =
        HOLY_MAIL_ACCOUNT_USER_ID

    record.AccountUsername =
        tostring(
            LocalPlayer.Name
        )

    HOLY_MAIL_HISTORY.Version =
        2

    HOLY_MAIL_HISTORY.UserId =
        HOLY_MAIL_ACCOUNT_USER_ID

    HOLY_MAIL_HISTORY.Username =
        tostring(
            LocalPlayer.Name
        )

    table.insert(
        HOLY_MAIL_HISTORY.Records,
        1,
        record
    )

    while #HOLY_MAIL_HISTORY.Records
        > HOLY_MAIL_HISTORY_LIMIT
    do
        table.remove(
            HOLY_MAIL_HISTORY.Records
        )
    end

    HolyMailHistorySave()

    if type(
        HOLY_MAIL_RUNTIME.RefreshHistory
    ) == "function" then
        pcall(
            HOLY_MAIL_RUNTIME.RefreshHistory
        )
    end

    return true
end

function HolyMailHistoryClear()
    HOLY_MAIL_HISTORY.Records =
        {}

    HOLY_MAIL_RUNTIME.ExpandedHistory =
        {}

    HolyMailHistorySave()

    if type(
        HOLY_MAIL_RUNTIME.RefreshHistory
    ) == "function" then
        pcall(
            HOLY_MAIL_RUNTIME.RefreshHistory
        )
    end

    return true
end

function HolyMailHistoryRecordClaim(mail)
    if type(mail) ~= "table"
        or type(mail.Data) ~= "table"
    then
        return false
    end

    local data =
        mail.Data

    local items = {}
    local itemCount = 0
    local knownValue = 0

    for itemKey, itemData in pairs(
        type(data.Items) == "table"
            and data.Items
            or {}
    ) do
        local item =
            type(itemData) == "table"
                and itemData
                or {}

        local count =
            math.max(
                1,
                math.floor(
                    tonumber(
                        item.Count
                            or item.Amount
                            or item.Quantity
                            or (
                                type(itemData) == "number"
                                    and itemData
                                    or 1
                            )
                    )
                    or 1
                )
            )

        local name =
            tostring(
                item.ItemName
                    or item.DisplayName
                    or item.Name
                    or item.FruitName
                    or itemKey
                    or "Unknown item"
            )

        local details =
            tostring(
                item.Mutation
                    or item.Variant
                    or item.Category
                    or item.ItemType
                    or "Mail item"
            )

        local icon =
            HolyMailHistoryNormalizeIcon(
                item.IMG
                    or item.Icon
                    or item.Image
                    or item.ImageId
                    or item.TextureId
            )

        local value =
            math.max(
                0,
                tonumber(
                    item.Value
                        or item.SellValue
                        or item.Price
                )
                or 0
            )

        itemCount +=
            count

        knownValue +=
            value * count

        table.insert(
            items,
            {
                Name = name,
                Details = details,
                Icon = icon,
                Count = count,
                Sent = count,
                Value = value * count,
            }
        )
    end

    local senderId =
        tonumber(
            data.SenderUserId
                or data.FromUserId
                or data.SenderId
                or data.UserId
        )
        or 0

    local senderName =
        tostring(
            data.SenderName
                or data.FromName
                or data.Username
                or (
                    senderId > 0
                        and (
                            "User "
                            .. tostring(senderId)
                        )
                        or "Unknown sender"
                )
        )

    return HolyMailHistoryAdd({
        Direction = "Received",
        Mode = "Inbox",
        Status = "Received",

        OtherUserId = senderId,
        OtherName = senderName,

        AttemptedMails = 1,
        AcceptedMails = 1,

        PlannedItems = itemCount,
        SentItems = itemCount,

        TargetValue = knownValue,
        AcceptedValue = knownValue,

        Items = items,

        Timestamp =
            tonumber(data.SentAt)
                or os.time(),
    })
end

