function HolyMailToday()
    return os.date("!%Y-%m-%d")
end

function HolyMailNormalizeScale(value)
    local cleanedValue =
        tostring(
            value or "90%"
        ):gsub(
            "%%",
            ""
        )

    local scale =
        tonumber(cleanedValue)
        or 90

    scale =
        math.clamp(
            math.floor(
                scale + 0.5
            ),
            80,
            110
        )

    return tostring(scale) .. "%",
        scale / 100
end

function HolyMailNormalizeInboxInterval(value)
    local seconds =
        tonumber(
            tostring(
                value or "2 seconds"
            ):match("%d+")
        )
        or 2

    local allowed = {
        [1] = true,
        [2] = true,
        [5] = true,
        [10] = true,
    }

    seconds =
        math.floor(
            seconds
        )

    if allowed[seconds] ~= true then
        seconds =
            2
    end

    local formatted =
        tostring(seconds)
        .. (
            seconds == 1
                and " second"
                or " seconds"
        )

    return formatted,
        seconds
end

function HolyMailNormalizeValueStrategy(
    value
)
    value =
        tostring(
            value
            or "Send at least"
        )

    local allowed = {
        ["Send at least"] = true,
        ["Closest amount"] = true,
        ["Don't go over"] = true,
    }

    if allowed[value] ~= true then
        value =
            "Send at least"
    end

    return value
end

function HolyMailNormalizeExtraLimitMode(
    value
)
    value =
        tostring(
            value
            or "5%"
        )

    local allowed = {
        ["No limit"] = true,
        ["1%"] = true,
        ["5%"] = true,
        ["10%"] = true,
        ["Custom"] = true,
    }

    if allowed[value] ~= true then
        value =
            "5%"
    end

    return value
end

function HolyMailNormalizeExtraLimitCustom(
    value
)
    value =
        tostring(
            value
            or "5%"
        )
            :gsub(
                "[%c]+",
                ""
            )
            :gsub(
                "^%s+",
                ""
            )
            :gsub(
                "%s+$",
                ""
            )

    if value == "" then
        value =
            "5%"
    end

    if #value > 24 then
        value =
            value:sub(
                1,
                24
            )
    end

    return value
end

function HolyMailFilterKey(
    value
)
    return tostring(
        value or ""
    )
        :gsub(
            "[%c]+",
            ""
        )
        :gsub(
            "^%s+",
            ""
        )
        :gsub(
            "%s+$",
            ""
        )
        :lower()
end

function HolyMailNormalizeFilterSelection(
    value
)
    local output = {}
    local seen = {}

    if type(value) ~= "table" then
        return output
    end

    for key, stored in pairs(
        value
    ) do
        local candidate

        if type(key) == "number" then
            candidate =
                stored
        elseif stored == true then
            candidate =
                key
        elseif type(stored) == "string" then
            candidate =
                stored
        end

        if candidate ~= nil then
            local display =
                tostring(
                    candidate
                )
                    :gsub(
                        "[%c]+",
                        ""
                    )
                    :gsub(
                        "^%s+",
                        ""
                    )
                    :gsub(
                        "%s+$",
                        ""
                    )

            local normalized =
                HolyMailFilterKey(
                    display
                )

            if normalized ~= ""
                and not seen[normalized]
            then
                seen[normalized] =
                    true

                table.insert(
                    output,
                    display:sub(
                        1,
                        80
                    )
                )

                if #output >= 250 then
                    break
                end
            end
        end
    end

    table.sort(
        output,
        function(left, right)
            return tostring(
                left
            ):lower()
                < tostring(
                    right
                ):lower()
        end
    )

    return output
end

function HolyMailFilterSelectionMap(
    value
)
    local output = {}

    for _, display in ipairs(
        HolyMailNormalizeFilterSelection(
            value
        )
    ) do
        local key =
            HolyMailFilterKey(
                display
            )

        if key ~= "" then
            output[key] =
                display
        end
    end

    return output
end

function HolyMailRecipientText(
    value,
    maximumLength
)
    local result =
        tostring(
            value or ""
        )
            :gsub(
                "[%c]+",
                ""
            )
            :gsub(
                "^%s+",
                ""
            )
            :gsub(
                "%s+$",
                ""
            )

    maximumLength =
        math.max(
            1,
            math.floor(
                tonumber(
                    maximumLength
                )
                or 40
            )
        )

    return result:sub(
        1,
        maximumLength
    )
end

function HolyMailNormalizeRecipientRecords(
    value,
    maximum,
    saved
)
    local output = {}
    local seen = {}

    maximum =
        math.clamp(
            math.floor(
                tonumber(maximum)
                    or 25
            ),
            1,
            50
        )

    if type(value) ~= "table" then
        return output
    end

    for _, record in pairs(
        value
    ) do
        if type(record) == "table" then
            local userId =
                math.floor(
                    tonumber(
                        record.UserId
                            or record.Id
                    )
                    or 0
                )

            local username =
                HolyMailRecipientText(
                    record.Name
                        or record.Username,
                    32
                )

            if userId > 0
                and userId
                    ~= HOLY_MAIL_ACCOUNT_USER_ID
                and username ~= ""
                and not seen[userId]
            then
                seen[userId] =
                    true

                local lastUsedAt =
                    math.max(
                        0,
                        math.floor(
                            tonumber(
                                record.LastUsedAt
                            )
                            or 0
                        )
                    )

                local addedAt =
                    math.max(
                        0,
                        math.floor(
                            tonumber(
                                record.AddedAt
                            )
                            or lastUsedAt
                        )
                    )

                table.insert(
                    output,
                    {
                        UserId =
                            userId,

                        Name =
                            username,

                        Label =
                            saved == true
                            and HolyMailRecipientText(
                                record.Label
                                    or username,
                                36
                            )
                            or nil,

                        Favorite =
                            saved == true
                            and record.Favorite == true
                            or false,

                        LastUsedAt =
                            lastUsedAt,

                        AddedAt =
                            addedAt,
                    }
                )

                if #output >= maximum then
                    break
                end
            end
        end
    end

    table.sort(
        output,
        function(left, right)
            if saved == true
                and left.Favorite
                    ~= right.Favorite
            then
                return left.Favorite == true
            end

            if left.LastUsedAt
                ~= right.LastUsedAt
            then
                return left.LastUsedAt
                    > right.LastUsedAt
            end

            return tostring(
                left.Label
                    or left.Name
            ):lower()
                < tostring(
                    right.Label
                        or right.Name
                ):lower()
        end
    )

    return output
end

function HolyMailNormalizeFleetGroupName(
    value
)
    local groupName =
        HolyMailRecipientText(
            value,
            24
        )

    if groupName == ""
        or groupName:lower() == "all"
    then
        return "Ungrouped"
    end

    return groupName
end

function HolyMailNormalizeFleetGroups(
    value
)
    local output = {
        "Ungrouped",
    }

    local seen = {
        ungrouped = true,
    }

    if type(value) ~= "table" then
        return output
    end

    for _, rawGroup in pairs(
        value
    ) do
        local groupName =
            HolyMailNormalizeFleetGroupName(
                rawGroup
            )

        local key =
            groupName:lower()

        if not seen[key]
            and #output < 20
        then
            seen[key] =
                true

            table.insert(
                output,
                groupName
            )
        end
    end

    return output
end

function HolyMailNormalizeFleetAccounts(
    value
)
    local output = {}
    local seen = {}
    local sequence = 0

    if type(value) ~= "table" then
        return output
    end

    for _, record in pairs(
        value
    ) do
        if type(record) == "table" then
            sequence +=
                1

            local userId =
                math.floor(
                    tonumber(
                        record.UserId
                            or record.Id
                    )
                    or 0
                )

            local username =
                HolyMailRecipientText(
                    record.Name
                        or record.Username,
                    32
                )

            if userId > 0
                and userId
                    ~= HOLY_MAIL_ACCOUNT_USER_ID
                and username ~= ""
                and not seen[userId]
            then
                seen[userId] =
                    true

                local addedAt =
                    math.max(
                        0,
                        math.floor(
                            tonumber(
                                record.AddedAt
                            )
                            or os.time()
                        )
                    )

                table.insert(
                    output,
                    {
                        UserId =
                            userId,

                        Name =
                            username,

                        Label =
                            HolyMailRecipientText(
                                record.Label
                                    or username,
                                36
                            ),

                        Group =
                            HolyMailNormalizeFleetGroupName(
                                record.Group
                            ),

                        Enabled =
                            record.Enabled
                                ~= false,

                        Priority =
                            math.max(
                                1,
                                math.floor(
                                    tonumber(
                                        record.Priority
                                    )
                                    or sequence
                                )
                            ),

                        AddedAt =
                            addedAt,
                    }
                )

                if #output >= 100 then
                    break
                end
            end
        end
    end

    table.sort(
        output,
        function(left, right)
            if left.Priority
                ~= right.Priority
            then
                return left.Priority
                    < right.Priority
            end

            if left.AddedAt
                ~= right.AddedAt
            then
                return left.AddedAt
                    < right.AddedAt
            end

            return left.Name:lower()
                < right.Name:lower()
        end
    )

    for index, record in ipairs(
        output
    ) do
        record.Priority =
            index
    end

    return output
end

function HolyMailResolveRecipient(
    value
)
    local raw =
        HolyMailRecipientText(
            value,
            80
        ):gsub(
            "^@",
            ""
        )

    if raw == "" then
        return nil,
            nil,
            "Enter a username or User ID."
    end

    local userId
    local username

    local numeric =
        tonumber(raw)

    if numeric then
        numeric =
            math.floor(
                numeric
            )

        local ok,
            result =
            pcall(
                Players.GetNameFromUserIdAsync,
                Players,
                numeric
            )

        if ok
            and type(result) == "string"
        then
            userId =
                numeric

            username =
                result
        end
    else
        local ok,
            result =
            pcall(
                Players.GetUserIdFromNameAsync,
                Players,
                raw
            )

        if ok then
            userId =
                math.floor(
                    tonumber(result)
                        or 0
                )

            local nameOk,
                currentName =
                pcall(
                    Players.GetNameFromUserIdAsync,
                    Players,
                    userId
                )

            username =
                nameOk
                and currentName
                or raw
        end
    end

    if not userId
        or userId <= 0
        or type(username) ~= "string"
        or username == ""
    then
        return nil,
            nil,
            "Recipient not found."
    end

    if userId
        == HOLY_MAIL_ACCOUNT_USER_ID
    then
        return nil,
            nil,
            "You cannot save your own account."
    end

    return userId,
        username,
        nil
end

function HolyMailTouchRecipient(
    userId,
    username
)
    userId =
        math.floor(
            tonumber(userId)
                or 0
        )

    username =
        HolyMailRecipientText(
            username,
            32
        )

    if userId <= 0
        or userId
            == HOLY_MAIL_ACCOUNT_USER_ID
        or username == ""
    then
        return false
    end

    local usedAt =
        os.time()

    local saved =
        HolyMailNormalizeRecipientRecords(
            HOLY_MAIL_STATE.SavedRecipients,
            25,
            true
        )

    for _, record in ipairs(
        saved
    ) do
        if record.UserId == userId then
            record.Name =
                username

            record.LastUsedAt =
                usedAt

            break
        end
    end

    local recent = {
        {
            UserId =
                userId,

            Name =
                username,

            LastUsedAt =
                usedAt,

            AddedAt =
                usedAt,
        },
    }

    for _, record in ipairs(
        HolyMailNormalizeRecipientRecords(
            HOLY_MAIL_STATE.RecentRecipients,
            8,
            false
        )
    ) do
        if record.UserId ~= userId then
            table.insert(
                recent,
                record
            )
        end
    end

    HOLY_MAIL_STATE.SavedRecipients =
        HolyMailNormalizeRecipientRecords(
            saved,
            25,
            true
        )

    HOLY_MAIL_STATE.RecentRecipients =
        HolyMailNormalizeRecipientRecords(
            recent,
            8,
            false
        )

    HolyMailSaveSettings()

    return true
end

function HolyMailSetHudScale(value)
    local formattedScale =
        HolyMailNormalizeScale(value)

    HOLY_MAIL_STATE.HudScale =
        formattedScale

    if type(HOLY_MAIL_RUNTIME.ApplyScale) == "function" then

        pcall(
            HOLY_MAIL_RUNTIME.ApplyScale
        )
    end

    HolyMailSaveSettings()

    return formattedScale
end

function HolyMailCheckDay()
    local today =
        HolyMailToday()

    if tostring(HOLY_MAIL_STATE.TrackerDay or "") ~= today then
        HOLY_MAIL_STATE.TrackerDay =
            today

        HOLY_MAIL_STATE.TrackerUsed =
            0

        return true
    end

    HOLY_MAIL_STATE.TrackerUsed =
        math.clamp(
            math.floor(
                tonumber(HOLY_MAIL_STATE.TrackerUsed)
                    or 0
            ),
            0,
            HOLY_MAIL_DAILY_LIMIT
        )

    return false
end

function HolyMailSaveSettings()
    HolyMailCheckDay()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local position =
        type(HOLY_MAIL_STATE.HudPosition) == "table"
            and {
                XScale =
                    tonumber(
                        HOLY_MAIL_STATE.HudPosition.XScale
                    ) or 0.5,

                XOffset =
                    tonumber(
                        HOLY_MAIL_STATE.HudPosition.XOffset
                    ) or 0,

                YScale =
                    tonumber(
                        HOLY_MAIL_STATE.HudPosition.YScale
                    ) or 0.5,

                YOffset =
                    tonumber(
                        HOLY_MAIL_STATE.HudPosition.YOffset
                    ) or 0,
            }
            or nil

    local payload = {
        Version =
            2,

        UserId =
            HOLY_MAIL_ACCOUNT_USER_ID,

        Username =
            tostring(
                LocalPlayer.Name
            ),

        HudEnabled =
            HOLY_MAIL_STATE.HudEnabled == true,

        StartMinimized =
            HOLY_MAIL_STATE.StartMinimized == true,

        HudScale =
            HolyMailNormalizeScale(
                HOLY_MAIL_STATE.HudScale
                or "100%"
            ),

        AutoClaim =
            HOLY_MAIL_STATE.AutoClaim == true,

        InboxInterval =
            HolyMailNormalizeInboxInterval(
                HOLY_MAIL_STATE.InboxInterval
                or "2 seconds"
            ),

        ValueStrategy =
            HolyMailNormalizeValueStrategy(
                HOLY_MAIL_STATE.ValueStrategy
            ),

        ExtraLimitMode =
            HolyMailNormalizeExtraLimitMode(
                HOLY_MAIL_STATE.ExtraLimitMode
            ),

        ExtraLimitCustom =
            HolyMailNormalizeExtraLimitCustom(
                HOLY_MAIL_STATE.ExtraLimitCustom
            ),

        FilterFruits =
            HolyMailNormalizeFilterSelection(
                HOLY_MAIL_STATE.FilterFruits
            ),

        FilterMutations =
            HolyMailNormalizeFilterSelection(
                HOLY_MAIL_STATE.FilterMutations
            ),

        SavedRecipients =
            HolyMailNormalizeRecipientRecords(
                HOLY_MAIL_STATE.SavedRecipients,
                25,
                true
            ),

        RecentRecipients =
            HolyMailNormalizeRecipientRecords(
                HOLY_MAIL_STATE.RecentRecipients,
                8,
                false
            ),

        FleetAccounts =
            HolyMailNormalizeFleetAccounts(
                HOLY_MAIL_STATE.FleetAccounts
            ),

        FleetGroups =
            HolyMailNormalizeFleetGroups(
                HOLY_MAIL_STATE.FleetGroups
            ),

        HudPosition =
            position,

        TrackerDay =
            tostring(HOLY_MAIL_STATE.TrackerDay),

        TrackerUsed =
            math.clamp(
                math.floor(
                    tonumber(HOLY_MAIL_STATE.TrackerUsed)
                        or 0
                ),
                0,
                HOLY_MAIL_DAILY_LIMIT
            ),
    }

    local encodeOk, encoded =
        pcall(function()
            return HttpService:JSONEncode(payload)
        end)

    if encodeOk ~= true
        or type(encoded) ~= "string"
    then
        return false
    end

    return pcall(function()
        writefile(
            HOLY_MAIL_SETTINGS_FILE,
            encoded
        )
    end)
end

function HolyMailLoadSettings()
    if HolyCanUseFiles() ~= true then
        HolyMailCheckDay()

        return false
    end

    local exists =
        false

    pcall(function()
        exists =
            isfile(HOLY_MAIL_SETTINGS_FILE)
    end)

    if exists ~= true then
        HolyMailCheckDay()

        return false
    end

    local readOk, raw =
        pcall(function()
            return readfile(
                HOLY_MAIL_SETTINGS_FILE
            )
        end)

    if readOk ~= true
        or type(raw) ~= "string"
        or raw == ""
    then
        HolyMailCheckDay()

        return false
    end

    local decodeOk, data =
        pcall(function()
            return HttpService:JSONDecode(raw)
        end)

    if decodeOk ~= true
        or type(data) ~= "table"
    then
        HolyMailCheckDay()

        return false
    end

    local storedUserId =
        math.floor(
            tonumber(
                data.UserId
            )
            or 0
        )

    if storedUserId > 0
        and storedUserId
            ~= HOLY_MAIL_ACCOUNT_USER_ID
    then
        HolyMailCheckDay()

        return false
    end

    HOLY_MAIL_STATE.HudEnabled =
        data.HudEnabled == true

    HOLY_MAIL_STATE.StartMinimized =
        data.StartMinimized == true

    HOLY_MAIL_STATE.HudScale =
        HolyMailNormalizeScale(
            data.HudScale
            or HOLY_MAIL_STATE.HudScale
            or "100%"
        )

    HOLY_MAIL_STATE.AutoClaim =
        data.AutoClaim == true

    HOLY_MAIL_STATE.InboxInterval =
        HolyMailNormalizeInboxInterval(
            data.InboxInterval
            or HOLY_MAIL_STATE.InboxInterval
            or "2 seconds"
        )

    HOLY_MAIL_STATE.ValueStrategy =
        HolyMailNormalizeValueStrategy(
            data.ValueStrategy
            or HOLY_MAIL_STATE.ValueStrategy
        )

    HOLY_MAIL_STATE.ExtraLimitMode =
        HolyMailNormalizeExtraLimitMode(
            data.ExtraLimitMode
            or HOLY_MAIL_STATE.ExtraLimitMode
        )

    HOLY_MAIL_STATE.ExtraLimitCustom =
        HolyMailNormalizeExtraLimitCustom(
            data.ExtraLimitCustom
            or HOLY_MAIL_STATE.ExtraLimitCustom
        )

    HOLY_MAIL_STATE.FilterFruits =
        HolyMailNormalizeFilterSelection(
            data.FilterFruits
            or HOLY_MAIL_STATE.FilterFruits
            or {}
        )

    HOLY_MAIL_STATE.FilterMutations =
        HolyMailNormalizeFilterSelection(
            data.FilterMutations
            or HOLY_MAIL_STATE.FilterMutations
            or {}
        )

    HOLY_MAIL_STATE.SavedRecipients =
        HolyMailNormalizeRecipientRecords(
            data.SavedRecipients
                or HOLY_MAIL_STATE.SavedRecipients
                or {},
            25,
            true
        )

    HOLY_MAIL_STATE.RecentRecipients =
        HolyMailNormalizeRecipientRecords(
            data.RecentRecipients
                or HOLY_MAIL_STATE.RecentRecipients
                or {},
            8,
            false
        )

    HOLY_MAIL_STATE.FleetAccounts =
        HolyMailNormalizeFleetAccounts(
            data.FleetAccounts
                or HOLY_MAIL_STATE.FleetAccounts
                or {}
        )

    HOLY_MAIL_STATE.FleetGroups =
        HolyMailNormalizeFleetGroups(
            data.FleetGroups
                or HOLY_MAIL_STATE.FleetGroups
                or {
                    "Ungrouped",
                }
        )

    HOLY_MAIL_STATE.TrackerDay =
        tostring(
            data.TrackerDay
                or HolyMailToday()
        )

    HOLY_MAIL_STATE.TrackerUsed =
        math.clamp(
            math.floor(
                tonumber(data.TrackerUsed)
                    or 0
            ),
            0,
            HOLY_MAIL_DAILY_LIMIT
        )

    if type(data.HudPosition) == "table" then
        HOLY_MAIL_STATE.HudPosition = {
            XScale =
                tonumber(data.HudPosition.XScale)
                    or 0.5,

            XOffset =
                tonumber(data.HudPosition.XOffset)
                    or 0,

            YScale =
                tonumber(data.HudPosition.YScale)
                    or 0.5,

            YOffset =
                tonumber(data.HudPosition.YOffset)
                    or 0,
        }
    end

    if HolyMailCheckDay() == true then
        HolyMailSaveSettings()
    end

    return true
end

function HolyMailReadPosition()
    local saved =
        HOLY_MAIL_STATE.HudPosition

    if type(saved) ~= "table" then
        return UDim2.fromScale(
            0.5,
            0.5
        )
    end

    return UDim2.new(
        tonumber(saved.XScale) or 0.5,
        tonumber(saved.XOffset) or 0,
        tonumber(saved.YScale) or 0.5,
        tonumber(saved.YOffset) or 0
    )
end

function HolyMailStorePosition(position)
    if typeof(position) ~= "UDim2" then
        return false
    end

    HOLY_MAIL_STATE.HudPosition = {
        XScale =
            position.X.Scale,

        XOffset =
            position.X.Offset,

        YScale =
            position.Y.Scale,

        YOffset =
            position.Y.Offset,
    }

    HolyMailSaveSettings()

    return true
end

function HolyMailRefreshControlUI()
    HolyMailCheckDay()

    HolySniperSetLabel(
        HOLY_MAIL_UI.UsageLabel,
        "Tracked today: "
            .. tostring(
                HOLY_MAIL_STATE.TrackerUsed
            )
            .. " / "
            .. tostring(
                HOLY_MAIL_DAILY_LIMIT
            )
    )

    local inboxText

    if HOLY_MAIL_RUNTIME.InboxKnown == true then
        inboxText =
            "Inbox: "
            .. tostring(
                HOLY_MAIL_RUNTIME.InboxCount
            )
            .. " / "
            .. tostring(
                HOLY_MAIL_INBOX_CAPACITY
            )
    else
        inboxText =
            "Inbox: Checking..."
    end

    HolySniperSetLabel(
        HOLY_MAIL_UI.InboxCountLabel,
        inboxText
    )

    HolySniperSetLabel(
        HOLY_MAIL_UI.InboxClaimedLabel,
        "Claimed this session: "
            .. tostring(
                HOLY_MAIL_RUNTIME.InboxClaimed
            )
    )

    HolySniperSetLabel(
        HOLY_MAIL_UI.InboxStatusLabel,
        tostring(
            HOLY_MAIL_RUNTIME.InboxStatus
            or "Waiting for mail"
        )
    )

    return true
end

function HolyMailSetTrackedUsed(value)
    HolyMailCheckDay()

    HOLY_MAIL_STATE.TrackerUsed =
        math.clamp(
            math.floor(
                tonumber(value)
                    or 0
            ),
            0,
            HOLY_MAIL_DAILY_LIMIT
        )

    if type(HOLY_MAIL_RUNTIME.UpdateQuota) == "function" then
        pcall(
            HOLY_MAIL_RUNTIME.UpdateQuota
        )
    end

    HolyMailSaveSettings()
    HolyMailRefreshControlUI()

    return HOLY_MAIL_STATE.TrackerUsed
end

function HolyMailGetInboxPackets()
    local sharedModules =
        ReplicatedStorage:FindFirstChild(
            "SharedModules"
        )

    local networkingModule =
        sharedModules
        and sharedModules:FindFirstChild(
            "Networking"
        )

    if not networkingModule
        or not networkingModule:IsA("ModuleScript")
    then
        return nil,
            nil,
            "SharedModules.Networking was not found"
    end

    local requireOk, networking =
        pcall(
            require,
            networkingModule
        )

    if requireOk ~= true
        or type(networking) ~= "table"
        or type(networking.Mailbox) ~= "table"
    then
        return nil,
            nil,
            "Networking.Mailbox could not be loaded"
    end

    local listPacket =
        networking.Mailbox.List

    local claimPacket =
        networking.Mailbox.Claim

    if type(listPacket) ~= "table"
        or type(listPacket.Fire) ~= "function"
    then
        return nil,
            nil,
            "Mailbox.List is unavailable"
    end

    if type(claimPacket) ~= "table"
        or type(claimPacket.Fire) ~= "function"
    then
        return nil,
            nil,
            "Mailbox.Claim is unavailable"
    end

    return listPacket,
        claimPacket,
        nil
end

function HolyMailListInbox(listPacket)
    if type(listPacket) ~= "table"
        or type(listPacket.Fire) ~= "function"
    then
        return nil,
            "Mailbox.List is unavailable"
    end

    local callOk, inbox =
        pcall(function()
            return listPacket:Fire()
        end)

    if callOk ~= true then
        return nil,
            tostring(inbox)
    end

    if type(inbox) ~= "table" then
        return nil,
            "Mailbox.List returned invalid data"
    end

    return inbox,
        nil
end

function HolyMailCountInbox(inbox)
    local count =
        0

    for _ in pairs(
        type(inbox) == "table"
            and inbox
            or {}
    ) do
        count +=
            1
    end

    return count
end

function HolyMailApplyInbox(inbox)
    HOLY_MAIL_RUNTIME.InboxCount =
        HolyMailCountInbox(
            inbox
        )

    HOLY_MAIL_RUNTIME.InboxKnown =
        true

    HolyMailRefreshControlUI()

    return HOLY_MAIL_RUNTIME.InboxCount
end

function HolyMailCollectClaimableMails(inbox)
    local claimable =
        {}

    for mailId, mailData in pairs(
        type(inbox) == "table"
            and inbox
            or {}
    ) do
        if type(mailId) == "string"
        and type(mailData) == "table"
        and type(mailData.Items) == "table"
        and next(mailData.Items) ~= nil
        then
            table.insert(
                claimable,
                {
                    Id =
                        mailId,

                    SentAt =
                        tonumber(
                            mailData.SentAt
                        ) or 0,

                    Data =
                        mailData,
                }
            )
        end
    end

    table.sort(
        claimable,
        function(first, second)
            if first.SentAt == second.SentAt then
                return first.Id < second.Id
            end

            return first.SentAt < second.SentAt
        end
    )

    return claimable
end

function HolyMailCleanInboxMessage(value)
    local message =
        tostring(
            value or ""
        ):gsub(
            "[%c]+",
            " "
        )

    if message == "" then
        message =
            "The server rejected the claim"
    end

    if #message > 110 then
        message =
            message:sub(
                1,
                107
            )
            .. "..."
    end

    return message
end

function HolyMailSyncInboxToggle(value)
    local toggle =
        type(Toggles) == "table"
        and Toggles.HolyMailAutoClaim
        or nil

    if type(toggle) ~= "table"
        or type(toggle.SetValue) ~= "function"
        or toggle.Value == (value == true)
    then
        return false
    end

    HOLY_MAIL_RUNTIME.SyncingInboxToggle =
        true

    pcall(function()
        toggle:SetValue(
            value == true
        )
    end)

    HOLY_MAIL_RUNTIME.SyncingInboxToggle =
        false

    return true
end

function HolyMailStopInboxWorker()
    HOLY_MAIL_RUNTIME.InboxWorkerToken =
        (
            tonumber(
                HOLY_MAIL_RUNTIME.InboxWorkerToken
            )
            or 0
        )
        + 1

    HOLY_MAIL_RUNTIME.InboxWorkerRunning =
        false

    return true
end

HOLY_MAIL_RUNTIME.StopInboxWorker =
    HolyMailStopInboxWorker

function HolyMailRefreshInboxCount()
    if HOLY_MAIL_RUNTIME.InboxClaiming == true then
        return false,
            "Mail is currently being claimed"
    end

    HOLY_MAIL_RUNTIME.InboxStatus =
        "Checking inbox..."

    HolyMailRefreshControlUI()

    local listPacket, _, packetError =
        HolyMailGetInboxPackets()

    if not listPacket then
        HOLY_MAIL_RUNTIME.InboxKnown =
            false

        HOLY_MAIL_RUNTIME.InboxStatus =
            "Could not check inbox"

        HOLY_MAIL_RUNTIME.InboxLastError =
            tostring(
                packetError
            )

        HolyMailRefreshControlUI()

        return false,
            packetError
    end

    local inbox, listError =
        HolyMailListInbox(
            listPacket
        )

    if not inbox then
        HOLY_MAIL_RUNTIME.InboxKnown =
            false

        HOLY_MAIL_RUNTIME.InboxStatus =
            "Could not check inbox"

        HOLY_MAIL_RUNTIME.InboxLastError =
            tostring(
                listError
            )

        HolyMailRefreshControlUI()

        return false,
            listError
    end

    HolyMailApplyInbox(
        inbox
    )

    if HOLY_MAIL_STATE.AutoClaim == true then
        HOLY_MAIL_RUNTIME.InboxStatus =
            "Watching for new mail..."
    elseif HOLY_MAIL_RUNTIME.InboxCount == 0 then
        HOLY_MAIL_RUNTIME.InboxStatus =
            "Inbox is empty"
    else
        HOLY_MAIL_RUNTIME.InboxStatus =
            "Auto Claim is off"
    end

    HolyMailRefreshControlUI()

    return true,
        inbox
end

function HolyMailClaimInbox(manual)
    if HOLY_MAIL_RUNTIME.InboxClaiming == true then
        if manual == true then
            HolyNotify(
                "HOLY Mail",
                "Mail is already being claimed.",
                3
            )
        end

        return false,
            "Mail is already being claimed",
            0
    end

    HOLY_MAIL_RUNTIME.InboxClaiming =
        true

    HOLY_MAIL_RUNTIME.InboxStatus =
        "Checking inbox..."

    HOLY_MAIL_RUNTIME.InboxLastError =
        ""

    HolyMailRefreshControlUI()

    local executionOk,
        successful,
        resultMessage,
        claimedCount =
        xpcall(
            function()
                local listPacket,
                    claimPacket,
                    packetError =
                    HolyMailGetInboxPackets()

                if not listPacket
                    or not claimPacket
                then
                    return false,
                        packetError,
                        0
                end

                local inbox, listError =
                    HolyMailListInbox(
                        listPacket
                    )

                if not inbox then
                    return false,
                        listError,
                        0
                end

                HolyMailApplyInbox(
                    inbox
                )

                local claimable =
                    HolyMailCollectClaimableMails(
                        inbox
                    )

                if #claimable == 0 then
                    if HOLY_MAIL_RUNTIME.InboxCount == 0 then
                        return true,
                            HOLY_MAIL_STATE.AutoClaim == true
                                and "Watching for new mail..."
                                or "Inbox is empty",
                            0
                    end

                    return true,
                        "No item gifts to claim",
                        0
                end

                local claimed =
                    0

                for index, mail in ipairs(
                    claimable
                ) do
                    if manual ~= true
                    and HOLY_MAIL_STATE.AutoClaim ~= true
                    then
                        break
                    end

                    HOLY_MAIL_RUNTIME.InboxStatus =
                        "Claiming "
                        .. tostring(index)
                        .. " of "
                        .. tostring(
                            #claimable
                        )
                        .. "..."

                    HolyMailRefreshControlUI()

                    local callOk,
                        accepted,
                        claimMessage =
                        pcall(function()
                            return claimPacket:Fire(
                                mail.Id
                            )
                        end)

                    if callOk ~= true then
                        return false,
                            tostring(accepted),
                            claimed
                    end

                    if accepted ~= true then
                        return false,
                            tostring(
                                claimMessage
                                or accepted
                            ),
                            claimed
                    end

                    claimed +=
                        1

                    HOLY_MAIL_RUNTIME.InboxClaimed +=
                        1

                    HolyMailHistoryRecordClaim(
                        mail
                    )

                    HOLY_MAIL_RUNTIME.InboxCount =
                        math.max(
                            0,
                            HOLY_MAIL_RUNTIME.InboxCount
                                - 1
                        )

                    HolyMailRefreshControlUI()
                end

                local finalInbox,
                    finalListError =
                    HolyMailListInbox(
                        listPacket
                    )

                if not finalInbox then
                    return false,
                        "Inbox refresh failed: "
                            .. tostring(
                                finalListError
                            ),
                        claimed
                end

                HolyMailApplyInbox(
                    finalInbox
                )

                if HOLY_MAIL_STATE.AutoClaim == true then
                    return true,
                        "Watching for new mail...",
                        claimed
                end

                if manual == true
                and claimed > 0
                then
                    return true,
                        "All item mail claimed",
                        claimed
                end

                return true,
                    "Auto Claim is off",
                    claimed
            end,
            function(message)
                return tostring(message)
                    .. "\n"
                    .. debug.traceback()
            end
        )

    HOLY_MAIL_RUNTIME.InboxClaiming =
        false

    if executionOk ~= true then
        resultMessage =
            tostring(
                successful
            )

        successful =
            false

        claimedCount =
            0
    end

    claimedCount =
        math.max(
            0,
            math.floor(
                tonumber(
                    claimedCount
                )
                or 0
            )
        )

    if successful == true then
        HOLY_MAIL_RUNTIME.InboxStatus =
            tostring(
                resultMessage
                or "Inbox checked"
            )

        if manual == true then
            HolyNotify(
                "HOLY Mail",
                claimedCount > 0
                    and (
                        "Claimed "
                        .. tostring(claimedCount)
                        .. (
                            claimedCount == 1
                                and " mail."
                                or " mails."
                        )
                    )
                    or tostring(
                        resultMessage
                        or "No item mail to claim."
                    ),
                4
            )
        end
    else
        local cleanMessage =
            HolyMailCleanInboxMessage(
                resultMessage
            )

        HOLY_MAIL_RUNTIME.InboxLastError =
            cleanMessage

        HOLY_MAIL_RUNTIME.InboxStatus =
            "Stopped: "
            .. cleanMessage

        if HOLY_MAIL_STATE.AutoClaim == true then
            HOLY_MAIL_STATE.AutoClaim =
                false

            HolyMailStopInboxWorker()

            HolyMailSyncInboxToggle(
                false
            )

            HolyMailSaveSettings()
        end

        HolyNotify(
            "HOLY Mail",
            "Auto Claim stopped: "
                .. cleanMessage,
            5
        )
    end

    HolyMailRefreshControlUI()

    return successful == true,
        resultMessage,
        claimedCount
end

function HolyMailStartInboxWorker()
    if HOLY_MAIL_STATE.AutoClaim ~= true then
        return false
    end

    if HOLY_MAIL_RUNTIME.InboxWorkerRunning == true then
        return true
    end

    HOLY_MAIL_RUNTIME.InboxWorkerToken =
        (
            tonumber(
                HOLY_MAIL_RUNTIME.InboxWorkerToken
            )
            or 0
        )
        + 1

    local token =
        HOLY_MAIL_RUNTIME.InboxWorkerToken

    HOLY_MAIL_RUNTIME.InboxWorkerRunning =
        true

    HOLY_MAIL_RUNTIME.InboxStatus =
        "Watching for new mail..."

    HolyMailRefreshControlUI()

    task.spawn(function()
        while HOLY_MAIL_STATE.AutoClaim == true
        and HOLY_MAIL_RUNTIME.InboxWorkerToken == token
        do
            HolyMailClaimInbox(
                false
            )

            if HOLY_MAIL_STATE.AutoClaim ~= true
            or HOLY_MAIL_RUNTIME.InboxWorkerToken ~= token
            then
                break
            end

            local _, interval =
                HolyMailNormalizeInboxInterval(
                    HOLY_MAIL_STATE.InboxInterval
                )

            local deadline =
                os.clock()
                + interval

            while HOLY_MAIL_STATE.AutoClaim == true
            and HOLY_MAIL_RUNTIME.InboxWorkerToken == token
            and os.clock() < deadline
            do
                task.wait(
                    math.min(
                        0.1,
                        math.max(
                            0,
                            deadline - os.clock()
                        )
                    )
                )
            end
        end

        if HOLY_MAIL_RUNTIME.InboxWorkerToken == token then
            HOLY_MAIL_RUNTIME.InboxWorkerRunning =
                false
        end
    end)

    return true
end

function HolyMailSetAutoClaim(value)
    local enabled =
        value == true

    HOLY_MAIL_STATE.AutoClaim =
        enabled

    HOLY_MAIL_RUNTIME.InboxLastError =
        ""

    if enabled == true then
        HOLY_MAIL_RUNTIME.InboxStatus =
            "Watching for new mail..."

        HolyMailStartInboxWorker()
    else
        HolyMailStopInboxWorker()

        HOLY_MAIL_RUNTIME.InboxStatus =
            "Auto Claim is off"
    end

    HolyMailSaveSettings()
    HolyMailRefreshControlUI()

    return enabled
end

