        Yellow =
            Color3.fromRGB(235, 188, 92),

        Red =
            Color3.fromRGB(240, 103, 111),

        Accent =
            Color3.fromRGB(45, 128, 246),
    }

    local function create(
        className,
        properties,
        parent
    )
        local object =
            Instance.new(className)

        if object:IsA(
            "GuiObject"
        ) then
            object.BorderSizePixel =
                0
        end

        for property, value in pairs(
            properties or {}
        ) do
            object[property] =
                value
        end

        object.Parent =
            parent

        return object
    end

    local function round(
        object,
        radius
    )
        return create(
            "UICorner",
            {
                CornerRadius =
                    UDim.new(
                        0,
                        radius or 12
                    ),
            },
            object
        )
    end

    local function outline(
        object,
        chosenColor
    )
        return create(
            "UIStroke",
            {
                Color =
                    chosenColor
                        or color.Border,

                Thickness =
                    1.15,

                Transparency =
                    0.18,

                ApplyStrokeMode =
                    Enum.ApplyStrokeMode.Border,

                LineJoinMode =
                    Enum.LineJoinMode.Round,
            },
            object
        )
    end

    local function text(
        parent,
        value,
        size,
        position,
        textSize,
        chosenColor,
        alignment,
        font
    )
        local requestedTextSize =
            math.floor(
                (
                    tonumber(textSize)
                    or 13
                )
                + 0.5
            )

        local minimumTextSize =
            (
                font == Enum.Font.GothamBold
                or font == Enum.Font.GothamSemibold
            )
                and 12
                or 11

        return create(
            "TextLabel",
            {
                BackgroundTransparency =
                    1,

                Text =
                    value or "",

                Size =
                    size,

                Position =
                    position,

                TextSize =
                    math.max(
                        requestedTextSize,
                        minimumTextSize
                    ),

                TextColor3 =
                    chosenColor
                        or color.Text,

                TextXAlignment =
                    alignment
                        or Enum.TextXAlignment.Left,

                TextYAlignment =
                    Enum.TextYAlignment.Center,

                TextTruncate =
                    Enum.TextTruncate.AtEnd,

                TextStrokeTransparency =
                    1,

                Font =
                    font
                        or Enum.Font.GothamMedium,
            },
            parent
        )
    end

