    local function updateQuota()
        HolyMailCheckDay()

        tracker.Used =
            math.clamp(
                math.floor(
                    tonumber(
                        HOLY_MAIL_STATE.TrackerUsed
                    )
                        or tracker.Used
                        or 0
                ),
                0,
                DAILY_LIMIT
            )

        HOLY_MAIL_STATE.TrackerUsed =
            tracker.Used

        quotaText.Text =
            state.Minimized
                    and string.format(
                        "%d/%d",
                        tracker.Used,
                        DAILY_LIMIT
                    )
                or string.format(
                    "%d / %d used here",
                    tracker.Used,
                    DAILY_LIMIT
                )

        HolyMailRefreshControlUI()
    end

    HOLY_MAIL_RUNTIME.UpdateQuota =
        updateQuota

    local function reportError(
        where,
        err
    )
        local result =
            tostring(where)
            .. ": "
            .. tostring(err)

        HOLY_MAIL_RUNTIME.LastError =
            result

        warn(
            "[HOLY MAIL] "
                .. result
        )

        setStatus(
            "Error",
            color.Red
        )

        messageText.Text =
            "Something went wrong. The error was copied."

        messageText.TextColor3 =
            color.Red

        pcall(function()
            if type(setclipboard) == "function" then
                setclipboard(result)
            end
        end)
    end

    local function protectedCall(
        where,
        callback
    )
        local ok, err =
            xpcall(
                callback,
                function(value)
                    local trace =
                        ""

                    pcall(function()
                        trace =
                            debug.traceback()
                    end)

                    return tostring(value)
                        .. (
                            trace ~= ""
                                and "\n" .. trace
                                or ""
                        )
                end
            )

        if not ok then
            reportError(
                where,
                err
            )
        end

        return ok
    end

    local function formatValue(value)
        value =
            math.max(
                0,
                tonumber(value)
                    or 0
            )

        if type(HolyVisualFormatTotalFruitValue) == "function" then
            local ok, result =
                pcall(
                    HolyVisualFormatTotalFruitValue,
                    value
                )

            if ok
                and type(result) == "string"
            then
                return result
            end
        end

        if value >= 1e15 then
            return "$"
                .. string.format(
                    "%.2fQa",
                    value / 1e15
                )
        elseif value >= 1e12 then
            return "$"
                .. string.format(
                    "%.2fT",
                    value / 1e12
                )
        elseif value >= 1e9 then
            return "$"
                .. string.format(
                    "%.2fB",
                    value / 1e9
                )
        elseif value >= 1e6 then
            return "$"
                .. string.format(
                    "%.2fM",
                    value / 1e6
                )
        elseif value >= 1e3 then
            return "$"
                .. string.format(
                    "%.1fK",
                    value / 1e3
                )
        end

        return "$"
            .. tostring(
                math.floor(value + 0.5)
            )
    end

    local function parseValue(value)
        local raw =
            tostring(value or "")
                :lower()
                :gsub("[$,%s]", "")

        local number =
            tonumber(
                raw:match("[%d%.]+")
            )

        if not number then
            return nil
        end

        if raw:find(
            "qa",
            1,
            true
        ) then
            number *= 1e15
        elseif raw:find(
            "t",
            1,
            true
        ) then
            number *= 1e12
        elseif raw:find(
            "b",
            1,
            true
        ) then
            number *= 1e9
        elseif raw:find(
            "m",
            1,
            true
        ) then
            number *= 1e6
        elseif raw:find(
            "k",
            1,
            true
        ) then
            number *= 1e3
        end

        number =
            math.floor(
                number + 0.5
            )

        return number > 0
                and number
            or nil
    end

    local function getRoots()
        local roots = {}

        if player.Character then
            table.insert(
                roots,
                player.Character
            )
        end

        local backpack =
            player:FindFirstChildOfClass(
                "Backpack"
            )

        if backpack then
            table.insert(
                roots,
                backpack
            )
        end

        return roots
    end

    local valueData

    local function simpleKey(value)
        return tostring(value or "")
            :lower()
            :gsub("[%s%p_]", "")
    end

    local function loadValueData()
        if valueData then
            return valueData
        end

        valueData = {
            Calculator = nil,
            Prices = {},
            Mutations = {},
        }

        local shared =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        if not shared then
            return valueData
        end

        local calculatorModule =
            shared:FindFirstChild(
                "FruitValueCalc"
            )

        if calculatorModule
            and calculatorModule:IsA("ModuleScript")
        then
            local ok, result =
                pcall(
                    require,
                    calculatorModule
                )

            if ok then
                if type(result) == "function" then
                    valueData.Calculator =
                        result
                elseif type(result) == "table" then
                    valueData.Calculator =
                        result.Calculate
                        or result.GetValue
                        or result.GetFruitValue
                        or result.Value
                end
            end
        end

        local priceModule =
            shared:FindFirstChild(
                "SellValueData"
            )

        if priceModule
            and priceModule:IsA("ModuleScript")
        then
            local ok, result =
                pcall(
                    require,
                    priceModule
                )

            if ok
                and type(result) == "table"
            then
                for fruitName, price in pairs(result) do
                    if tonumber(price) then
                        valueData.Prices[
                            simpleKey(fruitName)
                        ] =
                            tonumber(price)
                    end
                end
            end
        end

        local mutationFolder =
            shared:FindFirstChild(
                "MutationData"
            )

        if mutationFolder then
            for _, module in ipairs(
                mutationFolder:GetChildren()
            ) do
                if module:IsA("ModuleScript") then
                    local ok, result =
                        pcall(
                            require,
                            module
                        )

                    if ok
                        and type(result) == "table"
                    then
                        local multiplier =
                            tonumber(
                                result.PriceMultiplier
                                or result.SellMultiplier
                                or result.ValueMultiplier
                                or result.Multiplier
                                or result.Boost
                            )

                        if multiplier
                            and multiplier > 0
                        then
                            valueData.Mutations[
                                simpleKey(module.Name)
                            ] =
                                multiplier
                        end
                    end
                end
            end
        end

        return valueData
    end

    local function fallbackFruitValue(item)
        local name =
            tostring(
                item:GetAttribute("FruitName")
                or item:GetAttribute("Fruit")
                or item:GetAttribute("ItemName")
                or item.Name
            )

        name =
            name
                :gsub("%s*%b[]", "")
                :gsub("%s*%b()", "")
                :gsub("^%s+", "")
                :gsub("%s+$", "")

        local mutation =
            tostring(
                item:GetAttribute("Mutation")
                or item:GetAttribute("Mutations")
                or item:GetAttribute("Variant")
                or ""
            )

        if mutation == "" then
            for bracket in tostring(item.Name):gmatch(
                "%[([^%]]+)%]"
            ) do
                if not bracket
                    :lower()
                    :find("kg", 1, true)
                then
                    mutation =
                        bracket

                    break
                end
            end
        end

        local size =
            tonumber(
                item:GetAttribute("SizeMultiplier")
                or item:GetAttribute("SizeMulti")
                or item:GetAttribute("ScaleMultiplier")
                or item:GetAttribute("ScaleMulti")
                or item:GetAttribute("Scale")
                or item:GetAttribute("Weight")
                or item:GetAttribute("WeightKg")
            )

        size =
            size
            or tonumber(
                tostring(item.Name):match(
                    "([%d%.]+)%s*[Kk][Gg]"
                )
            )
            or 1

        size =
            math.max(
                0.01,
                size
            )

        local data =
            loadValueData()

        local calculated

        if type(data.Calculator) == "function" then
            local attempts = {
                {
                    name,
                    size,
                    item,
                    item,
                    item,
                },

                {
                    name,
                    size,
                    item,
                },

                {
                    name,
                    size,
                },

                {
                    item,
                },
            }

            for _, arguments in ipairs(attempts) do
                local ok, result =
                    pcall(
                        data.Calculator,
                        table.unpack(arguments)
                    )

                if ok
                    and tonumber(result)
                    and tonumber(result) >= 0
                then
                    calculated =
                        tonumber(result)

                    break
                end
            end
        end

        if not calculated then
            calculated =
                (
                    data.Prices[
                        simpleKey(name)
                    ] or 0
                )
                * size ^ 2.5
        end

        local multiplier =
            1

        for part in mutation:gmatch(
            "[^,%|/;]+"
        ) do
            multiplier *=
                data.Mutations[
                    simpleKey(part)
                ] or 1
        end

        calculated *=
            multiplier

        return calculated > 0
                and math.floor(
                    calculated + 0.5
                )
                or nil,
            name,
            mutation
    end

    local function valuePreviewFruitIcon(
        item,
        info
    )
        local candidates = {}

        if type(info) == "table" then
            table.insert(
                candidates,
                info.IMG
            )

            table.insert(
                candidates,
                info.Icon
            )

            table.insert(
                candidates,
                info.Image
            )

            table.insert(
                candidates,
                info.ImageId
            )

            table.insert(
                candidates,
                info.FruitImage
            )

            table.insert(
                candidates,
                info.FruitIcon
            )

            table.insert(
                candidates,
                info.TextureId
            )
        end

        if typeof(item) == "Instance" then
            table.insert(
                candidates,
                item:GetAttribute("IMG")
            )

            table.insert(
                candidates,
                item:GetAttribute("Icon")
            )

            table.insert(
                candidates,
                item:GetAttribute("Image")
            )

            table.insert(
                candidates,
                item:GetAttribute("ImageId")
            )

            table.insert(
                candidates,
                item:GetAttribute("FruitImage")
            )

            table.insert(
                candidates,
                item:GetAttribute("FruitIcon")
            )

            table.insert(
                candidates,
                item:GetAttribute("TextureId")
            )

            if item:IsA("Tool") then
                table.insert(
                    candidates,
                    item.TextureId
                )
            end
        end

        for _, candidate in ipairs(
            candidates
        ) do
            local icon =
                HolyMailHistoryNormalizeIcon(
                    candidate
                )

            if icon ~= "" then
                return icon
            end
        end

        if typeof(item) == "Instance" then
            for _, descendant in ipairs(
                item:GetDescendants()
            ) do
                local rawIcon

                if descendant:IsA("ImageLabel")
                    or descendant:IsA("ImageButton")
                then
                    rawIcon =
                        descendant.Image
                elseif descendant:IsA("Decal")
                    or descendant:IsA("Texture")
                then
                    rawIcon =
                        descendant.Texture
                end

                local icon =
                    HolyMailHistoryNormalizeIcon(
                        rawIcon
                    )

                if icon ~= "" then
                    return icon
                end
            end
        end

        return ""
    end

    local function readFruit(item)
        if not (
            item:IsA("Tool")
            or item:IsA("Configuration")
        ) then
            return nil
        end

        if item:GetAttribute("HarvestedFruit") ~= true then
            return nil
        end

        local id =
            tostring(
                item:GetAttribute("Id")
                or item:GetAttribute("FruitId")
                or ""
            )

        if id == "" then
            return nil
        end

        local info
        local value
        local fallbackName
        local fallbackMutation

        if type(HolyFruitAutomationReadToolInfo) == "function" then
            local ok, result =
                pcall(
                    HolyFruitAutomationReadToolInfo,
                    item
                )

            if ok
                and type(result) == "table"
            then
                info =
                    result
            end
        end

        if info
            and type(HolyFruitAutomationCalculateInfoValue) == "function"
        then
            local ok, result =
                pcall(
                    HolyFruitAutomationCalculateInfoValue,
                    info
                )

            if ok then
                value =
                    tonumber(
                        result
                        or info.ValueNumber
                        or info.Value
                    )
            end
        end

        if not value
            and item:IsA("Tool")
            and type(HolyVisualReadFruitTool) == "function"
        then
            local ok, result =
                pcall(
                    HolyVisualReadFruitTool,
                    item,
                    0
                )

            if ok
                and type(result) == "table"
            then
                value =
                    tonumber(result.Value)

                info =
                    info or result
            end
        end

        value =
            value
            or tonumber(
                item:GetAttribute("Value")
                or item:GetAttribute("SellValue")
                or item:GetAttribute("Price")
            )

        if not value
            or value <= 0
        then
            value,
            fallbackName,
            fallbackMutation =
                fallbackFruitValue(item)
        end

        if not value
            or value <= 0
        then
            return nil
        end

        local name =
            tostring(
                (
                    info
                    and (
                        info.FruitName
                        or info.Name
                        or info.DisplayName
                    )
                )
                or item:GetAttribute("FruitName")
                or item:GetAttribute("ItemName")
                or fallbackName
                or item.Name
            )

        local mutation =
            tostring(
                (
                    info
                    and (
                        info.Mutation
                        or info.RawMutation
                    )
                )
                or item:GetAttribute("Mutation")
                or item:GetAttribute("Variant")
                or fallbackMutation
                or "Normal"
            )

        local favorite =
            item:GetAttribute("IsFavorite") == true
            or item:GetAttribute("Favorite") == true
            or item:GetAttribute("Favorited") == true
            or (
                info
                and (
                    info.IsFavorite == true
                    or info.Favorite == true
                )
            )

        return {
            Id =
                id,

            Item =
                item,

            Name =
                name,

            Mutation =
                mutation ~= ""
                    and mutation
                    or "Normal",

            Icon =
                valuePreviewFruitIcon(
                    item,
                    info
                ),

            Value =
                math.floor(
                    value + 0.5
                ),

            Favorite =
                favorite == true,
        }
    end

    local function scanInventory()
        local fruits = {}
        local seen = {}
        local unvalued = 0

        for _, root in ipairs(getRoots()) do
            for _, item in ipairs(
                root:GetChildren()
            ) do
                if (
                    item:IsA("Tool")
                    or item:IsA("Configuration")
                )
                    and item:GetAttribute("HarvestedFruit") == true
                then
                    local id =
                        tostring(
                            item:GetAttribute("Id")
                            or item:GetAttribute("FruitId")
                            or ""
                        )

                    if id ~= ""
                        and not seen[id]
                    then
                        seen[id] =
                            true

                        local fruit =
                            readFruit(item)

                        if fruit then
                            table.insert(
                                fruits,
                                fruit
                            )
                        else
                            unvalued +=
                                1
                        end
                    end
                end
            end
        end

        state.Inventory =
            fruits

        return fruits,
            unvalued
    end

    state.Filters.Matches =
        function(fruit)
            if type(fruit) ~= "table" then
                return false
            end

            local selectedFruits =
                state.Filters.Fruits

            if type(selectedFruits) == "table"
                and next(
                    selectedFruits
                ) ~= nil
            then
                local fruitKey =
                    HolyMailFilterKey(
                        fruit.Name
                    )

                if selectedFruits[
                    fruitKey
                ] == nil then
                    return false
                end
            end

            local selectedMutations =
                state.Filters.Mutations

            if type(selectedMutations) == "table"
                and next(
                    selectedMutations
                ) ~= nil
            then
                local mutationText =
                    tostring(
                        fruit.Mutation
                        or "Normal"
                    )

                if HolyMailFilterKey(
                    mutationText
                ) == "" then
                    mutationText =
                        "Normal"
                end

                local matched =
                    false

                for part in mutationText:gmatch(
                    "[^,%|/;]+"
                ) do
                    local mutationKey =
                        HolyMailFilterKey(
                            part
                        )

                    if mutationKey ~= ""
                        and selectedMutations[
                            mutationKey
                        ] ~= nil
                    then
                        matched =
                            true

                        break
                    end
                end

                if not matched
                    and HolyMailFilterKey(
                        mutationText
                    ) == "normal"
                    and selectedMutations.normal
                then
                    matched =
                        true
                end

                if not matched then
                    return false
                end
            end

            return true
        end

    state.Filters.UpdateButton =
        function()
            local fruitCount = 0
            local mutationCount = 0

            for _ in pairs(
                state.Filters.Fruits
                or {}
            ) do
                fruitCount +=
                    1
            end

            for _ in pairs(
                state.Filters.Mutations
                or {}
            ) do
                mutationCount +=
                    1
            end

            if fruitCount <= 0
                and mutationCount <= 0
            then
                fruitsButton.Text =
                    "Filters: All"
            elseif fruitCount > 0
                and mutationCount <= 0
            then
                fruitsButton.Text =
                    "Filters: "
                    .. tostring(
                        fruitCount
                    )
                    .. (
                        fruitCount == 1
                            and " fruit"
                            or " fruits"
                    )
            elseif fruitCount <= 0
                and mutationCount > 0
            then
                fruitsButton.Text =
                    "Filters: "
                    .. tostring(
                        mutationCount
                    )
                    .. (
                        mutationCount == 1
                            and " mutation"
                            or " mutations"
                    )
            else
                fruitsButton.Text =
                    "Filters: "
                    .. tostring(
                        fruitCount
                    )
                    .. " fruits · "
                    .. tostring(
                        mutationCount
                    )
                    .. " mutations"
            end
        end

    state.Filters.UpdateButton()

    local function clearRows(
        container,
        layout
    )
        for _, child in ipairs(
            container:GetChildren()
        ) do
            if child ~= layout
                and not child:IsA(
                    "UIPadding"
                )
            then
                child:Destroy()
            end
        end
    end

