    local function addAvatar(
        parent,
        userId,
        size,
        position
    )
        local avatar =
            create(
                "ImageLabel",
                {
                    BackgroundColor3 =
                        color.Hover,

                    BorderSizePixel =
                        0,

                    Image =
                        avatarCache[userId]
                            or "",

                    Size =
                        size,

                    Position =
                        position,

                    ScaleType =
                        Enum.ScaleType.Crop,
                },
                parent
            )

        round(
            avatar,
            999
        )

        if avatar.Image == "" then
            task.spawn(function()
                local ok, image =
                    pcall(
                        Players.GetUserThumbnailAsync,
                        Players,
                        userId,
                        Enum.ThumbnailType.HeadShot,
                        Enum.ThumbnailSize.Size100x100
                    )

                if ok
                    and type(image) == "string"
                then
                    avatarCache[userId] =
                        image

                    if avatar.Parent then
                        avatar.Image =
                            image
                    end
                end
            end)
        end

        return avatar
    end

