    local function formatSignedMailValue(
        value
    )
        value =
            tonumber(value)
            or 0

        local prefix =
            value > 0
                and "+"
                or value < 0
                    and "-"
                    or ""

        return prefix
            .. formatValue(
                math.abs(value)
            )
    end

    local function formatSignedMailPercent(
        value
    )
        value =
            tonumber(value)
            or 0

        local prefix =
            value > 0
                and "+"
                or value < 0
                    and "-"
                    or ""

        return prefix
            .. string.format(
                "%.1f%%",
                math.abs(value)
            )
    end

    local function extraLimitCaption()
        local mode =
            HolyMailNormalizeExtraLimitMode(
                state.ExtraLimitMode
            )

        if mode == "No limit" then
            return "No limit"
        end

        local value =
            mode == "Custom"
            and HolyMailNormalizeExtraLimitCustom(
                state.ExtraLimitCustom
            )
            or mode

        if value:sub(1, 1) == "+" then
            return value
        end

        return "+"
            .. value
    end

    local function getMaximumExtra(
        target
    )
        target =
            math.max(
                0,
                tonumber(target)
                or 0
            )

        local mode =
            HolyMailNormalizeExtraLimitMode(
                state.ExtraLimitMode
            )

        if mode == "No limit" then
            return math.huge
        end

        if mode == "1%"
            or mode == "5%"
            or mode == "10%"
        then
            local percentage =
                tonumber(
                    mode:match(
                        "[%d%.]+"
                    )
                )
                or 5

            return target
                * percentage
                / 100
        end

        local custom =
            HolyMailNormalizeExtraLimitCustom(
                state.ExtraLimitCustom
            )

        if custom:find(
            "%",
            1,
            true
        ) then
            local percentage =
                tonumber(
                    custom
                        :gsub(
                            "%%",
                            ""
                        )
                        :gsub(
                            "%s+",
                            ""
                        )
                )

            if percentage
                and percentage >= 0
            then
                return target
                    * percentage
                    / 100
            end
        else
            local fixedValue =
                parseValue(
                    custom
                )

            if fixedValue
                and fixedValue >= 0
            then
                return fixedValue
            end
        end

        return target
            * 0.05
    end

