    local function allocate(
        available,
        target
    )
        local sorted =
            table.clone(
                available
            )

        table.sort(
            sorted,
            function(a, b)
                return a.Value
                    > b.Value
            end
        )

        local chosen = {}
        local used = {}
        local total = 0

        local allocation = {
            GuardBlocked = false,
            UnsafeValue = nil,
            UnsafeExtra = nil,
            MaxExtra = nil,
            MaxAllowed = nil,
        }

        for _, fruit in ipairs(
            sorted
        ) do
            if total + fruit.Value
                <= target
            then
                table.insert(
                    chosen,
                    fruit
                )

                used[fruit.Id] =
                    true

                total +=
                    fruit.Value
            end
        end

        if state.Strategy
            == "Send at least"
            and total < target
        then
            local maximumExtra =
                getMaximumExtra(
                    target
                )

            local maximumAllowed =
                maximumExtra == math.huge
                    and math.huge
                    or target
                        + maximumExtra

            allocation.MaxExtra =
                maximumExtra

            allocation.MaxAllowed =
                maximumAllowed

            local bestSafe
            local bestSafeExtra

            local bestUnsafe
            local bestUnsafeExtra

            for _, fruit in ipairs(
                sorted
            ) do
                if not used[fruit.Id] then
                    local candidateValue =
                        total
                        + fruit.Value

                    if candidateValue
                        >= target
                    then
                        local candidateExtra =
                            candidateValue
                            - target

                        if candidateExtra
                            <= maximumExtra
                        then
                            if not bestSafe
                                or candidateExtra
                                    < bestSafeExtra
                            then
                                bestSafe =
                                    fruit

                                bestSafeExtra =
                                    candidateExtra
                            end
                        elseif not bestUnsafe
                            or candidateExtra
                                < bestUnsafeExtra
                        then
                            bestUnsafe =
                                fruit

                            bestUnsafeExtra =
                                candidateExtra
                        end
                    end
                end
            end

            if bestSafe then
                table.insert(
                    chosen,
                    bestSafe
                )

                used[bestSafe.Id] =
                    true

                total +=
                    bestSafe.Value
            elseif bestUnsafe then
                allocation.GuardBlocked =
                    true

                allocation.UnsafeValue =
                    total
                    + bestUnsafe.Value

                allocation.UnsafeExtra =
                    allocation.UnsafeValue
                    - target
            end
        elseif state.Strategy
            == "Closest amount"
            and total < target
        then
            local best
            local difference

            for _, fruit in ipairs(
                sorted
            ) do
                if not used[fruit.Id] then
                    local current =
                        math.abs(
                            target
                            - total
                            - fruit.Value
                        )

                    if not best
                        or current
                            < difference
                    then
                        best =
                            fruit

                        difference =
                            current
                    end
                end
            end

            if best then
                local below =
                    math.abs(
                        target
                        - total
                    )

                local above =
                    math.abs(
                        target
                        - total
                        - best.Value
                    )

                if above < below then
                    table.insert(
                        chosen,
                        best
                    )

                    used[best.Id] =
                        true

                    total +=
                        best.Value
                end
            end
        end

        return chosen,
            total,
            allocation
    end

    rebuildPlan =
        function()
            if state.Busy
                or state.Running
            then
                return
            end

            state.Busy =
                true

            setStatus(
                "Checking",
                color.Yellow
            )

            messageText.TextColor3 =
                color.Muted

            local inventory, unvalued =
                scanInventory()

            local eligible = {}
            local protected = 0
            local filtered = 0

            for _, fruit in ipairs(
                inventory
            ) do
                if not state.Filters.Matches(
                    fruit
                )
                then
                    filtered +=
                        1
                elseif state.Protect
                    and fruit.Favorite
                then
                    protected +=
                        1
                else
                    table.insert(
                        eligible,
                        fruit
                    )
                end
            end

            local available =
                table.clone(eligible)

            local plan = {}
            local totalFruits = 0
            local totalValue = 0
            local totalMails = 0
            local incomplete = 0
            local overpayBlocked = 0

            for routeIndex, recipient in ipairs(
                state.Recipients
            ) do
                local planTarget =
                    tonumber(
                        recipient.Target
                    )
                    or 0

                local valueSession =
                    state.ValueSession

                if type(valueSession) == "table"
                    and type(
                        valueSession.RemainingTargets
                    ) == "table"
                    and valueSession.Status ~= "Complete"
                then
                    local remainingTarget =
                        valueSession.RemainingTargets[
                            recipient.UserId
                        ]

                    if remainingTarget ~= nil then
                        planTarget =
                            math.max(
                                0,
                                tonumber(
                                    remainingTarget
                                )
                                or 0
                            )
                    end
                end

                local chosen,
                    chosenValue,
                    allocation =
                    allocate(
                        available,
                        planTarget
                    )

                allocation =
                    type(allocation) == "table"
                    and allocation
                    or {
                        GuardBlocked = false,
                    }

                local selected = {}

                for _, fruit in ipairs(
                    chosen
                ) do
                    selected[fruit.Id] =
                        true
                end

                local remaining = {}

                for _, fruit in ipairs(
                    available
                ) do
                    if not selected[fruit.Id] then
                        table.insert(
                            remaining,
                            fruit
                        )
                    end
                end

                available =
                    remaining

                local complete =
                    planTarget <= 0
                    or (
                        allocation.GuardBlocked ~= true
                        and (
                            (
                                state.Strategy == "Send at least"
                                and chosenValue >= planTarget
                            )
                            or (
                                state.Strategy ~= "Send at least"
                                and #chosen > 0
                            )
                        )
                    )

                if planTarget > 0
                    and allocation.GuardBlocked == true
                then
                    overpayBlocked +=
                        1
                end

                if not complete then
                    incomplete +=
                        1
                end

                local entry = {
                    Index =
                        routeIndex,

                    Recipient =
                        recipient,

                    Target =
                        planTarget,

                    Fruits =
                        chosen,

                    Value =
                        chosenValue,

                    Extra =
                        chosenValue
                        - planTarget,

                    ExtraPercent =
                        planTarget > 0
                        and (
                            (
                                chosenValue
                                - planTarget
                            )
                            / planTarget
                            * 100
                        )
                        or 0,

                    Mails =
                        math.ceil(
                            #chosen / BATCH_LIMIT
                        ),

                    Complete =
                        complete,

                    GuardBlocked =
                        planTarget > 0
                        and allocation.GuardBlocked == true,

                    UnsafeValue =
                        allocation.UnsafeValue,

                    UnsafeExtra =
                        allocation.UnsafeExtra,

                    MaxExtra =
                        allocation.MaxExtra,

                    MaxAllowed =
                        allocation.MaxAllowed,
                }

                table.insert(
                    plan,
                    entry
                )

                totalFruits +=
                    #chosen

                totalValue +=
                    chosenValue

                totalMails +=
                    entry.Mails
            end

            state.Plan =
                plan

            clearRows(
                previewList,
                previewLayout
            )

            if #plan == 0 then
                local empty =
                    create(
                        "Frame",
                        {
                            BackgroundColor3 =
                                color.Field,

                            Size =
                                UDim2.new(
                                    1,
                                    -2,
                                    0,
                                    268
                                ),
                        },
                        previewList
                    )

                round(
                    empty,
                    13
                )

                outline(
                    empty,
                    Color3.fromRGB(
                        40,
                        51,
                        68
                    )
                )

                local emptyIcon =
                    create(
                        "Frame",
                        {
                            AnchorPoint =
                                Vector2.new(
                                    0.5,
                                    0
                                ),

                            BackgroundTransparency =
                                1,

                            Size =
                                UDim2.fromOffset(
                                    54,
                                    46
                                ),

                            Position =
                                UDim2.new(
                                    0.5,
                                    0,
                                    0,
                                    55
                                ),
                        },
                        empty
                    )

                local emptyIconBody =
                    create(
                        "Frame",
                        {
                            BackgroundTransparency =
                                1,

                            Size =
                                UDim2.fromOffset(
                                    48,
                                    38
                                ),

                            Position =
                                UDim2.fromOffset(
                                    3,
                                    4
                                ),
                        },
                        emptyIcon
                    )

                round(
                    emptyIconBody,
                    8
                )

                local emptyIconStroke =
                    outline(
                        emptyIconBody,
                        color.Secondary
                    )

                emptyIconStroke.Thickness =
                    2

                emptyIconStroke.Transparency =
                    0.1

                local emptyIconTray =
                    create(
                        "Frame",
                        {
                            BackgroundColor3 =
                                color.Secondary,

                            Size =
                                UDim2.fromOffset(
                                    22,
                                    3
                                ),

                            Position =
                                UDim2.fromOffset(
                                    16,
                                    29
                                ),
                        },
                        emptyIcon
                    )

                round(
                    emptyIconTray,
                    3
                )

                text(
                    empty,
                    "Nothing to preview yet",
                    UDim2.new(
                        1,
                        -30,
                        0,
                        28
                    ),
                    UDim2.fromOffset(
                        15,
                        124
                    ),
                    16,
                    color.Text,
                    Enum.TextXAlignment.Center,
                    Enum.Font.GothamBold
                )

                text(
                    empty,
                    "Add someone and choose how much to send.",
                    UDim2.new(
                        1,
                        -30,
                        0,
                        24
                    ),
                    UDim2.fromOffset(
                        15,
                        160
                    ),
                    12,
                    color.Secondary,
                    Enum.TextXAlignment.Center,
                    Enum.Font.GothamMedium
                )
            else
                for _, entry in ipairs(plan) do
                    local row =
                        create(
                            "Frame",
                            {
                                BackgroundColor3 =
                                    color.Field,

                                Size =
                                    UDim2.new(
                                        1,
                                        -2,
                                        0,
                                        118
                                    ),

                                LayoutOrder =
                                    entry.Index,
                            },
                            previewList
                        )

                    round(
                        row,
                        11
                    )

                    outline(
                        row,
                        color.Border
                    )

                    addAvatar(
                        row,
                        entry.Recipient.UserId,
                        UDim2.fromOffset(
                            32,
                            32
                        ),
                        UDim2.fromOffset(
                            12,
                            8
                        )
                    )

                    text(
                        row,
                        "@"
                            .. entry.Recipient.Name,
                        UDim2.new(
                            1,
                            -180,
                            0,
                            24
                        ),
                        UDim2.fromOffset(
                            54,
                            7
                        ),
                        11,
                        color.Text,
                        nil,
                        Enum.Font.GothamSemibold
                    )

                    text(
                        row,
                        entry.GuardBlocked
                                and "Cannot reach safely"
                            or entry.Complete
                                    and "Ready"
                                or "Needs value",
                        UDim2.fromOffset(
                            150,
                            24
                        ),
                        UDim2.new(
                            1,
                            -162,
                            0,
                            7
                        ),
                        9,
                        entry.GuardBlocked
                                and color.Red
                            or entry.Complete
                                    and color.Green
                                or color.Yellow,
                        Enum.TextXAlignment.Right,
                        Enum.Font.GothamBold
                    )

                    create(
                        "Frame",
                        {
                            BackgroundColor3 =
                                color.Border,

                            BackgroundTransparency =
                                0.25,

                            Size =
                                UDim2.new(
                                    1,
                                    -24,
                                    0,
                                    1
                                ),

                            Position =
                                UDim2.fromOffset(
                                    12,
                                    39
                                ),
                        },
                        row
                    )

                    local function addPreviewStat(
                        titleValue,
                        valueText,
                        x,
                        valueColor
                    )
                        text(
                            row,
                            titleValue,
                            UDim2.fromOffset(
                                104,
                                15
                            ),
                            UDim2.fromOffset(
                                x,
                                43
                            ),
                            10,
                            color.Secondary,
                            nil,
                            Enum.Font.GothamBold
                        )

                        text(
                            row,
                            valueText,
                            UDim2.fromOffset(
                                104,
                                20
                            ),
                            UDim2.fromOffset(
                                x,
                                58
                            ),
                            10,
                            valueColor
                                or color.Text,
                            nil,
                            Enum.Font.GothamSemibold
                        )
                    end

                    addPreviewStat(
                        "TARGET",
                        formatValue(
                            entry.Target
                            or entry.Recipient.Target
                        ),
                        12,
                        color.Text
                    )

                    addPreviewStat(
                        "SENDING",
                        formatValue(
                            entry.Value
                        ),
                        120,
                        color.Text
                    )

                    addPreviewStat(
                        "EXTRA "
                            .. formatSignedMailPercent(
                                entry.ExtraPercent
                            ),
                        formatSignedMailValue(
                            entry.Extra
                        ),
                        228,
                        entry.Extra >= 0
                                and color.Green
                            or color.Yellow
                    )

                    addPreviewStat(
                        "FRUITS",
                        tostring(
                            #entry.Fruits
                        ),
                        336,
                        color.Text
                    )

                    addPreviewStat(
                        "MAIL USES",
                        tostring(
                            entry.Mails
                        ),
                        444,
                        color.Text
                    )

                    local viewButton =
                        button(
                            row,
                            #entry.Fruits > 0
                                    and "View Selected Fruits"
                                or "No Fruits Selected",
                            UDim2.new(
                                1,
                                -24,
                                0,
                                25
                            ),
                            UDim2.fromOffset(
                                12,
                                84
                            ),
                            false
                        )

                    viewButton.TextSize =
                        12

                    viewButton.TextColor3 =
                        #entry.Fruits > 0
                                and color.Accent
                            or color.Muted

                    viewButton.Active =
                        #entry.Fruits > 0

                    local viewStroke =
                        viewButton:FindFirstChildOfClass(
                            "UIStroke"
                        )

                    if viewStroke
                        and #entry.Fruits > 0
                    then
                        viewStroke.Color =
                            Color3.fromRGB(
                                67,
                                135,
                                235
                            )
                    end

                    viewButton.MouseButton1Click:Connect(function()
                        if not viewButton.Active then
                            return
                        end

                        if type(showFruitPreview)
                            == "function"
                        then
                            showFruitPreview(
                                entry
                            )
                        end
                    end)
                end
            end

            local seconds =
                totalMails <= 1
                    and 0
                or (
                    totalMails - 1
                ) * COOLDOWN

            inventoryText.Text =
                string.format(
                    "%d available · %d favorites · %d filtered",
                    #eligible,
                    protected,
                    filtered
                )

            inventoryText.TextSize =
                8

            previewCount.Text =
                string.format(
                    "%d fruits - %d sends",
                    totalFruits,
                    totalMails
                )

            summaryPeopleValue.Text =
                tostring(
                    #state.Recipients
                )

            summarySendsValue.Text =
                tostring(
                    totalMails
                )

            summaryFruitsValue.Text =
                tostring(
                    totalFruits
                )

            summaryTotalValue.Text =
                formatValue(
                    totalValue
                )

            summaryTimeValue.Text =
                seconds > 0
                        and "~"
                            .. tostring(
                                math.ceil(seconds)
                            )
                            .. "s"
                    or "Immediate"

            local remainingUses =
                math.max(
                    0,
                    DAILY_LIMIT
                    - tracker.Used
                )

            local valueSession =
                state.ValueSession

            local valueSessionStatus =
                type(valueSession) == "table"
                and tostring(
                    valueSession.Status
                    or ""
                )
                or ""

            local reviewingUncertain =
                valueSessionStatus
                == "Uncertain"

            local resumingDelivery =
                valueSessionStatus
                == "Paused"

            local canSend =
                reviewingUncertain
                or resumingDelivery
                or (
                    #plan > 0
                    and totalMails > 0
                    and incomplete == 0
                    and overpayBlocked == 0
                    and totalMails <= remainingUses
                )

            sendButton.Active =
                canSend

            sendButton.AutoButtonColor =
                canSend

            sendButton.BackgroundColor3 =
                canSend
                        and color.Accent
                    or color.Hover

            sendButton.TextColor3 =
                canSend
                        and color.Text
                    or color.Muted

            sendButton.Text =
                reviewingUncertain
                        and "Review uncertain mail"
                    or resumingDelivery
                            and "Resume remaining delivery"
                        or "Review and send"

            if reviewingUncertain then
                messageText.Text =
                    "A mail was accepted, but item removal could not be confirmed."

                messageText.TextColor3 =
                    color.Red
            elseif resumingDelivery
                and totalMails <= 0
            then
                messageText.Text =
                    "No remaining batches. Press Resume to finish the session."

                messageText.TextColor3 =
                    color.Green
            elseif #inventory == 0
                and unvalued > 0
            then
                messageText.Text =
                    "Fruit values aren't ready. Load HOLY, then refresh the preview."

                messageText.TextColor3 =
                    color.Red
            elseif #state.Recipients == 0 then
                messageText.Text =
                    "Add a recipient and target."
            elseif overpayBlocked > 0 then
                messageText.Text =
                    tostring(
                        overpayBlocked
                    )
                    .. (
                        overpayBlocked == 1
                            and " target cannot be reached within the maximum extra value."
                            or " targets cannot be reached within the maximum extra value."
                    )

                messageText.TextColor3 =
                    color.Red
            elseif incomplete > 0 then
                messageText.Text =
                    tostring(
                        incomplete
                    )
                    .. " target(s) cannot be completed."
            elseif totalMails > remainingUses then
                messageText.Text =
                    "This needs more sends than you have left today."
            else
                messageText.Text =
                    "Everything is ready. Review it before sending."
            end

            state.Busy =
                false

            if reviewingUncertain then
                setStatus(
                    "Confirmation uncertain",
                    color.Red
                )
            elseif resumingDelivery then
                setStatus(
                    "Paused",
                    color.Yellow
                )
            else
                setStatus(
                    "Ready",
                    color.Green
                )
            end
        end

    local function closeModal()
        overlay.Visible =
            false

        for _, child in ipairs(
            overlay:GetChildren()
        ) do
            child:Destroy()
        end
    end

    local function showModal(
        titleValue,
        bodyValue,
        confirmValue,
        callback,
        warning
    )
        closeModal()

        overlay.Visible =
            true

        local modal =
            create(
                "Frame",
                {
                    AnchorPoint =
                        Vector2.new(
                            0.5,
                            0.5
                        ),

                    Position =
                        UDim2.fromScale(
                            0.5,
                            0.5
                        ),

                    Size =
                        UDim2.fromOffset(
                            430,
                            270
                        ),

                    BackgroundColor3 =
                        color.Card,

                    ZIndex =
                        51,
                },
                overlay
            )

        round(
            modal,
            18
        )

        outline(
            modal,
            warning
                    and color.Accent
                or color.Border
        )

        local heading =
            text(
                modal,
                titleValue,
                UDim2.new(
                    1,
                    -36,
                    0,
                    28
                ),
                UDim2.fromOffset(
                    18,
                    17
                ),
                18,
                color.Text,
                nil,
                Enum.Font.GothamBold
            )

        heading.ZIndex =
            52

        local body =
            text(
                modal,
                bodyValue,
                UDim2.new(
                    1,
                    -36,
                    0,
                    135
                ),
                UDim2.fromOffset(
                    18,
                    57
                ),
                11,
                color.Muted
            )

        body.TextWrapped =
            true

        body.TextYAlignment =
            Enum.TextYAlignment.Top

        body.ZIndex =
            52

        local cancel =
            button(
                modal,
                callback
                        and "Cancel"
                    or "Close",
                UDim2.fromOffset(
                    callback
                            and 112
                        or 394,
                    46
                ),
                UDim2.fromOffset(
                    18,
                    207
                ),
                false
            )

        cancel.ZIndex =
            53

        cancel.MouseButton1Click:Connect(
            closeModal
        )

        if callback then
            local confirm =
                button(
                    modal,
                    confirmValue,
                    UDim2.fromOffset(
                        266,
                        46
                    ),
                    UDim2.fromOffset(
                        146,
                        207
                    ),
                    true
                )

            confirm.ZIndex =
                53

            confirm.MouseButton1Click:Connect(function()
                closeModal()
                callback()
            end)
        end
    end

    state.SavedRecipients.Commit =
        function(
            records,
            recent
        )
            HOLY_MAIL_STATE.SavedRecipients =
                HolyMailNormalizeRecipientRecords(
                    records,
                    25,
                    true
                )

            HOLY_MAIL_STATE.RecentRecipients =
                HolyMailNormalizeRecipientRecords(
                    recent,
                    8,
                    false
                )

            state.SavedRecipients.Records =
                HOLY_MAIL_STATE.SavedRecipients

            state.SavedRecipients.Recent =
                HOLY_MAIL_STATE.RecentRecipients

            HolyMailSaveSettings()
            state.SavedRecipients.UpdateButtons()
        end

    state.SavedRecipients.Show =
        function(
            targetBox
        )
            if state.RecipientChangesLocked() then
                HolyNotify(
                    "HOLY Mail",
                    "Finish or safely end the paused delivery before changing recipients.",
                    4
                )

                return
            end

            if typeof(targetBox) ~= "Instance"
                or not targetBox:IsA(
                    "TextBox"
                )
            then
                targetBox =
                    recipientBox
            end

            local draft = {
