                        -36,
                        0,
                        40
                    ),
                    UDim2.fromOffset(
                        18,
                        78
                    )
                )

            searchBox.ZIndex =
                53

            local contactStatus =
                text(
                    modal,
                    "",
                    UDim2.new(
                        1,
                        -36,
                        0,
                        18
                    ),
                    UDim2.fromOffset(
                        18,
                        119
                    ),
                    9,
                    color.Muted,
                    Enum.TextXAlignment.Right,
                    Enum.Font.GothamMedium
                )

            contactStatus.ZIndex =
                52

            local contactList =
                create(
                    "ScrollingFrame",
                    {
                        BackgroundColor3 =
                            color.Field,

                        BorderSizePixel =
                            0,

                        Size =
                            UDim2.new(
                                1,
                                -36,
                                0,
                                294
                            ),

                        Position =
                            UDim2.fromOffset(
                                18,
