            favoriteDraftButton.ZIndex =
                53

            saveContactButton.ZIndex =
                53

            local managerStatus =
                text(
                    modal,
                    "Enter a label and Roblox username to save a new contact.",
                    UDim2.new(
                        1,
                        -36,
                        0,
                        34
                    ),
                    UDim2.fromOffset(
                        18,
                        496
                    ),
                    9,
                    color.Muted,
                    Enum.TextXAlignment.Left,
                    Enum.Font.GothamMedium
                )

            managerStatus.TextWrapped =
                true

            managerStatus.ZIndex =
                52

            local currentInput =
                HolyMailRecipientText(
                    targetBox.Text,
                    80
                )

            if currentInput ~= "" then
                usernameBox.Text =
                    currentInput
            end

            draft.UpdateFavorite =
                function()
                    favoriteDraftButton.Text =
                        draft.Favorite
                                and "★ Favorite"
                            or "☆ Favorite"

                    favoriteDraftButton.BackgroundColor3 =
                        draft.Favorite
                                and color.Accent
                            or color.Field
                end

            draft.ResetEditor =
                function()
                    draft.EditUserId =
                        nil

                    draft.EditOriginalName =
                        ""

                    draft.Favorite =
                        false

                    labelBox.Text =
                        ""

                    usernameBox.Text =
                        ""

                    saveContactButton.Text =
                        "Save"

                    draft.UpdateFavorite()
                end

            draft.Matches =
                function(
                    record
                )
                    local query =
                        HolyMailFilterKey(
                            draft.Search
                        )

                    if query == "" then
                        return true
                    end

                    local searchable =
                        HolyMailFilterKey(
                            tostring(
                                record.Label
                                    or ""
                            )
                            .. " "
                            .. tostring(
                                record.Name
                                    or ""
                            )
                            .. " "
                            .. tostring(
                                record.UserId
                                    or ""
                            )
                        )

                    return searchable:find(
                        query,
                        1,
                        true
                    ) ~= nil
                end

            draft.Render =
                function()
                    clearRows(
                        contactList,
                        contactLayout
                    )

                    draft.Records =
                        HolyMailNormalizeRecipientRecords(
                            draft.Records,
                            25,
                            true
                        )

                    draft.Recent =
                        HolyMailNormalizeRecipientRecords(
                            draft.Recent,
                            8,
                            false
                        )

                    local savedMap = {}
                    local visibleSaved = 0
                    local visibleRecent = 0
                    local layoutOrder = 0

                    for _, record in ipairs(
                        draft.Records
                    ) do
                        savedMap[
                            record.UserId
                        ] =
                            true
                    end

                    draft.AddSection =
                        function(
                            caption
                        )
                            layoutOrder +=
                                1

                            local section =
                                text(
                                    contactList,
                                    caption,
                                    UDim2.new(
                                        1,
                                        -4,
                                        0,
                                        24
                                    ),
                                    UDim2.fromOffset(
                                        0,
                                        0
                                    ),
                                    9,
                                    color.Muted,
                                    Enum.TextXAlignment.Left,
                                    Enum.Font.GothamBold
                                )

                            section.LayoutOrder =
                                layoutOrder

                            section.ZIndex =
                                53

                            create(
                                "UIPadding",
                                {
                                    PaddingLeft =
                                        UDim.new(
                                            0,
                                            6
                                        ),
                                },
                                section
                            )
                        end

                    draft.AddRow =
                        function(
                            record,
                            recent
                        )
                            layoutOrder +=
                                1

                            local row =
                                create(
                                    "Frame",
                                    {
                                        BackgroundColor3 =
                                            color.Card,

                                        Size =
                                            UDim2.new(
                                                1,
                                                -4,
                                                0,
                                                62
                                            ),

                                        LayoutOrder =
                                            layoutOrder,

                                        ZIndex =
                                            53,
                                    },
                                    contactList
                                )

                            round(
                                row,
                                10
                            )

                            outline(
                                row,
                                record.Favorite
                                        and color.Accent
                                    or color.Border
                            )

                            local avatar =
                                addAvatar(
                                    row,
                                    record.UserId,
                                    UDim2.fromOffset(
                                        38,
                                        38
                                    ),
                                    UDim2.fromOffset(
                                        10,
                                        12
                                    )
                                )

                            avatar.ZIndex =
                                54

                            local favoriteButton =
                                button(
                                    row,
                                    record.Favorite
                                            and "★"
                                            or "☆",
                                    UDim2.fromOffset(
                                        32,
                                        32
                                    ),
                                    UDim2.fromOffset(
                                        55,
                                        15
                                    ),
                                    record.Favorite == true
                                )

                            favoriteButton.ZIndex =
                                54

                            favoriteButton.Visible =
                                not recent

                            local displayLabel =
                                text(
                                    row,
                                    recent
                                            and (
                                                "@"
                                                .. record.Name
                                            )
                                            or tostring(
                                                record.Label
                                                    or record.Name
                                            ),
                                    UDim2.new(
                                        1,
                                        -310,
                                        0,
                                        21
                                    ),
                                    UDim2.fromOffset(
                                        96,
                                        8
                                    ),
                                    10,
                                    color.Text,
                                    Enum.TextXAlignment.Left,
                                    Enum.Font.GothamSemibold
                                )

                            displayLabel.ZIndex =
                                54

                            local identity =
                                text(
                                    row,
                                    recent
                                        and (
                                            "Recently used · "
                                            .. tostring(
                                                record.UserId
                                            )
                                        )
                                        or (
                                            "@"
                                            .. record.Name
                                            .. " · "
                                            .. tostring(
                                                record.UserId
                                            )
                                        ),
                                    UDim2.new(
                                        1,
                                        -310,
                                        0,
                                        18
                                    ),
                                    UDim2.fromOffset(
                                        96,
                                        33
                                    ),
                                    8,
                                    color.Muted
                                )

                            identity.ZIndex =
                                54

                            local useButton =
                                button(
                                    row,
                                    "Use",
                                    UDim2.fromOffset(
                                        60,
                                        34
                                    ),
                                    UDim2.new(
                                        1,
                                        -184,
                                        0,
                                        14
                                    ),
                                    true
                                )

                            local manageButton =
                                button(
                                    row,
                                    recent
                                        and "Save"
                                        or "Edit",
                                    UDim2.fromOffset(
                                        54,
                                        34
                                    ),
                                    UDim2.new(
                                        1,
                                        -116,
                                        0,
                                        14
                                    ),
                                    false
                                )

                            local deleteButton =
                                button(
                                    row,
                                    "X",
                                    UDim2.fromOffset(
                                        42,
                                        34
                                    ),
                                    UDim2.new(
                                        1,
                                        -54,
                                        0,
                                        14
                                    ),
                                    false
                                )

                            useButton.ZIndex =
                                54

                            manageButton.ZIndex =
                                54

                            deleteButton.ZIndex =
                                54

                            useButton.TextSize =
                                9

                            manageButton.TextSize =
                                8

                            deleteButton.TextSize =
                                10

                            deleteButton.Visible =
                                not recent

                            useButton.MouseButton1Click:Connect(function()
                                if state.RecipientChangesLocked() then
                                    return
                                end

                                useButton.Text =
                                    "Checking"

                                local userId,
                                    username,
                                    resolveError =
                                    HolyMailResolveRecipient(
                                        tostring(
                                            record.UserId
                                        )
                                    )

                                if not userId then
                                    managerStatus.Text =
                                        tostring(
                                            resolveError
                                                or "Recipient could not be verified."
                                        )

                                    managerStatus.TextColor3 =
                                        color.Red

                                    useButton.Text =
                                        "Use"

                                    return
                                end

                                targetBox.Text =
                                    username

                                HolyMailTouchRecipient(
                                    userId,
                                    username
                                )

                                closeModal()
                            end)

                            favoriteButton.MouseButton1Click:Connect(function()
                                if recent
                                    or state.RecipientChangesLocked()
                                then
                                    return
                                end

                                for _, savedRecord in ipairs(
                                    draft.Records
                                ) do
                                    if savedRecord.UserId
                                        == record.UserId
                                    then
                                        savedRecord.Favorite =
                                            not savedRecord.Favorite

                                        break
                                    end
                                end

                                state.SavedRecipients.Commit(
                                    draft.Records,
                                    draft.Recent
                                )

                                draft.Render()
                            end)

                            manageButton.MouseButton1Click:Connect(function()
                                draft.EditUserId =
                                    recent
                                    and nil
                                    or record.UserId

                                draft.EditOriginalName =
                                    recent
                                    and ""
                                    or record.Name

                                draft.Favorite =
                                    recent
                                    and false
                                    or record.Favorite == true

                                labelBox.Text =
                                    recent
                                    and record.Name
                                    or tostring(
                                        record.Label
                                            or record.Name
                                    )

                                usernameBox.Text =
                                    record.Name

                                saveContactButton.Text =
                                    recent
                                        and "Save"
                                        or "Update"

                                draft.UpdateFavorite()

                                managerStatus.Text =
                                    recent
                                        and "Choose a label, then save this recent recipient."
                                        or "Edit the label, username, or favorite status."

                                managerStatus.TextColor3 =
                                    color.Muted
                            end)

                            deleteButton.MouseButton1Click:Connect(function()
                                if recent
                                    or state.RecipientChangesLocked()
                                then
                                    return
                                end

                                for index,
                                    savedRecord in ipairs(
                                    draft.Records
                                ) do
                                    if savedRecord.UserId
                                        == record.UserId
                                    then
                                        table.remove(
                                            draft.Records,
                                            index
                                        )

                                        break
                                    end
                                end

                                if draft.EditUserId
                                    == record.UserId
                                then
                                    draft.ResetEditor()
                                end

                                state.SavedRecipients.Commit(
                                    draft.Records,
                                    draft.Recent
                                )

                                draft.Render()
                            end)
                        end

                    draft.AddSection(
                        "SAVED RECIPIENTS"
                    )

                    for _, record in ipairs(
                        draft.Records
                    ) do
                        if draft.Matches(
                            record
                        ) then
                            visibleSaved +=
                                1

                            draft.AddRow(
                                record,
                                false
                            )
                        end
                    end

                    draft.AddSection(
                        "RECENT"
                    )

                    for _, record in ipairs(
                        draft.Recent
                    ) do
                        if not savedMap[
                            record.UserId
                        ]
                            and draft.Matches(
                                record
                            )
                        then
                            visibleRecent +=
                                1

                            draft.AddRow(
                                record,
                                true
                            )
                        end
                    end

                    if visibleSaved <= 0
                        and visibleRecent <= 0
                    then
                        layoutOrder +=
                            1

                        local empty =
                            text(
                                contactList,
                                "No matching saved or recent recipients.",
                                UDim2.new(
                                    1,
                                    -4,
                                    0,
                                    80
                                ),
                                UDim2.fromOffset(
                                    0,
                                    0
                                ),
                                10,
                                color.Muted,
                                Enum.TextXAlignment.Center,
                                Enum.Font.GothamMedium
                            )

                        empty.LayoutOrder =
                            layoutOrder

                        empty.ZIndex =
                            53
                    end

                    contactStatus.Text =
                        tostring(
                            #draft.Records
                        )
                        .. " / 25 saved · "
                        .. tostring(
                            visibleRecent
                        )
                        .. " recent shown"
                end

            searchBox:GetPropertyChangedSignal(
                "Text"
            ):Connect(function()
                draft.Search =
                    searchBox.Text

                draft.Render()
            end)

            favoriteDraftButton.MouseButton1Click:Connect(function()
                draft.Favorite =
                    not draft.Favorite

                draft.UpdateFavorite()
            end)

            saveContactButton.MouseButton1Click:Connect(function()
                if state.RecipientChangesLocked() then
                    return
                end

                local raw =
                    HolyMailRecipientText(
                        usernameBox.Text,
                        80
                    )

                local resolveInput =
                    raw

                if draft.EditUserId
                    and HolyMailFilterKey(
                        raw
                    ) == HolyMailFilterKey(
                        draft.EditOriginalName
                    )
                then
                    resolveInput =
                        tostring(
                            draft.EditUserId
                        )
                end

                saveContactButton.Text =
                    "Checking"

                local userId,
                    username,
                    resolveError =
                    HolyMailResolveRecipient(
                        resolveInput
                    )

                if not userId then
                    managerStatus.Text =
                        tostring(
                            resolveError
                                or "Recipient could not be verified."
                        )

                    managerStatus.TextColor3 =
                        color.Red

                    saveContactButton.Text =
                        draft.EditUserId
                            and "Update"
                            or "Save"

                    return
                end

                local duplicateIndex
                local editingIndex

                for index, record in ipairs(
                    draft.Records
                ) do
                    if record.UserId == userId then
                        duplicateIndex =
                            index
                    end

                    if draft.EditUserId
                        and record.UserId
                            == draft.EditUserId
                    then
                        editingIndex =
                            index
                    end
                end

                if duplicateIndex
                    and duplicateIndex
                        ~= editingIndex
                then
                    managerStatus.Text =
                        "That UserId is already saved."

                    managerStatus.TextColor3 =
                        color.Yellow

                    saveContactButton.Text =
                        draft.EditUserId
                            and "Update"
                            or "Save"

                    return
                end

                if not editingIndex
                    and #draft.Records >= 25
                then
                    managerStatus.Text =
                        "The saved-recipient limit is 25."

                    managerStatus.TextColor3 =
                        color.Red

                    saveContactButton.Text =
                        "Save"

                    return
                end

                local label =
                    HolyMailRecipientText(
                        labelBox.Text,
                        36
                    )

                if label == "" then
                    label =
                        username
                end

                local previous =
                    editingIndex
                    and draft.Records[
                        editingIndex
                    ]
                    or nil

                local record = {
                    UserId =
                        userId,

                    Name =
                        username,

                    Label =
                        label,

                    Favorite =
                        draft.Favorite == true,

                    LastUsedAt =
                        previous
                        and previous.LastUsedAt
                        or 0,

                    AddedAt =
                        previous
                        and previous.AddedAt
                        or os.time(),
                }

                if editingIndex then
                    draft.Records[
                        editingIndex
                    ] =
                        record
                else
                    table.insert(
                        draft.Records,
                        record
                    )
                end

                state.SavedRecipients.Commit(
                    draft.Records,
                    draft.Recent
                )

                draft.Records =
                    HolyMailNormalizeRecipientRecords(
                        HOLY_MAIL_STATE.SavedRecipients,
                        25,
                        true
                    )

                draft.ResetEditor()

                managerStatus.Text =
                    "@"
                    .. username
                    .. " was saved."

                managerStatus.TextColor3 =
                    color.Green

                draft.Render()
            end)

            draft.UpdateFavorite()
            draft.Render()
        end

    state.SavedRecipients.ValueButton.MouseButton1Click:Connect(function()
        state.SavedRecipients.Show(
            recipientBox
        )
    end)

    state.Filters.Show =
        function()
            if state.Running
                or state.Busy
            then
                return
            end

            if type(
                state.ValueSession
            ) == "table"
                and state.ValueSession.Status
                    ~= "Complete"
            then
                messageText.Text =
                    "Finish or safely end the paused delivery before changing filters."

                messageText.TextColor3 =
                    color.Yellow

                return
            end

            local inventory =
                scanInventory()

            local draft = {
                Tab = "Fruits",
                Search = "",

                Fruits =
                    HolyMailFilterSelectionMap(
                        state.Filters.Fruits
                    ),

                Mutations =
                    HolyMailFilterSelectionMap(
                        state.Filters.Mutations
                    ),

                FruitOptionsMap = {},
                MutationOptionsMap = {},

                FruitIcons = {},
                FruitOwned = {},
                MutationOwned = {},
            }

            draft.AddOption =
                function(
                    target,
                    value
                )
                    local display =
                        tostring(
                            value or ""
                        )
                            :gsub(
                                "[%c]+",
                                ""
                            )
                            :gsub(
                                "^%s+",
                                ""
                            )
                            :gsub(
                                "%s+$",
                                ""
                            )

                    local key =
                        HolyMailFilterKey(
                            display
                        )

                    if key ~= "" then
                        target[key] =
                            display
                    end
                end

            for _, fruit in ipairs(
                inventory
            ) do
                local fruitKey =
                    HolyMailFilterKey(
                        fruit.Name
                    )

                if fruitKey ~= "" then
                    draft.FruitOwned[
                        fruitKey
                    ] =
                        (
                            tonumber(
                                draft.FruitOwned[
                                    fruitKey
                                ]
                            )
                            or 0
                        )
                        + 1
                end

                local mutationText =
                    tostring(
                        fruit.Mutation
                        or "Normal"
                    )

                local foundMutation =
                    false

                for part in mutationText:gmatch(
                    "[^,%|/;]+"
                ) do
                    local mutationKey =
                        HolyMailFilterKey(
                            part
                        )

                    if mutationKey ~= "" then
                        foundMutation =
                            true

                        draft.MutationOwned[
                            mutationKey
                        ] =
                            (
                                tonumber(
                                    draft.MutationOwned[
                                        mutationKey
                                    ]
                                )
                                or 0
                            )
                            + 1
                    end
                end

                if not foundMutation then
                    draft.MutationOwned.normal =
                        (
                            tonumber(
                                draft.MutationOwned.normal
                            )
                            or 0
                        )
                        + 1
                end
            end

            local seedData

            if type(
                HolyShopRequireModule
            ) == "function" then
                local ok,
                    result =
                    pcall(
                        HolyShopRequireModule,
                        "SharedModules.SeedData"
                    )

                if ok
                    and type(result) == "table"
                then
                    seedData =
                        result
                end
            end

            if type(seedData) == "table" then
                for _, row in pairs(
                    seedData
                ) do
                    if type(row) == "table"
                        and row.MutationSeed
                            ~= true
                    then
                        local fruitName =
                            tostring(
                                row.FruitName
                                or row.SeedName
                                or row.CropName
                                or row.Name
                                or ""
                            )
                                :gsub(
                                    "[%c]+",
                                    ""
                                )
                                :gsub(
                                    "^%s+",
                                    ""
                                )
                                :gsub(
                                    "%s+$",
                                    ""
                                )

                        local fruitKey =
                            HolyMailFilterKey(
                                fruitName
                            )

                        if fruitKey ~= "" then
                            draft.AddOption(
                                draft.FruitOptionsMap,
                                fruitName
                            )

                            local icon =
                                valuePreviewFruitIcon(
                                    nil,
                                    row
                                )

                            if icon ~= "" then
                                draft.FruitIcons[
                                    fruitKey
                                ] =
                                    icon
                            end
                        end
                    end
                end
            end

            if type(
                HolySellGetFruitDropdownValues
            ) == "function" then
                local ok,
                    fruitValues =
                    pcall(
                        HolySellGetFruitDropdownValues
                    )

                if ok
                    and type(fruitValues)
                        == "table"
                then
                    for _, fruitName in ipairs(
                        fruitValues
                    ) do
                        if HolyMailFilterKey(
                            fruitName
                        ) ~= "all"
                        then
                            draft.AddOption(
                                draft.FruitOptionsMap,
                                fruitName
                            )
                        end
                    end
                end
            end

            if type(
                HolyFarmBuildMutationNameCache
            ) == "function" then
                local ok,
                    mutationCache =
                    pcall(
                        HolyFarmBuildMutationNameCache,
                        true
                    )

                if ok
                    and type(mutationCache)
                        == "table"
                    and type(
                        mutationCache.Values
                    ) == "table"
                then
                    for _, mutationName in ipairs(
                        mutationCache.Values
                    ) do
                        draft.AddOption(
                            draft.MutationOptionsMap,
                            mutationName
                        )
                    end
                end
            end

            draft.AddOption(
                draft.MutationOptionsMap,
                "Normal"
            )

            for _, display in pairs(
                draft.Fruits
            ) do
                draft.AddOption(
                    draft.FruitOptionsMap,
                    display
                )
            end

            for _, display in pairs(
                draft.Mutations
            ) do
                draft.AddOption(
                    draft.MutationOptionsMap,
                    display
                )
            end

            draft.FruitOptions = {}
            draft.MutationOptions = {}

            for _, display in pairs(
                draft.FruitOptionsMap
            ) do
                table.insert(
                    draft.FruitOptions,
                    display
                )
            end

            for _, display in pairs(
                draft.MutationOptionsMap
            ) do
                table.insert(
                    draft.MutationOptions,
                    display
                )
            end

            table.sort(
                draft.FruitOptions,
                function(left, right)
                    return tostring(
                        left
                    ):lower()
                        < tostring(
                            right
                        ):lower()
                end
            )

            table.sort(
                draft.MutationOptions,
                function(left, right)
                    return tostring(
                        left
                    ):lower()
                        < tostring(
                            right
                        ):lower()
                end
            )

            closeModal()

            overlay.Visible =
                true

            local modal =
                create(
                    "Frame",
                    {
                        AnchorPoint =
                            Vector2.new(
                                0.5,
                                0.5
                            ),

                        Position =
                            UDim2.fromScale(
                                0.5,
                                0.5
                            ),

                        Size =
                            UDim2.fromOffset(
                                620,
                                530
                            ),

                        BackgroundColor3 =
                            color.Card,

                        ZIndex =
                            51,
                    },
                    overlay
                )

            round(
                modal,
                18
            )

            outline(
                modal,
                color.Border
            )

            local heading =
                text(
                    modal,
                    "Fruit & Mutation Filters",
                    UDim2.new(
                        1,
                        -36,
                        0,
                        28
                    ),
                    UDim2.fromOffset(
                        18,
                        15
                    ),
                    18,
                    color.Text,
                    nil,
                    Enum.Font.GothamBold
                )

            heading.ZIndex =
                52

            local subtitle =
                text(
                    modal,
                    "All in-game options are shown. Owned counts come from your current inventory.",
                    UDim2.new(
                        1,
                        -36,
                        0,
                        20
                    ),
                    UDim2.fromOffset(
                        18,
                        46
                    ),
                    9,
                    color.Muted
                )

            subtitle.ZIndex =
                52

            local searchBox =
                box(
                    modal,
                    "Search fruits or mutations",
                    UDim2.new(
                        1,
                        -36,
                        0,
                        42
                    ),
                    UDim2.fromOffset(
                        18,
                        75
                    )
                )

            searchBox.ZIndex =
                53

            local fruitTab =
                button(
                    modal,
                    "Fruits",
                    UDim2.fromOffset(
                        280,
                        38
                    ),
                    UDim2.fromOffset(
                        18,
                        128
                    ),
                    true
                )

            local mutationTab =
                button(
                    modal,
                    "Mutations",
                    UDim2.fromOffset(
                        280,
                        38
                    ),
                    UDim2.fromOffset(
                        322,
                        128
                    ),
                    false
                )

            fruitTab.ZIndex =
                53

            mutationTab.ZIndex =
                53

            local selectAllButton =
                button(
                    modal,
                    "Select visible",
                    UDim2.fromOffset(
                        138,
                        36
                    ),
                    UDim2.fromOffset(
                        18,
                        177
                    ),
                    false
                )

            local clearSelectionButton =
                button(
                    modal,
                    "Clear selection",
                    UDim2.fromOffset(
                        138,
                        36
                    ),
                    UDim2.fromOffset(
                        166,
                        177
                    ),
                    false
                )

            selectAllButton.ZIndex =
                53

            clearSelectionButton.ZIndex =
                53

            local selectionStatus =
                text(
                    modal,
                    "All selected",
                    UDim2.fromOffset(
                        280,
                        36
                    ),
                    UDim2.fromOffset(
                        322,
                        177
                    ),
                    9,
                    color.Muted,
                    Enum.TextXAlignment.Right,
                    Enum.Font.GothamMedium
                )

            selectionStatus.ZIndex =
                52

            local optionList =
                create(
                    "ScrollingFrame",
                    {
                        BackgroundColor3 =
                            color.Field,

                        BorderSizePixel =
                            0,

                        Size =
                            UDim2.new(
                                1,
                                -36,
                                0,
                                224
                            ),

                        Position =
                            UDim2.fromOffset(
                                18,
                                222
                            ),

                        CanvasSize =
                            UDim2.fromOffset(
                                0,
                                0
                            ),

                        AutomaticCanvasSize =
                            Enum.AutomaticSize.Y,

                        ScrollingDirection =
                            Enum.ScrollingDirection.Y,

                        ScrollBarThickness =
                            3,

                        ScrollBarImageColor3 =
                            color.Border,

                        ClipsDescendants =
                            true,

                        ZIndex =
                            52,
                    },
                    modal
                )

            round(
                optionList,
                11
            )

            outline(
                optionList,
                color.Border
            )

            local optionLayout =
                create(
                    "UIListLayout",
                    {
                        Padding =
                            UDim.new(
                                0,
                                5
                            ),

                        SortOrder =
                            Enum.SortOrder.LayoutOrder,
                    },
                    optionList
                )

            local optionPadding =
                create(
                    "UIPadding",
                    {
                        PaddingTop =
                            UDim.new(
                                0,
                                6
                            ),

                        PaddingBottom =
                            UDim.new(
                                0,
                                6
                            ),

                        PaddingLeft =
                            UDim.new(
                                0,
                                6
                            ),

                        PaddingRight =
                            UDim.new(
                                0,
                                6
                            ),
                    },
                    optionList
                )

            draft.RefreshTabs =
                function()
                    fruitTab.BackgroundColor3 =
                        draft.Tab == "Fruits"
                                and color.Accent
                            or color.Field

                    mutationTab.BackgroundColor3 =
                        draft.Tab == "Mutations"
                                and color.Accent
                            or color.Field

                    fruitTab.TextColor3 =
                        draft.Tab == "Fruits"
                                and color.Text
                            or color.Secondary

                    mutationTab.TextColor3 =
                        draft.Tab == "Mutations"
                                and color.Text
                            or color.Secondary
                end

            draft.Render =
                function()
                    clearRows(
                        optionList,
                        optionLayout
                    )

                    local options =
                        draft.Tab == "Fruits"
                        and draft.FruitOptions
                        or draft.MutationOptions

                    local selected =
                        draft.Tab == "Fruits"
                        and draft.Fruits
                        or draft.Mutations

                    local query =
                        HolyMailFilterKey(
                            draft.Search
                        )

                    local visibleCount = 0
                    local selectedCount = 0

                    for _ in pairs(
                        selected
                    ) do
                        selectedCount +=
                            1
                    end

                    for optionIndex, display in ipairs(
                        options
                    ) do
                        local optionKey =
                            HolyMailFilterKey(
                                display
                            )

                        if query == ""
                            or optionKey:find(
                                query,
                                1,
                                true
                            )
                        then
                            visibleCount +=
                                1

                            local isSelected =
                                selected[
                                    optionKey
                                ] ~= nil

                            local ownedMap =
                                draft.Tab == "Fruits"
                                and draft.FruitOwned
                                or draft.MutationOwned

                            local owned =
                                tonumber(
                                    ownedMap[
                                        optionKey
                                    ]
                                )
                                or 0

                            local icon =
                                draft.Tab == "Fruits"
                                and tostring(
                                    draft.FruitIcons[
                                        optionKey
                                    ]
                                    or ""
                                )
                                or ""

                            local optionButton =
                                button(
                                    optionList,
                                    isSelected
                                        and "✓"
                                        or "",
                                    UDim2.new(
                                        1,
                                        -4,
                                        0,
                                        42
                                    ),
                                    UDim2.fromOffset(
                                        0,
                                        0
                                    ),
                                    isSelected
                                )

                            optionButton.LayoutOrder =
                                optionIndex

                            optionButton.ZIndex =
                                53

                            optionButton.TextSize =
                                14

                            optionButton.TextXAlignment =
                                Enum.TextXAlignment.Left

                            create(
                                "UIPadding",
                                {
                                    PaddingLeft =
                                        UDim.new(
                                            0,
                                            12
                                        ),

                                    PaddingRight =
                                        UDim.new(
                                            0,
                                            12
                                        ),
                                },
                                optionButton
                            )

                            local nameOffset =
                                34

                            if icon ~= "" then
                                create(
                                    "ImageLabel",
                                    {
                                        BackgroundTransparency =
                                            1,

                                        Image =
                                            icon,

                                        Size =
                                            UDim2.fromOffset(
                                                26,
                                                26
                                            ),

                                        Position =
                                            UDim2.fromOffset(
                                                34,
                                                8
                                            ),

                                        ScaleType =
                                            Enum.ScaleType.Fit,

                                        ZIndex =
                                            54,
                                    },
                                    optionButton
                                )

                                nameOffset =
                                    68
                            end

                            local optionName =
                                text(
                                    optionButton,
                                    display,
                                    UDim2.new(
                                        1,
                                        -nameOffset
                                            - 126,
                                        1,
                                        0
                                    ),
                                    UDim2.fromOffset(
                                        nameOffset,
                                        0
                                    ),
                                    10,
                                    color.Text,
                                    Enum.TextXAlignment.Left,
                                    Enum.Font.GothamSemibold
                                )

                            optionName.ZIndex =
                                54

                            local ownedText =
                                text(
                                    optionButton,
                                    "Owned: "
                                        .. tostring(
                                            owned
                                        ),
                                    UDim2.fromOffset(
                                        104,
                                        42
                                    ),
                                    UDim2.new(
                                        1,
                                        -116,
                                        0,
                                        0
                                    ),
                                    9,
                                    owned > 0
                                        and color.Green
                                        or color.Muted,
                                    Enum.TextXAlignment.Right,
                                    Enum.Font.GothamMedium
                                )

                            ownedText.ZIndex =
                                54

                            optionButton.MouseButton1Click:Connect(function()
                                if selected[
                                    optionKey
                                ] ~= nil
                                then
                                    selected[
                                        optionKey
                                    ] =
                                        nil
                                else
                                    selected[
                                        optionKey
                                    ] =
                                        display
                                end

                                draft.Render()
                            end)
                        end
                    end

                    selectionStatus.Text =
                        selectedCount <= 0
                                and "All allowed · "
                                    .. tostring(
                                        visibleCount
                                    )
                                    .. " shown"
                            or tostring(
                                selectedCount
                            )
                                .. " selected · "
                                .. tostring(
                                    visibleCount
                                )
                                .. " shown"

                    if visibleCount <= 0 then
                        local empty =
                            text(
                                optionList,
                                "No matching options.",
                                UDim2.new(
                                    1,
                                    -4,
                                    0,
                                    90
                                ),
                                UDim2.fromOffset(
                                    0,
                                    0
                                ),
                                10,
                                color.Muted,
                                Enum.TextXAlignment.Center,
                                Enum.Font.GothamMedium
                            )

                        empty.LayoutOrder =
                            1

                        empty.ZIndex =
                            53
                    end
                end

            fruitTab.MouseButton1Click:Connect(function()
                draft.Tab =
                    "Fruits"

                draft.RefreshTabs()
                draft.Render()
            end)

            mutationTab.MouseButton1Click:Connect(function()
                draft.Tab =
                    "Mutations"

                draft.RefreshTabs()
                draft.Render()
            end)

            searchBox:GetPropertyChangedSignal(
                "Text"
            ):Connect(function()
                draft.Search =
                    searchBox.Text

                draft.Render()
            end)

            selectAllButton.MouseButton1Click:Connect(function()
                local options =
                    draft.Tab == "Fruits"
                    and draft.FruitOptions
                    or draft.MutationOptions

                local selected =
                    draft.Tab == "Fruits"
                    and draft.Fruits
                    or draft.Mutations

                local query =
                    HolyMailFilterKey(
                        draft.Search
                    )

                for _, display in ipairs(
                    options
                ) do
                    local optionKey =
                        HolyMailFilterKey(
                            display
                        )

                    if query == ""
                        or optionKey:find(
                            query,
                            1,
                            true
                        )
                    then
                        selected[
                            optionKey
                        ] =
                            display
                    end
                end

                draft.Render()
            end)

            clearSelectionButton.MouseButton1Click:Connect(function()
                if draft.Tab == "Fruits" then
                    draft.Fruits = {}
                else
                    draft.Mutations = {}
                end

                draft.Render()
            end)

            local cancelButton =
                button(
                    modal,
                    "Cancel",
                    UDim2.fromOffset(
                        180,
                        46
                    ),
                    UDim2.fromOffset(
                        18,
                        466
                    ),
                    false
                )

            local applyButton =
                button(
                    modal,
                    "Apply filters",
                    UDim2.fromOffset(
                        386,
                        46
                    ),
                    UDim2.fromOffset(
                        216,
                        466
                    ),
                    true
                )

            cancelButton.ZIndex =
                53

            applyButton.ZIndex =
                53

            cancelButton.MouseButton1Click:Connect(
                closeModal
            )

            applyButton.MouseButton1Click:Connect(function()
                state.Filters.Fruits =
                    HolyMailFilterSelectionMap(
                        draft.Fruits
                    )

                state.Filters.Mutations =
                    HolyMailFilterSelectionMap(
                        draft.Mutations
                    )

                HOLY_MAIL_STATE.FilterFruits =
                    HolyMailNormalizeFilterSelection(
                        state.Filters.Fruits
                    )

                HOLY_MAIL_STATE.FilterMutations =
                    HolyMailNormalizeFilterSelection(
                        state.Filters.Mutations
                    )

                HolyMailSaveSettings()

                state.Filters.UpdateButton()
                closeModal()

                task.spawn(function()
                    protectedCall(
                        "Mail filters",
                        rebuildPlan
                    )
                end)
            end)

            draft.RefreshTabs()
            draft.Render()
        end

    local function showStrategySettings()
        if state.Running
            or state.Busy
        then
            return
        end

        closeModal()

        overlay.Visible =
            true

        local modal =
            create(
                "Frame",
                {
                    AnchorPoint =
                        Vector2.new(
                            0.5,
                            0.5
                        ),

                    Position =
                        UDim2.fromScale(
                            0.5,
                            0.5
                        ),

                    Size =
                        UDim2.fromOffset(
                            610,
                            405
                        ),

                    BackgroundColor3 =
                        color.Card,

                    ZIndex =
                        51,
                },
                overlay
            )

        round(
            modal,
            18
        )

        outline(
            modal,
            color.Border
        )

        local heading =
            text(
                modal,
                "Value Strategy",
                UDim2.new(
                    1,
                    -36,
                    0,
                    28
                ),
                UDim2.fromOffset(
                    18,
                    16
                ),
                18,
                color.Text,
                nil,
                Enum.Font.GothamBold
            )

        heading.ZIndex =
            52

        local subtitle =
            text(
                modal,
                "Choose how HOLY selects fruits and how much extra value is allowed.",
                UDim2.new(
                    1,
                    -36,
                    0,
                    20
                ),
                UDim2.fromOffset(
                    18,
                    47
                ),
                10,
                color.Muted
            )

        subtitle.ZIndex =
            52

        local draftStrategy =
            HolyMailNormalizeValueStrategy(
                state.Strategy
            )

        local draftLimit =
            HolyMailNormalizeExtraLimitMode(
                state.ExtraLimitMode
            )

        local draftCustom =
            HolyMailNormalizeExtraLimitCustom(
                state.ExtraLimitCustom
            )

        local strategyChoices = {
            "Send at least",
            "Closest amount",
            "Don't go over",
        }

        local limitChoices = {
            "No limit",
            "1%",
            "5%",
            "10%",
            "Custom",
        }

        local strategyButtons = {}
        local limitButtons = {}

        text(
            modal,
            "STRATEGY",
            UDim2.fromOffset(
                200,
                18
            ),
            UDim2.fromOffset(
                18,
                82
            ),
            9,
            color.Muted,
            nil,
            Enum.Font.GothamBold
        ).ZIndex =
            52

        for index, choice in ipairs(
            strategyChoices
        ) do
            local choiceButton =
                button(
                    modal,
                    choice,
                    UDim2.fromOffset(
                        184,
                        40
                    ),
                    UDim2.fromOffset(
                        18
                        + (
                            index - 1
                        ) * 196,
                        105
                    ),
                    false
                )

            choiceButton.ZIndex =
                53

            choiceButton.TextSize =
                10

            strategyButtons[choice] =
                choiceButton
        end

        text(
            modal,
            "MAXIMUM EXTRA VALUE",
            UDim2.fromOffset(
                260,
                18
            ),
            UDim2.fromOffset(
                18,
                166
            ),
            9,
            color.Muted,
            nil,
            Enum.Font.GothamBold
        ).ZIndex =
            52

        for index, choice in ipairs(
            limitChoices
        ) do
            local choiceButton =
                button(
                    modal,
                    choice,
                    UDim2.fromOffset(
                        106,
                        38
                    ),
                    UDim2.fromOffset(
                        18
                        + (
                            index - 1
                        ) * 116,
                        190
                    ),
                    false
                )

            choiceButton.ZIndex =
                53

            choiceButton.TextSize =
                9

            limitButtons[choice] =
                choiceButton
        end

        local customBox =
            create(
                "TextBox",
                {
                    BackgroundColor3 =
                        color.Field,

                    Size =
                        UDim2.new(
                            1,
                            -36,
                            0,
                            43
                        ),

                    Position =
                        UDim2.fromOffset(
                            18,
                            248
                        ),

                    Text =
                        draftCustom,

                    PlaceholderText =
                        "Example: 2.5% or $5M",

                    TextColor3 =
                        color.Text,

                    PlaceholderColor3 =
                        color.Muted,

                    Font =
                        Enum.Font.GothamMedium,

                    TextSize =
                        11,

                    ClearTextOnFocus =
                        false,

                    ZIndex =
                        53,
                },
                modal
            )

        round(
            customBox,
            10
        )

        outline(
            customBox,
            color.Border
        )

        local customHint =
            text(
                modal,
                "Custom accepts a percentage such as 2.5% or a fixed value such as $5M.",
                UDim2.new(
                    1,
                    -36,
                    0,
                    18
                ),
                UDim2.fromOffset(
                    18,
                    296
                ),
                9,
                color.Muted
            )

        customHint.ZIndex =
            52

        local function refreshChoices()
            for choice, choiceButton in pairs(
                strategyButtons
            ) do
                local selected =
                    choice == draftStrategy

                choiceButton.BackgroundColor3 =
                    selected
                            and color.Accent
                        or color.Field

                choiceButton.TextColor3 =
                    selected
                            and color.Text
                        or color.Secondary
            end

            for choice, choiceButton in pairs(
                limitButtons
            ) do
                local selected =
                    choice == draftLimit

                choiceButton.BackgroundColor3 =
                    selected
                            and color.Accent
                        or color.Field

                choiceButton.TextColor3 =
                    selected
                            and color.Text
                        or color.Secondary
            end

            customBox.Visible =
                draftLimit == "Custom"

            customHint.Visible =
                draftLimit == "Custom"
        end

        for choice, choiceButton in pairs(
            strategyButtons
        ) do
            choiceButton.MouseButton1Click:Connect(function()
                draftStrategy =
                    choice

                refreshChoices()
            end)
        end

        for choice, choiceButton in pairs(
            limitButtons
        ) do
            choiceButton.MouseButton1Click:Connect(function()
                draftLimit =
                    choice

                refreshChoices()
            end)
        end

        refreshChoices()

        local cancel =
            button(
                modal,
                "Cancel",
                UDim2.fromOffset(
                    175,
                    46
                ),
                UDim2.fromOffset(
                    18,
                    339
                ),
                false
            )

        cancel.ZIndex =
            53

        cancel.MouseButton1Click:Connect(
            closeModal
        )

        local save =
            button(
                modal,
                "Save settings",
                UDim2.fromOffset(
                    381,
                    46
                ),
                UDim2.fromOffset(
                    211,
                    339
                ),
                true
            )

        save.ZIndex =
            53

        save.MouseButton1Click:Connect(function()
            if draftLimit == "Custom" then
                local custom =
                    HolyMailNormalizeExtraLimitCustom(
                        customBox.Text
                    )

                local valid =
                    false

            if custom:find(
                "%",
                1,
                true
            ) then
                    local percentage =
                        tonumber(
                            custom
                                :gsub(
                                    "%%",
                                    ""
                                )
                                :gsub(
                                    "%s+",
                                    ""
                                )
                        )

                    valid =
                        percentage ~= nil
                        and percentage >= 0
                else
                    local fixed =
                        parseValue(
                            custom
                        )

                    valid =
                        fixed ~= nil
                        and fixed >= 0
                end

                if not valid then
                    customHint.Text =
                        "Enter a valid percentage like 2.5% or value like $5M."

                    customHint.TextColor3 =
                        color.Red

                    return
                end

                draftCustom =
                    custom
            end

            state.Strategy =
                HolyMailNormalizeValueStrategy(
                    draftStrategy
                )

            state.ExtraLimitMode =
                HolyMailNormalizeExtraLimitMode(
                    draftLimit
                )

            state.ExtraLimitCustom =
                HolyMailNormalizeExtraLimitCustom(
                    draftCustom
                )

            HOLY_MAIL_STATE.ValueStrategy =
                state.Strategy

            HOLY_MAIL_STATE.ExtraLimitMode =
                state.ExtraLimitMode

            HOLY_MAIL_STATE.ExtraLimitCustom =
                state.ExtraLimitCustom

            HolyMailSaveSettings()

            updateStrategyButton()
            closeModal()

            task.spawn(function()
                protectedCall(
                    "Strategy settings",
                    rebuildPlan
                )
            end)
        end)
    end

    showFruitPreview =
        function(entry)
            if type(entry) ~= "table" then
                return
            end

            closeModal()

            overlay.Visible =
                true

            local modal =
                create(
                    "Frame",
                    {
                        AnchorPoint =
                            Vector2.new(
                                0.5,
                                0.5
                            ),

                        Position =
                            UDim2.fromScale(
                                0.5,
                                0.5
                            ),

                        Size =
                            UDim2.fromOffset(
                                650,
                                540
                            ),

                        BackgroundColor3 =
                            color.Card,

                        ZIndex =
                            51,
                    },
                    overlay
                )

            round(
                modal,
                18
            )

            outline(
                modal,
                color.Border
            )

            local heading =
                text(
                    modal,
                    "Selected Fruits",
                    UDim2.new(
                        1,
                        -36,
                        0,
                        26
                    ),
                    UDim2.fromOffset(
                        18,
                        13
                    ),
                    17,
                    color.Text,
                    nil,
                    Enum.Font.GothamBold
                )

            heading.ZIndex =
                52

            local subtitleLabel =
                text(
                    modal,
                    "@"
                        .. tostring(
                            entry.Recipient
                            and entry.Recipient.Name
                            or "Unknown"
                        )
                        .. "  ·  "
                        .. tostring(
                            #(
                                entry.Fruits
                                or {}
                            )
                        )
                        .. " fruits  ·  "
                        .. tostring(
                            entry.Mails
                            or 0
                        )
                        .. (
                            tonumber(
                                entry.Mails
                            ) == 1
                                and " mail"
                                or " mails"
                        ),
                    UDim2.new(
                        1,
                        -36,
                        0,
                        20
                    ),
                    UDim2.fromOffset(
                        18,
                        40
                    ),
                    9,
                    color.Muted
                )

            subtitleLabel.ZIndex =
                52

            local summaryStrip =
                create(
                    "Frame",
                    {
                        BackgroundColor3 =
                            color.Field,

                        Size =
                            UDim2.new(
                                1,
                                -36,
                                0,
                                70
                            ),

                        Position =
                            UDim2.fromOffset(
                                18,
                                69
                            ),

                        ZIndex =
                            52,
                    },
                    modal
                )

            round(
                summaryStrip,
                11
            )

            outline(
                summaryStrip,
                color.Border
            )

            local function addModalStat(
                titleValue,
                valueText,
                x,
                width,
                valueColor
            )
                local titleLabel =
                    text(
                        summaryStrip,
                        titleValue,
                        UDim2.fromOffset(
                            width,
                            18
                        ),
                        UDim2.fromOffset(
                            x,
                            11
                        ),
                        9,
                        color.Muted,
                        Enum.TextXAlignment.Center,
                        Enum.Font.GothamBold
                    )

                titleLabel.ZIndex =
                    53

                local valueLabel =
                    text(
                        summaryStrip,
                        valueText,
                        UDim2.fromOffset(
                            width,
                            25
                        ),
                        UDim2.fromOffset(
                            x,
                            32
                        ),
                        13,
                        valueColor
                            or color.Text,
                        Enum.TextXAlignment.Center,
                        Enum.Font.GothamBold
                    )

                valueLabel.ZIndex =
                    53
            end

            addModalStat(
                "TARGET",
                formatValue(
                    entry.Target
                    or (
                        entry.Recipient
                        and entry.Recipient.Target
                    )
                    or 0
                ),
                8,
                186,
                color.Text
            )

            addModalStat(
                "SENDING",
                formatValue(
                    entry.Value
                    or 0
                ),
                204,
                186,
                color.Text
            )

            addModalStat(
                "EXTRA "
                    .. formatSignedMailPercent(
                        entry.ExtraPercent
                        or 0
                    ),
                formatSignedMailValue(
                    entry.Extra
                    or 0
                ),
                400,
                186,
                (
                    tonumber(
                        entry.Extra
                    )
                    or 0
                ) >= 0
                        and color.Green
                    or color.Yellow
            )

            local fruitList =
                create(
                    "ScrollingFrame",
                    {
                        BackgroundTransparency =
                            1,

                        BorderSizePixel =
                            0,

                        Size =
                            UDim2.new(
                                1,
                                -36,
                                0,
                                326
                            ),

                        Position =
                            UDim2.fromOffset(
                                18,
                                151
                            ),

                        CanvasSize =
                            UDim2.fromOffset(
                                0,
                                0
                            ),

                        AutomaticCanvasSize =
                            Enum.AutomaticSize.Y,

                        ScrollingDirection =
                            Enum.ScrollingDirection.Y,

                        ScrollBarThickness =
                            3,

                        ScrollBarImageColor3 =
                            color.Border,

                        ClipsDescendants =
                            true,

                        ZIndex =
                            52,
                    },
                    modal
                )

            create(
                "UIListLayout",
                {
                    Padding =
                        UDim.new(
                            0,
                            6
                        ),

                    SortOrder =
                        Enum.SortOrder.LayoutOrder,
                },
                fruitList
            )

            local fruits =
                type(entry.Fruits) == "table"
                and entry.Fruits
                or {}

            local layoutOrder =
                0

            if #fruits == 0 then
                local emptyLabel =
                    text(
                        fruitList,
                        "No fruits were selected for this recipient.",
                        UDim2.new(
                            1,
                            -4,
                            0,
                            120
                        ),
                        UDim2.fromOffset(
                            0,
                            0
                        ),
                        11,
                        color.Muted,
                        Enum.TextXAlignment.Center,
                        Enum.Font.GothamMedium
                    )

                emptyLabel.LayoutOrder =
                    1

                emptyLabel.ZIndex =
                    53
            else
                for firstIndex = 1,
                    #fruits,
                    BATCH_LIMIT
                do
                    local lastIndex =
                        math.min(
                            firstIndex
                                + BATCH_LIMIT
                                - 1,
                            #fruits
                        )

                    local batchNumber =
                        math.floor(
                            (
                                firstIndex - 1
                            )
                            / BATCH_LIMIT
                        )
                        + 1

                    local batchValue =
                        0

                    for fruitIndex = firstIndex,
                        lastIndex
                    do
                        batchValue +=
                            tonumber(
                                fruits[
                                    fruitIndex
                                ].Value
                            )
                            or 0
                    end

                    layoutOrder +=
                        1

                    local batchHeader =
                        create(
                            "Frame",
                            {
                                BackgroundColor3 =
                                    color.Hover,

                                Size =
                                    UDim2.new(
                                        1,
                                        -4,
                                        0,
                                        31
                                    ),

                                LayoutOrder =
                                    layoutOrder,

                                ZIndex =
                                    52,
                            },
                            fruitList
                        )

                    round(
                        batchHeader,
                        9
                    )

                    local batchLabel =
                        text(
                            batchHeader,
                            "MAIL "
                                .. tostring(
                                    batchNumber
                                )
                                .. "  ·  "
                                .. tostring(
                                    lastIndex
                                    - firstIndex
                                    + 1
                                )
                                .. "/"
                                .. tostring(
                                    BATCH_LIMIT
                                )
                                .. " FRUITS  ·  "
                                .. formatValue(
                                    batchValue
                                ),
                            UDim2.new(
                                1,
                                -24,
                                1,
                                0
                            ),
                            UDim2.fromOffset(
                                12,
                                0
                            ),
                            9,
                            color.Secondary,
                            nil,
                            Enum.Font.GothamBold
                        )

                    batchLabel.ZIndex =
                        53

                    for fruitIndex = firstIndex,
                        lastIndex
                    do
                        local fruit =
                            fruits[
                                fruitIndex
                            ]

                        layoutOrder +=
                            1

                        local fruitRow =
                            create(
                                "Frame",
                                {
                                    BackgroundColor3 =
                                        color.Field,

                                    Size =
                                        UDim2.new(
                                            1,
                                            -4,
                                            0,
                                            54
                                        ),

                                    LayoutOrder =
                                        layoutOrder,

                                    ZIndex =
                                        52,
                                },
                                fruitList
                            )

                        round(
                            fruitRow,
                            10
                        )

                        outline(
                            fruitRow,
                            color.Border
                        )

                        local iconHolder =
                            create(
                                "Frame",
                                {
                                    BackgroundColor3 =
                                        color.Hover,

                                    Size =
                                        UDim2.fromOffset(
                                            40,
                                            40
                                        ),

                                    Position =
                                        UDim2.fromOffset(
                                            8,
                                            7
                                        ),

                                    ZIndex =
                                        53,
                                },
                                fruitRow
                            )

                        round(
                            iconHolder,
                            9
                        )

                        local fruitIcon =
                            create(
                                "ImageLabel",
                                {
                                    BackgroundTransparency =
                                        1,

                                    Image =
                                        tostring(
                                            fruit.Icon
                                            or ""
                                        ),

                                    Size =
                                        UDim2.new(
                                            1,
                                            -6,
                                            1,
                                            -6
                                        ),

                                    Position =
                                        UDim2.fromOffset(
                                            3,
                                            3
                                        ),

                                    ScaleType =
                                        Enum.ScaleType.Fit,

                                    ZIndex =
                                        54,
                                },
                                iconHolder
                            )

                        round(
                            fruitIcon,
                            7
                        )

                        local fruitName =
                            text(
                                fruitRow,
                                tostring(
                                    fruit.Name
                                    or "Unknown fruit"
                                ),
                                UDim2.new(
                                    1,
                                    -230,
                                    0,
                                    21
                                ),
                                UDim2.fromOffset(
                                    58,
                                    6
                                ),
                                10,
                                color.Text,
                                nil,
                                Enum.Font.GothamSemibold
                            )

                        fruitName.ZIndex =
                            53

                        local details =
                            tostring(
                                fruit.Mutation
                                or "Normal"
                            )

                        if fruit.Favorite == true then
                            details ..=
                                "  ·  Favorite"
                        end

                        details ..=
                            "  ·  Fruit "
                            .. tostring(
                                fruitIndex
                            )

                        local detailLabel =
                            text(
                                fruitRow,
                                details,
                                UDim2.new(
                                    1,
                                    -230,
                                    0,
                                    18
                                ),
                                UDim2.fromOffset(
                                    58,
                                    29
                                ),
                                8,
                                fruit.Favorite == true
                                        and color.Yellow
                                    or color.Muted
                            )

                        detailLabel.ZIndex =
                            53

                        local valueLabel =
                            text(
                                fruitRow,
                                formatValue(
                                    fruit.Value
                                    or 0
                                ),
                                UDim2.fromOffset(
                                    150,
                                    54
                                ),
                                UDim2.new(
                                    1,
                                    -164,
                                    0,
                                    0
                                ),
                                11,
                                color.Text,
                                Enum.TextXAlignment.Right,
                                Enum.Font.GothamBold
                            )

                        valueLabel.ZIndex =
                            53
                    end
                end
            end

            local closeButton =
                button(
                    modal,
                    "Close",
                    UDim2.new(
                        1,
                        -36,
                        0,
                        38
                    ),
                    UDim2.fromOffset(
                        18,
                        489
                    ),
                    false
                )

            closeButton.ZIndex =
                53

            closeButton.MouseButton1Click:Connect(
                closeModal
            )
        end

    local function getSendPacket()
        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        local networkingModule =
            sharedModules
            and sharedModules:FindFirstChild(
                "Networking"
            )

        if not networkingModule
            or not networkingModule:IsA("ModuleScript")
        then
            return nil,
                "SharedModules.Networking was not found"
        end

        local ok, networking =
            pcall(
                require,
                networkingModule
            )

        if not ok
            or type(networking) ~= "table"
        then
            return nil,
                "Networking require failed: "
                    .. tostring(networking)
        end

        local packet =
            type(networking.Mailbox) == "table"
            and networking.Mailbox.SendBatch
            or nil

        if type(packet) ~= "table"
            or type(packet.Fire) ~= "function"
        then
            return nil,
                "Networking.Mailbox.SendBatch is unavailable"
        end

        return packet
    end

    state.Safety.CurrentFruitMap =
        function()
            local fruits = {}

            for _, root in ipairs(
                getRoots()
            ) do
                for _, item in ipairs(
                    root:GetChildren()
                ) do
                    local id =
                        tostring(
                            item:GetAttribute("Id")
                            or item:GetAttribute("FruitId")
                            or ""
                        )

                    if id ~= "" then
                        fruits[id] =
                            item
                    end
                end
            end

            return fruits
        end

    state.Safety.ItemIsFavorite =
        function(
            item,
            fallback
        )
            if typeof(item) == "Instance" then
                return item:GetAttribute(
                    "IsFavorite"
                ) == true
                    or item:GetAttribute(
                        "Favorite"
                    ) == true
                    or item:GetAttribute(
                        "Favorited"
                    ) == true
            end

            return fallback == true
        end

    state.Safety.ValidateValueBatch =
        function(batch)
            HolyMailCheckDay()
            updateQuota()

            if tracker.Used >= DAILY_LIMIT then
                return false,
                    "No daily sends remain.",
                    "DAILY"
            end

            local owned =
                state.Safety.CurrentFruitMap()

            for _, fruit in ipairs(
                batch
            ) do
                local item =
                    owned[
                        tostring(
                            fruit.Id
                        )
                    ]

                if typeof(item) ~= "Instance" then
                    return false,
                        tostring(
                            fruit.Name
                            or "A selected fruit"
                        )
                        .. " is no longer in your inventory.",
                        "INVENTORY"
                end

                if state.Protect
                    and state.Safety.ItemIsFavorite(
                        item,
                        fruit.Favorite
                    )
                then
                    return false,
                        tostring(
                            fruit.Name
                            or "A selected fruit"
                        )
                        .. " became favorited.",
                        "FAVORITE"
                end
            end

            return true
        end

    state.Safety.WaitForValueRemoval =
        function(
            batch,
            timeout
        )
            local deadline =
                os.clock()
                + (
                    tonumber(timeout)
                    or 8
                )

            repeat
                local owned =
                    state.Safety.CurrentFruitMap()

                local remaining =
                    0

                for _, fruit in ipairs(
                    batch
                ) do
                    if owned[
                        tostring(
                            fruit.Id
                        )
                    ] then
                        remaining +=
                            1
                    end
                end

                if remaining == 0 then
                    return true
                end

                task.wait(
                    0.15
                )
            until os.clock() >= deadline

            return false
        end

    state.Safety.WaitForCooldown =
        function()
            while state.LastAccepted do
                local remaining =
                    COOLDOWN
                    - (
                        workspace:GetServerTimeNow()
                        - state.LastAccepted
                    )

                if remaining <= 0 then
                    return not state.Stop
                end

                if state.Stop then
                    return false
                end

                setStatus(
                    string.format(
                        "%.1fs",
                        remaining
                    ),
                    color.Yellow
                )

                task.wait(
                    math.min(
                        0.1,
                        remaining
                    )
                )
            end

            return not state.Stop
        end

    state.Safety.RecordAcceptedMail =
        function(started)
            state.LastAccepted =
                started

            tracker.Used =
                math.min(
                    DAILY_LIMIT,
                    tracker.Used + 1
                )

            HOLY_MAIL_STATE.TrackerDay =
                HolyMailToday()

            HOLY_MAIL_STATE.TrackerUsed =
                tracker.Used

            updateQuota()
            HolyMailSaveSettings()
        end

    state.Safety.SendValueBatch =
        function(
            packet,
            recipient,
            batch
        )
            local payload = {}

            for _, fruit in ipairs(
                batch
            ) do
                table.insert(
                    payload,
                    {
                        ItemKey =
                            fruit.Id,

                        Count =
                            1,

                        Category =
                            "HarvestedFruits",
                    }
                )
            end

            while not state.Stop do
                local valid,
                    validationMessage,
                    validationType =
                    state.Safety.ValidateValueBatch(
                        batch
                    )

                if not valid then
                    return false,
                        validationMessage,
                        validationType,
                        false
                end

                if not state.Safety.WaitForCooldown() then
                    return false,
                        "Stopped",
                        "STOPPED",
                        false
                end

                valid,
                validationMessage,
                validationType =
                    state.Safety.ValidateValueBatch(
                        batch
                    )

                if not valid then
                    return false,
                        validationMessage,
                        validationType,
                        false
                end

                local started =
                    workspace:GetServerTimeNow()

                setStatus(
                    "Sending",
                    color.Yellow
                )

                local ok,
                    first,
                    second =
                    pcall(function()
                        return packet:Fire(
                            recipient.UserId,
                            payload,
                            ""
                        )
                    end)

                if not ok then
                    return false,
                        tostring(
                            first
                        ),
                        "ERROR",
                        false
                end

                local message =
                    tostring(
                        second or ""
                    )

                if first == true then
                    state.Safety.RecordAcceptedMail(
                        started
                    )

                    local confirmed =
                        state.Safety.WaitForValueRemoval(
                            batch,
                            8
                        )

                    if not confirmed then
                        return false,
                            "The server accepted this mail, but inventory removal could not be confirmed.",
                            "UNCERTAIN",
                            true
                    end

                    return true,
                        message,
                        "CONFIRMED",
                        true
                end

                local lower =
                    message:lower()

                local seconds =
                    tonumber(
                        lower:match(
                            "wait%s+(%d+)%s*s"
                        )
                    )

                if seconds then
                    task.wait(
                        seconds + 0.25
                    )
                elseif lower:find(
                    "daily gift limit",
                    1,
                    true
                ) then
                    tracker.Used =
                        DAILY_LIMIT

                    HOLY_MAIL_STATE.TrackerDay =
                        HolyMailToday()

                    HOLY_MAIL_STATE.TrackerUsed =
                        DAILY_LIMIT

                    updateQuota()
                    HolyMailSaveSettings()

                    return false,
                        message,
                        "DAILY",
                        false
                else
                    return false,
                        message ~= ""
                                and message
                            or tostring(
                                first
                            ),
                        "REJECTED",
                        false
                end
            end

            return false,
                "Stopped",
                "STOPPED",
                false
        end

    state.Safety.AddFruitHistoryBatch =
        function(
            historyRecord,
            historyItemMap,
            batch
        )
            for _, fruit in ipairs(
                batch
            ) do
                local source =
                    fruit.Item

                local icon = ""

                if typeof(source) == "Instance" then
                    icon =
                        HolyMailHistoryNormalizeIcon(
                            source:GetAttribute("IMG")
                                or source:GetAttribute("Icon")
                                or source:GetAttribute("Image")
                                or source:GetAttribute("TextureId")
                                or (
                                    source:IsA("Tool")
                                    and source.TextureId
                                    or ""
                                )
                        )
                end

                local itemKey =
                    tostring(
                        fruit.Name
                        or "Unknown fruit"
                    )
                    .. "|"
                    .. tostring(
                        fruit.Mutation
                        or "Normal"
                    )
                    .. "|"
                    .. icon

                local historyItem =
                    historyItemMap[
                        itemKey
                    ]

                if not historyItem then
                    historyItem = {
                        Name =
                            tostring(
                                fruit.Name
                                or "Unknown fruit"
                            ),

                        Details =
                            tostring(
                                fruit.Mutation
                                or "Normal"
                            ),

                        Icon = icon,
                        Count = 0,
                        Sent = 0,
                        Value = 0,
                    }

                    historyItemMap[
                        itemKey
                    ] =
                        historyItem

                    table.insert(
                        historyRecord.Items,
                        historyItem
                    )
                end

                historyItem.Count +=
                    1

                historyItem.Sent +=
                    1

                historyItem.Value +=
                    tonumber(
                        fruit.Value
                    )
                    or 0
            end
        end

    state.Safety.RunValueDelivery =
        function(totalMails)
            protectedCall(
                "Delivery",
                function()
                    local packet,
                        packetError =
                        getSendPacket()

                    if not packet then
                        reportError(
                            "Networking",
                            packetError
                        )

                        if type(
                            state.ValueSession
                        ) == "table" then
                            state.ValueSession.Status =
                                "Paused"
                        end

                        return
                    end

                    local session =
                        state.ValueSession

                    if type(session) ~= "table" then
                        return
                    end

                    session.Status =
                        "Running"

                    state.Running =
                        true

                    state.Stop =
                        false

                    progressFill.Size =
                        UDim2.fromScale(
                            0,
                            1
                        )

                    renderRecipients()

                    local completedMails = 0
                    local fruitsSent = 0
                    local valueSent = 0
                    local completedRecipients = 0

                    local failure
                    local failureType

                    for routeIndex, entry in ipairs(
                        state.Plan
                    ) do
                        if state.Stop then
                            break
                        end

                        local recipientFinished =
                            true

                        local historyRecord = {
                            Direction = "Sent",
                            Mode = "By Value",
                            Status = "Failed",

                            OtherUserId =
                                entry.Recipient.UserId,

                            OtherName =
                                entry.Recipient.Name,

                            AttemptedMails =
                                entry.Mails,

                            AcceptedMails = 0,

                            PlannedItems =
                                #entry.Fruits,

                            SentItems = 0,

                            TargetValue =
                                entry.Target
                                or entry.Value,

                            AcceptedValue = 0,

                            Items = {},
                        }

                        local historyItemMap = {}

                        for firstIndex = 1,
                            #entry.Fruits,
                            BATCH_LIMIT
                        do
                            if state.Stop then
                                recipientFinished =
                                    false

                                break
                            end

                            local batch = {}
                            local batchValue = 0

                            for fruitIndex = firstIndex,
                                math.min(
                                    firstIndex
                                        + BATCH_LIMIT
                                        - 1,
                                    #entry.Fruits
                                )
                            do
                                local fruit =
                                    entry.Fruits[
                                        fruitIndex
                                    ]

                                table.insert(
                                    batch,
                                    fruit
                                )

                                batchValue +=
                                    tonumber(
                                        fruit.Value
                                    )
                                    or 0
                            end

                            sendButton.Text =
                                string.format(
                                    "@%s · mail %d/%d",
                                    entry.Recipient.Name,
                                    completedMails + 1,
                                    totalMails
                                )

                            setStatus(
                                string.format(
                                    "%d/%d",
                                    routeIndex,
                                    #state.Plan
                                ),
                                color.Yellow
                            )

                            local confirmed,
                                response,
                                responseType,
                                acceptedByServer =
                                state.Safety.SendValueBatch(
                                    packet,
                                    entry.Recipient,
                                    batch
                                )

                            if acceptedByServer then
                                completedMails +=
                                    1

                                fruitsSent +=
                                    #batch

                                valueSent +=
                                    batchValue

                                session.AcceptedMails =
                                    (
                                        tonumber(
                                            session.AcceptedMails
                                        )
                                        or 0
                                    )
                                    + 1

                                session.AcceptedItems =
                                    (
                                        tonumber(
                                            session.AcceptedItems
                                        )
                                        or 0
                                    )
                                    + #batch

                                session.AcceptedValue =
                                    (
                                        tonumber(
                                            session.AcceptedValue
                                        )
                                        or 0
                                    )
                                    + batchValue

                                local userId =
                                    entry.Recipient.UserId

                                local oldRemaining =
                                    tonumber(
                                        session.RemainingTargets[
                                            userId
                                        ]
                                    )
                                    or tonumber(
                                        entry.Target
                                    )
                                    or 0

                                session.RemainingTargets[
                                    userId
                                ] =
                                    math.max(
                                        0,
                                        oldRemaining
                                        - batchValue
                                    )

                                historyRecord.AcceptedMails +=
                                    1

                                historyRecord.SentItems +=
                                    #batch

                                historyRecord.AcceptedValue +=
                                    batchValue

                                state.Safety.AddFruitHistoryBatch(
                                    historyRecord,
                                    historyItemMap,
                                    batch
                                )

                                progressFill.Size =
                                    UDim2.fromScale(
                                        completedMails
                                            / math.max(
                                                totalMails,
                                                1
                                            ),
                                        1
                                    )

                                messageText.Text =
                                    string.format(
                                        "Accepted %d fruits worth %s.",
                                        fruitsSent,
                                        formatValue(
                                            valueSent
                                        )
                                    )
                            end

                            if not confirmed then
                                recipientFinished =
                                    false

                                failure =
                                    tostring(
                                        response
                                        or "Delivery paused"
                                    )

                                failureType =
                                    tostring(
                                        responseType
                                        or "PAUSED"
                                    )

                                if failureType
                                    == "UNCERTAIN"
                                then
                                    session.UncertainBatch = {
                                        Recipient =
                                            entry.Recipient,

                                        Fruits =
                                            batch,

                                        Value =
                                            batchValue,

                                        Accepted =
                                            acceptedByServer == true,
                                    }
                                end

                                break
                            end
                        end

                        if failureType == "UNCERTAIN" then
                            historyRecord.Status =
                                "Uncertain"
                        elseif recipientFinished then
                            historyRecord.Status =
                                "Sent"
                        elseif historyRecord.AcceptedMails > 0
                            or state.Stop
                        then
                            historyRecord.Status =
                                "Partial"
                        else
                            historyRecord.Status =
                                "Failed"
                        end

                        historyRecord.Error =
                            failure
                            or (
                                state.Stop
                                and "Stopped by user"
                                or ""
                            )

                        if historyRecord.AttemptedMails > 0 then
                            HolyMailHistoryAdd(
                                historyRecord
                            )
                        end

                        if recipientFinished then
                            completedRecipients +=
                                1
                        else
                            break
                        end
                    end

                    local stopped =
                        state.Stop
                        and not failure

                    local complete =
                        completedMails == totalMails
                        and not failure
                        and not stopped

                    if complete then
                        session.Status =
                            "Complete"

                        state.ValueSession =
                            nil
                    elseif failureType == "UNCERTAIN" then
                        session.Status =
                            "Uncertain"
                    else
                        session.Status =
                            "Paused"
                    end

                    state.Running =
                        false

                    state.Stop =
                        false

                    renderRecipients()

                    setStatus(
                        complete
                                and "Complete"
                            or failureType == "UNCERTAIN"
                                    and "Confirmation uncertain"
                                or "Paused",
                        complete
                                and color.Green
                            or failureType == "UNCERTAIN"
                                    and color.Red
                                or color.Yellow
                    )

                    sendButton.Text =
                        complete
                                and "Review and send"
                            or failureType == "UNCERTAIN"
                                    and "Review uncertain mail"
                                or "Resume remaining delivery"

                    showModal(
                        complete
                                and "Delivery complete"
                            or failureType == "UNCERTAIN"
                                    and "Confirmation uncertain"
                                or failureType == "DAILY"
                                        and "Daily limit reached"
                                    or "Delivery paused",
                        (
                            failure
                            and failure
                                .. "\n\n"
                            or ""
                        )
                        .. string.format(
                            "People completed: %d\nFruits accepted: %d\nValue accepted: %s\nSends accepted: %d",
                            completedRecipients,
                            fruitsSent,
                            formatValue(
                                valueSent
                            ),
                            completedMails
                        ),
                        nil,
                        nil,
                        not complete
                    )

                    task.spawn(
                        rebuildPlan
                    )
                end
            )
        end

    state.Safety.RequestValueDelivery =
        function()
            if state.Running then
                state.Stop =
                    true

                sendButton.Text =
                    "Stopping after current mail..."

                return
            end

            local session =
                state.ValueSession

            if type(session) == "table"
                and session.Status == "Uncertain"
            then
                showModal(
                    "Confirmation uncertain",
                    "The server accepted the previous mail, but HOLY could not confirm that its items disappeared.\n\nThat batch was removed from the remaining target and will never be resent automatically.",
                    "Continue safely",
                    function()
                        session.Status =
                            "Paused"

                        session.UncertainBatch =
                            nil

                        sendButton.Text =
                            "Resume remaining delivery"

                        task.spawn(
                            rebuildPlan
                        )
                    end,
                    true
                )

                return
            end

            local resuming =
                type(session) == "table"
                and session.Status == "Paused"

            if resuming then
                rebuildPlan()
            end

            if state.Busy
                or #state.Plan == 0
            then
                return
            end

            local mails = 0
            local fruits = 0
            local value = 0
            local incomplete = false
            local overpayBlocked = false

            for _, entry in ipairs(
                state.Plan
            ) do
                mails +=
                    entry.Mails

                fruits +=
                    #entry.Fruits

                value +=
                    entry.Value

                incomplete =
                    incomplete
                    or not entry.Complete

                overpayBlocked =
                    overpayBlocked
                    or entry.GuardBlocked == true
            end

            if resuming
                and mails <= 0
            then
                state.ValueSession =
                    nil

                messageText.Text =
                    "The remaining delivery is complete."

                messageText.TextColor3 =
                    color.Green

                sendButton.Text =
                    "Review and send"

                task.spawn(
                    rebuildPlan
                )

                return
            end

            if overpayBlocked then
                messageText.Text =
                    "Cannot reach one or more remaining targets within the maximum extra value."

                messageText.TextColor3 =
                    color.Red

                return
            end

            if incomplete
                or mails <= 0
            then
                messageText.Text =
                    "The remaining delivery cannot currently be completed safely."

                messageText.TextColor3 =
                    color.Red

                return
            end

            if mails
                > DAILY_LIMIT - tracker.Used
            then
                messageText.Text =
                    "This needs more sends than you have left today."

                messageText.TextColor3 =
                    color.Red

                return
            end

            local seconds =
                mails <= 1
                and 0
                or (
                    mails - 1
                ) * COOLDOWN

            local maximumExtraText =
                state.Strategy == "Send at least"
                        and extraLimitCaption()
                    or "Not used"

            showModal(
                resuming
                        and "Resume remaining delivery"
                    or "Review before sending",
                string.format(
                    "Strategy: %s\nMaximum extra: %s\nPeople: %d\nFruits remaining: %d\nRemaining value: %s\nSends remaining: %d\nTime: about %ds",
                    state.Strategy,
                    maximumExtraText,
                    #state.Plan,
                    fruits,
                    formatValue(
                        value
                    ),
                    mails,
                    math.ceil(
                        seconds
                    )
                ),
                resuming
                        and "Resume"
                    or "Send now",
                function()
                    if not resuming then
                        local remainingTargets = {}

                        for _, recipient in ipairs(
                            state.Recipients
                        ) do
                            remainingTargets[
                                recipient.UserId
                            ] =
                                tonumber(
                                    recipient.Target
                                )
                                or 0
                        end

                        state.ValueSession = {
                            Status = "Ready",

                            RemainingTargets =
                                remainingTargets,

                            AcceptedMails = 0,
                            AcceptedItems = 0,
                            AcceptedValue = 0,

                            UncertainBatch =
                                nil,
                        }
                    end

                    task.spawn(
                        state.Safety.RunValueDelivery,
                        mails
                    )
                end,
                true
            )
        end

    addButton.MouseButton1Click:Connect(function()
        protectedCall(
            "Add recipient",
            function()
                if state.RecipientChangesLocked() then
                    return
                end

                local raw =
                    recipientBox.Text
                        :gsub("^%s+", "")
                        :gsub("%s+$", "")

                local target =
                    parseValue(
                        valueBox.Text
                    )

                if raw == "" then
                    recipientBox.PlaceholderText =
                        "Enter a recipient"

                    return
                end

                if not target then
                    valueBox.Text =
                        ""

                    valueBox.PlaceholderText =
                        "Invalid value"

                    return
                end

                addButton.Text =
                    "Checking..."

                local userId
                local username

                local numeric =
                    tonumber(raw)

                if numeric then
                    local ok, result =
                        pcall(
                            Players.GetNameFromUserIdAsync,
                            Players,
                            math.floor(numeric)
                        )

                    if ok then
                        userId =
                            math.floor(numeric)

                        username =
                            result
                    end
                else
                    local ok, result =
                        pcall(
                            Players.GetUserIdFromNameAsync,
                            Players,
                            raw
                        )

                    if ok then
                        userId =
                            result

                        local nameOk, name =
                            pcall(
                                Players.GetNameFromUserIdAsync,
                                Players,
                                userId
                            )

                        username =
                            nameOk
                                and name
                                or raw
                    end
                end

                if not userId
                    or not username
                    or userId == player.UserId
                then
                    recipientBox.Text =
                        ""

                    recipientBox.PlaceholderText =
                        "Recipient not found"

                    addButton.Text =
                        "+ Add"

                    return
                end

                for index, recipient in ipairs(
                    state.Recipients
                ) do
                    if index ~= state.Editing
                        and recipient.UserId == userId
                    then
                        recipientBox.Text =
                            ""

                        recipientBox.PlaceholderText =
                            "Already added"

                        addButton.Text =
                            "+ Add"

                        return
                    end
                end

                local record = {
                    UserId =
                        userId,

                    Name =
                        username,

                    Target =
                        target,
                }

                if state.Editing
                    and state.Recipients[state.Editing]
                then
                    state.Recipients[state.Editing] =
                        record
                else
                    table.insert(
                        state.Recipients,
                        record
                    )
                end

                HolyMailTouchRecipient(
                    userId,
                    username
                )

                state.Editing =
                    nil

                recipientBox.Text =
                    ""

                valueBox.Text =
                    ""

                addButton.Text =
                    "+ Add"

                renderRecipients()
                rebuildPlan()
            end
        )
    end)

