        protectedCall(
            "Refresh preview",
            rebuildPlan
        )
    end)

    strategyButton.MouseButton1Click:Connect(function()
        if state.Running
            or state.Busy
        then
            return
        end

        showStrategySettings()
    end)

    fruitsButton.MouseButton1Click:Connect(function()
        protectedCall(
            "Fruit filters",
            state.Filters.Show
        )
    end)


    favoriteButton.MouseButton1Click:Connect(function()
        if state.Running
            or state.Busy
        then
            return
