    local function historyStatusColor(status)
        if status == "Sent" then
            return color.Accent
        elseif status == "Received" then
            return color.Green
        elseif status == "Partial"
            or status == "Stopped"
        then
            return color.Yellow
        end

        return color.Red
    end

    local function historyFormatTime(timestamp)
        local ok, result =
            pcall(
                os.date,
                "%d %b %Y  ·  %H:%M",
                math.floor(
                    tonumber(timestamp)
                        or os.time()
                )
            )

        return ok
                and result
            or "Unknown time"
    end

    local function historyMatchesSearch(
        record,
        query
    )
        if query == "" then
            return true
        end

        local searchable =
            tostring(
                record.OtherName
                    or ""
            )
            .. " "
            .. tostring(
                record.Mode
                    or ""
            )
            .. " "
            .. tostring(
                record.Status
                    or ""
            )

        for _, item in ipairs(
            type(record.Items) == "table"
                and record.Items
                or {}
        ) do
            searchable ..=
                " "
                .. tostring(
                    item.Name
                        or ""
                )
                .. " "
                .. tostring(
                    item.Details
                        or ""
                )
        end

        return searchable
            :lower()
            :find(
                query,
                1,
                true
            ) ~= nil
    end

    local function refreshHistoryFilters()
        for filterName, filterButton in pairs(
            historyFilterButtons
        ) do
            local selected =
                HOLY_MAIL_RUNTIME.HistoryFilter
                    == filterName

            filterButton.BackgroundColor3 =
                selected
                    and color.Accent
                    or color.Field

            filterButton.TextColor3 =
                selected
                    and color.White
                    or color.Secondary

            local stroke =
                filterButton:FindFirstChildOfClass(
                    "UIStroke"
                )

            if stroke then
                stroke.Color =
                    selected
                        and Color3.fromRGB(
                            83,
                            148,
                            247
                        )
                        or color.Border
            end
        end
    end

    local function refreshHistoryPage()
        for _, child in ipairs(
            historyList:GetChildren()
        ) do
            if child ~= historyLayout then
                child:Destroy()
            end
        end

        local records =
            type(HOLY_MAIL_HISTORY) == "table"
            and type(HOLY_MAIL_HISTORY.Records) == "table"
            and HOLY_MAIL_HISTORY.Records
            or {}

        local deliveries = 0
        local acceptedMails = 0
        local movedItems = 0
        local knownValue = 0

        for _, record in ipairs(records) do
            deliveries +=
                1

            acceptedMails +=
                tonumber(
                    record.AcceptedMails
                )
                or 0

            movedItems +=
                tonumber(
                    record.SentItems
                )
                or 0

            knownValue +=
                tonumber(
                    record.AcceptedValue
                )
                or 0
        end

        historyStatLabels[
            "DELIVERIES"
        ].Text =
            tostring(deliveries)

        historyStatLabels[
            "ACCEPTED MAIL"
        ].Text =
            tostring(acceptedMails)

        historyStatLabels[
            "ITEMS MOVED"
        ].Text =
            tostring(movedItems)

        historyStatLabels[
            "KNOWN VALUE"
        ].Text =
            formatValue(knownValue)

        refreshHistoryFilters()

        local query =
            tostring(
                HOLY_MAIL_RUNTIME.HistorySearch
                    or ""
            )
                :lower()
                :gsub("^%s+", "")
                :gsub("%s+$", "")

        local selectedFilter =
            tostring(
                HOLY_MAIL_RUNTIME.HistoryFilter
                    or "All"
            )

        local visibleRecords = {}

        for _, record in ipairs(records) do
            local status =
                tostring(
                    record.Status
                        or "Failed"
                )

            local direction =
                tostring(
                    record.Direction
                        or "Sent"
                )

            local filterMatches =
                selectedFilter == "All"
                or (
                    selectedFilter == "Sent"
                    and status == "Sent"
                )
                or (
                    selectedFilter == "Received"
                    and (
                        status == "Received"
                        or direction == "Received"
                    )
                )
                or (
                    selectedFilter == "Partial"
                    and (
                        status == "Partial"
                        or status == "Stopped"
                    )
                )

            if filterMatches
                and historyMatchesSearch(
                    record,
                    query
                )
            then
                table.insert(
                    visibleRecords,
                    record
                )
            end
        end

        if #visibleRecords == 0 then
            local empty =
                create(
                    "Frame",
                    {
                        BackgroundTransparency = 1,
                        Size = UDim2.new(
                            1,
                            -2,
                            0,
                            330
                        ),
                        LayoutOrder = 1,
                    },
                    historyList
                )

            text(
                empty,
                #records == 0
                    and "No delivery history yet"
                    or "No matching deliveries",
                UDim2.new(1, -30, 0, 30),
                UDim2.fromOffset(15, 116),
                16,
                color.Text,
                Enum.TextXAlignment.Center,
                Enum.Font.GothamSemibold
            )

            text(
                empty,
                #records == 0
                    and "Accepted sends and claimed mail will appear here."
                    or "Try another search or filter.",
                UDim2.new(1, -30, 0, 24),
                UDim2.fromOffset(15, 151),
                10,
                color.Muted,
                Enum.TextXAlignment.Center
            )

            return
        end

        for recordIndex, record in ipairs(
            visibleRecords
        ) do
            local recordId =
                tostring(
                    record.Id
                        or recordIndex
                )

            local expanded =
                HOLY_MAIL_RUNTIME.ExpandedHistory[
                    recordId
                ] == true

            local items =
                type(record.Items) == "table"
                    and record.Items
                    or {}

            local itemAreaHeight =
                expanded
                    and (
                        math.max(
                            1,
                            #items
                        ) * 48
                        + 14
                    )
                    or 0

            local recordHeight =
                74 + itemAreaHeight

            local status =
                tostring(
                    record.Status
                        or "Failed"
                )

            local direction =
                tostring(
                    record.Direction
                        or "Sent"
                )

            local statusColor =
                historyStatusColor(
                    status
                )

            local recordCard =
                create(
                    "Frame",
                    {
                        BackgroundColor3 = color.Field,
                        Size = UDim2.new(
                            1,
                            -2,
                            0,
                            recordHeight
                        ),
                        LayoutOrder = recordIndex,
                    },
                    historyList
                )

            round(recordCard, 12)
            outline(recordCard, color.Border)

            local accentLine =
                create(
                    "Frame",
                    {
                        BackgroundColor3 = statusColor,
                        Size = UDim2.fromOffset(
                            4,
                            recordHeight
                        ),
                        Position = UDim2.fromOffset(
                            0,
                            0
                        ),
                    },
                    recordCard
                )

            round(accentLine, 4)

            local userId =
                tonumber(
                    record.OtherUserId
                )
                or 0

            if userId > 0 then
                addAvatar(
                    recordCard,
                    userId,
                    UDim2.fromOffset(42, 42),
                    UDim2.fromOffset(14, 14)
                )
            else
                local avatarPlaceholder =
                    create(
                        "Frame",
                        {
                            BackgroundColor3 = color.Hover,
                            Size = UDim2.fromOffset(42, 42),
                            Position = UDim2.fromOffset(14, 14),
                        },
                        recordCard
                    )

                round(avatarPlaceholder, 999)
            end

            local otherName =
                tostring(
                    record.OtherName
                        or "Unknown user"
                )

            local title =
                direction == "Received"
                    and (
                        "From @"
                        .. otherName
                    )
                    or (
                        "To @"
                        .. otherName
                    )

            text(
                recordCard,
                title,
                UDim2.new(1, -340, 0, 22),
                UDim2.fromOffset(66, 11),
                12,
                color.Text,
                nil,
                Enum.Font.GothamBold
            )

            local acceptedMails =
                tonumber(
                    record.AcceptedMails
                )
                or 0

            local attemptedMails =
                tonumber(
                    record.AttemptedMails
                )
                or acceptedMails

            local sentItems =
                tonumber(
                    record.SentItems
                )
                or 0

            local plannedItems =
                tonumber(
                    record.PlannedItems
                )
                or sentItems

            local summary =
                historyFormatTime(
                    record.Timestamp
                )
                .. "  ·  "
                .. tostring(
                    record.Mode
                        or "Mail"
                )
                .. "  ·  "
                .. tostring(acceptedMails)
                .. "/"
                .. tostring(attemptedMails)
                .. " mail  ·  "
                .. tostring(sentItems)
                .. "/"
                .. tostring(plannedItems)
                .. " items"

            text(
                recordCard,
                summary,
                UDim2.new(1, -250, 0, 20),
                UDim2.fromOffset(66, 36),
                9,
                color.Muted
            )

            local value =
                tonumber(
                    record.AcceptedValue
                )
                or 0

            if value > 0 then
                text(
                    recordCard,
                    formatValue(value),
                    UDim2.fromOffset(120, 20),
                    UDim2.new(
                        1,
                        -250,
                        0,
                        13
                    ),
                    11,
                    color.Text,
                    Enum.TextXAlignment.Right,
                    Enum.Font.GothamSemibold
                )
            end

            text(
                recordCard,
                status,
                UDim2.fromOffset(92, 22),
                UDim2.new(
                    1,
                    -122,
                    0,
                    12
                ),
                10,
                statusColor,
                Enum.TextXAlignment.Center,
                Enum.Font.GothamBold
            )

            text(
                recordCard,
                expanded
                    and "−"
                    or "+",
                UDim2.fromOffset(24, 24),
                UDim2.new(
                    1,
                    -34,
                    0,
                    23
                ),
                15,
                color.Muted,
                Enum.TextXAlignment.Center,
                Enum.Font.GothamBold
            )

            local expandButton =
                create(
                    "TextButton",
                    {
                        BackgroundTransparency = 1,
                        Text = "",
                        AutoButtonColor = false,
                        Size = UDim2.new(
                            1,
                            0,
                            0,
                            72
                        ),
                    },
                    recordCard
                )

            expandButton.MouseButton1Click:Connect(function()
                HOLY_MAIL_RUNTIME.ExpandedHistory[
                    recordId
                ] =
                    not expanded

                refreshHistoryPage()
            end)

            if expanded then
                create(
                    "Frame",
                    {
                        BackgroundColor3 = color.Border,
                        BackgroundTransparency = 0.2,
                        Size = UDim2.new(
                            1,
                            -28,
                            0,
                            1
                        ),
                        Position = UDim2.fromOffset(
                            14,
                            72
                        ),
                    },
                    recordCard
                )

                if #items == 0 then
                    text(
                        recordCard,
                        "No item details were provided by this mail.",
                        UDim2.new(1, -32, 0, 46),
                        UDim2.fromOffset(16, 82),
                        10,
                        color.Muted,
                        Enum.TextXAlignment.Center
                    )
                else
                    for itemIndex, item in ipairs(
                        items
                    ) do
                        local itemY =
                            80
                            + (
                                itemIndex - 1
                            ) * 48

                        local itemRow =
                            create(
                                "Frame",
                                {
                                    BackgroundColor3 = color.Hover,
                                    Size = UDim2.new(
                                        1,
                                        -28,
                                        0,
                                        40
                                    ),
                                    Position = UDim2.fromOffset(
                                        14,
                                        itemY
                                    ),
                                },
                                recordCard
                            )

                        round(itemRow, 9)

                        create(
                            "ImageLabel",
                            {
                                BackgroundTransparency = 1,
                                Image = HolyMailHistoryNormalizeIcon(
                                    item.Icon
                                ),
                                Size = UDim2.fromOffset(30, 30),
                                Position = UDim2.fromOffset(7, 5),
                                ScaleType = Enum.ScaleType.Fit,
                            },
                            itemRow
                        )

                        text(
                            itemRow,
                            tostring(
                                item.Name
                                    or "Unknown item"
                            ),
                            UDim2.new(1, -280, 0, 18),
                            UDim2.fromOffset(46, 3),
                            10,
                            color.Text,
                            nil,
                            Enum.Font.GothamSemibold
                        )

                        local count =
                            math.max(
                                0,
                                math.floor(
                                    tonumber(
                                        item.Count
                                    )
                                    or 0
                                )
                            )

                        local sent =
                            math.max(
                                0,
                                math.floor(
                                    tonumber(
                                        item.Sent
                                    )
                                    or count
                                )
                            )

                        local details =
                            tostring(
                                item.Details
                                    or "Item"
                            )
                            .. "  ·  x"
                            .. tostring(count)

                        local itemValue =
                            tonumber(
                                item.Value
                            )
                            or 0

                        if itemValue > 0 then
                            details ..=
                                "  ·  "
                                .. formatValue(
                                    itemValue
                                )
                        end

                        text(
                            itemRow,
                            details,
                            UDim2.new(1, -280, 0, 16),
                            UDim2.fromOffset(46, 21),
                            8,
                            color.Muted
                        )

                        local itemStatus
                        local itemStatusColor

                        if direction == "Received" then
                            itemStatus =
                                "Received x"
                                .. tostring(sent)

                            itemStatusColor =
                                color.Green
                        elseif sent >= count then
                            itemStatus =
                                "Sent x"
                                .. tostring(sent)

                            itemStatusColor =
                                color.Green
                        elseif sent > 0 then
                            itemStatus =
                                tostring(sent)
                                .. "/"
                                .. tostring(count)
                                .. " sent"

                            itemStatusColor =
                                color.Yellow
                        else
                            itemStatus =
                                "Not sent"

                            itemStatusColor =
                                color.Red
                        end

                        text(
                            itemRow,
                            itemStatus,
                            UDim2.fromOffset(150, 40),
                            UDim2.new(
