    local function refreshInboxPage()
        local count =
            math.max(
                0,
                math.floor(
                    tonumber(
                        HOLY_MAIL_RUNTIME.InboxCount
                    )
                    or 0
                )
            )

        inboxCountLabel.Text =
            tostring(count)
            .. " / "
            .. tostring(
                HOLY_MAIL_INBOX_CAPACITY
            )
            .. " mail"

        inboxStatusLabel.Text =
            tostring(
                HOLY_MAIL_RUNTIME.InboxStatus
                or "Inbox ready"
            )

        inboxClaimedLabel.Text =
            "Claimed this session: "
            .. tostring(
                HOLY_MAIL_RUNTIME.InboxClaimed
                or 0
            )

        local autoClaim =
            HOLY_MAIL_STATE.AutoClaim == true

        inboxAutoButton.Text =
            "Auto Claim: "
            .. (
                autoClaim
                    and "ON"
                    or "OFF"
            )

        inboxAutoButton.BackgroundColor3 =
            autoClaim
                and color.Accent
                or color.Field
    end

    local function showMainPage(
        tabName
    )
        if state.Running
            and tabName ~= state.ActiveTab
        then
            return
        end

        local validTabs = {
            Send = true,
            Fleet = true,
            Inbox = true,
            History = true,
            Settings = true,
        }

        if validTabs[tabName] ~= true then
            tabName =
                "Send"
        end

        state.ActiveTab =
            tabName

        local expanded =
            not state.Minimized

        content.Visible =
            expanded
            and tabName == "Send"

        sendModeBar.Visible =
            expanded
            and tabName == "Send"

        state.Fleet.Page.Visible =
            expanded
            and tabName == "Fleet"

        inboxPage.Visible =
            expanded
            and tabName == "Inbox"

        historyPage.Visible =
            expanded
            and tabName == "History"

        settingsPage.Visible =
            expanded
            and tabName == "Settings"

        for currentName, currentButton in pairs(
            tabButtons
        ) do
            local selected =
                currentName == tabName

            currentButton.TextColor3 =
                selected
                    and color.Accent
                    or color.Muted

            currentButton.Font =
                selected
                    and Enum.Font.GothamBold
                    or Enum.Font.GothamSemibold

            tabLines[currentName].Visible =
                selected
        end

        if tabName == "Send" then
            subtitle.Text =
                state.MailMode == "Items"
                    and "Pick exact items"
                    or "Send fruits by value"
        elseif tabName == "Fleet" then
            subtitle.Text =
                "Manage alt accounts"

            if type(
                state.Fleet.Refresh
            ) == "function" then
                state.Fleet.Refresh()
            end
        elseif tabName == "Inbox" then
            subtitle.Text =
                "Claim incoming mail"

            refreshInboxPage()

            task.spawn(function()
                HolyMailRefreshInboxCount()

                if inboxPage.Parent ~= nil then
                    refreshInboxPage()
                end
            end)
        elseif tabName == "History" then
            subtitle.Text =
                "Recent deliveries"

            refreshHistoryPage()
        else
            subtitle.Text =
                "Mail preferences"
        end
    end

