    settingsScaleButton.MouseButton1Click:Connect(function()
        local choices = {
            "80%",
            "90%",
            "100%",
            "110%",
        }

        local current =
            HolyMailNormalizeScale(
                HOLY_MAIL_STATE.HudScale
                or "100%"
            )

        local nextIndex =
            1

        for index, choice in ipairs(
            choices
        ) do
            if choice == current then
                nextIndex =
                    index % #choices
                    + 1

                break
            end
        end

        local newScale =
            HolyMailSetHudScale(
                choices[nextIndex]
            )

        settingsScaleButton.Text =
            "HUD Scale: "
            .. tostring(newScale)
    end)

