                    or color.Border
        end
    end

    local function cleanItemKey(value)
        return tostring(
            value or ""
        )
            :lower()
            :gsub(
                "[%s%p_]",
                ""
            )
    end

    local function cleanItemName(value)
        local result =
            tostring(
                value or ""
            )

        result =
            result:gsub(
                "%s*%[%s*[xX]%d+%s*%]%s*$",
                ""
            )

        result =
            result:gsub(
                "%s+[xX]%d+%s*$",
                ""
            )

        result =
            result:gsub(
                "^%s+",
                ""
            )

        result =
            result:gsub(
                "%s+$",
                ""
            )

        return result
    end

    local function firstText(...)
        for index = 1, select("#", ...) do
            local value =
                select(
                    index,
                    ...
                )

            if type(value) == "string" then
                local cleaned =
                    cleanItemName(
                        value
                    )

                if cleaned ~= "" then
                    return cleaned
                end
            end
        end

        return ""
    end

    local function walkCatalog(
        value,
        callback,
        depth,
        seen
    )
        if type(value) ~= "table" then
            return
        end

        depth =
            depth or 0

        if depth > 6 then
            return
        end

        seen =
            seen or {}

        if seen[value] then
            return
        end

        seen[value] =
            true

        callback(value)

        for _, child in pairs(value) do
            if type(child) == "table" then
                walkCatalog(
                    child,
                    callback,
                    depth + 1,
                    seen
                )
            end
        end
    end

    local imageAssetId =
        nil

    do
        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        local imageModule =
            sharedModules
            and sharedModules:FindFirstChild(
                "ImageAssetId"
            )

        if imageModule
            and imageModule:IsA(
                "ModuleScript"
            )
        then
            local ok,
                result =
                pcall(
                    require,
                    imageModule
                )

            if ok
                and type(result) == "table"
            then
                imageAssetId =
                    result
            end
        end
    end

    local function coerceOwnedImage(
        value
    )
        if typeof(value) == "Instance" then
            if value:IsA(
                "StringValue"
            ) or value:IsA(
                "NumberValue"
            ) or value:IsA(
                "IntValue"
            ) then
                value =
                    value.Value
            elseif value:IsA(
                "ImageLabel"
            ) or value:IsA(
                "ImageButton"
            ) then
                value =
                    value.Image
            elseif value:IsA(
                "Decal"
            ) or value:IsA(
                "Texture"
            ) then
                value =
                    value.Texture
            elseif value:IsA(
                "Tool"
            ) then
                value =
                    value.TextureId
            else
                return ""
            end
        end

        if type(value) == "number" then
            if value <= 0 then
                return ""
            end

            return "rbxassetid://"
                .. tostring(
                    math.floor(value)
                )
        end

        if type(value) ~= "string" then
            return ""
        end

        local result =
            value:gsub(
                "^%s+",
                ""
            ):gsub(
                "%s+$",
                ""
            )

        if result == "" then
            return ""
        end

        if result:match(
            "^%d+$"
        ) then
            return "rbxassetid://"
                .. result
        end

        return result
    end

    local function normalizeOwnedImage(
        value
    )
        local direct =
            coerceOwnedImage(
                value
            )

        local resolver =
            type(imageAssetId) == "table"
            and imageAssetId.ResolveForDisplay
            or nil

        if type(resolver) == "function" then
            local candidates = {
                value,
            }

            if direct ~= "" then
                table.insert(
                    candidates,
                    direct
                )
            end

            for _, candidate in ipairs(
                candidates
            ) do
                local ok,
                    result =
                    pcall(
                        resolver,
                        candidate
                    )

                if not ok then
                    ok,
                    result =
                        pcall(
                            resolver,
                            imageAssetId,
                            candidate
                        )
                end

                if ok then
                    local resolved =
                        coerceOwnedImage(
                            result
                        )

                    if resolved ~= "" then
                        return resolved
                    end
                end
            end
        end

        return direct
    end

    local ownedImageFields = {
        "IMG",
        "Icon",
        "Image",
        "ImageId",
        "ImageID",
        "IconId",
        "IconID",
        "DisplayImage",
        "DisplayIcon",
        "ShopImage",
        "Thumbnail",
        "ThumbnailId",
        "ThumbnailImage",
        "Texture",
        "TextureId",
        "TextureID",
        "FruitImage",
        "FruitIcon",
        "SeedImage",
        "SeedIcon",
        "SeedPackImage",
        "SeedPackIcon",
        "PackImage",
        "EggImage",
        "EggIcon",
        "PetImage",
        "PetIcon",
        "PropImage",
        "PropIcon",
        "CrateImage",
        "CrateIcon",
    }

    local function readOwnedIconCandidate(
        value,
        seen
    )
        local valueType =
            typeof(value)

        if valueType == "Instance" then
            local direct =
                normalizeOwnedImage(
                    value
                )

            if direct ~= "" then
                return direct
            end

            for _, descendant in ipairs(
                value:GetDescendants()
            ) do
                local descendantName =
                    cleanItemKey(
                        descendant.Name
                    )

                local looksLikeImage =
                    descendantName:find(
                        "image",
                        1,
                        true
                    ) ~= nil
                    or descendantName:find(
                        "icon",
                        1,
                        true
                    ) ~= nil
                    or descendantName:find(
                        "texture",
                        1,
                        true
                    ) ~= nil

                if looksLikeImage then
                    local resolved =
                        normalizeOwnedImage(
                            descendant
                        )

                    if resolved ~= "" then
                        return resolved
                    end
                end
            end

            return ""
        end

        if valueType ~= "table" then
            return normalizeOwnedImage(
                value
            )
        end

        seen =
            seen or {}

        if seen[value] then
            return ""
        end

        seen[value] =
            true

        for _, fieldName in ipairs(
            ownedImageFields
        ) do
            local fieldValue =
                value[fieldName]

            if fieldValue ~= nil then
                local resolved =
                    readOwnedIconCandidate(
                        fieldValue,
                        seen
                    )

                if resolved ~= "" then
                    return resolved
                end
            end
        end

        return ""
    end

    local function firstOwnedIcon(...)
        for index = 1, select(
            "#",
            ...
        ) do
            local resolved =
                readOwnedIconCandidate(
                    select(
                        index,
                        ...
                    )
                )

            if resolved ~= "" then
                return resolved
            end
        end

        return ""
    end

    local function loadOwnedCatalogs()
        local catalogs = {
            Seeds = {},
            SeedPacks = {},
            Eggs = {},
            Gear = {},
            Props = {},
            Crates = {},
            Pets = {},
        }

        local sharedModules =
            ReplicatedStorage:FindFirstChild(
                "SharedModules"
            )

        if not sharedModules then
            return catalogs
        end

        local function loadModule(
            moduleName,
            callback
        )
            local module =
                sharedModules:FindFirstChild(
                    moduleName
                )

            if not module
                or not module:IsA(
                    "ModuleScript"
                )
            then
                return
            end

            local ok,
                result =
                pcall(
                    require,
                    module
                )

            if not ok
                or type(result) ~= "table"
            then
                return
            end

            walkCatalog(
                result,
                callback
            )
        end

        loadModule(
            "SeedData",
            function(row)
                local name =
                    firstText(
                        row.SeedName,
                        row.ItemName,
                        row.DisplayName,
                        row.Name
                    )

                if name ~= "" then
                    catalogs.Seeds[
                        cleanItemKey(name)
                    ] =
                        row
                end
            end
        )

        loadModule(
            "SeedPackData",
            function(row)
                local name =
                    firstText(
                        row.SeedPackName,
                        row.PackName,
                        row.ItemName,
                        row.DisplayName,
                        row.Name
                    )

                if name ~= "" then
                    catalogs.SeedPacks[
                        cleanItemKey(name)
                    ] =
                        row
                end
            end
        )

        loadModule(
            "EggData",
            function(row)
                local name =
                    firstText(
                        row.EggName,
                        row.ItemName,
                        row.DisplayName,
                        row.Name
                    )

                if name ~= "" then
                    catalogs.Eggs[
                        cleanItemKey(name)
                    ] =
                        row
                end
            end
        )

        loadModule(
            "GearShopData",
            function(row)
                local name =
                    firstText(
                        row.ItemName,
                        row.DisplayName,
                        row.Name
                    )

                if name ~= "" then
                    catalogs.Gear[
                        cleanItemKey(name)
                    ] =
                        row
                end
            end
        )

        loadModule(
            "PropData",
            function(row)
                local name =
                    firstText(
                        row.PropName,
                        row.ItemName,
                        row.DisplayName,
                        row.Name
                    )

                if name ~= "" then
                    catalogs.Props[
                        cleanItemKey(name)
                    ] =
                        row
                end
            end
        )

        loadModule(
            "CrateData",
            function(row)
                local name =
                    firstText(
                        row.CrateName,
                        row.ItemName,
                        row.DisplayName,
                        row.Name
                    )

                if name ~= "" then
                    catalogs.Crates[
                        cleanItemKey(name)
                    ] =
                        row
                end
            end
        )

        loadModule(
            "PetData",
            function(row)
                local name =
                    firstText(
                        row.DisplayName,
                        row.PetName,
                        row.ItemName,
                        row.Name
                    )

                if name ~= "" then
                    catalogs.Pets[
                        cleanItemKey(name)
                    ] =
                        row
                end
            end
        )

        if type(
            HolySniperGetPetData
        ) == "function" then
            local ok,
                petData =
                pcall(
                    HolySniperGetPetData
                )

            if ok
                and type(petData) == "table"
            then
                for key, row in pairs(
                    petData
                ) do
                    if type(row) == "table" then
                        local name =
                            firstText(
                                row.DisplayName,
                                row.PetName,
                                row.ItemName,
                                row.Name,
                                type(key) == "string"
                                    and key
                                    or nil
                            )

                        if name ~= "" then
                            catalogs.Pets[
                                cleanItemKey(name)
                            ] =
                                row
                        end
                    end
                end
            end
        end

        local crateFolder =
            sharedModules:FindFirstChild(
                "CrateData"
            )

        if crateFolder
            and not crateFolder:IsA(
                "ModuleScript"
            )
        then
            for _, child in ipairs(
                crateFolder:GetChildren()
            ) do
                if child:IsA(
                    "ModuleScript"
                ) then
                    local crateRow = {
                        CrateName =
                            child.Name,
                    }

                    local ok,
                        result =
                        pcall(
                            require,
                            child
                        )

                    if ok
                        and type(result) == "table"
                    then
                        crateRow =
                            result
                    end

                    catalogs.Crates[
                        cleanItemKey(
                            child.Name
                        )
                    ] =
                        crateRow
                end
            end
        end

        return catalogs
    end

    local function resolveOwnedRecordIcon(
        record,
        catalogs
    )
        if type(record) ~= "table" then
            return ""
        end

        local nameKey =
            cleanItemKey(
                record.Name
            )

        local icon =
            ""

        if record.Group == "Fruits" then
            local seedData =
                catalogs.Seeds[
                    nameKey
                ]

            icon =
                firstOwnedIcon(
                    seedData
                        and seedData.FruitImage,
                    seedData
                        and seedData.FruitIcon,
                    seedData
                )
        elseif record.Group == "Seeds" then
            if record.Category == "SeedPacks" then
                icon =
                    firstOwnedIcon(
                        catalogs.SeedPacks[
                            nameKey
                        ]
                    )
            else
                local seedData =
                    catalogs.Seeds[
                        nameKey
                    ]

                icon =
                    firstOwnedIcon(
                        seedData
                            and seedData.SeedImage,
                        seedData
                            and seedData.SeedIcon,
                        seedData
                    )
            end
        elseif record.Group == "Gear" then
            icon =
                firstOwnedIcon(
                    catalogs.Gear[
                        nameKey
                    ]
                )
        elseif record.Group == "Props" then
            icon =
                firstOwnedIcon(
                    catalogs.Props[
                        nameKey
                    ],
                    catalogs.Crates[
                        nameKey
                    ]
                )
        elseif record.Group == "Eggs" then
            icon =
                firstOwnedIcon(
                    catalogs.Eggs[
                        nameKey
                    ]
                )
        elseif record.Group == "Pets" then
            icon =
                firstOwnedIcon(
                    catalogs.Pets[
                        nameKey
                    ]
                )
        end

        if icon ~= "" then
            return icon
        end

        local instance =
            record.Instance

        if typeof(instance) == "Instance" then
            icon =
                firstOwnedIcon(
                    instance:GetAttribute(
                        "IMG"
                    ),
                    instance:GetAttribute(
                        "Image"
                    ),
                    instance:GetAttribute(
                        "Icon"
                    ),
                    instance:GetAttribute(
                        "TextureId"
                    ),
                    instance
                )
        end

        return icon
    end

    local function readOwnedCount(
        item,
        unique
    )
        if unique then
            return 1
        end

        local count =
            tonumber(
                item:GetAttribute(
                    "Count"
                )
                or item:GetAttribute(
                    "Amount"
                )
                or item:GetAttribute(
                    "Quantity"
                )
                or item:GetAttribute(
                    "Stack"
                )
                or item:GetAttribute(
                    "Uses"
                )
            )
            or 1

        return math.max(
            1,
            math.floor(
                count
            )
        )
    end

    local function readOwnedFavorite(item)
        return item:GetAttribute(
            "IsFavorite"
        ) == true
            or item:GetAttribute(
                "Favorite"
            ) == true
            or item:GetAttribute(
                "Favorited"
            ) == true
    end

    local function classifyOwnedItem(
        item,
        catalogs
    )
        if not (
            item:IsA("Tool")
            or item:IsA("Configuration")
        ) then
            return nil
        end

        local attributes =
            item:GetAttributes()

        local mainCategory =
            firstText(
                attributes.MainCategory,
                attributes.Category
            )

        local itemType =
            firstText(
                attributes.ItemType,
                attributes.Type
            )

        local mainKey =
            cleanItemKey(
                mainCategory
            )

        local typeKey =
            cleanItemKey(
                itemType
            )

        if attributes.HarvestedFruit == true then
            local itemKey =
                firstText(
                    attributes.Id,
                    attributes.FruitId,
                    attributes.FruitID,
                    attributes.UUID,
                    attributes.Guid
                )

            if itemKey == "" then
                return nil
            end

            local name =
                firstText(
                    attributes.FruitName,
                    attributes.Fruit,
                    attributes.ItemName,
                    item.Name
                )

            local mutation =
                firstText(
                    attributes.Mutation,
                    attributes.Variant,
                    attributes.Mutations
                )

            if mutation == "" then
                mutation =
                    "Normal"
            end

            return {
                Group =
                    "Fruits",

                Category =
                    "HarvestedFruits",

                ItemKey =
                    itemKey,

                Name =
                    name,

                Details =
                    mutation,

                Unique =
                    true,

                Supported =
                    true,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    1,

                Instance =
                    item,
            }
        end

        local petId =
            firstText(
                attributes.PetId,
                attributes.PetID
            )

        local petName =
            firstText(
                attributes.Pet,
                attributes.PetName
            )

        if petId ~= ""
            and petName ~= ""
        then
            local petDetails = {}

            local size =
                firstText(
                    attributes.Size,
                    attributes.PetSize,
                    attributes.SizeName
                )

            local variant =
                firstText(
                    attributes.Variant,
                    attributes.PetType,
                    attributes.TypeName
                )

            if size ~= ""
                and size ~= "Normal"
            then
                table.insert(
                    petDetails,
                    size
                )
            end

            if variant ~= ""
                and variant ~= "Normal"
            then
                table.insert(
                    petDetails,
                    variant
                )
            end

            return {
                Group =
                    "Pets",

                Category =
                    "Pets",

                ItemKey =
                    petId,

                Name =
                    petName,

                Details =
                    #petDetails > 0
                        and table.concat(
                            petDetails,
                            " · "
                        )
                        or "Normal",

                Unique =
                    true,

                Supported =
                    true,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    1,

                Instance =
                    item,
            }
        end

        local name =
            firstText(
                attributes.Egg,
                attributes.PropName,
                attributes.SeedPackName,
                attributes.SeedName,
                attributes.Seed,
                attributes.GearName,
                attributes.ItemName,
                item.Name
            )

        if name == "" then
            return nil
        end

        local nameKey =
            cleanItemKey(
                name
            )

        local eggName =
            firstText(
                attributes.Egg,
                name
            )

        local eggKey =
            cleanItemKey(
                eggName
            )

        local isEgg =
            mainKey == "egg"
            or mainKey == "eggs"
            or attributes.Egg ~= nil
            or catalogs.Eggs[eggKey] ~= nil

        if isEgg then
            return {
                Group =
                    "Eggs",

                Category =
                    "Eggs",

                ItemKey =
                    eggName,

                Name =
                    eggName,

                Details =
                    "Egg",

                Unique =
                    false,

                Supported =
                    true,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    readOwnedCount(
                        item,
                        false
                    ),

                Instance =
                    item,
            }
        end

        if mainKey:find(
            "seedpack",
            1,
            true
        )
            or typeKey:find(
                "seedpack",
                1,
                true
            )
            or catalogs.SeedPacks[nameKey] ~= nil
        then
            return {
                Group =
                    "Seeds",

                Category =
                    "SeedPacks",

                ItemKey =
                    name,

                Name =
                    name,

                Details =
                    "Seed Pack",

                Unique =
                    false,

                Supported =
                    true,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    readOwnedCount(
                        item,
                        false
                    ),

                Instance =
                    item,
            }
        end

        if mainKey == "seed"
            or mainKey == "seeds"
            or catalogs.Seeds[nameKey] ~= nil
        then
            return {
                Group =
                    "Seeds",

                Category =
                    "Seeds",

                ItemKey =
                    name,

                Name =
                    name,

                Details =
                    "Seed",

                Unique =
                    false,

                Supported =
                    true,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    readOwnedCount(
                        item,
                        false
                    ),

                Instance =
                    item,
            }
        end

        if mainKey:find(
            "prop",
            1,
            true
        )
            or catalogs.Props[nameKey] ~= nil
        then
            return {
                Group =
                    "Props",

                Category =
                    "Props",

                ItemKey =
                    name,

                Name =
                    name,

                Details =
                    "Prop",

                Unique =
                    false,

                Supported =
                    true,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    readOwnedCount(
                        item,
                        false
                    ),

                Instance =
                    item,
            }
        end

        if catalogs.Crates[nameKey] ~= nil
            or mainKey:find(
                "crate",
                1,
                true
            )
        then
            return {
                Group =
                    "Props",

                Category =
                    nil,

                ItemKey =
                    name,

                Name =
                    name,

                Details =
                    "Crate · needs a mail test",

                Unique =
                    false,

                Supported =
                    false,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    readOwnedCount(
                        item,
                        false
                    ),

                Instance =
                    item,
            }
        end

        local gearData =
            catalogs.Gear[nameKey]

        local gearType =
            firstText(
                attributes.ItemType,
                gearData
                    and gearData.ItemType,
                name
            )

        local gearKey =
            cleanItemKey(
                gearType
            )

        if gearKey:find(
            "wateringcan",
            1,
            true
        ) then
            return {
                Group =
                    "Gear",

                Category =
                    "WateringCans",

                ItemKey =
                    name,

                Name =
                    name,

                Details =
                    "Watering Can",

                Unique =
                    false,

                Supported =
                    true,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    readOwnedCount(
                        item,
                        false
                    ),

                Instance =
                    item,
            }
        end

        if gearKey:find(
            "trowel",
            1,
            true
        ) then
            return {
                Group =
                    "Gear",

                Category =
                    "Trowels",

                ItemKey =
                    name,

                Name =
                    name,

                Details =
                    "Trowel",

                Unique =
                    false,

                Supported =
                    true,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    readOwnedCount(
                        item,
                        false
                    ),

                Instance =
                    item,
            }
        end

        if gearKey:find(
            "sprinkler",
            1,
            true
        ) then
            return {
                Group =
                    "Gear",

                Category =
                    "Sprinklers",

                ItemKey =
                    name,

                Name =
                    name,

                Details =
                    "Sprinkler",

                Unique =
                    false,

                Supported =
                    true,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    readOwnedCount(
                        item,
                        false
                    ),

                Instance =
                    item,
            }
        end

        if gearData ~= nil
            or mainKey:find(
                "gear",
                1,
                true
            )
        then
            return {
                Group =
                    "Gear",

                Category =
                    nil,

                ItemKey =
                    name,

                Name =
                    name,

                Details =
                    "Gear · needs a mail test",

                Unique =
                    false,

                Supported =
                    false,

                Favorite =
                    readOwnedFavorite(
                        item
                    ),

                Count =
                    readOwnedCount(
                        item,
                        false
                    ),

                Instance =
                    item,
            }
        end

        return nil
    end

    local function scanExactItems()
        local catalogs =
            loadOwnedCatalogs()

        local grouped = {}
        local seenInstances = {}

        local roots = {
            player.Character,
            player:FindFirstChildOfClass(
                "Backpack"
            ),
        }

        for _, root in ipairs(roots) do
            if typeof(root) == "Instance" then
                for _, item in ipairs(
                    root:GetChildren()
                ) do
                    if not seenInstances[item] then
                        seenInstances[item] =
                            true

                        local record =
                            classifyOwnedItem(
                                item,
                                catalogs
                            )

                        if record then
                            record.Icon =
                                resolveOwnedRecordIcon(
                                    record,
                                    catalogs
                                )
                        end

                        if record
                            and not (
                                state.ExactProtect
                                and record.Favorite
                            )
                        then
                            local recordKey =
                                table.concat(
                                    {
                                        record.Group,
                                        record.Category
                                            or "Unknown",
                                        cleanItemKey(
                                            record.Name
                                        ),
                                        cleanItemKey(
                                            record.Details
                                        ),
                                    },
                                    "|"
                                )

                            local group =
                                grouped[recordKey]

                            if not group then
                                group = {
                                    Key =
                                        recordKey,

                                    Group =
                                        record.Group,

                                    Category =
                                        record.Category,

                                    ItemKey =
                                        record.ItemKey,

                                    Name =
                                        record.Name,

                                    Details =
                                        record.Details,

                                    Icon =
                                        record.Icon,

                                    Unique =
                                        record.Unique,

                                    Supported =
                                        record.Supported,

                                    Count =
                                        0,

                                    Sources =
                                        {},
                                }

                                grouped[recordKey] =
                                    group
                            end

                            if (
                                type(group.Icon) ~= "string"
                                or group.Icon == ""
                            )
                                and type(record.Icon) == "string"
                                and record.Icon ~= ""
                            then
                                group.Icon =
                                    record.Icon
                            end

                            group.Count +=
                                record.Count

                            table.insert(
                                group.Sources,
                                {
                                    ItemKey =
                                        record.ItemKey,

                                    Count =
                                        record.Count,

                                    Instance =
                                        record.Instance,
                                }
                            )
                        end
                    end
                end
            end
        end

        local records = {}
        local recordMap = {}

        for key, record in pairs(
            grouped
        ) do
            recordMap[key] =
                record

            table.insert(
                records,
                record
            )
        end

        table.sort(
            records,
            function(left, right)
                if left.Group ~= right.Group then
                    return left.Group < right.Group
                end

                if left.Name ~= right.Name then
                    return left.Name:lower()
                        < right.Name:lower()
                end

                return tostring(
                    left.Details
                ):lower()
                    < tostring(
                        right.Details
                    ):lower()
            end
        )

        state.ExactRecords =
            records

        state.ExactRecordMap =
            recordMap

        return records
    end

    local function selectedExactRecipient()
        for _, recipient in ipairs(
            state.ExactRecipients
        ) do
            if recipient.UserId
                == state.ExactSelectedUserId
            then
                return recipient
            end
        end

        return nil
    end

    local function exactQueueFor(userId)
        local queue =
            state.ExactQueues[userId]

        if type(queue) ~= "table" then
            queue = {}

            state.ExactQueues[userId] =
                queue
        end

        return queue
    end

    local function totalQueuedForKey(
        recordKey
    )
        local total = 0

        for _, queue in pairs(
            state.ExactQueues
        ) do
            local entry =
                queue[recordKey]

            if type(entry) == "table" then
                total +=
                    tonumber(
                        entry.Count
                    )
                    or 0
            end
        end

        return total
    end

