    updateExactSummary =
        function()
            local people = 0
            local items = 0
            local sendable = 0
            local sends = 0

            for _, recipient in ipairs(
                state.ExactRecipients
            ) do
                local queue =
                    exactQueueFor(
                        recipient.UserId
                    )

                local recipientEntries = 0
                local hasItems = false

                for _, entry in pairs(
                    queue
                ) do
                    local count =
                        tonumber(
                            entry.Count
                        )
                        or 0

                    if count > 0 then
                        hasItems =
                            true

                        items +=
                            count

                        if entry.Supported then
                            sendable +=
                                count

                            recipientEntries +=
                                entry.Unique
                                    and count
                                    or 1
                        end
                    end
                end

                if hasItems then
                    people +=
                        1
                end

                if recipientEntries > 0 then
                    sends +=
                        math.ceil(
                            recipientEntries
                            / BATCH_LIMIT
                        )
                end
            end

            local seconds =
                sends <= 1
                    and 0
                    or (
                        sends - 1
                    ) * COOLDOWN

            itemSummaryText.Text =
                string.format(
                    "People: %d\nItems: %d\nSends: %d\nKnown sendable: %d\nTime: %s",
                    people,
                    items,
                    sends,
                    sendable,
                    seconds <= 0
                            and "Immediate"
                        or "about "
                            .. tostring(
                                math.ceil(
                                    seconds
                                )
                            )
                            .. "s"
                )

            if not selectedExactRecipient() then
                itemMessageText.Text =
                    "Choose a recipient before adding items."
            elseif items <= 0 then
                itemMessageText.Text =
                    "Choose an owned item and enter an amount."
            elseif items ~= sendable then
                itemMessageText.Text =
                    "Some selected items still need a confirmed mail category."
            else
                itemMessageText.Text =
                    tostring(
                        items
                    )
                    .. " items are ready for review."
            end

            local exactSession =
                state.ExactSession

            local exactStatus =
                type(exactSession) == "table"
                and tostring(
                    exactSession.Status
                    or ""
                )
                or ""

            local reviewingUncertain =
                exactStatus == "Uncertain"

            local resumingDelivery =
                exactStatus == "Paused"

            itemSendButton.Active =
                state.Running
                or reviewingUncertain
                or resumingDelivery
                or (
                    sendable > 0
                    and items == sendable
                )

            itemSendButton.AutoButtonColor =
                itemSendButton.Active

            itemSendButton.BackgroundColor3 =
                itemSendButton.Active
                    and color.Accent
                    or color.Hover

            itemSendButton.Text =
                state.Running
                        and "Stop after current mail"
                    or reviewingUncertain
                            and "Review uncertain mail"
                        or resumingDelivery
                                and "Resume remaining delivery"
                            or "Review and send"

            return people,
                items,
                sends,
                sendable
        end

    renderExactItems =
