                )

                text(
                    row,
                    record.Name,
                    UDim2.new(
                        1,
                        -250,
                        0,
                        20
                    ),
                    UDim2.fromOffset(
                        56,
                        8
                    ),
                    10,
                    color.Text,
                    nil,
                    Enum.Font.GothamSemibold
                )

                local details =
                    record.Details
                    .. " · "
                    .. tostring(
                        available
                    )
                    .. " available"

                if not record.Supported then
                    details =
                        details
                        .. " · not ready"
                elseif queued > 0 then
                    details =
                        details
                        .. " · "
                        .. tostring(
                            queued
                        )
                        .. " selected"
                end

                text(
                    row,
                    details,
                    UDim2.new(
                        1,
                        -250,
                        0,
                        18
                    ),
                    UDim2.fromOffset(
                        56,
                        31
                    ),
                    12,
                    record.Supported
                            and color.Secondary
                        or color.Red
                )

                local amountBox =
                    box(
                        row,
                        "1",
                        UDim2.fromOffset(
                            66,
                            34
                        ),
                        UDim2.new(
                            1,
                            -172,
                            0,
                            12
                        )
                    )

                amountBox.TextXAlignment =
                    Enum.TextXAlignment.Center

                local addItemButton =
                    button(
                        row,
                        record.Supported
                                and "+ Add"
                            or "Not ready",
                        UDim2.fromOffset(
                            88,
                            34
                        ),
                        UDim2.new(
                            1,
                            -100,
                            0,
                            12
                        ),
                        record.Supported
                    )

                addItemButton.TextSize =
                    12

                addItemButton.Active =
                    record.Supported
                    and available > 0

                if not addItemButton.Active then
                    addItemButton.BackgroundColor3 =
                        color.Hover
                end

                addItemButton.MouseButton1Click:Connect(function()
                    if state.Running
                        or not addItemButton.Active
                    then
                        return
                    end

                    local recipient =
                        selectedExactRecipient()

                    if not recipient then
                        itemMessageText.Text =
                            "Choose a recipient first."

                        return
                    end

                    local rawAmount =
                        tostring(
                            amountBox.Text
                        ):lower():gsub(
                            "%s+",
                            ""
                        )

                    local wanted

                    if rawAmount == "all" then
                        wanted =
                            available
                    else
                        wanted =
                            math.floor(
                                tonumber(
                                    rawAmount
                                )
                                or 1
                            )
                    end

                    wanted =
                        math.clamp(
                            wanted,
                            1,
                            available
                        )

                    local queue =
                        exactQueueFor(
                            recipient.UserId
                        )

                    local entry =
                        queue[
                            record.Key
                        ]

                    if not entry then
                        entry = {
                            Key =
                                record.Key,

                            Name =
                                record.Name,

                            Details =
                                record.Details,

                            Icon =
                                record.Icon,

                            Group =
                                record.Group,

                            Category =
                                record.Category,

                            ItemKey =
                                record.ItemKey,

                            Unique =
                                record.Unique,

                            Supported =
                                record.Supported,

                            Count =
                                0,
                        }

                        queue[
                            record.Key
                        ] =
                            entry
                    end

                    entry.Count +=
                        wanted

                    amountBox.Text =
                        ""

                    renderExactRecipients()
                    renderExactItems()
                    updateExactSummary()
                end)
            end
        end

    refreshExactItems =
        function()
            local records =
                scanExactItems()

            local total = 0
            local protectedCount = 0

            for _, record in ipairs(
                records
            ) do
                total +=
                    record.Count
            end

            if state.ExactProtect then
                protectedCount =
                    1
            end

            itemInventoryCount.Text =
                tostring(
                    total
                )
                .. " owned"
                .. (
                    protectedCount > 0
                        and " · favorites skipped"
                        or ""
                )

            renderExactItems()
            renderExactRecipients()
            updateExactSummary()
        end

    local function addExactRecipient()
        if state.RecipientChangesLocked() then
            return
        end

        local raw =
            tostring(
                itemRecipientBox.Text
            )
                :gsub(
                    "^%s+",
                    ""
                )
                :gsub(
                    "%s+$",
                    ""
                )

        if raw == "" then
            itemRecipientBox.PlaceholderText =
                "Enter a recipient"

            return
        end

        itemRecipientAdd.Text =
            "Checking..."

        local userId
        local username
        local numeric =
            tonumber(
                raw
            )

        if numeric then
            local ok,
                result =
                pcall(
                    Players.GetNameFromUserIdAsync,
                    Players,
                    math.floor(
                        numeric
                    )
                )

            if ok then
                userId =
                    math.floor(
                        numeric
                    )

                username =
                    result
            end
        else
            local ok,
                result =
                pcall(
                    Players.GetUserIdFromNameAsync,
                    Players,
                    raw
                )

            if ok then
                userId =
                    result

                local nameOk,
                    name =
                    pcall(
                        Players.GetNameFromUserIdAsync,
                        Players,
                        userId
                    )

                username =
                    nameOk
                        and name
                        or raw
            end
        end

        if not userId
            or not username
            or userId == player.UserId
        then
            itemRecipientBox.Text =
                ""

            itemRecipientBox.PlaceholderText =
                "Recipient not found"

            itemRecipientAdd.Text =
                "+ Add"

            return
        end

        for _, recipient in ipairs(
            state.ExactRecipients
        ) do
            if recipient.UserId
                == userId
            then
                state.ExactSelectedUserId =
                    userId

                HolyMailTouchRecipient(
                    userId,
                    username
                )

                itemRecipientBox.Text =
                    ""

                itemRecipientAdd.Text =
                    "+ Add"

                renderExactRecipients()
                renderExactItems()
                updateExactSummary()

                return
            end
        end

        table.insert(
            state.ExactRecipients,
            {
                UserId =
                    userId,

                Name =
                    username,
            }
        )

        state.ExactSelectedUserId =
            userId

        HolyMailTouchRecipient(
            userId,
            username
        )

        itemRecipientBox.Text =
            ""

        itemRecipientBox.PlaceholderText =
            "Username or User ID"

        itemRecipientAdd.Text =
            "+ Add"

        renderExactRecipients()
        renderExactItems()
        updateExactSummary()
    end

    state.ExactClearButton.MouseButton1Click:Connect(function()
        if state.RecipientChangesLocked()
            or #state.ExactRecipients == 0
        then
            return
        end

        showModal(
            "Clear everyone?",
            "This removes every Pick Items recipient and every item selected for them. Your inventory will not be changed.",
            "Clear all",
            function()
                if state.RecipientChangesLocked() then
                    return
                end

                state.ExactRecipients = {}

                state.ExactQueues = {}

                state.ExactSelectedUserId =
                    nil

                itemRecipientBox.Text =
                    ""

                itemRecipientBox.PlaceholderText =
                    "Username or User ID"

                itemRecipientAdd.Text =
                    "+ Add"

                renderExactRecipients()
                renderExactItems()
                updateExactSummary()
            end,
            false
        )
    end)

    local function buildExactRoutes()
        scanExactItems()

        local usedUnique = {}
        local usedStacked = {}
        local routes = {}
        local totalItems = 0
        local totalMails = 0
        local missing = 0

        for _, recipient in ipairs(
            state.ExactRecipients
        ) do
            local payloads = {}
            local payloadHistoryKeys = {}

            local historyItems = {}
            local historyItemMap = {}

            local function addHistoryItem(
                recordKey,
                record,
                count
            )
                count =
                    math.max(
                        0,
                        math.floor(
                            tonumber(count)
                                or 0
                        )
                    )

                if count <= 0 then
                    return
                end

                local key =
                    tostring(recordKey)

                local historyItem =
                    historyItemMap[key]

                if not historyItem then
                    historyItem = {
                        Key = key,

                        Name =
                            tostring(
                                record.Name
                                    or "Unknown item"
                            ),

                        Details =
                            tostring(
                                record.Details
                                    or record.Group
                                    or "Item"
                            ),

                        Icon =
                            tostring(
                                record.Icon
                                    or ""
                            ),

                        Count = 0,
                        Sent = 0,
                        Value = 0,
                    }

                    historyItemMap[key] =
                        historyItem

                    table.insert(
                        historyItems,
                        historyItem
                    )
                end

                historyItem.Count +=
                    count
            end

            local recipientItems = 0
            local queue =
                exactQueueFor(
                    recipient.UserId
                )

            for recordKey, queued in pairs(
                queue
            ) do
                local wanted =
                    math.max(
                        0,
                        math.floor(
                            tonumber(
                                queued.Count
                            )
                            or 0
                        )
                    )

                if wanted > 0 then
                    local record =
                        state.ExactRecordMap[
                            recordKey
                        ]

                    if not record
                        or not record.Supported
                        or not record.Category
                    then
                        missing +=
                            wanted
                    elseif record.Unique then
                        local added = 0

                        for _, source in ipairs(
                            record.Sources
                        ) do
                            if added >= wanted then
                                break
                            end

                            if not usedUnique[
                                source.ItemKey
                            ] then
                                usedUnique[
                                    source.ItemKey
                                ] =
                                    true

                                table.insert(
                                    payloads,
                                    {
                                        ItemKey =
                                            source.ItemKey,

                                        Count =
                                            1,

                                        Category =
                                            record.Category,
                                    }
                                )

                                payloadHistoryKeys[
                                    #payloads
                                ] =
                                    tostring(
                                        recordKey
                                    )

                                addHistoryItem(
                                    recordKey,
                                    record,
                                    1
                                )

                                added +=
                                    1
                            end
                        end

                        recipientItems +=
                            added

                        totalItems +=
                            added

                        if added < wanted then
                            missing +=
                                wanted - added
                        end
                    else
                        local alreadyUsed =
                            usedStacked[
                                recordKey
                            ]
                            or 0

                        local available =
                            math.max(
                                0,
                                record.Count
                                    - alreadyUsed
                            )

                        local added =
                            math.min(
                                wanted,
                                available
                            )

                        if added > 0 then
                            usedStacked[
                                recordKey
                            ] =
                                alreadyUsed
                                + added

                            table.insert(
                                payloads,
                                {
                                    ItemKey =
                                        record.ItemKey,

                                    Count =
                                        added,

                                    Category =
                                        record.Category,
                                }
                            )

                            payloadHistoryKeys[
                                #payloads
                            ] =
                                tostring(
                                    recordKey
                                )

                            addHistoryItem(
                                recordKey,
                                record,
                                added
                            )

                            recipientItems +=
                                added

                            totalItems +=
                                added
                        end

                        if added < wanted then
                            missing +=
                                wanted - added
                        end
                    end
                end
            end

            if #payloads > 0 then
                local mails =
                    math.ceil(
                        #payloads
                        / BATCH_LIMIT
                    )

                totalMails +=
                    mails

                table.insert(
                    routes,
                    {
                        Recipient =
                            recipient,

                        Payloads =
                            payloads,

                        Items =
                            recipientItems,

                        Mails =
                            mails,

                        HistoryItems =
                            historyItems,

                        PayloadHistoryKeys =
                            payloadHistoryKeys,
                    }
                )
            end
        end

        return routes,
            totalItems,
            totalMails,
            missing
    end

    state.Safety.ExactRequirements =
        function(batchHistory)
            local requirements = {}

            for _, entry in ipairs(
                batchHistory
            ) do
                local key =
                    tostring(
                        entry.Key
                        or ""
                    )

                if key ~= "" then
                    requirements[key] =
                        (
                            requirements[key]
                            or 0
                        )
                        + math.max(
                            0,
                            math.floor(
                                tonumber(
                                    entry.Count
                                )
                                or 0
                            )
                        )
                end
            end

            return requirements
        end

    state.Safety.ValidateExactBatch =
        function(batchHistory)
            HolyMailCheckDay()
            updateQuota()

            if tracker.Used >= DAILY_LIMIT then
                return false,
                    "No daily sends remain.",
                    "DAILY"
            end

            scanExactItems()

            local requirements =
                state.Safety.ExactRequirements(
                    batchHistory
                )

            local snapshot = {}

            for recordKey, required in pairs(
                requirements
            ) do
                local record =
                    state.ExactRecordMap[
                        recordKey
                    ]

                local available =
                    record
                    and tonumber(
                        record.Count
                    )
                    or 0

                snapshot[recordKey] =
                    available

                if not record
                    or not record.Supported
                    or not record.Category
                    or available < required
                then
                    return false,
                        "Selected items changed, disappeared, or became protected.",
                        "INVENTORY"
                end
            end

            return true,
                snapshot,
                "READY"
        end

    state.Safety.WaitForExactRemoval =
        function(
            batchHistory,
            beforeSnapshot,
            timeout
        )
            local requirements =
                state.Safety.ExactRequirements(
                    batchHistory
                )

            local deadline =
                os.clock()
                + (
                    tonumber(timeout)
                    or 8
                )

            repeat
                scanExactItems()

                local complete =
                    true

                for recordKey, required in pairs(
                    requirements
                ) do
                    local record =
                        state.ExactRecordMap[
                            recordKey
                        ]

                    local current =
                        record
                        and tonumber(
                            record.Count
                        )
                        or 0

                    local before =
                        tonumber(
                            beforeSnapshot[
                                recordKey
                            ]
                        )
                        or 0

                    if current
                        > math.max(
                            0,
                            before - required
                        )
                    then
                        complete =
                            false

                        break
                    end
                end

                if complete then
                    return true
                end

                task.wait(
                    0.15
                )
            until os.clock() >= deadline

            return false
        end

    state.Safety.ConsumeExactQueue =
        function(
            recipientUserId,
            batchHistory
        )
            local queue =
                exactQueueFor(
                    recipientUserId
                )

            for recordKey, amount in pairs(
                state.Safety.ExactRequirements(
                    batchHistory
                )
            ) do
                local queued =
                    queue[
                        recordKey
                    ]

                if type(queued) == "table" then
                    queued.Count =
                        math.max(
                            0,
                            (
                                tonumber(
                                    queued.Count
                                )
                                or 0
                            )
                            - amount
                        )

                    if queued.Count <= 0 then
                        queue[
                            recordKey
                        ] =
                            nil
                    end
                end
            end
        end

    state.Safety.SendExactPayload =
        function(
            packet,
            recipient,
            payload,
            batchHistory
        )
            while not state.Stop do
                local valid,
                    snapshot,
                    validationType =
                    state.Safety.ValidateExactBatch(
                        batchHistory
                    )

                if not valid then
                    return false,
                        tostring(
                            snapshot
                        ),
                        validationType,
                        false
                end

                if not state.Safety.WaitForCooldown() then
                    return false,
                        "Stopped",
                        "STOPPED",
                        false
                end

                valid,
                snapshot,
                validationType =
                    state.Safety.ValidateExactBatch(
                        batchHistory
                    )

                if not valid then
                    return false,
                        tostring(
                            snapshot
                        ),
                        validationType,
                        false
                end

                local started =
                    workspace:GetServerTimeNow()

                setStatus(
                    "Sending",
                    color.Yellow
                )

                local ok,
                    first,
                    second =
                    pcall(function()
                        return packet:Fire(
                            recipient.UserId,
                            payload,
                            ""
                        )
                    end)

                if not ok then
                    return false,
                        tostring(
                            first
                        ),
                        "ERROR",
                        false
                end

                local message =
                    tostring(
                        second or ""
                    )

                if first == true then
                    state.Safety.RecordAcceptedMail(
                        started
                    )

                    state.Safety.ConsumeExactQueue(
                        recipient.UserId,
                        batchHistory
                    )

                    local confirmed =
                        state.Safety.WaitForExactRemoval(
                            batchHistory,
                            snapshot,
                            8
                        )

                    if not confirmed then
                        return false,
                            "The server accepted this mail, but inventory removal could not be confirmed.",
                            "UNCERTAIN",
                            true
                    end

                    return true,
                        message,
                        "CONFIRMED",
                        true
                end

                local lower =
                    message:lower()

                local seconds =
                    tonumber(
                        lower:match(
                            "wait%s+(%d+)%s*s"
                        )
                    )

                if seconds then
                    task.wait(
                        seconds + 0.25
                    )
                elseif lower:find(
                    "daily gift limit",
                    1,
                    true
                ) then
                    tracker.Used =
                        DAILY_LIMIT

                    HOLY_MAIL_STATE.TrackerDay =
                        HolyMailToday()

                    HOLY_MAIL_STATE.TrackerUsed =
                        DAILY_LIMIT

                    updateQuota()
                    HolyMailSaveSettings()

                    return false,
                        message,
                        "DAILY",
                        false
                else
                    return false,
                        message ~= ""
                                and message
                            or tostring(
                                first
                            ),
                        "REJECTED",
                        false
                end
            end

            return false,
                "Stopped",
                "STOPPED",
                false
        end

    state.Safety.RunExactDelivery =
        function(
            routes,
            totalItems,
            totalMails
        )
            protectedCall(
                "Item delivery",
                function()
                    local packet,
                        packetError =
                        getSendPacket()

                    if not packet then
                        itemMessageText.Text =
                            tostring(
                                packetError
                            )

                        if type(
                            state.ExactSession
                        ) == "table" then
                            state.ExactSession.Status =
                                "Paused"
                        end

                        return
                    end

                    local session =
                        state.ExactSession

                    if type(session) ~= "table" then
                        return
                    end

                    session.Status =
                        "Running"

                    state.Running =
                        true

                    state.Stop =
                        false

                    itemProgressFill.Size =
                        UDim2.fromScale(
                            0,
                            1
                        )

                    local completedMails = 0
                    local completedItems = 0
                    local completedPeople = 0
                    local failure
                    local failureType

                    renderExactRecipients()
                    updateExactSummary()

                    for _, route in ipairs(
                        routes
                    ) do
                        local recipientComplete =
                            true

                        local historyRecord = {
                            Direction = "Sent",
                            Mode = "Pick Items",
                            Status = "Failed",

                            OtherUserId =
                                route.Recipient.UserId,

                            OtherName =
                                route.Recipient.Name,

                            AttemptedMails =
                                route.Mails,

                            AcceptedMails = 0,

                            PlannedItems =
                                route.Items,

                            SentItems = 0,

                            TargetValue = 0,
                            AcceptedValue = 0,

                            Items = {},
                        }

                        local historyItemMap = {}

                        for _, historyItem in ipairs(
                            route.HistoryItems
                            or {}
                        ) do
                            local copy = {
                                Key =
                                    tostring(
                                        historyItem.Key
                                        or ""
                                    ),

                                Name =
                                    tostring(
                                        historyItem.Name
                                        or "Unknown item"
                                    ),

                                Details =
                                    tostring(
                                        historyItem.Details
                                        or "Item"
                                    ),

                                Icon =
                                    tostring(
                                        historyItem.Icon
                                        or ""
                                    ),

                                Count =
                                    tonumber(
                                        historyItem.Count
                                    )
                                    or 0,

                                Sent = 0,
                                Value = 0,
                            }

                            table.insert(
                                historyRecord.Items,
                                copy
                            )

                            historyItemMap[
                                copy.Key
                            ] =
                                copy
                        end

                        for firstIndex = 1,
                            #route.Payloads,
                            BATCH_LIMIT
                        do
                            if state.Stop then
                                recipientComplete =
                                    false

                                break
                            end

                            local payload = {}
                            local batchHistory = {}
                            local batchItems = 0

                            for payloadIndex = firstIndex,
                                math.min(
                                    firstIndex
                                        + BATCH_LIMIT
                                        - 1,
                                    #route.Payloads
                                )
                            do
                                local entry =
                                    route.Payloads[
                                        payloadIndex
                                    ]

                                table.insert(
                                    payload,
                                    entry
                                )

                                local historyEntry = {
                                    Key =
                                        tostring(
                                            route.PayloadHistoryKeys[
                                                payloadIndex
                                            ]
                                            or ""
                                        ),

                                    Count =
                                        tonumber(
                                            entry.Count
                                        )
                                        or 1,
                                }

                                table.insert(
                                    batchHistory,
                                    historyEntry
                                )

                                batchItems +=
                                    historyEntry.Count
                            end

                            itemSendButton.Text =
                                string.format(
                                    "@%s · %d/%d",
                                    route.Recipient.Name,
                                    completedMails + 1,
                                    totalMails
                                )

                            local confirmed,
                                response,
                                responseType,
                                acceptedByServer =
                                state.Safety.SendExactPayload(
                                    packet,
                                    route.Recipient,
                                    payload,
                                    batchHistory
                                )

                            if acceptedByServer then
                                completedMails +=
                                    1

                                completedItems +=
                                    batchItems

                                session.AcceptedMails =
                                    (
                                        tonumber(
                                            session.AcceptedMails
                                        )
                                        or 0
                                    )
                                    + 1

                                session.AcceptedItems =
                                    (
                                        tonumber(
                                            session.AcceptedItems
                                        )
                                        or 0
                                    )
                                    + batchItems

                                historyRecord.AcceptedMails +=
                                    1

                                historyRecord.SentItems +=
                                    batchItems

                                for _, acceptedItem in ipairs(
                                    batchHistory
                                ) do
                                    local historyItem =
                                        historyItemMap[
                                            acceptedItem.Key
                                        ]

                                    if historyItem then
                                        historyItem.Sent +=
                                            acceptedItem.Count
                                    end
                                end

                                itemProgressFill.Size =
                                    UDim2.fromScale(
                                        completedMails
                                            / math.max(
                                                totalMails,
                                                1
                                            ),
                                        1
                                    )

                                itemMessageText.Text =
                                    string.format(
                                        "Accepted %d of %d items.",
                                        completedItems,
                                        totalItems
                                    )
                            end

                            if not confirmed then
                                recipientComplete =
                                    false

                                failure =
                                    tostring(
                                        response
                                        or "Delivery paused"
                                    )

                                failureType =
                                    tostring(
                                        responseType
                                        or "PAUSED"
                                    )

                                if failureType
                                    == "UNCERTAIN"
                                then
                                    session.UncertainBatch = {
                                        Recipient =
                                            route.Recipient,

                                        Payload =
                                            payload,

                                        History =
                                            batchHistory,

                                        Accepted =
                                            acceptedByServer == true,
                                    }
                                end

                                break
                            end
                        end

                        if failureType == "UNCERTAIN" then
                            historyRecord.Status =
                                "Uncertain"
                        elseif recipientComplete then
                            historyRecord.Status =
                                "Sent"
                        elseif historyRecord.AcceptedMails > 0
                            or state.Stop
                        then
                            historyRecord.Status =
                                "Partial"
                        else
                            historyRecord.Status =
                                "Failed"
                        end

                        historyRecord.Error =
                            failure
                            or (
                                state.Stop
                                and "Stopped by user"
                                or ""
                            )

                        HolyMailHistoryAdd(
                            historyRecord
                        )

                        if recipientComplete then
                            completedPeople +=
                                1
                        else
                            break
                        end
                    end

                    local stopped =
                        state.Stop
                        and not failure

                    local complete =
                        completedMails == totalMails
                        and not failure
                        and not stopped

                    if complete then
                        session.Status =
                            "Complete"

                        state.ExactSession =
                            nil
                    elseif failureType == "UNCERTAIN" then
                        session.Status =
                            "Uncertain"
                    else
                        session.Status =
                            "Paused"
                    end

                    state.Running =
                        false

                    state.Stop =
                        false

                    setStatus(
                        complete
                                and "Complete"
                            or failureType == "UNCERTAIN"
                                    and "Confirmation uncertain"
                                or "Paused",
                        complete
                                and color.Green
                            or failureType == "UNCERTAIN"
                                    and color.Red
                                or color.Yellow
                    )

                    showModal(
                        complete
                                and "Delivery complete"
                            or failureType == "UNCERTAIN"
                                    and "Confirmation uncertain"
                                or failureType == "DAILY"
                                        and "Daily limit reached"
                                    or "Delivery paused",
                        (
                            failure
                            and failure
                                .. "\n\n"
                            or ""
                        )
                        .. string.format(
                            "People completed: %d\nItems accepted: %d\nSends accepted: %d",
                            completedPeople,
                            completedItems,
                            completedMails
                        ),
                        nil,
                        nil,
                        not complete
                    )

                    task.wait(
                        0.35
                    )

                    refreshExactItems()

                    if type(
                        state.ExactSession
                    ) == "table" then
                        if state.ExactSession.Status
                            == "Uncertain"
                        then
                            itemSendButton.Text =
                                "Review uncertain mail"

                            itemSendButton.Active =
                                true

                            itemSendButton.BackgroundColor3 =
                                color.Accent
                        elseif state.ExactSession.Status
                            == "Paused"
                        then
                            itemSendButton.Text =
                                "Resume remaining delivery"
                        end
                    else
                        itemSendButton.Text =
                            "Review and send"
                    end
                end
            )
        end

    state.Safety.RequestExactDelivery =
        function()
            if state.Running then
                state.Stop =
                    true

                itemSendButton.Text =
                    "Stopping after current mail..."

                return
            end

            local session =
                state.ExactSession

            if type(session) == "table"
                and session.Status == "Uncertain"
            then
                showModal(
                    "Confirmation uncertain",
                    "The server accepted the previous mail, but HOLY could not confirm that its items disappeared.\n\nThat batch was removed from the queue and will never be resent automatically.",
                    "Continue safely",
                    function()
                        session.Status =
                            "Paused"

                        session.UncertainBatch =
                            nil

                        refreshExactItems()

                        itemSendButton.Text =
                            "Resume remaining delivery"
                    end,
                    true
                )

                return
            end

            local resuming =
                type(session) == "table"
                and session.Status == "Paused"

            local routes,
                totalItems,
                totalMails,
                missing =
                buildExactRoutes()

            if missing > 0 then
                itemMessageText.Text =
                    tostring(
                        missing
                    )
                    .. " remaining items are unavailable, protected, or still need a mail test."

                refreshExactItems()

                return
            end

            if #routes == 0
                or totalItems <= 0
                or totalMails <= 0
            then
                if resuming then
                    state.ExactSession =
                        nil

                    itemMessageText.Text =
                        "The remaining delivery is complete."

                    itemMessageText.TextColor3 =
                        color.Green

                    itemSendButton.Text =
                        "Review and send"

                    refreshExactItems()
                else
                    itemMessageText.Text =
                        "Select at least one supported item."
                end

                return
            end

            local remaining =
                DAILY_LIMIT
                - tracker.Used

            if totalMails > remaining then
                itemMessageText.Text =
                    "This needs "
                    .. tostring(
                        totalMails
                    )
                    .. " sends, but only "
                    .. tostring(
                        remaining
                    )
                    .. " remain today."

                return
            end

            local seconds =
                totalMails <= 1
                and 0
                or (
                    totalMails - 1
                ) * COOLDOWN

            showModal(
                resuming
                        and "Resume remaining delivery"
                    or "Review before sending",
                string.format(
                    "People: %d\nItems remaining: %d\nSends remaining: %d\nTime: about %ds",
                    #routes,
                    totalItems,
                    totalMails,
                    math.ceil(
                        seconds
                    )
                ),
                resuming
                        and "Resume"
                    or "Send now",
                function()
                    if not resuming then
                        state.ExactSession = {
                            Status = "Ready",
                            AcceptedMails = 0,
                            AcceptedItems = 0,
                            UncertainBatch = nil,
                        }
                    end

                    task.spawn(
                        state.Safety.RunExactDelivery,
                        routes,
                        totalItems,
                        totalMails
                    )
                end,
                true
            )
        end

    local function applyMailMode(
        selectedMode
    )
        if state.Running then
            return
        end

        state.MailMode =
            selectedMode == "Items"
                and "Items"
                or "Value"

        local itemMode =
            state.MailMode == "Items"

        itemPanel.Visible =
            itemMode

        setSelectedButton(
            valueModeButton,
            not itemMode
        )

        setSelectedButton(
            itemModeButton,
            itemMode
        )

        if state.ActiveTab == "Send" then
            subtitle.Text =
                itemMode
                    and "Pick exact items"
                    or "Send fruits by value"
        end

        if itemMode then
            state.ExactView =
                "Owned"

            refreshExactItems()
        else
            task.spawn(function()
                protectedCall(
                    "Value mode refresh",
                    rebuildPlan
                )
            end)
        end
    end

    state.ApplyMailMode =
        applyMailMode

    state.Fleet.LoadIntoItems =
        function()
            if state.RecipientChangesLocked() then
                state.Fleet.StatusLabel.Text =
                    "Finish or safely end the current delivery first."

                state.Fleet.StatusLabel.TextColor3 =
                    color.Yellow

                return
            end

            local accounts =
                state.Fleet.EnabledAccounts()

            if #accounts == 0 then
                state.Fleet.StatusLabel.Text =
                    "This group has no enabled accounts."

                state.Fleet.StatusLabel.TextColor3 =
                    color.Red

                return
            end

            local snapshots = {}

            for _, account in ipairs(
                accounts
            ) do
                table.insert(
                    snapshots,
                    {
                        UserId =
                            account.UserId,

                        Name =
                            account.Name,
                    }
                )
            end

            state.ExactRecipients =
                snapshots

            state.ExactQueues =
                {}

            state.ExactSelectedUserId =
                snapshots[1]
                and snapshots[1].UserId
                or nil

            state.Fleet.LoadedGroup =
                state.Fleet.ActiveGroup

            itemRecipientBox.Text =
                ""

            itemRecipientBox.PlaceholderText =
                "Username or User ID"

            itemRecipientAdd.Text =
                "+ Add"

            applyMailMode(
                "Items"
            )

            if type(
                state.ShowMainPage
            ) == "function" then
                state.ShowMainPage(
                    "Send"
                )
            end

            itemMessageText.Text =
                tostring(
                    #snapshots
                )
                .. " Fleet accounts loaded. Choose items for each recipient."

            itemMessageText.TextColor3 =
                color.Secondary

            refreshExactItems()
        end

    valueModeButton.MouseButton1Click:Connect(function()
        applyMailMode(
            "Value"
        )
    end)

    itemModeButton.MouseButton1Click:Connect(function()
        applyMailMode(
            "Items"
        )
    end)

    itemRecipientAdd.MouseButton1Click:Connect(function()
        protectedCall(
            "Add item recipient",
            addExactRecipient
        )
    end)

    itemRecipientBox.FocusLost:Connect(function(enterPressed)
        if enterPressed then
            protectedCall(
                "Add item recipient",
                addExactRecipient
            )
        end
    end)

    for categoryName, categoryButton in pairs(
        itemCategoryButtons
    ) do
        categoryButton.MouseButton1Click:Connect(function()
            if state.Running then
                return
            end

            state.ExactCategories =
                type(
                    state.ExactCategories
                ) == "table"
                    and state.ExactCategories
                    or {}

            if state.ExactCategories[
                categoryName
            ] == true then
                state.ExactCategories[
                    categoryName
                ] =
                    nil
            else
                state.ExactCategories[
                    categoryName
                ] =
                    true
            end

            state.ExactView =
                "Owned"

            for otherName, otherButton in pairs(
                itemCategoryButtons
            ) do
                setSelectedButton(
                    otherButton,
                    state.ExactCategories[
                        otherName
                    ] == true
                )
            end

            renderExactItems()
        end)
    end

    itemSearchBox:GetPropertyChangedSignal(
        "Text"
    ):Connect(function()
        state.ExactSearch =
            itemSearchBox.Text

        if state.ExactView == "Owned" then
            renderExactItems()
        end
    end)

    itemRefreshButton.MouseButton1Click:Connect(function()
        protectedCall(
            "Refresh owned items",
            refreshExactItems
        )
    end)

    itemProtectButton.MouseButton1Click:Connect(function()
        if state.Running then
            return
        end

        state.ExactProtect =
            not state.ExactProtect

        itemProtectButton.Text =
            "Skip favorites: "
            .. (
                state.ExactProtect
                    and "ON"
                    or "OFF"
            )

        refreshExactItems()
    end)

    itemQueueButton.MouseButton1Click:Connect(function()
        state.ExactView =
            state.ExactView == "Owned"
                and "Selected"
                or "Owned"

        renderExactItems()
    end)

    itemSendButton.MouseButton1Click:Connect(function()
        protectedCall(
            "Exact item send",
            state.Safety.RequestExactDelivery
        )
    end)

    applyMailMode(
        "Value"
    )

    showMainPage(
        state.ActiveTab
    )

    updateQuota()
    renderRecipients()

    setStatus(
        "Ready",
        color.Green
    )

    messageText.Text =
        "HUD loaded. Add a recipient or refresh the preview."

    print(
        "[HOLY MAIL] V7 HUD loaded successfully"
    )

    if state.Minimized == true then
        applyMinimized()
    end

    task.spawn(function()
        protectedCall(
            "Initial inventory scan",
            rebuildPlan
        )
    end)

    return true
end

function HolyMailDestroyHud(reason)
    local deliveryState =
        HOLY_MAIL_RUNTIME.DeliveryState

    if type(deliveryState) == "table"
        and deliveryState.Running == true
    then
        deliveryState.Stop =
            true

        if HOLY_MAIL_RUNTIME.DestroyPending ~= true then
            HOLY_MAIL_RUNTIME.DestroyPending =
                true

            task.spawn(function()
                local deadline =
                    os.clock() + 15

                while type(HOLY_MAIL_RUNTIME.DeliveryState) == "table"
                    and HOLY_MAIL_RUNTIME.DeliveryState.Running == true
                    and os.clock() < deadline
                do
                    task.wait(0.1)
                end

                HOLY_MAIL_RUNTIME.DestroyPending =
                    false

                HolyMailDestroyHud(reason)
            end)
        end

        return false
    end

    local gui =
        HOLY_MAIL_RUNTIME.Gui

    if typeof(gui) == "Instance" then
        pcall(function()
            gui:Destroy()
        end)
    end

    HOLY_MAIL_RUNTIME.Gui =
        nil

    HOLY_MAIL_RUNTIME.Window =
        nil

    HOLY_MAIL_RUNTIME.DeliveryState =
        nil

    HOLY_MAIL_RUNTIME.SetMinimized =
        nil

    HOLY_MAIL_RUNTIME.ApplyScale =
        nil

    HOLY_MAIL_RUNTIME.UpdateQuota =
        nil

    HOLY_MAIL_RUNTIME.Status =
        "Closed"

    HolyMailRefreshControlUI()

    return true
end

function HolyMailSyncToggle(value)
    local toggle =
        type(Toggles) == "table"
        and Toggles.HolyMailHud
        or nil

    if type(toggle) ~= "table"
        or type(toggle.SetValue) ~= "function"
        or toggle.Value == (value == true)
    then
        return false
    end

    HOLY_MAIL_RUNTIME.SyncingToggle =
        true

    pcall(function()
        toggle:SetValue(
            value == true
        )
    end)

    HOLY_MAIL_RUNTIME.SyncingToggle =
        false

    return true
end

function HolyMailSetEnabled(
    value,
    fromToggle
)
    local enabled =
        value == true

    HOLY_MAIL_STATE.HudEnabled =
        enabled

    if enabled == true then
        local ok, result =
            xpcall(
                HolyMailCreateHud,
                function(message)
                    return tostring(message)
                        .. "\n"
                        .. debug.traceback()
                end
            )

        if ok ~= true
            or result ~= true
        then
            HOLY_MAIL_STATE.HudEnabled =
                false

            HOLY_MAIL_RUNTIME.Status =
                "Error"

            HOLY_MAIL_RUNTIME.LastError =
                tostring(result)

            warn(
                "[HOLY MAIL]",
                tostring(result)
            )

            HolyNotify(
                "HOLY Mail",
                "The Mail HUD could not open. The error was printed to the console.",
                6
            )

            enabled =
                false
        end
    else
        HolyMailDestroyHud("disabled")
    end

    HolyMailSaveSettings()
    HolyMailRefreshControlUI()

    if fromToggle ~= true then
        HolyMailSyncToggle(enabled)
    end

    return enabled
end

function HolyMailOpenHud()
    if HOLY_MAIL_STATE.HudEnabled ~= true then
        return HolyMailSetEnabled(true)
    end

    if typeof(HOLY_MAIL_RUNTIME.Gui) ~= "Instance" then
        HolyMailCreateHud()
    end

    if type(HOLY_MAIL_RUNTIME.SetMinimized) == "function" then
        HOLY_MAIL_RUNTIME.SetMinimized(false)
    end

    return true
end

function HolyMailResetPosition()
    HOLY_MAIL_STATE.HudPosition =
        nil

    local window =
        HOLY_MAIL_RUNTIME.Window

    if typeof(window) == "Instance" then
        window.Position =
            UDim2.fromScale(
                0.5,
                0.5
            )
    end

    HolyMailSaveSettings()

    return true
end

HOLY_MAIL_RUNTIME.Stop =
    function(reason)
        HolyMailStopInboxWorker()

        HOLY_MAIL_STATE.HudEnabled =
            false

        return HolyMailDestroyHud(
            reason or "stop"
        )
    end


