function HolyFarmNormalizePageMode(mode)

    local text =
        HolyCleanText(
            mode
        )

    local lower =
        text:lower()

    if lower:find("plant", 1, true) then
        return "Plant"
    end

    if lower:find("tool", 1, true) then
        return "Tools"
    end

    if lower:find("extra", 1, true)
    or lower:find("misc", 1, true)
    or lower:find("setting", 1, true) then

        return "Extra"
    end

    return "Collect"
end

function HolyFarmRefreshPage()

    HOLY_FARM_PAGE_STATE =
        type(HOLY_FARM_PAGE_STATE) == "table"
        and HOLY_FARM_PAGE_STATE
        or {}

    local mode =
        HolyFarmNormalizePageMode(
            HOLY_FARM_PAGE_STATE.Mode
            or "Collect"
        )

    HOLY_FARM_PAGE_STATE.Mode =
        mode

    local isCollect =
        mode == "Collect"

    local isPlant =
        mode == "Plant"

    local isTools =
        mode == "Tools"

    local isExtra =
        mode == "Extra"

    HolySetGroupboxVisible(
        FarmCollectionBox,
        isCollect
    )

    HolySetGroupboxVisible(
        FarmCollectionFiltersBox,
        isCollect
    )

    HolySetGroupboxVisible(
        FarmProCollectionBox,
        isCollect
    )

    HolySetGroupboxVisible(
        FarmCollectionOverridesBox,
        isCollect
    )

    HolySetGroupboxVisible(
        FarmPlantBox,
        isPlant
    )

    HolySetGroupboxVisible(
        FarmPlantSettingsBox,
        isPlant
    )

    HolySetGroupboxVisible(
        FarmToolsWaterBox,
        isTools
    )

    HolySetGroupboxVisible(
        FarmToolsUtilityBox,
        isTools
    )

    HolySetGroupboxVisible(
        FarmExtraUtilitiesBox,
        isExtra
    )

    HolySetGroupboxVisible(
        FarmFruitAutomationBox,
        isExtra
    )

    HolySetGroupboxVisible(
        FarmPlantMergeBox,
        isExtra
    )

    HolySetGroupboxVisible(
        FarmPlantPotsBox,
        isExtra
    )

    HolySetGroupboxVisible(
        FarmPlantEclipseBox,
        isExtra
    )

    if Tabs.Farm
    and type(Tabs.Farm.RefreshSides) == "function" then

        task.defer(function()

            Tabs.Farm:RefreshSides()
        end)
    end

    return mode
end

function HolyFarmSetPage(mode)

    HOLY_FARM_PAGE_STATE =
        type(HOLY_FARM_PAGE_STATE) == "table"
        and HOLY_FARM_PAGE_STATE
        or {}

    mode =
        HolyFarmNormalizePageMode(
            mode
        )

    HOLY_FARM_PAGE_STATE.Mode =
        mode

    if FarmModeControl
    and type(FarmModeControl.SetValue) == "function" then

        pcall(function()

            FarmModeControl:SetValue(
                mode,
                true
            )
        end)
    end

    return HolyFarmRefreshPage()
end

