function HolyServerFinderSelectionValues(value)

    local output =
        {}

    if type(value) ~= "table" then
        return output
    end

    for key, enabled in pairs(value) do

        local text =
            ""

        if type(key) == "number" then

            text =
                HolyCleanText(
                    enabled
                )

        elseif enabled == true then

            text =
                HolyCleanText(
                    key
                )
        end

        if text ~= "" then

            table.insert(
                output,
                text
            )
        end
    end

    return output
end

function HolyServerFinderAddMapValue(map, value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return false
    end

    map[value] =
        true

    return true
end

function HolyServerFinderNormalizeSizeChoice(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "big" then
        return "Big"
    end

    if lower == "huge"
    or lower == "mega" then
        return "Huge"
    end

    if lower == "normal"
    or lower == "regular" then
        return "Normal"
    end

    if lower == "big rainbow" then
        return "Big"
    end

    if lower == "mega rainbow"
    or lower == "huge rainbow" then
        return "Huge"
    end

    return ""
end

function HolyServerFinderNormalizeVariantChoice(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "rainbow"
    or lower == "big rainbow"
    or lower == "huge rainbow"
    or lower == "mega rainbow" then
        return "Rainbow"
    end

    if lower == "regular"
    or lower == "normal" then
        return "Regular"
    end

    return ""
end

function HolyServerFinderMapFromArray(value)

    local output =
        {}

    for _, text in ipairs(HolyServerFinderSelectionValues(value)) do

        HolyServerFinderAddMapValue(
            output,
            text
        )
    end

    return output
end

function HolyServerFinderSizeMapFromArray(value)

    local output =
        {}

    for _, text in ipairs(HolyServerFinderSelectionValues(value)) do

        local size =
            HolyServerFinderNormalizeSizeChoice(
                text
            )

        if size ~= "" then

            HolyServerFinderAddMapValue(
                output,
                size
            )
        end
    end

    return output
end

function HolyServerFinderVariantMapFromArray(value)

    local output =
        {}

    for _, text in ipairs(HolyServerFinderSelectionValues(value)) do

        local variant =
            HolyServerFinderNormalizeVariantChoice(
                text
            )

        if variant ~= "" then

            HolyServerFinderAddMapValue(
                output,
                variant
            )
        end
    end

    return output
end

function HolyServerFinderArrayFromMap(map)

    local output =
        {}

    if type(map) ~= "table" then
        return output
    end

    for key, enabled in pairs(map) do

        if enabled == true then

            local text =
                HolyCleanText(
                    key
                )

            if text ~= "" then

                table.insert(
                    output,
                    text
                )
            end
        end
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyServerFinderReadPosition(value)

    if type(value) ~= "table" then
        return nil
    end

    local x =
        tonumber(
            value.X
            or value.x
            or value[1]
        )

    local y =
        tonumber(
            value.Y
            or value.y
            or value[2]
        )

    if not x
    or not y then
        return nil
    end

    return {
        X =
            math.clamp(
                math.floor(x + 0.5),
                -5000,
                5000
            ),

        Y =
            math.clamp(
                math.floor(y + 0.5),
                -5000,
                5000
            ),
    }
end

