function HolyServerFinderNormalizeAutoJoinMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("notify", 1, true) then
        return "Notify"
    end

    if text:find("join", 1, true)
    or text:find("best", 1, true) then
        return "Join Best"
    end

    return "Off"
end

function HolyServerFinderNextAutoJoinMode(value)

    value =
        HolyServerFinderNormalizeAutoJoinMode(
            value
        )

    if value == "Off" then
        return "Notify"
    end

    if value == "Notify" then
        return "Join Best"
    end

    return "Off"
end

function HolyServerFinderNormalizeAutoJoinMatchMode(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("all", 1, true)
    or text == "and" then

        return "All Selected"
    end

    return "Any Selected"
end

function HolyServerFinderNormalizeAutoJoinPetScope(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find("any", 1, true) then
        return "Any Pet"
    end

    return "Selected Pets"
end

function HolyServerFinderSplitCommaList(value)

    local output =
        {}

    if type(value) == "table" then

        for key, enabled in pairs(value) do

            local text =
                ""

            if type(key) == "number" then

                text =
                    HolyCleanText(
                        enabled
                    )

            elseif enabled == true then

                text =
                    HolyCleanText(
                        key
                    )
            end

            if text ~= "" then

                table.insert(
                    output,
                    text
                )
            end
        end

    else

        value =
            HolyCleanText(
                value
            )

        value =
            value:gsub("/", ",")
                :gsub("%+", ",")
                :gsub(";", ",")

        for part in value:gmatch("[^,]+") do

            local text =
                HolyCleanText(
                    part
                )

            if text ~= "" then

                table.insert(
                    output,
                    text
                )
            end
        end
    end

    return output
end

function HolyServerFinderAutoJoinListHasAny(list)

    if type(list) ~= "table"
    or #list <= 0 then

        return true
    end

    for _, value in ipairs(list) do

        local text =
            HolyCleanText(
                value
            )
            :lower()

        if text == ""
        or text == "any"
        or text == "any pet"
        or text == "all" then

            return true
        end
    end

    return false
end

function HolyServerFinderAutoJoinUniqueList(list, normalizer, fallback)

    local output =
        {}

    local seen =
        {}

    fallback =
        fallback
        or "Any"

    for _, value in ipairs(HolyServerFinderSplitCommaList(list)) do

        local text =
            HolyCleanText(
                value
            )

        local lower =
            text:lower()

        if lower == ""
        or lower == "any"
        or lower == "all"
        or lower == "any pet" then

            return {
                "Any",
            }
        end

        if type(normalizer) == "function" then

            text =
                normalizer(
                    text
                )
        end

        text =
            HolyCleanText(
                text
            )

        if text ~= "" then

            local key =
                text:lower()

            if seen[key] ~= true then

                seen[key] =
                    true

                table.insert(
                    output,
                    text
                )
            end
        end
    end

    if #output <= 0 then
        return {
            fallback,
        }
    end

    return output
end

function HolyServerFinderNormalizeAutoJoinPetName(value)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return ""
    end

    return HolySniperResolvePetDisplay(
        text
    )
end

function HolyServerFinderNormalizeAutoJoinSizeName(value)

    local text =
        HolySniperNormalizeSizeName(
            value
        )

    if text == "Normal"
    or text == "Big"
    or text == "Huge" then

        return text
    end

    return ""
end

function HolyServerFinderNormalizeAutoJoinVariantName(value)

    local text =
        HolyCleanText(
            value
        )

    local lower =
        text:lower()

    if lower == "regular"
    or lower == "normal" then

        return "Regular"
    end

    text =
        HolySniperNormalizeVariantName(
            text
        )

    if text == "Normal" then
        return "Regular"
    end

    if text == "Rainbow" then
        return "Rainbow"
    end

    return text
end

function HolyServerFinderNormalizeAutoJoinRarityName(value)

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return ""
    end

    return text
end

function HolyServerFinderNormalizeAutoJoinPriority(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    if text:find(
        "high",
        1,
        true
    ) then

        return "High"
    end

    if text:find(
        "low",
        1,
        true
    ) then

        return "Low"
    end

    return "Medium"
end

function HolyServerFinderAutoJoinPriorityRank(value)

    value =
        HolyServerFinderNormalizeAutoJoinPriority(
            value
        )

    if value == "High" then
        return 1
    end

    if value == "Low" then
        return 3
    end

    return 2
end

function HolyServerFinderNormalizeAutoJoinRule(rule)

    rule =
        type(rule) == "table"
        and rule
        or {}

    local petScope =
        HolyServerFinderNormalizeAutoJoinPetScope(
            rule.PetScope
            or rule.Scope
            or "Selected Pets"
        )

    local pets =
        HolyServerFinderAutoJoinUniqueList(
            rule.Pets
            or rule.Pet
            or rule.SelectedPets,
            HolyServerFinderNormalizeAutoJoinPetName,
            "Any"
        )

    if petScope == "Any Pet" then

        pets =
            {
                "Any",
            }
    end

    if petScope ~= "Any Pet"
    and HolyServerFinderAutoJoinListHasAny(pets) == true then

        pets =
            {
                "Bunny",
            }
    end

    local sizes =
        HolyServerFinderAutoJoinUniqueList(
            rule.Sizes
            or rule.Size,
            HolyServerFinderNormalizeAutoJoinSizeName,
            "Any"
        )

    local variants =
        HolyServerFinderAutoJoinUniqueList(
            rule.Variants
            or rule.Variant
            or rule.Mutations
            or rule.Mutation,
            HolyServerFinderNormalizeAutoJoinVariantName,
            "Any"
        )

    local rarities =
        HolyServerFinderAutoJoinUniqueList(
            rule.Rarities
            or rule.Rarity,
            HolyServerFinderNormalizeAutoJoinRarityName,
            "Any"
        )

    return {
        PetScope =
            petScope,

        Pets =
            pets,

        Sizes =
            sizes,

        Variants =
            variants,

        Rarities =
            rarities,

        MatchMode =
            "All Selected",

        Priority =
            HolyServerFinderNormalizeAutoJoinPriority(
                rule.Priority
                or "Medium"
            ),
    }
end

function HolyServerFinderNormalizeAutoJoinRules(rules)

    local output =
        {}

    local suppliedList =
        type(rules) == "table"

    if suppliedList then

        for _, target in ipairs(rules) do

            if type(target) == "table" then

                table.insert(
                    output,
                    HolyServerFinderNormalizeAutoJoinRule(
                        target
                    )
                )
            end
        end
    end

    if suppliedList ~= true then

        for _, target in ipairs(
            HolyServerFinderGetDefaultAutoJoinRules()
        ) do

            table.insert(
                output,
                HolyServerFinderNormalizeAutoJoinRule(
                    target
                )
            )
        end
    end

    return output
end

function HolyServerFinderNormalizeAutoJoinHold(hold)

    if type(hold) ~= "table"
    or hold.Active ~= true then

        return nil
    end

    local jobId =
        HolyCleanText(
            hold.JobId
            or hold.TargetJobId
            or hold.ServerId
        )

    if jobId == "" then
        return nil
    end

    local expiresAt =
        tonumber(
            hold.ExpiresAt
            or hold.expiresAt
        )
        or 0

    if expiresAt > 0
    and expiresAt <= os.time() - 8 then

        return nil
    end

    local size =
        HolyCleanText(
            hold.Size
            or "Any"
        )

    if size == ""
    or size:lower() == "any" then

        size =
            "Any"

    else

        size =
            HolySniperNormalizeSizeName(
                size
            )
    end

    local variant =
        HolyCleanText(
            hold.Variant
            or hold.Mutation
            or "Any"
        )

    if variant == ""
    or variant:lower() == "any" then

        variant =
            "Any"

    else

        variant =
            HolyServerFinderNormalizeAutoJoinVariantName(
                variant
            )
    end

    local rarity =
        HolyCleanText(
            hold.Rarity
            or "Any"
        )

    if rarity == "" then
        rarity =
            "Any"
    end

    return {
        Active =
            true,

        JobId =
            jobId,

        PlaceId =
            tonumber(
                hold.PlaceId
                or hold.placeId
                or game.PlaceId
            )
            or game.PlaceId,

        Pet =
            HolyCleanText(
                hold.Pet
                or hold.BasePet
                or hold.BestPet
            ),

        Size =
            size,

        Variant =
            variant,

        Rarity =
            rarity,

        DisplayName =
            HolyCleanText(
                hold.DisplayName
                or hold.Name
                or hold.Pet
            ),

        RuleIndex =
            tonumber(
                hold.RuleIndex
            )
            or 0,

        ExpiresAt =
            expiresAt,

        CreatedAt =
            tonumber(
                hold.CreatedAt
            )
            or os.time(),

        Source =
            HolyCleanText(
                hold.Source
                or "Auto Join"
            ),
    }
end

function HolyServerFinderEnsureAutoJoinState()

    HOLY_SERVER_FINDER_STATE =
        type(HOLY_SERVER_FINDER_STATE) == "table"
        and HOLY_SERVER_FINDER_STATE
        or {}

    HOLY_SERVER_FINDER_STATE.AutoJoinMode =
        HolyServerFinderNormalizeAutoJoinMode(
            HOLY_SERVER_FINDER_STATE.AutoJoinMode
            or "Off"
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinMinLife =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinMinLife
            )
            or 30,
            0,
            420
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinCooldown =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinCooldown
            )
            or 10,
            1,
            120
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace
            )
            or 22,
            5,
            90
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinRules =
        HolyServerFinderNormalizeAutoJoinRules(
            HOLY_SERVER_FINDER_STATE.AutoJoinRules
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex =
        math.clamp(
            math.floor(
                tonumber(
                    HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex
                )
                or 1
            ),
            1,
            math.max(
                1,
                #HOLY_SERVER_FINDER_STATE.AutoJoinRules
            )
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinHold =
        HolyServerFinderNormalizeAutoJoinHold(
            HOLY_SERVER_FINDER_STATE.AutoJoinHold
        )

    return HOLY_SERVER_FINDER_STATE
end

function HolyServerFinderSetAutoJoinMode(value)

    HolyServerFinderEnsureAutoJoinState()

    local wantedMode =
        HolyServerFinderNormalizeAutoJoinMode(
            value
        )

    if wantedMode ~= "Off"
    and HolyAuthRequireServerSniper(
        "Auto Join",
        true
    ) ~= true then

        HOLY_SERVER_FINDER_STATE.AutoJoinMode =
            "Off"

        if type(HOLY_SERVER_FINDER_HUD) == "table"
        and type(HOLY_SERVER_FINDER_HUD.SetAutoJoinMode) == "function" then

            pcall(function()

                HOLY_SERVER_FINDER_HUD:SetAutoJoinMode(
                    "Off"
                )
            end)
        end

        HolyQueueSaveServerFinderSettings()

        if type(HolyServerFinderRefreshAutoJoinRulesPopup) == "function" then

            HolyServerFinderRefreshAutoJoinRulesPopup()
        end

        return "Off"
    end

    HOLY_SERVER_FINDER_STATE.AutoJoinMode =
        wantedMode

    if type(HOLY_SERVER_FINDER_HUD) == "table"
    and type(HOLY_SERVER_FINDER_HUD.SetAutoJoinMode) == "function" then

        pcall(function()

            HOLY_SERVER_FINDER_HUD:SetAutoJoinMode(
                HOLY_SERVER_FINDER_STATE.AutoJoinMode
            )
        end)
    end

    HolyQueueSaveServerFinderSettings()

    HolyServerFinderRefreshAutoJoinRulesPopup()

    return HOLY_SERVER_FINDER_STATE.AutoJoinMode
end

