function HolyServerFinderRowJobId(row)

    if type(row) ~= "table" then
        return ""
    end

    return HolyCleanText(
        row.JobId
        or row.jobId
        or row.ServerId
        or row.id
        or row.Id
        or row.Key
    )
end

function HolyServerFinderRowTimeLeft(row)

    if type(row) ~= "table" then
        return 0
    end

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if expiresAt > 0 then

        return math.max(
            0,
            expiresAt - os.time()
        )
    end

    local timeLeft =
        tonumber(
            row.TimeLeft
            or row.timeLeft
        )
        or 0

    local reportedAt =
        tonumber(
            row.ReportedAt
            or row.reportedAt
        )
        or 0

    if reportedAt > 0 then

        timeLeft =
            timeLeft
            - math.max(
                0,
                os.time() - reportedAt
            )
    end

    return math.max(
        0,
        timeLeft
    )
end

function HolyServerFinderRowIsFull(row)

    if type(row) ~= "table" then
        return true
    end

    local playing =
        tonumber(
            row.Playing
            or row.playing
        )
        or 0

    local maxPlayers =
        tonumber(
            row.MaxPlayers
            or row.maxPlayers
        )
        or 8

    return maxPlayers > 0
        and playing >= maxPlayers
end

function HolyServerFinderRowIsCurrent(row)

    local jobId =
        HolyServerFinderRowJobId(
            row
        )

    return jobId ~= ""
        and jobId == tostring(game.JobId)
end

function HolyServerFinderRowReportAge(row)

    if type(row) ~= "table" then
        return 999999
    end

    local reportedAt =
        tonumber(
            row.ReportedAt
            or row.reportedAt
        )
        or 0

    if reportedAt <= 0 then
        return 0
    end

    return math.max(
        0,
        os.time() - reportedAt
    )
end

function HolyServerFinderRowIsHiddenByAge(row)

    if type(row) ~= "table" then
        return true
    end

    if row.HideFromFinder == true
    or row.Expired == true then

        return true
    end

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if expiresAt > 0
    and expiresAt <= os.time() then

        return true
    end

    local reportedAt =
        tonumber(
            row.ReportedAt
            or row.reportedAt
        )
        or 0

    if reportedAt <= 0 then
        return false
    end

    local maxAge =
        tonumber(
            row.MaxReportAge
            or row.maxReportAge
        )
        or tonumber(SERVER_FINDER_ROW_HIDE_AFTER_SECONDS)
        or 45

    return HolyServerFinderRowReportAge(row) > maxAge
end

function HolyServerFinderRowIsStale(row)

    local maxAge =
        tonumber(
            row
            and (
                row.ManualJoinMaxAge
                or row.manualJoinMaxAge
            )
        )
        or tonumber(SERVER_FINDER_MANUAL_JOIN_FRESH_SECONDS)
        or 20

    return HolyServerFinderRowReportAge(row) > maxAge
end

function HolyServerFinderRowIsTooLate(row, minLife)

    if type(row) ~= "table" then
        return true
    end

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    local rawTimeLeft =
        tonumber(
            row.TimeLeft
            or row.timeLeft
        )

    if expiresAt <= 0
    and rawTimeLeft == nil then

        return false
    end

    local timeLeft =
        HolyServerFinderRowTimeLeft(
            row
        )

    if timeLeft <= 0 then
        return true
    end

    minLife =
        tonumber(minLife)
        or tonumber(SERVER_FINDER_TOO_LATE_SECONDS)
        or 15

    return timeLeft < minLife
end

function HolyServerFinderRowManualJoinAllowed(row)

    if type(row) ~= "table" then
        return false
    end

    if HolyServerFinderRowIsCurrent(row) == true then
        return false
    end

    if HolyServerFinderRowIsFull(row) == true then
        return false
    end

    if HolyServerFinderRowIsHiddenByAge(row) == true then
        return false
    end

    return true
end

function HolyServerFinderRowAutoJoinFresh(row, minLife)

    return HolyServerFinderRowManualJoinAllowed(
        row
    ) == true
end

function HolyServerFinderAnnotateJoinState(row)

    if type(row) ~= "table" then
        return nil
    end

    row.MaxReportAge =
        tonumber(SERVER_FINDER_ROW_HIDE_AFTER_SECONDS)
        or 45

    row.ManualJoinMaxAge =
        tonumber(SERVER_FINDER_MANUAL_JOIN_FRESH_SECONDS)
        or 20

    row.AutoJoinMaxAge =
        tonumber(SERVER_FINDER_AUTO_JOIN_FRESH_SECONDS)
        or 12

    row.ManualMinLife =
        tonumber(SERVER_FINDER_TOO_LATE_SECONDS)
        or 15

    row.ReportAge =
        HolyServerFinderRowReportAge(
            row
        )

    row.JoinEnabled =
        true

    row.JoinDisabled =
        false

    row.JoinText =
        "Join"

    row.JoinState =
        "fresh"

    row.Freshness =
        "Fresh"

    if HolyServerFinderRowIsHiddenByAge(row) == true then

        row.Expired =
            true

        row.HideFromFinder =
            true

        row.JoinEnabled =
            false

        row.JoinDisabled =
            true

        row.JoinText =
            "Gone"

        row.JoinState =
            "gone"

        row.Freshness =
            "Gone"

        return row
    end

    if HolyServerFinderRowIsCurrent(row) == true then

        row.JoinEnabled =
            false

        row.JoinDisabled =
            true

        row.JoinText =
            "Current"

        row.JoinState =
            "current"

        row.Freshness =
            "Current"

        return row
    end

    if HolyServerFinderRowIsFull(row) == true then

        row.JoinEnabled =
            false

        row.JoinDisabled =
            true

        row.JoinText =
            "Full"

        row.JoinState =
            "full"

        row.Freshness =
            "Full"

        return row
    end

    if HolyServerFinderRowIsTooLate(
        row,
        SERVER_FINDER_TOO_LATE_SECONDS
    ) == true then

        row.JoinEnabled =
            true

        row.JoinDisabled =
            false

        row.JoinText =
            "Join"

        row.JoinState =
            "late"

        row.Freshness =
            "Late"

        return row
    end

    if HolyServerFinderRowIsStale(row) == true then

        row.JoinEnabled =
            true

        row.JoinDisabled =
            false

        row.JoinText =
            "Join"

        row.JoinState =
            "stale"

        row.Freshness =
            "Stale"

        return row
    end

    if HolyServerFinderRowReportAge(row)
    > (
        tonumber(SERVER_FINDER_AUTO_JOIN_FRESH_SECONDS)
        or 12
    ) then

        row.JoinState =
            "aging"

        row.Freshness =
            "Aging"

    else

        row.JoinState =
            "fresh"

        row.Freshness =
            "Fresh"
    end

    return row
end

function HolyServerFinderAnnotateDisplayRows(rows)

    local output =
        {}

    rows =
        type(rows) == "table"
        and rows
        or {}

    for _, row in ipairs(rows) do

        row =
            HolyServerFinderAnnotateJoinState(
                row
            )

        if type(row) == "table"
        and row.HideFromFinder ~= true then

            table.insert(
                output,
                row
            )
        end
    end

    return output
end

function HolyServerFinderSelectionMatchesText(selection, text)

    if HolyServerFinderAutoJoinListHasAny(selection) == true then
        return true
    end

    local haystack =
        HolySniperPetAliasKey(
            text
        )

    for _, value in ipairs(selection or {}) do

        local needle =
            HolySniperPetAliasKey(
                value
            )

        if needle ~= ""
        and haystack == needle then

            return true
        end
    end

    return false
end

function HolyServerFinderAutoJoinRowSize(row)

    return HolySniperNormalizeSizeName(
        row.Size
        or row.size
        or "Normal"
    )
end

function HolyServerFinderAutoJoinRowVariant(row)

    local variant =
        HolySniperNormalizeVariantName(
            row.Variant
            or row.variant
            or row.Mutation
            or row.mutation
            or "Normal"
        )

    if variant == "Normal" then
        return "Regular"
    end

    return variant
end

function HolyServerFinderSelectionContainsValue(selection, value, normalizer)

    if HolyServerFinderAutoJoinListHasAny(selection) == true then
        return true
    end

    if type(normalizer) == "function" then

        value =
            normalizer(
                value
            )
    end

    value =
        HolyCleanText(
            value
        )
        :lower()

    for _, wanted in ipairs(selection or {}) do

        wanted =
            type(normalizer) == "function"
            and normalizer(wanted)
            or wanted

        wanted =
            HolyCleanText(
                wanted
            )
            :lower()

        if wanted == value then
            return true
        end
    end

    return false
end

function HolyServerFinderRaritySelectionMatches(selection, value)

    if HolyServerFinderAutoJoinListHasAny(selection) == true then
        return true
    end

    local rarity =
        HolyCleanText(
            value
        )
        :lower()

    for _, wanted in ipairs(selection or {}) do

        if rarity == HolyCleanText(wanted):lower() then
            return true
        end
    end

    return false
end

function HolyServerFinderAutoJoinRuleMatchesRow(rule, row)

    if type(rule) ~= "table"
    or type(row) ~= "table" then

        return false
    end

    rule =
        HolyServerFinderNormalizeAutoJoinRule(
            rule
        )

    if rule.PetScope ~= "Any Pet" then

        local basePet =
            HolyCleanText(
                row.BasePet
                or row.BestPet
                or row.PetName
                or row.Pet
                or row.DisplayName
                or row.Name
            )

        if HolyServerFinderSelectionMatchesText(
            rule.Pets,
            basePet
        ) ~= true then

            return false
        end
    end

    if HolyServerFinderRaritySelectionMatches(
        rule.Rarities,
        row.Rarity
        or row.rarity
    ) ~= true then

        return false
    end

    local sizeAny =
        HolyServerFinderAutoJoinListHasAny(
            rule.Sizes
        )

    local variantAny =
        HolyServerFinderAutoJoinListHasAny(
            rule.Variants
        )

    if sizeAny == true
    and variantAny == true then

        return true
    end

    local sizeMatch =
        HolyServerFinderSelectionContainsValue(
            rule.Sizes,
            HolyServerFinderAutoJoinRowSize(row),
            HolyServerFinderNormalizeAutoJoinSizeName
        )

    local variantMatch =
        HolyServerFinderSelectionContainsValue(
            rule.Variants,
            HolyServerFinderAutoJoinRowVariant(row),
            HolyServerFinderNormalizeAutoJoinVariantName
        )

    local matchMode =
        HolyServerFinderNormalizeAutoJoinMatchMode(
            rule.MatchMode
        )

    if matchMode == "All Selected" then

        if sizeAny ~= true
        and sizeMatch ~= true then
            return false
        end

        if variantAny ~= true
        and variantMatch ~= true then
            return false
        end

        return true
    end

    if sizeAny ~= true
    and sizeMatch == true then
        return true
    end

    if variantAny ~= true
    and variantMatch == true then
        return true
    end

    return false
end

function HolyServerFinderAutoJoinScoreRow(row)

    if type(row) ~= "table" then
        return 0
    end

    local score =
        0

    score =
        score
        + (
            tonumber(row.RarityRank)
            or HolyServerFinderRarityRank(
                row.Rarity
            )
        ) * 100000

    local freshness =
        HolyCleanText(
            row.Freshness
            or row.JoinState
            or ""
        )
        :lower()

    if HolyServerFinderRowIsTooLate(
        row,
        SERVER_FINDER_TOO_LATE_SECONDS
    ) == true then

        freshness =
            "late"

    elseif HolyServerFinderRowIsStale(row) == true then

        freshness =
            "stale"

    elseif HolyServerFinderRowReportAge(row)
    > (
        tonumber(SERVER_FINDER_AUTO_JOIN_FRESH_SECONDS)
        or 12
    ) then

        freshness =
            "aging"

    elseif freshness == "" then

        freshness =
            "fresh"
    end

    if freshness == "fresh" then

        score =
            score + 4500

    elseif freshness == "aging" then

        score =
            score + 3000

    elseif freshness == "stale" then

        score =
            score + 1500
    end

    local variant =
        HolyServerFinderAutoJoinRowVariant(
            row
        )

    local size =
        HolyServerFinderAutoJoinRowSize(
            row
        )

    if variant == "Rainbow" then
        score =
            score + 10000
    end

    if size == "Huge" then
        score =
            score + 5000

    elseif size == "Big" then

        score =
            score + 2500
    end

    score =
        score
        + math.min(
            999,
            math.floor(
                HolyServerFinderRowTimeLeft(row)
            )
        )

    local playing =
        tonumber(row.Playing)
        or 0

    local maxPlayers =
        tonumber(row.MaxPlayers)
        or 8

    score =
        score
        + math.max(
            0,
            maxPlayers - playing
        ) * 10

    return score
end

function HolyServerFinderFindAutoJoinTarget(rows)

    HolyServerFinderEnsureAutoJoinState()

    rows =
        type(rows) == "table"
        and rows
        or {}

    local minLife =
        tonumber(
            HOLY_SERVER_FINDER_STATE.AutoJoinMinLife
        )
        or 30

    local orderedFilters =
        {}

    for sourceIndex, filter in ipairs(
        HOLY_SERVER_FINDER_STATE.AutoJoinRules
        or {}
    ) do

        table.insert(
            orderedFilters,
            {
                SourceIndex =
                    sourceIndex,

                Filter =
                    HolyServerFinderNormalizeAutoJoinRule(
                        filter
                    ),
            }
        )
    end

    table.sort(orderedFilters, function(a, b)

        local rankA =
            HolyServerFinderAutoJoinPriorityRank(
                a.Filter.Priority
            )

        local rankB =
            HolyServerFinderAutoJoinPriorityRank(
                b.Filter.Priority
            )

        if rankA ~= rankB then
            return rankA < rankB
        end

        return a.SourceIndex
            < b.SourceIndex
    end)

    for _, entry in ipairs(orderedFilters) do

        local candidates =
            {}

        for _, row in ipairs(rows) do

            if type(row) == "table"
            and HolyServerFinderRowAutoJoinFresh(
                row,
                minLife
            ) == true
            and HolyServerFinderAutoJoinRuleMatchesRow(
                entry.Filter,
                row
            ) == true then

                table.insert(
                    candidates,
                    {
                        RuleIndex =
                            entry.SourceIndex,

                        Rule =
                            entry.Filter,

                        Row =
                            row,

                        Score =
                            HolyServerFinderAutoJoinScoreRow(
                                row
                            ),
                    }
                )
            end
        end

        if #candidates > 0 then

            table.sort(candidates, function(a, b)

                if a.Score ~= b.Score then
                    return a.Score > b.Score
                end

                return tostring(
                    a.Row.DisplayName
                    or ""
                ) < tostring(
                    b.Row.DisplayName
                    or ""
                )
            end)

            return candidates[1]
        end
    end

    return nil
end

function HolyServerFinderRowAlive(row)

    if type(row) ~= "table" then
        return false
    end

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if expiresAt <= 0 then
        return true
    end

    return expiresAt > os.time() - 2
        and HolyServerFinderRowTimeLeft(row) > 0
end

function HolyServerFinderRowBasePet(row)

    if type(row) ~= "table" then
        return ""
    end

    return HolyCleanText(
        row.BasePet
        or row.BestPet
        or row.Pet
        or row.PetName
        or row.DisplayName
        or row.Name
    )
end

function HolyServerFinderAutoJoinValueIsAny(value)

    local text =
        HolyCleanText(
            value
        )
        :lower()

    return text == ""
        or text == "any"
        or text == "any pet"
        or text == "all"
end

function HolyServerFinderHoldMatchesRow(hold, row)

    hold =
        HolyServerFinderNormalizeAutoJoinHold(
            hold
        )

    if type(hold) ~= "table"
    or type(row) ~= "table" then
        return false
    end

    if HolyServerFinderRowAlive(row) ~= true then
        return false
    end

    if HolyServerFinderAutoJoinValueIsAny(hold.Pet) ~= true then

        local holdPet =
            HolySniperPetAliasKey(
                hold.Pet
            )

        local rowPet =
            HolySniperPetAliasKey(
                HolyServerFinderRowBasePet(
                    row
                )
            )

        if holdPet == ""
        or rowPet ~= holdPet then
            return false
        end
    end

    if HolyServerFinderAutoJoinValueIsAny(hold.Size) ~= true then

        if HolySniperNormalizeSizeName(
            row.Size
            or row.size
            or "Normal"
        ) ~= HolySniperNormalizeSizeName(
            hold.Size
        ) then

            return false
        end
    end

    if HolyServerFinderAutoJoinValueIsAny(hold.Variant) ~= true then

        if HolyServerFinderAutoJoinRowVariant(
            row
        ) ~= HolyServerFinderNormalizeAutoJoinVariantName(
            hold.Variant
        ) then

            return false
        end
    end

    if HolyServerFinderAutoJoinValueIsAny(hold.Rarity) ~= true then

        if HolyCleanText(
            row.Rarity
            or row.rarity
        ):lower() ~= HolyCleanText(
            hold.Rarity
        ):lower() then

            return false
        end
    end

    return true
end

function HolyServerFinderFindHoldTargetInCurrentRows(rows, hold)

    rows =
        type(rows) == "table"
        and rows
        or {}

    for _, row in ipairs(rows) do

        if type(row) == "table"
        and HolyServerFinderRowIsCurrent(row) == true
        and HolyServerFinderHoldMatchesRow(
            hold,
            row
        ) == true then

            return row
        end
    end

    return nil
end

function HolyServerFinderFindCurrentAutoJoinTarget(rows)

    HolyServerFinderEnsureAutoJoinState()

    rows =
        type(rows) == "table"
        and rows
        or {}

    for ruleIndex, rule in ipairs(HOLY_SERVER_FINDER_STATE.AutoJoinRules or {}) do

        for _, row in ipairs(rows) do

            if type(row) == "table"
            and HolyServerFinderRowIsCurrent(row) == true
            and HolyServerFinderRowAlive(row) == true
            and HolyServerFinderAutoJoinRuleMatchesRow(
                rule,
                row
            ) == true then

                return {
                    RuleIndex =
                        ruleIndex,

                    Rule =
                        rule,

                    Row =
                        row,
                }
            end
        end
    end

    return nil
end

function HolyServerFinderClearAutoJoinHold(reason)

    HOLY_SERVER_FINDER_STATE =
        type(HOLY_SERVER_FINDER_STATE) == "table"
        and HOLY_SERVER_FINDER_STATE
        or {}

    HOLY_SERVER_FINDER_STATE.AutoJoinHold =
        nil

    if type(HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME) == "table" then

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedJobId =
            ""

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedAt =
            0

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
            tostring(reason or "")
    end

    HolyQueueSaveServerFinderSettings()

    return true
end

function HolyServerFinderArmAutoJoinHold(row, source, targetInfo)

    if type(row) ~= "table" then
        return false
    end

    local jobId =
        HolyServerFinderRowJobId(
            row
        )

    if jobId == "" then
        return false
    end

    local displayName =
        HolyCleanText(
            row.DisplayName
            or row.Pet
            or row.PetName
            or "target pet"
        )

    local hold = {
        Active =
            true,

        JobId =
            jobId,

        PlaceId =
            tonumber(
                row.PlaceId
                or row.placeId
                or game.PlaceId
            )
            or game.PlaceId,

        Pet =
            HolyServerFinderRowBasePet(
                row
            ),

        Size =
            HolyServerFinderAutoJoinRowSize(
                row
            ),

        Variant =
            HolyServerFinderAutoJoinRowVariant(
                row
            ),

        Rarity =
            HolyCleanText(
                row.Rarity
                or row.rarity
                or "Any"
            ),

        DisplayName =
            displayName,

        RuleIndex =
            type(targetInfo) == "table"
            and tonumber(targetInfo.RuleIndex)
            or 0,

        ExpiresAt =
            tonumber(
                row.ExpiresAt
                or row.expiresAt
            )
            or 0,

        CreatedAt =
            os.time(),

        Source =
            tostring(
                source
                or "Auto Join"
            ),
    }

    HOLY_SERVER_FINDER_STATE.AutoJoinHold =
        HolyServerFinderNormalizeAutoJoinHold(
            hold
        )

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedJobId =
        ""

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedAt =
        0

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
        "Armed "
        .. displayName

    HolySaveServerFinderSettings()

    return true
end

function HolyServerFinderAutoJoinHoldBlocks(rows)

    HolyServerFinderEnsureAutoJoinState()

    rows =
        type(rows) == "table"
        and rows
        or {}

    local hold =
        HOLY_SERVER_FINDER_STATE.AutoJoinHold

    if type(hold) == "table"
    and hold.Active == true then

        if hold.JobId == tostring(game.JobId) then

            if HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedJobId ~= tostring(game.JobId) then

                HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedJobId =
                    tostring(game.JobId)

                HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedAt =
                    os.clock()
            end

            local targetRow =
                HolyServerFinderFindHoldTargetInCurrentRows(
                    rows,
                    hold
                )

            if targetRow then

                HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
                    "Holding "
                    .. tostring(
                        targetRow.DisplayName
                        or hold.DisplayName
                        or "target"
                    )

                return true,
                    "hold target present"
            end

            local arrivedAt =
                tonumber(
                    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.HoldArrivedAt
                )
                or os.clock()

            local grace =
                tonumber(
                    HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace
                )
                or 22

            if os.clock() - arrivedAt < grace then

                HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
                    "Waiting for target data"

                return true,
                    "waiting for target data"
            end

            HolyServerFinderClearAutoJoinHold(
                "hold target gone"
            )

        elseif os.time() - (
            tonumber(hold.CreatedAt)
            or os.time()
        ) > 120 then

            HolyServerFinderClearAutoJoinHold(
                "stale hold"
            )
        end
    end

    local currentTarget =
        HolyServerFinderFindCurrentAutoJoinTarget(
            rows
        )

    if type(currentTarget) == "table"
    and type(currentTarget.Row) == "table" then

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastHoldStatus =
            "Current match "
            .. tostring(
                currentTarget.Row.DisplayName
                or currentTarget.Row.Pet
                or "pet"
            )

        return true,
            "current server has matching pet"
    end

    return false,
        "clear"
end

function HolyServerFinderJoinRow(row, source, targetInfo)

    if HolyAuthRequireServerSniper(
        tostring(source or "Server Finder Join"),
        true
    ) ~= true then

        return false
    end

    if type(row) ~= "table" then
        return false
    end

    local jobId =
        HolyServerFinderRowJobId(
            row
        )

    local placeId =
        tonumber(
            row.PlaceId
            or row.placeId
            or game.PlaceId
        )
        or game.PlaceId

    if jobId == "" then
        return false
    end

    if jobId == tostring(game.JobId) then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Server Finder",
                "Already in this server.",
                3
            )
        end

        return false
    end

    if HolySniperServerSwitchBlocked(
        "Server Finder",
        true
    ) == true then

        return false
    end

    if HolyServerFinderRowManualJoinAllowed(row) ~= true then

        local reason =
            tostring(
                row.JoinText
                or row.Freshness
                or "not fresh"
            )

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Server Finder",
                "Join blocked: "
                .. reason
                .. ". Refresh or wait for a fresh report.",
                4
            )
        end

        return false
    end

    HolyServerFinderArmAutoJoinHold(
        row,
        source,
        targetInfo
    )

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.Teleporting =
        true

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastTargetKey =
        HolyServerFinderRowKey(
            row
        )

    if type(HolyNotify) == "function" then

        HolyNotify(
            "HOLY Server Finder",
            tostring(source or "Joining")
            .. ": "
            .. tostring(row.DisplayName or row.Pet or "server"),
            3
        )
    end

    local startedJobId =
        tostring(game.JobId)

    local ok,
        err =
        pcall(function()

            TeleportService:TeleportToPlaceInstance(
                placeId,
                jobId,
                LocalPlayer
            )
        end)

    if ok ~= true then

        HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.Teleporting =
            false

        HolyServerFinderClearAutoJoinHold(
            "teleport failed"
        )

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Server Finder",
                "Teleport failed: "
                .. tostring(err),
                4
            )
        end

        return false
    end

    task.delay(12, function()

        if tostring(game.JobId) == startedJobId
        and type(HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME) == "table" then

            HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.Teleporting =
                false
        end
    end)

    return true
end

function HolyServerFinderEvaluateAutoJoin(hud)

    HolyServerFinderEnsureAutoJoinState()

    local mode =
        HolyServerFinderNormalizeAutoJoinMode(
            HOLY_SERVER_FINDER_STATE.AutoJoinMode
        )

    if mode == "Off" then
        return false
    end

    if HolyAuthRequireServerSniper(
        "Auto Join",
        false
    ) ~= true then

        HOLY_SERVER_FINDER_STATE.AutoJoinMode =
            "Off"

        if type(hud) == "table"
        and type(hud.SetAutoJoinMode) == "function" then

            pcall(function()

                hud:SetAutoJoinMode(
                    "Off"
                )
            end)
        end

        HolyQueueSaveServerFinderSettings()

        return false
    end

    if HolySniperServerSwitchBlocked(
        "Auto Join",
        false
    ) == true then

        return false
    end

    if HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.Teleporting == true then
        return false
    end

    local rows =
        type(hud) == "table"
        and type(hud.Rows) == "table"
        and hud.Rows
        or {}

    local holdBlocked =
        HolyServerFinderAutoJoinHoldBlocks(
            rows
        )

    if holdBlocked == true then
        return false
    end

    local now =
        os.clock()

    local cooldown =
        tonumber(
            HOLY_SERVER_FINDER_STATE.AutoJoinCooldown
        )
        or 10

    if now - (
        tonumber(
            HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastAttemptAt
        )
        or 0
    ) < cooldown then

        return false
    end

    local target =
        HolyServerFinderFindAutoJoinTarget(
            rows
        )

    if type(target) ~= "table"
    or type(target.Row) ~= "table" then

        return false
    end

    local row =
        target.Row

    HOLY_SERVER_FINDER_AUTO_JOIN_RUNTIME.LastAttemptAt =
        now

    if mode == "Notify" then

        if type(HolyNotify) == "function" then

            HolyNotify(
                "HOLY Auto Join",
                "Matched target #"
                .. tostring(target.RuleIndex)
                .. ": "
                .. tostring(row.DisplayName or row.Pet or "server"),
                5
            )
        end

        return true
    end

    return HolyServerFinderJoinRow(
        row,
        "Auto Join",
        target
    )
end

function HolyServerFinderAutoJoinJoinList(list, fallback)

    if HolyServerFinderAutoJoinListHasAny(list) == true then
        return fallback or "Any"
    end

    return table.concat(
        list,
        "/"
    )
end

function HolyServerFinderAutoJoinRulePetText(rule)

    rule =
        HolyServerFinderNormalizeAutoJoinRule(
            rule
        )

    if rule.PetScope == "Any Pet" then
        return "Any Pet"
    end

    return HolyServerFinderAutoJoinJoinList(
        rule.Pets,
        "Any Pet"
    )
end

function HolyServerFinderAutoJoinRuleDetailText(rule)

    rule =
        HolyServerFinderNormalizeAutoJoinRule(
            rule
        )

    local parts =
        {}

    if HolyServerFinderAutoJoinListHasAny(rule.Sizes) ~= true then

        table.insert(
            parts,
            HolyServerFinderAutoJoinJoinList(
                rule.Sizes,
                ""
            )
        )
    end

    if HolyServerFinderAutoJoinListHasAny(rule.Variants) ~= true then

        table.insert(
            parts,
            HolyServerFinderAutoJoinJoinList(
                rule.Variants,
                ""
            )
        )
    end

    if HolyServerFinderAutoJoinListHasAny(rule.Rarities) ~= true then

        table.insert(
            parts,
            HolyServerFinderAutoJoinJoinList(
                rule.Rarities,
                ""
            )
        )
    end

    if #parts <= 0 then
        return "Any"
    end

    local text =
        table.concat(
            parts,
            "/"
        )

    if rule.MatchMode == "All Selected"
    and #parts > 1 then

        text =
            text
            .. " · All"
    end

    return text
end

HOLY_SERVER_FINDER_MAIN_UI = {
    Lock = false,

    SelectedIndex =
        tonumber(
            HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex
        ),

    EditingIndex =
        nil,

    SearchText =
        "",

    WatchlistPage =
        1,

    WatchlistPageSize =
        7,

    BuilderPet =
        "Any Pet",

    BuilderSizes = {
        "Any",
    },

    BuilderVariants = {
        "Any",
    },

    BuilderRarities = {
        "Any",
    },

    BuilderPriority =
        "Medium",
}

function HolyServerFinderReadSingleValue(value)

    if type(value) ~= "table" then

        return HolyCleanText(
            value
        )
    end

    for key, enabled in pairs(value) do

        if enabled == true then

            return HolyCleanText(
                key
            )
        end
    end

    return HolyCleanText(
        value[1]
    )
end

function HolyServerFinderTargetSelectionList(value, anyLabel)

    local values =
        {}

    if type(value) == "table" then

        values =
            HolyServerFinderSelectionValues(
                value
            )

    else

        local text =
            HolyCleanText(
                value
            )

        if text ~= "" then

            values[1] =
                text
        end
    end

    anyLabel =
        HolyCleanText(
            anyLabel
        )

    for _, item in ipairs(values) do

        local lower =
            HolyCleanText(
                item
            )
            :lower()

        if lower == "any"
        or lower == "all"
        or lower == anyLabel:lower() then

            return {
                "Any",
            }
        end
    end

    local output =
        {}

    local seen =
        {}

    for _, item in ipairs(values) do

        local text =
            HolyCleanText(
                item
            )

        local key =
            text:lower()

        if text ~= ""
        and seen[key] ~= true then

            seen[key] =
                true

            table.insert(
                output,
                text
            )
        end
    end

    if #output == 0 then

        return {
            "Any",
        }
    end

    table.sort(output, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return output
end

function HolyServerFinderBuildPetOptions()

    local values = {
        "Any Pet",
    }

    local seen = {
        ["any pet"] = true,
    }

    local options =
        HolyServerFinderBuildFilterOptions()

    for _, petName in ipairs(
        options.Pets
        or {}
    ) do

        local text =
            HolyCleanText(
                petName
            )

        local key =
            text:lower()

        if text ~= ""
        and seen[key] ~= true then

            seen[key] =
                true

            table.insert(
                values,
                text
            )
        end
    end

    return values
end

function HolyServerFinderShortFilterList(values, fallback)

    if HolyServerFinderAutoJoinListHasAny(
        values
    ) == true then

        return fallback
            or "Any"
    end

    local shortNames = {
        Normal = "Norm",
        Regular = "Reg",
        Rainbow = "Rb",
        Common = "Com",
        Uncommon = "Unc",
        Legendary = "Leg",
        Mythic = "Myth",
    }

    local output =
        {}

    for _, value in ipairs(values or {}) do

        local text =
            HolyCleanText(
                value
            )

        table.insert(
            output,
            shortNames[text]
            or text
        )
    end

    return #output > 0
        and table.concat(
            output,
            "+"
        )
        or (
            fallback
            or "Any"
        )
end

function HolyServerFinderFilterKey(filter)

    filter =
        HolyServerFinderNormalizeAutoJoinRule(
            filter
        )

    local function sortedText(values)

        local copy =
            table.clone(
                values
                or {}
            )

        table.sort(copy, function(a, b)

            return tostring(a):lower()
                < tostring(b):lower()
        end)

        return table.concat(
            copy,
            "+"
        )
        :lower()
    end

    return table.concat({
        tostring(
            filter.PetScope
        ):lower(),

        sortedText(
            filter.Pets
        ),

        sortedText(
            filter.Sizes
        ),

        sortedText(
            filter.Variants
        ),

        sortedText(
            filter.Rarities
        ),
    }, "|")
end

function HolyServerFinderBuildAllWatchlistRows()

    HolyServerFinderEnsureAutoJoinState()

    local rows =
        {}

    local searchText =
        HolyCleanText(
            HOLY_SERVER_FINDER_MAIN_UI.SearchText
            or ""
        )
        :lower()

    for sourceIndex, sourceFilter in ipairs(
        HOLY_SERVER_FINDER_STATE.AutoJoinRules
        or {}
    ) do

        local filter =
            HolyServerFinderNormalizeAutoJoinRule(
                sourceFilter
            )

        local petText =
            filter.PetScope == "Any Pet"
            and "Any Pet"
            or table.concat(
                filter.Pets,
                "+"
            )

        local row = {
            SourceIndex =
                sourceIndex,

            Pet =
                petText,

            Size =
                HolyServerFinderShortFilterList(
                    filter.Sizes,
                    "Any"
                ),

            Variant =
                HolyServerFinderShortFilterList(
                    filter.Variants,
                    "Any"
                ),

            Rarity =
                HolyServerFinderShortFilterList(
                    filter.Rarities,
                    "Any"
                ),

            Priority =
                HolyServerFinderNormalizeAutoJoinPriority(
                    filter.Priority
                ),

            Filter =
                filter,
        }

        local haystack =
            table.concat({
                row.Pet,
                row.Size,
                row.Variant,
                row.Rarity,
                row.Priority,
            }, " ")
            :lower()

        if searchText == ""
        or haystack:find(
            searchText,
            1,
            true
        ) then

            table.insert(
                rows,
                row
            )
        end
    end

    table.sort(rows, function(a, b)

        local rankA =
            HolyServerFinderAutoJoinPriorityRank(
                a.Priority
            )

        local rankB =
            HolyServerFinderAutoJoinPriorityRank(
                b.Priority
            )

        if rankA ~= rankB then
            return rankA < rankB
        end

        return a.SourceIndex
            < b.SourceIndex
    end)

    return rows
end

function HolyServerFinderBuildWatchlistPage()

    local allRows =
        HolyServerFinderBuildAllWatchlistRows()

    local pageSize =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_MAIN_UI.WatchlistPageSize
            )
            or 7,
            1,
            16
        )

    local pageCount =
        math.max(
            1,
            math.ceil(
                #allRows
                / pageSize
            )
        )

    HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage =
        math.clamp(
            tonumber(
                HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage
            )
            or 1,
            1,
            pageCount
        )

    local firstIndex =
        (
            (
                HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage
                - 1
            )
            * pageSize
        )
        + 1

    local lastIndex =
        math.min(
            #allRows,
            firstIndex
            + pageSize
            - 1
        )

    local pageRows =
        {}

    for index = firstIndex, lastIndex do

        if type(allRows[index]) == "table" then

            table.insert(
                pageRows,
                allRows[index]
            )
        end
    end

    return pageRows,
        HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage,
        pageCount
end

function HolyServerFinderSetWatchlistPage(page)

    HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage =
        tonumber(page)
        or 1

    HOLY_SERVER_FINDER_MAIN_UI.SelectedIndex =
        nil

    if type(HolyServerFinderRefreshMainUI) == "function" then

        HolyServerFinderRefreshMainUI()
    end
end

function HolyServerFinderResetFilterBuilder(refresh)

    HOLY_SERVER_FINDER_MAIN_UI.EditingIndex =
        nil

    HOLY_SERVER_FINDER_MAIN_UI.BuilderPet =
        "Any Pet"

    HOLY_SERVER_FINDER_MAIN_UI.BuilderSizes = {
        "Any",
    }

    HOLY_SERVER_FINDER_MAIN_UI.BuilderVariants = {
        "Any",
    }

    HOLY_SERVER_FINDER_MAIN_UI.BuilderRarities = {
        "Any",
    }

    HOLY_SERVER_FINDER_MAIN_UI.BuilderPriority =
        "Medium"

    if refresh ~= false
    and type(HolyServerFinderRefreshMainUI) == "function" then

        HolyServerFinderRefreshMainUI()
    end
end

function HolyServerFinderLoadSelectedFilter()

    local index =
        tonumber(
            HOLY_SERVER_FINDER_MAIN_UI.SelectedIndex
        )

    local source =
        index
        and HOLY_SERVER_FINDER_STATE.AutoJoinRules[index]
        or nil

    if type(source) ~= "table" then

        HolyNotify(
            "Auto Join Watchlist",
            "Select a filter first.",
            3
        )

        return false
    end

    local filter =
        HolyServerFinderNormalizeAutoJoinRule(
            source
        )

    HOLY_SERVER_FINDER_MAIN_UI.EditingIndex =
        index

    HOLY_SERVER_FINDER_MAIN_UI.BuilderPet =
        filter.PetScope == "Any Pet"
        and "Any Pet"
        or tostring(
            filter.Pets[1]
            or "Any Pet"
        )

    HOLY_SERVER_FINDER_MAIN_UI.BuilderSizes =
        table.clone(
            filter.Sizes
        )

    HOLY_SERVER_FINDER_MAIN_UI.BuilderVariants =
        table.clone(
            filter.Variants
        )

    HOLY_SERVER_FINDER_MAIN_UI.BuilderRarities =
        table.clone(
            filter.Rarities
        )

    HOLY_SERVER_FINDER_MAIN_UI.BuilderPriority =
        HolyServerFinderNormalizeAutoJoinPriority(
            filter.Priority
        )

    HolyServerFinderRefreshMainUI()

    return true
end

function HolyServerFinderSaveFilterBuilder()

    if HolyAuthRequireServerSniper(
        "Auto Join Filters",
        true
    ) ~= true then

        return false
    end

    local petName =
        HolyCleanText(
            HOLY_SERVER_FINDER_MAIN_UI.BuilderPet
            or "Any Pet"
        )

    local anyPet =
        petName == ""
        or petName:lower() == "any pet"
        or petName:lower() == "any"

    local filter =
        HolyServerFinderNormalizeAutoJoinRule({
            PetScope =
                anyPet
                and "Any Pet"
                or "Selected Pets",

            Pets =
                anyPet
                and {
                    "Any",
                }
                or {
                    petName,
                },

            Sizes =
                HolyServerFinderTargetSelectionList(
                    HOLY_SERVER_FINDER_MAIN_UI.BuilderSizes,
                    "Any"
                ),

            Variants =
                HolyServerFinderTargetSelectionList(
                    HOLY_SERVER_FINDER_MAIN_UI.BuilderVariants,
                    "Any"
                ),

            Rarities =
                HolyServerFinderTargetSelectionList(
                    HOLY_SERVER_FINDER_MAIN_UI.BuilderRarities,
                    "Any"
                ),

            Priority =
                HolyServerFinderNormalizeAutoJoinPriority(
                    HOLY_SERVER_FINDER_MAIN_UI.BuilderPriority
                ),

            MatchMode =
                "All Selected",
        })

    local filters =
        HOLY_SERVER_FINDER_STATE.AutoJoinRules

    local editingIndex =
        tonumber(
            HOLY_SERVER_FINDER_MAIN_UI.EditingIndex
        )

    local savedIndex =
        nil

    local updated =
        false

    if editingIndex
    and filters[editingIndex] ~= nil then

        filters[editingIndex] =
            filter

        savedIndex =
            editingIndex

        updated =
            true

    else

        local newKey =
            HolyServerFinderFilterKey(
                filter
            )

        for index, existing in ipairs(filters) do

            if HolyServerFinderFilterKey(
                existing
            ) == newKey then

                filters[index] =
                    filter

                savedIndex =
                    index

                updated =
                    true

                break
            end
        end

        if savedIndex == nil then

            table.insert(
                filters,
                filter
            )

            savedIndex =
                #filters
        end
    end

    HOLY_SERVER_FINDER_MAIN_UI.SelectedIndex =
        savedIndex

    HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex =
        savedIndex
        or 1

    HolyQueueSaveServerFinderSettings()

    HolyNotify(
        "Auto Join Filters",
        updated
        and "Filter updated."
        or "Filter added.",
        3
    )

    HolyServerFinderResetFilterBuilder(
        false
    )

    HolyServerFinderRefreshMainUI()

    return true
end

function HolyServerFinderRemoveSelectedFilter()

    local index =
        tonumber(
            HOLY_SERVER_FINDER_MAIN_UI.SelectedIndex
        )

    if not index
    or HOLY_SERVER_FINDER_STATE.AutoJoinRules[index] == nil then

        HolyNotify(
            "Auto Join Watchlist",
            "Select a filter first.",
            3
        )

        return false
    end

    table.remove(
        HOLY_SERVER_FINDER_STATE.AutoJoinRules,
        index
    )

    HOLY_SERVER_FINDER_MAIN_UI.SelectedIndex =
        nil

    HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex =
        1

    HolyServerFinderResetFilterBuilder(
        false
    )

    HolyQueueSaveServerFinderSettings()

    HolyServerFinderRefreshMainUI()

    return true
end

function HolyServerFinderClearFilters()

    HOLY_SERVER_FINDER_STATE.AutoJoinRules =
        {}

    HOLY_SERVER_FINDER_MAIN_UI.SelectedIndex =
        nil

    HOLY_SERVER_FINDER_MAIN_UI.WatchlistPage =
        1

    HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex =
        1

    HolyServerFinderResetFilterBuilder(
        false
    )

    HolyQueueSaveServerFinderSettings()

    HolyServerFinderRefreshMainUI()

    return true
end

function HolyServerFinderRefreshAutoJoinRulesPopup()

    if type(HolyServerFinderRefreshMainUI) == "function" then

        HolyServerFinderRefreshMainUI()
    end
end

function HolyServerFinderBuildSavePayload()

    HolyServerFinderEnsureAutoJoinState()

    return {
        Enabled =
            HOLY_SERVER_FINDER_STATE.Enabled == true,

        AutoRefresh =
            HOLY_SERVER_FINDER_STATE.AutoRefresh == true,

        RefreshDelay =
            math.clamp(
                tonumber(HOLY_SERVER_FINDER_STATE.RefreshDelay)
                or 5,
                1,
                60
            ),

        HideFull =
            HOLY_SERVER_FINDER_STATE.HideFull ~= false,

        HudScale =
            HolyServerFinderGetHudScale(),

        SelectedPets =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedPets
            ),

        SelectedRarities =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedRarities
            ),

        SelectedSizes =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedSizes
            ),

        SelectedVariants =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedVariants
            ),

        AutoJoinMode =
            HolyServerFinderNormalizeAutoJoinMode(
                HOLY_SERVER_FINDER_STATE.AutoJoinMode
            ),

        AutoJoinMinLife =
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinMinLife
            )
            or 30,

        AutoJoinCooldown =
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinCooldown
            )
            or 10,

        AutoJoinHoldLoadGrace =
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace
            )
            or 22,

        AutoJoinHold =
            HolyServerFinderNormalizeAutoJoinHold(
                HOLY_SERVER_FINDER_STATE.AutoJoinHold
            ),

        AutoJoinSelectedRuleIndex =
            tonumber(
                HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex
            )
            or 1,

        AutoJoinRules =
            HolyServerFinderNormalizeAutoJoinRules(
                HOLY_SERVER_FINDER_STATE.AutoJoinRules
            ),

        Minimized =
            HOLY_SERVER_FINDER_STATE.Minimized == true,

        Position =
            HolyServerFinderReadPosition(
                HOLY_SERVER_FINDER_STATE.Position
            ),

        FilterPosition =
            HolyServerFinderReadPosition(
                HOLY_SERVER_FINDER_STATE.FilterPosition
            ),
    }
end

function HolySaveServerFinderSettings()

    if HolyCanUseFiles() ~= true then
        return false
    end

    HolyEnsureFolder()

    local encodeOk,
        encoded =
        pcall(function()

            return HttpService:JSONEncode(
                HolyServerFinderBuildSavePayload()
            )
        end)

    if encodeOk ~= true
    or type(encoded) ~= "string" then
        return false
    end

    local writeOk =
        pcall(function()

            writefile(
                SERVER_FINDER_SETTINGS_FILE,
                encoded
            )
        end)

    return writeOk == true
end

function HolyQueueSaveServerFinderSettings()

    HOLY_SERVER_FINDER_SAVE_TOKEN =
        (
            tonumber(
                HOLY_SERVER_FINDER_SAVE_TOKEN
            )
            or 0
        )
        + 1

    local token =
        HOLY_SERVER_FINDER_SAVE_TOKEN

    task.delay(0.35, function()

        if HOLY_SERVER_FINDER_SAVE_TOKEN ~= token then
            return
        end

        HolySaveServerFinderSettings()
    end)
end

function HolyLoadServerFinderSettings()

    -- The compact HUD only uses its search box.
HOLY_SERVER_FINDER_STATE.HideFull =
    false

HOLY_SERVER_FINDER_STATE.SelectedPets =
    {}

HOLY_SERVER_FINDER_STATE.SelectedRarities =
    {}

HOLY_SERVER_FINDER_STATE.SelectedSizes =
    {}

HOLY_SERVER_FINDER_STATE.SelectedVariants =
    {}

HOLY_SERVER_FINDER_STATE.SelectedTraits =
    {}

HOLY_SERVER_FINDER_STATE.FilterPosition =
    nil

    if HolyCanUseFiles() ~= true then
        return false
    end

    local exists =
        false

    pcall(function()

        exists =
            isfile(
                SERVER_FINDER_SETTINGS_FILE
            )
    end)

    if exists ~= true then
        return false
    end

    local readOk,
        raw =
        pcall(function()

            return readfile(
                SERVER_FINDER_SETTINGS_FILE
            )
        end)

    if readOk ~= true
    or type(raw) ~= "string"
    or raw == "" then
        return false
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                raw
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then
        return false
    end

    HOLY_SERVER_FINDER_STATE.Enabled =
        data.Enabled == true

    HOLY_SERVER_FINDER_STATE.AutoRefresh =
        data.AutoRefresh == true

    HOLY_SERVER_FINDER_STATE.RefreshDelay =
        math.clamp(
            tonumber(data.RefreshDelay)
            or 5,
            1,
            60
        )

    HOLY_SERVER_FINDER_STATE.HideFull =
        data.HideFull ~= false

    HOLY_SERVER_FINDER_STATE.HudScale =
        HolyServerFinderReadHudScale(
            data.HudScale
            or data.Scale
            or HOLY_SERVER_FINDER_STATE.HudScale
            or 80
        )

    HOLY_SERVER_FINDER_STATE.SelectedPets =
        HolyServerFinderMapFromArray(
            data.SelectedPets
        )

    HOLY_SERVER_FINDER_STATE.SelectedRarities =
        HolyServerFinderMapFromArray(
            data.SelectedRarities
        )

    HOLY_SERVER_FINDER_STATE.SelectedSizes =
        HolyServerFinderSizeMapFromArray(
            data.SelectedSizes
        )

    HOLY_SERVER_FINDER_STATE.SelectedVariants =
        HolyServerFinderVariantMapFromArray(
            data.SelectedVariants
        )

    if next(HOLY_SERVER_FINDER_STATE.SelectedSizes) == nil
    and next(HOLY_SERVER_FINDER_STATE.SelectedVariants) == nil
    and type(data.SelectedTraits) == "table" then

        HOLY_SERVER_FINDER_STATE.SelectedSizes =
            HolyServerFinderSizeMapFromArray(
                data.SelectedTraits
            )

        HOLY_SERVER_FINDER_STATE.SelectedVariants =
            HolyServerFinderVariantMapFromArray(
                data.SelectedTraits
            )
    end

    HOLY_SERVER_FINDER_STATE.SelectedTraits =
        {}

    HOLY_SERVER_FINDER_STATE.Minimized =
        data.Minimized == true

    HOLY_SERVER_FINDER_STATE.Position =
        HolyServerFinderReadPosition(
            data.Position
        )

    HOLY_SERVER_FINDER_STATE.FilterPosition =
        HolyServerFinderReadPosition(
            data.FilterPosition
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinMode =
        HolyServerFinderNormalizeAutoJoinMode(
            data.AutoJoinMode
            or HOLY_SERVER_FINDER_STATE.AutoJoinMode
            or "Off"
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinMinLife =
        math.clamp(
            tonumber(
                data.AutoJoinMinLife
            )
            or 30,
            0,
            420
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinCooldown =
        math.clamp(
            tonumber(
                data.AutoJoinCooldown
            )
            or 10,
            1,
            120
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinHoldLoadGrace =
        math.clamp(
            tonumber(
                data.AutoJoinHoldLoadGrace
            )
            or 22,
            5,
            90
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinHold =
        HolyServerFinderNormalizeAutoJoinHold(
            data.AutoJoinHold
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinSelectedRuleIndex =
        tonumber(
            data.AutoJoinSelectedRuleIndex
        )
        or 1

    HOLY_SERVER_FINDER_STATE.AutoJoinRules =
        type(data.AutoJoinRules) == "table"
        and data.AutoJoinRules
        or HolyServerFinderGetDefaultAutoJoinRules()

    HolyServerFinderEnsureAutoJoinState()

    HolyServerSniperForceLockedOff(
        "saved Server Sniper settings",
        false
    )

    return true
end

HolyLoadServerFinderSettings()

function HolyServerFinderAddUniqueChoice(list, seen, value)

    value =
        HolyCleanText(
            value
        )

    if value == "" then
        return false
    end

    if value == "Mega" then
        value =
            "Huge"
    end

    if value == "Any" then
        return false
    end

    local key =
        value:lower()

    if seen[key] == true then
        return false
    end

    seen[key] =
        true

    table.insert(
        list,
        value
    )

    return true
end

function HolyServerFinderSortChoices(list)

    table.sort(list, function(a, b)

        return tostring(a):lower()
            < tostring(b):lower()
    end)

    return list
end

function HolyServerFinderBuildFilterOptions()

    local pets =
        {}

    local rarities =
        {}

    local sizes =
        {}

    local variants =
        {}

    local seenPets =
        {}

    local seenRarities =
        {}

    local seenSizes =
        {}

    local seenVariants =
        {}

    for _, petName in ipairs(HolySniperGetPetValues()) do

        HolyServerFinderAddUniqueChoice(
            pets,
            seenPets,
            petName
        )
    end

    local petData =
        HolySniperGetPetData()

    for key, row in pairs(petData) do

        if HolySniperIsPetDataRow(
            key,
            row
        ) == true then

            HolyServerFinderAddUniqueChoice(
                rarities,
                seenRarities,
                row.Rarity
            )
        end
    end

    for _, sizeName in ipairs({
        "Normal",
        "Big",
        "Huge",
    }) do

        HolyServerFinderAddUniqueChoice(
            sizes,
            seenSizes,
            sizeName
        )
    end

    for _, variantName in ipairs({
        "Regular",
        "Rainbow",
    }) do

        HolyServerFinderAddUniqueChoice(
            variants,
            seenVariants,
            variantName
        )
    end

    return {
        Pets =
            HolyServerFinderSortChoices(
                pets
            ),

        Rarities =
            HolyServerFinderSortChoices(
                rarities
            ),

        Sizes =
            sizes,

        Variants =
            variants,
    }
end

function HolyServerFinderApplyFilterOptions(hud)

    if type(hud) ~= "table"
    or type(hud.SetFilterOptions) ~= "function" then
        return false
    end

    hud:SetFilterOptions(
        HolyServerFinderBuildFilterOptions()
    )

    return true
end

function HolyServerFinderGetPlayerCounts()

    local playing =
        #Players:GetPlayers()

    local maxPlayers =
        8

    pcall(function()

        maxPlayers =
            tonumber(
                Players.MaxPlayers
            )
            or maxPlayers
    end)

    if maxPlayers <= 0 then
        maxPlayers =
            8
    end

    return playing,
        maxPlayers
end

function HolyServerFinderBuildRowName(row)

    row =
        type(row) == "table"
        and row
        or {}

    local displayName =
        HolyCleanText(
            row.DisplayName
        )

    if displayName ~= "" then
        return displayName
    end

    local parts =
        {}

    local size =
        HolyCleanText(
            row.Size
        )

    local variant =
        HolyCleanText(
            row.Variant
        )

    local pet =
        HolyCleanText(
            row.Pet
        )

    if size ~= ""
    and size ~= "Any"
    and size ~= "Normal"
    and size ~= "Regular" then

        table.insert(
            parts,
            size
        )
    end

    if variant ~= ""
    and variant ~= "Any"
    and variant ~= "Normal"
    and variant ~= "Regular" then

        table.insert(
            parts,
            variant
        )
    end

    if pet ~= "" then

        table.insert(
            parts,
            pet
        )
    end

    if #parts <= 0 then
        return "Unknown Pet"
    end

    return table.concat(
        parts,
        " "
    )
end

function HolyServerFinderRarityRank(rarity)

    rarity =
        HolyCleanText(
            rarity
        )

    local ranks = {
        Secret = 8,
        Super = 7,
        Mythic = 6,
        Legendary = 5,
        Epic = 4,
        Rare = 3,
        Uncommon = 2,
        Common = 1,
    }

    return ranks[rarity]
        or 0
end

function HolyServerFinderBuildLocalPetRow(row)

    row =
        type(row) == "table"
        and row
        or {}

    local state =
        tostring(
            row.State
            or ""
        )
        :lower()

    if state == "sent"
    or state == "bought"
    or state == "gone" then

        return nil
    end

    local timeLeft =
        tonumber(
            row.TimeLeftNumber
            or row.TimeLeft
        )
        or 0

    local lifetime =
        tonumber(
            row.Lifetime
        )
        or 0

    if lifetime > 0
    and timeLeft <= 0 then

        return nil
    end

    local petName =
        HolyCleanText(
            row.Pet
            or row.PetName
        )

    if petName == "" then

        petName =
            HolyServerFinderBuildRowName(
                row
            )
    end

    if petName == "" then
        return nil
    end

    local now =
        os.time()

    local spawnedAt =
        tonumber(
            row.SpawnedAt
        )
        or 0

    local expiresAt =
        0

    if spawnedAt > 0
    and lifetime > 0 then

        expiresAt =
            spawnedAt
            + lifetime

    elseif timeLeft > 0 then

        expiresAt =
            now
            + timeLeft
    end

    local displayName =
        HolyServerFinderBuildRowName(
            row
        )

    local rarity =
        HolyCleanText(
            row.Rarity
        )

    local size =
        HolyCleanText(
            row.Size
        )

    local variant =
        HolyCleanText(
            row.Variant
        )

    return {
        Key =
            tostring(row.Key or row.UUID or petName),

        UUID =
            tostring(row.UUID or row.Key or ""),

        DisplayName =
            displayName,

        Pet =
            petName,

        PetName =
            petName,

        Rarity =
            rarity,

        RarityRank =
            HolyServerFinderRarityRank(
                rarity
            ),

        Size =
            size,

        Variant =
            variant,

        Mutation =
            variant,

        SpawnedAt =
            spawnedAt,

        Lifetime =
            lifetime,

        ExpiresAt =
            expiresAt,

        TimeLeft =
            math.max(
                0,
                expiresAt > 0
                and expiresAt - now
                or timeLeft
            ),

        Price =
            row.PriceNumber
            or row.Price
            or 0,

        PriceNumber =
            tonumber(
                row.PriceNumber
                or row.Price
            )
            or 0,
    }
end

function HolyServerFinderAddUniqueText(list, seen, value)

    value =
        HolyCleanText(
            value
        )

    if value == ""
    or value == "Any"
    or value == "Regular" then

        return false
    end

    local key =
        value:lower()

    if seen[key] == true then
        return false
    end

    seen[key] =
        true

    table.insert(
        list,
        value
    )

    return true
end

function HolyServerFinderBuildPetSummary(pets, maxShown)

    pets =
        type(pets) == "table"
        and pets
        or {}

    maxShown =
        math.max(
            1,
            tonumber(maxShown)
            or 3
        )

    local order =
        {}

    local counts =
        {}

    local seen =
        {}

    for _, pet in ipairs(pets) do

        local name =
            HolyCleanText(
                pet.DisplayName
                or pet.Pet
                or pet.PetName
            )

        if name ~= "" then

            local key =
                name:lower()

            if seen[key] ~= true then

                seen[key] =
                    true

                table.insert(
                    order,
                    name
                )

                counts[key] =
                    0
            end

            counts[key] =
                (
                    tonumber(
                        counts[key]
                    )
                    or 0
                )
                + 1
        end
    end

    if #order <= 0 then
        return "Unknown Server"
    end

    local shown =
        {}

    for index, name in ipairs(order) do

        if index > maxShown then
            break
        end

        local count =
            tonumber(
                counts[name:lower()]
            )
            or 1

        if count > 1 then

            table.insert(
                shown,
                name
                .. " x"
                .. tostring(count)
            )

        else

            table.insert(
                shown,
                name
            )
        end
    end

    local text =
        table.concat(
            shown,
            ", "
        )

    local extra =
        #order - maxShown

    if extra > 0 then

        text =
            text
            .. " +"
            .. tostring(extra)
    end

    return text
end

function HolyServerFinderBuildUniquePetField(pets, fieldName)

    local output =
        {}

    local seen =
        {}

    for _, pet in ipairs(pets or {}) do

        HolyServerFinderAddUniqueText(
            output,
            seen,
            pet[fieldName]
        )
    end

    return table.concat(
        output,
        " "
    )
end

function HolyServerFinderBuildPetSearchBlob(pets)

    local parts =
        {}

    for _, pet in ipairs(pets or {}) do

        for _, value in ipairs({
            pet.DisplayName,
            pet.Pet,
            pet.PetName,
            pet.Rarity,
            pet.Size,
            pet.Variant,
            pet.Mutation,
        }) do

            value =
                HolyCleanText(
                    value
                )

            if value ~= "" then

                table.insert(
                    parts,
                    value
                )
            end
        end
    end

    return table.concat(
        parts,
        " "
    )
end

function HolyServerFinderBuildLocalRows()

    local liveRows =
        {}

    local ok,
        result =
        pcall(function()

            return HolyLivePetsScanRows()
        end)

    if ok == true
    and type(result) == "table" then

        liveRows =
            result
    end

    local pets =
        {}

    for _, row in ipairs(liveRows) do

        local pet =
            HolyServerFinderBuildLocalPetRow(
                row
            )

        if pet then

            table.insert(
                pets,
                pet
            )
        end
    end

    if #pets <= 0 then
        return {}
    end

    table.sort(pets, function(a, b)

        local rarityA =
            tonumber(a.RarityRank)
            or 0

        local rarityB =
            tonumber(b.RarityRank)
            or 0

        if rarityA ~= rarityB then
            return rarityA > rarityB
        end

        local priceA =
            tonumber(a.PriceNumber)
            or 0

        local priceB =
            tonumber(b.PriceNumber)
            or 0

        if priceA ~= priceB then
            return priceA > priceB
        end

        local timeA =
            tonumber(a.TimeLeft)
            or 0

        local timeB =
            tonumber(b.TimeLeft)
            or 0

        if timeA ~= timeB then
            return timeA < timeB
        end

        return tostring(a.DisplayName or "")
            < tostring(b.DisplayName or "")
    end)

    local playing,
        maxPlayers =
        HolyServerFinderGetPlayerCounts()

    local now =
        os.time()

    local minExpiresAt =
        nil

    local maxExpiresAt =
        nil

    for _, pet in ipairs(pets) do

        local expiresAt =
            tonumber(
                pet.ExpiresAt
            )
            or 0

        if expiresAt > now then

            if minExpiresAt == nil
            or expiresAt < minExpiresAt then

                minExpiresAt =
                    expiresAt
            end

            if maxExpiresAt == nil
            or expiresAt > maxExpiresAt then

                maxExpiresAt =
                    expiresAt
            end
        end
    end

    minExpiresAt =
        minExpiresAt
        or 0

    maxExpiresAt =
        maxExpiresAt
        or 0

    local bestPet =
        pets[1]
        or {}

    local serverKey =
        tostring(game.JobId)
        .. "|local-server"

    local displayName =
        HolyServerFinderBuildPetSummary(
            pets,
            3
        )

    local searchBlob =
        HolyServerFinderBuildPetSearchBlob(
            pets
        )

    return {
        {
            Key =
                serverKey,

            Id =
                serverKey,

            PlaceId =
                game.PlaceId,

            JobId =
                tostring(game.JobId),

            DisplayName =
                displayName,

            Name =
                searchBlob,

            Pet =
                displayName,

            PetName =
                displayName,

            BestPet =
                bestPet.Pet
                or bestPet.PetName
                or "",

            BestDisplayName =
                bestPet.DisplayName
                or bestPet.Pet
                or "",

            Rarity =
                bestPet.Rarity
                or "",

            Size =
                HolyServerFinderBuildUniquePetField(
                    pets,
                    "Size"
                ),

            Variant =
                HolyServerFinderBuildUniquePetField(
                    pets,
                    "Variant"
                ),

            Mutation =
                HolyServerFinderBuildUniquePetField(
                    pets,
                    "Mutation"
                ),

            Playing =
                playing,

            MaxPlayers =
                maxPlayers,

            ReportedAt =
                now,

            ExpiresAt =
                maxExpiresAt,

            MinExpiresAt =
                minExpiresAt,

            MaxExpiresAt =
                maxExpiresAt,

            TimeLeft =
                math.max(
                    0,
                    maxExpiresAt > 0
                    and maxExpiresAt - now
                    or 0
                ),

            PetCount =
                #pets,

            Pets =
                pets,

            Source =
                "Local",

            IsCurrentServer =
                true,
        },
    }
end

function HolyServerFinderBackendUrl(path)

    path =
        HolyCleanText(
            path
        )

    if path == "" then
        path =
            "/"
    end

    if path:sub(1, 1) ~= "/" then
        path =
            "/"
            .. path
    end

    return tostring(SERVER_FINDER_API_BASE or "")
        :gsub("/+$", "")
        .. path
end

function HolyServerFinderRequestJson(method, url, payload)

    local requestFunction =
        HolyGetRequestFunction()

    if type(requestFunction) ~= "function" then
        return nil,
            "request unsupported"
    end

    method =
        tostring(method or "GET")
            :upper()

    url =
        HolyCleanText(
            url
        )

    if url == "" then
        return nil,
            "missing url"
    end

    local requestOptions = {
        Url =
            url,

        Method =
            method,

        Headers = {
            ["Accept"] =
                "application/json",

            ["Content-Type"] =
                "application/json",

            ["x-api-key"] =
                tostring(SERVER_FINDER_API_KEY or ""),
        },
    }

    if payload ~= nil then

        local encodeOk,
            encoded =
            pcall(function()

                return HttpService:JSONEncode(
                    payload
                )
            end)

        if encodeOk ~= true
        or type(encoded) ~= "string" then

            return nil,
                "encode failed"
        end

        requestOptions.Body =
            encoded
    end

    local requestOk,
        response =
        pcall(function()

            return requestFunction(
                requestOptions
            )
        end)

    if requestOk ~= true then

        return nil,
            "request failed: "
            .. tostring(response)
    end

    local status =
        0

    local body =
        ""

    if type(response) == "table" then

        status =
            tonumber(
                response.StatusCode
                or response.Status
                or response.statusCode
                or response.status
            )
            or 0

        body =
            response.Body
            or response.body
            or response.ResponseBody
            or response.responseBody
            or ""

    elseif type(response) == "string" then

        body =
            response
    end

    if status > 0
    and (
        status < 200
        or status >= 300
    ) then

        return nil,
            "http "
            .. tostring(status)
            .. ": "
            .. tostring(body):sub(1, 180)
    end

    local decodeOk,
        data =
        pcall(function()

            return HttpService:JSONDecode(
                tostring(body or "")
            )
        end)

    if decodeOk ~= true
    or type(data) ~= "table" then

        return nil,
            "decode failed: "
            .. tostring(body):sub(1, 180)
    end

    if data.ok == false then

        return nil,
            tostring(data.error or "backend error")
    end

    return data,
        "ok"
end

function HolyServerFinderReadServerVersion()

    local roots = {
        workspace,
        ReplicatedStorage,
        game,
    }

    local names = {
        "ServerVersion",
        "Version",
        "GameVersion",
        "BuildVersion",
    }

    for _, root in ipairs(roots) do

        if typeof(root) == "Instance" then

            for _, name in ipairs(names) do

                local ok,
                    value =
                    pcall(function()

                        return root:GetAttribute(
                            name
                        )
                    end)

                value =
                    HolyCleanText(
                        ok == true
                        and value
                        or ""
                    )

                if value ~= "" then
                    return value
                end
            end
        end
    end

    return ""
end

function HolyServerFinderBuildReportPayload()

    local liveRows =
        {}

    local scanOk,
        scanResult =
        pcall(function()

            return HolyLivePetsScanRows()
        end)

    if scanOk == true
    and type(scanResult) == "table" then

        liveRows =
            scanResult
    end

    local pets =
        {}

    for _, row in ipairs(liveRows) do

        local pet =
            HolyServerFinderBuildLocalPetRow(
                row
            )

        if pet then

            table.insert(
                pets,
                {
                    Key =
                        pet.Key,

                    UUID =
                        pet.UUID,

                    Pet =
                        pet.Pet,

                    PetName =
                        pet.PetName,

                    Rarity =
                        pet.Rarity,

                    Size =
                        pet.Size,

                    Variant =
                        pet.Variant,

                    Mutation =
                        pet.Mutation,

                    SpawnedAt =
                        tonumber(pet.SpawnedAt)
                        or 0,

                    Lifetime =
                        tonumber(pet.Lifetime)
                        or 0,

                    ExpiresAt =
                        tonumber(pet.ExpiresAt)
                        or 0,

                    Price =
                        tonumber(pet.PriceNumber)
                        or 0,
                }
            )
        end
    end

    local playing,
        maxPlayers =
        HolyServerFinderGetPlayerCounts()

    return {
        Key =
            tostring(SERVER_FINDER_API_KEY or ""),

        PlaceId =
            game.PlaceId,

        JobId =
            tostring(game.JobId),

        Playing =
            playing,

        MaxPlayers =
            maxPlayers,

        ServerVersion =
            HolyServerFinderReadServerVersion(),

        Reporter =
            tostring(
                LocalPlayer
                and LocalPlayer.Name
                or "unknown"
            ),

        Pets =
            pets,
    }
end

function HolyRareAlertAlias(value)

    if type(HolySniperPetAliasKey) == "function" then

        return HolySniperPetAliasKey(
            value
        )
    end

    return HolyCleanText(
        value
    )
        :lower()
        :gsub("[%s_%-%[%]%(%)%.]", "")
end

function HolyRareAlertNormalizeSize(value)

    if type(HolySniperNormalizeSizeName) == "function" then

        return HolySniperNormalizeSizeName(
            value
        )
    end

    local text =
        HolyCleanText(
            value
        )

    if text == "" then
        return "Normal"
    end

    if text == "Mega" then
        return "Huge"
    end

    return text
end

function HolyRareAlertNormalizeVariant(value)

    if type(HolySniperNormalizeVariantName) == "function" then

        local normalized =
            HolySniperNormalizeVariantName(
                value
            )

        if normalized == "Regular" then
            return "Normal"
        end

        return normalized
    end

    local text =
        HolyCleanText(
            value
        )

    if text == ""
    or text == "Regular" then

        return "Normal"
    end

    return text
end

function HolyRareAlertIsSpecificPet(row)

    row =
        type(row) == "table"
        and row
        or {}

    local key =
        HolyRareAlertAlias(
            row.Pet
            or row.PetName
            or row.DisplayName
        )

    return key == "raccoon"
        or key == "unicorn"
        or key == "goldendragonfly"
        or key == "dragonfly"
end

function HolyRareAlertIsVariantPet(row)

    row =
        type(row) == "table"
        and row
        or {}

    local size =
        HolyRareAlertNormalizeSize(
            row.Size
        )

    local variant =
        HolyRareAlertNormalizeVariant(
            row.Variant
            or row.Mutation
        )

    if size == "Big"
    or size == "Huge" then

        return true
    end

    if variant ~= ""
    and variant ~= "Normal"
    and variant ~= "Regular"
    and variant ~= "Any" then

        return true
    end

    return false
end

function HolyRareAlertShouldReportRow(row)

    if type(row) ~= "table" then
        return false
    end

    local state =
        tostring(
            row.State
            or ""
        )
        :lower()

    if state == "sent"
    or state == "bought"
    or state == "gone" then

        return false
    end

    local lifetime =
        tonumber(
            row.Lifetime
        )
        or 0

    local timeLeft =
        tonumber(
            row.TimeLeftNumber
            or row.TimeLeft
        )
        or 0

    if lifetime > 0
    and timeLeft <= 0 then

        return false
    end

    if HolyRareAlertIsSpecificPet(row) == true then
        return true
    end

    if HolyRareAlertIsVariantPet(row) == true then
        return true
    end

    return false
end

function HolyRareAlertRowExpiresAt(row)

    row =
        type(row) == "table"
        and row
        or {}

    local spawnedAt =
        tonumber(
            row.SpawnedAt
        )
        or 0

    local lifetime =
        tonumber(
            row.Lifetime
        )
        or 0

    if spawnedAt > 0
    and lifetime > 0 then

        return spawnedAt + lifetime
    end

    local timeLeft =
        tonumber(
            row.TimeLeftNumber
            or row.TimeLeft
        )
        or 0

    if timeLeft > 0 then

        return os.time() + timeLeft
    end

    return os.time() + 300
end

function HolyRareAlertRowKey(row)

    row =
        type(row) == "table"
        and row
        or {}

    local key =
        HolyCleanText(
            row.UUID
            or row.Key
            or ""
        )

    if key == "" then

        key =
            table.concat({
                HolyRareAlertAlias(
                    row.Pet
                    or row.PetName
                    or row.DisplayName
                ),

                HolyRareAlertNormalizeSize(
                    row.Size
                ),

                HolyRareAlertNormalizeVariant(
                    row.Variant
                    or row.Mutation
                ),

                tostring(
                    tonumber(row.SpawnedAt)
                    or 0
                ),
            }, "_")
    end

    return table.concat({
        tostring(game.PlaceId),
        tostring(game.JobId),
        key,
    }, "|")
end

function HolyRareAlertPruneSent()

    HOLY_RARE_ALERT_STATE =
        type(HOLY_RARE_ALERT_STATE) == "table"
        and HOLY_RARE_ALERT_STATE
        or {}

    HOLY_RARE_ALERT_STATE.Sent =
        type(HOLY_RARE_ALERT_STATE.Sent) == "table"
        and HOLY_RARE_ALERT_STATE.Sent
        or {}

    local now =
        os.time()

    for key, expiresAt in pairs(HOLY_RARE_ALERT_STATE.Sent) do

        if tonumber(expiresAt) == nil
        or tonumber(expiresAt) <= now then

            HOLY_RARE_ALERT_STATE.Sent[key] =
                nil
        end
    end
end

function HolyRareAlertBuildPetPayload(row)

    row =
        type(row) == "table"
        and row
        or {}

    local expiresAt =
        HolyRareAlertRowExpiresAt(
            row
        )

    local timeLeft =
        math.max(
            0,
            expiresAt - os.time()
        )

    return {
        Key =
            HolyCleanText(
                row.Key
                or row.UUID
                or ""
            ),

        UUID =
            HolyCleanText(
                row.UUID
                or row.Key
                or ""
            ),

        Pet =
            HolyCleanText(
                row.Pet
                or row.PetName
                or ""
            ),

        PetName =
            HolyCleanText(
                row.Pet
                or row.PetName
                or ""
            ),

        DisplayName =
            HolyCleanText(
                row.DisplayName
                or ""
            ),

        Rarity =
            HolyCleanText(
                row.Rarity
                or ""
            ),

        Size =
            HolyRareAlertNormalizeSize(
                row.Size
            ),

        Variant =
            HolyRareAlertNormalizeVariant(
                row.Variant
                or row.Mutation
            ),

        Mutation =
            HolyRareAlertNormalizeVariant(
                row.Variant
                or row.Mutation
            ),

        SpawnedAt =
            tonumber(row.SpawnedAt)
            or 0,

        Lifetime =
            tonumber(row.Lifetime)
            or 0,

        ExpiresAt =
            expiresAt,

        TimeLeft =
            timeLeft,

        Price =
            tonumber(
                row.PriceNumber
                or row.Price
            )
            or 0,
    }
end

function HolyRareAlertBuildPayload()

    HolyRareAlertPruneSent()

    local rows =
        {}

    local ok,
        result =
        pcall(function()

            return HolyLivePetsScanRows()
        end)

    if ok == true
    and type(result) == "table" then

        rows =
            result
    end

    local pets =
        {}

    local sentKeys =
        {}

    for _, row in ipairs(rows) do

        if HolyRareAlertShouldReportRow(row) == true then

            local rowKey =
                HolyRareAlertRowKey(
                    row
                )

            if HOLY_RARE_ALERT_STATE.Sent[rowKey] ~= true
            and HOLY_RARE_ALERT_STATE.Sent[rowKey] == nil then

                table.insert(
                    pets,
                    HolyRareAlertBuildPetPayload(
                        row
                    )
                )

                table.insert(
                    sentKeys,
                    {
                        Key =
                            rowKey,

                        ExpiresAt =
                            HolyRareAlertRowExpiresAt(
                                row
                            ),
                    }
                )
            end
        end
    end

    if #pets <= 0 then
        return nil,
            sentKeys
    end

    local playing,
        maxPlayers =
        0,
        8

    if type(HolyServerFinderGetPlayerCounts) == "function" then

        playing,
            maxPlayers =
            HolyServerFinderGetPlayerCounts()

    else

        playing =
            #Players:GetPlayers()

        maxPlayers =
            tonumber(Players.MaxPlayers)
            or 8
    end

    return {
        Key =
            tostring(
                SERVER_FINDER_API_KEY
                or ""
            ),

        PlaceId =
            game.PlaceId,

        JobId =
            tostring(
                game.JobId
            ),

        Playing =
            playing,

        MaxPlayers =
            maxPlayers,

        ServerVersion =
            type(HolyServerFinderReadServerVersion) == "function"
            and HolyServerFinderReadServerVersion()
            or "",

        Reporter =
            tostring(
                LocalPlayer
                and LocalPlayer.Name
                or "unknown"
            ),

        Pets =
            pets,
    },
        sentKeys
end

function HolyRareAlertSendPayload(payload, sentKeys)

    if type(payload) ~= "table" then
        return false,
            "empty"
    end

    if type(HolyServerFinderRequestJson) ~= "function"
    or type(HolyServerFinderBackendUrl) ~= "function" then

        return false,
            "request helper missing"
    end

    local data,
        reason =
        HolyServerFinderRequestJson(
            "POST",
            HolyServerFinderBackendUrl(
                "/rare-alert"
            ),
            payload
        )

    if type(data) == "table"
    and data.ok == true then

        HOLY_RARE_ALERT_STATE.LastReportAt =
            os.time()

        HOLY_RARE_ALERT_STATE.LastStatus =
            "Reported "
            .. tostring(
                #(
                    payload.Pets
                    or {}
                )
            )
            .. " pet(s)"

        for _, row in ipairs(sentKeys or {}) do

            local key =
                HolyCleanText(
                    row.Key
                )

            if key ~= "" then

                HOLY_RARE_ALERT_STATE.Sent[key] =
                    tonumber(row.ExpiresAt)
                    or (
                        os.time() + 300
                    )
            end
        end

        return true,
            "ok"
    end

    HOLY_RARE_ALERT_STATE.LastError =
        tostring(reason or "request failed")

    return false,
        HOLY_RARE_ALERT_STATE.LastError
end

function HolyRareAlertTick()

    HOLY_RARE_ALERT_STATE.LastScanAt =
        os.time()

    local payload,
        sentKeys =
        HolyRareAlertBuildPayload()

    if type(payload) ~= "table" then
        return false
    end

    return HolyRareAlertSendPayload(
        payload,
        sentKeys
    )
end

function HolyRareAlertStart(reason)

    HOLY_RARE_ALERT_STATE =
        type(HOLY_RARE_ALERT_STATE) == "table"
        and HOLY_RARE_ALERT_STATE
        or {}

    if HOLY_RARE_ALERT_STATE.Running == true then
        return false
    end

    HOLY_RARE_ALERT_STATE.Running =
        true

    HOLY_RARE_ALERT_STATE.Sent =
        type(HOLY_RARE_ALERT_STATE.Sent) == "table"
        and HOLY_RARE_ALERT_STATE.Sent
        or {}

    local token =
        {}

    HOLY_RARE_ALERT_STATE.Token =
        token

    task.spawn(function()

        task.wait(
            1.25
        )

        while HOLY_RARE_ALERT_STATE.Token == token do

            pcall(function()

                HolyRareAlertTick()
            end)

            task.wait(
                tonumber(
                    HOLY_RARE_ALERT_STATE.ScanInterval
                )
                or 0.85
            )
        end

        if HOLY_RARE_ALERT_STATE.Token == token then

            HOLY_RARE_ALERT_STATE.Running =
                false
        end
    end)

    return true
end

function HolyRareAlertStop(reason)

    HOLY_RARE_ALERT_STATE =
        type(HOLY_RARE_ALERT_STATE) == "table"
        and HOLY_RARE_ALERT_STATE
        or {}

    HOLY_RARE_ALERT_STATE.Token =
        nil

    HOLY_RARE_ALERT_STATE.Running =
        false

    return true
end

function HolyServerFinderReportNow(reason)

    HOLY_SERVER_FINDER_REPORTER =
        type(HOLY_SERVER_FINDER_REPORTER) == "table"
        and HOLY_SERVER_FINDER_REPORTER
        or {}

    local payload =
        HolyServerFinderBuildReportPayload()

    local data,
        requestReason =
        HolyServerFinderRequestJson(
            "POST",
            HolyServerFinderBackendUrl(
                "/report"
            ),
            payload
        )

    HOLY_SERVER_FINDER_REPORTER.LastReportAt =
        os.time()

    if type(data) == "table"
    and data.ok == true then

        HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
            data.deleted == true
            and "Deleted empty server"
            or (
                "Reported "
                .. tostring(data.petCount or 0)
                .. " pet(s)"
            )

        return true,
            HOLY_SERVER_FINDER_REPORTER.LastReportStatus
    end

    HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
        tostring(requestReason or "report failed")

    return false,
        HOLY_SERVER_FINDER_REPORTER.LastReportStatus
end

function HolyServerFinderReportForRefresh(reason)

    HOLY_SERVER_FINDER_REPORTER =
        type(HOLY_SERVER_FINDER_REPORTER) == "table"
        and HOLY_SERVER_FINDER_REPORTER
        or {}

    if type(HolyGetRequestFunction()) ~= "function" then

        HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
            "request unsupported"

        return false,
            "request unsupported"
    end

    if HOLY_SERVER_FINDER_REPORTER.RefreshReportRunning == true then

        return false,
            "report already running"
    end

    local nowClock =
        os.clock()

    if nowClock - (
        tonumber(
            HOLY_SERVER_FINDER_REPORTER.LastRefreshReportClock
        )
        or 0
    ) < 0.85 then

        return false,
            "refresh report cooldown"
    end

    HOLY_SERVER_FINDER_REPORTER.RefreshReportRunning =
        true

    HOLY_SERVER_FINDER_REPORTER.LastRefreshReportClock =
        nowClock

    local ok,
        success,
        status =
        pcall(function()

            return HolyServerFinderReportNow(
                reason or "refresh"
            )
        end)

    HOLY_SERVER_FINDER_REPORTER.RefreshReportRunning =
        false

    if ok == true then

        return success == true,
            tostring(status or HOLY_SERVER_FINDER_REPORTER.LastReportStatus or "reported")
    end

    HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
        tostring(success or "report failed")

    return false,
        HOLY_SERVER_FINDER_REPORTER.LastReportStatus
end

function HolyServerFinderStartReporter()

    HOLY_SERVER_FINDER_REPORTER =
        type(HOLY_SERVER_FINDER_REPORTER) == "table"
        and HOLY_SERVER_FINDER_REPORTER
        or {}

    if HOLY_SERVER_FINDER_REPORTER.Running == true then
        return false
    end

    if type(HolyGetRequestFunction()) ~= "function" then

        HOLY_SERVER_FINDER_REPORTER.LastReportStatus =
            "request unsupported"

        return false
    end

    local token =
        {}

    HOLY_SERVER_FINDER_REPORTER.Token =
        token

    HOLY_SERVER_FINDER_REPORTER.Running =
        true

    task.spawn(function()

        while HOLY_SERVER_FINDER_REPORTER.Token == token do

            local interval =
                math.max(
                    3,
                    tonumber(SERVER_FINDER_REPORT_INTERVAL)
                    or 5
                )

            pcall(function()

                local lastReportAt =
                    tonumber(
                        HOLY_SERVER_FINDER_REPORTER.LastReportAt
                    )
                    or 0

                if os.time() - lastReportAt >= interval then

                    HolyServerFinderReportNow(
                        "loop"
                    )
                end
            end)

            task.wait(
                interval
            )
        end

        if HOLY_SERVER_FINDER_REPORTER.Token == token then

            HOLY_SERVER_FINDER_REPORTER.Running =
                false
        end
    end)

    return true
end

function HolyServerFinderNormalizeBackendPet(row)

    if type(row) ~= "table" then
        return nil
    end

    local petName =
        HolyCleanText(
            row.Pet
            or row.PetName
            or row.Name
        )

    if petName == "" then
        return nil
    end

    local size =
        HolySniperNormalizeSizeName(
            row.Size
            or row.size
            or "Normal"
        )

    local variant =
        HolySniperNormalizeVariantName(
            row.Variant
            or row.variant
            or row.Mutation
            or row.mutation
            or "Normal"
        )

    local spawnedAt =
        tonumber(
            row.SpawnedAt
            or row.spawnedAt
        )
        or 0

    local lifetime =
        tonumber(
            row.Lifetime
            or row.lifetime
        )
        or 0

    local expiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if expiresAt <= 0
    and spawnedAt > 0
    and lifetime > 0 then

        expiresAt =
            spawnedAt
            + lifetime
    end

    local displayName =
        HolyLivePetsBuildDisplayName(
            petName,
            size,
            variant
        )

    return {
        Key =
            HolyCleanText(
                row.Key
                or row.UUID
                or row.Id
                or displayName
            ),

        UUID =
            HolyCleanText(
                row.UUID
                or row.Key
                or ""
            ),

        DisplayName =
            displayName,

        Pet =
            petName,

        PetName =
            petName,

        Rarity =
            HolyCleanText(
                row.Rarity
                or row.rarity
            ),

        RarityRank =
            HolyServerFinderRarityRank(
                row.Rarity
                or row.rarity
            ),

        Size =
            size,

        Variant =
            variant,

        Mutation =
            variant,

        SpawnedAt =
            spawnedAt,

        Lifetime =
            lifetime,

        ExpiresAt =
            expiresAt,

        TimeLeft =
            math.max(
                0,
                expiresAt - os.time()
            ),

        Price =
            row.Price
            or row.price
            or 0,

        PriceNumber =
            tonumber(
                row.Price
                or row.price
            )
            or 0,
    }
end

function HolyServerFinderNormalizeBackendRow(row)

    if type(row) ~= "table" then
        return nil
    end

    local jobId =
        HolyCleanText(
            row.JobId
            or row.jobId
            or row.ServerId
            or row.id
            or row.Id
        )

    if jobId == "" then
        return nil
    end

    local pets =
        {}

    if type(row.Pets) == "table" then

        for _, petRow in ipairs(row.Pets) do

            local pet =
                HolyServerFinderNormalizeBackendPet(
                    petRow
                )

            if pet then

                table.insert(
                    pets,
                    pet
                )
            end
        end
    end

    table.sort(pets, function(a, b)

        if a.RarityRank ~= b.RarityRank then
            return a.RarityRank > b.RarityRank
        end

        if a.PriceNumber ~= b.PriceNumber then
            return a.PriceNumber > b.PriceNumber
        end

        return tostring(a.DisplayName)
            < tostring(b.DisplayName)
    end)

    local now =
        os.time()

    local maxExpiresAt =
        tonumber(
            row.ExpiresAt
            or row.expiresAt
        )
        or 0

    if maxExpiresAt <= 0 then

        for _, pet in ipairs(pets) do

            maxExpiresAt =
                math.max(
                    maxExpiresAt,
                    tonumber(pet.ExpiresAt)
                    or 0
                )
        end
    end

    local bestPet =
        pets[1]
        or {}

    local displayName =
        HolyCleanText(
            row.DisplayName
            or row.displayName
        )

    if displayName == "" then

        displayName =
            HolyServerFinderBuildPetSummary(
                pets,
                3
            )
    end

    return {
        Key =
            jobId,

        Id =
            jobId,

        PlaceId =
            tonumber(
                row.PlaceId
                or row.placeId
            )
            or game.PlaceId,

        JobId =
            jobId,

        DisplayName =
            displayName,

        Name =
            HolyServerFinderBuildPetSearchBlob(
                pets
            ),

        Pet =
            displayName,

        PetName =
            displayName,

        BestPet =
            HolyCleanText(
                row.BestPet
                or row.bestPet
                or bestPet.Pet
                or bestPet.PetName
            ),

        BestDisplayName =
            bestPet.DisplayName
            or bestPet.Pet
            or "",

        Rarity =
            HolyCleanText(
                row.Rarity
                or row.rarity
                or bestPet.Rarity
            ),

        Size =
            HolyServerFinderBuildUniquePetField(
                pets,
                "Size"
            ),

        Variant =
            HolyServerFinderBuildUniquePetField(
                pets,
                "Variant"
            ),

        Mutation =
            HolyServerFinderBuildUniquePetField(
                pets,
                "Mutation"
            ),

        Playing =
            tonumber(
                row.Playing
                or row.playing
            )
            or 0,

        MaxPlayers =
            tonumber(
                row.MaxPlayers
                or row.maxPlayers
            )
            or 8,

        ServerVersion =
            HolyCleanText(
                row.ServerVersion
                or row.serverVersion
            ),

        ReportedAt =
            tonumber(
                row.ReportedAt
                or row.reportedAt
            )
            or now,

        ExpiresAt =
            maxExpiresAt,

        TimeLeft =
            math.max(
                0,
                maxExpiresAt - now
            ),

        PetCount =
            tonumber(
                row.PetCount
                or row.petCount
            )
            or #pets,

        Pets =
            pets,

        Source =
            "Cloudflare",

        IsCurrentServer =
            jobId == tostring(game.JobId),
    }
end

function HolyServerFinderFetchBackendRows()

    if HolyAuthRequireServerSniper(
        "Server Finder Backend",
        false
    ) ~= true then

        return nil,
            "server sniper slot required"
    end

    if type(HolyGetRequestFunction()) ~= "function" then
        return nil,
            "request unsupported"
    end

    local hideFullValue =
        HOLY_SERVER_FINDER_STATE.HideFull ~= false
        and "1"
        or "0"

    local url =
        HolyServerFinderBackendUrl(
            "/servers"
        )
        .. "?placeId="
        .. tostring(game.PlaceId)
        .. "&limit=100"
        .. "&maxAge=45"
        .. "&hideFull="
        .. hideFullValue

    local data,
        requestReason =
        HolyServerFinderRequestJson(
            "GET",
            url,
            nil
        )

    HOLY_SERVER_FINDER_REPORTER.LastFetchAt =
        os.time()

    if type(data) ~= "table"
    or data.ok ~= true then

        HOLY_SERVER_FINDER_REPORTER.LastFetchStatus =
            tostring(requestReason or "fetch failed")

        return nil,
            HOLY_SERVER_FINDER_REPORTER.LastFetchStatus
    end

    local rows =
        {}

    local serverRows =
        type(data.servers) == "table"
        and data.servers
        or type(data.Servers) == "table"
        and data.Servers
        or {}

    for _, serverRow in ipairs(serverRows) do

        local normalized =
            HolyServerFinderNormalizeBackendRow(
                serverRow
            )

        if normalized then

            table.insert(
                rows,
                normalized
            )
        end
    end

    HOLY_SERVER_FINDER_REPORTER.LastFetchStatus =
        "Fetched "
        .. tostring(#rows)
        .. " server(s)"

    return rows,
        "ok"
end

function HolyServerFinderMergeRows(backendRows, localRows)

    local output =
        {}

    local indexByJobId =
        {}

    local function add(row, allowReplace)

        if type(row) ~= "table" then
            return
        end

        local jobId =
            HolyCleanText(
                row.JobId
                or row.jobId
                or row.ServerId
                or row.Id
                or row.Key
            )

        if jobId == "" then
            return
        end

        local existingIndex =
            indexByJobId[jobId]

        if existingIndex then

            if allowReplace == true then

                output[existingIndex] =
                    row
            end

            return
        end

        indexByJobId[jobId] =
            #output + 1

        table.insert(
            output,
            row
        )
    end

    for _, row in ipairs(backendRows or {}) do

        add(
            row,
            false
        )
    end

    for _, row in ipairs(localRows or {}) do

        add(
            row,
            true
        )
    end

    return output
end

function HolyServerFinderPetBaseName(pet)

    pet =
        type(pet) == "table"
        and pet
        or {}

    local baseName =
        HolyCleanText(
            pet.Pet
            or pet.PetName
            or pet.BasePet
            or pet.Name
        )

    if baseName ~= "" then
        return baseName
    end

    return HolyCleanText(
        pet.DisplayName
        or "Unknown Pet"
    )
end

function HolyServerFinderPetDisplayName(pet)

    pet =
        type(pet) == "table"
        and pet
        or {}

    local baseName =
        HolyCleanText(
            pet.Pet
            or pet.PetName
            or pet.BasePet
        )

    local displayName =
        HolyCleanText(
            pet.DisplayName
            or pet.Name
        )

    local size =
        HolySniperNormalizeSizeName(
            pet.Size
            or pet.size
            or "Normal"
        )

    local variant =
        HolySniperNormalizeVariantName(
            pet.Variant
            or pet.variant
            or pet.Mutation
            or pet.mutation
            or "Normal"
        )

    if baseName ~= "" then

        return HolyLivePetsBuildDisplayName(
            baseName,
            size,
            variant
        )
    end

    if displayName ~= "" then
        return displayName
    end

    return "Unknown Pet"
end

function HolyServerFinderPetGroupKey(pet)

    pet =
        type(pet) == "table"
        and pet
        or {}

    local baseName =
        HolySniperPetAliasKey(
            HolyServerFinderPetBaseName(
                pet
            )
        )

    local size =
        HolySniperNormalizeSizeName(
            pet.Size
            or pet.size
            or "Normal"
        )

    local variant =
        HolySniperNormalizeVariantName(
            pet.Variant
            or pet.variant
            or pet.Mutation
            or pet.mutation
            or "Normal"
        )

    local rarity =
        HolyCleanText(
            pet.Rarity
            or pet.rarity
        )

    return table.concat({
        baseName,
        size:lower(),
        variant:lower(),
        rarity:lower(),
    }, "|")
end

function HolyServerFinderClonePetForDisplay(pet)

    pet =
        type(pet) == "table"
        and pet
        or {}

    local copy =
        {}

    for key, value in pairs(pet) do

        copy[key] =
            value
    end

    local baseName =
        HolyServerFinderPetBaseName(
            pet
        )

    local size =
        HolySniperNormalizeSizeName(
            pet.Size
            or pet.size
            or "Normal"
        )

    local variant =
        HolySniperNormalizeVariantName(
            pet.Variant
            or pet.variant
            or pet.Mutation
            or pet.mutation
            or "Normal"
        )

    copy.Pet =
        baseName

    copy.PetName =
        baseName

    copy.Size =
        size

    copy.Variant =
        variant

    copy.Mutation =
        variant

    copy.DisplayName =
        HolyServerFinderPetDisplayName(
            copy
        )

    copy.Rarity =
        HolyCleanText(
            copy.Rarity
            or copy.rarity
        )

    copy.RarityRank =
        tonumber(copy.RarityRank)
        or HolyServerFinderRarityRank(
            copy.Rarity
        )

    copy.PriceNumber =
        tonumber(
            copy.PriceNumber
            or copy.Price
            or copy.price
        )
        or 0

    copy.Price =
        copy.PriceNumber

    return copy
end

function HolyServerFinderBuildPetDisplayRows(serverRows)

    local output =
        {}

    local now =
        os.time()

    for _, serverRow in ipairs(serverRows or {}) do

        if type(serverRow) ~= "table" then
            continue
        end

        local jobId =
            HolyCleanText(
                serverRow.JobId
                or serverRow.jobId
                or serverRow.ServerId
                or serverRow.Id
                or serverRow.Key
            )

        if jobId == "" then
            continue
        end

        local pets =
            {}

        if type(serverRow.Pets) == "table" then

            for _, pet in ipairs(serverRow.Pets) do

                if type(pet) == "table" then

                    local copy =
                        HolyServerFinderClonePetForDisplay(
                            pet
                        )

                    table.insert(
                        pets,
                        copy
                    )
                end
            end
        end

        if #pets <= 0 then

            local copy =
                HolyServerFinderClonePetForDisplay(
                    serverRow
                )

            if HolyCleanText(copy.DisplayName) ~= ""
            and HolyCleanText(copy.DisplayName) ~= "Unknown Pet" then

                table.insert(
                    pets,
                    copy
                )
            end
        end

        if #pets <= 0 then
            continue
        end

        local groups =
            {}

        local order =
            {}

        for _, pet in ipairs(pets) do

            local key =
                HolyServerFinderPetGroupKey(
                    pet
                )

            if groups[key] == nil then

                groups[key] = {
                    Key =
                        key,

                    Count =
                        0,

                    Pets =
                        {},

                    DisplayName =
                        HolyCleanText(
                            pet.DisplayName
                        ),

                    BasePet =
                        HolyCleanText(
                            pet.Pet
                            or pet.PetName
                        ),

                    Rarity =
                        HolyCleanText(
                            pet.Rarity
                        ),

                    RarityRank =
                        tonumber(pet.RarityRank)
                        or HolyServerFinderRarityRank(
                            pet.Rarity
                        ),

                    Size =
                        HolySniperNormalizeSizeName(
                            pet.Size
                            or "Normal"
                        ),

                    Variant =
                        HolySniperNormalizeVariantName(
                            pet.Variant
                            or pet.Mutation
                            or "Normal"
                        ),

                    PriceNumber =
                        tonumber(
                            pet.PriceNumber
                            or pet.Price
                        )
                        or 0,

                    ExpiresAt =
                        0,
                }

                table.insert(
                    order,
                    key
                )
            end

            local group =
                groups[key]

            group.Count =
                group.Count + 1

            group.PriceNumber =
                math.max(
                    tonumber(group.PriceNumber)
                    or 0,
                    tonumber(
                        pet.PriceNumber
                        or pet.Price
                    )
                    or 0
                )

            group.RarityRank =
                math.max(
                    tonumber(group.RarityRank)
                    or 0,
                    tonumber(pet.RarityRank)
                    or HolyServerFinderRarityRank(
                        pet.Rarity
                    )
                )

            local expiresAt =
                tonumber(
                    pet.ExpiresAt
                    or pet.expiresAt
                )
                or 0

            if expiresAt <= 0 then

                local spawnedAt =
                    tonumber(
                        pet.SpawnedAt
                        or pet.spawnedAt
                    )
                    or 0

                local lifetime =
                    tonumber(
                        pet.Lifetime
                        or pet.lifetime
                    )
                    or 0

                if spawnedAt > 0
                and lifetime > 0 then

                    expiresAt =
                        spawnedAt
                        + lifetime
                end
            end

            if expiresAt > group.ExpiresAt then

                group.ExpiresAt =
                    expiresAt
            end

            table.insert(
                group.Pets,
                pet
            )
        end

        for _, key in ipairs(order) do

            local group =
                groups[key]

            local displayName =
                HolyCleanText(
                    group.DisplayName
                )

            if displayName == "" then

                displayName =
                    HolyLivePetsBuildDisplayName(
                        group.BasePet,
                        group.Size,
                        group.Variant
                    )
            end

            if group.Count > 1 then

                displayName =
                    displayName
                    .. " x"
                    .. tostring(group.Count)
            end

            local expiresAt =
                tonumber(group.ExpiresAt)
                or tonumber(serverRow.ExpiresAt)
                or 0

            local otherPetCount =
                math.max(
                    0,
                    #pets - group.Count
                )

            local searchBlob =
                HolyServerFinderBuildPetSearchBlob(
                    group.Pets
                )

            table.insert(
                output,
                {
                    Key =
                        tostring(jobId)
                        .. "|pet|"
                        .. tostring(key),

                    Id =
                        tostring(jobId)
                        .. "|pet|"
                        .. tostring(key),

                    JobId =
                        jobId,

                    PlaceId =
                        tonumber(
                            serverRow.PlaceId
                            or serverRow.placeId
                        )
                        or game.PlaceId,

                    DisplayName =
                        displayName,

                    Name =
                        searchBlob,

                    Pet =
                        displayName,

                    PetName =
                        displayName,

                    BasePet =
                        group.BasePet,

                    BestPet =
                        group.BasePet,

                    BestDisplayName =
                        displayName,

                    Rarity =
                        group.Rarity,

                    RarityRank =
                        group.RarityRank,

                    Size =
                        group.Size,

                    Variant =
                        group.Variant,

                    Mutation =
                        group.Variant,

                    Price =
                        group.PriceNumber,

                    PriceNumber =
                        group.PriceNumber,

                    Playing =
                        tonumber(
                            serverRow.Playing
                            or serverRow.playing
                        )
                        or 0,

                    MaxPlayers =
                        tonumber(
                            serverRow.MaxPlayers
                            or serverRow.maxPlayers
                        )
                        or 8,

                    ServerVersion =
                        HolyCleanText(
                            serverRow.ServerVersion
                            or serverRow.serverVersion
                        ),

                    ReportedAt =
                        tonumber(
                            serverRow.ReportedAt
                            or serverRow.reportedAt
                        )
                        or now,

                    ExpiresAt =
                        expiresAt,

                    TimeLeft =
                        math.max(
                            0,
                            expiresAt > 0
                            and expiresAt - now
                            or 0
                        ),

                    PetCount =
                        group.Count,

                    ServerPetCount =
                        #pets,

                    OtherPetCount =
                        otherPetCount,

                    Pets =
                        group.Pets,

                    Source =
                        serverRow.Source
                        or "Cloudflare",

                    IsCurrentServer =
                        serverRow.IsCurrentServer == true
                        or jobId == tostring(game.JobId),

                    ParentServerRow =
                        serverRow,
                }
            )
        end
    end

    table.sort(output, function(a, b)

        if a.IsCurrentServer ~= b.IsCurrentServer then
            return a.IsCurrentServer == true
        end

        local rarityA =
            tonumber(a.RarityRank)
            or 0

        local rarityB =
            tonumber(b.RarityRank)
            or 0

        if rarityA ~= rarityB then
            return rarityA > rarityB
        end

        local priceA =
            tonumber(a.PriceNumber)
            or 0

        local priceB =
            tonumber(b.PriceNumber)
            or 0

        if priceA ~= priceB then
            return priceA > priceB
        end

        local timeA =
            tonumber(a.TimeLeft)
            or 0

        local timeB =
            tonumber(b.TimeLeft)
            or 0

        if timeA ~= timeB then
            return timeA > timeB
        end

        return tostring(a.DisplayName or "")
            < tostring(b.DisplayName or "")
    end)

    return output
end

function HolyServerFinderRefreshRows(hud, reason)

    if HolyAuthRequireServerSniper(
        "Server Finder Refresh",
        true
    ) ~= true then

        return false
    end

    if type(hud) ~= "table"
    or type(hud.SetRows) ~= "function" then
        return false
    end

    HolyServerFinderReportForRefresh(
        reason or "refresh"
    )

    local localRows =
        HolyServerFinderBuildLocalRows()

    local backendRows =
        nil

    local ok,
        result =
        pcall(function()

            return HolyServerFinderFetchBackendRows()
        end)

    if ok == true
    and type(result) == "table" then

        backendRows =
            result
    end

    local mergedRows =
        HolyServerFinderMergeRows(
            backendRows,
            localRows
        )

    local displayRows =
        HolyServerFinderAnnotateDisplayRows(
            HolyServerFinderBuildPetDisplayRows(
                mergedRows
            )
        )

    hud:SetRows(
        displayRows
    )

    HolyServerFinderEvaluateAutoJoin(
        hud
    )

    return true
end

function HolyServerFinderPullStateFromHud(hud)

    if type(hud) ~= "table"
    or type(hud.GetSettings) ~= "function" then
        return false
    end

    local settings =
        hud:GetSettings()

    if type(settings) ~= "table" then
        return false
    end

    HOLY_SERVER_FINDER_STATE.AutoRefresh =
        settings.AutoRefresh == true

    HOLY_SERVER_FINDER_STATE.RefreshDelay =
        math.clamp(
            tonumber(settings.RefreshDelay)
            or 5,
            1,
            60
        )

    HOLY_SERVER_FINDER_STATE.HideFull =
        settings.HideFull ~= false

    HOLY_SERVER_FINDER_STATE.SelectedPets =
        HolyServerFinderMapFromArray(
            settings.SelectedPets
        )

    HOLY_SERVER_FINDER_STATE.SelectedRarities =
        HolyServerFinderMapFromArray(
            settings.SelectedRarities
        )

    HOLY_SERVER_FINDER_STATE.SelectedSizes =
        HolyServerFinderSizeMapFromArray(
            settings.SelectedSizes
            or settings.SelectedTraits
        )

    HOLY_SERVER_FINDER_STATE.SelectedVariants =
        HolyServerFinderVariantMapFromArray(
            settings.SelectedVariants
            or settings.SelectedTraits
        )

    HOLY_SERVER_FINDER_STATE.SelectedTraits =
        {}

    HOLY_SERVER_FINDER_STATE.Minimized =
        settings.Minimized == true

    HOLY_SERVER_FINDER_STATE.Position =
        HolyServerFinderReadPosition(
            settings.Position
        )

    HOLY_SERVER_FINDER_STATE.FilterPosition =
        HolyServerFinderReadPosition(
            settings.FilterPosition
        )

    HOLY_SERVER_FINDER_STATE.HudScale =
        HolyServerFinderReadHudScale(
            settings.HudScale
            or settings.Scale
            or HOLY_SERVER_FINDER_STATE.HudScale
            or 80
        )

    HOLY_SERVER_FINDER_STATE.AutoJoinMode =
        HolyServerFinderNormalizeAutoJoinMode(
            settings.AutoJoinMode
            or HOLY_SERVER_FINDER_STATE.AutoJoinMode
            or "Off"
        )

    HolyServerFinderEnsureAutoJoinState()

    return true
end

function HolyServerFinderApplyStateToHud(hud)

    if type(hud) ~= "table"
    or type(hud.ApplySettings) ~= "function" then
        return false
    end

    HolyServerFinderEnsureAutoJoinState()

    hud:ApplySettings({
        AutoRefresh =
            HOLY_SERVER_FINDER_STATE.AutoRefresh == true,

        RefreshDelay =
            HOLY_SERVER_FINDER_STATE.RefreshDelay,

        HideFull =
            HOLY_SERVER_FINDER_STATE.HideFull ~= false,

        AutoJoinMode =
            HolyServerFinderNormalizeAutoJoinMode(
                HOLY_SERVER_FINDER_STATE.AutoJoinMode
            ),

        SelectedPets =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedPets
            ),

        SelectedRarities =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedRarities
            ),

        SelectedSizes =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedSizes
            ),

        SelectedVariants =
            HolyServerFinderArrayFromMap(
                HOLY_SERVER_FINDER_STATE.SelectedVariants
            ),

        Minimized =
            HOLY_SERVER_FINDER_STATE.Minimized == true,

        Position =
            HOLY_SERVER_FINDER_STATE.Position,

        FilterPosition =
            HOLY_SERVER_FINDER_STATE.FilterPosition,

        HudScale =
            HolyServerFinderGetHudScale(),

        Scale =
            HolyServerFinderGetHudScaleFactor(),
    })

    HolyServerFinderApplyScaleToHud(
        hud
    )

    return true
end

function HolyServerFinderSyncToggle(value)

    if HOLY_SERVER_FINDER_TOGGLE_LOCK == true then
        return false
    end

    local toggle =
        HOLY_SERVER_FINDER_TOGGLE

    if type(toggle) ~= "table"
    or type(toggle.SetValue) ~= "function" then
        return false
    end

    HOLY_SERVER_FINDER_TOGGLE_LOCK =
        true

    pcall(function()

        toggle:SetValue(
            value == true
        )
    end)

    HOLY_SERVER_FINDER_TOGGLE_LOCK =
        false

    return true
end

function HolyServerFinderSetHudVisible(value)

    value =
        value == true

    if value == true
    and HolyAuthRequireServerSniper(
        "Server Pet Finder HUD",
        true
    ) ~= true then

        HOLY_SERVER_FINDER_STATE.Enabled =
            false

        HOLY_SERVER_FINDER_STATE.AutoJoinMode =
            "Off"

        HolyServerFinderSyncToggle(
            false
        )

        HolyQueueSaveServerFinderSettings()

        if type(HOLY_SERVER_FINDER_HUD) == "table"
        and type(HOLY_SERVER_FINDER_HUD.Hide) == "function" then

            HOLY_SERVER_FINDER_HUD:Hide()
        end

        return false
    end

    HOLY_SERVER_FINDER_STATE.Enabled =
        value

    HolyQueueSaveServerFinderSettings()

    if value == true then

        HolyServerFinderOpenHud()

        return true
    end

    if type(HOLY_SERVER_FINDER_HUD) == "table"
    and type(HOLY_SERVER_FINDER_HUD.Hide) == "function" then

        HOLY_SERVER_FINDER_HUD:Hide()
    end

    return true
end

function HolyServerFinderOpenHud(showHud)

    if HolyAuthRequireServerSniper(
        "Server Finder HUD",
        showHud ~= false
    ) ~= true then

        return false
    end

    if HOLY_SERVER_FINDER_HUD == nil then

        HOLY_SERVER_FINDER_HUD =
            Library:CreateServerFinderHUD({
                Title =
                    "HOLY Server Finder",

                CurrentServer =
                    tostring(game.JobId),

                SimpleMode =
                    true,

                HideFull =
                    false,

                AutoRefresh =
                    HOLY_SERVER_FINDER_STATE.AutoRefresh == true,

                RefreshDelay =
                    HOLY_SERVER_FINDER_STATE.RefreshDelay,

                HudScale =
                    HolyServerFinderGetHudScale(),

                Scale =
                    HolyServerFinderGetHudScaleFactor(),

                AutoJoinMode =
                    HolyServerFinderNormalizeAutoJoinMode(
                        HOLY_SERVER_FINDER_STATE.AutoJoinMode
                    ),

                Minimized =
                    HOLY_SERVER_FINDER_STATE.Minimized == true,

                Position =
                    HOLY_SERVER_FINDER_STATE.Position,

                OnVisibleChanged =
                    function(visible, hud)

                        HOLY_SERVER_FINDER_STATE.Enabled =
                            visible == true

                        if visible == true then

                            HolyServerFinderPullStateFromHud(
                                hud
                            )
                        end

                        HolyServerFinderSyncToggle(
                            visible == true
                        )

                        HolyQueueSaveServerFinderSettings()
                    end,

                OnSettingsChanged =
                    function(hud)

                        HolyServerFinderPullStateFromHud(
                            hud
                        )

                        HolyQueueSaveServerFinderSettings()
                    end,

                OnRefresh =
                    function(hud)

                        HolyServerFinderRefreshRows(
                            hud,
                            "refresh button"
                        )
                    end,

                OnJoin =
                    function(row)

                        HolyServerFinderJoinRow(
                            row,
                            "Manual Join"
                        )
                    end,
            })
    end

    HolyServerFinderApplyStateToHud(
        HOLY_SERVER_FINDER_HUD
    )

    HolyServerFinderRefreshRows(
        HOLY_SERVER_FINDER_HUD,
        showHud == false
        and "background refresh"
        or "hud open"
    )

    HOLY_SERVER_FINDER_HUD:SetCurrentServer(
        tostring(game.JobId)
    )

    if showHud ~= false then

        HOLY_SERVER_FINDER_HUD:Show()
    end

    return true
end

HOLY_SERVER_FINDER_BACKGROUND_TOKEN = {
    Active = true,
}

do

    local token =
        HOLY_SERVER_FINDER_BACKGROUND_TOKEN

    task.spawn(function()

        local nextRefreshAt =
            0

        while token.Active == true
        and HOLY_SERVER_FINDER_BACKGROUND_TOKEN == token do

            HolyServerFinderEnsureAutoJoinState()

            local mode =
                HolyServerFinderNormalizeAutoJoinMode(
                    HOLY_SERVER_FINDER_STATE.AutoJoinMode
                )

            local shouldRun =
                HOLY_SERVER_FINDER_STATE.AutoRefresh == true
                or mode ~= "Off"

            if shouldRun == true
            and HolyAuthHasServerSniperSlot() == true
            and os.clock() >= nextRefreshAt then

                local delay =
                    math.clamp(
                        tonumber(
                            HOLY_SERVER_FINDER_STATE.RefreshDelay
                        )
                        or 5,
                        1,
                        60
                    )

                nextRefreshAt =
                    os.clock()
                    + delay

                if HOLY_SERVER_FINDER_HUD == nil then

                    HolyServerFinderOpenHud(
                        false
                    )

                else

                    local hudVisible =
                        HOLY_SERVER_FINDER_HUD.Visible == true

                    local visibleAutoRefresh =
                        hudVisible
                        and HOLY_SERVER_FINDER_STATE.AutoRefresh == true

                    if visibleAutoRefresh ~= true then

                        HolyServerFinderRefreshRows(
                            HOLY_SERVER_FINDER_HUD,
                            "background automation"
                        )
                    end
                end
            end

            task.wait(
                0.5
            )
        end
    end)
end

