function HolyOpenDeveloperConsole()

    local StarterGui =
        game:GetService(
            "StarterGui"
        )

    local lastError =
        nil

    for attempt = 1, 10 do

        local success,
            result =
            pcall(function()

                StarterGui:SetCore(
                    "DevConsoleVisible",
                    true
                )
            end)

        if success == true then

            print(
                "[HOLY] Developer Console opened."
            )

            return true,
                "opened"
        end

        lastError =
            result

        task.wait(
            0.25
        )
    end

    return false,
        tostring(
            lastError
            or "unknown error"
        )
end

