function HolyServerFinderRefreshMainUI()

    HolyServerFinderEnsureAutoJoinState()

    local ui =
        HOLY_SERVER_FINDER_MAIN_UI

    if type(ui) ~= "table" then
        return false
    end

    ui.Lock =
        true

    local function setValue(control, value)

        if type(control) == "table"
        and type(control.SetValue) == "function" then

            pcall(function()

                control:SetValue(
                    value
                )
            end)
        end
    end

    setValue(
        ui.HudToggle,
        HOLY_SERVER_FINDER_STATE.Enabled == true
    )

    setValue(
        ui.AutoRefreshToggle,
        HOLY_SERVER_FINDER_STATE.AutoRefresh == true
    )

    setValue(
        ui.RefreshDelayInput,
        tostring(
            HOLY_SERVER_FINDER_STATE.RefreshDelay
            or 5
        )
    )

    setValue(
        ui.ModeDropdown,
        HolyServerFinderModeDisplay(
            HOLY_SERVER_FINDER_STATE.AutoJoinMode
        )
    )

    setValue(
        ui.MinLifeInput,
        tostring(
            HOLY_SERVER_FINDER_STATE.AutoJoinMinLife
            or 30
        )
    )

    setValue(
        ui.CooldownInput,
        tostring(
            HOLY_SERVER_FINDER_STATE.AutoJoinCooldown
            or 10
        )
    )

    setValue(
        ui.BuilderPetDropdown,
        ui.BuilderPet
    )

    setValue(
        ui.BuilderSizeDropdown,
        ui.BuilderSizes
    )

    setValue(
        ui.BuilderVariantDropdown,
        ui.BuilderVariants
    )

    setValue(
        ui.BuilderRarityDropdown,
        ui.BuilderRarities
    )

    setValue(
        ui.BuilderPriorityDropdown,
        ui.BuilderPriority
    )

    local pageRows,
        page,
        pageCount =
        HolyServerFinderBuildWatchlistPage()

    if type(ui.WatchlistTable) == "table" then

        ui.WatchlistTable:SetRows(
            pageRows
        )

        local selectedRow =
            nil

        for rowIndex, rowData in ipairs(pageRows) do

            if tonumber(
                rowData.SourceIndex
            ) == tonumber(
                ui.SelectedIndex
            ) then

                selectedRow =
                    rowIndex

                break
            end
        end

        ui.WatchlistTable:SetSelected(
            selectedRow
        )
    end

    if type(ui.WatchlistPager) == "table" then

        ui.WatchlistPager:SetVisible(
            pageCount > 1
        )

        ui.WatchlistPager:SetText(
            "Page",
            "Page "
                .. tostring(page)
                .. "/"
                .. tostring(pageCount)
        )

        ui.WatchlistPager:SetDisabled(
            "Prev",
            page <= 1
        )

        ui.WatchlistPager:SetDisabled(
            "Next",
            page >= pageCount
        )
    end

    local selectedExists =
        tonumber(ui.SelectedIndex) ~= nil
        and HOLY_SERVER_FINDER_STATE.AutoJoinRules[
            tonumber(ui.SelectedIndex)
        ] ~= nil

    if type(ui.WatchlistActions) == "table" then

        ui.WatchlistActions:SetDisabled(
            "Edit",
            selectedExists ~= true
        )

        ui.WatchlistActions:SetDisabled(
            "Remove",
            selectedExists ~= true
        )
    end

    if type(ui.BuilderActions) == "table" then

        local editing =
            tonumber(ui.EditingIndex) ~= nil
            and HOLY_SERVER_FINDER_STATE.AutoJoinRules[
                tonumber(ui.EditingIndex)
            ] ~= nil

        ui.BuilderActions:SetText(
            "Reset",
            editing
            and "Cancel Edit"
            or "Reset"
        )

        ui.BuilderActions:SetText(
            "Save",
            editing
            and "Save Changes"
            or "Save Filter"
        )
    end

    ui.Lock =
        false

    HolySniperSetLabel(
        ui.FinderStatus,
        "HUD: "
            .. (
                HOLY_SERVER_FINDER_STATE.Enabled
                and "ON"
                or "OFF"
            )
            .. " · Auto refresh: "
            .. (
                HOLY_SERVER_FINDER_STATE.AutoRefresh
                and "ON"
                or "OFF"
            )
            .. " · "
            .. tostring(
                HOLY_SERVER_FINDER_STATE.RefreshDelay
                or 5
            )
            .. "s"
    )

    HolySniperSetLabel(
        ui.AutoJoinStatus,
        "Mode: "
            .. HolyServerFinderModeDisplay(
                HOLY_SERVER_FINDER_STATE.AutoJoinMode
            )
            .. " · "
            .. tostring(
                #(
                    HOLY_SERVER_FINDER_STATE.AutoJoinRules
                    or {}
                )
            )
            .. " filters"
    )

    return true
end

HOLY_SERVER_FINDER_TOGGLE:OnChanged(function(value)

    if HOLY_SERVER_FINDER_TOGGLE_LOCK == true
    or HOLY_SERVER_FINDER_MAIN_UI.Lock == true then

        return
    end

    if value == true
    and HolyAuthRequireServerSniper(
        "Server Finder HUD",
        true
    ) ~= true then

        HolyServerFinderSyncToggle(
            false
        )

        return
    end

    HolyServerFinderSetHudVisible(
        value == true
    )

    HolyServerFinderRefreshMainUI()
end)

HOLY_SERVER_FINDER_MAIN_UI.AutoRefreshToggle:OnChanged(function(value)

    if HOLY_SERVER_FINDER_MAIN_UI.Lock == true then
        return
    end

    if value == true
    and HolyAuthRequireServerSniper(
        "Auto Refresh",
        true
    ) ~= true then

        HolyServerFinderRefreshMainUI()

        return
    end

    HOLY_SERVER_FINDER_STATE.AutoRefresh =
        value == true

    HolyServerFinderApplyStateToHud(
        HOLY_SERVER_FINDER_HUD
    )

    HolyQueueSaveServerFinderSettings()

    HolyServerFinderRefreshMainUI()
end)

HOLY_SERVER_FINDER_MAIN_UI.RefreshDelayInput:OnChanged(function(value)

    if HOLY_SERVER_FINDER_MAIN_UI.Lock == true then
        return
    end

    HOLY_SERVER_FINDER_STATE.RefreshDelay =
        math.clamp(
            tonumber(value)
            or 5,
            1,
            60
        )

    HolyServerFinderApplyStateToHud(
        HOLY_SERVER_FINDER_HUD
    )

    HolyQueueSaveServerFinderSettings()

    HolyServerFinderRefreshMainUI()
end)

HOLY_SERVER_FINDER_MAIN_UI.ModeDropdown:OnChanged(function(value)

    if HOLY_SERVER_FINDER_MAIN_UI.Lock == true then
        return
    end

    HolyServerFinderSetAutoJoinMode(
        HolyServerFinderModeFromDisplay(
            value
        )
    )
end)

HOLY_SERVER_FINDER_MAIN_UI.MinLifeInput:OnChanged(function(value)

    if HOLY_SERVER_FINDER_MAIN_UI.Lock == true then
        return
    end

    HOLY_SERVER_FINDER_STATE.AutoJoinMinLife =
        math.clamp(
            tonumber(value)
            or 30,
            0,
            420
        )

    HolyQueueSaveServerFinderSettings()

    HolyServerFinderRefreshMainUI()
end)

HOLY_SERVER_FINDER_MAIN_UI.CooldownInput:OnChanged(function(value)

    if HOLY_SERVER_FINDER_MAIN_UI.Lock == true then
        return
    end

    HOLY_SERVER_FINDER_STATE.AutoJoinCooldown =
        math.clamp(
            tonumber(value)
            or 10,
            1,
            120
        )

    HolyQueueSaveServerFinderSettings()

    HolyServerFinderRefreshMainUI()
end)

HolyServerFinderRefreshMainUI()

if HOLY_SERVER_FINDER_STATE.Enabled == true then

    if HolyAuthHasServerSniperSlot() == true then

        task.defer(function()

            HolyServerFinderSetHudVisible(
                true
            )
        end)

    else

        task.defer(function()

            HolyServerSniperForceLockedOff(
                "startup",
                false
            )
        end)
    end
end

HolySniperSetPageMode(
    HOLY_SNIPER_PAGE_STATE.Mode
)

HolySniperRefreshUI()

HolyDataStartPetLoader(
    "sniper ui ready"
)

HolyDefenseRestoreState()

if HOLY_SNIPER_STATE.ActivateSniper == true then

    HolySniperStart(
        "startup"
    )
end

