local function HolyFarmAddPageNote(box, text)

    if type(box) ~= "table"
    or type(box.AddLabel) ~= "function" then

        return false
    end

    pcall(function()

        box:AddLabel({
            Text =
                text,

            DoesWrap =
                true,

            Size =
                13,
        })
    end)

    return true
end

