local function createWatchlistAction(text, position, size, primary)

    local button =
        Instance.new(
            "TextButton"
        )

    button.AutoButtonColor =
        false

    button.BackgroundColor3 =
        primary == true
        and Library.Scheme.AccentColor
        or Library.Scheme.MainColor

    button.BackgroundTransparency =
        primary == true
        and 0.12
        or 0.22

    button.BorderSizePixel =
        0

    button.Position =
        position

    button.Size =
        size

    button.Text =
        text

    button.TextColor3 =
        Library.Scheme.FontColor

    button.TextSize =
        11

    button.FontFace =
        Library.Scheme.Font

    button.Parent =
        AuctionWatchlistActions

    local corner =
        Instance.new(
            "UICorner"
        )

    corner.CornerRadius =
        UDim.new(
            0,
            4
        )

    corner.Parent =
        button

    local stroke =
        Instance.new(
            "UIStroke"
        )

    stroke.ApplyStrokeMode =
        Enum.ApplyStrokeMode.Border

    stroke.Color =
        primary == true
        and Library.Scheme.AccentColor
        or Library.Scheme.OutlineColor

    stroke.Transparency =
        primary == true
        and 0.05
        or 0.24

    stroke.Thickness =
        1

    stroke.Parent =
        button

    return button
end

