function HolySettingsRefreshDashboard()

    local dashboard =
        tostring(
            HOLY_DEV_UI_STATE.SettingsDashboard
            or "Interface"
        )

    local showInterface =
        dashboard == "Interface"

    local showThemes =
        dashboard == "Themes"

    local showSession =
        dashboard == "Session"

    local showPerformance =
        dashboard == "Performance"

    local showAccount =
        dashboard == "Account"

    HolySetGroupboxVisible(
        SettingsUIBox,
        showInterface
    )

    HolySetGroupboxVisible(
        SettingsLayoutBox,
        showInterface
    )

    HolySetGroupboxVisible(
        SettingsWorldBox,
        showInterface
    )

    HolySetGroupboxVisible(
        SettingsThemeEditorBox,
        showThemes
    )

    HolySetGroupboxVisible(
        SettingsThemeLibraryBox,
        showThemes
    )

    HolySetGroupboxVisible(
        SettingsSessionBox,
        showSession
    )

    HolySetGroupboxVisible(
        SettingsProtectionBox,
        showSession
    )

    HolySetGroupboxVisible(
        SettingsPerformanceBox,
        showPerformance
    )

    HolySetGroupboxVisible(
        SettingsAccountBox,
        showAccount
    )

    HolySetGroupboxVisible(
        SettingsPairingBox,
        showAccount
    )
end

function HolySettingsSetDashboard(value)

    value =
        tostring(
            value
            or "Interface"
        )

    if value ~= "Themes"
    and value ~= "Session"
    and value ~= "Performance"
    and value ~= "Account" then

        value =
            "Interface"
    end

    HOLY_DEV_UI_STATE.SettingsDashboard =
        value

    HolySaveUISettings()

    if SettingsModeControl
    and type(SettingsModeControl.SetValue) == "function" then

        SettingsModeControl:SetValue(
            value,
            true
        )
    end

    HolySettingsRefreshDashboard()
end

SettingsModeControl =
    Tabs.Settings:AddTopSegmentedControl({
        Values = {
            "Interface",
            "Themes",
            "Session",
            "Performance",
            "Account",
        },

        Default =
            HOLY_DEV_UI_STATE.SettingsDashboard,

        Width =
            390,

        Height =
            42,

        PillHeight =
            30,

        Callback =
            function(value)

                HolySettingsSetDashboard(
                    value
                )
            end,
    })

HolySettingsRefreshDashboard()

