local function HolyThemeAddColorControl(
    optionId,
    text,
    key
)

    local label =
        SettingsThemeEditorBox:AddLabel(
            text
        )

    label:AddColorPicker(
        optionId,
        {
            Default =
                HOLY_THEME_STATE.Draft[
                    key
                ],

            Title =
                text,
        }
    )

    local picker =
        Options[
            optionId
        ]

    picker:OnChanged(function(value)

        HolyThemeSetDraftColor(
            key,
            value
        )
    end)

    HOLY_THEME_STATE.UI.ColorPickers =
        HOLY_THEME_STATE.UI.ColorPickers
        or {}

