                HOLY_WATERING_REJOIN_STATE.WateringDelay,

            Min =
                0.1,

            Max =
                10,

            Rounding =
                2,

            Suffix =
                "s",

            HideMax =
                true,

            Tooltip =
                "Delay between watering uses in Delay mode.",
        }
    )

HOLY_WATERING_REJOIN_UI.WateringDelaySlider:OnChanged(function(value)

    HolyWateringRejoinSetWateringDelay(
        value
    )
end)

HOLY_WATERING_REJOIN_UI.RejoinDelaySlider =
    VulnWateringRejoinBox:AddSlider(
        "HolyWateringRejoinRejoinDelay",
        {
            Text =
                "Rejoin Delay",

            Default =
                HOLY_WATERING_REJOIN_STATE.RejoinDelay,

            Min =
                1,

            Max =
                60,

            Rounding =
                1,

            Suffix =
                "s",

            HideMax =
                true,

            Tooltip =
                "How long to wait after all planned watering uses finish before rejoining.",
        }
    )

HOLY_WATERING_REJOIN_UI.RejoinDelaySlider:OnChanged(function(value)

    HolyWateringRejoinSetRejoinDelay(
        value
    )
end)

HolySetGroupboxVisible(
    VulnRollbackBox,
    SHOW_PATCHED_VULN_TOOLS
)

HolySetGroupboxVisible(
    VulnWateringRejoinBox,
    SHOW_PATCHED_VULN_TOOLS
)

--==================================================
-- [8] FINISH
--==================================================

HolyAccountLoadSavedToken()
HolyAccountRefreshUI()

if HolyAccountTokenValid(
    HOLY_ACCOUNT_RUNTIME.Token
) == true then

    HolyAccountStartHeartbeat()
end

if type(HolyRareAlertStart) == "function" then

    task.defer(function()

        HolyRareAlertStart(
            "startup"
        )
    end)
end

if SHOW_PATCHED_VULN_TOOLS == true
and HOLY_WATERING_REJOIN_STATE.Enabled == true then

    task.defer(function()

        task.wait(
            1
        )

        HolyWateringRejoinStart(
            "saved startup"
        )
    end)
end

HolyStartupLoadingStep(
    4,
    "Ready",
    "HOLY PRO has finished loading."
)

if type(HolyStartupLoading) == "table" then

    local loadingElapsed =
        os.clock()
        - HolyStartupLoadingStartedAt

    if loadingElapsed < 0.6 then

        task.wait(
            0.6 - loadingElapsed
        )
    end

    pcall(function()

        HolyStartupLoading:Continue()
    end)

    pcall(function()

        Window:Toggle(
            HOLY_DEV_UI_STATE.ShowUIOnLoad
            == true
        )
    end)
end

if HOLY_DEV_UI_STATE.PerformanceMonitor == true then

    task.defer(function()

        HolyPerformanceMonitorStart()
    end)
end

HolyNotify(
    "HOLY Premium",
    "Loaded. Toggle UI with LeftAlt.",
    4
)

